/* AUTO-GENERATED by content-engine/import.cjs — subject:hazmat — do not edit by hand.
   Replaces 283 upgraded questions in place, appends 0 new ones, fills en/ru/tr/es/hi.
   Idempotent: re-run import.cjs to regenerate. Safe to remove (just delete this file + its <script> tag). */
(function(){
  if(!window.CDL_DATA||!window.I18N){ return; }
  var SUBJ="hazmat";
  var D=window.CDL_DATA, I=window.I18N;
  var cat=D.categories.filter(function(c){return c.id===SUBJ;})[0]; if(!cat) return;
  I.q=I.q||{}; ["ru","tr","es","hi"].forEach(function(L){ I.q[L]=I.q[L]||{}; I.q[L][SUBJ]=I.q[L][SUBJ]||{}; });
  var REPL={"0":{"q":"I just earned my H endorsement and a new driver asks me why all the placarding, shipping-paper, and packaging rules even exist. Of the following, which BEST describes the main purpose behind the hazardous materials regulations?","options":["To contain the material so it cannot escape, and to communicate the danger so others can stay clear and respond safely","To guarantee faster delivery windows by giving placarded loads priority access to highway lanes and routes","To document each shipment so the carrier can bill the customer the correct hazardous-handling surcharge","To reduce the carrier's fuel costs by routing heavy hazardous loads onto the shortest available roads"],"answer":0,"explanation":"HazMat rules exist to contain the material so it cannot escape and to communicate the danger so others can stay clear and respond safely.","handbook":"The intent of the regulations is to contain the material, communicate the risk, and ensure safe transportation.","hbref":"§9.1","qid":"HM-001"},"1":{"q":"I just got hired to run a route hauling a placarded load of corrosive material, and I already hold a Class A CDL with a tanker endorsement. Before I can legally take this trip, which of the following must I do?","options":["Nothing extra — my Class A CDL with the tanker endorsement already covers any placarded load I haul","Obtain the hazardous materials (H) endorsement, which requires passing a TSA security threat assessment and fingerprinting","Add a doubles/triples endorsement, since placarded loads must be split across multiple trailers","Add a passenger endorsement, because placarded loads are regulated the same way passenger transport is"],"answer":1,"explanation":"Hauling any placardable quantity of hazardous materials requires the hazardous materials (H) endorsement, which requires a TSA security threat assessment and fingerprinting.","handbook":"You must have a hazardous materials endorsement to transport placarded amounts of hazardous materials.","hbref":"§9.1","qid":"HM-002"},"2":{"q":"I already hold a Texas Class A CDL and a valid DOT medical certificate. My new employer wants me to start pulling placardable loads of corrosives, so I need to add the H endorsement. When I ask the DPS clerk what extra step this endorsement requires that my current license did NOT, which of the following is she MOST likely to tell me?","options":["Nothing extra is needed; once you hold a Class A CDL with a current DOT medical card, the H endorsement is simply printed on your license at no additional requirement","You must pass a second, more detailed DOT physical and submit an updated medical examiner's certificate before the endorsement can be issued","You must pass a TSA security threat assessment, which includes a background check and fingerprinting, before the endorsement can be issued","You only need to retake and pass the standard CDL vision screening to confirm you can still read placards at a distance"],"answer":2,"explanation":"The HazMat endorsement requires passing a TSA security threat assessment, including a background check and fingerprinting, before it can be issued.","handbook":"Applicants for a hazardous materials endorsement must pass a Transportation Security Administration background check.","hbref":"§9.1","qid":"HM-003"},"3":{"q":"I'm hired to haul a load of corrosive material and I'm reviewing the paperwork at the dock before departure. I notice the hazard class, proper shipping name, and UN identification number are already entered on the shipping papers, but I want to be sure the right party handled that. Under the HazMat rules, whose job was it to identify the material as hazardous and prepare those shipping papers in the first place?","options":["The motor carrier, since the carrier owns the trip and is responsible for transporting the load and reporting any incidents","The driver, since I am the one who must keep the papers within reach and refuse the load if anything looks wrong","The receiver, since the company accepting delivery confirms the contents and signs for the hazardous material","The shipper, since the shipper classifies, names, packages, and labels the material and prepares the shipping papers"],"answer":3,"explanation":"The shipper classifies, names, packages, and labels the hazardous material and prepares the shipping papers before the load reaches the driver.","handbook":"The shipper is responsible for describing and packaging hazardous materials and preparing the shipping papers.","hbref":"§9.1","qid":"HM-004"},"4":{"q":"I'm hauling a placarded load of corrosives across Texas and just merged onto the interstate. To stay compliant with HazMat shipping-paper rules while I'm driving, where should the shipping papers be right now?","options":["Within my reach with my seat belt on, or in a pouch on the driver's door, and on top of my other papers","Secured in the sleeper berth so wind from an open window can't scatter them","Filed in the document box mounted on the outside of the trailer near the placards","Tucked under the freight in the trailer so they stay with the actual cargo"],"answer":0,"explanation":"While the vehicle is moving, HazMat shipping papers must be within the driver's reach with the seat belt on, or in the driver's door pouch, and on top of other papers.","handbook":"Drivers must keep shipping papers in a door pouch, within reach in clear view, or on the driver's seat when out of the vehicle.","hbref":"§9.2","qid":"HM-005"},"5":{"q":"I'm a new driver loading a mixed freight trailer that includes one HazMat item along with several non-regulated commodities. When I review the combined shipping paper before I leave the dock, how should the HazMat material be identified on that document so the paperwork is legal?","options":["Entered last on the page so it stays separate from the ordinary freight lines","Entered first, or highlighted, or marked with an 'X' in the HM column","Written only on a separate back page that is stapled behind the freight list","Left in regular print since the placards on the trailer already flag the hazard"],"answer":1,"explanation":"On a mixed shipping paper, the HazMat entry must be made distinguishable by entering it first, highlighting it, or marking it with an 'X' in the HM column.","handbook":"Hazardous materials must be described first on the shipping paper, or highlighted, or marked with an X in the HM column.","hbref":"§9.2","qid":"HM-006"},"6":{"q":"I'm hauling a Table 2 load of corrosives and just bolted the four diamond-shaped placards onto all sides of my trailer before pulling out of the terminal. A new driver asks me why those diamonds matter so much that I'd refuse to roll without them. Which explanation correctly states the primary purpose those placards serve?","options":["They certify that the shipper correctly classified and packaged the load, so I don't have to inspect the shipment myself","They prove I hold a valid H endorsement and passed the TSA background check required to haul this freight","They warn everyone around the vehicle of the hazard the cargo presents so responders and the public can react safely","They record the aggregate gross weight of the regulated material so scale officers can confirm I'm under 1,001 lb"],"answer":2,"explanation":"Placards warn everyone around the vehicle of the hazard the cargo presents so responders and the public can react safely.","handbook":"Placards are used to warn others of hazardous materials.","hbref":"§9.3","qid":"HM-007"},"7":{"q":"I'm hauling a placarded load of corrosives, and a yard supervisor tells me a co-worker already mounted the required placards on both sides of the trailer and across the rear. Before I roll out the gate, which statement correctly tells me what I still must do to be legal on placard placement?","options":["Nothing more is needed; with both sides and the rear covered, three placards satisfy the placarding rule for a corrosive load.","Add a placard to the roof of the trailer so it is visible from above, but the front is not required since the cab blocks the view.","Move the rear placard to the front bumper, because the front and the two sides are the only positions an officer actually inspects.","Add a placard to the front of the vehicle as well, so the load is placarded on the front, rear, and both sides."],"answer":3,"explanation":"Placards must be displayed on all four sides of the vehicle — front, rear, and both sides — each readable from the direction it faces.","handbook":"Placarded vehicles must display warning placards on the front, rear, and both sides.","hbref":"§9.3","qid":"HM-008"},"8":{"q":"I'm hauling a placarded load of corrosives when one of my drums starts leaking onto the shoulder. I've warned bystanders and called responders, but the dispatcher tells me to read the firefighters the reference number off the document that identifies how to handle this exact material's spill. Which item in my cab am I supposed to use?","options":["The Emergency Response Guidebook (ERG), which lets responders match the material to its hazard and protective actions","The shipping papers, since the proper shipping name and UN/NA number are already listed there for the load","The vehicle's owner's manual, which covers the truck's systems and the manufacturer's emergency procedures","The bill of lading, since it documents the freight and the carrier's incident-reporting contact details"],"answer":0,"explanation":"Every HazMat driver must carry the Emergency Response Guidebook (ERG), which lets responders match the material to its hazard and protective actions.","handbook":"The Emergency Response Guidebook helps responders deal with hazardous materials spills and fires.","hbref":"§9.2","qid":"HM-009"},"9":{"q":"I'm about to leave the terminal hauling a placarded load of Class 3 flammable liquid. My dispatcher is pushing me to get rolling because I'm behind schedule. To do my job safely and legally before I pull out, which of these should I do?","options":["Pull the placards off the trailer so I don't draw attention from other drivers on the highway","Carefully inspect the vehicle, tires, and load securement before I start the trip","Skip the pre-trip inspection this once so I can make up the time I lost waiting at the dock","Disconnect the trailer brakes so the unit rolls easier and I burn less fuel on the run"],"answer":1,"explanation":"Hauling HazMat requires carefully inspecting the vehicle, tires, and load securement before starting the trip, and schedule pressure never excuses skipping it.","handbook":"Drivers of placarded vehicles must inspect their vehicle thoroughly before and during a trip.","hbref":"§9.4","qid":"HM-010"},"11":{"q":"During a required en-route tire check on my placarded HazMat load, I find one tire on the trailer is dangerously overheated. According to Texas HazMat rules, what must I do before I continue?","options":["Pour water over the tire to cool it down, then keep driving to the next service stop to have it checked","Add air to restore the correct pressure, then drive carefully until the tire cools on its own","Remove the overheated tire and place it a safe distance from the vehicle, and do not drive until it is fixed","Reduce my speed and keep driving so the airflow cools the tire before the next required check"],"answer":2,"explanation":"An overheating tire on a placarded load is a fire and explosion risk, so remove it, place it well away from the vehicle, and do not drive until it is repaired.","handbook":"If a tire is overheated, remove it and place it a safe distance from the vehicle; do not drive until repaired.","hbref":"§9.4","qid":"HM-011"},"12":{"q":"I'm placarded for a load of oxidizers and pulled into a rest area for my break. A buddy in another rig wants to step over and have a cigarette with me. To stay legal, how far from my trailer must we both stay while smoking?","options":["At least 5 feet, the same buffer required when parking off the traveled road","At least 10 feet, far enough that no flame can reach the trailer","At least 100 feet, the same buffer used for explosives near a building","At least 25 feet from the vehicle, since it carries oxidizers"],"answer":3,"explanation":"Smoking or any open flame must stay at least 25 feet from a placarded vehicle carrying explosives, oxidizers, or flammables.","handbook":"Do not smoke within 25 feet of a vehicle carrying explosives, oxidizers, or flammable materials.","hbref":"§9.4","qid":"HM-012"},"13":{"q":"I've pulled up to a loading dock to load Division 1.2 explosives into my trailer. The dock crew is waiting for me to get the truck ready before they start moving cases on board. Before any of the explosives are loaded, what must I do with my vehicle?","options":["Shut off the engine and set the parking brake to secure the vehicle before loading begins","Keep the engine idling so the air brakes stay charged and the cab climate control runs during loading","Leave the engine running but apply the parking brake, since the motor itself is not a real ignition source","Roll all the windows down and sound the horn twice to alert the dock crew that loading is starting"],"answer":0,"explanation":"Before loading or unloading explosives, turn off the engine to remove the ignition source and set the parking brake to secure the vehicle.","handbook":"Turn off your engine before loading or unloading explosives and set the parking brake.","hbref":"§9.4","qid":"HM-013"},"14":{"q":"I'm picking up a load of gasoline in drums at a fuel terminal, and my dispatcher tells me to confirm the hazard class on the shipping papers before I placard. Based on how HazMat classes are defined, which hazard class number should appear next to this gasoline load?","options":["Class 1, because flammable liquids carry the highest explosion danger and are grouped with explosives","Class 3, because gasoline is a flammable liquid and that is exactly what this class covers","Class 8, because gasoline can burn skin and damage materials on contact like a corrosive","Class 2, because gasoline gives off flammable vapors and is handled as a flammable gas"],"answer":1,"explanation":"Gasoline is a flammable liquid, which is exactly what Hazard Class 3 covers.","handbook":"Hazard Class 3 is flammable liquids.","hbref":"§9.2","qid":"HM-014"},"15":{"q":"I'm at the dock loading a shipment, and the shipping paper lists the proper shipping name, the hazard class, and the UN number for a load of explosives. Before I placard my trailer and head out, I need to confirm the hazard class number that identifies this load as explosives. Which hazard class is correct?","options":["Class 8, which covers corrosives like battery acid","Class 3, which covers flammable liquids like gasoline","Class 1, which covers explosives such as dynamite","Class 7, which covers radioactive materials like uranium"],"answer":2,"explanation":"Explosives such as dynamite are Hazard Class 1, the first of the nine hazard classes.","handbook":"Hazard Class 1 covers explosives.","hbref":"§9.2","qid":"HM-015"},"16":{"q":"I'm picking up two HazMat loads at the terminal. The first is a small drum of a Table 2 corrosive weighing only 300 lb; the second is a single cylinder of poison gas (Class 2.3). My dispatcher tells me I'll \"need placards for the placarded amount.\" What does that phrase actually tell me about when placards are required?","options":["Any vehicle carrying HazMat must always display placards, so both the 300 lb corrosive and the poison gas require them regardless of weight or class","Placards are only legally required when the vehicle is moving on a public highway after dark or in reduced visibility","No placards are needed for either load because both shipments are under the 1,001 lb total threshold for the trip","Placards are required only for certain quantities or classes — the poison gas needs them in any amount, while the corrosive needs them only at 1,001 lb or more"],"answer":3,"explanation":"Table 1 materials like poison gas require placards in any amount, while Table 2 materials like corrosives need placards only at 1,001 lb or more.","handbook":"Placards are required based on the hazard class and the amount of material being transported.","hbref":"§9.3","qid":"HM-016"},"17":{"q":"I'm picking up a placarded load of corrosives. The shipper hands me the shipping papers and tells me everything has been classified, packaged, and labeled correctly. Before I haul this load, what tells me the shipper has formally certified that the shipment is properly described, packaged, marked, and labeled?","options":["The shipper's signed certification statement appearing on the shipping paper itself","A verbal assurance from the shipper given to me at the loading dock","The presence of the correct hazard class placards already mounted on all four sides","My own inspection of the seals and labels confirming nothing is leaking"],"answer":0,"explanation":"The shipper certifies that a HazMat shipment is properly named, packaged, marked, and labeled by signing a certification statement on the shipping paper.","handbook":"The shipper certifies on the shipping paper that the materials are properly prepared for transport.","hbref":"§9.2","qid":"HM-017"},"19":{"q":"My placarded corrosives tanker rolls over on a rural highway and Class 8 product is leaking onto the shoulder. After I move people back, stop smoking, and grab the ERG, my company needs the serious incident reported by phone. Which contact is the one that exists specifically to receive a report of a serious hazmat incident?","options":["CHEMTREC, which I call first because it is the only agency authorized to take an official incident report","The National Response Center, the federal hotline that exists to receive reports of serious hazmat incidents","The shipper listed on my paperwork, because the company that packaged the load must file the report","The vehicle manufacturer's hotline, so the rollover and tank failure are formally documented"],"answer":1,"explanation":"Serious hazardous materials incidents must be reported to the National Response Center, the federal hotline at 1-800-424-8802.","handbook":"Carriers must report hazardous materials incidents to the National Response Center.","hbref":"§9.5","qid":"HM-018"},"20":{"q":"It is 2:30 a.m. on a Sunday and one of my placarded drums has begun leaking corrosive material at a rest stop. I have already warned bystanders, kept people away, and prevented smoking. I now want to call CHEMTREC (1-800-424-9300) for emergency chemical handling guidance, but I'm worried no one will answer at this hour on a weekend. Which statement is correct?","options":["CHEMTREC only answers calls during normal business hours, so I must wait until Monday morning to get guidance.","CHEMTREC is staffed only on weekdays, so I should call my carrier's office instead since it is Sunday.","CHEMTREC is staffed 24 hours a day, every day, so I can call right now and reach an emergency expert.","CHEMTREC is reachable only during nighttime hours, so calling at 2:30 a.m. is the one window that works."],"answer":2,"explanation":"CHEMTREC (1-800-424-9300) is staffed 24 hours a day, every day, to provide emergency response information.","handbook":"CHEMTREC provides emergency information 24 hours a day for hazardous materials incidents.","hbref":"§9.5","qid":"HM-019"},"21":{"q":"I'm hauling a placarded load of corrosives (not explosives) and need to pull over to make a phone call and check my paperwork. There's no rest area nearby, so I'm looking at the shoulder of a two-lane highway. To stay legal under the HazMat parking rules, which of the following must I do?","options":["Park as close to the edge of the traveled lane as I can so I leave the most room on the shoulder for other traffic","Park within 300 feet of the roadway but keep the load unattended only for a few minutes","Pull the vehicle up onto the shoulder pavement and stop directly beside the white edge line of the lane","Keep the vehicle at least 5 feet away from the traveled part of the road before I stop and park"],"answer":3,"explanation":"A placarded vehicle must never be parked within 5 feet of the traveled part of the road.","handbook":"Never park a placarded vehicle within 5 feet of the traveled part of a road.","hbref":"§9.6","qid":"HM-020"},"22":{"q":"I'm hauling Division 1.2 explosives and pull over for a mandatory tire check. On the shoulder up ahead I see a vehicle fire, with a crowd of people gathered nearby watching. To park legally and safely with this load, what is the minimum distance I must keep between my truck and that crowd gathered at the scene?","options":["At least 300 feet from the gathering of people","At least 25 feet from the gathering of people","At least 50 feet from the gathering of people","At least 5 feet from the gathering of people"],"answer":0,"explanation":"Explosives loads (Division 1.1, 1.2, 1.3) must never be parked within 300 feet of a place where people gather.","handbook":"Never park a vehicle carrying explosives within 300 feet of an open fire.","hbref":"§9.6","qid":"HM-021"},"23":{"q":"I'm hauling a placarded load of Division 1.2 explosives and need to step away from my rig at a rest area for a few minutes. Regulations say this load must never be left unattended. For my vehicle to legally count as 'attended,' which of the following must be true of the person watching it?","options":["They may rest in the sleeper berth as long as they can hear the truck and respond if something happens","They are awake, within 100 feet of the vehicle, have it in clear view, and are able to move it quickly if needed","They walk past and inspect the vehicle at least once every two hours, the same interval used for tire checks","They remain anywhere within the rest area and stay reachable by cell phone in case of an emergency"],"answer":1,"explanation":"An explosives load is attended only if the person is awake, within 100 feet, has it in clear view, and can move it quickly.","handbook":"An attendant must be awake, within 100 feet of the vehicle, and able to move it in an emergency.","hbref":"§9.6","qid":"HM-022"},"24":{"q":"I'm a CDL driver hauling a placarded load of corrosives. At the dock, a clerk hands me a clipboard and rattles off what \"my job\" includes before I roll. To stay inside my actual legal lane as the driver, I need to spot the one task on this list that is NOT a driver responsibility but belongs to someone else in the chain. Which of these is that task?","options":["Refusing to accept a package that I find is leaking or improperly marked","Putting the required placards on all four sides before I drive","Producing and chemically formulating the hazardous material being shipped","Keeping the shipping papers within my reach while I drive"],"answer":2,"explanation":"The driver's duties are inspecting, refusing bad shipments, placarding, keeping shipping papers handy, and driving safely — never producing the material.","handbook":"Drivers must refuse leaking shipments, apply placards, and follow safe transport rules.","hbref":"§9.1","qid":"HM-023"},"25":{"q":"It is below freezing and I am loading a trailer for a long haul. My truck has a working cargo-space heater, and I'd like to run it to protect the load from the cold. Of the four shipments waiting on the dock, for which one should I keep the cargo heater turned OFF?","options":["A pallet of canned soup and bottled water that could freeze and burst in the cold","Boxed household furniture and packing materials that hold moisture in cold weather","Refrigerated produce that the receiver wants kept from freezing during transit","Drums of a Class 3 flammable liquid loaded along with boxes of explosives"],"answer":3,"explanation":"Cargo heaters must stay off when hauling explosives or flammable liquids because the flame or heat can ignite vapors or set off the explosives.","handbook":"You usually may not use cargo heaters when transporting explosives or flammable materials.","hbref":"§9.4","qid":"HM-024"},"26":{"q":"It's been three weeks since I delivered a placarded load of corrosives and the trip is long over. My dispatcher tells me the company is still holding on to that shipment's hazmat shipping papers in a file. Which of the following is the BEST reason the carrier keeps those completed papers on file after the run is finished?","options":["Federal and state regulators may demand the records for inspection, so the carrier must retain them for the required period","The driver who hauled the load is required to personally keep those original papers on file for the rest of their career","Once delivery is confirmed and the load is off the truck, the papers no longer serve any purpose and can be discarded","The papers only need to be kept while the material is in transit and must reach the driver's door pouch"],"answer":0,"explanation":"The carrier must keep completed shipping papers for the required period because federal and state regulators may demand them for inspection.","handbook":"Carriers must retain hazardous materials records as required by regulation.","hbref":"§9.2","qid":"HM-025"},"27":{"q":"I'm prepping shipping papers for a load and I open the Hazardous Materials Table in the regulations to pull the details for my product's entry. As I read across the row for my material, every column I see comes straight from that Table EXCEPT for one piece of information I'd have to get from somewhere other than the Table. Which of the following would I NOT find by reading the Hazardous Materials Table?","options":["The proper shipping name I must use to describe the material on my shipping papers","My home address as the driver, which never appears anywhere in the Table","The hazard class or division assigned to the material I am hauling","The identification number (UN/NA) that must be listed with the entry"],"answer":1,"explanation":"The Hazardous Materials Table describes the material itself — shipping name, hazard class, ID number, packing group, and labels — never the driver's personal information.","handbook":"The Hazardous Materials Table lists the proper shipping name, hazard class, identification number, and required labels.","hbref":"§9.2","qid":"HM-026"},"28":{"q":"I'm picking up a load of Class 3 flammable liquid at a shipper's dock. The shipping papers correctly identify the material and show it requires placards, but the shipper hands me the truck without any placards displayed and says they're \"out of stock.\" Before I pull onto the road, what must I do?","options":["Drive to my first scheduled stop and ask the receiver to supply the missing placards, since the load is already loaded and the papers are correct","Proceed without placards but keep the shipping papers on top within reach, because correct paperwork legally substitutes for missing placards","Obtain the correct placards and apply them to all four sides before I move the vehicle onto the road","Refuse the entire shipment outright and leave it on the dock, since a missing placard makes the load illegal to accept"],"answer":2,"explanation":"If the shipper provides no placards, the driver must obtain the correct ones and apply them to all four sides before moving the vehicle onto the road.","handbook":"A vehicle must display the correct placards before it is moved with a placarded load.","hbref":"§9.3","qid":"HM-027"},"29":{"q":"I'm loading boxed corrosive material into my trailer, and the shipper has applied a marking to each individual package. At the dock another driver tells me these package markings are exactly the same thing as the placards I'll hang on all four sides of my vehicle. To inspect the load correctly, which statement should I rely on?","options":["The package markings are full-size placards, and federal rules let me move them onto the vehicle sides to satisfy the four-side placarding requirement","Package markings are optional notes from the shipper, so the vehicle placards are the only diamond markings that actually carry legal weight","Hazard communication in the US is handled by placards only, so any diamonds on the boxes are merely decorative and can be ignored","The diamonds on each package are hazard labels the shipper applies, and they are separate from the larger placards that go on the vehicle"],"answer":3,"explanation":"Labels are the smaller diamonds the shipper puts on individual packages, while placards are the larger diamonds placed on all four sides of the vehicle.","handbook":"Shippers apply diamond-shaped hazard labels to packages; placards are placed on the vehicle.","hbref":"§9.3","qid":"HM-028"},"30":{"q":"I'm building a load that includes a refrigerated tank of anhydrous ammonia and a cylinder of compressed oxygen. On the shipping papers both entries are marked as Hazard Class 2. As I verify the paperwork against what I'm actually loading, which physical state should I expect every Class 2 material to be in?","options":["A gas (the class covers flammable, non-flammable, and poison gases)","A flammable liquid that gives off vapors at low temperature","A solid that becomes dangerous only when it gets wet","A corrosive that can be either liquid or solid form"],"answer":0,"explanation":"Hazard Class 2 is the gases class, covering flammable, non-flammable, and poison gases.","handbook":"Hazard Class 2 covers gases.","hbref":"§9.2","qid":"HM-029"},"31":{"q":"I'm a new HazMat driver loading a corrosive cleaning product. The label on the drums shows the manufacturer's brand name in big letters, the shipper handed me papers, and the dispatcher keeps calling the load by its catalog product name. When I check that the proper shipping name on my shipping papers is correct, which name must it match?","options":["The brand name printed in large letters on the drum labels, since that is what identifies the actual product","The proper shipping name listed in the Hazardous Materials Table for that material, not any trade or brand name","The catalog product name the dispatcher uses, because that is how the company tracks the load","Any common name for the product, as long as the hazard class and ID number on the papers are correct"],"answer":1,"explanation":"Shipping papers must list the proper shipping name exactly as it appears in the Hazardous Materials Table, not a trade or brand name.","handbook":"Use the proper shipping name from the Hazardous Materials Table to describe the material.","hbref":"§9.2","qid":"HM-030"},"32":{"q":"I'm doing a pre-trip inspection on my placarded tanker before hauling a flammable liquids load. I climb up to the cab area and check the fire extinguisher mounted by the door. Which condition means the extinguisher is acceptable and I'm legal to roll?","options":["The extinguisher is mounted and sealed, so I don't need to check the gauge or its rating before leaving","The extinguisher is the size I'm used to, even though the pressure gauge needle sits in the red zone","The extinguisher is fully charged and carries a rating high enough for the hazard I'm hauling","The extinguisher is present in the cab, since carrying any working extinguisher satisfies the requirement"],"answer":2,"explanation":"A placarded vehicle must carry a fire extinguisher that is both fully charged and rated high enough for the hazard being hauled.","handbook":"Vehicles carrying hazardous materials must have a properly charged and rated fire extinguisher.","hbref":"§9.4","qid":"HM-031"},"33":{"q":"I'm hauling a placarded load of flammable liquid and pull into a fuel island to top off my tank. My co-driver offers to help so we can finish faster. To fuel the truck correctly and safely, which of the following MUST happen?","options":["I can leave the nozzle latched open and step away to clean the windshield, as long as the engine stays running to power the lights","I should keep the engine idling so the fuel pump primes faster, and stand back about 25 feet while it fills","I can start fueling and walk inside to pay, since the auto shutoff on the pump will stop the flow when the tank is full","I must shut the engine off, and one of us has to stay at the nozzle controlling the fuel flow the entire time"],"answer":3,"explanation":"When fueling a placarded vehicle, the engine must be off and someone must stay at the nozzle controlling the fuel flow the entire time.","handbook":"When fueling, turn off the engine and have someone control the nozzle; never smoke while fueling.","hbref":"§9.4","qid":"HM-032"},"34":{"q":"I'm hauling a placarded load of Division 1.1 explosives and my GPS offers the fastest route, which cuts straight through a downtown business district and a major river tunnel during the afternoon. According to required HazMat routing, what should I do?","options":["Plan a route that avoids populated areas and tunnels wherever required, even if it adds miles","Take the GPS route since the tunnel keeps me off congested surface streets and saves time","Use the downtown route but only if I stay parked at least 5 feet from the traveled road during stops","Follow the fastest route as long as I cross the railroad tracks without shifting gears"],"answer":0,"explanation":"A driver hauling placarded explosives must follow designated HazMat routing, avoiding tunnels and populated areas even if it adds miles.","handbook":"Plan routes to avoid tunnels, populated areas, and other restricted locations when required.","hbref":"§9.6","qid":"HM-033"},"35":{"q":"I'm loading my trailer for a placarded HazMat run and my shipping papers list two materials that the segregation table shows can react dangerously if they come into contact. The dock crew is in a hurry and wants me to just get rolling. Which action keeps me legal and safe?","options":["Strap the two incompatible materials onto the same pallet so they ride tight and won't shift during the trip","Keep the two materials loaded separately as the segregation rules require so the reactive items stay apart","Combine the two materials into one sealed box so a single spill can't spread to the rest of the load","Load both materials normally and skip the segregation check since I'm running a short, direct route"],"answer":1,"explanation":"Incompatible materials listed in the segregation table must be loaded and kept apart so they cannot react if they come into contact.","handbook":"Some hazardous materials must be loaded separately because they can react dangerously together.","hbref":"§9.4","qid":"HM-034"},"36":{"q":"I'm loading drums of battery acid for transport. The shipping papers list the load with a hazard class number, and I want to confirm I've matched the correct hazard class to this corrosive material before I placard. Which hazard class number belongs on the placards for a corrosive like acid?","options":["Class 3, because flammable liquids in drums and acids are grouped together","Class 5, because acids react strongly and behave as oxidizers","Class 8, because corrosives such as acids fall under that hazard class","Class 1, because pressurized acid drums are treated as explosives"],"answer":2,"explanation":"Corrosives such as acids belong to Hazard Class 8.","handbook":"Hazard Class 8 covers corrosives.","hbref":"§9.2","qid":"HM-035"},"37":{"q":"At a shipper's dock I'm handed shipping papers for a load, and the entry lists a hazard class of 7 next to the proper shipping name and a UN identification number. Before I placard my trailer and pull out, which type of material does that class 7 designation tell me I am actually carrying?","options":["Flammable liquids, the kind found in fuel and solvent loads","Compressed and liquefied gases under pressure in the cylinders","Corrosive substances such as strong acids and caustic liquids","Radioactive materials that emit ionizing radiation in transit"],"answer":3,"explanation":"Hazard Class 7 is radioactive materials, which emit ionizing radiation in transit.","handbook":"Hazard Class 7 covers radioactive materials.","hbref":"§9.2","qid":"HM-036"},"38":{"q":"At the loading dock, a shipper hands me papers describing a material listed as 'Hazard Class 6.' Before I placard and roll out, I want to be sure I understand what kind of danger I'm hauling. What does a Class 6 designation tell me about this load?","options":["It is a poisonous (toxic) material, so I must protect against exposure and inhalation hazards","It is an oxidizer that can intensify a fire, so I must keep it far from flammables","It is a corrosive material that can burn skin and metal, so I must check for leaks","It is a non-flammable compressed gas, so I must guard against pressure release"],"answer":0,"explanation":"Hazard Class 6 covers poisonous (toxic) materials, so guard against exposure and inhalation hazards.","handbook":"Hazard Class 6 covers poisons (toxic materials).","hbref":"§9.2","qid":"HM-037"},"39":{"q":"I'm prepping a shipment and the proper shipping name on my papers is followed by the hazard class number \"5.1,\" with an ID number in the UN format. The shipper hands me a placard to hang on all four sides. Which placard correctly matches a Hazard Class 5 material?","options":["A CORROSIVE placard, because Class 5 covers acids and battery fluid that eat through metal","An OXIDIZER placard, because Class 5 covers oxidizers and organic peroxides","An EXPLOSIVES placard, because Class 5 covers blasting agents and detonators","A RADIOACTIVE placard, because Class 5 covers materials that emit radiation"],"answer":1,"explanation":"Hazard Class 5 covers oxidizers and organic peroxides, so a class 5.1 load requires an OXIDIZER placard.","handbook":"Hazard Class 5 covers oxidizers and organic peroxides.","hbref":"§9.2","qid":"HM-038"},"40":{"q":"I'm loading a single trailer with several non-bulk packages that fall under two different hazard classes, and I'd rather hang one 'DANGEROUS' placard on all four sides instead of a separate placard for each class. Under DPS HazMat rules, when is using the 'DANGEROUS' placard actually permitted?","options":["Only when every package in the load belongs to one single hazard class","Only when the shipment is exclusively boxed or palletized food-grade products","When the load contains two or more hazard classes that the rules allow to share one placard","In virtually any situation, as a convenient catch-all replacement for class-specific placards"],"answer":2,"explanation":"A single DANGEROUS placard may replace individual placards when a load carries two or more hazard classes the rules allow to be combined.","handbook":"The DANGEROUS placard may be used for certain mixed loads of different hazard classes.","hbref":"§9.3","qid":"HM-039"},"41":{"q":"I'm hauling a placarded tanker when a state trooper stops me and points to the four-digit number displayed on the placard, asking what it tells him. Based on how this number is used in an emergency, what does that four-digit ID number actually identify?","options":["The total gross weight of the loaded tank so responders know the spill volume","The hazard class division, such as 3 for flammable liquids, in numeric form","The designated HazMat route the carrier assigned me to follow to the terminal","The specific hazardous material being carried, looked up in the Emergency Response Guidebook"],"answer":3,"explanation":"The four-digit UN/NA number identifies the specific hazardous material, which responders look up in the Emergency Response Guidebook.","handbook":"The four-digit identification number identifies the specific hazardous material.","hbref":"§9.2","qid":"HM-040"},"42":{"q":"I'm reviewing the shipping papers for my load and I notice each hazardous material entry lists a packing group of I, II, or III. A newer driver asks me what that Roman numeral is actually telling us. Based on my HazMat training, what does the packing group indicate about the material?","options":["How great a danger the material poses, with Group I being the most dangerous","The hazard class number that identifies the type of hazard, such as flammable or corrosive","The minimum weight at which the load must be placarded on all four sides","The order in which the entries must be listed on the shipping paper"],"answer":0,"explanation":"The packing group ranks a material's degree of danger, with Group I being the most dangerous, Group II medium, and Group III the least.","handbook":"The packing group shows the degree of danger (I, II, or III).","hbref":"§9.2","qid":"HM-041"},"43":{"q":"I'm hauling a placarded load of corrosives across Texas when a state trooper at a weigh station asks me to point out where the 24-hour emergency response phone number is documented for my shipment. Which location should I show the officer?","options":["On the placards mounted on all four sides of the trailer","On the shipping paper kept within my reach in the cab","On my Hazardous Materials (H) endorsement card","In the Emergency Response Guidebook stored in the cab"],"answer":1,"explanation":"The 24-hour emergency response phone number is entered on the shipping paper, which must be kept within the driver's reach in the cab.","handbook":"An emergency response telephone number must be on the shipping paper.","hbref":"§9.2","qid":"HM-042"},"44":{"q":"I'm reviewing the shipping papers for a load and one entry is listed with a hazard class of 4. Before I placard and inspect, I want to confirm what kind of hazard I'm actually hauling. Which of the following correctly describes what Hazard Class 4 materials are?","options":["Flammable gases that can ignite if released from a pressurized cylinder","Flammable liquids such as gasoline that give off ignitable vapors","Flammable solids, including spontaneously combustible and dangerous-when-wet materials","Corrosive materials that can burn skin or eat through metal containers"],"answer":2,"explanation":"Hazard Class 4 covers flammable solids, including spontaneously combustible and dangerous-when-wet materials.","handbook":"Hazard Class 4 covers flammable solids.","hbref":"§9.2","qid":"HM-043"},"45":{"q":"I'm loading a Class 4.3 material flagged as \"Dangerous When Wet\" into my trailer, and rain is in the forecast for the whole route. Before I close the doors, which precaution matters MOST for this specific hazard?","options":["Keep the cargo from getting too cold, since chilling is what destabilizes these solids","Make sure the boxes are sealed against dust, because airborne particles trigger the reaction","Confirm the load is freshly painted and sealed so fumes cannot escape during transit","Keep the material completely dry and sealed, because contact with water can make it ignite"],"answer":3,"explanation":"Dangerous-when-wet materials react with water and can ignite, so they must be kept completely dry and sealed against moisture.","handbook":"Some Class 4 materials are dangerous when wet because they react with water.","hbref":"§9.2","qid":"HM-044"},"46":{"q":"I'm loading several compressed gas cylinders into my trailer for a HazMat run. Before I close the doors and pull out, which loading practice keeps me compliant and the load safe?","options":["Stand each cylinder upright and brace it so it cannot tip, roll, or shift in transit","Lay the cylinders flat and pack them loosely so they have room to settle on rough roads","Crack each valve slightly open before departure so internal pressure can equalize en route","Stack them on their sides only if the trailer floor is level, otherwise stand them up"],"answer":0,"explanation":"Compressed gas cylinders must be stood upright and braced so they cannot tip, roll, or shift during transport.","handbook":"Compressed gas cylinders must be secured and kept upright as required.","hbref":"§9.4","qid":"HM-045"},"47":{"q":"I'm loading my trailer with a Class 6.1 (poison/toxic) shipment, and I still have floor space left over. To save a second trip, I want to top off the load with other freight headed to the same terminal. Which load is the one I must NOT put in the same vehicle as the poison?","options":["A pallet of sealed cardboard cartons of auto parts","Bagged dry dog food and boxed cereal for a grocery store","A crate of mechanic's hand tools and tie-down gear","Several bags of clean, dry construction sand"],"answer":1,"explanation":"Poison and toxic (Class 6.1) materials must never be loaded with food intended for humans or animals because of contamination risk.","handbook":"Do not load poisons with food meant for humans or animals.","hbref":"§9.4","qid":"HM-046"},"48":{"q":"During my pre-trip, I find a drum on my placarded load marked Class 8, and a small amount of liquid has leaked onto the floor near it. As I decide how to handle this leak, which of the following is the MOST important hazard I must account for before going near it?","options":["The material will quickly lower the temperature inside the trailer, so I should ventilate first","The material is highly explosive on contact with air, so I should evacuate a 300-foot radius","The material can chemically burn my skin and eyes on contact, so I must avoid touching it and protect myself","The material is essentially inert in liquid form, so I can wipe it up with a rag and continue my trip"],"answer":2,"explanation":"Class 8 corrosives can chemically burn skin and eyes on contact, so the driver must avoid touching them and protect themselves.","handbook":"Corrosives can burn skin and eyes; handle them with care.","hbref":"§9.2","qid":"HM-047"},"49":{"q":"I'm about to load a shipment of Class 3 flammable liquids into my trailer. Before I begin loading, I notice the cargo space still has some leftover debris and exposed metal hardware rattling around from the last run. According to HazMat rules, which condition must the cargo space meet before I start loading?","options":["Damp throughout, since moisture lowers the chance of accidental ignition during loading","Loaded with my hand tools first so they ride secured against the front wall","Sealed and unventilated so flammable vapors cannot escape into the cab area","Clean and free of any spark-producing hazards before the freight goes in"],"answer":3,"explanation":"The cargo area must be clean and free of spark-producing hazards before flammable liquids are loaded, since loose metal can ignite vapors.","handbook":"The cargo area must be clean and free of spark hazards before loading.","hbref":"§9.4","qid":"HM-048"},"50":{"q":"I'm prepping my placarded tanker before a run and I'm mounting the diamond-shaped placards on the trailer. Besides making sure each one stays clean and readable from the direction it faces, how must I actually position each placard so it meets DPS requirements?","options":["Set it as a square turned so one point faces straight up, like a diamond","Lay it flat with one full edge sitting level along the bottom","Mount it on the driver and passenger sides only, not front or rear","Cover it with clear film until I reach the loading dock"],"answer":0,"explanation":"Placards are diamonds displayed as a square turned on point, with one corner pointing straight up, and kept clean and readable.","handbook":"Placards must be readable and turned as a square pointing up.","hbref":"§9.3","qid":"HM-049"},"51":{"q":"While loading my placarded trailer at the shipper's dock, I notice one drum of corrosive material has a fresh wet stain running down its side and the package label is partly torn. The shipper insists it is 'only a little' and tells me to load it so the run stays on schedule. What should I do?","options":["Load it as-is since the shipper prepared and certified the package, and any reporting is the carrier's job after delivery","Refuse the package and do not transport it, because the driver must reject any leaking or damaged hazardous materials shipment","Load it but bury it deep in the center of the other cargo so the leak is contained and away from the trailer walls","Load it but write a note on the shipping papers so the receiver is warned about the leak on arrival"],"answer":1,"explanation":"A driver must inspect shipments and refuse to transport any hazardous materials package that is leaking or damaged.","handbook":"Refuse any leaking or damaged hazardous materials package.","hbref":"§9.4","qid":"HM-050"},"52":{"q":"I just delivered a tanker load of a flammable liquid and the tank reads 'empty' on the gauge. Before I drive back to the terminal, I'm deciding whether I can pull the placards. Under what condition do I LEAST have grounds to remove them while the tank is still in this 'empty' state?","options":["When the tank has been steam-cleaned, purged, and certified free of any product","When the shipping papers and the carrier both confirm the tank now meets the 'cleaned and purged' standard","When the tank still contains clinging residue or hazardous vapors from the last load","When the tank has been triple-rinsed at the terminal and re-weighed empty"],"answer":2,"explanation":"A tank counts as 'empty' only when no clinging residue or hazardous vapors from the last load remain, so placards must stay on until it is truly clean.","handbook":"An empty tank may still require placards because of residue or vapors.","hbref":"§9.3","qid":"HM-051"},"53":{"q":"I'm picking up a load that the shipper has classified as hazardous WASTE, not just regular hazardous material, and I want to make sure I leave the facility with the one document that the regulations specifically require for this type of shipment. Which document MUST accompany this hazardous waste load?","options":["A standard bill of lading prepared for an ordinary commercial freight shipment","Only the Emergency Response Guidebook kept in the cab for incident reference","A Safety Data Sheet describing the chemical's properties and handling steps","A Uniform Hazardous Waste Manifest that travels with the waste shipment"],"answer":3,"explanation":"Hazardous waste shipments must travel with a Uniform Hazardous Waste Manifest that tracks the waste from generation through transport to final disposal.","handbook":"Hazardous waste requires a uniform hazardous waste manifest.","hbref":"§9.2","qid":"HM-052"},"54":{"q":"I'm hauling a placarded load of Division 1.1 explosives and I notice a cargo brace inside the trailer has worked loose. I need to tighten the fasteners before I can safely continue. Which of the following should I use to do the job?","options":["Non-sparking tools made of brass or bronze, to avoid any spark that could ignite the explosives","Standard steel tools, since they grip the fasteners tightest and finish the job fastest","Whatever heavy steel bar is closest, because more leverage means I am done sooner","Any tool painted with a red safety marking, since red-marked tools are rated for hazmat work"],"answer":0,"explanation":"Work near Class 1 explosives must be done with non-sparking brass or bronze tools, since a single metal-on-metal spark could ignite the explosives.","handbook":"Use non-sparking tools near explosives.","hbref":"§9.4","qid":"HM-053"},"55":{"q":"I placarded all four sides of my trailer at the loading dock and confirmed each one was readable before pulling out. Three hours into a long haul, I stop for fuel and tell my co-driver the placards are 'already handled.' Regarding when I am responsible for verifying placards are in place, which statement is correct?","options":["My responsibility ends once I confirm the placards at the dock, since the pre-trip inspection is when placarding is checked.","I must verify the placards are in place both before the trip and again during the trip as I travel.","I only need to recheck the placards when I arrive at the delivery point to satisfy the receiver.","Placarding is the shipper's duty, so verifying it en route is not part of my driving responsibility."],"answer":1,"explanation":"You must make sure placards are in place both before the trip and again during it, since they can loosen, fall off, or be obscured while driving.","handbook":"Check that placards are in place before and during the trip.","hbref":"§9.3","qid":"HM-054"},"56":{"q":"I'm hauling a placarded load of corrosives when one of the drums starts leaking onto the shoulder. As I dig the shipping papers out of my reach on the seat, I notice the shipper has clipped emergency response information to them. When the fire department and a hazmat crew arrive on scene, what is the PRIMARY purpose of that shipper's emergency information?","options":["It lists the retail value of the cargo so the responders can prioritize which loads to protect first","It tells me which fuel grade and tire pressure the carrier prefers for long hauls in hot weather","It gives the responders the details they need to safely handle the spill or fire from this specific material","It certifies that I completed my TSA background check and hold a valid H endorsement to drive"],"answer":2,"explanation":"Emergency response information accompanies the shipping papers to give responders the specific data needed to safely handle a spill, leak, or fire from that material.","handbook":"The shipper's emergency information helps responders handle spills and fires.","hbref":"§9.5","qid":"HM-055"},"57":{"q":"I'm loading several packages of Class 7 radioactive material, and the shipper points to a number printed on each package's label and tells me I must add these figures together and keep the total within a set limit for my vehicle. What is the purpose of this number I'm being told to track?","options":["It is a color code that tells me which side of the trailer to place the matching placard on","It is a speed rating that caps how fast I may drive while the radioactive load is aboard","It is a route index that tells me which designated highways I am permitted to use","It is a transport index that limits the total radiation exposure allowed on my vehicle"],"answer":3,"explanation":"Each radioactive package carries a transport index, and the driver must sum these indices and keep the total under a set limit to control radiation exposure on the vehicle.","handbook":"Radioactive shipments use a transport index to limit exposure.","hbref":"§9.2","qid":"HM-056"},"58":{"q":"I'm hauling a placarded load of corrosives when a wheel-bearing problem forces me to pull over and wait for a replacement tractor on the shoulder. The dispatcher radios that another company truck is nearby and suggests I pump the product over to it so the delivery isn't late. Which response best fits proper HazMat practice?","options":["Refuse the on-road transfer; hazmat should only be moved between vehicles in a genuine emergency, so I should wait for the repair or proper arrangements","Go ahead and transfer the load, since keeping the delivery on schedule is the carrier's first priority","Transfer it only after re-placarding both vehicles, which makes a roadside transfer fully acceptable","Make the transfer because the load is already stopped and parked safely off the traveled part of the road"],"answer":0,"explanation":"Hazmat should be transferred between vehicles only in a genuine emergency, so a routine breakdown or late delivery is no reason for a roadside transfer.","handbook":"Do not transfer hazmat between vehicles on the road except in an emergency.","hbref":"§9.4","qid":"HM-057"},"59":{"q":"I'm loading a shipment that the shipper's papers identify as a marine pollutant before my run to the port. As the driver completing my inspection, which of these conditions must be satisfied before I agree to transport this load?","options":["The marine pollutant labels may be covered until I reach the marine terminal","The package must display the required marine pollutant markings before I haul it","The marine pollutant markings can be left off since it travels by road first","The container must be hidden from view to keep the load secure on the road"],"answer":1,"explanation":"A marine pollutant must display the required markings on the package before transport, and a driver must refuse any improperly marked hazmat shipment.","handbook":"Marine pollutants must be marked as required.","hbref":"§9.3","qid":"HM-058"},"63":{"q":"I'm doing my pre-trip inspection on a tractor-trailer placarded for a flammable-liquid load. I want to make sure my fire extinguisher meets the federal requirement before I roll. Which of these would actually satisfy the rule?","options":["The extinguisher can stay locked inside the sealed trailer with the cargo, since that's where a fire would most likely start.","A fully charged extinguisher is fine even if it's buried behind cargo straps, as long as it's the right rating for the load.","The extinguisher must be properly rated for the load, fully charged, and mounted where I can reach it quickly.","Any small charged extinguisher works, because the rating only matters for the receiver's dock equipment, not the truck."],"answer":2,"explanation":"A placarded vehicle's fire extinguisher must be properly rated for the load, fully charged, and mounted where the driver can reach it quickly.","handbook":"A vehicle carrying placarded hazmat must have a properly rated, charged fire extinguisher.","hbref":"§9.5","qid":"HM-059"},"67":{"q":"You are hauling a placarded load of flammable liquid and pull into a rest area for your 2-hour tire check. You find that one of the tires on your trailer is hot to the touch and clearly overheating. Which of the following is the correct action to take?","options":["Pour water over the hot tire to cool it quickly, then continue to your delivery so the shipment stays on schedule.","Add air to bring the hot tire back up to its proper pressure, then continue driving the planned route.","Leave the tire in place and continue driving, since some heat buildup is normal on a fully loaded placarded trailer.","Remove the overheated tire and place it a safe distance from the vehicle, then check it before going on."],"answer":3,"explanation":"If a tire overheats on a placarded load it is a fire hazard, so remove it, place it a safe distance from the vehicle, and check it before continuing.","handbook":"An overheated tire on a placarded vehicle must be removed and placed a safe distance away.","hbref":"§9.5","qid":"HM-060"},"69":{"q":"I just dropped off my last hazmat skid at the consignee, and the trailer is now completely empty and residue-free, but the four placards are still bolted on. I'm about to deadhead back to the yard on the interstate. Which action keeps me legal for this empty run?","options":["Remove or cover the placards now, since the trailer no longer carries a load that requires them.","Leave the placards displayed the whole way back, because a placarded trailer is always treated as safer by other drivers.","Leave them up only until I reach the first railroad crossing, then take them down at the stop.","It makes no real difference either way, so I can leave the placards on the empty trailer if it saves time."],"answer":0,"explanation":"Placards must be removed or covered once the vehicle no longer carries a load that legally requires them, so they don't misrepresent the cargo.","handbook":"Remove or cover placards when the vehicle no longer requires them.","hbref":"§9.3","qid":"HM-061"},"70":{"q":"I'm pre-tripping a placarded load and checking the shipping paper against the package before I sign for it. The entry already shows the proper shipping name and the hazard class. To be complete and legal, which remaining piece of information MUST appear in that same entry?","options":["The total mileage I'll cover on my designated HazMat route","The identification (ID) number (UN/NA) for the material","The 24-hour CHEMTREC phone number for the carrier","The packing group letter stamped on the outer drum"],"answer":1,"explanation":"A complete shipping paper entry lists the proper shipping name, hazard class, and the UN/NA identification number in that order.","handbook":"Hazmat shipping papers list the proper shipping name, hazard class, and ID number.","hbref":"§9.2","qid":"HM-062"},"71":{"q":"I'm stopped at a weigh station and the inspector points to the orange panel below the diamond placard on my trailer, which shows the bold black number \"1203.\" He asks me what that four-digit number is telling responders. Which is the correct explanation?","options":["It is the gross weight, in pounds, of the hazardous material loaded in that compartment","It is the hazard class division code that ranks how dangerous the load is from 1 to 9","It is the UN/NA identification number that names the specific material being hauled","It is the emergency telephone code responders dial to reach CHEMTREC about the load"],"answer":2,"explanation":"A four-digit number on a placard or orange panel is the UN/NA identification number that names the specific material being hauled.","handbook":"The 4-digit ID number on a placard identifies the specific material.","hbref":"§9.3","qid":"HM-063"},"72":{"q":"A freight broker offers me a load of corrosive material that will require placards on all four sides of my trailer. I already carry my CDL with the Tanker (N) and Doubles/Triples (T) endorsements, and I just renewed my medical card. Before I can legally accept and haul this shipment, what must I have completed?","options":["Nothing further — because my load is corrosive (Class 8) and not explosive, the placards alone satisfy the legal requirement and no special endorsement is needed.","Only the Tanker (N) endorsement, which I already hold, since any placarded material is considered a bulk liquid hazard under federal rules.","A current Passenger (P) endorsement, because hauling a regulated load that affects public safety is treated the same as transporting passengers.","The HazMat (H) endorsement, which requires passing a TSA security threat assessment with fingerprinting before I may transport any placarded hazardous material."],"answer":3,"explanation":"Transporting any placarded hazardous material requires the HazMat (H) endorsement, which mandates a TSA security threat assessment with fingerprinting.","handbook":"Transporting placardable hazmat requires the HazMat (H) endorsement.","hbref":"§9.1","qid":"HM-064"},"73":{"q":"I already hold a Class A CDL and passed my road test, but I want to start hauling placardable hazardous materials. Besides passing the written HazMat knowledge test, what is the ONE additional requirement I must satisfy before the H endorsement can be added to my license?","options":["I must complete a TSA security threat assessment, which includes fingerprinting and a background check","I must pass a second, separate road test in a placarded vehicle","I must first obtain my tank vehicle (N) endorsement as a prerequisite","I must add the doubles/triples (T) endorsement to my license"],"answer":0,"explanation":"The HazMat (H) endorsement uniquely requires applicants to clear a TSA security threat assessment that includes fingerprinting and a background check.","handbook":"The HazMat endorsement requires a TSA background check.","hbref":"§9.1","qid":"HM-065"},"76":{"q":"I'm parked at a rest area with my placarded load of flammable liquid. A fellow driver walks up wanting to chat and lights a cigarette as he approaches my rig. To keep us safe, what is the closest he should be allowed to smoke near my placarded vehicle?","options":["No closer than about 15 feet, the same buffer used before railroad tracks","No closer than about 25 feet from the placarded vehicle","No closer than about 5 feet, the same as the parking buffer from the road","Anywhere outside the cab is acceptable since the load is sealed"],"answer":1,"explanation":"Smoking is prohibited within about 25 feet of a placarded vehicle carrying explosives, oxidizers, or flammables.","handbook":"Do not smoke within 25 feet of a placarded hazmat vehicle.","hbref":"§9.5","qid":"HM-066"},"77":{"q":"I'm picking up a load and the shipping paper lists the material with a hazard class of 7. Before I placard and inspect the packages, I want to confirm what kind of hazard I'll actually be hauling. Based on the hazard class shown, what is in my trailer?","options":["A flammable liquid such as gasoline or diesel fuel","A corrosive liquid that can burn skin and damage metal","A radioactive material","A compressed gas under high pressure"],"answer":2,"explanation":"In the federal hazard class system, Class 7 always means radioactive materials.","handbook":"Class 7 hazardous materials are radioactive materials.","hbref":"§9.3","qid":"HM-067"},"78":{"q":"I'm prepping a placarded load and my shipping paper lists the cargo's hazard class as 'Class 1.' To park and handle it correctly, I need to know what kind of material I'm actually hauling. A Class 1 designation tells me the load is:","options":["Flammable liquids, like the gasoline or diesel that fall under Class 3","Corrosive liquids, the acids and bases grouped under Class 8","Compressed or flammable gases, which belong to Class 2","Explosives, the materials that fall under Class 1"],"answer":3,"explanation":"In the fixed hazard class numbering, Class 1 always means explosives.","handbook":"Class 1 hazardous materials are explosives.","hbref":"§9.3","qid":"HM-068"},"79":{"q":"I'm reviewing the shipping papers for my load and one entry lists the hazard class as \"2.1\" with a UN number for the material. Based on the hazard class numbering system, what kind of material am I actually hauling?","options":["A flammable gas, because Class 2 covers gases (with 2.1 being flammable)","A flammable liquid, because that's the most common flammable cargo class","An explosive, because the low class number means it ignites violently","A radioactive material, since it carries a special UN identification number"],"answer":0,"explanation":"Class 2 covers gases, and division 2.1 specifically denotes a flammable gas.","handbook":"Class 2 hazardous materials are gases.","hbref":"§9.3","qid":"HM-069"},"80":{"q":"I'm picking up a shipment and the shipping paper lists the entry as \"Acetone, 3, UN1090.\" The dispatcher asks me to confirm what kind of hazard that middle number tells me I'm hauling so I grab the right placards. Based on the hazard class shown, what am I carrying?","options":["A flammable solid that can ignite through friction","A flammable liquid that gives off ignitable vapors","A flammable compressed gas under pressure","An oxidizing agent that intensifies a fire"],"answer":1,"explanation":"Class 3 always means flammable liquids, which give off ignitable vapors.","handbook":"Class 3 hazardous materials are flammable liquids.","hbref":"§9.3","qid":"HM-070"},"81":{"q":"I'm prepping shipping papers for a load and the hazard class on the entry reads \"Class 4.\" Before I placard, I want to confirm what general category this material falls under so I match the right placard. Under the hazard class system, a Class 4 material is identified as which of the following?","options":["A corrosive liquid that can damage skin and metal","A flammable liquid such as gasoline or fuel oil","A flammable solid, including spontaneously combustible and dangerous-when-wet materials","An explosive item that detonates under shock or heat"],"answer":2,"explanation":"Class 4 covers flammable solids, including spontaneously combustible and dangerous-when-wet materials.","handbook":"Class 4 hazardous materials are flammable solids.","hbref":"§9.3","qid":"HM-071"},"82":{"q":"I'm reviewing the shipping papers for my next load and the entry lists a Class 5 hazardous material in the hazard-class column. Before I accept and placard the shipment, I need to confirm what kind of substance I'll actually be hauling. Which description correctly matches a Class 5 material?","options":["Flammable liquids such as gasoline, diesel additives, and solvents","Corrosive materials such as battery acid and other strong liquids","Poisons and toxic liquids that present an inhalation hazard","Oxidizers and organic peroxides"],"answer":3,"explanation":"Class 5 is the oxidizers and organic peroxides group.","handbook":"Class 5 hazardous materials are oxidizers and organic peroxides.","hbref":"§9.3","qid":"HM-072"},"83":{"q":"I'm reviewing the shipping papers for a load before I leave the terminal, and one entry is marked as Class 6. The shipper hasn't written out the proper shipping name yet and asks me to confirm what kind of material a Class 6 placard covers so the paperwork matches the hazard. Which description correctly identifies what falls under Class 6?","options":["Poisons (toxic) and infectious substances","Flammable liquids such as gasoline and common solvents","Corrosive liquids that can burn skin and metal","Oxidizers and organic peroxides that intensify fire"],"answer":0,"explanation":"Class 6 covers poison (toxic) substances and infectious substances.","handbook":"Class 6 hazardous materials are poisons and infectious substances.","hbref":"§9.3","qid":"HM-073"},"84":{"q":"I'm doing my pre-trip and reviewing the shipping papers for a load that lists a Class 8 hazard. Before I handle the containers and choose the right gloves and eye protection, I need to know what kind of danger this material actually presents. Which statement correctly describes what a Class 8 material is?","options":["It is a flammable liquid that can ignite from a spark, so my main concern is keeping all ignition sources away from the load.","It is a corrosive that can chemically burn skin, eyes, and metal, so my main concern is preventing contact and protecting surfaces.","It is a compressed gas under pressure that can rupture violently, so my main concern is keeping the cylinders cool and secured.","It is a radioactive material that emits harmful radiation, so my main concern is limiting my exposure time near the load."],"answer":1,"explanation":"Class 8 is corrosives, which chemically burn skin, eyes, and metal on contact, so preventing contact and protecting surfaces is the priority.","handbook":"Class 8 hazardous materials are corrosives.","hbref":"§9.3","qid":"HM-074"},"85":{"q":"I'm reviewing the shipping papers for a load and see an entry classified as a Class 9 hazardous material. My trainer asks me what that classification actually tells me about the cargo. Which statement correctly describes what a Class 9 designation means?","options":["It identifies a Division 2.3 product, meaning the load is a poison gas requiring placards in any amount","It identifies a flammable liquid, the same category covered by hazard Class 3 on the shipping paper","It identifies a miscellaneous dangerous good that does not fit neatly into the other eight hazard classes","It identifies an explosive item, the same family of cargo covered by hazard Class 1 placarding rules"],"answer":2,"explanation":"Class 9 is the miscellaneous catch-all for dangerous goods that don't fit any of the other eight hazard classes.","handbook":"Class 9 hazardous materials are miscellaneous dangerous goods.","hbref":"§9.3","qid":"HM-075"},"86":{"q":"I'm hauling a placardable load of corrosives and a state trooper waves me into a weigh station. He tells me he could only see one placard from where he was standing and asks me to confirm how my rig is supposed to be placarded. Which statement correctly describes proper placarding?","options":["Placards are required only on the rear of the trailer, since that's what following traffic and inspectors behind me read","A single placard on the driver's side is sufficient as long as it is readable from the direction it faces","Placards belong on the front of the tractor and the rear of the trailer only, so they are visible head-on and from behind","Placards must be displayed on all four sides of the vehicle, each readable from the direction it faces"],"answer":3,"explanation":"Placards must be displayed on all four sides of the vehicle, each readable from the direction it faces.","handbook":"Hazmat placards are placed on all four sides of the vehicle.","hbref":"§9.3","qid":"HM-076"},"87":{"q":"I'm doing my pre-trip inspection and need to confirm the warning markings on my trailer are correct before I haul a placardable HazMat load. When I look at a properly displayed HazMat placard on each side of the unit, what overall shape should I expect it to be?","options":["A diamond, which is a square turned to rest on one of its points (corner)","A triangle, the same shape as the reflective warning triangles I carry","A rectangle that is wider than it is tall, like the ID number panel","A circle bordered with a colored ring, like a road sign symbol"],"answer":0,"explanation":"A HazMat placard is diamond-shaped — a square set on point so it rests on one corner.","handbook":"A hazmat placard is diamond-shaped.","hbref":"§9.3","qid":"HM-077"},"88":{"q":"I'm hauling a placarded load and notice during my pre-trip that the placard on the right side of my trailer is smeared with road grime and partly covered by a strap hanger, though the other three placards are clean. Before I drive, what does Texas DPS require me to do about that right-side placard?","options":["Nothing extra, because as long as the front and rear placards stay clear, the side placards are not regulated for visibility","Clean it and reposition the strap so the placard is readable and not obscured, since placards on all four sides must be visible from the direction they face","Remove that one placard entirely, because a partly dirty placard is treated as no placard and the remaining three still cover the load","Leave it as is and simply note the condition on my shipping papers so an inspector knows I am aware of it"],"answer":1,"explanation":"Since placards on all four sides must be readable from the direction they face, a dirty or obscured placard must be cleaned and cleared before driving.","handbook":"Placards must be readable and not obscured.","hbref":"§9.3","qid":"HM-078"},"89":{"q":"I'm loading mixed freight and one pallet is a hazardous material listed in Table 2 of the placarding rules. A coworker tells me, 'Hazmat is hazmat — the second any of it goes on the trailer, you have to placard.' Before I hang anything on the four sides, how should I decide whether placards are actually required for this load?","options":["Any amount triggers placards, so the moment a single hazmat package is aboard I must placard all four sides","Placards are based only on the packaging, so I placard solely because food and non-food items are loaded together","It depends on the material's class and quantity — some classes require placards in any amount, while these Table 2 materials require them only at 1,001 lb or more aggregate gross weight","Placards are never legally required for a mixed freight load, so I can skip them entirely on this trip"],"answer":2,"explanation":"Placarding depends on class and quantity — some classes need placards in any amount, while Table 2 materials need them only at 1,001 lb or more aggregate gross weight.","handbook":"Placards are required at a certain threshold amount or hazard class.","hbref":"§9.3","qid":"HM-079"},"90":{"q":"I'm loading my trailer at a dock with several non-bulk packages from different Table 2 hazard classes. No single hazard class on board adds up to 1,001 pounds, but the combined Table 2 freight crosses that threshold. A coworker says I can run one DANGEROUS placard for the whole mixed load instead of a separate placard for each class. Under the placarding rules, when is using the DANGEROUS placard actually permitted?","options":["Only when the entire trailer is a single full load of one Table 2 material weighing 1,001 pounds or more","Never, because each hazard class on board must always display its own specific placard with no exceptions","Only when the load is made up of Class 1 explosives that require placarding in any amount","When I'm hauling certain non-bulk loads made up of two or more Table 2 hazard classes, the DANGEROUS placard may be used for that mixed small load"],"answer":3,"explanation":"The DANGEROUS placard may be used for a non-bulk load mixing two or more Table 2 hazard classes in place of separate class placards.","handbook":"The DANGEROUS placard may be used for certain mixed loads.","hbref":"§9.3","qid":"HM-080"},"91":{"q":"I'm loading a Class 3 flammable liquid and the only placards left in my supply box are leftover Class 8 (corrosive) placards from my last run. Before I roll out, which statement correctly reflects what I'm required to do about the placards on my vehicle?","options":["The placards I display must identify the hazard class of the material I'm actually hauling, so I cannot use the Class 8 placards for a Class 3 load.","Any DOT-style placard is acceptable as long as it's diamond-shaped and displayed on all four sides of the vehicle.","I may run the Class 8 placards as long as I keep the correct Class 3 shipping papers within reach in the cab.","Placards only need to match the load when I'm crossing a state line, so the Class 8 placards are fine for an in-state run."],"answer":0,"explanation":"Placards must match the actual hazard class of the material you are hauling, so a Class 3 load needs Class 3 placards.","handbook":"A placard must match the material being hauled.","hbref":"§9.3","qid":"HM-081"},"92":{"q":"I'm finishing the pre-trip on my van trailer loaded with a placardable Class 3 flammable liquid, and I want to confirm my placards are displayed correctly before I roll. Which of these conditions must be true for me to legally start the trip?","options":["Placards on the front and rear only, since those are the sides other drivers actually read","A placard on each of all four sides of the vehicle, secured so each one is readable from the direction it faces","Placards on both sides of the trailer plus a copy of the shipping papers taped beside each one","One placard mounted flat on the trailer roof so it stays visible and protected from road spray"],"answer":1,"explanation":"A placarded HazMat vehicle must display a placard on all four sides, each secured and readable from the direction it faces.","handbook":"Placards must be on all four sides, secure and readable, before driving.","hbref":"§9.3","qid":"HM-082"},"93":{"q":"During my pre-trip inspection of a placarded load, I notice one of the four required placards is so faded by the sun that the hazard class number is hard to read, though I can still barely make it out. What is the correct action before I begin the trip?","options":["Leave it in place, since the placard is still faintly legible if you look closely","Cover the faded placard with clear tape to protect it from further fading","Replace the faded placard with a new, fully readable one before starting the trip","Proceed and replace it at the next stop, as long as the other three placards are clear"],"answer":2,"explanation":"A faded or damaged placard must be replaced with a fully readable one before the trip begins.","handbook":"Replace a faded or damaged placard before the trip.","hbref":"§9.3","qid":"HM-083"},"94":{"q":"I'm picking up a placarded load and the shipper hands me the shipping papers. Before I sign and pull out, what must I confirm about those papers?","options":["That they list only the proper shipping name, so the hazard class and ID number can be added later","That a copy was left at the terminal, since the original is optional on short in-state hauls","That at least one entry is filled in, even if a few HazMat details are still missing","That every HazMat entry is accurate and complete before I transport the load"],"answer":3,"explanation":"HazMat shipping papers must be accurate and complete before you transport the load, with each entry showing the proper shipping name, hazard class, and ID number.","handbook":"Hazmat shipping papers must be accurate and complete.","hbref":"§9.2","qid":"HM-084"},"95":{"q":"I'm rolling down the interstate hauling a placarded load of corrosives, seat belt buckled. A trooper could pull me over at any mile marker. According to Texas DPS rules, where must my hazmat shipping papers be RIGHT NOW while I'm driving?","options":["Within my reach with the seat belt on, or in a pouch on the driver's door, sitting on top of my other papers","Latched inside the trailer with the freight so they stay clean and travel with the actual cargo","Tucked into the glove box on the passenger side so they don't slide off the seat in a hard stop","Held only by the shipper, who faxes a copy to the carrier's dispatch before each run"],"answer":0,"explanation":"While driving, keep HazMat shipping papers within reach with the seat belt on, or in the driver's door pouch, on top of your other papers.","handbook":"On the road, keep hazmat papers within reach or on the seat.","hbref":"§9.2","qid":"HM-085"},"96":{"q":"I'm loading a placarded shipment and reviewing the shipping paper before I leave the dock. The hazardous material is mixed in with several non-hazardous freight entries on the same page. For the paper to be acceptable, how must the HazMat entry appear among the other items?","options":["It can be entered anywhere among the freight as long as the proper shipping name, hazard class, and ID number are all present","It must be listed first, or clearly identified by highlighting or an 'X' in the HM column so it stands out from the non-hazardous freight","It must be placed last on the page so the total weight of the non-hazardous freight is tallied above it","It only needs to be marked separately if the shipper or the receiving facility specifically requests it"],"answer":1,"explanation":"On a mixed shipping paper, the HazMat entry must stand out by being listed first or marked with highlighting or an 'X' in the HM column.","handbook":"Hazmat must be listed first or clearly highlighted on the shipping paper.","hbref":"§9.2","qid":"HM-086"},"97":{"q":"I'm hauling a placarded load of corrosives when a fitting on one of my drums starts leaking and fumes drift across the shoulder. I pull over safely, warn others, and reach for the Emergency Response Guidebook (ERG) I keep in the cab. Which of the following is the ERG actually designed to help me do at this moment?","options":["Identify the fastest detour that avoids weigh stations and toll roads ahead","Confirm the proper shipping name, hazard class, and ID number for my paperwork","Determine the initial isolation distance and protective actions for the spilled material","Verify which placards are required and on which sides of the trailer they belong"],"answer":2,"explanation":"The Emergency Response Guidebook gives the initial isolation distance and protective actions for a spilled or leaking material.","handbook":"The ERG helps you respond to a hazmat incident.","hbref":"§9.2","qid":"HM-087"},"98":{"q":"I'm picking up a placarded load of corrosives, and the shipping papers in my hand list the proper shipping name, hazard class, and ID number with a signed certification statement at the bottom. As the CDL driver, I know my job is to inspect the load, refuse anything leaking, placard the vehicle, and keep these papers within reach. But when I check that signed line certifying the material is described correctly and properly prepared for transport, whose certification am I actually looking at?","options":["The carrier's, since the trucking company dispatches the load and is responsible for reporting any incident that happens during transport","Mine as the driver, since I'm the one who inspects the shipment, placards the truck, and keeps the papers within my reach while driving","No one's in particular, because the certification line is just a formality and the real legal responsibility rests entirely with whoever receives the load","The shipper's, because the shipper classifies, packages, marks, and prepares the shipping papers, then certifies the material is described correctly"],"answer":3,"explanation":"The shipper classifies, packages, marks, and prepares the shipping papers, then certifies that the material is described correctly.","handbook":"The shipper certifies that the hazmat is described correctly.","hbref":"§9.2","qid":"HM-088"},"99":{"q":"I'm at the loading dock about to accept a drum of corrosive liquid, and before I sign the shipping paper I want to confirm the HazMat entry is described correctly. Which set of details must actually appear on that line for the entry to be a proper HazMat description?","options":["The proper shipping name, the hazard class, and the identification (UN/NA) number, listed in that sequence","The hazard class label color, the placard wording, and the four-digit number shown on the placard","The retail value of the load, its total gross weight, and the destination ZIP code","An 'X' in the HM column by itself, since that mark is all that legally identifies a hazardous entry"],"answer":0,"explanation":"A HazMat entry must list the proper shipping name, the hazard class, and the identification (UN/NA) number in that exact sequence.","handbook":"The shipping paper shows the proper name, hazard class, and ID number.","hbref":"§9.2","qid":"HM-089"},"100":{"q":"I'm hauling a placarded load of corrosives and pull into a rest area to use the restroom. I'll be leaving the cab and walking away from my truck for a few minutes. According to HazMat rules, where should I leave my shipping papers while I'm out of the vehicle?","options":["Folded inside the glove box, latched shut so they stay out of sight","On the driver's seat or in the driver's door pouch","Locked in the trailer with the load they describe","Tucked behind the sun visor on the passenger side"],"answer":1,"explanation":"When out of the truck, leave HazMat shipping papers on the driver's seat or in the driver's door pouch so responders can find them quickly.","handbook":"When you leave the cab, leave hazmat papers in a door pouch or on the seat.","hbref":"§9.2","qid":"HM-090"},"101":{"q":"I'm at a weigh station with a placarded load, and the inspector asks me to point out, from the shipping papers alone, the total amount of hazardous material I'm hauling. Other than the proper shipping name, hazard class, and ID number, which value will my shipping papers actually show for that entry?","options":["The combined weight of all my truck's axles","The recommended cold tire pressure for the load","The total quantity of the hazardous material being shipped","The engine hours logged since the trip began"],"answer":2,"explanation":"Shipping papers list the total quantity of hazardous material for each entry, so the amount on board comes directly from that figure.","handbook":"Shipping papers list the total quantity of hazmat.","hbref":"§9.2","qid":"HM-091"},"102":{"q":"I've backed my placarded tanker up to the dock and the shipper's crew is ready to start pumping product into the trailer. Before I let any loading begin, which action is the most important for me to take to keep the vehicle from moving on its own?","options":["Leave the engine running at a fast idle so I have full air pressure available the whole time","Pull the placards off the front and rear so the dock crew can reach the fill valves more easily","Open the trailer's discharge and vent valves first so pressure can equalize during the transfer","Set the parking brakes and place chocks against the wheels so the rig stays put while we load"],"answer":3,"explanation":"Before loading or unloading HazMat you must set the parking brakes and chock the wheels so the vehicle cannot roll.","handbook":"Before loading or unloading hazmat, set the brakes and chock the wheels.","hbref":"§9.5","qid":"HM-092"},"103":{"q":"I'm at a terminal loading drums of a Class 3 flammable liquid onto my placarded trailer. A coworker walks up with a lit cigarette and asks if it's okay to finish his smoke while he helps me load. Which response is correct?","options":["No — smoking is not allowed near the loading of flammables, and he must keep any lit cigarette well clear of the operation","Yes — smoking is fine as long as he stays at least 5 feet back from the open trailer doors","Yes — the rule only restricts open flames like flares or fusees, not cigarettes","Yes — smoking is permitted because the drums are still sealed until they are loaded and placarded"],"answer":0,"explanation":"Smoking is prohibited near the loading of flammables, so any lit cigarette must be kept well clear of the operation.","handbook":"Smoking near hazmat loading is prohibited.","hbref":"§9.5","qid":"HM-093"},"104":{"q":"I'm at a depot floor-loading boxes of Division 1.1 explosives into my trailer by hand. As I prepare the cargo area and move each box, which practice keeps the load safest and complies with HazMat handling rules?","options":["Drag the cases across the bare steel floor and pull them snug using a sharpened metal cargo hook","Place a non-sparking floor lining in the cargo space and set each box down gently, handling every case with care","Skip any floor covering and toss the cases into place quickly so the doors can be sealed sooner","Roll a forklift directly over the loaded cases to compress them tight before closing the trailer"],"answer":1,"explanation":"Division 1.1 explosives need a non-sparking floor lining and gentle handling of every case to avoid friction, sparks, or impact that could detonate the load.","handbook":"When loading explosives, use a floor lining and handle with care.","hbref":"§9.5","qid":"HM-094"},"105":{"q":"I'm loading boxes of corrosive material into my dry van for a HazMat run. The packages are properly marked and my placards are up. As I arrange the load in the cargo area, which of these BEST describes how I should handle the containers themselves?","options":["Stack them up loosely toward the front so they settle into place during the first few stops","Place them near the doors unstrapped so emergency responders can reach them fast","Block, brace, and secure them so they cannot shift, slide, or fall while the truck is moving","Suspend them from the upper rails of the trailer to keep them off the floor entirely"],"answer":2,"explanation":"Containers of hazardous materials must be blocked, braced, and secured so they cannot shift, slide, or fall during transport.","handbook":"Hazmat containers must be secured so they cannot shift.","hbref":"§9.5","qid":"HM-095"},"106":{"q":"I'm at a bulk terminal loading a tanker with gasoline, a Class 3 flammable liquid. The transfer line connects to the terminal's own pump, so I won't need my truck's engine to move the product. As the hoses are hooked up and product starts to flow, what should I do with my engine?","options":["Keep it idling in low gear so I can pull forward the moment loading finishes","Let it run at fast idle to keep air pressure and the alternator charging the batteries","Leave it running only if the terminal staff tell me the area is well ventilated","Shut the engine off, since I don't need it to power a product pump during this transfer"],"answer":3,"explanation":"When loading or unloading flammable liquids the engine must be off unless it is needed to run a product pump.","handbook":"Turn off the engine when loading flammable liquids unless needed for a pump.","hbref":"§9.5","qid":"HM-096"},"107":{"q":"I'm at a terminal about to transfer a Class 3 flammable liquid from my cargo tank into a storage tank. Before I open any valve or start the flow, I connect a bonding wire between the truck and the storage tank and attach a ground. What is the PRIMARY reason I do this before handling the flammable liquid?","options":["To equalize the electrical charge between the truck and the tank so a static spark cannot form and ignite the vapors","To create a backup electrical path that keeps the truck's lights and gauges powered while the engine is shut off","To reduce the temperature of the liquid as it flows so the fuel does not expand and overflow the receiving tank","To slow the flow rate so less product is lost to evaporation and spillage during the transfer"],"answer":0,"explanation":"Bonding and grounding equalize the electrical charge between truck and tank so a static spark cannot form and ignite the flammable vapors.","handbook":"Bond and ground flammable liquids to prevent a static spark.","hbref":"§9.5","qid":"HM-097"},"108":{"q":"I'm hauling a placarded load of corrosives on a 380-mile run with two scheduled rest stops. I walked around the trailer and checked all my tie-downs and bracing in the yard before I pulled out, and everything was secure. To stay compliant with HazMat cargo rules, what does the regulation require me to do about inspecting the cargo and its securing devices for the rest of this trip?","options":["Nothing more is required once the pre-trip yard inspection confirms the cargo and tie-downs are secure, since re-checking en route is only mandatory for oversized or overweight loads.","Keep inspecting the cargo and its securing devices both before the trip and again at points during the trip, not just once at the start.","Re-inspect the securing devices only at the final delivery point, because checks made before unloading are the ones that legally matter for cargo claims.","Repeat a full cargo and tie-down inspection on a strict annual schedule that the carrier documents, separate from any single trip's pre-trip walkaround."],"answer":1,"explanation":"You must inspect the cargo and its securing devices both before the trip and again at points during it, not just once at the start.","handbook":"Inspect hazmat cargo and securing devices before and during the trip.","hbref":"§9.5","qid":"HM-098"},"109":{"q":"I'm hauling a placarded load of Division 1.1 explosives and a strap has come loose, so I need to reposition a crate in the trailer. Which of the following is the MOST important rule about the tools I use to do this work near the explosives?","options":["The tools should be made of heavy steel so they grip the crates firmly without slipping","The tools should be left in the cab and the crate moved by hand to avoid any contact","The tools must not be capable of causing sparks or damaging the explosive packages","The tools should have a sharp edge so I can quickly cut and re-secure the loose strap"],"answer":2,"explanation":"Tools used near explosives must be non-sparking and incapable of damaging the packages, since sparks or impact can trigger detonation.","handbook":"Tools used near explosives must not cause sparks or damage.","hbref":"§9.5","qid":"HM-099"},"110":{"q":"I'm at a delivery dock unloading a placarded trailer of Class 3 flammable liquid in drums. A forklift operator wants to idle his propane-powered lift right beside the open trailer doors, a worker nearby is about to light a cigarette, and the dock supervisor asks me where open flames and running engines should be during the operation. What is the correct instruction I should give?","options":["Keep ignition sources right at the trailer doors so the forklift can work efficiently and finish the unloading faster","Allow smoking and idling engines as long as they stay at least 5 feet from the traveled part of the roadway","Position the running forklift inside the trailer to speed loading, since the drums are sealed and won't ignite","Keep all ignition sources, including open flames and running engines, well away from the unloading area"],"answer":3,"explanation":"When loading or unloading flammable materials, keep all ignition sources, including open flames and running engines, well away from the area.","handbook":"Keep ignition sources well away when unloading hazmat.","hbref":"§9.5","qid":"HM-100"},"111":{"q":"I'm loading a placardable HazMat shipment at a customer's dock. As I inspect the packages before signing for them, which condition tells me I can legally accept and transport this load?","options":["Every package is properly labeled and shows no signs of leaking","Each package has been opened so I can confirm the contents myself","The packages are painted a bright color so they stand out to other drivers","The packages are stacked high above the cab where I can watch them"],"answer":0,"explanation":"A HazMat shipment may be accepted only when every package is properly labeled and shows no sign of leaking.","handbook":"Hazmat packages must be properly labeled and not leaking.","hbref":"§9.5","qid":"HM-101"},"112":{"q":"I'm loading a mixed trailer at a distribution dock. My shipping papers list several drums of a Class 6.1 poison (toxic) material that I'll be hauling cross-country. The dock supervisor wants to fill the remaining trailer space to save a second trip. Of the loads he's offering, which one am I prohibited from loading alongside my poison drums?","options":["Pallets of bagged agricultural fertilizer headed to the same region","Crates of packaged human food and animal feed for a grocery warehouse","Additional sealed drums of the same Class 6.1 poison material","Boxes of empty, unlabeled plastic shipping containers"],"answer":1,"explanation":"Class 6.1 poison (toxic) materials must never be loaded or transported in the same vehicle as food or feed for humans or animals.","handbook":"Poisons must not be loaded with food or feed products.","hbref":"§9.4","qid":"HM-102"},"113":{"q":"I'm loading a mixed HazMat shipment of corrosives and oxidizers onto my trailer, and I need to confirm whether these two materials are allowed to ride next to each other or must be kept apart. Which reference tells me which hazardous materials may NOT be loaded together in the same vehicle?","options":["The shipping paper's HM column, since the 'X' marks indicate which loads must stay separated","The Emergency Response Guidebook, since it lists which materials react with one another","The segregation (separation) table, since it specifies which materials cannot be loaded together","Table 1 of the placarding rules, since it lists the materials that require placards in any amount"],"answer":2,"explanation":"The segregation (separation) table tells the driver which hazardous materials are prohibited from being loaded and transported together.","handbook":"Use the segregation table to know what can't be loaded together.","hbref":"§9.4","qid":"HM-103"},"114":{"q":"I'm loading a trailer that already holds several drums of a Class 5 oxidizer, and the dock supervisor hands me four more pallets to fit in the same space. To keep the load safe, which of these items should I make sure is NOT stowed right next to the oxidizer drums?","options":["A pallet of sealed water-filled jugs","A pallet of empty plastic drums","A pallet of bagged sand","A pallet of flammable solvent cans"],"answer":3,"explanation":"Class 5 oxidizers release oxygen and can intensify or start a fire, so they must be kept away from flammable materials.","handbook":"Keep oxidizers away from flammable materials.","hbref":"§9.4","qid":"HM-104"},"115":{"q":"While loading my placarded trailer, the shipper hands me two HazMat items the segregation table says I must keep apart, and asks why they can't ride side by side. According to the handbook, what is the BEST reason these incompatible materials must be separated?","options":["Placed together they could react with each other, catch fire, or release a dangerous gas","Keeping them together would push the load over the 1,001 lb placarding threshold","Mixing them would smear the proper shipping name and hazard class on the papers","Stacking them together would block the reflective triangles stored at the rear"],"answer":0,"explanation":"Incompatible hazardous materials are kept separated because, if combined, they could react, catch fire, or release a dangerous gas.","handbook":"Some materials are separated because together they could react, ignite, or release gas.","hbref":"§9.4","qid":"HM-105"},"116":{"q":"I'm loading a mixed HazMat shipment and my paperwork lists a drum of a cyanide compound and several containers of corrosive acid (Class 8) going to the same customer. Which loading decision keeps me compliant and safe?","options":["Load them side by side in the same compartment so they stay with the matching shipping papers","Keep the cyanides and acids separated and never load them together in the same load","Load them together only if I secure both in a single sealed outer container","Load them together as long as I cross the railroad tracks without shifting gears"],"answer":1,"explanation":"Cyanides and acids must never be loaded together because contact releases deadly hydrogen cyanide gas.","handbook":"Cyanides and acids must never be loaded together.","hbref":"§9.4","qid":"HM-106"},"117":{"q":"You are hauling a placarded load of corrosives when you smell a sharp odor and notice a wet stain spreading beneath a drum in your trailer. You pull onto the shoulder and confirm the package is leaking. Before you do anything else, what is your FIRST priority?","options":["Open the leaking drum to identify the chemical inside, then check the Emergency Response Guidebook for the proper shipping name","Use water from your supply to dilute and flush the spilled product toward the nearest storm drain before it spreads further","Stop the vehicle, secure the area around the leak, and keep bystanders and other people well away from the scene","Continue slowly to the delivery site where trained staff and proper equipment can contain and offload the leaking drum"],"answer":2,"explanation":"At any HazMat leak the first action is to stop, secure the area, and keep people well away from the scene.","handbook":"At a hazmat leak, stop, secure the area, and keep people away.","hbref":"§9.5","qid":"HM-107"},"118":{"q":"You are hauling a placarded load of corrosives when one of your drums begins leaking and venting vapor at a roadside stop on a windy afternoon. After you have warned others and kept people back, where should you position yourself while waiting for emergency responders and CHEMTREC to arrive?","options":["Just downwind of the trailer so you can keep watching the leaking drum closely","Right beside the cargo doors so you can hand the shipping papers to responders fast","Below the spill on the slope so escaping liquid drains away from where you stand","Well upwind of the vehicle and a safe distance away from the leaking load"],"answer":3,"explanation":"In a HazMat emergency stay upwind and at a safe distance so vapors blow away from you rather than toward you.","handbook":"In a hazmat emergency, stay upwind and away.","hbref":"§9.5","qid":"HM-108"},"119":{"q":"I'm hauling a placarded load of corrosives when one drum begins leaking and fumes start spreading along the shoulder. I've already warned others, kept people back, and stopped any smoking nearby. Now I need expert technical guidance on how to handle this specific chemical. Who should I contact for that expert help?","options":["CHEMTREC or the local emergency responders, who can give expert chemical-handling guidance","My carrier's dispatch office, since the carrier is the one required to handle incident reporting","The shipper who classified and packaged the drums, since they prepared the shipping papers","No one by phone — the Emergency Response Guidebook alone covers every step I need to take"],"answer":0,"explanation":"For expert real-time guidance on handling a leaking chemical, contact CHEMTREC or local emergency responders.","handbook":"Call CHEMTREC or emergency responders for help in a hazmat incident.","hbref":"§9.5","qid":"HM-109"},"120":{"q":"You're hauling a placarded load of flammable liquid on a rural Texas highway when you notice flames coming from under your trailer. You pull onto the shoulder and the fire is clearly spreading. You have a fire extinguisher rated for small fires, but the flames are already reaching the cargo area. What should you do FIRST?","options":["Open the trailer doors to check the cargo and let the heat and smoke vent before the fire grows larger","Get yourself a safe distance away from the vehicle, then call emergency responders and notify CHEMTREC","Empty your fire extinguisher onto the cargo-area flames and stay close in case the fire flares back up","Stay at the cab and keep the engine running so you can move the rig away from the spreading flames"],"answer":1,"explanation":"Never fight a HazMat cargo fire alone; get a safe distance from the vehicle, then call emergency responders and notify CHEMTREC.","handbook":"If a hazmat vehicle is on fire, get away and call for help.","hbref":"§9.5","qid":"HM-110"},"121":{"q":"I'm hauling a placarded load of corrosives when I notice liquid dripping from a drum and pooling under my trailer at a rest area. I've already moved people back, stopped smoking, and notified emergency responders. Which action is the ONE thing I should do regarding moving the leaking vehicle?","options":["Drive it slowly to the next truck stop so a mechanic can reseal the leaking drum","Reposition it just far enough to finish clearing the rest area exit ramp","Leave it where it is unless an official directs me to move it to protect life","Move it off the lot quickly to keep the spill away from other parked trucks"],"answer":2,"explanation":"Never move a leaking hazmat vehicle on your own judgment; leave it in place unless an official directs the move to protect life.","handbook":"Do not move a leaking hazmat vehicle except as directed to protect life.","hbref":"§9.5","qid":"HM-111"},"122":{"q":"I'm hauling placarded corrosives when I notice product leaking from a drum and pooling on the shoulder where I've pulled over. I have my Emergency Response Guidebook and a phone. Which of these should be my FIRST priority while I wait for emergency responders?","options":["Shovel loose dirt and gravel over the puddle so the corrosive soaks in and stops moving","Hose the spill down with water to dilute it and push it off into the ditch and away","Light reflective triangles around the puddle and set a flare upwind to mark the leak","Keep bystanders back from the area and act to stop the leak from spreading further"],"answer":3,"explanation":"In a hazmat incident, keep people away and contain the spill from spreading until trained emergency responders arrive; do not attempt cleanup yourself.","handbook":"In a spill, warn others and prevent it from spreading.","hbref":"§9.5","qid":"HM-112"},"123":{"q":"I'm hauling a placarded HazMat load when a fire breaks out under my trailer at a rest stop. Before I act or talk to the responding fire crew, what is the proper use of my shipping papers and the Emergency Response Guidebook (ERG)?","options":["To identify exactly what material I'm carrying and the specific hazards it poses so responders can react safely","To prove to the carrier that the shipment was loaded and documented correctly before the trip","To find the nearest approved HazMat parking route so I can move the burning trailer off-site","To confirm the load weighs 1,001 lb or more and therefore legally required placards"],"answer":0,"explanation":"Shipping papers and the ERG identify the exact material and its specific hazards so you and emergency responders can react safely.","handbook":"Use the shipping papers and ERG to identify the material and hazards.","hbref":"§9.5","qid":"HM-113"},"124":{"q":"A drum on your placarded trailer has split and is leaking onto the shoulder. You have already pulled over, set out your reflective triangles, and are keeping bystanders back while you wait for emergency responders. One of the bystanders lights a cigarette, and another driver who stopped to help asks if it is okay to have a quick smoke since they are standing well behind your truck. What is the correct action regarding smoking at this incident?","options":["Allow a quick smoke as long as everyone stays at least 25 feet behind the leaking trailer","Prohibit smoking entirely and ask everyone nearby to put out any cigarettes immediately","Permit smoking only for the driver who stopped to help, since helpers are exempt from the rule","Permit smoking only on the upwind side, away from where the product is leaking onto the shoulder"],"answer":1,"explanation":"Smoking is never allowed at a hazmat incident because leaking product or its vapors may be flammable, so any flame or ember must be stopped immediately.","handbook":"Smoking is not allowed at a hazmat incident.","hbref":"§9.5","qid":"HM-114"},"125":{"q":"I'm hauling a placarded load of corrosives when a container ruptures and product begins leaking onto the shoulder of a rural highway. After I've warned others, kept people away from the spill, and prevented anyone from smoking nearby, the law requires that the incident be reported. To whom must this incident be reported as required?","options":["Only to the shipper, since the shipper classified, packaged, and prepared the shipping papers and is therefore the party accountable for what is inside the container","To no one, as long as I personally contain the leak, cool the area, and document the damage with photos before continuing on toward the delivery point","To the proper authorities, such as emergency responders or CHEMTREC, with the carrier handling the required incident report to the agencies involved","Only to the nearest local news or radio station so that other drivers in the area are warned to avoid the affected stretch of the highway"],"answer":2,"explanation":"Notify the proper authorities such as emergency responders or CHEMTREC, while the carrier files the required incident report to the agencies involved.","handbook":"After an incident, report it to the proper authorities as required.","hbref":"§9.5","qid":"HM-115"},"126":{"q":"You are hauling a placarded load of flammable liquid across town and your GPS offers a fast route that runs through a long highway tunnel and a dense downtown district to save 20 minutes. Which choice best follows safe HazMat route-planning practice?","options":["Take the tunnel-and-downtown route, since it is the shortest and saves the most time","Stay on the route but skip the required weigh station to avoid drawing attention to the load","Take the route but plan to park within the downtown area to recheck your placards","Reject that route and pick a path that avoids the tunnel and the heavily populated downtown area"],"answer":3,"explanation":"When routing hazmat, avoid tunnels and heavily populated areas because a release or fire there magnifies the danger to the public.","handbook":"When planning a hazmat route, avoid tunnels and heavily populated areas.","hbref":"§9.5","qid":"HM-116"},"127":{"q":"I'm hauling a placarded load of flammable liquid through a rural Texas county on a route with several types of crossings. To stay compliant with DPS HazMat rules, at which of the following am I REQUIRED to bring my vehicle to a complete stop before proceeding?","options":["A railroad track crossing, where I must stop 15 to 50 feet before the nearest rail","A flashing yellow caution signal at a rural four-way intersection","An open fuel station, before pulling in to top off my diesel tank","Every private driveway and field entrance I pass along the route"],"answer":0,"explanation":"A placarded vehicle must come to a complete stop 15 to 50 feet before the nearest rail at a railroad crossing and never shift gears while crossing.","handbook":"Placarded vehicles must stop before railroad crossings.","hbref":"§9.5","qid":"HM-117"},"128":{"q":"I'm hauling a placarded load of Division 1.2 explosives across Texas and need to make a quick stop for lunch. There's no co-driver with me. Under DPS rules, what am I required to do with this load?","options":["I may leave the truck parked and locked in the restaurant lot while I eat inside, as long as the doors are secured","I must keep the explosives load attended at all times, so I cannot leave it unattended while I go inside to eat","I may leave it unattended for short stops as long as I park more than 300 feet from any building","I may leave it unattended if I shut the engine off and set the parking brake before walking away"],"answer":1,"explanation":"Division 1.1, 1.2, and 1.3 explosives must never be left unattended; the driver or a qualified attendant must stay with the vehicle at all times.","handbook":"Class 1 explosives loads must be attended at all times.","hbref":"§9.5","qid":"HM-118"},"129":{"q":"I'm hauling a placarded load of flammable liquid and need to stop for the night. Up ahead I spot a roadside campfire that someone left burning near a rest area. Before I pick a spot to park, what is the minimum distance the handbook requires me to keep between my placarded vehicle and that open fire?","options":["At least 25 feet, the same distance required for no smoking near the load","At least 50 feet, matching the maximum stopping distance before railroad tracks","At least 300 feet between the vehicle and the open fire","No set distance is required as long as the engine is shut off"],"answer":2,"explanation":"A placarded vehicle must be parked at least 300 feet from an open fire because an open flame is a direct ignition hazard to the load.","handbook":"Park a placarded vehicle at least 300 feet from an open fire.","hbref":"§9.5","qid":"HM-119"},"130":{"q":"I'm hauling a placarded load of hazardous material on an unfamiliar interstate when my GPS reroutes me onto a road I've never driven. Along this stretch I'll pass a busy truck stop, an open weigh station, and a long underground passage cut through a mountain. Which of these am I MOST likely to be legally barred from entering with my hazmat load, forcing me to find an alternate route?","options":["The truck stop, because placarded vehicles cannot park where the public gathers","The open weigh station, because hazmat loads must bypass all inspection scales","Nothing here is restricted, since a posted interstate route always permits hazmat","The underground passage, because some hazmat is barred from certain tunnels"],"answer":3,"explanation":"Avoid tunnels on a hazmat route because authorities can legally bar certain hazardous materials from specific tunnels entirely.","handbook":"Some hazmat may not be taken through certain tunnels.","hbref":"§9.5","qid":"HM-120"},"131":{"q":"I'm hauling a placarded load of corrosives across the city when I hit unexpected highway construction that has closed two lanes and backed traffic up for miles on my assigned hazmat route. A detour sign points toward a shorter path through the downtown business district, and my GPS suggests an even faster shortcut over a low bridge. Which choice should guide where I drive?","options":["Stay on the designated or required hazmat route, finding a way back to it as soon as the road conditions allow","Take the downtown detour because following posted detour signs always overrides hazmat routing rules","Follow the GPS shortcut over the low bridge since it saves the most time and avoids the worst congestion","Pick whichever path is physically shortest, because the law only requires you to minimize total miles driven"],"answer":0,"explanation":"Hazmat drivers must follow the designated or required route and return to it as soon as road conditions allow, regardless of shortcuts or traffic.","handbook":"Stay on the designated or required hazmat route.","hbref":"§9.5","qid":"HM-121"},"132":{"q":"I'm hauling a placarded load and need to pull over to deal with a phone call and stretch my legs for a few minutes. Four spots are within reach off my route. Which one should I AVOID choosing as my parking spot?","options":["A wide gravel pull-out on a rural stretch with no structures in sight","The curb directly beside a tunnel entrance where pedestrians are gathering","A marked truck stop lot well back from the building's main entrance","An open field-side shoulder more than 5 feet off the traveled road"],"answer":1,"explanation":"Placarded loads must be kept away from tunnels, bridges, and crowds, so a tunnel entrance with gathered pedestrians combines two hazards to avoid.","handbook":"Avoid parking a placarded vehicle near bridges, tunnels, and crowds.","hbref":"§9.5","qid":"HM-122"},"133":{"q":"You are hauling Division 1.2 explosives and your fuel gauge is low, so you pull into a truck stop to refuel. While the tank fills, which of the following actions BEST meets your responsibilities for this load?","options":["Leave the engine idling at the pump so you can top off and pull away quickly, then step inside to pay","Park right next to the busy store entrance under the lights so the loaded trailer stays in plain view of staff","Stay with the vehicle the entire time and keep it positioned away from crowds and gathering places","Lock the cab, leave the rig at the pump, and go inside to grab coffee while the automatic shutoff finishes fueling"],"answer":2,"explanation":"Division 1.1, 1.2, and 1.3 explosives may never be left unattended, so the driver must stay with the vehicle and keep it away from crowds and gathering places.","handbook":"With explosives, attend the vehicle and keep it away from crowds.","hbref":"§9.5","qid":"HM-123"},"134":{"q":"I already hold a Class A CDL and I just got hired to haul placarded loads of corrosive liquid. My buddy says all I have to do before I can legally start is pass a quick written test at the DPS office to add the endorsement. Which of the following is the ONE requirement I cannot skip in order to get the HazMat (H) endorsement I need?","options":["Completing a behind-the-wheel road test specifically with a placarded tank trailer","Holding the endorsement for at least 30 days before hauling any placarded load","Renewing my DOT medical certificate within the same week I add the endorsement","Passing a TSA security threat assessment, including a background check and fingerprinting"],"answer":3,"explanation":"The HazMat endorsement requires passing a TSA security threat assessment that includes a background check and fingerprinting, not just a written test.","handbook":"Hauling placarded hazmat requires passing a TSA security threat assessment.","hbref":"§9.1","qid":"HM-124"},"135":{"q":"I'm hauling a placarded load of flammable liquid and need to make a quick stop at a roadside diner to grab lunch. Which of the following actions would put me in violation of HazMat rules?","options":["Leaving the placarded vehicle unattended in the lot while I sit inside the diner to eat","Keeping my shipping papers in the door pouch within reach while parked","Inspecting the tires before I pull back onto the highway","Parking more than 5 feet from the traveled part of the road"],"answer":0,"explanation":"A placarded hazmat vehicle must never be left unattended, so walking away from the truck while the load is unwatched is a prohibited violation.","handbook":"A placarded hazmat vehicle should not be left unattended carelessly.","hbref":"§9.5","qid":"HM-125"},"136":{"q":"I'm hauling a placarded load of corrosives and stop overnight at a truck stop. When I return to my rig in the morning to begin my en-route inspection, which of the following observations should concern me MOST as a security issue I am specifically trained to watch for?","options":["A thin layer of frost has formed on the windshield overnight","A cargo seal has been cut and a placard appears partially peeled back","The fuel gauge is reading slightly lower than the night before","Another truck is now parked in the space beside mine"],"answer":1,"explanation":"A cut cargo seal and a partially peeled-back placard are classic signs of tampering or theft that hazmat drivers are trained to watch for.","handbook":"Hazmat drivers should watch for signs of tampering or theft.","hbref":"§9.1","qid":"HM-126"},"137":{"q":"I just got hired by a carrier that hauls placardable HazMat loads, and during orientation my dispatcher hands me a binder of company documents and says federal rules require many carriers like ours to keep one of these on file in writing. Which document is he most likely referring to as a regulatory requirement?","options":["A written daily lunch and rest-stop schedule that every driver must sign before leaving the yard","A written list of the company's preferred fuel stations approved for placarded vehicles","A written security plan that addresses how the company guards against HazMat theft and misuse","A written record of the radio stations drivers may listen to while transporting the load"],"answer":2,"explanation":"Many carriers hauling hazardous materials must develop and maintain a written security plan covering personnel, unauthorized access, and en-route security.","handbook":"Many hazmat carriers must have a written security plan.","hbref":"§9.1","qid":"HM-127"},"138":{"q":"It is winter and my trailer is equipped with an automatic cargo heater. Before I leave the terminal, the dispatcher hands me a load and tells me to keep the cargo warm en route. Of the following loads, with which one must I absolutely NOT run the cargo heater?","options":["A sealed dry-box load of canned food that could freeze in the cold","An empty trailer I am repositioning to the next pickup","A palletized load of bottled drinking water sensitive to freezing","A load of flammable liquid drums that give off vapors as they warm"],"answer":3,"explanation":"A cargo heater must not be used with flammable-liquid loads because the vapors they give off as they warm can be ignited, causing a fire or explosion.","handbook":"A cargo heater must not be used with certain flammable cargo.","hbref":"§9.5","qid":"HM-128"},"140":{"q":"I'm loading a placardable shipment and the shipping papers list an entry that my carrier has flagged as a \"Forbidden\" material under the hazardous materials regulations. Before I sign for the load, which statement correctly tells me what my obligation is regarding this entry?","options":["I must not transport this material at all, because forbidden materials may never be moved on any vehicle under any condition.","I may transport it as long as I display the correct placards on all four sides and keep the papers within reach.","I may transport it only if its aggregate gross weight stays under 1,001 pounds for the trip.","I may transport it once the shipper adds the proper shipping name, hazard class, and ID number to the papers."],"answer":0,"explanation":"Forbidden materials may never be transported under any condition, so the only correct action is to refuse to move them at all.","handbook":"Forbidden materials may never be transported.","hbref":"§9.3","qid":"HM-129"},"141":{"q":"I'm prepping a load and the shipper tells me part of it qualifies as a \"limited quantity\" shipment. Before I sign for it, which of the following should I expect to be TRUE about that portion of the load?","options":["Because it is a special category, it is exempt from every HazMat rule and I can haul it without any paperwork","It involves smaller amounts of the material, so it carries reduced packaging and marking requirements","It always demands the maximum number of placards on all four sides regardless of weight","The term only applies to liquids, so any solids in the load cannot be a limited quantity"],"answer":1,"explanation":"A limited quantity ships in smaller amounts that fall below set thresholds, which is why it qualifies for reduced packaging and marking requirements.","handbook":"A limited quantity shipment has smaller amounts with reduced requirements.","hbref":"§9.3","qid":"HM-130"},"142":{"q":"I'm doing my pre-trip inspection on a HazMat load and I open the back to compare each carton against my shipping papers. The shipper sealed and packaged everything, but I still need to confirm what each individual package is supposed to carry. To match the cartons to the proper shipping name, hazard class, and ID number on my papers, what should I expect to find printed on each package itself?","options":["A copy of the shipping papers taped to each carton so the package and the paperwork always travel together","The carrier's name and my full name, so responders know which driver and company are hauling the load","A hazard label and markings identifying the material, so I can verify the package against the entries on my shipping papers","A retail price tag with the product cost, so the receiver can confirm the value of the shipment on delivery"],"answer":2,"explanation":"The shipper labels and marks each package with its hazard class and shipping name so you can cross-check every package against your shipping papers.","handbook":"Each hazmat package usually shows a hazard label and markings.","hbref":"§9.3","qid":"HM-131"},"143":{"q":"I'm loading a shipment of Class 7 radioactive material and the shipper is going over the package labels with me before I sign the papers. He points out a number printed on the label that I'll need to account for when I figure out how much of this material can go in my trailer together. Which of the following is this controlling figure that radioactive packages may carry?","options":["A poison-inhalation-hazard rating that exempts the load from placards in any amount","A clearance code that lets the load bypass weigh stations and route restrictions","A reportable-quantity (RQ) limit that removes the need for any package markings","A transport index limit that restricts how much can be carried together"],"answer":3,"explanation":"Class 7 radioactive packages carry a transport index whose limit controls how much radioactive material can be loaded and hauled together.","handbook":"Radioactive materials may have a transport index limit.","hbref":"§9.3","qid":"HM-132"},"144":{"q":"I'm loading a placarded shipment that the shipping papers identify as a reactive material, and I'm deciding where in the trailer and how to store it for the haul. To handle it safely, which of the following must I keep this reactive material away from?","options":["Heat sources, water or moisture, and any other reactive materials being carried","Soft warm blankets or padding used to cushion the load in transit","Any large empty open space in the trailer where the package could shift","Direct exposure to very bright light coming through the trailer doors"],"answer":0,"explanation":"Reactive materials must be kept away from heat, water or moisture, and other reactive materials, since contact can trigger a violent reaction.","handbook":"Reactive materials must be kept away from heat, water, or other reactives.","hbref":"§9.4","qid":"HM-133"},"145":{"q":"I'm assigned to pick up a tank load of refrigerated liquid nitrogen, a cryogenic (very cold) liquid, for a long haul. As I inspect the trailer before accepting the shipment, which condition tells me the load is being handled correctly for this type of cargo?","options":["The tank is fully sealed with no vent so the cold cannot escape and the product stays frozen","The tank uses special insulated equipment and has a working vent to safely release built-up pressure","A small heater unit is mounted inside the tank to keep the liquid from freezing the valves shut","The tank is a standard dry-bulk hauler with no extra fittings since the cold needs no special care"],"answer":1,"explanation":"Cryogenic liquids constantly absorb heat and build pressure, so they require special insulated equipment and a working vent to safely release that pressure.","handbook":"Cryogenic liquids require special equipment and venting.","hbref":"§9.5","qid":"HM-134"},"146":{"q":"My placarded trailer rolls over on a rural Texas highway and a drum starts leaking. The first fire crew arrives before I can say much, grabs my shipping papers, and immediately reads off the hazard class and the UN/NA identification number listed for the load. What is the MAIN reason that hazard class and ID number are so important to those responders at the scene?","options":["They let the responders calculate whether my load was over the 1,001-pound threshold that required placards in the first place","They prove that I, the driver, already called CHEMTREC and the carrier filed the incident report before help arrived","They let the responders quickly identify exactly what the danger is so they can react to the material correctly","They confirm the placards were mounted on all four sides and were readable from the direction they faced"],"answer":2,"explanation":"The proper shipping name, hazard class, and ID number let emergency responders quickly identify the exact danger and react to the material correctly.","handbook":"The hazard class and ID number help responders identify the danger.","hbref":"§9.2","qid":"HM-135"},"148":{"q":"I already hold a Texas Class A CDL and have been hauling dry freight for two years. Next month my carrier wants me to start pulling loads that require placards on all four sides of the trailer. Before I can legally accept that first placarded run, what must I complete?","options":["Nothing extra — a Class A CDL by itself already authorizes any placarded HazMat load","Only the Tanker (N) endorsement, since placarded freight is hauled in bulk tanks","Just a doubles/triples (T) endorsement to cover the added trailer weight","The HazMat (H) endorsement, which requires passing a TSA security threat assessment with fingerprinting"],"answer":3,"explanation":"Hauling a placardable quantity of hazardous material requires the HazMat (H) endorsement, which is issued only after passing a TSA security threat assessment with fingerprinting.","handbook":"The HazMat (H) endorsement is required to transport placarded hazmat.","hbref":"§9.1","qid":"HM-136"},"149":{"q":"I just picked up a placarded load of corrosives. The shipping papers have an error in the hazard class, and I notice it before I leave the terminal. A dispatcher tells me, \"That paperwork is 100% the shipper's problem — your only job is to drive.\" Under the HazMat rules, which statement is TRUE?","options":["Safe transport is a shared responsibility — the shipper, carrier, and driver each have specific duties, and I must not knowingly haul an improperly marked shipment.","Because the shipper alone classifies and prepares the papers, the driver bears no responsibility for paperwork errors and may legally transport the load as given.","Once the carrier dispatches the load, full legal responsibility for the shipment transfers to the carrier, so the driver can rely entirely on dispatch.","The driver's only duty is safe driving, so paperwork accuracy is solely the shipper's job and never something the driver needs to verify."],"answer":0,"explanation":"HazMat safety is a shared responsibility among shipper, carrier, and driver, and you must refuse to knowingly haul a leaking or improperly marked shipment.","handbook":"The shipper, carrier, and driver all share hazmat responsibility.","hbref":"§9.1","qid":"HM-137"},"150":{"q":"I'm picking up a load of compressed propane cylinders and the dock supervisor hands me shipping papers showing the material as Hazard Class 2. Before I placard, I want to confirm what Class 2 actually represents. Which statement is correct?","options":["Class 2 covers corrosives, like the battery acid and sodium hydroxide loads I sometimes haul.","Class 2 covers gases, including flammable, non-flammable, and poison-gas materials like my propane.","Class 2 covers explosives, so this load falls under the same rules as dynamite and fireworks.","Class 2 covers radioactive materials, which is why these cylinders need extra shielding."],"answer":1,"explanation":"Hazard Class 2 is Gases, subdivided into 2.1 flammable, 2.2 non-flammable, and 2.3 poison gas, and propane is a flammable gas in this class.","handbook":"Hazard Class 2 is gases.","hbref":"§9.2","qid":"HM-138"},"151":{"q":"I'm loading drums of battery acid for a delivery, and the shipping papers list the hazard class as 8. Before I placard my trailer, I need to confirm what kind of hazard this load actually represents. Which of the following correctly describes what a Hazard Class 8 material is?","options":["A compressed or liquefied gas that can leak and create a breathing hazard","A toxic substance that can poison a person through skin contact or inhalation","A corrosive material that can chemically burn skin, metal, or other materials","An explosive material that can detonate from heat, shock, or friction"],"answer":2,"explanation":"Hazard Class 8 is Corrosives, materials like battery acid that chemically burn or eat away skin, metal, and other materials.","handbook":"Hazard Class 8 is corrosives.","hbref":"§9.2","qid":"HM-139"},"152":{"q":"I'm loading my trailer when the shipper hands me papers for a shipment marked 'Hazard Class 7' with a UN number and the proper shipping name. Before I placard, I need to understand exactly what kind of danger I'm hauling. Based on the hazard class system, what does Class 7 tell me about this load?","options":["It is a corrosive material, so leaking containers could burn skin and eat through metal surfaces","It is a flammable liquid, so I must keep all ignition sources and open flames far away from it","It is a compressed or poison gas, so a pressure release could create an inhalation hazard","It is a radioactive material, so I am hauling a load that emits radiation and needs special handling"],"answer":3,"explanation":"Hazard Class 7 always means Radioactive materials, so the load emits radiation and needs special handling regardless of the shipping name shown.","handbook":"Hazard Class 7 is radioactive materials.","hbref":"§9.2","qid":"HM-140"},"153":{"q":"I'm loading a trailer and my shipping papers list a Hazard Class 5 material. Before I placard, I want to confirm what kind of hazard this load actually presents. A Class 5 material is one that:","options":["Is an oxidizer or organic peroxide that can intensify a fire by releasing oxygen","Is a corrosive that can destroy skin tissue or eat through steel and aluminum","Is an explosive capable of a mass detonation if exposed to heat or shock","Is a compressed gas that can be flammable, non-flammable, or poisonous"],"answer":0,"explanation":"Hazard Class 5 oxidizers and organic peroxides release oxygen, which can start or intensify a fire even without an outside ignition source.","handbook":"Hazard Class 5 is oxidizers and organic peroxides.","hbref":"§9.2","qid":"HM-141"},"154":{"q":"I'm loading a small quantity of a Poison Inhalation Hazard (PIH) material at the dock, and the total weight is well under 1,001 pounds. My dispatcher tells me the load is so light I can just run it like a normal freight haul. Which of the following is the correct way to handle this PIH shipment?","options":["Because the load is under 1,001 pounds, no placards are required and I can drive it as ordinary freight","I must treat it with extra caution and display the proper placards, because PIH materials require placarding in any amount","I only need to placard if I'm crossing a state line; in-state PIH loads under 1,001 pounds need no special handling","I should reduce my paperwork and skip the shipping papers since the quantity is so small"],"answer":1,"explanation":"Poison Inhalation Hazard (PIH) materials are a Table 1 hazard that must be placarded in any amount, with no minimum weight threshold.","handbook":"Poison inhalation hazard materials require extra care and placards.","hbref":"§9.2","qid":"HM-142"},"155":{"q":"I'm loading my trailer with several boxes of an item whose shipping paper lists it under Hazard Class 9. It isn't flammable, isn't corrosive, and isn't a compressed gas, yet it still required a placard. Which statement BEST describes what Hazard Class 9 covers?","options":["Compressed and liquefied gases that are non-flammable under pressure","Corrosive liquids and solids that can damage skin or metal","Miscellaneous hazardous materials that don't fit the other eight classes","Explosives ranging from blasting agents to fireworks and detonators"],"answer":2,"explanation":"Hazard Class 9 is the catch-all Miscellaneous category for regulated materials that pose a transport hazard but don't fit Classes 1 through 8.","handbook":"Hazard Class 9 is miscellaneous hazardous materials.","hbref":"§9.2","qid":"HM-143"},"156":{"q":"I'm prepping shipping papers for a load and the entry shows Hazard Class 4. Before I placard, I want to confirm what kind of material I'm actually hauling so I grab the right placard. Which of the following correctly describes what a Class 4 material is?","options":["A flammable liquid such as gasoline or diesel fuel","A compressed gas, whether flammable or non-flammable","A corrosive material that can damage skin and metal","A flammable solid that can ignite or burn readily"],"answer":3,"explanation":"Hazard Class 4 covers flammable solids, including spontaneously combustible and dangerous-when-wet materials, that can ignite or burn readily.","handbook":"Hazard Class 4 is flammable solids.","hbref":"§9.2","qid":"HM-144"},"157":{"q":"I'm placarded and stopped at a Texas weigh station when an inspector points to a 4-digit number, 1203, displayed on an orange panel on my trailer and asks me what that number tells him. Which is the correct answer?","options":["It is the ID (UN/NA) number that identifies the specific material I'm hauling","It is the proper shipping name code assigned to the load by the carrier","It is the hazard class number that tells which of the nine classes applies","It is the placard table number showing whether the 1,001 lb rule applies"],"answer":0,"explanation":"A 4-digit number on shipping papers or a placard is the UN/NA ID number that identifies the exact material being hauled.","handbook":"The 4-digit identification number identifies the material.","hbref":"§9.2","qid":"HM-145"},"158":{"q":"During my pre-trip, a state trooper asks me to read off the 4-digit UN/NA identification number for the load I'm hauling so he can cross-check it in the Emergency Response Guidebook. I walk to the side of my placarded trailer to find it. Where am I correctly allowed to read that 4-digit ID number?","options":["Only from the proper shipping name printed on the shipping papers; it never appears on the outside of the trailer","Either displayed directly on the placard itself or on an orange panel mounted next to the placard","Only from the hazard class number shown in the bottom corner of the diamond placard","Only from the manufacturer's data plate stamped on the trailer frame near the landing gear"],"answer":1,"explanation":"The 4-digit UN/NA ID number may be shown either in the center of the placard itself or on an orange panel mounted next to the placard.","handbook":"The ID number appears on the placard or an orange panel.","hbref":"§9.3","qid":"HM-146"},"159":{"q":"At a roadside inspection, an officer points to the diamond-shaped placard on the rear of my trailer and asks me to read off the hazard class number that identifies what I'm hauling. The placard shows a symbol up top, written words in the middle band, and a single digit. Where on the placard should I look to find that hazard class number?","options":["Centered in the middle of the placard, right where the written name of the material is printed","At the very top point of the diamond, directly above the hazard symbol or pictograph","At the bottom corner of the diamond, below the symbol and the written name of the material","Along the left or right side edge of the diamond, beside the hazard symbol"],"answer":2,"explanation":"On a placard, the single-digit hazard class number sits at the bottom corner of the diamond, below the symbol and the written hazard name.","handbook":"The hazard class number is shown at the bottom of the placard.","hbref":"§9.3","qid":"HM-147"},"160":{"q":"I'm loading my trailer at a freight terminal with several non-bulk packages, each from a different Table 2 hazard class, and none of them individually reaches the 1,001 lb threshold that would force a separate placard. Rather than hang a different placard for each class, I'd like to use a single 'DANGEROUS' placard for the whole mixed shipment. Under which condition is using that one 'DANGEROUS' placard actually permitted?","options":["Only when every package on the trailer belongs to the exact same single hazard class","Only when the trailer is carrying no regulated hazardous material whatsoever","Only when the load is limited to consumer food items shipped alongside the freight","When the load contains two or more different Table 2 hazard classes being transported together"],"answer":3,"explanation":"The DANGEROUS placard may be used in place of separate placards when a non-bulk load combines two or more Table 2 hazard classes.","handbook":"A DANGEROUS placard may be used for two or more Table 2 hazard classes.","hbref":"§9.3","qid":"HM-148"},"161":{"q":"I'm loading a single small drum of a Table 1 material (a Division 2.3 poison gas) for a short local run. The total weight of the hazardous material is well under 1,000 pounds. Before I pull out, how must I placard the vehicle?","options":["I must display the placards on all four sides regardless of how little I'm carrying, because Table 1 materials require placarding in any amount.","I don't need placards on this trip, because I'm hauling less than the 1,001-pound aggregate gross weight that triggers placarding.","I only need placards once my combined hazardous load reaches 1,001 pounds or more, so a single small drum is exempt.","I only need placards if the run is interstate or crosses into a populated area, since a short local trip doesn't require them."],"answer":0,"explanation":"A Division 2.3 poison gas is a Table 1 material that must be placarded on all four sides in any amount, regardless of weight.","handbook":"Table 1 hazardous materials require placards in any amount.","hbref":"§9.3","qid":"HM-149"},"162":{"q":"I'm loading a mixed freight trailer and the only hazardous material on board is a Table 2 product. My shipping papers show the aggregate gross weight adds up to exactly 900 lb. Under DPS placarding rules, what must I do before I pull out?","options":["Placard all four sides, because any amount of a hazardous material listed on Table 2 always triggers placarding","No placards are required, because Table 2 materials only need placards at 1,001 lb or more aggregate gross weight","Placard all four sides, because the load is above the 100 lb reporting threshold for Table 2 shipments","Placard only the rear, since 900 lb is enough to require partial placarding but not full four-sided placarding"],"answer":1,"explanation":"Table 2 materials require placards only when their aggregate gross weight reaches 1,001 pounds or more.","handbook":"Table 2 materials require placards at 1,001 pounds or more.","hbref":"§9.3","qid":"HM-150"},"163":{"q":"I'm loading a trailer at a shipper's dock and notice the diamond-shaped hazard warnings the shipper applied to identify what's inside. Where are these hazard labels required to be displayed?","options":["On all four sides of the trailer, readable from the direction each faces","On the shipping papers, in the HM column next to each entry","On the individual packages and containers themselves","On the driver's door pouch where the papers are kept"],"answer":2,"explanation":"Hazard labels are applied by the shipper directly to each individual package and container to identify the hazard class of the contents.","handbook":"Labels are placed on packages.","hbref":"§9.3","qid":"HM-151"},"164":{"q":"I'm loading a shipment of corrosives that requires placards, and my co-driver hands me four diamond-shaped CORROSIVE placards. He tells me where he thinks they belong, but I want to do it right before we roll. Where must these placards actually be displayed?","options":["Affixed to each individual package and overpack inside the trailer so inspectors can see the hazard when the doors open","Attached to the shipping papers in the HM column next to the proper shipping name, hazard class, and ID number","Clipped to a pouch on the driver's door beside the paperwork so they stay within my reach while driving","Mounted on all four sides of the vehicle, readable from the direction each one faces"],"answer":3,"explanation":"Placards are displayed on all four sides of the vehicle and each one must be readable from the direction it faces.","handbook":"Placards are placed on the vehicle.","hbref":"§9.3","qid":"HM-152"},"165":{"q":"While loading my trailer, I pick up a sealed package marked with a pair of black vertical arrows pointing upward on two opposite sides. The shipper's papers are in order, but I want to confirm I am positioning it correctly. What do these orientation arrows require me to do with this package?","options":["Keep the package upright at all times, with the arrows pointing up, so the closures stay on top","Lay the package on its side so the arrows point horizontally toward the trailer wall","Stack it however it fits, since the arrows only show where the forklift should lift it","Turn the package upside down so the sealed end rests against the trailer floor"],"answer":0,"explanation":"Package orientation arrows mean the package must be kept upright with the arrows pointing up so the closures stay on top.","handbook":"Orientation arrows show which way is up.","hbref":"§9.2","qid":"HM-153"},"166":{"q":"I'm a new HazMat driver doing my pre-trip review of the shipping paper for a corrosive load. I can clearly see the proper shipping name and the hazard class listed for each entry. To confirm the description is complete and federally compliant before I roll, which remaining piece of information MUST also appear in that basic shipping description?","options":["The total declared dollar value of the corrosive cargo","The identification number (UN or NA) for the material","The gross vehicle weight rating shown on my CDL","The expiration date of my HazMat endorsement"],"answer":1,"explanation":"A complete basic shipping description lists the proper shipping name, hazard class, and the UN or NA identification number in that order.","handbook":"Shipping papers list the shipping name, hazard class, and ID number.","hbref":"§9.2","qid":"HM-154"},"167":{"q":"I'm reviewing the shipping papers for a load and notice a Roman numeral 'II' listed next to the material's entry as its Packing Group. A newer driver asks me what that 'II' is actually telling us about the shipment. Which of the following is the correct explanation of what the Packing Group indicates?","options":["It states the hazard class number (1 through 9) assigned to the material","It gives the minimum gross weight that triggers the placarding requirement","It shows the relative degree of danger the material presents (I, II, or III)","It lists the UN/NA identification number that follows the shipping name"],"answer":2,"explanation":"The Packing Group, shown as a Roman numeral I, II, or III, indicates the relative degree of danger the material presents.","handbook":"The packing group shows the degree of danger.","hbref":"§9.2","qid":"HM-155"},"168":{"q":"I'm loading a HazMat shipment and the shipping paper lists the material's packing group as \"PG I.\" A newer driver tells me the Roman numeral \"I\" just means it's the first item listed and that it represents the lowest hazard level of the three packing groups. Before I sign for the load and placard, what does \"Packing Group I\" actually tell me about this material's degree of danger?","options":["It indicates the least degree of danger, since Packing Group I is the lowest tier and Packing Group III is the most hazardous","It indicates only a medium degree of danger, ranking between Packing Group II and Packing Group III","It indicates no real danger and is used only to show the item's position on the shipping paper","It indicates the greatest degree of danger, since Packing Group I is the most hazardous of the three packing groups"],"answer":3,"explanation":"Packing Group I indicates the greatest degree of danger, as it is the most hazardous of the three packing groups.","handbook":"Packing Group I indicates the greatest danger.","hbref":"§9.2","qid":"HM-156"},"169":{"q":"I'm loading a mixed HazMat trailer and notice two of my packages have different hazard classes. Before I stack them side by side, I pull out the segregation table. What is this table actually telling me?","options":["Which materials are incompatible and must NOT be loaded together in the same load","Which materials must always be loaded together so their placards match","Which materials should be sold or delivered first to reduce my liability","Which materials need to be labeled a second time before I close the doors"],"answer":0,"explanation":"The segregation table shows which materials are incompatible and must not be loaded together in the same load.","handbook":"The segregation table shows materials that cannot be loaded together.","hbref":"§9.4","qid":"HM-157"},"170":{"q":"I'm at the shipper's dock about to load several drums of a Class 8 corrosive material onto my placarded trailer. As I move the first drum, I notice a wet, glistening film around its bottom seam and a small puddle on the pallet. Before I load ANY of these packages, what is the single most important thing my pre-loading inspection must confirm?","options":["That each drum is painted a bright, high-visibility color so it can be spotted easily in the trailer","That the packages are not leaking or damaged, since I must refuse any container showing a leak or breach","That the drums are stacked as high as possible to keep the load tight and prevent shifting in transit","That the bungs are left loose or open so internal pressure can vent during the trip"],"answer":1,"explanation":"Before loading, inspect each package to confirm it is not leaking or damaged, and refuse any container showing a leak or breach.","handbook":"Inspect packages for leaks or damage before loading.","hbref":"§9.4","qid":"HM-158"},"171":{"q":"I'm a driver loading a flammable liquid (Class 3) onto my trailer at a busy terminal yard. Several things are happening around me at once, and I want to load safely. Which of the following must I make sure to keep AWAY from the cargo area while I load this hazmat?","options":["A pallet jack used by the dock crew","A delivery truck idling at the next dock","An open flame or spark-producing source","A stack of empty wooden pallets"],"answer":2,"explanation":"Keep open flames and spark-producing sources away from hazmat during loading, since flammable materials can ignite from any ignition source.","handbook":"Do not load hazmat near a flame or spark source.","hbref":"§9.4","qid":"HM-159"},"172":{"q":"I'm loading several drums and boxes of placarded hazmat into my dry van for a long interstate run. After I get them aboard, what must I do with these containers before I close the doors and roll?","options":["Set them snugly against the nose of the trailer and rely on the front wall to hold them in place during the trip","Spread them evenly across the floor so the weight is balanced, then let normal floor friction keep them settled","Stack them as high as possible against one sidewall to free up floor space for the rest of the load","Brace and secure each container so it cannot shift, slide, or tip while the vehicle is moving"],"answer":3,"explanation":"Brace and secure each hazmat container so it cannot shift, slide, or tip while the vehicle is moving.","handbook":"Hazmat containers must be braced so they cannot shift.","hbref":"§9.4","qid":"HM-160"},"173":{"q":"I'm hauling a load of hazardous waste and the shipper hands me a hazardous waste manifest along with the rest of my paperwork before I leave the terminal. To stay in compliance with HazMat rules, what must I do with that manifest?","options":["Sign it and keep a copy with my shipping papers within reach","Leave it signed at the terminal so the carrier can file it for me","Carry it unsigned until the receiving facility signs it at delivery","Mail the signed copy to the state agency after the trip ends"],"answer":0,"explanation":"A hazardous waste manifest must be signed by the driver and kept with the shipping papers within reach while driving.","handbook":"A hazardous waste manifest must be signed and kept with the shipping papers.","hbref":"§9.2","qid":"HM-161"},"174":{"q":"I'm a new H-endorsed driver, and a shipper hands me paperwork for a material that the regulations specifically list as one that simply cannot be moved by any commercial vehicle under any circumstances. Before I do anything else, what is the correct way to think about this load?","options":["It can be hauled in any quantity as long as I placard all four sides of the trailer","It is forbidden from transport, so no driver may legally carry it at all","It may be carried freely because my H endorsement covers every hazard class","It never needs placards, so I can move it without notifying anyone"],"answer":1,"explanation":"Some materials are so dangerous they are forbidden from transport entirely and may not be legally hauled by anyone.","handbook":"Some hazardous materials are forbidden from transport.","hbref":"§9.2","qid":"HM-162"},"175":{"q":"I'm loading a shipment marked as Class 1 explosives, and the shipping paper lists the material with a division number right after the class. A coworker tells me Class 1 is a single undivided category, so the division number must be a typo. Which statement correctly describes how Class 1 is structured?","options":["Class 1 is a single undivided category, so any division number after it is an error","Class 1 is split into exactly two groups based on packaging color codes","Class 1 is broken into several divisions, numbered 1.1 through 1.6","Class 1 has no subgroups; divisions only exist for gases in Class 2"],"answer":2,"explanation":"Hazard Class 1 (Explosives) is subdivided into several divisions numbered 1.1 through 1.6.","handbook":"Class 1 explosives are split into divisions 1.1–1.6.","hbref":"§9.2","qid":"HM-163"},"176":{"q":"At a freight terminal, a dispatcher hands me shipping papers for a load labeled \"Division 1.1\" and asks how seriously I should treat the explosion potential before I placard and route the trip. Based on what the hazard division tells me, which statement should drive my decision?","options":["It carries only a projection hazard, so I plan mainly for flying fragments rather than a full detonation","It poses just a minor fire risk, so a standard fire extinguisher and careful fueling are all I really need","It has a slight blast hazard limited to the package itself, so distance from buildings is not a major concern","It presents a mass explosion hazard, meaning the entire load can detonate at once, so I must treat it as the most dangerous explosive division"],"answer":3,"explanation":"Division 1.1 explosives present a mass explosion hazard where the entire load can detonate at once, making them the most dangerous explosive division.","handbook":"Division 1.1 explosives have a mass explosion hazard.","hbref":"§9.2","qid":"HM-164"},"177":{"q":"I'm hauling a placarded Division 1.2 explosives load and I need to stop for a meal break in a small town. As the driver, which action keeps me legal under the rules for this load?","options":["Stay with the vehicle, or have a qualified person watch it, so the load is never left unattended","Lock the cab, set the brakes, and leave it in the restaurant's lot while I eat inside","Park it within 5 feet of the traveled road so I can keep an eye on it from the window","Leave it unattended for up to 2 hours as long as it sits beside a building"],"answer":0,"explanation":"Division 1.1, 1.2, and 1.3 explosives must never be left unattended; the driver or another qualified person must stay with and watch the load at all times.","handbook":"Certain explosives loads must be attended at all times.","hbref":"§9.6","qid":"HM-165"},"178":{"q":"I'm hauling Division 1.1 explosives when my trailer develops a mechanical problem along a two-lane public highway. A second company truck arrives, and my dispatcher wants me to move the explosive freight over to the other vehicle so the load can keep moving. Under HazMat rules, where am I permitted to carry out this transfer between vehicles?","options":["Right there on the highway shoulder, since the second truck is already on scene and ready to receive the load","Not on the public road at all unless it's a genuine emergency — a transfer must be done at a safe, off-road location like a terminal or depot","Anywhere along the route, as long as I display the proper placards on all four sides of both vehicles during the swap","On the road is fine here, because my dispatcher gave the direct order to keep the freight moving"],"answer":1,"explanation":"Class 1 explosives may not be transferred between vehicles on a public road except in a genuine emergency; transfers belong at a safe off-road site like a terminal.","handbook":"Do not transfer Class 1 explosives between vehicles on a public road.","hbref":"§9.6","qid":"HM-166"},"179":{"q":"I'm hauling Division 1.2 explosives and need to pull over to rest. Up ahead I see a rest area where someone has a roadside campfire burning. The spacing rules are running through my head. What is the minimum distance I must keep between my parked explosives load and that open fire?","options":["5 feet, the same minimum I must keep from the traveled part of the road","10 feet, just far enough to stay clear of any drifting embers","300 feet, the required separation between explosives and an open fire","1 foot, since the fire is contained inside a campfire ring"],"answer":2,"explanation":"A vehicle carrying explosives must be parked at least 300 feet from an open fire.","handbook":"Do not park explosives within 300 feet of an open fire.","hbref":"§9.6","qid":"HM-167"},"180":{"q":"I'm reviewing the shipping papers for a Class 2 gas load before I roll out, trying to confirm which division I'm hauling. I know Class 2 covers more than one type of gas, and the carrier told me the three recognized divisions of Class 2 are flammable gas (2.1), non-flammable gas (2.2), and a third division I need to identify for placarding. Which of the following is that third recognized division of Class 2 gases?","options":["Flammable solid gas, since some Class 2 gases can settle into a combustible solid form","Corrosive gas, because pressurized gases in tanks behave like Class 8 corrosive material","Liquid-only gas, since gases stored under pressure are always carried in liquid state","Poison gas, which is Division 2.3 and may require placards in any amount"],"answer":3,"explanation":"Class 2 gases include poison (toxic) gas as Division 2.3, a Table 1 material that requires placards in any amount.","handbook":"Class 2 gases may be flammable, non-flammable, or poisonous.","hbref":"§9.2","qid":"HM-168"},"181":{"q":"During a rest stop, I notice that one of the compressed-gas cylinders on my placarded load has developed a slow leak, hissing near the valve. There are travelers walking around the parking area nearby. Which of the following is the MOST appropriate immediate action?","options":["Move people away from the cylinder, keep the area clear, and call for emergency help","Tighten the valve and seal the leak yourself so the gas stops escaping","Warm the cylinder slightly so the pressure equalizes and the hissing stops","Roll and shake the cylinder to reseat the valve and reduce the pressure"],"answer":0,"explanation":"For a leaking compressed-gas cylinder, move people away, keep the area clear, prevent ignition sources, and call for emergency help rather than trying to fix it yourself.","handbook":"Keep a leaking cylinder away from people and get help.","hbref":"§9.5","qid":"HM-169"},"182":{"q":"I'm loading a Class 7 radioactive shipment, and the shipper hands me packages bearing radioactive labels. Each label shows a number that tells me the radiation level of the package. Which numbering system will I see on these Class 7 labels?","options":["The labels are numbered A, B, or C, matching the package's transport index","The labels are numbered I, II, or III, indicating the package's radiation level","The labels are numbered 1 through 9, matching the hazard class system","The labels are numbered X, Y, or Z, matching the packing group letter"],"answer":1,"explanation":"Class 7 radioactive material uses three label categories marked with Roman numerals I, II, or III to indicate the package's radiation level.","handbook":"Radioactive material labels are numbered I, II, and III.","hbref":"§9.2","qid":"HM-170"},"183":{"q":"I'm loading several Class 7 radioactive packages, and the shipper points out the 'transport index' number printed on each label. To load my trailer safely and legally, what does this transport index value actually tell me?","options":["The total monetary value of the radioactive contents for insurance purposes","The combined gross weight of all the radioactive packages on board","The degree of radiation control needed when handling and transporting the package","The UN/NA identification number assigned to that radioactive material"],"answer":2,"explanation":"The transport index on a Class 7 radioactive package tells you the degree of radiation control needed when handling and loading it.","handbook":"The transport index shows the radiation control required.","hbref":"§9.2","qid":"HM-171"},"184":{"q":"I'm hauling a placarded load of corrosives across town and my GPS offers three possible routes to the same destination, all about the same distance. Following Texas HazMat routing guidance, which of these should I make the greatest effort to choose?","options":["The route that runs through a long underground tunnel, since it avoids surface traffic lights and saves a few minutes","The route that passes directly beside a packed downtown stadium just as an event is letting out","The route that loops past several crowded shopping plazas to stay on wider, well-lit streets","The route that stays on open through-streets and bypasses both the tunnel and the crowded event areas"],"answer":3,"explanation":"HazMat drivers must follow designated routes that avoid tunnels and heavily populated or crowded areas whenever possible.","handbook":"Hazmat routes should avoid tunnels and crowded places.","hbref":"§9.6","qid":"HM-172"},"185":{"q":"I'm dispatched to haul a load of Division 1.1 explosives across the state. My trainer says that before this trip, federal rules require my carrier to prepare a specific written document that I must carry and follow. Which document is he talking about?","options":["A written route plan that the trip must follow","A written driver's daily fuel and mileage log","A written bill of sale for the explosive cargo","A written 72-hour roadside weather forecast"],"answer":0,"explanation":"Loads of explosives (Division 1.1, 1.2, 1.3) must be transported under a written route plan prepared by the carrier and carried by the driver.","handbook":"Explosives require a written route plan.","hbref":"§9.6","qid":"HM-173"},"186":{"q":"I'm three hours into a long haul with a placarded load of corrosives and just pulled into a rest area to use the restroom. The truck has been running fine since my pre-trip inspection, and my tires looked good when I left. Before I get back on the highway, what should I do about my tires?","options":["Nothing — a thorough pre-trip tire check covers me for the whole trip unless a tire actually goes flat","Inspect the tires now, since I should check them at the start of the trip and again every 2 hours or 100 miles","Only check them if the tire-pressure warning light comes on or I feel the truck pulling to one side","Wait and inspect the tires once a day, which is enough for a placarded load on a long run"],"answer":1,"explanation":"A driver hauling a placarded HazMat load must inspect the tires at the start of the trip and again at every stop, meaning every 2 hours or 100 miles.","handbook":"Check the tires before the trip and at each stop.","hbref":"§9.4","qid":"HM-174"},"187":{"q":"I pull my placarded tanker into a fuel island to top off the diesel before the next leg of my run. As I get ready to start pumping, which of the following describes how I must handle the engine and the fueling operation to stay compliant?","options":["Leave the engine idling low so the air system stays charged, and operate the nozzle myself","Shut the engine off, lock the nozzle on automatic, and step inside to pay while it fills","Shut the engine off and keep a person physically at the nozzle controlling the flow the whole time","Keep the engine running at high idle to power the lift pump, with no one needed at the nozzle"],"answer":2,"explanation":"When fueling a placarded vehicle, the engine must be off and someone must stay at the nozzle controlling the flow of fuel the entire time.","handbook":"Turn off the engine when fueling a placarded vehicle.","hbref":"§9.4","qid":"HM-175"},"189":{"q":"You are hauling a placarded load of corrosive liquid when one drum begins leaking badly onto the highway shoulder, creating a serious hazmat spill. After you have warned others, kept people away, and prevented smoking, your carrier instructs you to make the required notification of this serious incident to the National Response Center. Which number do you call to report it?","options":["411, the directory-assistance line, to be connected to the nearest hazmat response unit","911, the local emergency line, which fully satisfies the National Response Center requirement","1-800-555-1212, the toll-free line that routes the report to the proper federal agency","1-800-424-8802, the National Response Center line for reporting serious hazmat incidents"],"answer":3,"explanation":"Serious hazmat incidents must be reported to the National Response Center at 1-800-424-8802.","handbook":"Report hazmat incidents to the National Response Center.","hbref":"§9.5","qid":"HM-176"},"190":{"q":"A drum on my placarded trailer starts leaking corrosive liquid on a remote shoulder, and I have no idea what to do with the chemical or how to neutralize it. After I warn others and keep people back, which number should I call to reach 24-hour emergency guidance on handling this specific hazardous material?","options":["1-800-424-9300, the CHEMTREC emergency line","1-800-275-8777, the national shipping-and-postal hotline","1-888-275-8255, the federal highway-safety report line","1-800-829-1040, the federal agency information line"],"answer":0,"explanation":"CHEMTREC runs a 24-hour emergency line at 1-800-424-9300 that gives drivers immediate technical guidance for handling a hazardous material in an incident.","handbook":"CHEMTREC (1-800-424-9300) gives 24-hour emergency information.","hbref":"§9.5","qid":"HM-177"},"191":{"q":"I'm hauling a placarded load of corrosives across Texas with my seat belt fastened. A DPS trooper pulls me over and asks about my HazMat shipping papers. According to handbook rules, where should those papers have been while I was driving?","options":["Sealed in a waterproof envelope and stored in the trailer with the freight","Within my reach and in clear view, lying on top of my other papers","Zipped inside my logbook binder on the bunk behind the driver's seat","Locked in the glove box so they stay secure if the cab is broken into"],"answer":1,"explanation":"While driving, HazMat shipping papers must be within the driver's reach and placed on top of other papers in clear view.","handbook":"Keep shipping papers within reach and in clear view.","hbref":"§9.2","qid":"HM-178"},"192":{"q":"I'm hauling a placarded HazMat load and pull into a rest area to use the restroom. I'll be leaving the cab for a few minutes with the engine off. According to Texas DPS rules, where should my shipping papers be while I'm away from the truck?","options":["Locked inside the glove box so no one can tamper with them while I'm gone","Folded into my shirt pocket and carried with me into the rest area","Left in plain view on the driver's seat or in the driver's door pouch","Stored in the side cargo compartment next to the Emergency Response Guidebook"],"answer":2,"explanation":"When the driver leaves the cab, HazMat shipping papers must be left in plain view on the driver's seat or in the driver's door pouch so responders can find them.","handbook":"When out of the cab, leave papers on the seat or in the door pouch.","hbref":"§9.2","qid":"HM-179"},"193":{"q":"I'm parked at a rest area with my trailer placarded for Class 3 flammable liquids. A few drivers are standing near my rig chatting, and one lights a cigarette. To stay within the federal smoking rule for my placarded load, what is the minimum distance everyone must keep that lit cigarette away from my vehicle?","options":["At least 5 feet, the same buffer required when parking away from the traveled part of the road","At least 2 feet, since the flammable liquid is sealed inside the tank and poses little risk","At least 100 yards, the same distance kept from explosives left unattended at a rail crossing","At least 25 feet from the vehicle, since no smoking is permitted within that range of a flammable load"],"answer":3,"explanation":"Smoking is prohibited within 25 feet of a placarded vehicle carrying explosives, oxidizers, or flammables, so a lit cigarette must stay at least that far away.","handbook":"Do not smoke within 25 feet of explosives, oxidizers, or flammables.","hbref":"§9.4","qid":"HM-180"},"194":{"q":"I'm a new driver assigned to haul a load of Division 1.1 explosives across Texas. The shipper has finished classifying and labeling the load, and my carrier has assigned the run. Before I pull out of the yard, which of the following must I already have in WRITTEN form in the cab?","options":["A written route plan for the trip plus the shipping papers for the load","A signed weight ticket from the scale and a copy of my fuel receipt","A written log of the radio channels I'll monitor along the route","A notarized weather forecast covering every county I'll pass through"],"answer":0,"explanation":"Before transporting Division 1.1 explosives, the driver must carry a written route plan along with the shipping papers for the load.","handbook":"Class 1 explosives require written route and shipping papers.","hbref":"§9.6","qid":"HM-181"},"195":{"q":"I'm loading a placarded HazMat shipment at a dock and inspecting each package before it goes on my trailer. The shipper hands me four containers. Which ONE must I refuse to transport?","options":["A drum that is sealed tight with no visible damage to the seam or lid","A pail with a corrosive product slowly seeping from a crack at its base","A carton with the correct hazard class label applied to the outer surface","A box that is properly closed and matches the description on my shipping papers"],"answer":1,"explanation":"A driver must refuse any hazardous materials shipment that is leaking, such as a package seeping product from a crack.","handbook":"Drivers must refuse leaking hazmat packages.","hbref":"§9.4","qid":"HM-182"},"196":{"q":"I already hold a Class A CDL and now I want to add the H endorsement so I can haul placarded loads of corrosives. Before Texas DPS will issue this endorsement, which additional requirement must I satisfy that is NOT required for my base CDL?","options":["Pass a second DOT medical exam and submit an updated medical examiner's certificate","Complete a separate behind-the-wheel skills test using a placarded tank vehicle","Clear a TSA security threat assessment, which includes fingerprinting and a background check","Retake the CDL vision screening and the general knowledge written test at DPS"],"answer":2,"explanation":"The HazMat endorsement uniquely requires passing a TSA security threat assessment, including fingerprinting and a background check.","handbook":"The HazMat endorsement requires a TSA background check.","hbref":"§9.1","qid":"HM-183"},"197":{"q":"I've held my Texas CDL with the HazMat (H) endorsement for several years and pass every medical exam on time. A newer driver tells me that once I earned the H endorsement by clearing the TSA security threat assessment, that part of my credential is permanent and I never have to deal with it again as long as my base CDL stays valid. Which statement about my HazMat endorsement is correct?","options":["It is locked in for life once the TSA threat assessment clears, so no further action on that part is ever required.","It only stays valid as long as I keep passing my DOT medical exam, which is what controls the endorsement.","It transfers automatically and never expires as long as I keep my underlying Texas CDL active.","It must be renewed periodically, which requires going through a new TSA security threat assessment / background check."],"answer":3,"explanation":"The HazMat endorsement is time-limited and must be renewed periodically by passing a new TSA security threat assessment and background check.","handbook":"The HazMat endorsement must be renewed periodically.","hbref":"§9.1","qid":"HM-184"},"198":{"q":"I'm hauling a placarded load of corrosives when a valve fails and product starts leaking onto the shoulder. I grab the Emergency Response Guidebook (ERG) from my cab. In this situation, what is the ERG actually designed to help me do?","options":["Identify the material's hazards and the correct initial actions for the spill so I can protect myself and the public","Calculate the dollar value of the lost product so the carrier can file an accurate insurance claim","Determine the most fuel-efficient detour route around the incident to avoid wasting diesel","Locate the nearest approved lodging and rest area while I wait for the cleanup crew"],"answer":0,"explanation":"The Emergency Response Guidebook lets a driver identify a material's hazards and the correct initial spill actions to protect themselves and the public.","handbook":"The ERG helps responders deal with spills and fires.","hbref":"§9.5","qid":"HM-185"},"199":{"q":"There's a leak from my placarded tank at a crash scene. A firefighter runs up and asks me to read off the four-digit ID number from my shipping papers. EXCEPT for one, all of the following explain why that number matters to him. Which choice is the one he actually needs it for?","options":["It tells him the dollar value of the cargo so he can file the carrier's damage claim","It lets him look the material up in the Emergency Response Guidebook to find the correct response procedures","It confirms my H endorsement and TSA background check are valid for this load","It shows the proper shipping name so he can read it aloud over the radio to dispatch"],"answer":1,"explanation":"The four-digit UN/NA identification number lets a responder look the material up in the Emergency Response Guidebook to find the correct response procedures.","handbook":"The ID number is used to look up the material in the ERG.","hbref":"§9.2","qid":"HM-186"},"200":{"q":"I'm hauling a placarded load when smoke starts pouring from under my trailer and I see flames spreading along the tires. I have a small fire extinguisher in the cab, but the fire is already too large for me to safely control. EXCEPT for one choice below, every action listed would make this situation more dangerous. Which is the action I should actually take?","options":["Open the cargo doors to check exactly which drums are burning so I can describe them to responders","Grab my extinguisher and keep fighting the fire myself until it is fully out or help finally arrives","Keep bystanders far back, stay upwind, and call emergency responders for help right away","Drive the burning rig to the nearest town so firefighters there have a shorter distance to reach me"],"answer":2,"explanation":"When a placarded hazmat load is on fire and beyond your control, keep bystanders back, stay upwind, and call emergency responders immediately instead of fighting it.","handbook":"For a hazmat fire, keep people away and call for help.","hbref":"§9.5","qid":"HM-187"},"201":{"q":"You are hauling a placarded HazMat load and your GPS routes you straight through a long highway tunnel that would save you nearly an hour. You are not sure whether your material is permitted in that tunnel. Before you reach the tunnel entrance, what should you do FIRST?","options":["Reduce your speed and keep both lanes clear so you can pass through the tunnel quickly and safely","Pull off the placards before entering so the tunnel attendants do not flag you down inside","Stop just inside the tunnel entrance and call your carrier to ask whether you may continue","Check the designated route rules, because some HazMat is banned from tunnels and a different route may be required"],"answer":3,"explanation":"Some hazardous materials are banned from tunnels, so a driver must check the designated route rules first because a different route may be required.","handbook":"Check route rules before entering a tunnel with hazmat.","hbref":"§9.6","qid":"HM-188"},"202":{"q":"My carrier just handed me a written security plan before a placarded HazMat run and asked me to follow its procedures for keeping shipping papers secured, verifying my route, and limiting unauthorized access to the trailer. From a Texas DPS standpoint, what is the PRIMARY purpose this security plan is designed to accomplish?","options":["Reduce the chance that the hazardous materials are stolen or misused by unauthorized people","Speed up loading and unloading so the delivery arrives ahead of its scheduled time","Lower fuel consumption by mapping the shortest possible route between the stops","Keep the cargo area clean so the materials are not contaminated during transit"],"answer":0,"explanation":"A HazMat security plan exists to reduce the chance that hazardous materials are stolen or misused by unauthorized people.","handbook":"A security plan helps prevent theft or misuse of hazmat.","hbref":"§9.1","qid":"HM-189"},"203":{"q":"I'm hauling a placarded load of corrosives across an unfamiliar city and stop the night before to map out my trip. According to the Texas CDL Handbook, what is the MAIN reason planning my route in advance is so important for a HazMat driver?","options":["It lets me skip the en-route tire checks because I already know how long the trip will take","It helps me identify and stay out of restricted areas where my placarded load is prohibited","It allows me to remove my placards on stretches of open highway to save fuel","It guarantees I can find the cheapest fuel stations and rest stops along the way"],"answer":1,"explanation":"Planning the route ahead of time helps a driver identify and stay out of restricted areas where a placarded load is prohibited.","handbook":"Plan your route to avoid restricted areas.","hbref":"§9.6","qid":"HM-190"},"204":{"q":"I'm loading a trailer at a freight terminal and my manifest includes several pallets of Class 1 (Division 1.1) explosives along with other hazardous materials waiting on the dock. Before I let the dock crew stack everything together, what should guide my decision about which products can ride in the same load as the explosives?","options":["Explosives may share a load with any hazard class as long as each pallet is separately blocked and braced so it cannot shift in transit","Explosives can be loaded with anything provided the combined freight stays under the 1,001-pound placarding threshold for the trailer","The segregation (load/unload) table prohibits loading explosives together with certain other hazardous materials, so I must check it before combining them","Explosives must be loaded completely alone and may never share a trailer with any other freight whatsoever"],"answer":2,"explanation":"Always consult the segregation (load/unload) table before combining explosives with other hazardous materials, since some products are forbidden to load together.","handbook":"Do not load explosives with materials the table forbids.","hbref":"§9.4","qid":"HM-191"},"205":{"q":"I'm at the loading dock about to hand-load several drums and pails of a Class 8 corrosive liquid into my trailer. The dock worker asks how I want each container positioned before we strap them down. To package the load safely so the liquid stays sealed inside, how should I have every container set?","options":["Lying on their sides so the drums nest tightly and shift less in transit","With the openings turned down so any seepage drains away from the closure","With the hazard labels turned toward the wall to keep them from getting scuffed","Standing upright with the openings facing up so the closures stay above the liquid"],"answer":3,"explanation":"Load liquid hazardous materials upright with the closures facing up so the openings stay above the liquid level and the seals don't leak.","handbook":"Load liquid hazmat with the openings up.","hbref":"§9.4","qid":"HM-192"},"206":{"q":"I'm hand-loading a trailer with cartons of a corrosive (Class 8) material, and a dock worker hands me a metal cargo hook to drag the heavy boxes into place faster. Before I grab anything, which rule should stop me from using that hook on these packages?","options":["I must not use any hook or tool that could puncture, tear, or otherwise damage the HazMat packages","I may use the hook freely as long as I keep the cartons upright and the labels facing outward","Hooks are allowed on Class 8 only after I have applied placards to all four sides of the trailer","Hooks are permitted only if I check the tires within the first 100 miles after loading"],"answer":0,"explanation":"Never use a hook or any tool that could puncture, tear, or damage hazardous materials packaging, since a breach can release the contents.","handbook":"Do not use tools that can damage hazmat packages.","hbref":"§9.4","qid":"HM-193"},"207":{"q":"I'm loading compressed gas cylinders (Class 2) into my trailer on a hot afternoon. To handle them correctly under the rules, what should I do with these cylinders before I get rolling?","options":["Lay them down loose so they can settle naturally and shift as the load adjusts on the road","Secure them firmly so they can't move and keep them protected from sources of heat","Stand them upright with the valves cracked open so internal pressure can vent off slowly","Stack them high against the warm trailer wall and chock only the bottom row"],"answer":1,"explanation":"Secure compressed gas cylinders so they can't shift or fall and keep them away from heat, because heat raises internal pressure and can cause a rupture.","handbook":"Secure gas cylinders and protect them from heat.","hbref":"§9.4","qid":"HM-194"},"208":{"q":"I'm placarding a tanker before a Texas haul and notice it carries two placards: a large primary one for its main hazard class plus a smaller second placard with no class number printed at the bottom corner. My trainer calls the second one a 'subsidiary' placard. What is it telling me about this load?","options":["It confirms the leftover or 'old' classification the shipper used before the cargo was reloaded","It indicates the tank is empty and only residue remains inside the vessel","It warns of an additional hazard the material poses beyond its primary hazard class","It marks the current fuel level so responders know how much product is aboard"],"answer":2,"explanation":"A subsidiary placard warns of an additional hazard the material poses beyond its primary hazard class.","handbook":"A subsidiary placard indicates an additional hazard.","hbref":"§9.3","qid":"HM-195"},"209":{"q":"I'm preparing to haul a placarded load of corrosives, and the shipper hands me shipping papers listing an emergency response telephone number near the top. Before I sign and roll, which requirement must that emergency response number satisfy?","options":["It only has to be reachable during the shipper's normal weekday business hours","It can route to a recorded voicemail box as long as someone returns the call later","It is allowed to be a personal cell number for the driver listed on the papers","It must be a number that is staffed and monitored at all times while the HazMat is in transport"],"answer":3,"explanation":"The emergency response phone number on the shipping papers must be staffed and monitored at all times while the hazardous material is in transport.","handbook":"The emergency phone number must be monitored at all times.","hbref":"§9.2","qid":"HM-196"},"210":{"q":"You are hauling a placarded load of corrosives when a fitting fails and a puddle begins spreading from under your trailer onto the shoulder of a two-lane highway. Other vehicles are still passing close by. After pulling fully off the road, what is your FIRST priority before doing anything else?","options":["Keep bystanders back from the leak and warn approaching traffic of the hazard","Rinse the spilled material off the pavement so it stops spreading downhill","Remove or cover the placards so curious onlookers don't panic about the load","Get back in the cab and drive to the next exit to clear the scene quickly"],"answer":0,"explanation":"At a HazMat incident the driver's first duty is to keep people away from the leak and warn approaching traffic of the hazard.","handbook":"If hazmat spills, keep people away and warn traffic.","hbref":"§9.5","qid":"HM-197"},"211":{"q":"I've pulled into a rest area with my placarded load and want to step out for a smoke break. Near which of these should I absolutely NOT light up?","options":["Beside the empty, fully purged trailer I just dropped","Beside the trailer placarded for a flammable liquid","Beside a parked passenger car in the next stall over","Beside the clean, swept-out cab of my tractor"],"answer":1,"explanation":"Never smoke within 25 feet of a vehicle placarded for flammables, since the vapors can ignite from an open flame or lit cigarette.","handbook":"Never smoke around flammable hazardous materials.","hbref":"§9.4","qid":"HM-198"},"212":{"q":"Your placarded tanker hauling a flammable liquid jackknifes on a rural two-lane and you smell a strong chemical odor pooling near the trailer. Two motorists have stopped and are walking toward the wreck, one lighting a cigarette. Which action should you take FIRST?","options":["Climb back into the cab and reposition the trailer off the roadway before the leak spreads","Gather the shipping papers and the Emergency Response Guidebook and start cleaning up the spill","Keep the bystanders well back, prevent any smoking, and notify emergency responders and CHEMTREC","Set out lit flares behind the wreck to warn approaching traffic of the hazard"],"answer":2,"explanation":"After a HazMat crash, keep bystanders well back, prevent any smoking, and immediately notify emergency responders and CHEMTREC.","handbook":"After a hazmat crash, keep people back and get help.","hbref":"§9.5","qid":"HM-199"},"213":{"q":"I'm doing a pre-trip on my placarded trailer at the Laredo yard, and I notice the placard on the rear has faded badly and one on the right side is partly hidden behind a mud flap bracket. My partner says it's fine as long as the front and rear placards are clean, since those are what oncoming traffic and the cop behind me actually see. Based on DPS placarding rules, which statement is correct?","options":["Your partner is right that only the front and rear matter, since those face the directions other drivers approach from, so the faded side placard can be ignored before you drive.","It is acceptable as long as at least one placard on the vehicle stays fully readable from outside the cab, so a single clean front placard would let you drive today.","Placards only need to be clearly visible to the driver from inside the cab to confirm the load is marked, so external fading or obstruction does not matter before you drive.","All four placards must be present and readable from the direction each one faces, so the faded rear and the partly hidden side placard both must be fixed before you drive."],"answer":3,"explanation":"Placards are required on all four sides and each must be legible from the direction it faces, so any faded or obscured placard must be fixed before driving.","handbook":"Placards must be readable from all four directions.","hbref":"§9.3","qid":"HM-200"},"214":{"q":"I'm doing my pre-trip inspection on a placarded load and I want to confirm the placards are mounted the way the regulations require. Ignoring the printed symbol and class number inside, what overall shape should each correctly displayed placard form on the side of my trailer?","options":["A square set on one of its corners so it reads as a diamond with the point up","A square set flat on one of its straight edges, like a road sign panel","A round circular disc, so the warning is visible from every angle","An upright triangle, matching the reflective warning devices in my kit"],"answer":0,"explanation":"A placard is a square turned 45 degrees and set on one corner, forming a diamond with the point up.","handbook":"Placards are diamond-shaped (a square on point).","hbref":"§9.3","qid":"HM-201"},"215":{"q":"I'm loading a placarded HazMat shipment and double-checking that each package is marked correctly before I sign for it. Besides the proper shipping name printed on the package, which piece of information must also appear on the package marking?","options":["My name as the driver who accepted the load","The identification (UN/NA) number for the material","The color code matching the placard on the trailer","The fuel type the carrier's tractor burns"],"answer":1,"explanation":"Package markings must include the material's identification (UN/NA) number along with the proper shipping name.","handbook":"Package markings include the shipping name and ID number.","hbref":"§9.3","qid":"HM-202"},"216":{"q":"I'm reviewing the shipping papers for a load before I leave the terminal, and I notice the letters \"RQ\" entered in the HM column right next to one of the listed materials. Before I sign and place the papers within my reach, what does that \"RQ\" notation actually tell me about that entry?","options":["It marks the suggested low-traffic route I should follow to keep that material away from populated areas","It confirms the shipper double-checked the package and certified it as leak-free for loading","It flags that the material is present at a reportable quantity, so a spill of it must be reported","It means the entry was reviewed and cleared, so I can move it to the bottom of my paperwork"],"answer":2,"explanation":"\"RQ\" means Reportable Quantity, indicating the material is present in an amount that requires reporting a spill if released.","handbook":"'RQ' on shipping papers means reportable quantity.","hbref":"§9.2","qid":"HM-203"},"217":{"q":"I'm loading a mixed shipment and the dock supervisor hands me several packages marked Class 6 (Division 6.1) poison. I have an empty trailer and need to decide where these go relative to the rest of my freight. To load this poison safely and legally, which item must I make absolutely certain it is kept away from?","options":["The reflective warning triangles I carry for emergencies","The fire extinguisher mounted near the cargo doors","The spare tire stored under the trailer body","Any food, foodstuffs, or edible products in the load"],"answer":3,"explanation":"Poison (Division 6.1) materials must never be loaded with or near any food, foodstuffs, or edible products to prevent contamination.","handbook":"Keep poisonous materials away from food.","hbref":"§9.4","qid":"HM-204"},"218":{"q":"I'm hauling a placarded load of Class 5 oxidizers when a small electrical fire starts near my trailer. As I size up the situation, why is it especially urgent that I keep this material away from any flames?","options":["Oxidizers release oxygen, so they will make the fire burn hotter and more intensely","Oxidizers will smother and put the flames out, but the fumes released are toxic","Oxidizers freeze on contact with heat, which can crack the trailer and spill the load","Oxidizers are harmless near fire, but the placards themselves are flammable"],"answer":0,"explanation":"Oxidizers release oxygen that feeds a fire, making it burn hotter and more intensely.","handbook":"Oxidizers can make a fire burn hotter and worse.","hbref":"§9.2","qid":"HM-205"},"219":{"q":"I'm hauling a placarded load of a Class 3 flammable liquid, and the shipping paper lists the material's flash point. During my pre-trip safety review, my trainer asks me what that flash point number actually tells me about this cargo. Which statement correctly describes what the flash point indicates?","options":["It is the temperature at which the liquid will freeze and stop sloshing in the tank","It is the lowest temperature at which the liquid gives off enough vapor to form an ignitable mixture","It is the temperature at which the liquid will self-ignite without any spark or open flame","It is the temperature at which the liquid expands enough to start leaking from the container"],"answer":1,"explanation":"Flash point is the lowest temperature at which a liquid gives off enough vapor to form an ignitable mixture.","handbook":"The flash point is the temperature at which a liquid gives off ignitable vapor.","hbref":"§9.2","qid":"HM-206"},"220":{"q":"I'm hauling a dry bulk tank loaded with cement powder, and I'm approaching a cloverleaf off-ramp with a posted curve. Because of how this type of cargo behaves, which factor should most shape how I take this turn?","options":["The load sits low and settled, so I can take the curve at the posted highway speed without adjusting","The tank is baffled like a liquid tanker, so surge is fully controlled and only braking distance matters","The load rides high and shifts as the vehicle moves, so I should slow well before the curve and steer smoothly","The powder packs solid once moving, so abrupt steering corrections in the curve are perfectly safe"],"answer":2,"explanation":"Dry bulk tanks have a high center of gravity and shifting loads, so slow down well before a curve and steer smoothly.","handbook":"Dry bulk loads shift, so drive smoothly and slow in turns.","hbref":"§9.4","qid":"HM-207"},"222":{"q":"I just accepted a load that has to be placarded on all four sides, and the carrier's dispatcher is rushing me to roll out. Before I leave the yard, which credential must I personally hold in order to legally drive this placarded load?","options":["A current DOT medical examiner's certificate, which by itself authorizes me to haul any placarded shipment","A tanker (N) endorsement, since placarded loads are always transported in bulk tank trailers","Nothing extra on my license, because the shipper already prepared the papers and applied the placards","A valid HazMat (H) endorsement, obtained after passing a TSA background check and fingerprinting"],"answer":3,"explanation":"Hauling a placarded HazMat load requires a valid HazMat (H) endorsement, earned by passing a TSA background check and fingerprinting.","handbook":"Drivers of placarded vehicles must hold a HazMat endorsement.","hbref":"§9.1","qid":"HM-208"},"223":{"q":"I'm hauling a placarded load of corrosives and want to prepare my shipping papers correctly before I pull out. I take a few minutes to tab and clearly mark the hazmat entries. When an inspector or first responder asks for them, what is the whole point of tabbing and marking those papers this way?","options":["So that the hazmat papers can be located quickly and easily in an emergency or inspection","So the hazmat papers can stay folded and stored out of sight until they are specifically requested","So the hazmat entries are separated and set aside from the rest of the load's paperwork","So the hazmat papers can be discarded once the delivery has been completed and signed for"],"answer":0,"explanation":"Hazmat shipping papers must be tabbed or marked so they can be located quickly and easily during an emergency or inspection.","handbook":"Keep shipping papers easy to find.","hbref":"§9.2","qid":"HM-209"},"224":{"q":"You are hauling a placarded load of corrosives when a connection fails and the material begins leaking onto the shoulder of a busy highway. Bystanders are starting to gather near your trailer. Of the actions below, which should be your FIRST priority before anything else?","options":["Pull out the shipping papers and call CHEMTREC to report the exact product and quantity","Keep yourself clear of the leak and move bystanders away to protect everyone from exposure","Open the Emergency Response Guidebook to look up the spill cleanup procedure for that ID number","Contact your carrier so the company can file the required incident report with the authorities"],"answer":1,"explanation":"In any HazMat incident, protect life first by keeping clear of the leak and moving bystanders away from exposure.","handbook":"In an emergency, protect yourself and others first.","hbref":"§9.5","qid":"HM-210"},"225":{"q":"You pull your tank truck up to the rack to load a flammable liquid. Before any product starts flowing into the cargo tank, which step is the MOST important to prevent a static-electricity spark from igniting the vapors?","options":["Leave the truck's engine idling so the alternator can keep the tank's level sensors powered during the load","Set out your reflective warning triangles around the loading rack in case other vehicles approach","Bond the tank to the loading equipment and ground both before opening the fill line","Open the dome cover early so built-up vapors can vent off and lower the pressure inside"],"answer":2,"explanation":"Bonding and grounding before opening the fill line drains the static electricity that flammable-liquid flow generates, preventing a spark that could ignite the vapor.","handbook":"Bond and ground a cargo tank when loading flammable liquids.","hbref":"§9.4","qid":"HM-211"},"227":{"q":"I'm hauling a placarded load that requires attendance, and I've parked at a designated stop for the night. My co-driver agrees to stay with the vehicle as the attendant while I rest in a nearby motel. Which of the following best describes how my co-driver must perform this attendance duty for it to count?","options":["He may nap in the sleeper berth as long as he stays within 100 feet of the cargo","He may sit in a closed restaurant across the lot, since he can still see the trailer","He may leave briefly to refuel his personal car if no one is around","He must remain awake and alert, within 100 feet of and with an unobstructed view of the vehicle"],"answer":3,"explanation":"An attendant for a placarded load must stay awake and alert, within 100 feet of the vehicle, and keep an unobstructed view of it.","handbook":"The attendant must be awake and alert.","hbref":"§9.6","qid":"HM-212"},"228":{"q":"I'm hauling a placarded load of flammable liquid on a long interstate run and just finished my pre-trip tire check before leaving the terminal. To stay compliant with the en-route inspection rule, how often must I stop to re-check my tires during the trip?","options":["At least every 2 hours or every 100 miles, whichever comes first","At least every 100 miles, but the 2-hour clock does not apply once I'm on the highway","At least every 3 hours or every 150 miles, whichever comes first","Only when I stop to refuel or take a required 30-minute break"],"answer":0,"explanation":"While hauling a placarded load you must check the tires en route at least every 2 hours or every 100 miles, whichever comes first.","handbook":"Examine a placarded vehicle every 2 hours or 100 miles.","hbref":"§9.4","qid":"HM-213"},"229":{"q":"I'm first on scene at a rollover hauling a placarded load. Dispatch can't read the proper shipping name through the smoke, but they radio me the 4-digit UN identification number stenciled on the package. To look up the emergency response info the FASTEST using only that number, which section of the ERG should I turn to?","options":["The orange-bordered guide pages, which group materials by their assigned hazard color","The yellow-bordered pages, which list materials in numerical order by ID number","The blue-bordered pages, which list materials alphabetically by shipping name","The white-bordered pages, which list materials by package weight and quantity"],"answer":1,"explanation":"The ERG's yellow-bordered pages list materials in numerical order by ID number, so they are fastest when you only know the 4-digit ID number.","handbook":"The ERG yellow pages list materials by ID number.","hbref":"§9.5","qid":"HM-214"},"230":{"q":"I'm at the scene of a leak on my placarded load. The shipping papers were destroyed, so I don't have the UN/NA identification number, but the container is clearly stenciled \"CHLORINE.\" To look this material up fast in the ERG's blue-bordered pages, what am I relying on to find the entry?","options":["The four-digit UN/NA identification number stenciled on the container","The placard hazard class number displayed on the tank","The proper shipping name of the material, listed alphabetically","The DOT color code printed on the package label"],"answer":2,"explanation":"The ERG's blue-bordered pages list materials alphabetically by proper shipping name, so they are the tool to use when you know the name but not the ID number.","handbook":"The ERG blue pages list materials by name.","hbref":"§9.5","qid":"HM-215"},"231":{"q":"I'm hauling a placarded load of corrosives when a coupling fails and product begins leaking onto the shoulder. I grab my Emergency Response Guidebook (ERG), look up the material's ID number, and need to know how to protect people and respond safely at the scene. Which section of the ERG should I turn to for that information?","options":["The blue-bordered pages, because the response action guides for each material are arranged there alphabetically by proper shipping name","The green-bordered pages, because they list the protective action distances and tell me exactly how to handle the spill","The yellow-bordered pages, because the numbered guides describing what to do at the scene are indexed there by UN/NA number","The orange-bordered pages, because they contain the numbered response action guides telling me how to protect people and control the incident"],"answer":3,"explanation":"The ERG's orange-bordered pages contain the numbered response guides explaining the hazards and the public-safety actions to protect people and control an incident.","handbook":"The ERG orange pages give response guides.","hbref":"§9.5","qid":"HM-216"},"232":{"q":"A tanker ahead of me has rolled over and is leaking poison gas. While calling CHEMTREC, I open my Emergency Response Guidebook to the green-bordered pages to decide where I should move people. What information are these green pages designed to give me?","options":["The initial isolation and protective-action distances telling me how far to evacuate and keep people away from the release","The list of proper shipping names matched to their four-digit UN/NA identification numbers","The general response guide describing fire, spill, and first-aid actions for that material's guide number","The CHEMTREC and emergency phone numbers to call for technical assistance during the incident"],"answer":0,"explanation":"The ERG's green-bordered pages give the initial isolation and protective-action distances that tell you how far to evacuate and keep people away from a release.","handbook":"The ERG green pages give isolation and evacuation distances.","hbref":"§9.5","qid":"HM-217"},"233":{"q":"I'm loading my trailer at a terminal and the dock supervisor hands me shipping papers that list a letter code (a \"compatibility group\" letter) printed right after the hazard division on one of my entries. He says this letter tells me which other items in the same hazard class can or cannot be loaded together in the same vehicle. Based on how HazMat is regulated, which class of material is this compatibility-group letter referring to?","options":["Class 8 Corrosives, so I can keep acids and bases from reacting with each other in the trailer","Class 1 Explosives, so I can tell which divisions and types may be loaded and transported together","Class 2 Gases, so I can separate the flammable gases from the poison gases during loading","Class 7 Radioactive, so I can keep the transport index totals within the limits for one vehicle"],"answer":1,"explanation":"Compatibility group letters belong only to Class 1 Explosives, showing which explosive divisions and types may be safely loaded and transported together.","handbook":"Compatibility groups apply to Class 1 explosives.","hbref":"§9.2","qid":"HM-218"},"234":{"q":"I'm prepping shipping papers for a placardable load and I notice one entry lists an identification number that begins with the letters 'NA' instead of 'UN.' A newer driver asks me what that prefix signals about where the number is valid. Which of the following is the correct thing to tell him?","options":["It is an internationally harmonized number recognized for shipments anywhere in Europe and Asia","It signals the load may only be transported on designated overseas export routes, never domestically","It is an identification number assigned for use within North America, including the United States and Canada","It means 'Not Applicable,' so no hazard class or proper shipping name is required for that line"],"answer":2,"explanation":"An 'NA' prefix marks an identification number assigned for use only within North America, namely the United States and Canada.","handbook":"NA identification numbers are used in North America.","hbref":"§9.2","qid":"HM-219"},"235":{"q":"I'm hauling a placarded load of a flammable liquid from Houston toward a port for export overseas, and my shipping papers list the material with a proper shipping name, hazard class, and a 'UN' identification number. A new driver riding with me argues that this 'UN' number only matters here in Texas and can be ignored once the freight leaves the state. Which statement about that 'UN' identification number is correct?","options":["The 'UN' number applies only within Texas, so the new driver is right that it stops mattering at the state line","The 'UN' number is valid only for shipments moving by sea, so it applies once the freight reaches the port","The 'UN' number is valid only for shipments moving by air, so a different code is needed for this truck","The 'UN' number is recognized internationally, so it identifies the material the same way no matter where the freight travels"],"answer":3,"explanation":"A 'UN' identification number is internationally recognized, so it identifies the material the same way no matter where the freight travels.","handbook":"UN identification numbers are used internationally.","hbref":"§9.2","qid":"HM-220"},"236":{"q":"I'm doing my pre-trip inspection and notice one of my packages has a diamond-shaped label I don't recognize. To confirm whether it's marking a poison (toxic) material before I accept the load, which symbol on that label should I be looking for?","options":["A skull and crossbones inside the diamond","A flame symbol above the hazard class number","A black ball burning with rays inside the diamond","A propeller-style three-bladed trefoil symbol"],"answer":0,"explanation":"A poison or toxic material (Division 6.1) is identified by a skull and crossbones symbol inside the diamond label.","handbook":"Poison labels often show a skull and crossbones.","hbref":"§9.2","qid":"HM-221"},"237":{"q":"I'm inspecting freight at a loading dock and pick up a package marked with a yellow-and-white diamond Class 7 hazard label. To confirm the contents before I sign for the load, I scan the printing inside the diamond. Which single word printed on that diamond label confirms this is a Class 7 shipment?","options":["FRAGILE, because the package contains delicate sealed source containers that can break","RADIOACTIVE, because the printed word on a Class 7 diamond label states the hazard directly","CORROSIVE, because Class 7 sealed sources are stored in acid-resistant outer casings","OXIDIZER, because the radioactive material gives off energy that can support combustion"],"answer":1,"explanation":"A Class 7 label literally prints the word RADIOACTIVE inside the diamond, which states the hazard class directly.","handbook":"Radioactive labels include the word RADIOACTIVE.","hbref":"§9.2","qid":"HM-222"},"238":{"q":"I'm at the loading rack filling my cargo tank with gasoline on a hot Texas afternoon, and the loader asks how high I want the product brought up before he shuts off the pump. To haul this flammable liquid safely and legally, how should I have the tank loaded?","options":["Brimmed all the way to the top so the liquid can't slosh and surge against the baffles while I'm braking","Filled only to the halfway mark, since a flammable liquid tank may never legally be run more than 50 percent full","Stopped short of full so there's empty space left for the product to expand as it warms during the trip","Topped off completely, then sealed with the correct hazard label applied over the dome so it counts as full"],"answer":2,"explanation":"A cargo tank of flammable liquid must not be loaded completely full because the liquid expands as it warms and needs empty space.","handbook":"Do not load a tank completely full; allow for expansion (outage).","hbref":"§9.4","qid":"HM-223"},"239":{"q":"I'm loading a cargo tank with a flammable liquid early on a cold morning, and I plan to drive south into much warmer weather as the day heats up. To decide how full I can safely fill the tank, which fact about the load should drive my decision?","options":["I can fill the tank completely to the top, because liquid contracts and takes up less space as the outside temperature rises during the day","The fill level doesn't matter for liquids, because only compressed gases change volume when the temperature around the tank changes","I should top it off now while it's cold, because a colder liquid expands and would overflow if I waited until midday to load it","I must leave empty space (outage) in the tank, because the liquid will expand as it warms up and needs room so it doesn't overflow"],"answer":3,"explanation":"Leave empty space (outage) in the tank because the liquid expands as it warms and needs room to prevent overflow.","handbook":"Liquids expand when warmed, so leave outage space.","hbref":"§9.4","qid":"HM-224"},"240":{"q":"I'm loading two boxes of placarded HazMat at a dock when the shipper's paperwork warns that the two materials can react dangerously if they come into contact. The trailer is half-empty and I want to finish quickly. To load this shipment safely, what should I do?","options":["Load the two materials so they are kept separated from each other in the trailer","Load the two materials side by side so they are easy to unload together","Mix the loose product from both so it settles evenly during transport","Stack the two materials tightly so neither one can shift on the road"],"answer":0,"explanation":"Two HazMat that can react with each other must be loaded so they are kept separated in the trailer.","handbook":"Materials that can react must be kept separated.","hbref":"§9.4","qid":"HM-225"},"241":{"q":"I'm at the dock about to load a placardable HazMat shipment, and I'm doing my final walkaround before the cargo goes on. As I review what condition the equipment must be in BEFORE any HazMat is loaded onto my trailer, which of the following must be true?","options":["I may load now and verify the brake adjustment and lamp operation at my first 2-hour tire check down the road","The brakes and lights must already be inspected and confirmed in proper working order before any HazMat is loaded","Only the trailer service brakes must work; lights can be checked later since loading happens in daylight at the dock","The brakes and lights only matter once the placards are mounted, so I can load first and inspect after placarding"],"answer":1,"explanation":"The brakes and lights must be inspected and confirmed in proper working order before any HazMat is loaded.","handbook":"Inspect the vehicle, including brakes and lights, before loading.","hbref":"§9.4","qid":"HM-226"},"242":{"q":"I'm loading a pallet of corrosive packages by hand at a shipper's dock, and several boxes are heavy and awkward to grip. To handle them safely and avoid damaging the containers, which part of each package should I use to lift and move it?","options":["Grab it by the printed hazard labels, since those panels are reinforced to withstand handling","Pull it by the loose taped flaps or banding, since those give me the firmest grip on the box","Lift it by a solid, strong section of the package, never by weak parts or the labels","Drag it across the dock by whatever edge is closest, since the corrosive can resist scuffing"],"answer":2,"explanation":"Lift HazMat packages by a solid, strong section, never by weak parts or the labels, to keep the container intact.","handbook":"Handle packages properly, not by weak parts.","hbref":"§9.4","qid":"HM-227"},"243":{"q":"I just got hired to haul placarded HazMat, and my dispatcher hands me a thick binder of the company's own loading and routing procedures. As I read through it, I notice the company rules sometimes go further than what I learned for my endorsement. To stay legal on every trip, beyond following my carrier's company rules, what else am I REQUIRED to obey at all times?","options":["Only my carrier's internal rules, since the company binder already incorporates everything the law requires of me","The verbal routing instructions my dispatcher gives me by radio, which override any written procedure","Whatever local road signs and posted limits tell me, since those replace the federal rules for HazMat","The federal and state hazardous materials regulations (the HMR), which apply on top of my carrier's own rules"],"answer":3,"explanation":"A driver must follow the federal and state hazardous materials regulations (HMR), which apply on top of the carrier's own rules.","handbook":"Drivers must follow the carrier's rules and the regulations.","hbref":"§9.1","qid":"HM-228"},"244":{"q":"I'm picking up a placarded HazMat load and the shipping papers include a signed shipper's certification. Before I sign as the driver, I want to be sure what that certification is actually telling me. What does the shipper's signed certification on the shipping paper legally represent?","options":["That the shipment was properly classified, described, packaged, marked, and labeled in accordance with the regulations","That the carrier has verified the freight charges are correct and the customer has already paid for the shipment","That the driver has personally inspected each package and accepted full liability for any leaks found en route","That the load was independently weighed twice and the total gross weight matches the bill of lading exactly"],"answer":0,"explanation":"The shipper's signed certification legally states that the shipment was properly classified, described, packaged, marked, and labeled per the regulations.","handbook":"The shipper certifies the load is properly prepared.","hbref":"§9.2","qid":"HM-229"},"245":{"q":"During my pre-trip walk-around I notice the four placards on the trailer are bright orange, while the smaller diamond labels on the individual packages inside are a deep red. A fellow driver tells me the colors are just there to help shippers track inventory. Based on hazard communication rules, what is the color of a diamond hazard label actually telling me?","options":["It identifies the carrier and the shipper responsible for the load","It signals the general type or class of hazard the material presents","It indicates the total weight of product loaded in that package","It shows the UN/NA identification number assigned to the material"],"answer":1,"explanation":"The color of a diamond hazard label signals the general type or class of hazard, such as red for flammables and yellow for oxidizers.","handbook":"Label color often indicates the type of hazard.","hbref":"§9.2","qid":"HM-230"},"246":{"q":"I'm loading my trailer at the dock and the shipping papers show a small package of a Division 2.3 poison gas weighing only about 40 pounds, plus several drums of a Table 2 corrosive totaling 600 pounds. The dock supervisor tells me I don't need to placard anything because my whole load is well under the 1,001-pound line. What should I do about placarding before I roll?","options":["Skip placards entirely, since the combined weight of both materials is under 1,001 pounds.","Placard only for the corrosive drums, because they make up the largest share of the cargo weight.","Placard for the poison gas regardless of its weight, because that material requires placards in any amount.","Wait until the load reaches 1,001 pounds total before adding any placards to the trailer."],"answer":2,"explanation":"Table 1 materials like Division 2.3 poison gas must be placarded in any amount, no matter how light the package.","handbook":"Table 1 materials require placards in any amount.","hbref":"§9.3","qid":"HM-231"},"247":{"q":"I just delivered a load of flammable liquid and my cargo tank gauge reads empty, so I head to a truck stop to grab lunch. A friend tells me that since the tank is unloaded, I can pull off all four placards and treat the rig like any non-hazmat trailer. Before I touch anything, what is the safest assumption I should make about my 'empty' tank?","options":["Because the gauge shows empty, the tank no longer contains any hazardous material and is completely safe to handle.","Because the product is gone, I can legally remove the placards immediately, since placards only apply while liquid is actually being carried.","Because the load was delivered, the residue inside has fully evaporated and cannot create any flammable vapor or hazard.","Because residue and vapors can remain inside, the tank may still be dangerous and must be treated as if it still holds hazardous material."],"answer":3,"explanation":"An emptied cargo tank can still hold dangerous liquid residue and vapors, so it must be treated and placarded as if loaded until properly purged.","handbook":"An empty tank may still be dangerous from residue.","hbref":"§9.4","qid":"HM-232"},"248":{"q":"I'm getting my X endorsement and the examiner asks me to tell the difference between a 'cargo tank' and a portable tank at the terminal. Walking the yard, I see several tanks holding liquid HazMat. Which one should I correctly identify as the 'cargo tank'?","options":["The bulk tank that is permanently attached to and forms part of the truck or trailer itself","A self-contained steel tank that was loaded onto the trailer with a forklift and can be lifted back off","Any tank holding 1,001 pounds or more of liquid, regardless of how it sits on the vehicle","A loose 55-gallon drum strapped down inside the box of the trailer for transport"],"answer":0,"explanation":"A cargo tank is permanently attached to and forms an integral part of the truck or trailer, unlike a removable portable tank.","handbook":"A cargo tank is permanently mounted on the vehicle.","hbref":"§9.4","qid":"HM-233"},"249":{"q":"I'm doing my pre-trip on a placarded HazMat load and checking the fire extinguisher mounted in my cab. The gauge reads full and it's securely mounted, but I want to confirm the unit itself meets the requirement before I roll. Which extinguisher rating is the LEAST that satisfies the requirement for my placarded vehicle?","options":["A 1 A rating, since the extinguisher must handle ordinary combustibles like wood and paper","At least a 10 B:C rating","Any working extinguisher is acceptable as long as the gauge reads full and it is securely mounted","A water-type extinguisher rated for the gallons of fuel my tank can hold"],"answer":1,"explanation":"A placarded HazMat vehicle must carry a fire extinguisher rated at least 10 B:C.","handbook":"A placarded vehicle needs at least a 10 B:C fire extinguisher.","hbref":"§9.4","qid":"HM-234"},"250":{"q":"I'm hauling a placarded load of flammable liquid on a rural two-lane road and approaching an uncontrolled railroad crossing with no gates, lights, or stop sign. Which of the following describes what Texas law requires me to do?","options":["Continue at road speed since there is no signal or stop sign forcing me to stop","Slow to a near-stop, downshift while on the tracks, and pull through to keep momentum","Stop 15 to 50 feet before the nearest rail, and cross only if I can fully clear the tracks without stopping","Stop within 5 feet of the nearest rail, then proceed once I confirm the way is clear"],"answer":2,"explanation":"A placarded vehicle must always stop 15 to 50 feet before the nearest rail and cross only when it can fully clear the tracks without stopping.","handbook":"Placarded vehicles must stop at railroad crossings.","hbref":"§9.4","qid":"HM-235"},"251":{"q":"I'm hauling a placarded load of flammable liquid and I've made my required stop 15 to 50 feet before a railroad crossing. The lights are off, no train is coming, and I can see that the far side is clear with enough room for my whole rig. As I pull forward across the tracks, what is the correct way to proceed?","options":["Downshift to a lower gear midway across so the engine has more pulling power over the rails","Shift up through the gears as I clear so I build speed and spend less time on the tracks","Slow to a near crawl on top of the rails to feel for any rough spots before continuing","Cross in a single gear without changing gears at any point until I am completely clear"],"answer":3,"explanation":"Cross railroad tracks in one selected gear and never shift gears while on the tracks to avoid stalling on the rails.","handbook":"Cross railroad tracks without shifting gears.","hbref":"§9.4","qid":"HM-236"},"252":{"q":"I'm hauling a placarded load of Division 1.1 explosives and need to stop overnight. While walking the lot to pick a spot, which of these conditions should make me reject a location and move on?","options":["A spot directly beside a trash-burning barrel where workers toss in glowing debris","A flat, well-graded gravel pad more than 5 feet back from the traveled road","A shaded corner of the lot kept cool by a row of tall trees","A spot with smooth, freshly paved asphalt and good drainage"],"answer":0,"explanation":"Explosives must be kept away from active ignition sources like a trash-burning barrel throwing flames and sparks.","handbook":"Keep explosives away from open flames and sparks.","hbref":"§9.4","qid":"HM-237"},"253":{"q":"I'm loading several sealed drums of a Class 8 corrosive liquid into my van trailer at the shipper's dock. The forklift operator asks how I want them positioned for the haul. To handle this load safely and properly, how should the drums be carried?","options":["Laid on their sides so they pack tighter and shift less during transit","Standing upright, right side up, the way they were filled and sealed","Stacked upside down so any leak is caught against the sealed top","Set on their sides but chocked snugly so they cannot roll loose"],"answer":1,"explanation":"Drums of hazardous materials must be carried upright, right side up, because their closures and seals are designed to face up.","handbook":"Carry drums upright (right side up).","hbref":"§9.4","qid":"HM-238"},"254":{"q":"I'm prepping a bulk cargo tank that carries molten sulfur, which ships at a temperature high enough to count as an elevated-temperature material. Before I roll, I want to confirm the tank shows the one extra marking the rules require for this kind of load. Which marking am I checking for?","options":["A \"COLD\" marking, since the warning tells responders the contents must be kept chilled below ambient temperature","A \"MOLTEN\" marking spelled out beside the proper shipping name to flag the liquefied state of the cargo","A \"HOT\" marking, which identifies the load as an elevated-temperature material to anyone approaching it","A \"WET\" marking, since the rules treat any superheated liquid like a dangerous-when-wet substance"],"answer":2,"explanation":"Elevated-temperature materials must display the word HOT to warn anyone approaching of the burn and thermal hazard.","handbook":"Elevated-temperature materials are marked HOT.","hbref":"§9.3","qid":"HM-239"},"255":{"q":"During my pre-trip, I'm reviewing the shipping papers for a drum of a substance that the shipper warns is harmful to fish and waterways if it spills near a river. I need to confirm the package is marked correctly before I accept the load. Which marking should appear on this package to identify it as a substance harmful to the aquatic environment?","options":["KEEP DRY, because contact with water makes this type of substance more dangerous","DANGEROUS WHEN WET, since the hazard involves water and the waterway","THIS SIDE UP, to keep the harmful liquid from leaking out toward the water","MARINE POLLUTANT, which identifies a substance harmful to the aquatic environment"],"answer":3,"explanation":"A substance harmful to waterways and aquatic life is identified by the MARINE POLLUTANT marking.","handbook":"Materials harmful to water are marked MARINE POLLUTANT.","hbref":"§9.3","qid":"HM-240"},"256":{"q":"I'm a new CDL driver studying for my HazMat endorsement, and my dispatcher tells me I'm legally required to know the rules that govern how hazardous materials are classified, packaged, marked, and transported. When I ask where those binding rules are actually written down, which source is the correct legal authority I should be studying?","options":["The federal regulations (49 CFR), which contain the legally binding Hazardous Materials Regulations","The Emergency Response Guidebook (ERG), which contains the legally binding hazard classification rules","The Texas CDL Handbook (DL-7C), which is the official legal source of all HazMat transport rules","The bill of lading and shipping papers, where the carrier writes the governing HazMat rules"],"answer":0,"explanation":"The Hazardous Materials Regulations are the legally binding rules codified in Title 49 of the Code of Federal Regulations (49 CFR).","handbook":"Hazmat rules are in the federal regulations.","hbref":"§9.1","qid":"HM-241"},"257":{"q":"I just picked up a placarded load of corrosives and stopped at a truck stop to organize my paperwork before heading out on a long interstate run. Where am I required to keep my Emergency Response Guidebook (ERG) so I am in compliance once I'm rolling?","options":["Filed at the carrier's terminal office so dispatch can reference it during an incident","Inside the vehicle, where I can reach it while driving the placarded load","With the shipper's paperwork, since the shipper prepares the hazard information","Locked in the trailer with the corrosives so it stays with the actual product"],"answer":1,"explanation":"Carry the Emergency Response Guidebook inside the cab where you can reach it while driving, since it is only useful if it is with you.","handbook":"Carry an Emergency Response Guidebook in the vehicle.","hbref":"§9.5","qid":"HM-242"},"258":{"q":"You are hauling a placarded load when you notice a small amount of liquid dripping from one of your sealed drums onto the trailer floor. The leak is minor and no one's life is in immediate danger. Which action best follows DPS HazMat procedure?","options":["Continue your route to the next truck stop, where a mechanic can inspect and reseal the drum","Drive slowly to the nearest repair shop so the leak can be fixed before it spreads further","Leave the vehicle where it is, do not move it, and call for qualified help to handle the leak","Cover the drip with absorbent rags, keep going, and report the leak when you finish the run"],"answer":2,"explanation":"If a HazMat leak is found, never move the vehicle and instead call qualified help, since moving it can spread contamination.","handbook":"Do not move a leaking vehicle unless to protect life; get help.","hbref":"§9.5","qid":"HM-243"},"259":{"q":"I'm about to start a long haul carrying placarded flammable liquid, and I want my pre-trip inspection to meet the hazmat standard before I roll out. Which of the following BEST describes what I must inspect before this trip begins?","options":["Only the shipping papers and the four placards, since the vehicle itself was checked on the previous run","Only the tires, because they are the one item the rules require me to re-check every 2 hours or 100 miles","Only the brake system, since brakes are the single most critical component on a loaded hazmat unit","The brakes and the entire vehicle, performing a complete pre-trip inspection of the whole unit"],"answer":3,"explanation":"Hauling placarded HazMat adds to your duties, so perform a complete pre-trip inspection of the brakes and the entire vehicle before the trip.","handbook":"Inspect the whole vehicle before a hazmat trip.","hbref":"§9.4","qid":"HM-244"},"260":{"q":"I'm hauling a placarded load of chlorine (Class 2.3 poison gas) on a rural Texas highway when I approach an unmarked railroad crossing with no gate, no flashing lights, and no other traffic around. What does the law require me to do here?","options":["Stop between 15 and 50 feet before the nearest rail, then cross only if I can clear the tracks completely","Slow down and treat it as a yield, rolling through since there are no signals or approaching trains","Stop only if I see a STOP or RxR sign posted, otherwise proceed at the posted highway speed","Shift into a lower gear before the rails and keep the engine pulling steadily all the way across"],"answer":0,"explanation":"A placarded poison gas load must stop 15 to 50 feet before the nearest rail at every crossing and cross only if it can fully clear the tracks.","handbook":"Vehicles with poison gas must stop at railroad crossings.","hbref":"§9.4","qid":"HM-245"},"261":{"q":"I earned my HazMat (H) endorsement and have been hauling placarded loads ever since. My buddy says that once you pass the security threat assessment and the written test, you're set for life and never have to touch the HazMat material again. At what interval does Texas DPS actually expect me to repeat my HazMat training to stay current?","options":["About every 1 year, tied to each annual medical certificate renewal","About every 3 years","About every 10 years, matching the standard CDL renewal cycle","Never again — once the endorsement and TSA check are passed, no retraining is required"],"answer":1,"explanation":"HazMat training must be repeated about every 3 years to keep the driver current on safe handling, placarding, and emergency procedures.","handbook":"Hazmat training must be repeated at least every three years.","hbref":"§9.1","qid":"HM-246"},"262":{"q":"I'm doing my pre-trip and the shipping papers list a Class 6.1 load; the trailer is already showing a diamond placard reading 'POISON' (TOXIC). A newer driver asks me what that placard is actually warning us about. Which statement should I give him?","options":["It warns the load is a flammable liquid, so the real danger is fire if it ignites near an open flame","It warns the load is corrosive, so the real danger is chemical burns to skin and eyes on contact","It warns the material is harmful or deadly to people, so exposure to it can poison or kill","It warns the load is an oxidizer, so the real danger is that it makes other materials burn faster"],"answer":2,"explanation":"A POISON or TOXIC placard warns that the material is harmful or deadly to people and can poison or kill on exposure.","handbook":"A poison/toxic placard warns of a harmful or deadly material.","hbref":"§9.2","qid":"HM-247"},"263":{"q":"I'm hauling a load placarded 'OXYGEN' (Class 2.2) when I notice smoke coming from one of my tires at a roadside check. As I size up the situation, which of the following should weigh MOST heavily in how I treat the heat and any flame near this cargo?","options":["The oxygen will smother and choke out any small fire before it can spread, so I have extra time to react.","Being a non-flammable gas, the oxygen cannot affect a fire either way, so the tire is my only concern.","The oxygen will cool the surrounding load and lower the temperature, reducing the danger from the hot tire.","The oxygen can feed and intensify a fire, so I must treat even a small flame near this load as a serious threat."],"answer":3,"explanation":"Oxygen feeds and intensifies fire, so any flame or overheating near an oxygen load must be treated as a serious threat.","handbook":"Oxygen can make a fire burn hotter and faster.","hbref":"§9.2","qid":"HM-248"},"264":{"q":"You're hauling a placarded load of Division 1.2 explosives and need to stop for your federally required rest break. Scanning for a legal parking spot, which location MUST you keep at least 300 feet away from before you shut down?","options":["A roadside warehouse where workers and customers regularly gather","The painted fog line on the edge of the traveled roadway","A set of railroad tracks crossing the highway ahead","Another commercial vehicle parked legally in the rest area"],"answer":0,"explanation":"Division 1.1, 1.2, and 1.3 explosives may never be parked within 300 feet of a building where people gather, such as a roadside warehouse.","handbook":"Park explosives at least 300 feet from bridges, tunnels, and buildings.","hbref":"§9.6","qid":"HM-249"},"265":{"q":"I'm hauling a placarded load and need to leave my rig parked on the shoulder of a rural highway for a few minutes while I check a roadside problem. Regulations say the vehicle must be attended. To legally count as the attendant, how far from my parked placarded vehicle am I allowed to be?","options":["Within 5 feet of the vehicle, the same distance I must keep clear of the traveled road","Within 100 feet of the vehicle, with it in clear view and able to move it if needed","Within 300 feet of the vehicle, the same buffer required around bridges and tunnels","Within a quarter of a mile, as long as I can still see the placards"],"answer":1,"explanation":"The attendant of a parked placarded vehicle must stay within 100 feet of it, keep it in clear view, and be able to move it in an emergency.","handbook":"An attendant must be within 100 feet of the vehicle.","hbref":"§9.6","qid":"HM-250"},"266":{"q":"During my pre-trip, my dispatcher tells me one of the cargo tanks on my rig is a \"portable tank\" rather than a cargo tank truck. As I inspect it to confirm, which feature would CORRECTLY identify it as a portable tank?","options":["It is permanently welded to the vehicle's chassis and cannot be removed","It is an integral structural part of the trailer frame itself","It is a bulk container that is not permanently attached to the vehicle","It is a fixed tank built directly into the cab and body of the truck"],"answer":2,"explanation":"A portable tank is a bulk container that is not permanently attached to the vehicle, so it can be loaded and removed.","handbook":"A portable tank is not permanently mounted on the vehicle.","hbref":"§9.4","qid":"HM-251"},"267":{"q":"I'm loading a Class 2 compressed gas shipment at a chemical depot and the dock supervisor asks how the product should already be containerized before I sign for it and haul it. To accept the load legally and safely, in which type of container must the compressed gas be packaged?","options":["Sealed in heavy fiberboard cartons that are banded together on a shrink-wrapped pallet","Loaded loose in the open bed of a flatbed trailer and secured with cargo straps","Poured into a lined hopper trailer the same way dry bulk materials are hauled","Contained in pressurized cylinders or carried in a tube trailer built for the gas"],"answer":3,"explanation":"Compressed gas is held under pressure and must be carried in engineered cylinders or a tube trailer built for the gas.","handbook":"Compressed gas is carried in cylinders or tube trailers.","hbref":"§9.4","qid":"HM-252"},"268":{"q":"I'm hauling a cargo tank of liquefied flammable gas on a hot Texas afternoon, and as the load warms in the sun I hear a brief hiss and see a small puff of vapor venting from a spring-loaded device on top of the tank, which then stops on its own. What is this pressure relief valve doing, and how should I treat it?","options":["It is automatically releasing built-up internal pressure to keep the tank from rupturing, so I leave it alone and let it function as designed.","It is a sign the tank is overfilled past its rated capacity, so I must stop and bleed off product until the hissing stops.","It is adding pressure to the tank to keep the gas compressed, so I should expect it to keep cycling and ignore the vapor entirely.","It is failing and venting cargo, so I should tighten or cap the valve at my next stop to seal the tank shut and stop the loss."],"answer":0,"explanation":"A pressure relief valve automatically vents built-up internal pressure to keep the tank from rupturing, so let it function as designed.","handbook":"Pressure relief valves release pressure to prevent bursting.","hbref":"§9.4","qid":"HM-253"},"270":{"q":"I just finished unloading a placarded HazMat delivery, and as I'm doing my walk-around I notice that one of the packages left on the dock has a wet, discolored stain spreading across the bottom and a faint chemical odor. The consignee has already signed for the load. Under DPS HazMat rules, what is the correct thing for me to do?","options":["Nothing further is required of me — the consignee signed for the shipment, so responsibility for the leaking package has fully transferred to them","Report the leak right away and make sure the package is contained and handled safely, even though delivery is technically complete","Quietly set the package aside out of view and say nothing, since reporting a leak after a signed delivery will only create paperwork and delay me","Reseal the package with tape, mark down the value, and arrange to dispose of or resell the contents at a discount to recover the loss"],"answer":1,"explanation":"A discovered leak must be reported promptly and the package contained and handled safely, even after delivery is complete.","handbook":"Report and safely handle a leaking package.","hbref":"§9.5","qid":"HM-254"},"271":{"q":"A drum of corrosive (Class 8) liquid in my trailer ruptures during a delivery stop and a puddle is spreading across the lot. I have already warned bystanders, kept people back, and notified CHEMTREC. Who should actually perform the physical cleanup of this spilled material?","options":["I should grab my gloves and absorbent and clean it up myself, since I am the driver in control of the load","The shipper must come out and clean it up, because the shipper classified and packaged the material","Trained emergency responders or qualified cleanup contractors should handle the cleanup","Any available bystander can be directed to help contain and remove the material quickly"],"answer":2,"explanation":"Spill cleanup is a specialized job for trained emergency responders or qualified cleanup contractors who can handle the material safely.","handbook":"Trained responders handle hazmat spill cleanup.","hbref":"§9.5","qid":"HM-255"},"272":{"q":"I just completed the security awareness training required for my HazMat endorsement, and a coworker asks me what the point of that training actually was. Based on what the training is designed to accomplish, which of the following is the BEST description of what it taught me to do?","options":["Memorize the four hazard classes that always require placards so I can placard faster at the dock","Adjust my following distance and braking points so I can move a placarded load more quickly through traffic","Skip redundant en-route inspections once my paperwork has already been verified at the terminal","Recognize suspicious behavior or potential security risks around my load and report those threats to the proper authorities"],"answer":3,"explanation":"Security awareness training teaches drivers to recognize suspicious behavior or security threats to their load and report them to the proper authorities.","handbook":"Security training helps drivers spot and report threats.","hbref":"§9.1","qid":"HM-256"},"273":{"q":"I'm hauling a placarded load of corrosives and a state trooper at a weigh station asks me to point to the \"basic description\" of the material on my shipping papers. Which combination of entries should I show the trooper as the basic description?","options":["The proper shipping name, hazard class, identification number, and packing group","The proper shipping name, total weight, emergency phone number, and ERG guide page","The hazard class, placard color, shipper's signature, and number of packages","The identification number, vehicle registration, carrier name, and route plan"],"answer":0,"explanation":"The basic description of a hazardous material is the proper shipping name, hazard class, identification number, and packing group.","handbook":"These items form the basic shipping description.","hbref":"§9.2","qid":"HM-257"},"274":{"q":"I'm hauling a placarded load of Class 3 flammable liquid when a small fire breaks out near a leaking drum in the cargo area. I have access to several extinguishing options. To knock down this fire most effectively, what should I use?","options":["Douse it with a steady, heavy stream of water to cool the burning liquid down","Smother it with foam or use a B:C-rated extinguisher to cut off the oxygen","Shovel loose roadside sand over the flames until they are buried","Let it burn itself out while you back away and wait for responders"],"answer":1,"explanation":"A flammable-liquid (Class 3) fire must be smothered with foam or a B:C-rated extinguisher to cut off oxygen, never cooled with water.","handbook":"Fight a flammable liquid fire with foam or a B:C extinguisher.","hbref":"§9.5","qid":"HM-258"},"275":{"q":"I'm hauling a Class 3 flammable liquid (drums of gasoline) when one drum starts a small fire in the cargo area after a leak. A bystander runs up with a bucket of water and offers to help me knock down the flames before they grow. Before I let him throw it, what should I expect water to do to this flammable-liquid fire?","options":["Smother the flames quickly because the water cuts off the fire's oxygen supply","Cool the burning gasoline below its flash point and put the fire right out","Spread the fire, since the burning liquid floats on and is carried by the water","Do little either way, so it is the safest thing to try while waiting for help"],"answer":2,"explanation":"Water spreads a burning flammable liquid like gasoline because the liquid floats on top of the water and is carried along with it.","handbook":"Water can spread a burning flammable liquid.","hbref":"§9.5","qid":"HM-259"},"276":{"q":"I'm hauling a placarded load of a Class 5 oxidizer when a small fire breaks out in the cargo. A bystander grabs an extinguisher and says, \"Don't worry, smothering it by cutting off the air will put it out fast.\" Based on the chemistry of what I'm carrying, why is that assumption wrong?","options":["Because oxidizers are corrosive, so they eat through the extinguisher before it can smother the flames","Because the fire is too cold to be affected, since oxidizers only burn at freezing temperatures","Because oxidizers absorb water, so adding any moisture from the extinguisher makes the fire spread faster","Because an oxidizer releases its own oxygen, so the fire can keep burning even with little air around it"],"answer":3,"explanation":"An oxidizer (Class 5) supplies its own oxygen, so the fire can keep burning even with little air around it and cannot be smothered.","handbook":"Oxidizers can keep a fire going with little air.","hbref":"§9.2","qid":"HM-260"},"277":{"q":"During my pre-trip inspection at the dock, I notice a small wet stain and a faint chemical smell coming from one of the corrosive (Class 8) packages a shipper just loaded. The bill of lading looks complete and the delivery is time-sensitive. What is the BEST reason I should refuse to transport this package?","options":["A leaking package can harm people and contaminate the surrounding area, so it must not be transported","A small leak only affects on-time delivery, so I can haul it as long as I drive faster to make up the schedule","The shipper already signed the bill of lading, so the leak becomes the carrier's paperwork problem, not mine","A minor stain is normal for Class 8 freight, so I can wipe the package down and load it without further action"],"answer":0,"explanation":"A leaking hazardous material package can injure people and contaminate the area, so the driver must refuse it and not transport it.","handbook":"Do not transport leaking packages; they endanger people.","hbref":"§9.4","qid":"HM-261"},"278":{"q":"My placarded tanker develops a corrosive leak while I'm parked at a roadside rest area. The proper response is to leave the vehicle in place, keep people back, and notify emergency responders. Under what circumstance would I be justified in actually moving the leaking vehicle?","options":["To reach the nearest fuel station before the tank empties out","To move people out of immediate danger from the spreading hazard","To get to a repair shop faster and avoid a long delay","To position the truck closer to a building for easier cleanup"],"answer":1,"explanation":"A leaking HazMat vehicle should only be moved when necessary to get people out of immediate danger from the spreading hazard.","handbook":"Move a leaking vehicle only to protect life.","hbref":"§9.5","qid":"HM-262"},"279":{"q":"I'm hauling a placarded load of corrosives when a coupling failure causes a release onto the shoulder. After I've contained the immediate danger, kept bystanders back, prevented smoking, and called emergency responders and CHEMTREC, federal rules still require that the incident be reported. Which party am I responsible for notifying so that this required incident report can be made?","options":["The shipper, since they classified, packaged, and prepared the shipping papers for the corrosives","The local fire marshal, who must file the official written incident report for any roadside spill","My employer/carrier, who is the party responsible for transporting the load and reporting the incident","The state DPS weigh-station inspector nearest the spill, since placarded loads are tracked at scales"],"answer":2,"explanation":"The carrier is the party responsible for transporting the load and making the required hazmat incident report.","handbook":"Report hazmat incidents to your employer/carrier.","hbref":"§9.5","qid":"HM-263"},"280":{"q":"I'm walking around my trailer doing a pre-trip inspection on a load that needs a Class 3 flammable-liquid placard. To confirm the placard is correct, I check the diamond for the hazard class number. Where on the placard should I look to read that number?","options":["At the very top point of the diamond, just above the symbol","Centered in the middle of the diamond, inside the symbol","Along the far-right corner of the diamond","At the bottom point of the diamond, below the symbol"],"answer":3,"explanation":"On a DOT placard the hazard class or division number is placed at the bottom point of the diamond, below the symbol.","handbook":"The hazard class number is at the bottom of the placard.","hbref":"§9.3","qid":"HM-264"},"281":{"q":"I'm doing my pre-trip and inspecting a diamond-shaped placard on the trailer to confirm it's the right one. To quickly identify the type of danger at a glance, which area of the placard should I look at for the hazard symbol (such as the flame, skull, or radioactive trefoil)?","options":["The top corner of the placard, above the written hazard class name","The bottom corner of the placard, where the hazard class number is printed","The right edge of the placard, beside the four-digit ID number","The center of the placard, directly over the diagonal color split"],"answer":0,"explanation":"On a DOT placard the hazard symbol is placed in the top corner of the diamond, above the written hazard class name.","handbook":"The hazard symbol is at the top of the placard.","hbref":"§9.3","qid":"HM-265"},"282":{"q":"At a loading dock, my dispatcher tells me my next load will be shipped in \"bulk packaging\" and I need to verify it before I sign the papers. As I walk the trailer, which of these containers correctly fits the definition of bulk packaging?","options":["A pallet stacked with sealed fiberboard cases, each holding several small bottles inside cushioning","A large portable tank loaded directly with the product, with no inner packaging holding the contents","A single 5-gallon plastic drum with a screw-top lid sitting near the trailer wall","A small zip-sealed bag of granules tucked inside a labeled cardboard carton"],"answer":1,"explanation":"Bulk packaging is a large container, such as a portable tank, loaded directly with the product with no inner packaging holding the contents.","handbook":"Bulk packaging holds large amounts with no inner packaging.","hbref":"§9.2","qid":"HM-266"},"283":{"q":"I'm loading my trailer at a chemical warehouse and the shipper tells me to sign for several 'non-bulk' packages of a Class 8 corrosive. As I sort the freight on my dock, which container should I expect to match that 'non-bulk' description?","options":["The 6,000-gallon cargo tank permanently mounted on a separate trailer","The portable rail tank car being switched onto the warehouse siding","The sealed 55-gallon steel drums stacked together on a single pallet","The river barge compartment waiting to receive the same product"],"answer":2,"explanation":"Non-bulk packaging is the smaller containers used to ship HazMat, such as drums, boxes, jerricans, and bags.","handbook":"Non-bulk packaging is smaller, like drums and boxes.","hbref":"§9.2","qid":"HM-267"},"284":{"q":"During my pre-trip on a cargo tank loaded with a flammable liquid, I climb up to inspect the dome area on top of the tank. Before I pull onto the highway, what condition must the manhole covers be in to keep the load secure and leak-free?","options":["Cracked open slightly so internal vapor pressure can vent during the trip","Removed and stowed in the cab so they cannot rattle loose on the road","Left wide open until I reach the next inspection stop down the route","Fully closed and properly sealed before the vehicle is moved"],"answer":3,"explanation":"A cargo tank's manhole (dome) covers must be fully closed and properly sealed before the vehicle is moved to keep the load contained.","handbook":"Tank manhole covers must be closed and sealed.","hbref":"§9.4","qid":"HM-268"},"285":{"q":"I'm a tank driver about to load a Class 3 flammable liquid through a transfer hose, and during my pre-loading check I notice one hose has a worn outer layer with a small surface crack near the coupling. Before I attach it and start the product flow, what does the handbook require me to do about the hoses used for loading or unloading?","options":["Use only hoses that are in good condition, so I must set this cracked hose aside and select an undamaged one before loading","Go ahead and load with this hose since the crack is only on the outer layer and the engine will stay running to keep pressure steady","Use the cracked hose but reduce the flow rate, because a slower transfer prevents a hose in marginal condition from failing","Attach the hose as-is and simply station a second person 25 feet away to watch for leaks during the transfer"],"answer":0,"explanation":"Hoses used to load or unload HazMat must be in good condition, so a cracked hose must be set aside and an undamaged one used.","handbook":"Loading/unloading hoses must be in good condition.","hbref":"§9.4","qid":"HM-269"},"286":{"q":"I'm at a terminal getting my placarded trailer ready, and several tasks line up: I have to fuel the tractor, swap a burned-out clearance lamp, sign off on the shipping papers, and oversee a crew transferring drums of a Class 3 flammable liquid into the trailer. During which of these tasks must I be MOST strict about keeping all ignition sources — lit cigarettes, open flames, sparking tools — completely away from the operation?","options":["While fueling the tractor, since the engine stays running so I can monitor the fuel gauge as the tank fills","While the crew is loading the Class 3 flammable liquid drums into the trailer, since vapors can ignite during the transfer","While replacing the burned-out clearance lamp, since I'll be working with the electrical wiring near the load","While reviewing and signing the shipping papers, since I must keep them on top within reach before I drive"],"answer":1,"explanation":"Keep all ignition sources away while loading Class 3 flammable liquids, because escaping vapors can ignite during the transfer.","handbook":"Keep ignition sources away when loading flammable materials.","hbref":"§9.4","qid":"HM-270"},"287":{"q":"I'm doing my pre-trip inspection on a truck loaded with Division 1.1 explosives before heading out on a designated HazMat route. Several things catch my eye during the walk-around. Which of the following findings would by itself make this vehicle unsafe to operate and require me to fix it before I haul this load?","options":["One of the rear mud flaps is cracked and slightly bent at the lower edge","A reflective triangle in my emergency kit has a faded, dull surface","There is a fuel leak dripping steadily from a fitting near the tank","The passenger-side mirror is loosely mounted and vibrates while idling"],"answer":2,"explanation":"A vehicle hauling explosives must have no fuel or oil leaks, since any leak is an unacceptable fire and ignition hazard near the load.","handbook":"A vehicle hauling explosives must have no fuel or oil leaks.","hbref":"§9.4","qid":"HM-271"},"288":{"q":"A roadside officer stops me and asks for proof that I'm authorized to haul a placarded tank of corrosives. I completed my TSA security threat assessment and fingerprinting months ago and passed everything. Which single document do I hand over that actually shows my HazMat (H/X) endorsement is currently valid?","options":["The TSA security threat assessment approval letter I received in the mail after my background check cleared","My current DOT medical examiner's certificate, since it is what proves I am physically cleared to drive","The fingerprint receipt and application packet I submitted at the licensing office for the endorsement","My commercial driver license, because the H or X endorsement is printed directly on the license itself"],"answer":3,"explanation":"The HazMat endorsement is a code (H, or X for tank plus HazMat) printed directly on the face of your commercial driver license.","handbook":"The HazMat endorsement appears on the CDL.","hbref":"§9.1","qid":"HM-272"},"289":{"q":"I'm hauling a placarded load of corrosives and need to make a short stop to check my paperwork. The only spots I can find are all close to a two-lane highway. Under the rules for parking a placarded vehicle, which of these locations would put me in violation?","options":["A shoulder pull-off where my truck would sit just 3 feet from the traveled part of the road","A gravel lot set back about 20 feet from the edge of the traveled road","A rest-area space measured 10 feet back from the traveled part of the road","A wide turnout that keeps my truck a full 8 feet off the traveled road"],"answer":0,"explanation":"A placarded vehicle must not be parked within 5 feet of the traveled part of the road.","handbook":"Do not park a placarded vehicle within 5 feet of the traveled road.","hbref":"§9.6","qid":"HM-273"},"290":{"q":"I'm picking up a placarded load and the shipper hands me paperwork showing the proper shipping name, hazard class, and ID number. The carrier has dispatched and will report any incident. As I think about who else is legally on the hook for safe transport of this HazMat, which party completes the shared-responsibility chain alongside the shipper and the carrier?","options":["The customer receiving the freight, since they accept the load at the dock","The driver, who inspects the load, refuses leaks, placards, and drives safely","The TSA agent who issued my background-check clearance","The dispatcher, who only assigns the route and never touches the cargo"],"answer":1,"explanation":"The driver completes the HazMat safety chain by inspecting the load, refusing leaking or improperly marked shipments, placarding all sides, and driving safely.","handbook":"Shipper, carrier, and driver all share hazmat responsibility.","hbref":"§9.1","qid":"HM-274"},"291":{"q":"I'm loading a Class 7 radioactive shipment, and the shipper tells me to verify the labels match the transport index before I sign the papers. Looking at the package, I see two labels printed with a Roman-numeral category that tells me the radiation level. Which set of category designations should I expect to find on those radioactive labels?","options":["Categories A, B, or C, lettered to match the package group","Categories 1, 2, or 9, matching the hazard class numbers","Categories I, II, or III, indicating the radiation level","Categories X, Y, or Z, marking the transport index range"],"answer":2,"explanation":"Radioactive (Class 7) labels carry a category in Roman numerals — I, II, or III — indicating the radiation level and transport index.","handbook":"Radioactive labels are category I, II, or III.","hbref":"§9.2","qid":"HM-275"},"292":{"q":"I'm loading a trailer with two different HazMat packages, and the shipping papers show they are reactive with each other. The shipper hasn't told me to keep them separated, and there's room to set them side by side. Before I secure them next to each other, what is the real safety concern I need to weigh?","options":["Setting them next to each other is fine because the packaging alone is built to keep any two materials from ever interacting","The only worry is that the combined weight may push me over the 1,001 lb threshold that triggers placards","Nothing meaningful happens; reactive materials simply neutralize one another when stored in the same space","Loading the two reactive chemicals together could start a fire or a chemical reaction, so they must be kept apart"],"answer":3,"explanation":"Incompatible reactive materials must be kept separated during loading because contact can trigger a fire or dangerous chemical reaction.","handbook":"Reactive chemicals loaded together can cause a fire or reaction.","hbref":"§9.4","qid":"HM-276"},"293":{"q":"A drum on my placarded trailer is leaking an unknown liquid onto the shoulder, and the shipping papers are unclear about exactly what it is. To figure out what the substance is so I can give responders accurate information, which of these should I NEVER do?","options":["Taste or touch the material to help identify what it is","Check the proper shipping name and ID number on the shipping papers","Look up the four-digit ID number in the Emergency Response Guidebook","Note the hazard class shown on the placard and labels"],"answer":0,"explanation":"Never taste or touch a material to identify it, since even a tiny amount can cause serious injury, poisoning, or chemical burns.","handbook":"Never touch or taste a material to identify it.","hbref":"§9.5","qid":"HM-277"},"294":{"q":"You are hauling a placarded load of flammable liquid and stop at a roadside rest area. While you are out of the cab, you notice flames coming from the rear of your trailer near the cargo. The fire is already too large to knock down with your small extinguisher. What should you do FIRST?","options":["Climb in and try to drive the burning trailer to an open field away from the rest area","Keep people back from the vehicle and notify emergency responders for help","Open the trailer doors to vent the smoke and reach the burning cargo inside","Set the shipping papers aside in the cab so the fire cannot destroy them"],"answer":1,"explanation":"For a HazMat fire beyond control of a hand extinguisher, protect life first by keeping people away and notifying emergency responders.","handbook":"If a placarded load is on fire, get people away and get help.","hbref":"§9.5","qid":"HM-278"},"295":{"q":"I'm doing my pre-trip on a placarded trailer the dock crew loaded overnight, and the paperwork sitting on the driver's seat lists a Class 8 corrosive load. Before I roll, what is the one thing I MUST confirm about the placards already hung on all four sides?","options":["That the placard color matches the paint scheme and lettering on the side of my tractor","That a placard is displayed on each of the four sides so it is readable from every direction","That the placards correctly identify the actual material I am hauling as shown on the shipping papers","That the placards match the type of fuel burned by the tractor pulling the load"],"answer":2,"explanation":"The driver must verify that the placards correctly identify the actual material being hauled, cross-checked against the shipping papers.","handbook":"Make sure the placards match the material being transported.","hbref":"§9.3","qid":"HM-279"},"296":{"q":"I'm loading a placardable shipment of corrosives (Class 8), but I'm out of Class 8 placards in my supply box. I do have leftover Class 3 (Flammable) placards from a previous run, and the truck is already several hours behind schedule. Which of the following is the correct way to think about placarding this load before I leave?","options":["Using the Class 3 placards is acceptable for a short trip, since displaying any placard still warns other drivers that I'm hauling hazardous material","I may run without any placards as long as I keep the shipping papers showing Class 8 within reach on the seat","Mixing the Class 3 placards on two sides and leaving the other two sides blank is allowed because the load is only partially placarded","Displaying the wrong (Class 3) placards is illegal and unsafe, so I must not move the load until I have the correct Class 8 placards"],"answer":3,"explanation":"Placards must be correct on all four sides, so a load may not be moved with wrong placards; a Class 8 corrosive needs Class 8 placards.","handbook":"Displaying the wrong placards is illegal.","hbref":"§9.3","qid":"HM-280"},"297":{"q":"You're hauling a placarded load of flammable liquid across Texas and your hours-of-service clock is forcing a break within the next 20 minutes. Coming up, you can see a packed shopping-center lot, a crowded roadside rest area full of families, and a quiet gravel pull-off well clear of any crowd. Where should you plan to make your stop?","options":["At the quiet gravel pull-off, choosing a safe place away from people whenever you stop with a placarded load","At the crowded roadside rest area, because rest areas are the only legally approved stopping points for placarded vehicles","At the packed shopping-center lot, since staying in a busy, well-lit area with witnesses keeps the cargo safer from theft","Wherever you happen to be when the clock runs out, parking right at the edge of the traveled road so you do not lose drive time"],"answer":0,"explanation":"When transporting a placarded load, always plan to stop in a safe place well away from people to minimize exposure if something goes wrong.","handbook":"Plan hazmat stops in safe places away from people.","hbref":"§9.6","qid":"HM-281"},"298":{"q":"I just earned my H endorsement and I'm reviewing why all the hazmat regulations exist before my first placarded run. A fellow driver tells me the rules boil down to three core goals: containing the product, communicating the risk, and one more. EXCEPT for which goal below, all of these reflect the actual purpose of the hazmat regulations. Which option does NOT belong because it misstates the third goal?","options":["To contain the material so a release is prevented or limited","To move the freight faster and cut delivery costs for the carrier","To communicate the hazard through placards, labels, and shipping papers","To ensure the product reaches its destination safely and without harm"],"answer":1,"explanation":"The goals of the hazmat rules are to contain the product, communicate the risk, and ensure safe transport, not to speed delivery or cut costs.","handbook":"The rules contain the material, communicate the risk, and ensure safe transport.","hbref":"§9.1","qid":"HM-282"},"299":{"q":"I'm a new HazMat driver picking up a load of corrosives. The drums look sealed, but I notice the shipping papers were filled out before I arrived and I had no say in how the product was classified or boxed. As I sort out who owns which duty, which of the following is the SHIPPER'S responsibility rather than mine as the driver?","options":["Stopping 15 to 50 feet before any railroad crossing and never shifting gears while crossing","Placarding all four sides of the trailer and keeping the papers within my reach while driving","Correctly determining the proper shipping name and selecting the right packaging for the material","Refusing the shipment if a drum is leaking and inspecting the cargo before I haul it"],"answer":2,"explanation":"The shipper classifies the material, determines the proper shipping name, and selects the correct packaging before the load reaches the driver.","handbook":"The shipper is responsible for correctly naming and packaging the material.","hbref":"§9.1","qid":"HM-283"}};
  var APPEND=[];
  var TR={"ru":{"0":{"q":"Я только что получил отметку H в правах, и новый водитель спрашивает меня, зачем вообще нужны все эти правила о табличках-плакардах, грузовых документах и упаковке. Что из перечисленного НАИЛУЧШИМ образом описывает главную цель правил перевозки опасных грузов?","options":["Удержать материал так, чтобы он не вытек, и сообщить об опасности, чтобы окружающие могли держаться в стороне и безопасно реагировать","Гарантировать более быструю доставку, давая грузам с плакардами приоритетный доступ к полосам и маршрутам шоссе","Документировать каждую отгрузку, чтобы перевозчик мог выставить клиенту правильную надбавку за обращение с опасным грузом","Снизить расходы перевозчика на топливо, направляя тяжёлые опасные грузы по самым коротким доступным дорогам"],"explanation":"Правила перевозки опасных грузов призваны удержать материал, чтобы он не вытек, и предупредить об опасности, чтобы окружающие держались в стороне и реагировали безопасно."},"1":{"q":"Меня только что наняли на маршрут для перевозки партии коррозионного вещества, требующей размещения плакатов (placard), и у меня уже есть CDL класса A с разрешением на цистерну (tanker). Что из перечисленного я обязан сделать, чтобы легально выйти в этот рейс?","options":["Ничего дополнительного — мой CDL класса A с разрешением на цистерну уже покрывает любой груз с плакатами","Получить разрешение на опасные материалы (H), которое требует прохождения проверки безопасности TSA и снятия отпечатков пальцев","Добавить разрешение на двойные/тройные прицепы, поскольку грузы с плакатами нужно распределять по нескольким прицепам","Добавить пассажирское разрешение, потому что грузы с плакатами регулируются так же, как перевозка пассажиров"],"explanation":"Для перевозки любого количества опасных грузов, требующего размещения табличек, нужна отметка об опасных грузах (H), а для нее — проверка безопасности TSA и снятие отпечатков пальцев."},"2":{"q":"У меня уже есть техасские права CDL класса A и действующая медицинская справка DOT. Новый работодатель хочет, чтобы я начал перевозить грузы с коррозийными веществами, требующие размещения табличек (плакардов), поэтому мне нужно добавить разрешение H. Когда я спрашиваю сотрудника DPS, какой дополнительный шаг требует это разрешение, которого НЕ требовали мои текущие права, что она, скорее всего, мне ответит?","options":["Ничего дополнительного не нужно; как только у вас есть права CDL класса A с действующей медицинской картой DOT, разрешение H просто впечатывается в права без каких-либо дополнительных требований","Вы должны пройти второй, более подробный медосмотр DOT и предоставить обновлённую справку медицинского эксперта, прежде чем разрешение будет выдано","Вы должны пройти проверку угрозы безопасности TSA, которая включает проверку биографических данных и снятие отпечатков пальцев, прежде чем разрешение будет выдано","Вам нужно только повторно пройти стандартную проверку зрения CDL, чтобы подтвердить, что вы по-прежнему можете читать таблички на расстоянии"],"explanation":"Для получения отметки об опасных грузах нужно пройти проверку безопасности TSA, включая проверку биографических данных и снятие отпечатков пальцев."},"3":{"q":"Меня наняли перевезти груз коррозийного материала, и перед выездом я проверяю документы на погрузочной площадке. Я замечаю, что класс опасности, надлежащее транспортное наименование и идентификационный номер ООН уже внесены в транспортные документы, но я хочу убедиться, что этим занималась нужная сторона. Согласно правилам перевозки опасных грузов, чьей обязанностью было изначально определить материал как опасный и подготовить эти транспортные документы?","options":["Автоперевозчик, поскольку перевозчик отвечает за рейс, за транспортировку груза и за сообщение о любых происшествиях","Водитель, поскольку именно я обязан держать документы в пределах досягаемости и отказаться от груза, если что-то выглядит неправильно","Получатель, поскольку компания, принимающая поставку, подтверждает содержимое и расписывается за опасный груз","Грузоотправитель, поскольку грузоотправитель классифицирует, называет, упаковывает и маркирует материал и готовит транспортные документы"],"explanation":"Грузоотправитель классифицирует, именует, упаковывает и маркирует опасный груз и оформляет грузовые документы до того, как груз попадает к водителю."},"4":{"q":"Я перевожу по Техасу груз с табличками (плакардами) — коррозийные вещества — и только что выехал на автомагистраль. Чтобы соблюдать правила о товаросопроводительных документах на опасный груз во время движения, где сейчас должны находиться эти документы?","options":["В пределах моей досягаемости при пристёгнутом ремне безопасности, либо в кармане на двери водителя, и поверх остальных документов","Закреплёнными в спальном отсеке, чтобы поток воздуха из открытого окна их не разбросал","В коробке для документов, закреплённой снаружи прицепа рядом с табличками-плакардами","Уложенными под грузом в прицепе, чтобы они находились вместе с самим грузом"],"explanation":"Во время движения грузовые документы на опасный груз должны быть в пределах досягаемости водителя с пристегнутым ремнем или в кармане двери водителя и поверх других бумаг."},"5":{"q":"Я новый водитель и загружаю прицеп со смешанным грузом, в котором есть один опасный груз (HazMat) вместе с несколькими нерегулируемыми товарами. Когда я проверяю общий грузовой документ перед выездом с погрузочной площадки, как должен быть обозначен опасный материал в этом документе, чтобы документация была законной?","options":["Записан последним на странице, чтобы оставаться отдельно от строк обычного груза","Записан первым, либо выделен, либо отмечен знаком 'X' в графе HM","Указан только на отдельной задней странице, прикреплённой степлером за списком груза","Оставлен обычным шрифтом, так как таблички на прицепе уже указывают на опасность"],"explanation":"В смешанном грузовом документе запись об опасном грузе должна выделяться: ее вносят первой, выделяют маркером или отмечают знаком «X» в колонке HM."},"6":{"q":"Я перевожу груз коррозийных веществ из Таблицы 2 и только что прикрепил четыре ромбовидные таблички (placards) на все стороны прицепа перед выездом из терминала. Новичок спрашивает, почему эти ромбы настолько важны, что я отказался бы ехать без них. Какое объяснение верно описывает основное назначение этих табличек?","options":["Они удостоверяют, что грузоотправитель правильно классифицировал и упаковал груз, поэтому мне не нужно самому осматривать отправление","Они подтверждают, что у меня есть действующая отметка H и я прошёл проверку TSA, необходимую для перевозки этого груза","Они предупреждают всех вокруг транспортного средства об опасности груза, чтобы спасатели и окружающие могли действовать безопасно","Они фиксируют суммарную полную массу регулируемого материала, чтобы инспекторы на весах подтвердили, что я не превышаю 1 001 фунт"],"explanation":"Таблички-плакаты предупреждают всех вокруг транспортного средства об опасности груза, чтобы спасатели и окружающие могли реагировать безопасно."},"7":{"q":"Я перевожу груз с табличками опасности (плакардами) - коррозийные вещества. Бригадир на площадке говорит, что коллега уже установил нужные плакарды с обеих сторон прицепа и сзади. Прежде чем я выеду за ворота, какое утверждение верно указывает, что мне ещё нужно сделать, чтобы соблюсти правила размещения плакардов?","options":["Больше ничего не нужно: если закрыты обе стороны и задняя часть, три плакарда удовлетворяют требованиям для коррозийного груза.","Установить плакард на крышу прицепа, чтобы его было видно сверху, но передняя часть не требуется, так как кабина перекрывает обзор.","Перенести задний плакард на передний бампер, потому что перёд и две стороны - единственные места, которые инспектор реально проверяет.","Установить плакард также спереди транспортного средства, чтобы груз был обозначен плакардами спереди, сзади и с обеих сторон."],"explanation":"Таблички должны размещаться со всех четырех сторон транспортного средства — спереди, сзади и с обеих сторон — и читаться с той стороны, куда обращены."},"8":{"q":"Я перевожу груз с коррозийными веществами и установленными табличками, когда одна из бочек начинает протекать на обочину. Я предупредил прохожих и вызвал спасателей, но диспетчер велит мне зачитать пожарным справочный номер из документа, который указывает, как ликвидировать утечку именно этого материала. Какой предмет в кабине я должен использовать?","options":["Аварийное руководство по реагированию (ERG), которое позволяет спасателям сопоставить материал с его опасностью и защитными мерами","Товаротранспортные документы, ведь надлежащее название груза и номер UN/NA уже указаны там для этой партии","Руководство по эксплуатации автомобиля, в котором описаны системы грузовика и аварийные процедуры производителя","Транспортная накладная, поскольку она документирует груз и контактные данные перевозчика для отчётов об инцидентах"],"explanation":"Каждый водитель опасных грузов обязан иметь при себе Руководство по реагированию в чрезвычайных ситуациях (ERG), которое помогает спасателям сопоставить материал с его опасностью и защитными мерами."},"9":{"q":"Я собираюсь выехать с терминала, перевозя груз класса 3 (легковоспламеняющаяся жидкость) с табличками-плакардами. Диспетчер торопит меня выезжать, потому что я отстаю от графика. Чтобы выполнить свою работу безопасно и по закону перед выездом, что из этого я должен сделать?","options":["Снять плакарды с прицепа, чтобы не привлекать внимание других водителей на шоссе","Тщательно осмотреть транспортное средство, шины и крепление груза перед началом поездки","Пропустить предрейсовый осмотр на этот раз, чтобы наверстать время, потерянное в ожидании у дока","Отсоединить тормоза прицепа, чтобы машина катилась легче и я тратил меньше топлива в рейсе"],"explanation":"Перевозка опасных грузов требует тщательного осмотра транспортного средства, шин и крепления груза перед началом поездки, и нехватка времени не оправдывает его пропуск."},"11":{"q":"Во время обязательной проверки шин в пути на моём грузе с опасными материалами и размещёнными табличками я обнаруживаю, что одна шина прицепа опасно перегрелась. Согласно правилам Техаса по опасным грузам, что я обязан сделать, прежде чем продолжить движение?","options":["Полить шину водой, чтобы охладить её, и продолжить движение до ближайшего пункта обслуживания для проверки","Подкачать воздух, чтобы восстановить нужное давление, и осторожно ехать дальше, пока шина не остынет сама","Снять перегретую шину и положить её на безопасном расстоянии от транспортного средства, и не продолжать движение, пока неисправность не устранена","Снизить скорость и продолжать ехать, чтобы встречный поток воздуха охладил шину до следующей обязательной проверки"],"explanation":"Перегретая шина на грузе с табличками создаёт опасность пожара и взрыва, поэтому снимите её, отнесите подальше от транспортного средства и не двигайтесь, пока она не отремонтирована."},"12":{"q":"У меня груз с окислителями, на машине размещены таблички (placards), и я заехал на стоянку для отдыха. Водитель из соседнего грузовика хочет подойти и покурить вместе со мной. Чтобы не нарушить правила, на каком расстоянии от моего прицепа мы оба должны находиться во время курения?","options":["Не менее 5 футов — такой же буфер требуется при парковке в стороне от проезжей части","Не менее 10 футов — достаточно далеко, чтобы пламя не достигло прицепа","Не менее 100 футов — такой же буфер, как для взрывчатых веществ возле здания","Не менее 25 футов от транспортного средства, поскольку оно перевозит окислители"],"explanation":"Курение и любой открытый огонь должны находиться не менее чем в 25 футах от транспортного средства с табличками, перевозящего взрывчатые вещества, окислители или легковоспламеняющиеся материалы."},"13":{"q":"Я подъехал к погрузочной платформе, чтобы загрузить в прицеп взрывчатые вещества подкласса 1.2. Бригада на платформе ждёт, пока я подготовлю грузовик, прежде чем начать заносить ящики. Что я обязан сделать с автомобилем до того, как начнётся погрузка взрывчатых веществ?","options":["Заглушить двигатель и поставить стояночный тормоз, чтобы закрепить автомобиль перед началом погрузки","Оставить двигатель работать на холостом ходу, чтобы пневмотормоза оставались под давлением, а в кабине работал климат-контроль во время погрузки","Оставить двигатель работающим, но затянуть стояночный тормоз, ведь сам мотор не является настоящим источником воспламенения","Опустить все стёкла и дважды посигналить, чтобы предупредить бригаду на платформе о начале погрузки"],"explanation":"Перед погрузкой или разгрузкой взрывчатых веществ заглушите двигатель, чтобы устранить источник воспламенения, и поставьте на стояночный тормоз для фиксации транспортного средства."},"14":{"q":"Я забираю груз бензина в бочках на топливном терминале, и мой диспетчер просит подтвердить класс опасности в товарно-транспортных документах, прежде чем устанавливать таблички. Исходя из определения классов опасности, какой номер класса опасности должен стоять рядом с этим грузом бензина?","options":["Класс 1, потому что легковоспламеняющиеся жидкости несут наибольшую опасность взрыва и относятся к взрывчатым веществам","Класс 3, потому что бензин — это легковоспламеняющаяся жидкость, а именно это и охватывает данный класс","Класс 8, потому что бензин может обжигать кожу и повреждать материалы при контакте, как коррозийное вещество","Класс 2, потому что бензин выделяет легковоспламеняющиеся пары и рассматривается как легковоспламеняющийся газ"],"explanation":"Бензин — это легковоспламеняющаяся жидкость, что в точности соответствует классу опасности 3."},"15":{"q":"Я нахожусь на погрузочной площадке и гружу партию, а в товарно-транспортной накладной указаны надлежащее транспортное наименование, класс опасности и номер ООН для груза взрывчатых веществ. Прежде чем установить таблички на прицеп и выехать, мне нужно подтвердить номер класса опасности, который определяет этот груз как взрывчатые вещества. Какой класс опасности правильный?","options":["Класс 8, который охватывает коррозионные вещества, такие как аккумуляторная кислота","Класс 3, который охватывает легковоспламеняющиеся жидкости, такие как бензин","Класс 1, который охватывает взрывчатые вещества, такие как динамит","Класс 7, который охватывает радиоактивные материалы, такие как уран"],"explanation":"Взрывчатые вещества, такие как динамит, относятся к классу опасности 1 — первому из девяти классов опасности."},"16":{"q":"Я забираю два груза с опасными материалами на терминале. Первый — небольшая бочка коррозивного вещества из Таблицы 2 весом всего 300 фунтов; второй — один баллон ядовитого газа (класс 2.3). Диспетчер говорит, что мне «понадобятся таблички для требующего их количества». Что эта фраза на самом деле говорит о том, когда требуются таблички?","options":["Любое транспортное средство с опасным грузом всегда должно иметь таблички, поэтому и 300 фунтов коррозивного вещества, и ядовитый газ требуют их независимо от веса или класса","Таблички юридически требуются только когда машина движется по дороге общего пользования в тёмное время или при плохой видимости","Таблички не нужны ни для одного груза, так как оба отправления в сумме ниже порога в 1 001 фунт для этой поездки","Таблички требуются только для определённых количеств или классов — ядовитый газ требует их в любом количестве, а коррозивное вещество — только при 1 001 фунте или более"],"explanation":"Материалы Таблицы 1, такие как ядовитый газ, требуют табличек в любом количестве, тогда как материалы Таблицы 2, такие как коррозийные вещества, требуют табличек только при весе 1001 фунт и более."},"17":{"q":"Я забираю груз коррозионных веществ с размещёнными знаками опасности (плакардами). Грузоотправитель передаёт мне транспортные документы и говорит, что всё правильно классифицировано, упаковано и промаркировано. Что именно подтверждает, что грузоотправитель официально удостоверил, что груз правильно описан, упакован, маркирован и промаркирован этикетками?","options":["Подписанное грузоотправителем заявление о сертификации на самом транспортном документе","Устное заверение от грузоотправителя, данное мне на погрузочной площадке","Наличие правильных знаков класса опасности, уже закреплённых со всех четырёх сторон","Моя собственная проверка пломб и этикеток, подтверждающая отсутствие утечек"],"explanation":"Грузоотправитель удостоверяет, что опасный груз правильно поименован, упакован, маркирован и снабжён ярлыками, подписывая заявление о сертификации на транспортном документе."},"19":{"q":"Мой автоцистерна с табличками опасности и коррозийным грузом переворачивается на сельском шоссе, и продукт класса 8 вытекает на обочину. После того как я отвёл людей подальше, прекратил курение и взял Руководство по реагированию в чрезвычайных ситуациях (ERG), моей компании нужно сообщить о серьёзном инциденте по телефону. Какой контакт существует именно для приёма сообщения о серьёзном инциденте с опасными материалами?","options":["CHEMTREC, которому я звоню первым, потому что это единственное ведомство, уполномоченное принимать официальное сообщение об инциденте","Национальный центр реагирования (National Response Center), федеральная горячая линия, существующая для приёма сообщений о серьёзных инцидентах с опасными материалами","Грузоотправитель, указанный в моих документах, потому что компания, упаковавшая груз, обязана подать сообщение","Горячая линия производителя транспортного средства, чтобы опрокидывание и разрушение цистерны были официально задокументированы"],"explanation":"О серьёзных инцидентах с опасными материалами необходимо сообщать в Национальный центр реагирования — федеральную горячую линию 1-800-424-8802."},"20":{"q":"Сейчас 2:30 ночи в воскресенье, и одна из моих бочек с табличками опасного груза начала протекать едким (коррозийным) веществом на стоянке для отдыха. Я уже предупредил окружающих, не подпускаю людей и не допускаю курения. Теперь я хочу позвонить в CHEMTREC (1-800-424-9300) за экстренными указаниями по обращению с химикатами, но переживаю, что в такой час и в выходной никто не ответит. Какое утверждение верно?","options":["CHEMTREC принимает звонки только в обычные рабочие часы, поэтому мне придётся ждать до утра понедельника, чтобы получить указания.","CHEMTREC работает только по будням, поэтому, раз сегодня воскресенье, мне следует звонить в офис своего перевозчика.","CHEMTREC работает круглосуточно, 24 часа в сутки и каждый день, поэтому я могу позвонить прямо сейчас и связаться с экспертом по чрезвычайным ситуациям.","До CHEMTREC можно дозвониться только в ночные часы, поэтому звонок в 2:30 ночи — единственное подходящее время."],"explanation":"CHEMTREC (1-800-424-9300) работает круглосуточно, каждый день, предоставляя информацию для аварийного реагирования."},"21":{"q":"Я перевожу груз коррозийных веществ (не взрывчатки) с размещёнными табличками-плакардами и мне нужно остановиться, чтобы позвонить и проверить документы. Зоны отдыха поблизости нет, поэтому я присматриваюсь к обочине двухполосного шоссе. Чтобы не нарушить правила парковки для опасных грузов, что я обязан сделать?","options":["Припарковаться как можно ближе к краю проезжей полосы, чтобы оставить максимум места на обочине для другого транспорта","Припарковаться в пределах 300 футов от дороги, но оставить груз без присмотра лишь на несколько минут","Заехать колёсами на покрытие обочины и остановиться прямо у белой краевой линии полосы","Держать машину на расстоянии не менее 5 футов от проезжей части дороги, прежде чем остановиться и припарковаться"],"explanation":"Транспортное средство с табличками никогда не должно парковаться ближе 5 футов от проезжей части дороги."},"22":{"q":"Я перевожу взрывчатые вещества подразделения 1.2 и останавливаюсь для обязательной проверки шин. Впереди на обочине я вижу горящий автомобиль, рядом собралась толпа людей и наблюдает. Чтобы припарковаться законно и безопасно с таким грузом, какое минимальное расстояние я должен сохранять между моим грузовиком и этой толпой собравшихся людей?","options":["Не менее 300 футов от скопления людей","Не менее 25 футов от скопления людей","Не менее 50 футов от скопления людей","Не менее 5 футов от скопления людей"],"explanation":"Грузы со взрывчаткой (подкласс 1.1, 1.2, 1.3) нельзя парковать ближе 300 футов от места скопления людей."},"23":{"q":"Я перевожу груз взрывчатых веществ подразделения 1.2 с размещёнными табличками (placards) и мне нужно на несколько минут отойти от машины на стоянке для отдыха. Правила гласят, что такой груз никогда нельзя оставлять без присмотра. Чтобы моё транспортное средство по закону считалось «находящимся под присмотром», что из перечисленного должно быть верно в отношении человека, наблюдающего за ним?","options":["Он может отдыхать в спальном отсеке, пока слышит грузовик и может среагировать, если что-то случится","Он бодрствует, находится в пределах 100 футов от транспортного средства, ясно видит его и способен быстро отогнать его при необходимости","Он проходит мимо и осматривает транспортное средство не реже одного раза в каждые два часа — с тем же интервалом, что и проверка шин","Он остаётся где угодно в пределах зоны отдыха и доступен по мобильному телефону на случай чрезвычайной ситуации"],"explanation":"Груз со взрывчаткой считается под присмотром, только если человек бодрствует, находится в пределах 100 футов, хорошо его видит и может быстро отогнать машину."},"24":{"q":"Я водитель с CDL, перевожу груз коррозийных веществ с размещёнными табличками (placards). На погрузочной площадке клерк подаёт мне планшет и перечисляет, что входит в «мои обязанности», прежде чем я тронусь. Чтобы оставаться в рамках своих реальных юридических обязанностей водителя, мне нужно вычислить ту единственную задачу из списка, которая НЕ является обязанностью водителя, а лежит на ком-то другом в цепочке. Какая из этих задач такова?","options":["Отказ принять упаковку, в которой я обнаружил течь или которая неправильно маркирована","Размещение требуемых табличек (placards) на всех четырёх сторонах перед началом движения","Производство и химическая разработка состава перевозимого опасного материала","Хранение товарно-транспортных документов в пределах моей досягаемости во время движения"],"explanation":"Обязанности водителя — осмотр, отказ от некачественных грузов, размещение табличек, хранение перевозочных документов под рукой и безопасное вождение, но не производство материала."},"25":{"q":"На улице мороз, и я загружаю прицеп для дальнего рейса. В моём грузовике есть исправный обогреватель грузового отсека, и я хотел бы включить его, чтобы защитить груз от холода. Из четырёх отправлений, ожидающих на погрузочной площадке, для какого из них обогреватель грузового отсека следует оставить ВЫКЛЮЧЕННЫМ?","options":["Поддон консервированного супа и бутилированной воды, которые могут замёрзнуть и лопнуть на холоде","Коробки с домашней мебелью и упаковочными материалами, которые впитывают влагу в холодную погоду","Охлаждённые овощи и фрукты, которые получатель просит не дать замёрзнуть в пути","Бочки с легковоспламеняющейся жидкостью класса 3, погруженные вместе с коробками взрывчатых веществ"],"explanation":"Грузовые обогреватели должны быть выключены при перевозке взрывчатки или легковоспламеняющихся жидкостей, так как пламя или тепло могут воспламенить пары или вызвать взрыв."},"26":{"q":"Прошло три недели с тех пор, как я доставил груз коррозийных веществ с табличками опасности, и поездка давно завершена. Мой диспетчер сообщает, что компания всё ещё хранит транспортные документы (shipping papers) этой опасной партии в архиве. Какая из перечисленных причин ЛУЧШЕ всего объясняет, почему перевозчик хранит эти заполненные документы после завершения рейса?","options":["Федеральные и местные контролирующие органы могут потребовать эти записи для проверки, поэтому перевозчик обязан хранить их в течение установленного срока","Водитель, перевозивший груз, обязан лично хранить эти оригинальные документы до конца своей карьеры","После подтверждения доставки и выгрузки документы больше не нужны и могут быть уничтожены","Документы нужно хранить только пока материал в пути, и они должны находиться в кармане на двери водителя"],"explanation":"Перевозчик обязан хранить заполненные перевозочные документы в течение установленного срока, поскольку федеральные и местные органы могут потребовать их для проверки."},"27":{"q":"Я готовлю транспортные документы на груз и открываю Таблицу опасных материалов в правилах, чтобы найти данные по записи моего продукта. Просматривая строку для своего материала, я вижу, что каждый столбец берётся прямо из этой Таблицы, КРОМЕ одной информации, которую мне пришлось бы взять не из Таблицы, а из другого источника. Что из перечисленного я НЕ найду, читая Таблицу опасных материалов?","options":["Надлежащее транспортное наименование, которым я обязан описать материал в транспортных документах","Мой домашний адрес как водителя, который нигде в Таблице не указывается","Класс или подкласс опасности, присвоенный материалу, который я перевожу","Идентификационный номер (UN/NA), который должен быть указан вместе с записью"],"explanation":"Таблица опасных материалов описывает сам материал — название груза, класс опасности, номер ООН, группу упаковки и знаки, но не личные данные водителя."},"28":{"q":"Я забираю груз легковоспламеняющейся жидкости класса 3 на погрузочной площадке грузоотправителя. В транспортных документах материал указан правильно, и в них отмечено, что требуются таблички-плакарды, но грузоотправитель передаёт мне автомобиль без единой размещённой таблички и говорит, что они \"закончились на складе\". Прежде чем выехать на дорогу, что я обязан сделать?","options":["Доехать до первой запланированной остановки и попросить получателя предоставить недостающие таблички, ведь груз уже погружён, а документы оформлены верно","Двигаться без табличек, но держать транспортные документы сверху и в пределах досягаемости, поскольку правильное оформление документов юридически заменяет отсутствующие таблички","Получить правильные таблички-плакарды и разместить их со всех четырёх сторон автомобиля, прежде чем выехать на дорогу","Полностью отказаться от груза и оставить его на площадке, поскольку отсутствие таблички делает груз незаконным для приёма"],"explanation":"Если грузоотправитель не предоставил таблички, водитель обязан получить нужные и разместить их на всех четырёх сторонах перед выездом на дорогу."},"29":{"q":"Я загружаю в прицеп коробки с коррозийным материалом, и грузоотправитель нанёс маркировку на каждую отдельную упаковку. На погрузочной платформе другой водитель говорит мне, что эта маркировка на упаковках — это абсолютно то же самое, что и плакаты (placards), которые я повешу на все четыре стороны транспортного средства. Чтобы правильно проверить груз, на какое утверждение мне следует опираться?","options":["Маркировка на упаковках — это полноразмерные плакаты, и федеральные правила позволяют мне перенести их на борта транспортного средства, чтобы выполнить требование о размещении плакатов с четырёх сторон","Маркировка на упаковках — это необязательные пометки грузоотправителя, поэтому плакаты на транспортном средстве — единственные ромбовидные знаки, имеющие юридическую силу","Передача информации об опасности в США осуществляется только плакатами, поэтому любые ромбы на коробках являются лишь декоративными и могут быть проигнорированы","Ромбы на каждой упаковке — это знаки опасности (этикетки), которые наносит грузоотправитель, и они отдельны от более крупных плакатов, размещаемых на транспортном средстве"],"explanation":"Этикетки — это маленькие ромбы, которые грузоотправитель наклеивает на отдельные упаковки, а таблички — большие ромбы на всех четырёх сторонах машины."},"30":{"q":"Я формирую груз, в который входит охлаждаемая цистерна с безводным аммиаком и баллон со сжатым кислородом. В транспортных документах обе позиции отмечены как класс опасности 2. Сверяя документы с тем, что я фактически гружу, в каком физическом состоянии я должен ожидать каждый материал класса 2?","options":["Газ (класс охватывает воспламеняющиеся, невоспламеняющиеся и ядовитые газы)","Воспламеняющаяся жидкость, выделяющая пары при низкой температуре","Твёрдое вещество, которое становится опасным только при намокании","Коррозионное вещество, которое может быть в жидком или твёрдом виде"],"explanation":"Класс опасности 2 — это газы, включая горючие, негорючие и ядовитые газы."},"31":{"q":"Я новый водитель, перевозящий опасные грузы, и загружаю коррозийное чистящее средство. На этикетке бочек крупными буквами указано фирменное название производителя, грузоотправитель выдал мне документы, а диспетчер постоянно называет груз по его каталожному наименованию. Когда я проверяю, что надлежащее транспортное наименование в моих перевозочных документах указано верно, какому названию оно должно соответствовать?","options":["Фирменному названию, напечатанному крупными буквами на этикетках бочек, так как именно оно обозначает фактический продукт","Надлежащему транспортному наименованию из Таблицы опасных материалов для этого вещества, а не торговому или фирменному названию","Каталожному наименованию продукта, которое использует диспетчер, потому что именно так компания отслеживает груз","Любому общепринятому названию продукта, при условии что класс опасности и идентификационный номер в документах указаны верно"],"explanation":"В перевозочных документах должно указываться надлежащее наименование груза точно так, как оно приведено в Таблице опасных материалов, а не торговое или фирменное название."},"32":{"q":"Я провожу предрейсовый осмотр своего автоцистерны с табличками опасности перед перевозкой груза легковоспламеняющихся жидкостей. Я поднимаюсь к кабине и проверяю огнетушитель, закрепленный у двери. Какое условие означает, что огнетушитель пригоден и я могу легально выезжать?","options":["Огнетушитель закреплен и опломбирован, поэтому перед выездом мне не нужно проверять манометр или его класс защиты","Огнетушитель того размера, к которому я привык, хотя стрелка манометра находится в красной зоне","Огнетушитель полностью заряжен и имеет класс защиты, достаточно высокий для перевозимой мной опасности","Огнетушитель есть в кабине, так как наличие любого работающего огнетушителя удовлетворяет требованию"],"explanation":"Транспортное средство с табличками опасности должно иметь огнетушитель, полностью заряженный и с классом, достаточным для перевозимого опасного груза."},"33":{"q":"Я перевожу груз легковоспламеняющей жидкости с размещёнными знаками опасности (плакардами) и заезжаю на АЗС, чтобы дозаправить бак. Мой напарник предлагает помочь, чтобы закончить быстрее. Чтобы заправить машину правильно и безопасно, что из перечисленного ОБЯЗАТЕЛЬНО должно быть выполнено?","options":["Я могу зафиксировать пистолет в открытом положении и отойти, чтобы протереть лобовое стекло, пока двигатель работает для питания фар","Мне следует оставить двигатель работать на холостом ходу, чтобы топливный насос быстрее набрал давление, и отойти примерно на 25 футов, пока бак наполняется","Я могу начать заправку и уйти внутрь, чтобы расплатиться, ведь автоматическое отключение на колонке остановит подачу, когда бак наполнится","Я обязан выключить двигатель, и один из нас должен всё время оставаться у пистолета, контролируя подачу топлива"],"explanation":"При заправке транспорта с табличками опасности двигатель должен быть выключен, а кто-то всё время должен находиться у заправочного пистолета, контролируя подачу топлива."},"34":{"q":"Я перевожу маркированный груз взрывчатых веществ подкласса 1.1, и мой навигатор предлагает самый быстрый маршрут, который проходит прямо через деловой центр города и крупный речной тоннель во второй половине дня. Согласно обязательным правилам маршрутизации опасных грузов, что мне следует сделать?","options":["Проложить маршрут, который позволяет избегать населённых районов и тоннелей там, где это требуется, даже если это удлинит путь","Поехать по маршруту навигатора, поскольку тоннель уводит меня с загруженных улиц и экономит время","Воспользоваться маршрутом через центр, но только если на остановках я буду стоять не менее чем в 5 футах от проезжей части","Следовать по самому быстрому маршруту, пока я пересекаю железнодорожные пути, не переключая передачи"],"explanation":"Водитель, перевозящий взрывчатые вещества с табличками опасности, обязан следовать установленному маршруту для опасных грузов, избегая туннелей и населённых районов, даже если путь длиннее."},"35":{"q":"Я загружаю прицеп для рейса с опасными грузами на табличках, и в моих товарно-транспортных документах указаны два материала, которые по таблице совместимости (сегрегации) могут опасно реагировать при контакте друг с другом. Бригада на погрузочной площадке торопится и хочет, чтобы я поскорее выехал. Какое действие сохранит мою работу законной и безопасной?","options":["Закрепить оба несовместимых материала на одном поддоне, чтобы они ехали плотно и не смещались в пути","Держать эти два материала загруженными раздельно, как требуют правила сегрегации, чтобы реагирующие вещества оставались порознь","Объединить оба материала в одну запечатанную коробку, чтобы единичный пролив не распространился на остальной груз","Загрузить оба материала как обычно и пропустить проверку по таблице сегрегации, раз маршрут короткий и прямой"],"explanation":"Несовместимые материалы из таблицы раздельной перевозки следует грузить и держать отдельно, чтобы они не вступили в реакцию при контакте."},"36":{"q":"Я загружаю бочки с аккумуляторной кислотой для перевозки. В транспортных документах груз указан с номером класса опасности, и перед установкой табличек я хочу убедиться, что правильно сопоставил класс опасности этому коррозионному веществу. Какой номер класса опасности должен быть на табличках для коррозионного вещества, такого как кислота?","options":["Класс 3, потому что легковоспламеняющиеся жидкости в бочках и кислоты объединены вместе","Класс 5, потому что кислоты сильно реагируют и ведут себя как окислители","Класс 8, потому что коррозионные вещества, такие как кислоты, относятся к этому классу опасности","Класс 1, потому что бочки с кислотой под давлением рассматриваются как взрывчатые вещества"],"explanation":"Коррозийные вещества, такие как кислоты, относятся к классу опасности 8."},"37":{"q":"На погрузочной площадке отправителя мне вручают транспортные документы на груз, и в записи указан класс опасности 7 рядом с правильным транспортным наименованием и идентификационным номером ООН. Прежде чем я повешу таблички на прицеп и выеду, на какой именно тип материала указывает мне это обозначение класса 7?","options":["Легковоспламеняющиеся жидкости, какие бывают в грузах топлива и растворителей","Сжатые и сжиженные газы под давлением в баллонах","Коррозийные вещества, такие как сильные кислоты и едкие жидкости","Радиоактивные материалы, испускающие ионизирующее излучение при перевозке"],"explanation":"Класс опасности 7 — это радиоактивные материалы, испускающие ионизирующее излучение при перевозке."},"38":{"q":"На погрузочной платформе грузоотправитель передаёт мне документы, в которых материал указан как «Класс опасности 6». Прежде чем установить таблички и выехать, я хочу точно понимать, какую опасность я везу. О чём говорит обозначение «Класс 6» применительно к этому грузу?","options":["Это ядовитый (токсичный) материал, поэтому я должен защищаться от воздействия и опасности вдыхания","Это окислитель, который может усилить пожар, поэтому я должен держать его подальше от горючих веществ","Это коррозийный материал, который может обжечь кожу и разъесть металл, поэтому я должен проверить на утечки","Это негорючий сжатый газ, поэтому я должен предохраняться от сброса давления"],"explanation":"Класс опасности 6 охватывает ядовитые (токсичные) материалы, поэтому необходимо защищаться от воздействия и вдыхания."},"39":{"q":"Я готовлю груз, и за надлежащим транспортным наименованием в моих документах стоит номер класса опасности \"5.1\" и идентификационный номер в формате ООН. Грузоотправитель выдаёт мне табличку (placard) для размещения со всех четырёх сторон. Какая табличка правильно соответствует материалу класса опасности 5?","options":["Табличка CORROSIVE (коррозийное вещество), потому что класс 5 включает кислоты и аккумуляторную жидкость, разъедающие металл","Табличка OXIDIZER (окислитель), потому что класс 5 включает окислители и органические пероксиды","Табличка EXPLOSIVES (взрывчатые вещества), потому что класс 5 включает взрывчатые смеси и детонаторы","Табличка RADIOACTIVE (радиоактивное вещество), потому что класс 5 включает материалы, испускающие излучение"],"explanation":"Класс опасности 5 охватывает окислители и органические пероксиды, поэтому груз класса 5.1 требует таблички ОКИСЛИТЕЛЬ (OXIDIZER)."},"40":{"q":"Я загружаю один прицеп несколькими ненасыпными упаковками, которые относятся к двум разным классам опасности, и предпочёл бы повесить один плакат 'DANGEROUS' (опасно) на все четыре стороны вместо отдельного плаката для каждого класса. Согласно правилам DPS по опасным грузам, когда фактически разрешается использовать плакат 'DANGEROUS'?","options":["Только когда каждая упаковка в грузе относится к одному единственному классу опасности","Только когда груз состоит исключительно из коробочной или паллетированной пищевой продукции","Когда груз содержит два или более класса опасности, которым правила разрешают использовать один общий плакат","Практически в любой ситуации, как удобная универсальная замена плакатам конкретных классов"],"explanation":"Одна табличка DANGEROUS может заменить отдельные таблички, когда груз содержит два или более класса опасности, которые правила разрешают объединять."},"41":{"q":"Я везу цистерну с табличками опасного груза, когда меня останавливает дорожный инспектор, указывает на четырёхзначный номер на табличке и спрашивает, что он означает. Исходя из того, как этот номer используется при чрезвычайной ситуации, что именно идентифицирует этот четырёхзначный номер?","options":["Полную массу гружёной цистерны, чтобы спасатели знали объём разлива","Подкласс опасности, например 3 для легковоспламеняющихся жидкостей, в числовой форме","Назначенный перевозчиком маршрут для опасных грузов до терминала","Конкретный перевозимый опасный материал, который ищут в Руководстве по реагированию на чрезвычайные ситуации (ERG)"],"explanation":"Четырёхзначный номер UN/NA указывает на конкретный опасный материал, который спасатели находят в Руководстве по действиям в чрезвычайных ситуациях (ERG)."},"42":{"q":"Я проверяю товарно-транспортные документы на свой груз и замечаю, что для каждой позиции опасного материала указана группа упаковки I, II или III. Новый водитель спрашивает меня, что на самом деле означает эта римская цифра. Исходя из моей подготовки по перевозке опасных грузов, что указывает группа упаковки относительно материала?","options":["Насколько велика опасность материала, причём группа I — самая опасная","Номер класса опасности, определяющий тип опасности, например воспламеняющийся или едкий","Минимальный вес, при котором груз должен иметь таблички со всех четырёх сторон","Порядок, в котором позиции должны перечисляться в товарно-транспортном документе"],"explanation":"Группа упаковки указывает степень опасности материала: группа I — наиболее опасная, группа II — средняя, группа III — наименьшая."},"43":{"q":"Я перевожу по Техасу груз коррозийных веществ с размещенными табличками (плакардами), и на весовой станции инспектор дорожной полиции просит меня показать, где для моего груза указан круглосуточный телефон экстренного реагирования. Какое место мне следует показать инспектору?","options":["На табличках (плакардах), закрепленных на всех четырех сторонах прицепа","В транспортной (грузовой) накладной, которую я держу в пределах досягаемости в кабине","На моей карточке допуска для перевозки опасных грузов (эндорсмент H)","В Руководстве по реагированию на аварийные ситуации (ERG), хранящемся в кабине"],"explanation":"Круглосуточный телефон экстренного реагирования указывается в транспортном документе, который должен находиться в пределах досягаемости водителя в кабине."},"44":{"q":"Я проверяю товарно-транспортные документы на груз, и одна запись указана с классом опасности 4. Прежде чем разместить таблички и провести осмотр, я хочу подтвердить, какой именно тип опасности я перевожу. Какое из следующих утверждений правильно описывает материалы класса опасности 4?","options":["Легковоспламеняющиеся газы, которые могут воспламениться при выходе из баллона под давлением","Легковоспламеняющиеся жидкости, такие как бензин, выделяющие воспламеняющиеся пары","Легковоспламеняющиеся твёрдые вещества, включая самовозгорающиеся и опасные при намокании материалы","Едкие (коррозионные) вещества, которые могут обжечь кожу или разъесть металлическую тару"],"explanation":"Класс опасности 4 включает легковоспламеняющиеся твёрдые вещества, в том числе самовозгорающиеся и опасные при намокании материалы."},"45":{"q":"Я загружаю в прицеп материал класса 4.3 с маркировкой \"Опасен при намокании\", а на весь маршрут прогнозируют дождь. Прежде чем закрыть двери, какая мера предосторожности ВАЖНЕЕ ВСЕГО именно для этой опасности?","options":["Не давать грузу слишком сильно охлаждаться, так как именно охлаждение делает эти твёрдые вещества нестабильными","Убедиться, что коробки защищены от пыли, потому что взвешенные частицы запускают реакцию","Проверить, что груз свежеокрашен и герметизирован, чтобы пары не выходили при перевозке","Держать материал полностью сухим и герметичным, потому что контакт с водой может вызвать его воспламенение"],"explanation":"Опасные при намокании материалы реагируют с водой и могут воспламениться, поэтому их нужно держать полностью сухими и герметично защищёнными от влаги."},"46":{"q":"Я загружаю несколько баллонов со сжатым газом в свой прицеп для рейса с опасными грузами. Прежде чем закрыть двери и тронуться, какой способ загрузки обеспечивает соответствие требованиям и безопасность груза?","options":["Поставить каждый баллон вертикально и закрепить его так, чтобы он не мог опрокинуться, катиться или сместиться в пути","Уложить баллоны плашмя и упаковать их свободно, чтобы у них был запас хода на неровной дороге","Слегка приоткрыть вентиль каждого баллона перед отправлением, чтобы внутреннее давление выровнялось в пути","Укладывать их набок только если пол прицепа ровный, в противном случае ставить вертикально"],"explanation":"Баллоны со сжатым газом должны стоять вертикально и быть закреплены, чтобы не опрокинуться, не катиться и не смещаться при перевозке."},"47":{"q":"Я загружаю прицеп грузом класса 6.1 (яд/токсичный материал), и у меня остаётся свободное место на полу. Чтобы не делать второй рейс, я хочу дозагрузить машину другим грузом, который идёт на тот же терминал. Какой груз НЕЛЬЗЯ перевозить в одной машине вместе с ядом?","options":["Паллета с запечатанными картонными коробками автозапчастей","Сухой корм для собак в мешках и коробки с хлопьями для продуктового магазина","Ящик слесарных ручных инструментов и крепёжных ремней","Несколько мешков чистого сухого строительного песка"],"explanation":"Ядовитые и токсичные материалы (класс 6.1) нельзя грузить вместе с продуктами питания для людей или животных из-за риска заражения."},"48":{"q":"Во время предрейсового осмотра я обнаруживаю на своём грузе с табличками бочку с маркировкой класса 8, и небольшое количество жидкости вытекло на пол рядом с ней. Решая, как поступить с этой утечкой, какую из перечисленных опасностей я ОБЯЗАН учесть в первую очередь, прежде чем приближаться к ней?","options":["Вещество быстро понизит температуру внутри прицепа, поэтому сначала следует проветрить","Вещество крайне взрывоопасно при контакте с воздухом, поэтому нужно эвакуировать зону радиусом 300 футов","Вещество может химически обжечь кожу и глаза при контакте, поэтому я не должен к нему прикасаться и обязан защитить себя","В жидком виде вещество практически инертно, поэтому я могу вытереть его тряпкой и продолжить рейс"],"explanation":"Коррозионные вещества класса 8 могут химически обжечь кожу и глаза при контакте, поэтому водитель должен избегать прикосновения и защищать себя."},"49":{"q":"Я собираюсь загружать партию легковоспламеняющихся жидкостей класса 3 в свой прицеп. Перед началом погрузки я замечаю, что в грузовом отсеке остался мусор и болтающиеся открытые металлические детали от предыдущего рейса. Согласно правилам перевозки опасных грузов, какому условию должен отвечать грузовой отсек до начала погрузки?","options":["Быть влажным по всей поверхности, так как влага снижает вероятность случайного воспламенения при погрузке","Быть сначала загруженным моим ручным инструментом, закреплённым у передней стенки","Быть герметично закрытым и без вентиляции, чтобы горючие пары не попали в кабину","Быть чистым и свободным от любых источников искр до размещения груза"],"explanation":"Грузовой отсек должен быть чистым и свободным от источников искр перед погрузкой легковоспламеняющихся жидкостей, так как незакреплённый металл может воспламенить пары."},"50":{"q":"Я готовлю свою цистерну с табличками-плакардами перед рейсом и устанавливаю плакарды ромбовидной формы на прицеп. Помимо того, что каждый из них должен оставаться чистым и читаемым с той стороны, в которую он обращён, как именно я должен расположить каждый плакард, чтобы соответствовать требованиям DPS?","options":["Установить как квадрат, повёрнутый так, чтобы один угол смотрел строго вверх, в виде ромба","Расположить плашмя так, чтобы одна полная сторона лежала ровно вдоль низа","Закрепить только на стороне водителя и пассажира, не спереди и не сзади","Закрыть прозрачной плёнкой, пока не доеду до погрузочной площадки"],"explanation":"Знаки опасности — это ромбы, размещаемые как квадрат, повёрнутый углом вверх, одним углом строго вверх, и сохраняемые чистыми и читаемыми."},"51":{"q":"Во время погрузки моего прицепа с табличками (плакардами) на складе грузоотправителя я замечаю, что на одной бочке с коррозийным веществом по боку стекает свежее мокрое пятно, а маркировочная этикетка частично оторвана. Грузоотправитель уверяет, что это 'совсем чуть-чуть', и велит мне загрузить бочку, чтобы рейс не выбился из графика. Что мне следует сделать?","options":["Загрузить как есть, поскольку упаковку подготовил и сертифицировал грузоотправитель, а любая отчётность - это задача перевозчика уже после доставки","Отказаться принимать эту упаковку и не перевозить её, потому что водитель обязан отклонить любой протекающий или повреждённый груз с опасными материалами","Загрузить, но закопать поглубже в центр остального груза, чтобы утечка была локализована и подальше от стенок прицепа","Загрузить, но сделать запись в транспортных документах, чтобы получателя предупредили об утечке при прибытии"],"explanation":"Водитель обязан осматривать грузы и отказываться перевозить любую упаковку с опасными материалами, которая протекает или повреждена."},"52":{"q":"Я только что доставил автоцистерну с легковоспламеняющейся жидкостью, и датчик показывает, что цистерна 'пустая'. Перед возвращением на терминал я решаю, можно ли снять таблички (плакарды). При каком условии у меня МЕНЬШЕ всего оснований снимать их, пока цистерна находится в таком 'пустом' состоянии?","options":["Когда цистерна была обработана паром, продута и сертифицирована как полностью свободная от продукта","Когда товарно-транспортные документы и перевозчик подтверждают, что цистерна теперь соответствует стандарту 'очищена и продута'","Когда в цистерне всё ещё остаются прилипшие остатки продукта или опасные пары от последнего груза","Когда цистерна была трижды промыта на терминале и повторно взвешена как пустая"],"explanation":"Цистерна считается «пустой» только когда в ней не осталось налипших остатков или опасных паров от последнего груза, поэтому таблички должны оставаться, пока она по-настоящему не очищена."},"53":{"q":"Я забираю груз, который грузоотправитель классифицировал как опасные ОТХОДЫ, а не просто обычный опасный материал, и хочу убедиться, что покидаю предприятие с тем единственным документом, который правила специально требуют для такого типа перевозки. Какой документ ОБЯЗАТЕЛЬНО должен сопровождать этот груз опасных отходов?","options":["Стандартная транспортная накладная, оформленная как для обычной коммерческой грузовой перевозки","Только Руководство по действиям в чрезвычайных ситуациях (ERG), хранимое в кабине для справки при инциденте","Паспорт безопасности материала (SDS), описывающий свойства химиката и порядок обращения с ним","Единый манифест опасных отходов (Uniform Hazardous Waste Manifest), сопровождающий груз отходов"],"explanation":"Перевозка опасных отходов должна сопровождаться единым манифестом опасных отходов (Uniform Hazardous Waste Manifest), отслеживающим отходы от образования через транспортировку до окончательной утилизации."},"54":{"q":"Я перевожу груз с маркировкой класса 1.1 (взрывчатые вещества) и замечаю, что крепление груза внутри прицепа ослабло. Прежде чем безопасно продолжить путь, мне нужно затянуть крепёж. Чем из перечисленного следует воспользоваться для этой работы?","options":["Искробезопасными инструментами из латуни или бронзы, чтобы исключить любую искру, способную воспламенить взрывчатые вещества","Обычными стальными инструментами, ведь они крепче всего держат крепёж и позволяют закончить работу быстрее всего","Любым тяжёлым стальным ломом, что окажется под рукой, ведь чем больше рычаг, тем быстрее я закончу","Любым инструментом с красной защитной маркировкой, ведь инструменты с красной меткой допущены к работе с опасными грузами"],"explanation":"Работа рядом со взрывчатыми веществами класса 1 должна выполняться неискрящими инструментами из латуни или бронзы, так как одна искра от удара металла о металл может воспламенить взрывчатку."},"55":{"q":"Я разместил таблички-плакарды на всех четырех сторонах прицепа на погрузочной площадке и убедился, что каждая читается, прежде чем выехать. Через три часа долгого рейса я останавливаюсь на заправку и говорю напарнику, что с плакардами 'уже всё в порядке'. Когда именно я обязан проверять наличие плакардов на месте? Какое утверждение верно?","options":["Моя ответственность заканчивается после проверки плакардов на площадке, ведь размещение плакардов проверяется при предрейсовом осмотре.","Я обязан убедиться, что плакарды на месте, как перед рейсом, так и в течение всего рейса во время движения.","Мне нужно перепроверить плакарды только по прибытии в пункт доставки, чтобы удовлетворить получателя.","Размещение плакардов — обязанность грузоотправителя, поэтому проверка в пути не входит в мои водительские обязанности."],"explanation":"Нужно убедиться, что таблички на месте как перед поездкой, так и в пути, поскольку они могут ослабнуть, отвалиться или загрязниться во время движения."},"56":{"q":"Я перевожу груз с коррозийными веществами и установленными табличками, когда одна из бочек начинает течь на обочину. Доставая транспортные документы с сиденья, я замечаю, что грузоотправитель прикрепил к ним информацию для действий при чрезвычайных ситуациях. Когда на место прибывают пожарные и бригада по опасным материалам, какова ОСНОВНАЯ цель этой аварийной информации от грузоотправителя?","options":["Она указывает розничную стоимость груза, чтобы спасатели могли решить, какие грузы защищать в первую очередь","Она сообщает мне, какую марку топлива и давление в шинах предпочитает перевозчик для дальних рейсов в жару","Она даёт спасателям сведения, необходимые для безопасной ликвидации утечки или пожара именно с этим материалом","Она подтверждает, что я прошёл проверку TSA и имею действующий допуск H для управления автомобилем"],"explanation":"Информация для аварийного реагирования прилагается к товаросопроводительным документам, чтобы дать спасателям конкретные данные для безопасной ликвидации утечки, разлива или пожара от этого материала."},"57":{"q":"Я загружаю несколько упаковок радиоактивного материала класса 7, и грузоотправитель указывает на число, напечатанное на этикетке каждой упаковки, и говорит, что я должен сложить эти значения и удерживать сумму в пределах установленного лимита для моего транспортного средства. Какова цель этого числа, которое мне велят отслеживать?","options":["Это цветовой код, который указывает, на какую сторону прицепа нужно поместить соответствующую табличку (плакард)","Это рейтинг скорости, ограничивающий, насколько быстро я могу ехать, пока радиоактивный груз находится на борту","Это маршрутный индекс, который указывает, какие назначенные шоссе мне разрешено использовать","Это транспортный индекс, который ограничивает суммарную дозу радиационного облучения, допустимую на моём транспортном средстве"],"explanation":"Каждая радиоактивная упаковка имеет транспортный индекс, и водитель должен суммировать эти индексы и удерживать общую сумму ниже установленного предела, чтобы контролировать радиационное облучение на транспортном средстве."},"58":{"q":"Я везу груз коррозийных веществ с табличками-плакардами, когда из-за неисправности подшипника колеса вынужден съехать на обочину и ждать тягач на замену. Диспетчер по рации сообщает, что рядом находится другой грузовик компании, и предлагает перекачать продукт в него, чтобы не сорвать сроки доставки. Какой ответ лучше всего соответствует правильной практике перевозки опасных грузов?","options":["Отказаться от перегрузки на дороге; опасный груз можно перемещать между машинами только при настоящей чрезвычайной ситуации, поэтому мне следует дождаться ремонта или надлежащих мер","Согласиться на перегрузку, ведь соблюдение графика доставки — это первоочередная задача перевозчика","Перегрузить только после повторной установки плакардов на обе машины, что делает придорожную перегрузку полностью допустимой","Выполнить перегрузку, поскольку груз уже остановлен и безопасно припаркован вне проезжей части дороги"],"explanation":"Перегрузка опасных грузов между транспортными средствами допускается только в настоящей чрезвычайной ситуации, поэтому обычная поломка или задержка доставки не является основанием для перегрузки на дороге."},"59":{"q":"Я загружаю груз, который в документах грузоотправителя обозначен как загрязнитель морской среды, перед рейсом в порт. Как водитель, завершающий осмотр, какое из этих условий должно быть выполнено, прежде чем я соглашусь перевозить этот груз?","options":["Маркировку загрязнителя морской среды можно закрыть, пока я не доберусь до морского терминала","Упаковка должна иметь требуемую маркировку загрязнителя морской среды, прежде чем я её повезу","Маркировку загрязнителя морской среды можно не наносить, так как сначала груз едет по дороге","Контейнер должен быть скрыт от обзора, чтобы груз был в безопасности в пути"],"explanation":"Морской загрязнитель должен иметь требуемую маркировку на упаковке до перевозки, и водитель обязан отказаться от любого неправильно маркированного груза с опасными материалами."},"63":{"q":"Я провожу предрейсовый осмотр тягача с прицепом, на котором размещены таблички (placards) для груза легковоспламеняющейся жидкости. Я хочу убедиться, что мой огнетушитель отвечает федеральным требованиям, прежде чем тронуться в путь. Что из перечисленного действительно соответствует правилу?","options":["Огнетушитель может оставаться запертым внутри опломбированного прицепа вместе с грузом, ведь именно там вероятнее всего начнётся пожар.","Полностью заряженный огнетушитель подходит, даже если он завален за крепёжными ремнями груза, лишь бы он был нужного класса для данного груза.","Огнетушитель должен соответствовать классу груза, быть полностью заряженным и закреплён так, чтобы я мог быстро до него дотянуться.","Подойдёт любой небольшой заряженный огнетушитель, потому что класс важен только для оборудования на разгрузочной площадке получателя, а не для грузовика."],"explanation":"Огнетушитель на транспортном средстве с табличками должен иметь подходящий для груза класс, быть полностью заряженным и установлен там, где водитель может быстро до него дотянуться."},"67":{"q":"Вы перевозите груз с опасными материалами (горючая жидкость) с установленными табличками-плакардами и заезжаете на стоянку для проверки шин каждые 2 часа. Вы обнаруживаете, что одна из шин прицепа горячая на ощупь и явно перегревается. Какое из следующих действий является правильным?","options":["Облить горячую шину водой, чтобы быстро охладить её, и продолжить путь к месту доставки, чтобы успеть к сроку.","Подкачать воздух в горячую шину, чтобы восстановить нужное давление, и продолжить движение по запланированному маршруту.","Оставить шину на месте и продолжить движение, так как некоторый нагрев нормален для полностью загруженного прицепа с плакардами.","Снять перегретую шину и отнести её на безопасное расстояние от транспортного средства, а затем проверить её, прежде чем продолжить путь."],"explanation":"Если шина перегревается на грузе с табличками, это пожароопасно, поэтому снимите её, отнесите на безопасное расстояние от транспортного средства и проверьте перед продолжением движения."},"69":{"q":"Я только что сдал грузополучателю последний поддон с опасным грузом, и теперь прицеп полностью пуст и без остатков, но все четыре таблички с маркировкой опасности по-прежнему закреплены. Я собираюсь ехать порожняком обратно на базу по автомагистрали. Какое действие позволит мне законно совершить эту порожнюю поездку?","options":["Снять или закрыть таблички сейчас, так как прицеп больше не везёт груз, который требует их установки.","Оставить таблички на всём обратном пути, потому что прицеп с маркировкой опасности другие водители всегда считают более безопасным.","Оставить их только до первого железнодорожного переезда, а затем снять их на остановке.","На самом деле разницы нет, поэтому я могу оставить таблички на пустом прицепе, если это экономит время."],"explanation":"Таблички (плакарды) необходимо снять или закрыть, как только транспортное средство перестаёт перевозить груз, требующий их по закону, чтобы они не вводили в заблуждение о содержимом."},"70":{"q":"Я провожу предрейсовый осмотр груза с табличками опасности и сверяю транспортный документ с упаковкой перед тем, как расписаться за него. В записи уже указаны надлежащее транспортное наименование и класс опасности. Какой ОСТАВШИЙСЯ элемент информации ОБЯЗАТЕЛЬНО должен присутствовать в этой же записи, чтобы она была полной и законной?","options":["Общий пробег, который я преодолею по назначенному маршруту перевозки опасных грузов","Идентификационный номер (ID) (UN/NA) материала","Круглосуточный телефон CHEMTREC для перевозчика","Буква группы упаковки, нанесённая на внешней бочке"],"explanation":"Полная запись в перевозочном документе содержит правильное транспортное наименование, класс опасности и идентификационный номер ООН/NA именно в этом порядке."},"71":{"q":"Я остановился на весовой станции, и инспектор указывает на оранжевую табличку под ромбовидным знаком (плакардом) на моём прицепе, где жирным чёрным шрифтом нанесён номер \"1203\". Он спрашивает, что этот четырёхзначный номер сообщает аварийным службам. Какое объяснение верное?","options":["Это полная масса в фунтах опасного груза, загруженного в данный отсек","Это код подкласса опасности, который ранжирует опасность груза по шкале от 1 до 9","Это идентификационный номер ООН/NA (UN/NA), называющий конкретный перевозимый материал","Это код экстренного телефона, который службы набирают, чтобы связаться с CHEMTREC по поводу груза"],"explanation":"Четырёхзначный номер на табличке или оранжевой панели — это идентификационный номер ООН/NA, который указывает конкретный перевозимый материал."},"72":{"q":"Грузовой брокер предлагает мне груз коррозийного вещества, который потребует размещения табличек-плакардов на всех четырёх сторонах моего прицепа. У меня уже есть CDL с разрешениями на цистерну (N) и сдвоенные/строенные прицепы (T), и я только что обновил медицинскую справку. Что я должен пройти, прежде чем смогу законно принять и перевезти этот груз?","options":["Ничего больше — поскольку мой груз коррозийный (класс 8), а не взрывчатый, самих плакардов достаточно для выполнения закона, и особое разрешение не требуется.","Только разрешение на цистерну (N), которое у меня уже есть, поскольку любой груз с плакардами считается опасностью наливной жидкости по федеральным правилам.","Действующее разрешение на перевозку пассажиров (P), потому что перевозка регулируемого груза, влияющего на общественную безопасность, приравнивается к перевозке пассажиров.","Разрешение на опасные грузы (H), которое требует прохождения проверки безопасности TSA со снятием отпечатков пальцев, прежде чем я смогу перевозить любой опасный груз с плакардами."],"explanation":"Для перевозки любого опасного груза, требующего табличек, нужна отметка HazMat (H), которая требует прохождения проверки угрозы безопасности TSA со снятием отпечатков пальцев."},"73":{"q":"У меня уже есть CDL класса A, и я сдал дорожный экзамен, но теперь я хочу перевозить опасные материалы, требующие табличек (placard). Помимо сдачи письменного теста на знание правил перевозки опасных грузов, какое ОДНО дополнительное требование я обязан выполнить, прежде чем индоссамент H будет добавлен в мои права?","options":["Я должен пройти оценку угрозы безопасности TSA, которая включает снятие отпечатков пальцев и проверку биографии","Я должен сдать второй, отдельный дорожный экзамен на транспортном средстве с табличками","Я должен сначала получить индоссамент на цистерну (N) в качестве обязательного условия","Я должен добавить индоссамент на сдвоенные/строенные прицепы (T) в свои права"],"explanation":"Отметка HazMat (H) уникальна тем, что требует от заявителей пройти проверку угрозы безопасности TSA, включающую снятие отпечатков пальцев и проверку биографии."},"76":{"q":"Я припарковался на стоянке для отдыха с грузом легковоспламеняющейся жидкости, на машине размещены таблички (плакарды). Другой водитель подходит поболтать и закуривает сигарету, приближаясь к моему тягачу. Ради нашей безопасности, на каком ближайшем расстоянии ему можно курить рядом с моим автомобилем с табличками?","options":["Не ближе примерно 15 футов — такой же запас, как перед железнодорожными путями","Не ближе примерно 25 футов от автомобиля с табличками","Не ближе примерно 5 футов — как при парковке от проезжей части","В любом месте вне кабины, ведь груз герметично закрыт"],"explanation":"Курение запрещено в радиусе примерно 25 футов от транспортного средства с табличками, перевозящего взрывчатые вещества, окислители или легковоспламеняющиеся материалы."},"77":{"q":"Я забираю груз, и в транспортной накладной материал указан с классом опасности 7. Прежде чем установить таблички и осмотреть упаковки, я хочу подтвердить, какой именно опасный груз я буду перевозить. Исходя из указанного класса опасности, что находится в моём прицепе?","options":["Легковоспламеняющаяся жидкость, например бензин или дизельное топливо","Едкая (коррозийная) жидкость, способная обжечь кожу и разъесть металл","Радиоактивный материал","Сжатый газ под высоким давлением"],"explanation":"В федеральной системе классов опасности класс 7 всегда означает радиоактивные материалы."},"78":{"q":"Я готовлю груз с табличками (плакардами), и в товарно-транспортных документах класс опасности груза указан как «Класс 1». Чтобы правильно припарковаться и обращаться с грузом, мне нужно знать, что я на самом деле везу. Обозначение «Класс 1» говорит мне, что груз — это:","options":["Легковоспламеняющиеся жидкости, такие как бензин или дизель, которые относятся к Классу 3","Коррозийные (едкие) жидкости — кислоты и щёлочи, объединённые в Класс 8","Сжатые или горючие газы, которые относятся к Классу 2","Взрывчатые вещества — материалы, относящиеся к Классу 1"],"explanation":"В фиксированной нумерации классов опасности класс 1 всегда означает взрывчатые вещества."},"79":{"q":"Я проверяю транспортные документы на свой груз, и в одной из записей класс опасности указан как \"2.1\" с номером ООН для этого материала. Исходя из системы нумерации классов опасности, какой именно материал я перевожу?","options":["Легковоспламеняющийся газ, потому что класс 2 относится к газам (а 2.1 — это легковоспламеняющийся)","Легковоспламеняющаяся жидкость, потому что это самый распространённый класс горючего груза","Взрывчатое вещество, потому что низкий номер класса означает бурное воспламенение","Радиоактивный материал, поскольку у него есть специальный идентификационный номер ООН"],"explanation":"Класс 2 охватывает газы, а подкласс 2.1 конкретно обозначает легковоспламеняющийся газ."},"80":{"q":"Я забираю груз, и в транспортных документах запись указана как «Ацетон, 3, UN1090». Диспетчер просит подтвердить, какой вид опасности обозначает эта средняя цифра, чтобы я взял правильные информационные таблички (плакарды). Исходя из указанного класса опасности, что я перевожу?","options":["Легковоспламеняющееся твёрдое вещество, способное воспламеняться от трения","Легковоспламеняющаяся жидкость, выделяющая воспламеняющиеся пары","Легковоспламеняющийся сжатый газ под давлением","Окисляющее вещество, усиливающее горение"],"explanation":"Класс 3 всегда означает легковоспламеняющиеся жидкости, которые выделяют воспламеняющиеся пары."},"81":{"q":"Я готовлю товаросопроводительные документы на груз, и в графе класса опасности указано \"Класс 4\". Прежде чем устанавливать таблички, я хочу подтвердить, к какой общей категории относится этот материал, чтобы выбрать правильную табличку. Согласно системе классов опасности, материал Класса 4 определяется как что из перечисленного?","options":["Едкая (коррозионная) жидкость, способная повредить кожу и металл","Легковоспламеняющаяся жидкость, например бензин или печное топливо","Легковоспламеняющееся твёрдое вещество, включая самовозгорающиеся и опасные при намокании материалы","Взрывчатое изделие, детонирующее от удара или нагрева"],"explanation":"Класс 4 охватывает легковоспламеняющиеся твёрдые вещества, включая самовозгорающиеся и опасные при намокании материалы."},"82":{"q":"Я проверяю товаросопроводительные документы для следующего груза, и в графе класса опасности указан опасный материал Класса 5. Прежде чем принять груз и установить таблички, мне нужно подтвердить, какое именно вещество я буду перевозить. Какое описание верно соответствует материалу Класса 5?","options":["Легковоспламеняющиеся жидкости, такие как бензин, дизельные присадки и растворители","Коррозийные материалы, такие как аккумуляторная кислота и другие сильные жидкости","Яды и токсичные жидкости, представляющие опасность при вдыхании","Окислители и органические пероксиды"],"explanation":"Класс 5 — это группа окислителей и органических пероксидов."},"83":{"q":"Перед выездом из терминала я проверяю транспортные документы на груз, и одна запись отмечена как Класс 6. Грузоотправитель ещё не указал правильное отгрузочное наименование и просит меня подтвердить, какой тип материала охватывает плакат Класса 6, чтобы документы соответствовали опасности. Какое описание верно определяет то, что относится к Классу 6?","options":["Яды (токсичные) и инфекционные вещества","Легковоспламеняющиеся жидкости, такие как бензин и обычные растворители","Коррозионные жидкости, способные прожигать кожу и металл","Окислители и органические перекиси, усиливающие горение"],"explanation":"Класс 6 охватывает ядовитые (токсичные) и инфекционные вещества."},"84":{"q":"Я провожу предрейсовый осмотр и проверяю товарно-транспортные документы на груз, в которых указан класс опасности 8. Прежде чем брать в руки контейнеры и подобрать правильные перчатки и защиту для глаз, мне нужно знать, какую именно опасность представляет этот материал. Какое утверждение правильно описывает, что такое материал класса 8?","options":["Это легковоспламеняющаяся жидкость, которая может воспламениться от искры, поэтому моя главная забота — держать все источники возгорания подальше от груза.","Это коррозийное вещество, которое может химически обжечь кожу, глаза и металл, поэтому моя главная забота — не допускать контакта и защищать поверхности.","Это сжатый газ под давлением, который может резко разорвать ёмкость, поэтому моя главная забота — держать баллоны охлаждёнными и закреплёнными.","Это радиоактивный материал, излучающий вредную радиацию, поэтому моя главная забота — ограничить время пребывания рядом с грузом."],"explanation":"Класс 8 — это коррозионные вещества, которые при контакте химически разъедают кожу, глаза и металл, поэтому главное — предотвратить контакт и защитить поверхности."},"85":{"q":"Я проверяю товаросопроводительные документы на груз и вижу запись, классифицированную как опасный материал класса 9. Инструктор спрашивает меня, что эта классификация на самом деле говорит о грузе. Какое утверждение правильно описывает значение обозначения класса 9?","options":["Оно обозначает продукт подкласса 2.3, то есть груз является ядовитым газом, требующим табличек-плакардов в любом количестве","Оно обозначает легковоспламеняющуюся жидкость — ту же категорию, что и класс опасности 3 в товаросопроводительном документе","Оно обозначает прочий опасный груз, который не вписывается чётко ни в один из остальных восьми классов опасности","Оно обозначает взрывчатое изделие — то же семейство груза, что подпадает под правила размещения плакардов класса опасности 1"],"explanation":"Класс 9 — это «прочее», категория для опасных грузов, не подпадающих ни под один из остальных восьми классов опасности."},"86":{"q":"Я перевожу груз коррозийных веществ, требующий размещения табличек-плакардов, и инспектор дорожной полиции направляет меня на весовую станцию. Он говорит, что со своего места видел только одну табличку, и просит подтвердить, как именно должна быть обозначена моя машина. Какое утверждение правильно описывает надлежащее размещение плакардов?","options":["Плакарды требуются только на задней части прицепа, ведь именно их читают едущие сзади машины и инспекторы позади меня","Одного плакарда со стороны водителя достаточно, если он читается с того направления, в которое обращён","Плакарды должны быть только спереди тягача и сзади прицепа, чтобы их было видно спереди и сзади","Плакарды должны размещаться на всех четырёх сторонах транспортного средства, и каждый должен читаться с того направления, в которое обращён"],"explanation":"Таблички должны размещаться на всех четырёх сторонах транспортного средства, и каждая должна читаться с той стороны, к которой обращена."},"87":{"q":"Я провожу предрейсовый осмотр и должен убедиться, что предупреждающая маркировка на моём прицепе правильная, прежде чем везти опасный груз (HazMat), требующий табличек. Когда я смотрю на правильно размещённую табличку HazMat на каждой стороне машины, какую общую форму она должна иметь?","options":["Ромб, то есть квадрат, повёрнутый так, что он стоит на одном из своих углов (вершине)","Треугольник, такой же формы, как светоотражающие аварийные треугольники, которые я вожу с собой","Прямоугольник, который шире, чем выше, как панель с идентификационным номером","Круг с цветной каймой по краю, как символ на дорожном знаке"],"explanation":"Табличка опасного груза имеет форму ромба — квадрат, поставленный на угол, опираясь на одну вершину."},"88":{"q":"Я перевожу груз с табличками опасности (плакардами) и во время предрейсового осмотра замечаю, что плакард на правой стороне прицепа испачкан дорожной грязью и частично закрыт креплением ремня, тогда как остальные три плаката чистые. Что требует от меня Texas DPS сделать с этим правым плакардом, прежде чем выехать?","options":["Ничего дополнительно, ведь пока передний и задний плакарды остаются чистыми и читаемыми, видимость боковых плакардов не регламентируется","Очистить его и переставить крепление ремня так, чтобы плакард был читаемым и не закрытым, ведь плакарды со всех четырёх сторон должны быть видны с той стороны, куда они обращены","Полностью снять этот плакард, ведь частично грязный плакард приравнивается к его отсутствию, а оставшихся трёх достаточно для обозначения груза","Оставить как есть и просто отметить состояние в транспортных документах, чтобы инспектор знал, что я в курсе"],"explanation":"Поскольку таблички на всех четырёх сторонах должны читаться со своей стороны, грязную или закрытую табличку нужно очистить и освободить от помех до начала движения."},"89":{"q":"Я загружаю смешанный груз, и один поддон — это опасный материал, указанный в Таблице 2 правил размещения табличек (плакардов). Коллега говорит мне: «Опасный груз есть опасный груз — как только хоть что-то из него попадает в прицеп, надо вешать таблички». Прежде чем размещать что-либо на четырёх сторонах, как мне определить, действительно ли для этого груза требуются таблички?","options":["Любое количество требует табличек, поэтому в тот момент, когда на борту оказывается хотя бы одна упаковка опасного груза, я обязан разместить таблички на всех четырёх сторонах","Таблички зависят только от упаковки, поэтому я вешаю их исключительно потому, что пищевые и непищевые товары загружены вместе","Это зависит от класса материала и его количества — некоторые классы требуют табличек при любом количестве, а данные материалы Таблицы 2 требуют их только при совокупной массе брутто 1001 фунт или более","Для смешанного груза таблички вообще никогда не требуются по закону, поэтому в этой поездке я могу полностью обойтись без них"],"explanation":"Необходимость табличек зависит от класса и количества: некоторые классы требуют табличек при любом количестве, а материалы Таблицы 2 — только при общей массе брутто 1001 фунт и более."},"90":{"q":"Я загружаю свой прицеп на складе несколькими негабаритными (нерасфасованными) упаковками из разных классов опасности Таблицы 2. Ни один отдельный класс опасности на борту не достигает 1 001 фунта, но суммарный груз по Таблице 2 превышает этот порог. Коллега говорит, что я могу повесить один знак DANGEROUS на весь смешанный груз вместо отдельного знака для каждого класса. Согласно правилам размещения знаков, когда использование знака DANGEROUS действительно разрешено?","options":["Только когда весь прицеп занят единым полным грузом одного материала из Таблицы 2 весом 1 001 фунт или более","Никогда, потому что каждый класс опасности на борту всегда обязан иметь собственный конкретный знак без исключений","Только когда груз состоит из взрывчатых веществ Класса 1, которые требуют размещения знаков в любом количестве","Когда я везу определённые нерасфасованные грузы, состоящие из двух или более классов опасности Таблицы 2, для такого смешанного небольшого груза можно использовать знак DANGEROUS"],"explanation":"Табличку DANGEROUS можно использовать для нерасфасованного груза, объединяющего два или более классов опасности Таблицы 2, вместо отдельных табличек по классам."},"91":{"q":"Я загружаю легковоспламеняющуюся жидкость класса 3, а единственные таблички (плакарды), оставшиеся в моём ящике, это таблички класса 8 (коррозийные вещества) от предыдущего рейса. Перед выездом: какое утверждение правильно отражает мои обязанности в отношении табличек на транспортном средстве?","options":["Размещаемые таблички должны указывать класс опасности фактически перевозимого материала, поэтому я не могу использовать таблички класса 8 для груза класса 3.","Любая табличка стандарта DOT допустима, если она ромбовидной формы и размещена со всех четырёх сторон транспортного средства.","Я могу ехать с табличками класса 8, если держу правильные сопроводительные документы класса 3 в пределах досягаемости в кабине.","Таблички должны соответствовать грузу только при пересечении границы штата, поэтому для рейса внутри штата таблички класса 8 подойдут."],"explanation":"Таблички должны соответствовать фактическому классу опасности перевозимого груза, поэтому для груза класса 3 нужны таблички класса 3."},"92":{"q":"Я заканчиваю предрейсовый осмотр фургона-прицепа, загруженного легковоспламеняющейся жидкостью класса 3, требующей размещения знаков опасности (плакард), и хочу убедиться, что плакарды размещены правильно до выезда. Какое из этих условий должно быть выполнено, чтобы я мог законно начать поездку?","options":["Плакарды только спереди и сзади, поскольку именно эти стороны реально видят другие водители","Плакард на каждой из всех четырёх сторон транспортного средства, закреплён так, чтобы каждый был читаем со стороны, куда он обращён","Плакарды по обеим сторонам прицепа плюс копия транспортных документов, приклеенная рядом с каждым из них","Один плакард, уложенный плашмя на крыше прицепа, чтобы он оставался видимым и защищённым от дорожных брызг"],"explanation":"Транспортное средство с опасными грузами должно иметь таблички со всех четырёх сторон, каждая закреплена и читаема со своей стороны."},"93":{"q":"Во время предрейсового осмотра груза с табличками (placards) я замечаю, что одна из четырёх обязательных табличек настолько выцвела на солнце, что номер класса опасности читается с трудом, хотя я ещё едва могу его разобрать. Какое действие правильно перед началом рейса?","options":["Оставить её на месте, ведь табличка ещё слабо читается, если присмотреться","Заклеить выцветшую табличку прозрачным скотчем, чтобы защитить её от дальнейшего выцветания","Заменить выцветшую табличку на новую, полностью читаемую, до начала рейса","Продолжить движение и заменить её на следующей остановке, пока остальные три таблички чёткие"],"explanation":"Выцветшую или повреждённую табличку нужно заменить полностью читаемой до начала поездки."},"94":{"q":"Я забираю груз с табличками, и грузоотправитель передаёт мне транспортные документы. Прежде чем подписать и выехать, что я должен проверить в этих документах?","options":["Что в них указано только надлежащее транспортное наименование, а класс опасности и идентификационный номер можно добавить позже","Что копия осталась на терминале, поскольку оригинал необязателен при коротких внутриштатных рейсах","Что заполнена хотя бы одна запись, даже если некоторые сведения об опасном грузе ещё отсутствуют","Что каждая запись об опасном грузе точна и полна, прежде чем я повезу груз"],"explanation":"Транспортные документы на опасные грузы должны быть точными и полными до перевозки, с указанием надлежащего наименования, класса опасности и идентификационного номера."},"95":{"q":"Я еду по межштатной автомагистрали с грузом коррозийных веществ, на машине размещены таблички опасности, ремень безопасности пристёгнут. Полицейский может остановить меня на любой отметке мили. Согласно правилам DPS Техаса, где ПРЯМО СЕЙЧАС должны находиться мои товаросопроводительные документы на опасный груз во время движения?","options":["В пределах моей досягаемости при пристёгнутом ремне безопасности или в кармане на двери водителя, поверх остальных моих документов","Заперты внутри прицепа вместе с грузом, чтобы оставались чистыми и перемещались вместе с самим грузом","Убраны в бардачок со стороны пассажира, чтобы не соскользнули с сиденья при резком торможении","Находятся только у грузоотправителя, который отправляет копию по факсу в диспетчерскую перевозчика перед каждым рейсом"],"explanation":"Во время движения держите транспортные документы на опасные грузы в пределах досягаемости с пристёгнутым ремнём или в кармане двери водителя, поверх остальных бумаг."},"96":{"q":"Я загружаю груз с табличками-плакардами и проверяю товарно-транспортную накладную перед выездом из дока. Опасный материал записан вперемешку с несколькими неопасными грузами на той же странице. Чтобы накладная была приемлемой, как должна выглядеть запись об опасном грузе среди остальных позиций?","options":["Её можно вписать где угодно среди грузов, лишь бы присутствовали правильное транспортное наименование, класс опасности и идентификационный номер","Она должна быть указана первой либо чётко выделена подсветкой или отметкой 'X' в графе HM, чтобы выделяться на фоне неопасного груза","Её нужно разместить последней на странице, чтобы общий вес неопасного груза был подсчитан выше неё","Её нужно выделять отдельно, только если грузоотправитель или принимающий объект прямо этого потребуют"],"explanation":"В смешанном транспортном документе запись об опасном грузе должна выделяться: указываться первой либо отмечаться выделением или знаком «X» в колонке HM."},"97":{"q":"Я везу груз коррозийных веществ с размещенными табличками-плакардами, когда фитинг на одной из бочек начинает течь и пары сносит на обочину. Я безопасно съезжаю на обочину, предупреждаю окружающих и беру Руководство по реагированию на чрезвычайные ситуации (ERG), которое держу в кабине. Что именно ERG предназначено помочь мне сделать в этот момент?","options":["Найти самый быстрый объезд впереди в обход весовых станций и платных дорог","Подтвердить надлежащее транспортное наименование, класс опасности и идентификационный номер для моих документов","Определить начальное расстояние изоляции и защитные действия для вытекшего материала","Проверить, какие таблички-плакарды требуются и на каких сторонах прицепа они должны быть"],"explanation":"Руководство по аварийному реагированию (ERG) указывает начальное расстояние изоляции и защитные меры для пролитого или протекающего материала."},"98":{"q":"Я забираю груз с коррозийными веществами, на который установлены таблички (плакарды), и в транспортных документах у меня в руках указаны правильное транспортное наименование, класс опасности и идентификационный номер, а внизу стоит подписанное заявление о сертификации. Как водитель с CDL, я знаю, что моя обязанность — осмотреть груз, отказаться от любого протекающего груза, установить таблички и держать документы в пределах досягаемости. Но когда я смотрю на эту подписанную строку, удостоверяющую, что материал описан правильно и надлежащим образом подготовлен к перевозке, чью именно сертификацию я на самом деле вижу?","options":["Перевозчика, так как транспортная компания отправляет груз и отвечает за сообщение о любом происшествии во время перевозки","Мою, как водителя, так как именно я осматриваю груз, устанавливаю таблички на машину и держу документы в пределах досягаемости во время движения","Ничью конкретно, потому что строка сертификации — это просто формальность, а реальная юридическая ответственность полностью лежит на том, кто получает груз","Грузоотправителя, потому что грузоотправитель классифицирует, упаковывает, маркирует и готовит транспортные документы, а затем удостоверяет, что материал описан правильно"],"explanation":"Грузоотправитель классифицирует, упаковывает, маркирует груз и оформляет транспортные документы, затем удостоверяет, что материал описан правильно."},"99":{"q":"Я нахожусь на погрузочной платформе и собираюсь принять бочку с коррозионной жидкостью. Прежде чем подписать товарно-транспортный документ, я хочу убедиться, что запись об опасном грузе оформлена правильно. Какой набор данных обязательно должен присутствовать в этой строке, чтобы описание опасного груза считалось надлежащим?","options":["Надлежащее транспортное наименование, класс опасности и идентификационный номер (UN/NA), указанные именно в этой последовательности","Цвет этикетки класса опасности, текст на табличке-плакате и четырёхзначный номер, указанный на плакате","Розничная стоимость груза, его общий вес брутто и почтовый индекс пункта назначения","Только отметка «X» в графе HM, поскольку именно этот знак юридически обозначает опасную запись"],"explanation":"Запись об опасном грузе должна содержать надлежащее наименование, класс опасности и идентификационный номер (UN/NA) именно в этой последовательности."},"100":{"q":"Я перевожу груз коррозийных веществ с табличками-плакардами и заезжаю на зону отдыха, чтобы воспользоваться туалетом. Я выйду из кабины и отойду от грузовика на несколько минут. Согласно правилам перевозки опасных грузов, где следует оставить сопроводительные документы, пока меня нет в автомобиле?","options":["Сложенными в бардачке, закрытом на защёлку, чтобы они были не на виду","На сиденье водителя или в кармане водительской двери","Запертыми в прицепе вместе с грузом, который они описывают","Засунутыми за солнцезащитный козырёк со стороны пассажира"],"explanation":"Покидая грузовик, оставляйте транспортные документы на опасные грузы на сиденье водителя или в кармане двери водителя, чтобы спасатели быстро их нашли."},"101":{"q":"Я на весовой станции с грузом, помеченным табличками опасности, и инспектор просит меня указать только по товаросопроводительным документам общее количество перевозимого опасного материала. Помимо надлежащего транспортного наименования, класса опасности и идентификационного номера, какое значение фактически будет указано в моих документах для этой записи?","options":["Суммарный вес всех осей моего грузовика","Рекомендуемое давление в холодных шинах для данного груза","Общее количество перевозимого опасного материала","Моточасы двигателя, накопленные с начала рейса"],"explanation":"В грузовых документах указано общее количество опасного материала по каждой позиции, поэтому объём на борту берётся прямо из этой цифры."},"102":{"q":"Я подал свою цистерну с размещёнными табличками опасности задним ходом к погрузочной платформе, и бригада грузоотправителя готова начать закачку продукта в прицеп. Прежде чем разрешить начать погрузку, какое действие для меня важнее всего, чтобы автомобиль не тронулся с места сам по себе?","options":["Оставить двигатель работать на повышенных оборотах, чтобы всё время иметь полное давление воздуха","Снять таблички опасности спереди и сзади, чтобы бригаде было удобнее дотягиваться до наливных клапанов","Сначала открыть сливной и вентиляционный клапаны прицепа, чтобы давление выровнялось во время перекачки","Поставить на стояночный тормоз и подложить упоры под колёса, чтобы автопоезд не сдвинулся во время погрузки"],"explanation":"Перед погрузкой или разгрузкой опасных грузов нужно поставить стояночный тормоз и подложить упоры под колёса, чтобы транспортное средство не могло покатиться."},"103":{"q":"Я нахожусь на терминале и загружаю бочки с легковоспламеняющейся жидкостью класса 3 на свой прицеп с размещёнными табличками-плакардами. Коллега подходит с зажжённой сигаретой и спрашивает, можно ли ему докурить, помогая мне с погрузкой. Какой ответ верный?","options":["Нет — курение запрещено возле места погрузки легковоспламеняющихся веществ, и он обязан держать зажжённую сигарету вдали от операции","Да — курить можно, пока он остаётся не менее чем в 5 футах от открытых дверей прицепа","Да — правило ограничивает только открытый огонь, например фальшфейеры, а не сигареты","Да — курение разрешено, потому что бочки герметичны, пока их не погрузят и не выставят плакарды"],"explanation":"Курение запрещено вблизи погрузки легковоспламеняющихся веществ, поэтому зажжённую сигарету нужно держать вдали от места работ."},"104":{"q":"Я на складе вручную загружаю в прицеп коробки со взрывчатыми веществами подкласса 1.1, укладывая их прямо на пол. Подготавливая грузовой отсек и перемещая каждую коробку, какая практика обеспечивает максимальную безопасность груза и соответствует правилам обращения с опасными грузами?","options":["Тащить ящики по голому стальному полу и подтягивать их вплотную заострённым металлическим грузовым крюком","Уложить в грузовом отсеке неискрящее напольное покрытие и аккуратно ставить каждую коробку, бережно обращаясь с каждым ящиком","Обойтись без напольного покрытия и быстро забросить ящики на место, чтобы поскорее опечатать двери","Проехать погрузчиком прямо по уложенным ящикам, чтобы плотно их спрессовать перед закрытием прицепа"],"explanation":"Взрывчатые вещества подкласса 1.1 требуют неискрящего настила пола и осторожного обращения с каждым ящиком, чтобы избежать трения, искр или удара, способных вызвать детонацию."},"105":{"q":"Я загружаю коробки с коррозийным материалом в свой фургон для перевозки опасных грузов. Упаковки правильно маркированы, таблички установлены. Размещая груз в кузове, какой из вариантов ЛУЧШЕ всего описывает, как мне следует обращаться с самими контейнерами?","options":["Сложить их свободно ближе к передней части, чтобы они утрамбовались на месте во время первых остановок","Поставить их у дверей незакреплёнными, чтобы спасатели могли быстро до них добраться","Заблокировать, подпереть и закрепить их так, чтобы они не могли сдвинуться, соскользнуть или упасть во время движения","Подвесить их к верхним направляющим прицепа, чтобы они полностью не касались пола"],"explanation":"Контейнеры с опасными материалами должны быть закреплены, подперты и зафиксированы, чтобы они не могли сместиться, соскользнуть или упасть во время перевозки."},"106":{"q":"Я нахожусь на наливном терминале и загружаю автоцистерну бензином, легковоспламеняющейся жидкостью класса 3. Перекачивающая магистраль подключена к собственному насосу терминала, поэтому двигатель моего грузовика для перекачки продукта не понадобится. Шланги подсоединены, и продукт начинает поступать. Что мне следует сделать с двигателем?","options":["Оставить его работать на холостом ходу на низкой передаче, чтобы можно было сразу тронуться после окончания загрузки","Оставить его работать на повышенных оборотах холостого хода, чтобы поддерживать давление воздуха и заряжать аккумуляторы через генератор","Оставить его работать только если персонал терминала скажет, что площадка хорошо проветривается","Заглушить двигатель, поскольку он не нужен для привода насоса продукта во время этой перекачки"],"explanation":"При погрузке или разгрузке легковоспламеняющихся жидкостей двигатель должен быть выключен, если он не нужен для работы насоса."},"107":{"q":"Я на терминале и собираюсь перекачать легковоспламеняющуюся жидкость класса 3 из своей автоцистерны в резервуар для хранения. Прежде чем открыть клапан или начать перекачку, я соединяю провод выравнивания потенциалов между грузовиком и резервуаром и подключаю заземление. Какова ГЛАВНАЯ причина, по которой я делаю это перед работой с легковоспламеняющейся жидкостью?","options":["Чтобы уравнять электрический заряд между грузовиком и резервуаром, чтобы не возникла статическая искра и не воспламенила пары","Чтобы создать резервный электрический путь, который питает фары и приборы грузовика, пока двигатель выключен","Чтобы снизить температуру жидкости при перекачке, чтобы топливо не расширилось и не перелилось через край приёмного резервуара","Чтобы замедлить скорость потока, чтобы меньше продукта терялось из-за испарения и пролива во время перекачки"],"explanation":"Соединение и заземление выравнивают электрический заряд между автомобилем и цистерной, чтобы не возникла статическая искра, способная воспламенить пары."},"108":{"q":"Я перевожу маркированный плакатами груз коррозийных веществ на маршруте длиной 380 миль с двумя запланированными остановками для отдыха. Перед выездом я обошёл прицеп во дворе и проверил все крепления и распорки — всё было надёжно закреплено. Чтобы соблюдать правила перевозки опасных грузов, что требует от меня регламент в отношении проверки груза и его крепёжных устройств на оставшейся части поездки?","options":["Больше ничего не требуется, если предрейсовая проверка во дворе подтвердила, что груз и крепления надёжны, поскольку повторная проверка в пути обязательна только для негабаритных или сверхтяжёлых грузов.","Продолжать проверять груз и его крепёжные устройства как перед поездкой, так и в нескольких точках во время поездки, а не только один раз в начале.","Повторно проверять крепёжные устройства только в конечном пункте доставки, потому что именно проверки перед разгрузкой имеют юридическое значение для претензий по грузу.","Повторять полную проверку груза и креплений строго по годовому графику, который ведёт перевозчик, отдельно от предрейсового осмотра любой отдельной поездки."],"explanation":"Груз и его крепления нужно проверять как перед поездкой, так и в пути, а не только один раз в начале."},"109":{"q":"Я перевожу груз взрывчатых веществ подкласса 1.1 с установленными плакатами, и один из ремней ослаб, поэтому мне нужно переставить ящик в прицепе. Какое из следующих правил является НАИБОЛЕЕ важным в отношении инструментов, которыми я работаю рядом со взрывчаткой?","options":["Инструменты должны быть из тяжёлой стали, чтобы прочно удерживать ящики и не соскальзывать","Инструменты следует оставить в кабине и переставлять ящик вручную, чтобы избежать любого контакта","Инструменты не должны быть способны вызвать искру или повредить упаковку взрывчатых веществ","Инструменты должны иметь острое лезвие, чтобы я мог быстро срезать и заново закрепить ослабший ремень"],"explanation":"Инструменты, используемые вблизи взрывчатых веществ, должны быть неискрящими и не способными повредить упаковку, так как искры или удар могут вызвать детонацию."},"110":{"q":"Я на разгрузочной площадке выгружаю прицеп с маркировкой, перевозящий легковоспламеняющуюся жидкость класса 3 в бочках. Оператор погрузчика хочет оставить работать свой пропановый погрузчик прямо рядом с открытыми дверями прицепа, рабочий поблизости собирается закурить, а начальник площадки спрашивает меня, где во время операции должны находиться открытый огонь и работающие двигатели. Какое правильное указание я должен дать?","options":["Держать источники возгорания прямо у дверей прицепа, чтобы погрузчик работал эффективно и быстрее завершил разгрузку","Разрешить курение и работу двигателей на холостом ходу, если они находятся не менее чем в 5 футах от проезжей части дороги","Поставить работающий погрузчик внутрь прицепа, чтобы ускорить погрузку, поскольку бочки запечатаны и не воспламенятся","Держать все источники возгорания, включая открытый огонь и работающие двигатели, на достаточном расстоянии от зоны разгрузки"],"explanation":"При погрузке или разгрузке легковоспламеняющихся материалов держите все источники возгорания, включая открытое пламя и работающие двигатели, вдали от зоны."},"111":{"q":"Я загружаю партию опасных грузов, требующую табличек, на погрузочной площадке заказчика. Осматривая упаковки перед тем, как расписаться за груз, по какому признаку я могу законно принять и перевозить эту партию?","options":["Каждая упаковка правильно маркирована и не имеет признаков утечки","Каждая упаковка вскрыта, чтобы я мог лично убедиться в содержимом","Упаковки окрашены в яркий цвет, чтобы их замечали другие водители","Упаковки уложены высоко над кабиной, где я могу за ними наблюдать"],"explanation":"Груз с опасными материалами можно принимать только тогда, когда каждая упаковка правильно маркирована и не имеет признаков утечки."},"112":{"q":"Я загружаю смешанный прицеп на распределительном складе. В моих транспортных документах указано несколько бочек ядовитого (токсичного) материала класса 6.1, который я повезу через всю страну. Начальник склада хочет заполнить оставшееся место в прицепе, чтобы сэкономить на втором рейсе. Какой из предлагаемых им грузов мне запрещено грузить рядом с моими бочками с ядом?","options":["Поддоны с мешками сельскохозяйственного удобрения, направляемые в тот же регион","Ящики с упакованными продуктами питания для людей и кормом для животных для продуктового склада","Дополнительные запечатанные бочки с тем же ядовитым материалом класса 6.1","Коробки с пустыми немаркированными пластиковыми транспортными контейнерами"],"explanation":"Ядовитые (токсичные) вещества класса 6.1 нельзя загружать или перевозить в одном транспортном средстве с продуктами питания или кормом для людей или животных."},"113":{"q":"Я загружаю в свой прицеп смешанную партию опасных грузов: коррозионные вещества и окислители, и мне нужно подтвердить, можно ли перевозить эти два материала рядом друг с другом или их следует держать раздельно. Какой справочник укажет мне, какие опасные материалы НЕЛЬЗЯ грузить вместе в одно транспортное средство?","options":["Графа HM в товаросопроводительных документах, поскольку отметки «X» указывают, какие грузы должны быть разделены","Руководство по реагированию в чрезвычайных ситуациях (ERG), поскольку в нём перечислено, какие материалы вступают в реакцию друг с другом","Таблица сегрегации (разделения), поскольку она определяет, какие материалы нельзя грузить вместе","Таблица 1 правил размещения табличек, поскольку в ней перечислены материалы, требующие табличек в любом количестве"],"explanation":"Таблица разделения (сегрегации) указывает водителю, какие опасные материалы запрещено загружать и перевозить вместе."},"114":{"q":"Я загружаю прицеп, в котором уже стоит несколько бочек с окислителем класса 5, и начальник погрузочной площадки даёт мне ещё четыре поддона, которые нужно разместить в том же пространстве. Чтобы груз был безопасным, какой из этих предметов мне НЕ следует ставить вплотную к бочкам с окислителем?","options":["Поддон с закрытыми канистрами, наполненными водой","Поддон с пустыми пластиковыми бочками","Поддон с песком в мешках","Поддон с банками легковоспламеняющегося растворителя"],"explanation":"Окислители класса 5 выделяют кислород и могут усилить или вызвать пожар, поэтому их следует держать вдали от легковоспламеняющихся материалов."},"115":{"q":"Во время погрузки моего прицепа с табличками опасного груза грузоотправитель передаёт мне два предмета HazMat, которые согласно таблице совместимости я обязан держать раздельно, и спрашивает, почему их нельзя везти рядом. Согласно руководству, какова НАИЛУЧШАЯ причина, по которой эти несовместимые материалы должны быть разделены?","options":["Находясь вместе, они могут вступить в реакцию друг с другом, воспламениться или выделить опасный газ","Хранение их вместе превысит порог нанесения табличек в 1 001 фунт","Их смешивание смажет надлежащее транспортное наименование и класс опасности в документах","Их совместная укладка перекроет доступ к светоотражающим треугольникам сзади"],"explanation":"Несовместимые опасные материалы держат раздельно, потому что при соединении они могут вступить в реакцию, воспламениться или выделить опасный газ."},"116":{"q":"Я загружаю смешанную партию опасных грузов, и в моих документах указаны бочка с цианидным соединением и несколько ёмкостей с коррозионной кислотой (класс 8), которые едут одному и тому же заказчику. Какое решение по загрузке обеспечит соблюдение правил и безопасность?","options":["Загрузить их рядом в одном отсеке, чтобы они находились вместе с соответствующими товаросопроводительными документами","Держать цианиды и кислоты раздельно и никогда не загружать их вместе в один груз","Загрузить их вместе только при условии, что обе ёмкости помещены в единую герметичную внешнюю тару","Загрузить их вместе при условии, что я пересекаю железнодорожные пути без переключения передач"],"explanation":"Цианиды и кислоты никогда нельзя загружать вместе, потому что при контакте выделяется смертельный газ — цианистый водород."},"117":{"q":"Вы перевозите груз коррозийных веществ с табличками-плакатами, когда чувствуете резкий запах и замечаете влажное пятно, расползающееся под бочкой в прицепе. Вы съезжаете на обочину и убеждаетесь, что упаковка протекает. Прежде чем сделать что-либо ещё, какой ваш ПЕРВЫЙ приоритет?","options":["Открыть протекающую бочку, чтобы определить химикат внутри, а затем свериться с Руководством по реагированию при ЧС для уточнения надлежащего отгрузочного наименования","Использовать воду из своего запаса, чтобы разбавить и смыть пролитое вещество в ближайший ливневый сток, пока оно не распространилось дальше","Остановить транспортное средство, оградить зону вокруг утечки и не подпускать посторонних и других людей к месту происшествия","Медленно продолжить путь к месту доставки, где обученный персонал и нужное оборудование смогут локализовать утечку и выгрузить бочку"],"explanation":"При любой утечке опасных материалов первое действие — остановиться, оградить место и держать людей подальше от места происшествия."},"118":{"q":"Вы перевозите груз с коррозионными веществами, обозначенный табличками-плакатами, когда одна из бочек начинает протекать и выпускать пары на придорожной стоянке в ветреный день. После того как вы предупредили окружающих и отвели людей подальше, где вам следует находиться, ожидая прибытия аварийных служб и CHEMTREC?","options":["С подветренной стороны прицепа, чтобы можно было пристально наблюдать за протекающей бочкой","Прямо у грузовых дверей, чтобы быстро передать сопроводительные документы спасателям","Ниже места разлива на склоне, чтобы вытекающая жидкость стекала прочь от вас","С наветренной стороны автомобиля и на безопасном расстоянии от протекающего груза"],"explanation":"При аварии с опасными материалами оставайтесь с наветренной стороны и на безопасном расстоянии, чтобы пары относило от вас, а не к вам."},"119":{"q":"Я перевожу груз с табличками-плакардами, содержащий коррозионные вещества, когда одна бочка начинает течь и пары распространяются вдоль обочины. Я уже предупредил окружающих, отвёл людей подальше и прекратил курение поблизости. Теперь мне нужна экспертная техническая консультация по работе именно с этим химикатом. К кому мне обратиться за такой экспертной помощью?","options":["В CHEMTREC или к местным аварийным службам, которые дадут экспертные указания по обращению с химикатом","В диспетчерскую моего перевозчика, ведь именно перевозчик обязан сообщать об инциденте","К грузоотправителю, который классифицировал и упаковал бочки и подготовил транспортные документы","Ни к кому по телефону — Путеводитель по аварийным действиям (ERG) сам по себе охватывает все нужные мне шаги"],"explanation":"За экспертной оперативной консультацией по обращению с протекающим химикатом обращайтесь в CHEMTREC или к местным аварийным службам."},"120":{"q":"Вы перевозите груз легковоспламеняющейся жидкости с информационными табло (плакардами) по сельской автостраде в Техасе и замечаете пламя из-под прицепа. Вы съезжаете на обочину, и огонь явно распространяется. У вас есть огнетушитель, рассчитанный на небольшие возгорания, но пламя уже достигает грузового отсека. Что нужно сделать В ПЕРВУЮ ОЧЕРЕДЬ?","options":["Открыть двери прицепа, чтобы осмотреть груз и выпустить жар и дым до того, как огонь разгорится сильнее","Отойти на безопасное расстояние от транспортного средства, затем вызвать аварийные службы и сообщить в CHEMTREC","Полностью разрядить огнетушитель на пламя в грузовом отсеке и оставаться рядом на случай, если огонь вспыхнет снова","Оставаться у кабины и держать двигатель работающим, чтобы можно было отвести тягач от распространяющегося пламени"],"explanation":"Никогда не тушите пожар груза с опасными материалами в одиночку; отойдите на безопасное расстояние от транспортного средства, затем вызовите аварийные службы и уведомите CHEMTREC."},"121":{"q":"Я перевожу груз с коррозивными веществами с размещёнными знаками опасности и замечаю, что из бочки капает жидкость и собирается лужей под прицепом на стоянке для отдыха. Я уже отвёл людей, прекратил курение и вызвал аварийные службы. Какое ОДНО действие я должен предпринять в отношении перемещения текущего транспортного средства?","options":["Медленно доехать до ближайшей стоянки для грузовиков, чтобы механик загерметизировал протекающую бочку","Переставить его ровно настолько, чтобы освободить выезд со стоянки для отдыха","Оставить его на месте, если только официальное лицо не прикажет переместить его ради спасения жизни","Быстро убрать его с площадки, чтобы отвести утечку подальше от других рядом стоящих грузовиков"],"explanation":"Никогда не перемещайте протекающий транспорт с опасными грузами по своему усмотрению; оставьте его на месте, если только должностное лицо не прикажет переместить его для защиты жизни."},"122":{"q":"Я перевожу коррозийные вещества с размещёнными табличками и замечаю, что продукт вытекает из бочки и скапливается на обочине, где я остановился. У меня есть Руководство по чрезвычайным ситуациям (ERG) и телефон. Что должно быть моим ПЕРВЫМ приоритетом, пока я жду аварийные службы?","options":["Засыпать лужу рыхлой землёй и гравием, чтобы коррозийное вещество впиталось и перестало растекаться","Залить разлив водой, чтобы разбавить его и смыть в кювет подальше","Расставить вокруг лужи светоотражающие треугольники и поставить факел с наветренной стороны, чтобы обозначить утечку","Удерживать посторонних подальше от участка и принять меры, чтобы остановить дальнейшее растекание утечки"],"explanation":"При инциденте с опасными грузами держите людей подальше и не давайте утечке распространяться до прибытия обученных спасателей; не пытайтесь убирать разлив самостоятельно."},"123":{"q":"Я перевожу груз с опасными материалами и табличками-плакатами, когда на стоянке под моим прицепом вспыхивает пожар. Прежде чем действовать или говорить с прибывшей пожарной командой, как правильно использовать мои транспортные документы и Руководство по реагированию на чрезвычайные ситуации (ERG)?","options":["Чтобы точно определить, какой материал я перевожу, и конкретные опасности, которые он представляет, чтобы спасатели могли действовать безопасно","Чтобы доказать перевозчику, что груз был правильно загружен и оформлен до начала поездки","Чтобы найти ближайший утверждённый маршрут стоянки для опасных грузов и отогнать горящий прицеп в другое место","Чтобы подтвердить, что груз весит 1 001 фунт или более и поэтому по закону требует табличек-плакатов"],"explanation":"Транспортные документы и ERG позволяют точно определить материал и его конкретные опасности, чтобы вы и спасатели могли безопасно реагировать."},"124":{"q":"Бочка на вашем трейлере с табличками опасного груза треснула, и из неё на обочину вытекает содержимое. Вы уже съехали на обочину, выставили светоотражающие треугольники и удерживаете прохожих на расстоянии, ожидая аварийные службы. Один из прохожих закуривает сигарету, а другой остановившийся помочь водитель спрашивает, можно ли быстро покурить, ведь он стоит далеко позади вашего грузовика. Как правильно поступить в отношении курения на месте этого происшествия?","options":["Разрешить быстро покурить при условии, что все находятся не менее чем в 25 футах позади протекающего трейлера","Полностью запретить курение и попросить всех находящихся рядом немедленно затушить сигареты","Разрешить курить только остановившемуся помочь водителю, поскольку помощники освобождены от этого правила","Разрешить курить только с наветренной стороны, в стороне от места, где груз вытекает на обочину"],"explanation":"Курение никогда не допускается на месте инцидента с опасными грузами, так как утечка или её пары могут быть огнеопасными, поэтому любое пламя или искру нужно немедленно устранить."},"125":{"q":"Я перевожу груз коррозийных веществ с размещёнными табличками (плакатами), когда контейнер разрушается и продукт начинает вытекать на обочину сельской автотрассы. После того как я предупредил окружающих, не подпускал людей к месту утечки и не дал никому курить поблизости, закон требует сообщить об этом инциденте. Кому необходимо сообщить об инциденте, как того требуют правила?","options":["Только грузоотправителю, поскольку именно грузоотправитель классифицировал, упаковал и подготовил товарно-транспортные документы и потому несёт ответственность за содержимое контейнера","Никому, при условии что я лично локализую утечку, охлажу участок и задокументирую ущерб фотографиями, прежде чем продолжить путь к месту доставки","Надлежащим органам, например аварийным службам или CHEMTREC, при этом перевозчик подаёт требуемый отчёт об инциденте в соответствующие ведомства","Только ближайшей местной телестанции или радиостанции, чтобы другие водители в районе были предупреждены и объехали пострадавший участок трассы"],"explanation":"Уведомите соответствующие органы, например спасателей или CHEMTREC, а перевозчик подаёт требуемый отчёт об инциденте в соответствующие ведомства."},"126":{"q":"Вы перевозите груз легковоспламеняющейся жидкости с табличками опасности через город, и навигатор предлагает быстрый маршрут через длинный автомобильный тоннель и плотно застроенный центр города, что экономит 20 минут. Какой выбор лучше всего соответствует правилам безопасного планирования маршрута для опасных грузов?","options":["Поехать по маршруту через тоннель и центр города, так как он самый короткий и экономит больше всего времени","Остаться на маршруте, но пропустить обязательную весовую станцию, чтобы не привлекать внимание к грузу","Поехать по маршруту, но запланировать остановку в центре города для повторной проверки табличек опасности","Отказаться от этого маршрута и выбрать путь, который позволит объехать тоннель и плотно населённый центр города"],"explanation":"При выборе маршрута для опасных грузов избегайте туннелей и густонаселённых районов, так как утечка или пожар там многократно увеличивают опасность для людей."},"127":{"q":"Я перевожу груз легковоспламеняющейся жидкости с размещенными табличками (плакардами) по сельскому округу Техаса по маршруту с несколькими типами переездов и перекрестков. Чтобы соблюдать правила DPS по опасным грузам, перед чем из перечисленного я ОБЯЗАН полностью остановить транспортное средство, прежде чем продолжить движение?","options":["Перед железнодорожным переездом, где я обязан остановиться за 15-50 футов до ближайшего рельса","Перед мигающим желтым предупреждающим сигналом на сельском перекрестке с четырьмя направлениями","Перед открытой заправочной станцией, прежде чем заехать и дозаправить дизельный бак","Перед каждым частным въездом и въездом на поле, который я проезжаю по маршруту"],"explanation":"Транспорт с табличками опасности должен полностью остановиться за 15-50 футов до ближайшего рельса на железнодорожном переезде и никогда не переключать передачи при пересечении."},"128":{"q":"Я перевожу по Техасу груз взрывчатых веществ подкласса 1.2 с размещёнными табличками (плакардами) и мне нужно быстро остановиться на обед. Со мной нет второго водителя. Что требуют правила DPS делать с этим грузом?","options":["Я могу оставить грузовик припаркованным и запертым на стоянке ресторана, пока ем внутри, если двери надёжно закрыты","Я обязан постоянно находиться при грузе с взрывчаткой, поэтому я не могу оставить его без присмотра, чтобы зайти поесть","Я могу оставить его без присмотра на короткое время, если припаркуюсь более чем в 300 футах от любого здания","Я могу оставить его без присмотра, если заглушу двигатель и поставлю на стояночный тормоз перед уходом"],"explanation":"Взрывчатые вещества подкласса 1.1, 1.2 и 1.3 никогда нельзя оставлять без присмотра; водитель или квалифицированный сопровождающий должен постоянно находиться при транспорте."},"129":{"q":"Я перевожу груз легковоспламеняющейся жидкости с размещенными табличками (плакардами) и должен остановиться на ночь. Впереди у зоны отдыха я замечаю придорожный костер, который кто-то оставил гореть. Прежде чем выбрать место для стоянки, какое минимальное расстояние требует руководство соблюдать между моим транспортным средством с плакардами и этим открытым огнем?","options":["Не менее 25 футов — такое же расстояние, как для запрета курения рядом с грузом","Не менее 50 футов — равно максимальному расстоянию остановки перед железнодорожными путями","Не менее 300 футов между транспортным средством и открытым огнем","Установленное расстояние не требуется, пока двигатель заглушен"],"explanation":"Транспорт с табличками опасности должен стоять не ближе 300 футов от открытого огня, так как открытое пламя является прямой угрозой воспламенения груза."},"130":{"q":"Я перевожу груз опасных материалов с табличками-плакардами по незнакомой автомагистрали, когда навигатор перенаправляет меня на дорогу, по которой я никогда не ездил. На этом участке я проеду оживлённую стоянку для грузовиков, открытый пункт весового контроля и длинный подземный проход, прорубленный сквозь гору. Куда из перечисленного мне, скорее всего, будет ЗАКОННО запрещено въезжать с моим опасным грузом, что вынудит меня искать объездной маршрут?","options":["На стоянку для грузовиков, потому что транспорту с плакардами нельзя парковаться там, где собираются люди","На открытый пункт весового контроля, потому что опасные грузы должны объезжать все контрольные весы","Ничто здесь не ограничено, ведь обозначенный маршрут автомагистрали всегда разрешает опасные грузы","В подземный проход, потому что некоторые опасные материалы запрещены в определённых тоннелях"],"explanation":"Избегайте туннелей на маршруте с опасными грузами, так как власти могут на законных основаниях полностью запретить провоз определённых опасных материалов через конкретные туннели."},"131":{"q":"Я перевожу груз коррозийных веществ с табличками опасности через город, когда внезапно натыкаюсь на дорожные работы, перекрывшие две полосы и создавшие пробку на много миль на моём назначенном маршруте для опасных грузов. Знак объезда указывает на более короткий путь через деловой центр города, а навигатор предлагает ещё более быстрый объезд по низкому мосту. Какой принцип должен определять, где мне ехать?","options":["Оставаться на назначенном или обязательном маршруте для опасных грузов, вернувшись на него, как только позволят дорожные условия","Поехать через центр по объезду, потому что следование установленным знакам объезда всегда имеет приоритет над правилами маршрутизации опасных грузов","Следовать предложенному навигатором объезду по низкому мосту, так как он экономит больше всего времени и обходит самую сильную пробку","Выбрать физически кратчайший путь, потому что закон требует лишь минимизировать общее количество пройденных миль"],"explanation":"Водители опасных грузов обязаны следовать назначенному или обязательному маршруту и возвращаться на него, как только позволят дорожные условия, независимо от объездов или пробок."},"132":{"q":"Я перевожу груз с табличками опасности (плакардами) и хочу остановиться на несколько минут, чтобы ответить на звонок и размять ноги. Рядом с маршрутом есть четыре места. Какое из них мне следует ИЗБЕГАТЬ выбирать для стоянки?","options":["Широкая гравийная площадка на сельском участке, где поблизости нет никаких сооружений","Обочина прямо у въезда в тоннель, где собираются пешеходы","Размеченная стоянка для грузовиков, далеко от главного входа в здание","Обочина у открытого поля на расстоянии более 5 футов от проезжей части дороги"],"explanation":"Грузы с табличками опасности нужно держать вдали от тоннелей, мостов и скоплений людей, поэтому въезд в тоннель с собравшимися пешеходами объединяет сразу две опасности."},"133":{"q":"Вы перевозите взрывчатые вещества подкласса 1.2, и уровень топлива низкий, поэтому вы заезжаете на стоянку для грузовиков, чтобы заправиться. Пока бак наполняется, какое из перечисленных действий ЛУЧШЕ всего соответствует вашим обязанностям при таком грузе?","options":["Оставить двигатель работающим на холостом ходу у колонки, чтобы быстро долить и уехать, а самому зайти внутрь оплатить","Поставить машину прямо у оживлённого входа в магазин под фонарями, чтобы загруженный прицеп был на виду у персонала","Всё время оставаться рядом с машиной и держать её подальше от скоплений людей и мест сбора","Запереть кабину, оставить тягач у колонки и пойти внутрь за кофе, пока автоматический клапан завершает заправку"],"explanation":"Взрывчатые вещества классов 1.1, 1.2 и 1.3 нельзя оставлять без присмотра, поэтому водитель должен находиться при транспортном средстве и держать его вдали от скоплений людей."},"134":{"q":"У меня уже есть CDL класса A, и меня только что наняли перевозить грузы с табличками (плакардами) — едкую (коррозийную) жидкость. Мой приятель говорит, что прежде чем я смогу законно начать, мне достаточно сдать короткий письменный тест в офисе DPS, чтобы добавить эту специальную отметку (endorsement). Какое из перечисленных требований является ЕДИНСТВЕННЫМ, которое нельзя обойти, чтобы получить нужную мне отметку для опасных грузов (HazMat, отметка H)?","options":["Прохождение практического экзамена по вождению именно на цистерне-прицепе с табличками (плакардами)","Наличие этой отметки не менее 30 дней до перевозки любого груза с табличками","Обновление медицинской справки DOT в течение той же недели, когда добавляется отметка","Прохождение оценки угрозы безопасности TSA, включая проверку биографии и снятие отпечатков пальцев"],"explanation":"Для получения допуска HazMat нужно пройти оценку угрозы безопасности TSA, включающую проверку биографии и снятие отпечатков пальцев, а не только письменный тест."},"135":{"q":"Я перевожу груз легковоспламеняющейся жидкости с размещёнными табличками (плакардами) и хочу быстро остановиться у придорожной закусочной, чтобы пообедать. Какое из следующих действий нарушит правила перевозки опасных грузов?","options":["Оставить транспортное средство с табличками без присмотра на стоянке, пока я сижу внутри закусочной и ем","Держать товаросопроводительные документы в кармане двери в пределах досягаемости во время стоянки","Проверить шины перед тем, как снова выехать на шоссе","Припарковаться на расстоянии более 5 футов от проезжей части дороги"],"explanation":"Транспортное средство с опасным грузом и табличками нельзя оставлять без присмотра, поэтому уход от грузовика, когда груз без наблюдения, является нарушением."},"136":{"q":"Я перевожу маркированный груз коррозийных веществ и останавливаюсь на ночь на стоянке для грузовиков. Когда утром я возвращаюсь к своему тягачу, чтобы начать осмотр перед рейсом, какое из следующих наблюдений должно обеспокоить меня БОЛЬШЕ ВСЕГО как проблема безопасности, на которую я специально обучен обращать внимание?","options":["За ночь на лобовом стекле образовался тонкий слой инея","Грузовая пломба перерезана, а табличка-плакат выглядит частично отклеенной","Указатель уровня топлива показывает немного меньше, чем накануне вечером","Рядом с моим местом теперь припаркован другой грузовик"],"explanation":"Срезанная пломба груза и частично отклеенная табличка опасности — классические признаки вмешательства или кражи, которые водители опасных грузов обучены замечать."},"137":{"q":"Меня только что приняли на работу в перевозчика, который возит грузы опасных материалов, требующие табличек (placards), и во время инструктажа диспетчер вручает мне папку с документами компании и говорит, что федеральные правила требуют, чтобы многие перевозчики, как наш, имели один из этих документов в письменном виде. На какой документ он, скорее всего, ссылается как на нормативное требование?","options":["Письменный ежедневный график обедов и остановок для отдыха, который каждый водитель должен подписать перед выездом со двора","Письменный список предпочитаемых компанией заправочных станций, одобренных для транспортных средств с табличками","Письменный план безопасности (security plan), описывающий, как компания защищается от кражи и неправомерного использования опасных материалов","Письменный список радиостанций, которые водители могут слушать во время перевозки груза"],"explanation":"Многие перевозчики опасных грузов обязаны разрабатывать и поддерживать письменный план безопасности, охватывающий персонал, несанкционированный доступ и безопасность в пути."},"138":{"q":"Зима, и мой прицеп оснащён автоматическим грузовым обогревателем. Перед выездом с терминала диспетчер выдаёт мне груз и велит сохранять его в тепле в пути. С каким из перечисленных грузов я категорически НЕ должен включать грузовой обогреватель?","options":["Герметичный груз консервов в сухом фургоне, который может замёрзнуть на холоде","Пустой прицеп, который я перегоняю к следующему месту погрузки","Паллетированный груз бутилированной питьевой воды, чувствительной к замерзанию","Груз бочек с легковоспламеняющейся жидкостью, выделяющих пары при нагреве"],"explanation":"Грузовой обогреватель нельзя использовать с грузом легковоспламеняющейся жидкости, так как выделяемые при нагреве пары могут воспламениться и вызвать пожар или взрыв."},"140":{"q":"Я гружу партию, требующую размещения табличек (плакардов), и в транспортных документах указана позиция, которую мой перевозчик отметил как \"запрещённый\" (forbidden) материал согласно правилам перевозки опасных грузов. Прежде чем я подпишу документы на груз, какое утверждение правильно описывает мою обязанность в отношении этой позиции?","options":["Я вообще не должен перевозить этот материал, потому что запрещённые материалы нельзя перевозить ни на каком транспортном средстве и ни при каких условиях.","Я могу перевозить его, если размещу нужные таблички (плакарды) со всех четырёх сторон и буду держать документы в пределах досягаемости.","Я могу перевозить его, только если совокупный вес брутто за рейс не превысит 1 001 фунт.","Я могу перевозить его, как только грузоотправитель добавит в документы правильное транспортное наименование, класс опасности и идентификационный номер."],"explanation":"Запрещённые материалы нельзя перевозить ни при каких условиях, поэтому единственно правильное действие — вообще отказаться их перевозить."},"141":{"q":"Я готовлю груз, и грузоотправитель сообщает, что часть его квалифицируется как партия \"ограниченного количества\" (limited quantity). Прежде чем я распишусь за неё, что из перечисленного должно быть ВЕРНО в отношении этой части груза?","options":["Поскольку это особая категория, она освобождена от всех правил по опасным грузам, и я могу везти её вообще без документов","Речь идёт о меньших количествах материала, поэтому к нему применяются сниженные требования к упаковке и маркировке","Она всегда требует максимального числа табличек (плакардов) со всех четырёх сторон независимо от веса","Этот термин относится только к жидкостям, поэтому любые твёрдые вещества в грузе не могут быть ограниченным количеством"],"explanation":"Ограниченное количество перевозится в меньших объёмах ниже установленных порогов, поэтому к нему применяются сниженные требования к упаковке и маркировке."},"142":{"q":"Я провожу предрейсовый осмотр груза с опасными материалами и открываю кузов, чтобы сверить каждую коробку с товарно-транспортными документами. Грузоотправитель всё опломбировал и упаковал, но мне всё равно нужно подтвердить, что находится в каждой отдельной упаковке. Чтобы сопоставить коробки с надлежащим транспортным наименованием, классом опасности и идентификационным номером в документах, что я должен ожидать увидеть нанесённым на самой упаковке?","options":["Копию товарно-транспортных документов, приклеенную к каждой коробке, чтобы упаковка и документы всегда перемещались вместе","Название перевозчика и моё полное имя, чтобы спасатели знали, какой водитель и какая компания везут груз","Знак опасности и маркировку, идентифицирующие материал, чтобы я мог сверить упаковку с записями в товарно-транспортных документах","Розничный ценник со стоимостью товара, чтобы получатель мог подтвердить ценность груза при доставке"],"explanation":"Грузоотправитель маркирует каждую упаковку классом опасности и транспортным наименованием, чтобы вы могли сверить каждую упаковку с транспортными документами."},"143":{"q":"Я загружаю партию радиоактивного материала класса 7, и грузоотправитель проверяет со мной маркировку упаковок перед тем, как я подпишу документы. Он указывает на число, напечатанное на этикетке, которое мне нужно будет учесть, когда я буду рассчитывать, сколько этого материала можно совместно разместить в моём прицепе. Какое из перечисленных значений представляет собой этот определяющий показатель, который могут иметь радиоактивные упаковки?","options":["Показатель опасности отравления при вдыхании, освобождающий груз от размещения табличек при любом количестве","Код допуска, позволяющий грузу не проходить весовые станции и игнорировать ограничения маршрута","Лимит отчётного количества (RQ), устраняющий необходимость в какой-либо маркировке упаковки","Лимит транспортного индекса, ограничивающий, сколько можно перевозить совместно"],"explanation":"Радиоактивные упаковки класса 7 имеют транспортный индекс, предельное значение которого ограничивает количество радиоактивного материала, перевозимого вместе."},"144":{"q":"Я загружаю груз с табличками опасности, который в транспортных документах указан как реактивный (реакционноспособный) материал, и решаю, где именно в прицепе и как его разместить на время перевозки. Чтобы обращаться с ним безопасно, от чего из перечисленного я обязан держать этот реактивный материал подальше?","options":["От источников тепла, от воды или влаги и от любых других реактивных материалов в грузе","От мягких тёплых одеял или прокладок, которыми смягчают груз при перевозке","От любого большого пустого открытого пространства в прицепе, где упаковка может сместиться","От прямого попадания очень яркого света через двери прицепа"],"explanation":"Реакционноспособные материалы нужно держать вдали от тепла, воды или влаги и других реакционноспособных веществ, так как контакт может вызвать бурную реакцию."},"145":{"q":"Мне поручено забрать автоцистерну с охлаждённым жидким азотом - криогенной (очень холодной) жидкостью - для дальней перевозки. Осматривая прицеп перед приёмом груза, по какому признаку я пойму, что груз такого типа обслуживается правильно?","options":["Цистерна полностью герметична, без вентиляции, чтобы холод не уходил и продукт оставался замороженным","Цистерна оснащена специальным изолированным оборудованием и исправным клапаном для безопасного сброса накопившегося давления","Внутри цистерны установлен небольшой нагреватель, чтобы жидкость не заморозила клапаны","Это обычная цистерна для сыпучих грузов без дополнительной арматуры, ведь холод не требует особого ухода"],"explanation":"Криогенные жидкости постоянно поглощают тепло и создают давление, поэтому им нужно специальное изолированное оборудование и исправный клапан для безопасного сброса давления."},"146":{"q":"Мой прицеп с размещёнными табличками опасности переворачивается на сельской трассе в Техасе, и из бочки начинает вытекать груз. Первая пожарная бригада прибывает раньше, чем я успеваю что-либо объяснить, берёт мои товаросопроводительные документы и сразу зачитывает класс опасности и идентификационный номер ООН/NA, указанный для груза. В чём ГЛАВНАЯ причина того, что класс опасности и идентификационный номер так важны для спасателей на месте происшествия?","options":["Они позволяют спасателям рассчитать, превышал ли мой груз порог в 1 001 фунт, при котором изначально требовались таблички опасности","Они доказывают, что я, водитель, уже позвонил в CHEMTREC, а перевозчик подал отчёт об инциденте до прибытия помощи","Они позволяют спасателям быстро точно определить, в чём именно состоит опасность, чтобы правильно среагировать на этот материал","Они подтверждают, что таблички опасности были установлены со всех четырёх сторон и читались с того направления, на которое были обращены"],"explanation":"Транспортное наименование, класс опасности и идентификационный номер позволяют спасателям быстро определить точную опасность и правильно действовать с материалом."},"148":{"q":"У меня уже есть CDL класса A штата Техас, и я два года вожу сухой груз. В следующем месяце мой перевозчик хочет, чтобы я начал возить грузы, требующие размещения знаков (плакатов) на всех четырёх сторонах прицепа. Что я должен пройти, прежде чем законно принять этот первый рейс с плакатами?","options":["Ничего дополнительно — CDL класса A сам по себе уже разрешает любой груз с плакатами","Только разрешение на цистерну (N), поскольку груз с плакатами перевозится наливом в цистернах","Только разрешение на двойные/тройные прицепы (T), чтобы покрыть дополнительный вес прицепа","Разрешение на опасные грузы (H), для которого нужно пройти проверку безопасности TSA со снятием отпечатков пальцев"],"explanation":"Перевозка количества опасного груза, требующего табличек, требует допуска HazMat (H), который выдается только после прохождения проверки безопасности TSA со снятием отпечатков пальцев."},"149":{"q":"Я только что забрал груз коррозийных веществ с табличками-плакардами. В транспортных документах есть ошибка в классе опасности, и я замечаю её ещё до выезда из терминала. Диспетчер говорит мне: «Эти бумаги — на 100% забота грузоотправителя, твоя единственная задача — вести машину». Согласно правилам перевозки опасных грузов, какое утверждение ВЕРНО?","options":["Безопасная перевозка — это общая ответственность: у грузоотправителя, перевозчика и водителя есть свои конкретные обязанности, и я не имею права сознательно везти неправильно маркированный груз.","Поскольку только грузоотправитель классифицирует и оформляет документы, водитель не несёт ответственности за ошибки в бумагах и может законно перевезти груз в том виде, в каком он есть.","Как только перевозчик отправил груз в рейс, вся юридическая ответственность за него переходит к перевозчику, поэтому водитель может полностью полагаться на диспетчерскую службу.","Единственная обязанность водителя — безопасное вождение, поэтому правильность документов — исключительно дело грузоотправителя, и водителю никогда не нужно её проверять."],"explanation":"Безопасность опасных грузов — общая ответственность грузоотправителя, перевозчика и водителя, и вы обязаны отказаться сознательно везти протекающий или неправильно маркированный груз."},"150":{"q":"Я забираю груз баллонов со сжатым пропаном, и начальник дока вручает мне товарно-транспортные документы, где материал указан как опасный класс 2. Прежде чем установить таблички, я хочу подтвердить, что на самом деле означает класс 2. Какое утверждение верно?","options":["Класс 2 охватывает коррозионные вещества, такие как аккумуляторная кислота и гидроксид натрия, которые я иногда вожу.","Класс 2 охватывает газы, включая воспламеняющиеся, невоспламеняющиеся и ядовитые газы, как мой пропан.","Класс 2 охватывает взрывчатые вещества, поэтому на этот груз распространяются те же правила, что и на динамит и фейерверки.","Класс 2 охватывает радиоактивные материалы, поэтому этим баллонам нужна дополнительная защитная экранировка."],"explanation":"Класс опасности 2 — это газы, разделенные на 2.1 воспламеняющиеся, 2.2 невоспламеняющиеся и 2.3 ядовитые газы, и пропан относится к воспламеняющимся газам этого класса."},"151":{"q":"Я загружаю бочки с аккумуляторной кислотой для доставки, и в транспортных документах класс опасности указан как 8. Прежде чем повесить таблички на прицеп, мне нужно понять, какую именно опасность представляет этот груз. Какое из следующих утверждений верно описывает материал класса опасности 8?","options":["Сжатый или сжиженный газ, который может вытечь и создать опасность для дыхания","Токсичное вещество, которое может отравить человека при контакте с кожей или вдыхании","Коррозионный материал, способный химически обжечь кожу, металл или другие материалы","Взрывчатое вещество, которое может сдетонировать от нагрева, удара или трения"],"explanation":"Класс опасности 8 — это коррозионные вещества, такие как аккумуляторная кислота, которые химически разъедают или сжигают кожу, металл и другие материалы."},"152":{"q":"Я загружаю прицеп, когда грузоотправитель вручает мне документы на груз с пометкой 'Класс опасности 7', с номером ООН и надлежащим транспортным наименованием. Прежде чем установить таблички, мне нужно точно понять, какую опасность я перевожу. Согласно системе классов опасности, что говорит мне Класс 7 об этом грузе?","options":["Это коррозийный материал, поэтому при утечке содержимое может обжечь кожу и разъесть металлические поверхности","Это легковоспламеняющаяся жидкость, поэтому я должен держать все источники возгорания и открытый огонь подальше от неё","Это сжатый или ядовитый газ, поэтому сброс давления может создать опасность вдыхания","Это радиоактивный материал, поэтому я везу груз, излучающий радиацию и требующий особого обращения"],"explanation":"Класс опасности 7 всегда означает радиоактивные материалы, поэтому груз испускает излучение и требует особого обращения независимо от указанного транспортного наименования."},"153":{"q":"Я загружаю прицеп, и в моих товарно-транспортных документах указан материал класса опасности 5. Прежде чем размещать таблички (плакарды), я хочу подтвердить, какую именно опасность представляет этот груз. Материал класса 5 — это материал, который:","options":["Является окислителем или органическим пероксидом, способным усиливать огонь за счёт выделения кислорода","Является коррозионным веществом, способным разрушать кожные ткани или разъедать сталь и алюминий","Является взрывчатым веществом, способным к массовой детонации при воздействии тепла или удара","Является сжатым газом, который может быть горючим, негорючим или ядовитым"],"explanation":"Окислители и органические пероксиды класса опасности 5 выделяют кислород, что может вызвать или усилить пожар даже без внешнего источника воспламенения."},"154":{"q":"Я гружу на доке небольшое количество вещества с ядовитой ингаляционной опасностью (PIH), и общий вес значительно меньше 1 001 фунта. Диспетчер говорит, что груз настолько лёгкий, что я могу везти его как обычный фрахт. Как правильно следует обращаться с этой партией PIH?","options":["Поскольку груз весит меньше 1 001 фунта, таблички не требуются, и я могу везти его как обычный фрахт","Я должен соблюдать особую осторожность и разместить надлежащие таблички, потому что материалы PIH требуют размещения табличек в любом количестве","Мне нужны таблички, только если я пересекаю границу штата; для внутриштатных партий PIH весом менее 1 001 фунта особого обращения не требуется","Мне следует сократить документацию и не оформлять товаросопроводительные документы, раз количество такое малое"],"explanation":"Материалы с опасностью отравления при вдыхании (PIH) относятся к Таблице 1 и требуют размещения табличек при любом количестве, без минимального порога веса."},"155":{"q":"Я загружаю прицеп несколькими коробками с грузом, который в транспортной накладной указан под классом опасности 9. Он не горючий, не коррозийный и не является сжатым газом, и всё же для него потребовалась табличка-плакат. Какое утверждение ЛУЧШЕ всего описывает, что охватывает класс опасности 9?","options":["Сжатые и сжиженные газы, негорючие под давлением","Коррозийные жидкости и твёрдые вещества, способные повредить кожу или металл","Прочие (разные) опасные материалы, не подходящие под остальные восемь классов","Взрывчатые вещества — от взрывчатых смесей до фейерверков и детонаторов"],"explanation":"Класс опасности 9 — это общая категория «Прочие» для регулируемых материалов, представляющих транспортную опасность, но не подпадающих под классы с 1 по 8."},"156":{"q":"Я готовлю товарно-транспортные документы на груз, и в записи указан класс опасности 4. Прежде чем установить таблички, я хочу подтвердить, какой именно материал я везу, чтобы выбрать правильную табличку. Какое из следующих утверждений правильно описывает материал класса 4?","options":["Легковоспламеняющаяся жидкость, например бензин или дизельное топливо","Сжатый газ, будь то горючий или негорючий","Коррозийный материал, способный повредить кожу и металл","Легковоспламеняющееся твёрдое вещество, которое легко воспламеняется или горит"],"explanation":"Класс опасности 4 включает легковоспламеняющиеся твёрдые вещества, в том числе самовозгорающиеся и опасные при намокании, которые легко воспламеняются или горят."},"157":{"q":"Я еду с размещёнными табличками опасного груза и остановился на весовой станции в Техасе, когда инспектор указывает на четырёхзначный номер 1203 на оранжевой панели моего прицепа и спрашивает, что этот номер ему сообщает. Какой ответ правильный?","options":["Это идентификационный номер (UN/NA), который определяет конкретный материал, который я перевожу","Это код надлежащего отгрузочного наименования, присвоенный грузу перевозчиком","Это номер класса опасности, указывающий, какой из девяти классов применяется","Это номер таблицы табличек, показывающий, применяется ли правило 1 001 фунта"],"explanation":"Четырёхзначный номер в товаросопроводительных документах или на табличке — это идентификационный номер ООН/NA, определяющий конкретный перевозимый материал."},"158":{"q":"Во время предрейсового осмотра инспектор дорожной полиции просит меня назвать 4-значный идентификационный номер UN/NA груза, который я везу, чтобы сверить его с Аварийным справочником (ERG). Я подхожу к боку прицепа с табличками, чтобы найти этот номер. Где я могу правильно прочитать этот 4-значный идентификационный номер?","options":["Только по надлежащему транспортному наименованию, напечатанному в транспортных документах; снаружи прицепа он никогда не указывается","Либо непосредственно на самой табличке (плакате), либо на оранжевой панели, закреплённой рядом с табличкой","Только по номеру класса опасности, указанному в нижнем углу ромбовидной таблички","Только по заводской табличке изготовителя, выбитой на раме прицепа возле опорного устройства"],"explanation":"Четырёхзначный идентификационный номер ООН/NA может указываться либо в центре самой таблички, либо на оранжевой панели рядом с ней."},"159":{"q":"Во время придорожной проверки инспектор указывает на ромбовидную табличку (placard) сзади моего прицепа и просит меня назвать номер класса опасности, который определяет перевозимый груз. На табличке вверху изображён символ, в средней полосе написаны слова, и есть одна цифра. Где именно на табличке мне следует искать этот номер класса опасности?","options":["По центру таблички, прямо там, где напечатано письменное название материала","В самой верхней точке ромба, прямо над символом опасности или пиктограммой","В нижнем углу ромба, под символом и письменным названием материала","Вдоль левого или правого бокового края ромба, рядом с символом опасности"],"explanation":"На табличке однозначный номер класса опасности располагается в нижнем углу ромба, под символом и письменным названием опасности."},"160":{"q":"Я загружаю прицеп на грузовом терминале несколькими нерасфасованными упаковками, каждая из которых относится к своему классу опасности из Таблицы 2, и ни одна из них по отдельности не достигает порога в 1 001 фунт, который потребовал бы отдельного плаката. Вместо того чтобы вешать отдельный плакат для каждого класса, я хотел бы использовать один плакат 'DANGEROUS' (ОПАСНО) на всю смешанную партию. При каком условии использование этого единого плаката 'DANGEROUS' действительно разрешено?","options":["Только когда каждая упаковка в прицепе относится к одному и тому же единственному классу опасности","Только когда в прицепе вообще не перевозится никакой регулируемый опасный материал","Только когда груз ограничен потребительскими продуктами питания, отправляемыми вместе с фрахтом","Когда груз содержит два или более различных класса опасности из Таблицы 2, перевозимых вместе"],"explanation":"Табличка DANGEROUS может использоваться вместо отдельных табличек, когда нерасфасованный груз содержит два или более классов опасности из Таблицы 2."},"161":{"q":"Я загружаю одну небольшую бочку материала из Таблицы 1 (ядовитый газ подкласса 2.3) для короткого местного рейса. Общий вес опасного груза значительно меньше 1000 фунтов. Прежде чем выехать, как я должен разместить таблички (плакарды) на транспортном средстве?","options":["Я обязан разместить таблички со всех четырёх сторон, независимо от того, насколько мал груз, потому что материалы из Таблицы 1 требуют табличек в любом количестве.","В этом рейсе таблички не нужны, потому что я везу меньше совокупного полного веса в 1001 фунт, при котором требуются таблички.","Таблички нужны только когда мой суммарный опасный груз достигнет 1001 фунта или более, поэтому одна маленькая бочка не подпадает под требование.","Таблички нужны только если рейс межштатный или проходит через населённую местность, поскольку короткий местный рейс их не требует."],"explanation":"Ядовитый газ подкласса 2.3 относится к Таблице 1 и должен иметь таблички на всех четырёх сторонах при любом количестве, независимо от веса."},"162":{"q":"Я загружаю прицеп со смешанным грузом, и единственный опасный материал на борту - это продукт из Таблицы 2. В моих транспортных документах указано, что совокупная масса брутто составляет ровно 900 фунтов. Согласно правилам размещения табличек DPS, что я обязан сделать перед выездом?","options":["Разместить таблички на всех четырёх сторонах, потому что любое количество опасного материала из Таблицы 2 всегда требует размещения табличек","Таблички не требуются, потому что материалы из Таблицы 2 требуют табличек только при совокупной массе брутто 1 001 фунт или более","Разместить таблички на всех четырёх сторонах, потому что груз превышает порог отчётности в 100 фунтов для перевозок по Таблице 2","Разместить табличку только сзади, поскольку 900 фунтов достаточно для частичного размещения табличек, но не для полного размещения на четырёх сторонах"],"explanation":"Материалы из Таблицы 2 требуют размещения табличек только при достижении суммарной полной массы 1001 фунт или более."},"163":{"q":"Я загружаю прицеп на складе грузоотправителя и замечаю ромбовидные предупреждения об опасности, которые грузоотправитель нанёс, чтобы обозначить содержимое. Где должны размещаться эти знаки опасности (этикетки)?","options":["На всех четырёх сторонах прицепа, читаемыми с той стороны, куда они обращены","На транспортных документах, в колонке HM рядом с каждой записью","На самих отдельных упаковках и контейнерах","В сумке на двери водителя, где хранятся документы"],"explanation":"Знаки опасности наносятся грузоотправителем непосредственно на каждую отдельную упаковку и контейнер для обозначения класса опасности содержимого."},"164":{"q":"Я загружаю партию коррозийных веществ, которая требует табличек-плакатов, и мой сменный водитель передаёт мне четыре ромбовидные таблички КОРРОЗИЯ. Он говорит, куда, по его мнению, их нужно поместить, но я хочу всё сделать правильно перед выездом. Где на самом деле должны быть размещены эти таблички?","options":["Прикреплены к каждой отдельной упаковке и контейнеру внутри прицепа, чтобы инспекторы видели опасность при открытии дверей","Прикреплены к товарно-транспортным документам в столбце HM рядом с надлежащим транспортным наименованием, классом опасности и идентификационным номером","Закреплены в кармане на двери водителя рядом с документами, чтобы оставаться в пределах моей досягаемости во время движения","Размещены на всех четырёх сторонах транспортного средства и читаемы с той стороны, в которую обращена каждая из них"],"explanation":"Знаки-таблички размещаются на всех четырёх сторонах транспортного средства, и каждый должен быть читаем с той стороны, к которой он обращён."},"165":{"q":"Загружая прицеп, я беру запечатанный упаковочный ящик, на двух противоположных сторонах которого нанесены две чёрные вертикальные стрелки, направленные вверх. Документы грузоотправителя в порядке, но я хочу убедиться, что устанавливаю его правильно. Что эти стрелки ориентации требуют от меня сделать с этим ящиком?","options":["Держать упаковку всегда в вертикальном положении, стрелками вверх, чтобы закрытые горловины оставались сверху","Положить упаковку на бок, чтобы стрелки указывали горизонтально в сторону стенки прицепа","Складывать как угодно, ведь стрелки лишь показывают, где погрузчик должен её поднимать","Перевернуть упаковку вверх дном, чтобы запечатанный конец опирался на пол прицепа"],"explanation":"Стрелки ориентации упаковки означают, что упаковку нужно держать вертикально стрелками вверх, чтобы крышки и закрытия оставались сверху."},"166":{"q":"Я новый водитель с допуском на опасные грузы и провожу предрейсовую проверку транспортной накладной на коррозионный груз. Я ясно вижу надлежащее транспортное наименование и класс опасности для каждой позиции. Чтобы убедиться, что описание полное и соответствует федеральным требованиям перед выездом, какая оставшаяся информация ТАКЖЕ ДОЛЖНА присутствовать в этом базовом описании груза?","options":["Общая заявленная стоимость коррозионного груза в долларах","Идентификационный номер (UN или NA) для материала","Полная разрешённая масса, указанная в моих водительских правах CDL","Дата окончания срока действия моего допуска на опасные грузы"],"explanation":"Полное базовое транспортное описание включает надлежащее транспортное наименование, класс опасности и идентификационный номер UN или NA именно в этом порядке."},"167":{"q":"Я проверяю транспортные документы на груз и замечаю римскую цифру 'II', указанную рядом с записью о материале в качестве его группы упаковки (Packing Group). Новый водитель спрашивает меня, что эта 'II' на самом деле говорит нам о грузе. Какое из следующих объяснений правильно описывает, что обозначает группа упаковки?","options":["Она указывает номер класса опасности (с 1 по 9), присвоенный материалу","Она указывает минимальную полную массу, при которой требуется размещение табличек (плакардов)","Она показывает относительную степень опасности материала (I, II или III)","Она указывает идентификационный номер ООН/NA (UN/NA), который следует за наименованием груза"],"explanation":"Группа упаковки, обозначаемая римской цифрой I, II или III, указывает на относительную степень опасности материала."},"168":{"q":"Я загружаю партию опасных грузов, и в товарно-транспортной накладной группа упаковки материала указана как «PG I» (группа упаковки I). Новичок-водитель говорит мне, что римская цифра «I» просто означает, что это первая позиция в списке, и что она обозначает самый низкий уровень опасности из трёх групп упаковки. Прежде чем я подпишу документы на груз и размещу таблички, что на самом деле говорит мне «группа упаковки I» о степени опасности этого материала?","options":["Она указывает на наименьшую степень опасности, так как группа упаковки I — это самый низкий уровень, а группа упаковки III — самый опасный","Она указывает лишь на среднюю степень опасности, занимая место между группой упаковки II и группой упаковки III","Она указывает на отсутствие реальной опасности и используется только для обозначения позиции позиции в накладной","Она указывает на наибольшую степень опасности, так как группа упаковки I — самая опасная из трёх групп упаковки"],"explanation":"Группа упаковки I означает наибольшую степень опасности, так как является самой опасной из трёх групп упаковки."},"169":{"q":"Я загружаю прицеп со смешанным опасным грузом и замечаю, что у двух упаковок разные классы опасности. Прежде чем поставить их рядом, я достаю таблицу совместимости (сегрегации). Что на самом деле говорит мне эта таблица?","options":["Какие материалы несовместимы и НЕ должны загружаться вместе в один груз","Какие материалы всегда нужно загружать вместе, чтобы их таблички (плакарды) совпадали","Какие материалы следует продать или доставить первыми, чтобы снизить мою ответственность","Какие материалы нужно промаркировать второй раз перед закрытием дверей"],"explanation":"Таблица совместимости показывает, какие материалы несовместимы и не должны загружаться вместе в один груз."},"170":{"q":"Я нахожусь на погрузочной площадке грузоотправителя и собираюсь загрузить несколько бочек с коррозийным веществом класса 8 в свой прицеп с табличками опасного груза. Перемещая первую бочку, я замечаю влажную блестящую плёнку вокруг нижнего шва и небольшую лужу на поддоне. Прежде чем загрузить ЛЮБУЮ из этих упаковок, что является самым важным, что мой предпогрузочный осмотр обязан подтвердить?","options":["Что каждая бочка окрашена в яркий, хорошо заметный цвет, чтобы её было легко увидеть в прицепе","Что упаковки не протекают и не повреждены, поскольку я обязан отказаться от любого контейнера с признаками течи или нарушения целостности","Что бочки уложены как можно выше, чтобы груз был плотным и не смещался в пути","Что пробки оставлены неплотно закрытыми или открытыми, чтобы внутреннее давление могло стравливаться во время поездки"],"explanation":"Перед погрузкой осмотрите каждую упаковку, чтобы убедиться в отсутствии течи или повреждений, и откажитесь от любого контейнера с течью или нарушением целостности."},"171":{"q":"Я водитель, загружающий легковоспламеняющуюся жидкость (класс 3) в свой прицеп на оживлённой площадке терминала. Вокруг меня одновременно происходит несколько вещей, и я хочу выполнить погрузку безопасно. Что из перечисленного я обязан держать ПОДАЛЬШЕ от грузового отсека во время погрузки этого опасного груза?","options":["Поддонную тележку, которой пользуется бригада на доке","Грузовик доставки, работающий на холостом ходу у соседнего дока","Источник открытого огня или искрообразования","Штабель пустых деревянных поддонов"],"explanation":"Держите открытое пламя и источники искр вдали от опасных грузов при погрузке, так как горючие материалы могут воспламениться от любого источника возгорания."},"172":{"q":"Я загружаю несколько бочек и коробок с опасным грузом, требующим табличек, в свой закрытый фургон для дальнего междуштатного рейса. После того как я погрузил их в кузов, что я должен сделать с этими ёмкостями, прежде чем закрыть двери и тронуться в путь?","options":["Плотно придвинуть их к передней стенке прицепа и положиться на то, что передняя стенка удержит их на месте в течение всей поездки","Равномерно распределить их по полу, чтобы уравновесить вес, а затем положиться на обычное трение о пол, чтобы они оставались на месте","Сложить их как можно выше у одной боковой стенки, чтобы освободить место на полу для остальной части груза","Закрепить и зафиксировать каждую ёмкость так, чтобы она не могла сдвинуться, соскользнуть или опрокинуться во время движения транспортного средства"],"explanation":"Закрепите и зафиксируйте каждый контейнер с опасным грузом так, чтобы он не мог сдвинуться, соскользнуть или опрокинуться во время движения транспортного средства."},"173":{"q":"Я перевожу груз опасных отходов, и перед выездом из терминала грузоотправитель вручает мне манифест на опасные отходы вместе с остальными документами. Что я обязан сделать с этим манифестом, чтобы соблюсти правила перевозки опасных грузов?","options":["Подписать его и держать копию вместе с товаросопроводительными документами в пределах досягаемости","Оставить его подписанным на терминале, чтобы перевозчик подал его за меня","Везти его неподписанным, пока на доставке его не подпишет принимающий объект","Отправить подписанную копию в государственное ведомство по почте после поездки"],"explanation":"Манифест опасных отходов должен быть подписан водителем и храниться вместе с грузовыми документами в пределах досягаемости во время движения."},"174":{"q":"Я новый водитель с допуском H, и грузоотправитель вручает мне документы на материал, который правила прямо относят к веществам, которые в принципе нельзя перевозить никаким коммерческим транспортом ни при каких обстоятельствах. Прежде чем сделать что-либо ещё, как правильно отнестись к этому грузу?","options":["Его можно везти в любом количестве, если разместить таблички с опасностью на всех четырёх сторонах прицепа","Он запрещён к перевозке, поэтому ни один водитель не имеет права его перевозить вообще","Его можно везти свободно, потому что мой допуск H охватывает все классы опасности","Ему никогда не нужны таблички, поэтому я могу везти его, никого не уведомляя"],"explanation":"Некоторые материалы настолько опасны, что полностью запрещены к перевозке, и никто не может их законно транспортировать."},"175":{"q":"Я загружаю груз, обозначенный как взрывчатые вещества класса 1, и в транспортных документах материал указан с номером подкласса сразу после класса. Коллега говорит мне, что класс 1 - это единая неделимая категория, поэтому номер подкласса наверняка опечатка. Какое утверждение правильно описывает структуру класса 1?","options":["Класс 1 - это единая неделимая категория, поэтому любой номер подкласса после него является ошибкой","Класс 1 делится ровно на две группы по цветовой кодировке упаковки","Класс 1 разбит на несколько подклассов, пронумерованных от 1.1 до 1.6","У класса 1 нет подгрупп; подклассы существуют только для газов в классе 2"],"explanation":"Класс опасности 1 (Взрывчатые вещества) подразделяется на несколько подклассов с номерами от 1.1 до 1.6."},"176":{"q":"На грузовом терминале диспетчер передаёт мне товарно-транспортные документы на груз с маркировкой «Подкласс 1.1» и спрашивает, насколько серьёзно я должен оценивать потенциал взрыва, прежде чем установить таблички и проложить маршрут. Исходя из того, что говорит мне подкласс опасности, какое утверждение должно определять моё решение?","options":["Он несёт только опасность разлёта осколков, поэтому я планирую в основном защиту от летящих фрагментов, а не от полной детонации","Он представляет лишь незначительный риск пожара, поэтому стандартного огнетушителя и осторожной заправки мне вполне достаточно","У него лишь слабая взрывная опасность, ограниченная самой упаковкой, поэтому расстояние до зданий не имеет большого значения","Он представляет опасность массового взрыва — весь груз может сдетонировать одновременно, поэтому я должен относиться к нему как к самому опасному подклассу взрывчатых веществ"],"explanation":"Взрывчатые вещества подкласса 1.1 представляют опасность массового взрыва, когда весь груз может детонировать одновременно, что делает их самым опасным подклассом взрывчатых веществ."},"177":{"q":"Я перевожу груз взрывчатых веществ Подкласса 1.2 с табличками-плакатами, и мне нужно остановиться на обед в небольшом городке. Какое действие водителя соответствует правилам перевозки этого груза?","options":["Оставаться с автомобилем или поручить квалифицированному лицу наблюдать за ним, чтобы груз никогда не оставался без присмотра","Запереть кабину, поставить на тормоз и оставить машину на стоянке у ресторана, пока я ем внутри","Припарковаться в пределах 5 футов от проезжей части дороги, чтобы следить за машиной из окна","Оставить груз без присмотра на срок до 2 часов, если он стоит рядом со зданием"],"explanation":"Взрывчатые вещества подклассов 1.1, 1.2 и 1.3 нельзя оставлять без присмотра; водитель или другой квалифицированный человек должен постоянно находиться при грузе и наблюдать за ним."},"178":{"q":"Я перевожу взрывчатые вещества подкласса 1.1, когда у моего прицепа возникает техническая неисправность на двухполосном шоссе общего пользования. Прибывает второй грузовик компании, и диспетчер хочет, чтобы я перегрузил взрывчатый груз на другой автомобиль, чтобы груз продолжил движение. Согласно правилам перевозки опасных грузов, где мне разрешено проводить такую перегрузку между транспортными средствами?","options":["Прямо здесь, на обочине шоссе, ведь второй грузовик уже на месте и готов принять груз","Ни в коем случае не на дороге общего пользования, если только это не настоящая чрезвычайная ситуация — перегрузку нужно делать в безопасном месте вне дороги, например на терминале или на базе","В любом месте по маршруту, пока я размещаю надлежащие знаки опасности со всех четырёх сторон обоих автомобилей во время перегрузки","На дороге это допустимо, потому что диспетчер дал прямой приказ продолжать движение груза"],"explanation":"Взрывчатые вещества класса 1 нельзя перегружать между транспортными средствами на общественной дороге, кроме случаев настоящей чрезвычайной ситуации; перегрузку следует выполнять в безопасном месте вне дороги, например на терминале."},"179":{"q":"Я перевожу взрывчатые вещества подкласса 1.2 и мне нужно остановиться на отдых. Впереди я вижу зону отдыха, где у кого-то горит костёр у дороги. В голове крутятся правила о допустимых расстояниях. Какое минимальное расстояние я обязан сохранять между припаркованным грузом со взрывчаткой и этим открытым огнём?","options":["5 футов — тот же минимум, который я обязан соблюдать от проезжей части дороги","10 футов — достаточно, чтобы быть в стороне от разлетающихся искр","300 футов — требуемое расстояние между взрывчаткой и открытым огнём","1 фут, поскольку огонь ограничен внутри кострового кольца"],"explanation":"Транспортное средство с взрывчатыми веществами должно стоять на расстоянии не менее 300 футов от открытого огня."},"180":{"q":"Перед выездом я проверяю транспортные документы на груз газа Класса 2, чтобы подтвердить, какой именно раздел я перевожу. Я знаю, что Класс 2 охватывает более одного типа газа, и перевозчик сказал мне, что три признанных раздела Класса 2 — это легковоспламеняющийся газ (2.1), невоспламеняющийся газ (2.2) и третий раздел, который мне нужно определить для размещения табличек (placards). Что из перечисленного является этим третьим признанным разделом газов Класса 2?","options":["Легковоспламеняющийся твердый газ, так как некоторые газы Класса 2 могут переходить в горючую твердую форму","Коррозионный газ, потому что газы под давлением в цистернах ведут себя как коррозионный материал Класса 8","Только жидкий газ, так как газы под давлением всегда перевозятся в жидком состоянии","Ядовитый (токсичный) газ, который относится к Разделу 2.3 и может требовать табличек в любом количестве"],"explanation":"Газы класса 2 включают ядовитый (токсичный) газ как подкласс 2.3 — материал из Таблицы 1, требующий размещения табличек при любом количестве."},"181":{"q":"Во время остановки на отдых я замечаю, что один из баллонов со сжатым газом на моём грузе с табличками опасности дал медленную утечку и шипит возле вентиля. Рядом по парковке ходят путешественники. Какое из следующих действий является НАИБОЛЕЕ правильным немедленным шагом?","options":["Отвести людей подальше от баллона, держать зону свободной и вызвать аварийную помощь","Затянуть вентиль и самостоятельно загерметизировать утечку, чтобы газ перестал выходить","Слегка подогреть баллон, чтобы давление выровнялось и шипение прекратилось","Покатать и потрясти баллон, чтобы вентиль встал на место и давление снизилось"],"explanation":"При утечке из баллона со сжатым газом отведите людей, держите зону свободной, не допускайте источников возгорания и вызовите экстренную помощь, а не пытайтесь устранить утечку сами."},"182":{"q":"Я загружаю радиоактивный груз класса 7, и грузоотправитель передаёт мне упаковки с радиоактивными этикетками. На каждой этикетке указан номер, который сообщает мне уровень радиации упаковки. Какую систему нумерации я увижу на этих этикетках класса 7?","options":["Этикетки нумеруются A, B или C, что соответствует транспортному индексу упаковки","Этикетки нумеруются I, II или III, указывая на уровень радиации упаковки","Этикетки нумеруются от 1 до 9, что соответствует системе классов опасности","Этикетки нумеруются X, Y или Z, что соответствует букве группы упаковки"],"explanation":"Радиоактивные материалы класса 7 используют три категории этикеток, обозначенных римскими цифрами I, II или III, указывающими уровень радиации упаковки."},"183":{"q":"Я загружаю несколько радиоактивных упаковок класса 7, и грузоотправитель указывает мне на число 'транспортный индекс', напечатанное на каждой этикетке. Чтобы загрузить прицеп безопасно и по закону, что на самом деле сообщает мне это значение транспортного индекса?","options":["Общую денежную стоимость радиоактивного содержимого для целей страхования","Суммарный полный вес всех радиоактивных упаковок на борту","Степень контроля радиации, необходимого при обращении с упаковкой и её перевозке","Идентификационный номер ООН/NA, присвоенный данному радиоактивному материалу"],"explanation":"Транспортный индекс на упаковке с радиоактивным материалом класса 7 указывает степень радиационного контроля, необходимого при обращении и погрузке."},"184":{"q":"Я перевожу через город груз с коррозийными веществами под табличками опасности, и навигатор предлагает три возможных маршрута до одного и того же пункта назначения, все примерно одинаковой длины. Согласно правилам маршрутизации опасных грузов в Техасе, какой из них мне следует выбрать в первую очередь?","options":["Маршрут, проходящий через длинный подземный туннель, так как он позволяет избежать светофоров на поверхности и сэкономить несколько минут","Маршрут, проходящий прямо рядом с переполненным стадионом в центре города как раз в момент окончания мероприятия","Маршрут, идущий мимо нескольких многолюдных торговых центров, чтобы оставаться на широких, хорошо освещённых улицах","Маршрут, проходящий по открытым сквозным улицам и обходящий и туннель, и места массового скопления людей"],"explanation":"Водители опасных грузов должны следовать установленным маршрутам, избегая по возможности тоннелей и густонаселённых или многолюдных мест."},"185":{"q":"Меня направили перевезти груз взрывчатых веществ подкласса 1.1 через весь штат. Мой инструктор говорит, что перед этой поездкой федеральные правила требуют, чтобы мой перевозчик подготовил особый письменный документ, который я обязан иметь при себе и которому должен следовать. О каком документе идёт речь?","options":["Письменный план маршрута, которому должна следовать поездка","Письменный ежедневный журнал расхода топлива и пробега водителя","Письменный договор купли-продажи на взрывчатый груз","Письменный прогноз погоды на дороге на 72 часа"],"explanation":"Грузы взрывчатых веществ (подкласс 1.1, 1.2, 1.3) должны перевозиться по письменному плану маршрута, составленному перевозчиком и имеющимся у водителя."},"186":{"q":"Я три часа в дальнем рейсе с грузом коррозийных веществ, на котором установлены таблички (placards), и только что заехал на зону отдыха, чтобы зайти в туалет. Грузовик работал исправно с момента предрейсового осмотра, и шины выглядели хорошо, когда я выезжал. Прежде чем снова выехать на шоссе, что мне следует сделать с шинами?","options":["Ничего — тщательная предрейсовая проверка шин покрывает меня на весь рейс, пока какая-нибудь шина действительно не спустит","Осмотреть шины сейчас, поскольку я должен проверять их в начале рейса и затем каждые 2 часа или каждые 100 миль","Проверять их только если загорится сигнальная лампа давления в шинах или я почувствую, что грузовик уводит в сторону","Подождать и осматривать шины раз в сутки — этого достаточно для груза с табличками в дальнем рейсе"],"explanation":"Водитель с грузом опасных материалов, обозначенным табличками, должен проверять шины в начале поездки и на каждой остановке — каждые 2 часа или 100 миль."},"187":{"q":"Я заезжаю на своей цистерне с табличками опасного груза на заправочную станцию, чтобы долить дизель перед следующим участком маршрута. Когда я готовлюсь начать заправку, какой из вариантов описывает, как я обязан обращаться с двигателем и процессом заправки, чтобы соблюсти правила?","options":["Оставить двигатель работать на низких оборотах холостого хода, чтобы пневмосистема оставалась под давлением, и самому держать заправочный пистолет","Заглушить двигатель, зафиксировать пистолет на автоматическом режиме и зайти внутрь оплатить, пока бак наполняется","Заглушить двигатель и держать человека физически у заправочного пистолета, контролируя подачу топлива всё время","Держать двигатель на повышенных холостых оборотах, чтобы запитать перекачивающий насос, при этом у пистолета никто не нужен"],"explanation":"При заправке транспортного средства с табличками двигатель должен быть выключен, а человек должен оставаться у заправочного пистолета, контролируя подачу топлива всё время."},"189":{"q":"Вы перевозите груз с табличками опасности (коррозийная жидкость), когда одна из бочек начинает сильно протекать на обочину шоссе, создавая серьёзную утечку опасного материала. После того как вы предупредили окружающих, удалили людей от места происшествия и не допустили курения, ваш перевозчик поручает вам сделать обязательное уведомление об этом серьёзном инциденте в Национальный центр реагирования (National Response Center). По какому номеру вы звоните, чтобы сообщить о происшествии?","options":["411 — линия справочной службы, чтобы вас соединили с ближайшим подразделением реагирования на опасные материалы","911 — местная линия экстренной помощи, которая полностью выполняет требование об уведомлении Национального центра реагирования","1-800-555-1212 — бесплатная линия, которая направляет сообщение в соответствующее федеральное ведомство","1-800-424-8802 — линия Национального центра реагирования для сообщения о серьёзных инцидентах с опасными материалами"],"explanation":"О серьёзных инцидентах с опасными материалами необходимо сообщать в Национальный центр реагирования по номеру 1-800-424-8802."},"190":{"q":"Бочка на моём прицепе с табличками опасного груза начинает протекать едкой (коррозийной) жидкостью на удалённой обочине, и я понятия не имею, что делать с этим химикатом и как его нейтрализовать. После того как я предупрежу окружающих и не подпущу людей, по какому номеру мне следует позвонить, чтобы получить круглосуточную экстренную консультацию по обращению с этим конкретным опасным материалом?","options":["1-800-424-9300, экстренная линия CHEMTREC","1-800-275-8777, национальная горячая линия по почте и доставке","1-888-275-8255, федеральная линия отчётов о безопасности на дорогах","1-800-829-1040, информационная линия федерального ведомства"],"explanation":"CHEMTREC работает круглосуточно по номеру 1-800-424-9300 и даёт водителям немедленные технические указания по обращению с опасным материалом при инциденте."},"191":{"q":"Я перевожу груз коррозийных веществ с размещёнными знаками опасности по Техасу, пристегнув ремень безопасности. Инспектор DPS останавливает меня и спрашивает про товаросопроводительные документы на опасный груз. Согласно правилам руководства, где эти документы должны были находиться во время движения?","options":["Запечатаны в водонепроницаемый конверт и хранятся в прицепе вместе с грузом","В пределах моей досягаемости и на виду, лежат поверх остальных моих документов","Застёгнуты в папке с путевым журналом на спальном месте позади водителя","Заперты в бардачке, чтобы они остались в сохранности при взломе кабины"],"explanation":"Во время движения товаросопроводительные документы на опасный груз должны находиться в пределах досягаемости водителя и лежать поверх других бумаг на виду."},"192":{"q":"Я перевожу груз с опасными материалами, на котором установлены таблички, и заезжаю на зону отдыха, чтобы воспользоваться туалетом. Я выйду из кабины на несколько минут с выключенным двигателем. Согласно правилам Техасского DPS, где должны находиться мои товаросопроводительные документы, пока меня нет в грузовике?","options":["Заперты в бардачке, чтобы никто не смог их трогать, пока меня нет","Сложены в нагрудный карман рубашки и взяты со мной в зону отдыха","Оставлены на виду на водительском сиденье или в кармане водительской двери","Убраны в боковой грузовой отсек рядом с Руководством по действиям в чрезвычайных ситуациях (ERG)"],"explanation":"Когда водитель выходит из кабины, товаросопроводительные документы на опасный груз должны оставаться на виду на водительском сиденье или в кармане водительской двери."},"193":{"q":"Я стою на стоянке для отдыха, мой прицеп имеет таблички (плакарды) для легковоспламеняющихся жидкостей класса 3. Рядом с моей машиной несколько водителей разговаривают, и один из них закуривает сигарету. Чтобы соблюсти федеральное правило о курении для моего груза с табличками, на каком минимальном расстоянии все должны держать зажжённую сигарету от моего транспортного средства?","options":["Не менее 5 футов — это та же буферная зона, что требуется при стоянке вдали от проезжей части дороги","Не менее 2 футов, поскольку легковоспламеняющаяся жидкость запечатана внутри цистерны и почти не представляет опасности","Не менее 100 ярдов — это то же расстояние, что соблюдается от взрывчатых веществ, оставленных без присмотра у железнодорожного переезда","Не менее 25 футов от транспортного средства, так как курение запрещено в пределах этого расстояния от легковоспламеняющегося груза"],"explanation":"Курение запрещено в пределах 25 футов от транспортного средства с табличками, перевозящего взрывчатые вещества, окислители или легковоспламеняющиеся грузы."},"194":{"q":"Я новый водитель, которому поручено перевезти груз взрывчатых веществ подкласса 1.1 через Техас. Грузоотправитель завершил классификацию и маркировку груза, а перевозчик назначил рейс. Прежде чем выехать со двора, что из перечисленного я уже должен иметь в ПИСЬМЕННОМ виде в кабине?","options":["Письменный план маршрута поездки плюс товаросопроводительные документы на груз","Подписанный весовой талон с весов и копию чека за топливо","Письменный список радиоканалов, которые я буду слушать по маршруту","Нотариально заверенный прогноз погоды по каждому округу, который я проеду"],"explanation":"Перед перевозкой взрывчатых веществ класса 1.1 водитель обязан иметь письменный план маршрута вместе с грузовыми документами на груз."},"195":{"q":"Я загружаю партию опасного груза с табличками на доке и осматриваю каждую упаковку перед погрузкой в прицеп. Грузоотправитель передаёт мне четыре контейнера. Какой ОДИН из них я обязан отказаться перевозить?","options":["Бочка, плотно запечатанная, без видимых повреждений шва или крышки","Ведро, из трещины у основания которого медленно сочится коррозийное вещество","Коробка с правильно нанесённой маркировкой класса опасности на внешней поверхности","Ящик, надлежащим образом закрытый и соответствующий описанию в моих товарно-транспортных документах"],"explanation":"Водитель обязан отказаться принимать любой груз с опасными материалами, который протекает, например упаковку, из трещины которой сочится продукт."},"196":{"q":"У меня уже есть CDL класса A, и теперь я хочу добавить разрешение H, чтобы перевозить грузы с табличками, например коррозионные вещества. Прежде чем Техасский DPS выдаст это разрешение, какое дополнительное требование я обязан выполнить, которое НЕ требуется для моего базового CDL?","options":["Пройти повторный медосмотр DOT и предоставить обновленную медицинскую справку от врача-эксперта","Сдать отдельный экзамен по вождению на автомобиле-цистерне с табличками опасного груза","Пройти оценку угрозы безопасности TSA, которая включает снятие отпечатков пальцев и проверку биографических данных","Повторно пройти проверку зрения CDL и письменный экзамен на общие знания в DPS"],"explanation":"Для получения отметки на перевозку опасных грузов требуется пройти проверку угроз безопасности TSA, включая снятие отпечатков пальцев и проверку прошлого."},"197":{"q":"Я уже несколько лет имею техасские права CDL с допуском на перевозку опасных грузов (отметка H) и вовремя прохожу каждый медосмотр. Менее опытный водитель говорит мне, что после того, как я получил отметку H, пройдя проверку угрозы безопасности TSA, эта часть удостоверения становится постоянной, и мне больше никогда не придётся к ней возвращаться, пока действуют мои основные права CDL. Какое утверждение о моём допуске на перевозку опасных грузов верно?","options":["Он закрепляется пожизненно, как только пройдена проверка TSA, поэтому никаких дальнейших действий по этой части никогда не требуется.","Он действует только до тех пор, пока я успешно прохожу медосмотр DOT, именно это и определяет действие отметки.","Он переносится автоматически и никогда не истекает, пока действуют мои основные техасские права CDL.","Его необходимо периодически продлевать, что требует прохождения новой проверки угрозы безопасности TSA / проверки биографических данных."],"explanation":"Отметка на перевозку опасных грузов действует ограниченный срок и должна периодически продлеваться путём прохождения новой проверки угроз безопасности TSA."},"198":{"q":"Я перевожу груз с табличками-плакардами (коррозийные вещества), когда выходит из строя клапан и продукт начинает вытекать на обочину. Я достаю из кабины Руководство по реагированию на чрезвычайные ситуации (ERG). В этой ситуации для чего на самом деле предназначено ERG?","options":["Определить опасные свойства вещества и правильные первоначальные действия при разливе, чтобы защитить себя и окружающих","Рассчитать денежную стоимость утраченного груза, чтобы перевозчик мог подать точное страховое требование","Определить самый экономичный по топливу объездной маршрут вокруг места происшествия, чтобы не тратить дизель","Найти ближайшую одобренную гостиницу и зону отдыха, пока я жду бригаду по очистке"],"explanation":"Справочник по аварийному реагированию помогает водителю определить опасности вещества и правильные первоначальные действия при утечке для защиты себя и окружающих."},"199":{"q":"На месте аварии из моей цистерны с табличками-плакардами идёт утечка. Подбегает пожарный и просит меня назвать четырёхзначный идентификационный номер из товаросопроводительных документов. КРОМЕ одного, все приведённые ниже варианты объясняют, зачем ему этот номер. Какой вариант указывает, для чего он действительно ему нужен?","options":["Он сообщает ему стоимость груза в долларах, чтобы он мог оформить претензию перевозчика об ущербе","Он позволяет ему найти материал в Руководстве по экстренному реагированию (ERG) и определить правильные процедуры реагирования","Он подтверждает, что моё разрешение H и проверка TSA действительны для этого груза","Он показывает надлежащее транспортное наименование, чтобы он зачитал его по рации диспетчеру"],"explanation":"Четырёхзначный идентификационный номер UN/NA позволяет спасателю найти вещество в Справочнике по аварийному реагированию и определить правильные процедуры реагирования."},"200":{"q":"Я перевожу груз с табличками-плакардами, когда из-под прицепа начинает валить дым, и я вижу, как пламя распространяется вдоль шин. В кабине у меня есть небольшой огнетушитель, но огонь уже слишком сильный, чтобы я мог безопасно с ним справиться. КРОМЕ одного варианта ниже, каждое из перечисленных действий сделает эту ситуацию более опасной. Какое действие мне действительно следует предпринять?","options":["Открыть грузовые двери, чтобы точно увидеть, какие бочки горят, и описать их спасателям","Схватить огнетушитель и продолжать тушить пожар самому, пока он полностью не погаснет или не приедет помощь","Держать посторонних на большом расстоянии, оставаться с наветренной стороны и немедленно вызвать аварийно-спасательные службы","Доехать на горящем тягаче до ближайшего города, чтобы тамошним пожарным было ближе добираться до меня"],"explanation":"Когда маркированный опасный груз горит и вы не можете справиться, удерживайте людей подальше, оставайтесь с наветренной стороны и немедленно вызывайте спасателей."},"201":{"q":"Вы перевозите груз опасных материалов с размещёнными табличками (placards), и навигатор ведёт вас прямо через длинный шоссейный тоннель, что сэкономит почти час. Вы не уверены, разрешён ли ваш материал в этом тоннеле. Что вы должны сделать В ПЕРВУЮ ОЧЕРЕДЬ, прежде чем подъедете к въезду в тоннель?","options":["Снизить скорость и держать обе полосы свободными, чтобы быстро и безопасно проехать через тоннель","Снять таблички перед въездом, чтобы дежурные по тоннелю не остановили вас внутри","Остановиться сразу за въездом в тоннель и позвонить перевозчику, чтобы спросить, можно ли продолжать движение","Проверить правила установленного маршрута, поскольку некоторые опасные материалы запрещены в тоннелях и может потребоваться другой маршрут"],"explanation":"Некоторые опасные материалы запрещены в туннелях, поэтому водитель должен сначала проверить правила установленного маршрута, так как может потребоваться другой путь."},"202":{"q":"Перевозчик только что выдал мне письменный план безопасности перед рейсом с плакардированным опасным грузом и попросил соблюдать его процедуры по защите грузовых документов, проверке маршрута и ограничению несанкционированного доступа к прицепу. С точки зрения Департамента общественной безопасности Техаса (DPS), какова ОСНОВНАЯ цель этого плана безопасности?","options":["Снизить вероятность того, что опасные материалы будут украдены или использованы не по назначению посторонними лицами","Ускорить погрузку и разгрузку, чтобы доставка прибыла раньше запланированного срока","Снизить расход топлива за счёт прокладки кратчайшего возможного маршрута между остановками","Сохранить грузовой отсек в чистоте, чтобы материалы не были загрязнены во время перевозки"],"explanation":"План безопасности при перевозке опасных грузов существует, чтобы снизить риск кражи или неправомерного использования опасных материалов посторонними лицами."},"203":{"q":"Я перевожу груз коррозийных веществ с табличками-плакардами через незнакомый город и накануне вечером останавливаюсь, чтобы спланировать маршрут. Согласно Руководству CDL штата Техас, какова ГЛАВНАЯ причина, по которой заблаговременное планирование маршрута так важно для водителя, перевозящего опасные грузы?","options":["Это позволяет мне пропустить проверки шин в пути, потому что я уже знаю, сколько займёт поездка","Это помогает мне выявить запретные зоны, где мой груз с плакардами запрещён, и объехать их","Это позволяет мне снимать плакарды на участках открытого шоссе, чтобы экономить топливо","Это гарантирует, что я найду самые дешёвые заправки и места для отдыха по пути"],"explanation":"Заблаговременное планирование маршрута помогает водителю выявлять и избегать запретных зон, где маркированный груз запрещён."},"204":{"q":"Я загружаю прицеп на грузовом терминале, и в моей накладной указано несколько паллет взрывчатых веществ класса 1 (подкласс 1.1), а также другие опасные грузы, ожидающие на погрузочной площадке. Прежде чем разрешить бригаде сложить всё вместе, чем я должен руководствоваться при решении, какие продукты можно везти в одном грузе со взрывчатыми веществами?","options":["Взрывчатые вещества можно везти с любым классом опасности при условии, что каждая паллета отдельно закреплена и зафиксирована, чтобы не сместиться в пути","Взрывчатые вещества можно грузить с чем угодно, если общий вес груза не превышает порог в 1 001 фунт для размещения табличек на прицепе","Таблица сегрегации (погрузки/разгрузки) запрещает грузить взрывчатые вещества вместе с определёнными другими опасными материалами, поэтому я обязан свериться с ней перед объединением грузов","Взрывчатые вещества должны грузиться полностью отдельно и никогда не могут делить прицеп ни с каким другим грузом"],"explanation":"Перед совмещением взрывчатых веществ с другими опасными грузами всегда сверяйтесь с таблицей сегрегации (погрузки/разгрузки), так как некоторые продукты запрещено грузить вместе."},"205":{"q":"Я нахожусь на погрузочной платформе и собираюсь вручную загрузить в прицеп несколько бочек и вёдер с коррозийной жидкостью класса 8. Работник дока спрашивает, как разместить каждую ёмкость перед тем, как мы закрепим их ремнями. Чтобы упаковать груз безопасно и жидкость осталась герметично закрытой внутри, как должна стоять каждая ёмкость?","options":["Лёжа на боку, чтобы бочки плотно прилегали друг к другу и меньше смещались в пути","Отверстиями вниз, чтобы любая просочившаяся жидкость стекала от крышки","Этикетками опасности к стенке, чтобы они не поцарапались","Вертикально, отверстиями вверх, чтобы крышки оставались выше уровня жидкости"],"explanation":"Грузите жидкие опасные грузы вертикально, отверстиями вверх, чтобы закрытия оставались выше уровня жидкости и уплотнения не подтекали."},"206":{"q":"Я вручную загружаю прицеп коробками с коррозионным материалом (класс 8), и докер протягивает мне металлический грузовой крюк, чтобы быстрее затаскивать тяжёлые ящики на место. Прежде чем взяться за что-либо, какое правило должно остановить меня от использования этого крюка на этих упаковках?","options":["Я не должен использовать крюк или любой инструмент, который может проколоть, порвать или иным образом повредить упаковки с опасным грузом","Я могу свободно пользоваться крюком, пока держу коробки вертикально, а этикетки обращены наружу","Крюки разрешены для класса 8 только после того, как я размещу таблички на всех четырёх сторонах прицепа","Крюки разрешены только если я проверю шины в течение первых 100 миль после загрузки"],"explanation":"Никогда не используйте крюк или любой инструмент, который может проколоть, порвать или повредить упаковку опасных грузов, так как нарушение целостности приведёт к утечке содержимого."},"207":{"q":"Я загружаю баллоны со сжатым газом (класс 2) в свой прицеп жарким днём. Чтобы поступить с ними правильно по правилам, что мне следует сделать с этими баллонами перед началом движения?","options":["Положить их свободно, чтобы они сами улеглись и могли смещаться по мере того, как груз устаканивается в пути","Надёжно закрепить их, чтобы они не могли двигаться, и держать их защищёнными от источников тепла","Поставить их вертикально с приоткрытыми вентилями, чтобы внутреннее давление медленно стравливалось","Сложить их высоко у тёплой стенки прицепа и подклинить только нижний ряд"],"explanation":"Закрепляйте баллоны со сжатым газом так, чтобы они не смещались и не падали, и держите их вдали от источников тепла, поскольку нагрев повышает внутреннее давление и может вызвать разрыв."},"208":{"q":"Я устанавливаю таблички-знаки опасности на цистерну перед рейсом по Техасу и замечаю две таблички: большую основную для главного класса опасности и меньшую вторую табличку без номера класса внизу. Мой инструктор называет вторую 'дополнительной' (subsidiary) табличкой. О чём она сообщает по поводу этого груза?","options":["Она подтверждает прежнюю, 'старую' классификацию, которую грузоотправитель использовал до перезагрузки груза","Она указывает, что цистерна пуста и внутри остался только осадок","Она предупреждает о дополнительной опасности материала помимо его основного класса опасности","Она обозначает текущий уровень топлива, чтобы спасатели знали, сколько продукта на борту"],"explanation":"Дополнительный плакат предупреждает о дополнительной опасности, которую несёт груз помимо его основного класса опасности."},"209":{"q":"Я готовлюсь перевозить груз коррозийных веществ с размещёнными табличками (placards), и грузоотправитель выдаёт мне транспортные документы, в которых вверху указан телефонный номер для экстренного реагирования. Прежде чем я подпишу документы и выеду, какому требованию должен соответствовать этот номер экстренного реагирования?","options":["Он должен быть доступен только в обычные рабочие часы грузоотправителя по будням","Он может переключаться на голосовую почту с записью, если кто-то перезвонит позже","Допускается, чтобы это был личный мобильный номер водителя, указанного в документах","Это должен быть номер, который укомплектован персоналом и контролируется постоянно, пока опасный груз находится в пути"],"explanation":"Номер телефона экстренной службы в транспортных документах должен обслуживаться и контролироваться постоянно, пока опасный груз находится в пути."},"210":{"q":"Вы перевозите груз с маркировкой (плакардами) едких/коррозийных веществ, когда выходит из строя соединение, и лужа начинает растекаться из-под прицепа на обочину двухполосного шоссе. Другие машины по-прежнему проезжают близко. После того как вы полностью съехали с проезжей части, что является вашим ПЕРВЫМ приоритетом, прежде чем делать что-либо еще?","options":["Не подпускать посторонних к месту утечки и предупреждать приближающийся транспорт об опасности","Смыть пролитое вещество с асфальта, чтобы оно перестало растекаться вниз по склону","Снять или закрыть плакарды, чтобы любопытные зеваки не паниковали из-за груза","Вернуться в кабину и доехать до ближайшего съезда, чтобы быстрее освободить место происшествия"],"explanation":"При инциденте с опасным грузом первая обязанность водителя — не подпускать людей к месту утечки и предупреждать приближающийся транспорт об опасности."},"211":{"q":"Я заехал на зону отдыха с грузом, имеющим табличку (placard), и хочу выйти покурить. Рядом с чем из перечисленного мне категорически НЕЛЬЗЯ закуривать?","options":["Рядом с пустым, полностью продутым прицепом, который я только что отцепил","Рядом с прицепом, на котором табличка легковоспламеняющейся жидкости","Рядом с легковым автомобилем, припаркованным на соседнем месте","Рядом с чистой, выметенной кабиной моего тягача"],"explanation":"Никогда не курите ближе 25 футов от транспортного средства с плакатом легковоспламеняющихся веществ, так как пары могут воспламениться от открытого огня или зажжённой сигареты."},"212":{"q":"Ваш автоцистерна с табличками опасного груза, перевозящая легковоспламеняющуюся жидкость, складывается \"домиком\" на загородной двухполосной дороге, и вы чувствуете сильный химический запах, скапливающийся возле прицепа. Двое водителей остановились и идут к месту аварии, один прикуривает сигарету. Какое действие вам следует предпринять ПЕРВЫМ?","options":["Залезть обратно в кабину и убрать прицеп с проезжей части, пока утечка не распространилась","Собрать сопроводительные документы и Аварийное руководство (ERG) и начать устранять разлив","Держать посторонних на безопасном расстоянии, не допускать курения и уведомить аварийные службы и CHEMTREC","Выставить горящие сигнальные факелы позади места аварии, чтобы предупредить приближающийся транспорт об опасности"],"explanation":"После аварии с опасным грузом держите посторонних на безопасном расстоянии, не допускайте курения и немедленно уведомите аварийные службы и CHEMTREC."},"213":{"q":"Я провожу предрейсовый осмотр прицепа с табличками опасности на стоянке в Ларедо и замечаю, что задняя табличка сильно выцвела, а одна на правой стороне частично закрыта кронштейном брызговика. Мой напарник говорит, что всё в порядке, пока передняя и задняя таблички чистые, ведь именно их видят встречный транспорт и полицейский позади меня. Согласно правилам DPS по размещению табличек, какое утверждение верно?","options":["Твой напарник прав, что важны только передняя и задняя таблички, ведь они обращены туда, откуда приближаются другие водители, так что выцветшую боковую можно не трогать перед поездкой.","Это допустимо, пока хотя бы одна табличка на машине остаётся полностью читаемой снаружи кабины, так что одной чистой передней таблички хватило бы, чтобы выехать сегодня.","Таблички должны быть чётко видны лишь водителю изнутри кабины, чтобы подтвердить маркировку груза, так что внешнее выцветание или загораживание значения перед поездкой не имеет.","Все четыре таблички должны присутствовать и быть читаемы со стороны, в которую обращена каждая, поэтому выцветшую заднюю и частично скрытую боковую нужно исправить перед поездкой."],"explanation":"Плакаты обязательны со всех четырёх сторон, и каждый должен быть читаем со стороны, в которую он обращён, поэтому любой выцветший или закрытый плакат нужно исправить до начала движения."},"214":{"q":"Я провожу предрейсовый осмотр груза с табличками-плакардами и хочу убедиться, что плакарды установлены так, как требуют правила. Не обращая внимания на нанесённый внутри символ и номер класса, какую общую форму должен иметь каждый правильно размещённый плакард на боку моего прицепа?","options":["Квадрат, поставленный на один из своих углов, так что он выглядит как ромб с вершиной, направленной вверх","Квадрат, стоящий ровно на одной из своих прямых сторон, как панель дорожного знака","Круглый диск, чтобы предупреждение было видно со всех сторон","Треугольник вершиной вверх, как светоотражающие предупреждающие устройства в моём наборе"],"explanation":"Знак опасности — это квадрат, повёрнутый на 45 градусов и поставленный на угол, образуя ромб с вершиной вверх."},"215":{"q":"Я загружаю партию опасных грузов с табличками и перепроверяю, что каждая упаковка правильно промаркирована, прежде чем поставить подпись. Помимо надлежащего транспортного наименования, напечатанного на упаковке, какая ещё информация обязательно должна присутствовать в маркировке упаковки?","options":["Моё имя как водителя, принявшего груз","Идентификационный номер (UN/NA) материала","Цветовой код, совпадающий с табличкой на прицепе","Тип топлива, на котором работает тягач перевозчика"],"explanation":"На маркировке упаковки должен быть указан идентификационный номер материала (UN/NA) вместе с правильным транспортным наименованием."},"216":{"q":"Перед выездом из терминала я проверяю транспортные документы на груз и замечаю буквы \"RQ\", вписанные в колонку HM прямо рядом с одним из перечисленных материалов. Прежде чем подписать документы и положить их в зоне досягаемости, что именно эта пометка \"RQ\" сообщает мне об этой записи?","options":["Она указывает рекомендованный маршрут с малым трафиком, по которому мне следует ехать, чтобы держать этот материал подальше от населённых районов","Она подтверждает, что грузоотправитель перепроверил упаковку и удостоверил её отсутствие утечек для погрузки","Она сигнализирует, что материал присутствует в нормативно установленном количестве, подлежащем отчётности, поэтому о его разливе необходимо сообщать","Она означает, что запись проверена и одобрена, поэтому я могу переместить её в самый низ моих документов"],"explanation":"\"RQ\" означает «отчётное количество» (Reportable Quantity), то есть материал присутствует в объёме, при разливе которого утечку необходимо сообщить."},"217":{"q":"Я загружаю смешанную партию груза, и начальник погрузочной платформы передаёт мне несколько упаковок с маркировкой Класс 6 (Подкласс 6.1) — яд. У меня пустой прицеп, и мне нужно решить, куда поместить эти упаковки относительно остального груза. Чтобы загрузить этот яд безопасно и в соответствии с законом, от чего я обязан держать его абсолютно подальше?","options":["Светоотражающие аварийные треугольники, которые я вожу на случай ЧП","Огнетушитель, закреплённый рядом с грузовыми дверями","Запасное колесо, хранящееся под кузовом прицепа","Любые продукты питания, пищевые товары или съедобные изделия в грузе"],"explanation":"Ядовитые материалы (подкласс 6.1) нельзя грузить вместе с любыми продуктами питания, пищевыми или съедобными товарами или рядом с ними во избежание заражения."},"218":{"q":"Я перевожу груз с табличками-плакардами класса 5 (окислители), когда рядом с прицепом начинается небольшой электрический пожар. Оценивая ситуацию, почему особенно срочно держать этот материал подальше от любого огня?","options":["Окислители выделяют кислород, поэтому они заставят огонь гореть жарче и интенсивнее","Окислители задушат и погасят пламя, но выделяемые при этом пары токсичны","Окислители замерзают при контакте с теплом, что может треснуть прицеп и пролить груз","Окислители безвредны рядом с огнём, но сами таблички-плакарды легко воспламеняются"],"explanation":"Окислители выделяют кислород, который питает огонь, заставляя его гореть жарче и интенсивнее."},"219":{"q":"Я перевожу груз легковоспламеняющейся жидкости класса 3 с табличками опасности, и в товарно-транспортной накладной указана температура вспышки этого вещества. Во время предрейсовой проверки безопасности мой инструктор спрашивает, что именно это значение температуры вспышки говорит мне об этом грузе. Какое утверждение верно описывает, на что указывает температура вспышки?","options":["Это температура, при которой жидкость замерзает и перестаёт плескаться в цистерне","Это наименьшая температура, при которой жидкость выделяет достаточно паров для образования воспламеняющейся смеси","Это температура, при которой жидкость самовоспламеняется без искры или открытого пламени","Это температура, при которой жидкость расширяется настолько, что начинает вытекать из ёмкости"],"explanation":"Температура вспышки — это самая низкая температура, при которой жидкость выделяет достаточно паров для образования воспламеняемой смеси."},"220":{"q":"Я везу автоцистерну для сыпучих грузов, загруженную цементным порошком, и приближаюсь к съезду-клеверу с указанной на знаке кривой. С учётом того, как ведёт себя такой груз, какой фактор должен в наибольшей степени определять, как я прохожу этот поворот?","options":["Груз лежит низко и осел, поэтому я могу пройти поворот на указанной скоростной скорости без изменений","Цистерна оснащена перегородками, как у наливной, поэтому переплеск полностью под контролем и важен лишь тормозной путь","Груз располагается высоко и смещается при движении машины, поэтому я должен сбросить скорость заранее перед поворотом и рулить плавно","Порошок плотно слёживается при движении, поэтому резкие повороты руля внутри кривой абсолютно безопасны"],"explanation":"Цистерны для сыпучих грузов имеют высокий центр тяжести и смещающийся груз, поэтому снижайте скорость задолго до поворота и рулите плавно."},"222":{"q":"Я только что принял груз, который должен быть обозначен табличками (плакардами) со всех четырёх сторон, и диспетчер перевозчика торопит меня с выездом. Прежде чем покинуть площадку, какой документ я должен иметь лично, чтобы законно управлять этим грузом с плакардами?","options":["Действующую медицинскую справку (сертификат медэксперта DOT), которая сама по себе даёт право перевозить любой груз с плакардами","Разрешение на цистерну (N), так как грузы с плакардами всегда перевозятся в наливных цистернах","Ничего дополнительного в правах, потому что грузоотправитель уже подготовил документы и установил плакарды","Действующее разрешение на опасные грузы HazMat (H), полученное после проверки TSA с проверкой биографии и снятием отпечатков пальцев"],"explanation":"Для перевозки груза с табличками опасности требуется действующее свидетельство на опасные грузы (H), получаемое после проверки TSA и снятия отпечатков пальцев."},"223":{"q":"Я перевожу маркированный груз коррозийных веществ и хочу правильно подготовить транспортные документы перед выездом. Я трачу несколько минут, чтобы пометить закладками и четко отметить записи об опасных грузах. Когда инспектор или спасатель попросит их, в чем главный смысл такой маркировки и пометки документов?","options":["Чтобы документы на опасный груз можно было быстро и легко найти при аварии или проверке","Чтобы документы на опасный груз оставались сложенными и убранными из виду до момента, пока их специально не запросят","Чтобы записи об опасном грузе были отделены и отложены в сторону от остальной документации по грузу","Чтобы документы на опасный груз можно было выбросить после завершения и подписания доставки"],"explanation":"Транспортные документы на опасные грузы должны иметь закладки или пометки, чтобы их можно было быстро и легко найти при аварии или проверке."},"224":{"q":"Вы перевозите груз коррозийных веществ с размещёнными табличками (плакардами), когда соединение разрушается и материал начинает вытекать на обочину оживлённого шоссе. Рядом с вашим прицепом начинают собираться прохожие. Какое из перечисленных действий должно стать вашим ПЕРВЫМ приоритетом прежде всего остального?","options":["Достать товарно-транспортные документы и позвонить в CHEMTREC, чтобы сообщить точное наименование и количество вещества","Держаться в стороне от утечки и отвести прохожих подальше, чтобы защитить всех от воздействия вещества","Открыть Руководство по аварийному реагированию (ERG) и найти процедуру ликвидации разлива по этому идентификационному номеру","Связаться со своим перевозчиком, чтобы компания подала властям требуемый отчёт об инциденте"],"explanation":"При любом происшествии с опасными грузами в первую очередь защитите жизни: держитесь подальше от утечки и уведите посторонних от зоны воздействия."},"225":{"q":"Вы подаёте свой автоцистерну к наливной эстакаде для загрузки легковоспламеняющейся жидкости. Прежде чем продукт начнёт поступать в цистерну, какой шаг НАИБОЛЕЕ важен для предотвращения искры статического электричества, способной воспламенить пары?","options":["Оставить двигатель работающим на холостом ходу, чтобы генератор питал датчики уровня в цистерне во время налива","Расставить светоотражающие аварийные треугольники вокруг наливной эстакады на случай приближения других машин","Соединить (выровнять потенциалы) цистерну с наливным оборудованием и заземлить обе части до открытия наливной линии","Заранее открыть верхний люк, чтобы скопившиеся пары вышли и снизили давление внутри"],"explanation":"Соединение и заземление перед открытием наливной линии отводят статическое электричество, возникающее при перекачке горючей жидкости, предотвращая искру и воспламенение паров."},"227":{"q":"Я перевожу груз с табличками (плакардами), который требует постоянного присмотра, и припарковался на специально отведённой стоянке на ночь. Мой сменный водитель соглашается остаться с транспортным средством в качестве сопровождающего, пока я отдыхаю в мотеле неподалёку. Что из перечисленного лучше всего описывает, как мой сменный водитель должен выполнять эту обязанность по присмотру, чтобы она считалась выполненной?","options":["Он может вздремнуть в спальном отсеке, пока находится в пределах 100 футов от груза","Он может сидеть в закрытом ресторане на другом конце стоянки, ведь он всё равно видит прицеп","Он может ненадолго отлучиться, чтобы заправить свою личную машину, если рядом никого нет","Он должен оставаться бодрствующим и внимательным, в пределах 100 футов от транспортного средства и с беспрепятственным обзором на него"],"explanation":"Сопровождающий груз с табличками опасности должен бодрствовать и быть начеку, находиться в пределах 100 футов от транспортного средства и иметь беспрепятственный обзор."},"228":{"q":"Я перевожу груз легковоспламеняющейся жидкости с табличками опасности (плакардами) в дальнем рейсе по межштатной автомагистрали и только что закончил предрейсовую проверку шин перед выездом с терминала. Чтобы соблюсти правило проверки в пути, как часто я должен останавливаться, чтобы повторно проверять шины во время рейса?","options":["Не реже чем каждые 2 часа или каждые 100 миль, в зависимости от того, что наступит раньше","Не реже чем каждые 100 миль, но правило 2 часов перестаёт действовать, как только я выехал на автомагистраль","Не реже чем каждые 3 часа или каждые 150 миль, в зависимости от того, что наступит раньше","Только когда я останавливаюсь для дозаправки или на обязательный 30-минутный перерыв"],"explanation":"При перевозке груза с табличками опасности шины нужно проверять в пути не реже чем каждые 2 часа или каждые 100 миль, в зависимости от того, что наступит раньше."},"229":{"q":"Я первым прибыл на место опрокидывания транспортного средства с грузом, обозначенным табличками. Диспетчер не может разглядеть надлежащее транспортное наименование сквозь дым, но по рации передаёт мне 4-значный идентификационный номер ООН, нанесённый по трафарету на упаковку. Чтобы БЫСТРЕЕ всего найти информацию об аварийном реагировании, используя только этот номер, к какому разделу ERG мне следует обратиться?","options":["Страницы с оранжевой каймой — руководства, где материалы сгруппированы по присвоенному цвету опасности","Страницы с жёлтой каймой, где материалы перечислены в числовом порядке по идентификационному номеру","Страницы с синей каймой, где материалы перечислены по алфавиту по транспортному наименованию","Страницы с белой каймой, где материалы перечислены по массе и количеству упаковки"],"explanation":"Страницы ERG с жёлтой рамкой перечисляют материалы в числовом порядке по идентификационному номеру, поэтому они быстрее всего, когда известен только 4-значный ID-номер."},"230":{"q":"Я на месте утечки моего груза с размещенными табличками (placard). Грузовые документы уничтожены, поэтому у меня нет идентификационного номера UN/NA, но на контейнере четко выгравировано слово \"ХЛОР\" (CHLORINE). Чтобы быстро найти этот материал на страницах ERG с синей рамкой, на что я опираюсь при поиске записи?","options":["Четырехзначный идентификационный номер UN/NA, выгравированный на контейнере","Номер класса опасности, указанный на табличке (placard) на цистерне","Надлежащее отгрузочное наименование материала, перечисленное в алфавитном порядке","Цветовой код DOT, напечатанный на этикетке упаковки"],"explanation":"Страницы ERG с синей рамкой перечисляют материалы в алфавитном порядке по надлежащему транспортному наименованию, поэтому их используют, когда известно название, но не ID-номер."},"231":{"q":"Я перевожу груз с коррозийными веществами, имеющий таблички (плакарды), и в этот момент отказывает сцепное устройство, после чего продукт начинает вытекать на обочину. Я беру свой Справочник по реагированию на чрезвычайные ситуации (ERG), нахожу идентификационный номер вещества и должен узнать, как защитить людей и безопасно действовать на месте. К какому разделу ERG мне следует обратиться за этой информацией?","options":["К страницам с синей рамкой, потому что руководства по ответным действиям для каждого вещества расположены там по алфавиту согласно надлежащему транспортному наименованию","К страницам с зелёной рамкой, потому что в них указаны расстояния для защитных действий и точно описано, как обращаться с утечкой","К страницам с жёлтой рамкой, потому что пронумерованные руководства, описывающие, что делать на месте, индексированы там по номеру UN/NA","К страницам с оранжевой рамкой, потому что в них содержатся пронумерованные руководства по ответным действиям, объясняющие, как защитить людей и взять ситуацию под контроль"],"explanation":"Страницы ERG с оранжевой рамкой содержат пронумерованные руководства по реагированию, описывающие опасности и меры безопасности для защиты людей и контроля инцидента."},"232":{"q":"Идущая впереди меня автоцистерна перевернулась, и из неё вытекает ядовитый газ. Пока я звоню в CHEMTREC, я открываю Аварийное руководство (ERG) на страницах с зелёной рамкой, чтобы решить, куда отвести людей. Какую информацию должны давать эти зелёные страницы?","options":["Начальные расстояния изоляции и защитных действий, показывающие, насколько далеко эвакуировать людей и держать их в стороне от места утечки","Список надлежащих транспортных наименований, сопоставленных с их четырёхзначными идентификационными номерами UN/NA","Общее руководство по реагированию с описанием действий при пожаре, разливе и оказании первой помощи для номера руководства данного вещества","Телефоны CHEMTREC и экстренных служб, по которым следует звонить за технической помощью во время инцидента"],"explanation":"Страницы ERG с зелёной рамкой дают расстояния начальной изоляции и защитных действий, указывающие, на какое расстояние эвакуировать и удерживать людей от утечки."},"233":{"q":"Я загружаю прицеп на терминале, и начальник погрузочной площадки выдаёт мне товарно-транспортные документы, в которых рядом с подразделом класса опасности у одной из позиций напечатана буква (буква \"группы совместимости\"). Он говорит, что эта буква указывает, какие другие предметы того же класса опасности можно или нельзя грузить вместе в одном транспортном средстве. Исходя из правил перевозки опасных грузов, к какому классу материалов относится эта буква группы совместимости?","options":["Класс 8, коррозионные вещества, чтобы кислоты и щёлочи не вступали в реакцию друг с другом в прицепе","Класс 1, взрывчатые вещества, чтобы определить, какие подразделы и типы можно грузить и перевозить вместе","Класс 2, газы, чтобы отделить горючие газы от ядовитых газов при погрузке","Класс 7, радиоактивные материалы, чтобы суммарный транспортный индекс не превышал предел для одного транспортного средства"],"explanation":"Буквы группы совместимости относятся только к классу 1 «Взрывчатые вещества» и показывают, какие подклассы и типы взрывчатых веществ можно безопасно загружать и перевозить вместе."},"234":{"q":"Я готовлю транспортные документы на груз, требующий размещения знаков опасности, и замечаю, что в одной записи идентификационный номер начинается с букв «NA», а не «UN». Новичок спрашивает меня, что этот префикс говорит о том, где этот номер действителен. Что из перечисленного будет правильным ответом?","options":["Это международно согласованный номер, признаваемый для перевозок по всей Европе и Азии","Это означает, что груз можно перевозить только по специальным экспортным зарубежным маршрутам, но не внутри страны","Это идентификационный номер, присвоенный для использования в Северной Америке, включая США и Канаду","Это означает «Не применимо», поэтому для этой строки не требуется ни класс опасности, ни правильное транспортное наименование"],"explanation":"Префикс «NA» обозначает идентификационный номер, присвоенный для использования только в Северной Америке, а именно в США и Канаде."},"235":{"q":"Я перевожу маркированный плакатами груз легковоспламеняющейся жидкости из Хьюстона в порт для экспорта за океан, и в моих перевозочных документах материал указан с надлежащим транспортным наименованием, классом опасности и идентификационным номером 'UN'. Едущий со мной новый водитель утверждает, что этот номер 'UN' важен только здесь, в Техасе, и его можно игнорировать, как только груз покинет штат. Какое утверждение об этом идентификационном номере 'UN' является верным?","options":["Номер 'UN' применяется только в пределах Техаса, поэтому новый водитель прав: за границей штата он перестаёт иметь значение","Номер 'UN' действителен только для грузов, перевозимых морем, поэтому он начинает применяться, когда груз достигает порта","Номер 'UN' действителен только для грузов, перевозимых по воздуху, поэтому для этого грузовика нужен другой код","Номер 'UN' признан на международном уровне, поэтому он идентифицирует материал одинаково независимо от того, куда движется груз"],"explanation":"Идентификационный номер «UN» признан на международном уровне, поэтому он обозначает материал одинаково, куда бы ни перевозился груз."},"236":{"q":"Я провожу предрейсовый осмотр и замечаю на одной из упаковок ромбовидную этикетку, которую не узнаю. Чтобы подтвердить, что она обозначает ядовитый (токсичный) материал, прежде чем принять груз, какой символ на этой этикетке мне следует искать?","options":["Череп и скрещённые кости внутри ромба","Символ пламени над номером класса опасности","Чёрный горящий шар с лучами внутри ромба","Трёхлопастный символ-трилистник в виде пропеллера"],"explanation":"Ядовитый или токсичный материал (подкласс 6.1) обозначается символом черепа со скрещёнными костями внутри ромбовидного знака."},"237":{"q":"Я осматриваю груз на погрузочной площадке и беру упаковку с желто-белой ромбовидной этикеткой опасности класса 7. Чтобы подтвердить содержимое перед тем, как расписаться за груз, я изучаю надпись внутри ромба. Какое одно слово, напечатанное на этой ромбовидной этикетке, подтверждает, что это груз класса 7?","options":["ХРУПКОЕ (FRAGILE), потому что в упаковке находятся хрупкие герметичные контейнеры с источником, которые могут разбиться","РАДИОАКТИВНО (RADIOACTIVE), потому что напечатанное слово на ромбовидной этикетке класса 7 прямо указывает на опасность","ЕДКОЕ (CORROSIVE), потому что герметичные источники класса 7 хранятся в кислотостойких внешних оболочках","ОКИСЛИТЕЛЬ (OXIDIZER), потому что радиоактивный материал выделяет энергию, способную поддерживать горение"],"explanation":"На этикетке класса 7 внутри ромба напечатано слово RADIOACTIVE, которое прямо указывает класс опасности."},"238":{"q":"Жарким техасским днём я стою на наливной эстакаде и заполняю свою автоцистерну бензином, и оператор спрашивает, до какого уровня поднять продукт, прежде чем выключить насос. Как нужно загрузить эту цистерну, чтобы безопасно и законно перевозить эту легковоспламеняющуюся жидкость?","options":["Залить до самого верха, чтобы жидкость не плескалась и не билась о перегородки во время торможения","Заполнить только до половины, поскольку цистерну с легковоспламеняющейся жидкостью по закону нельзя заполнять более чем на 50 процентов","Не доливать до полного, чтобы оставалось свободное пространство для расширения продукта при нагреве в пути","Залить полностью до краёв, затем загерметизировать с правильной табличкой опасности на горловине, чтобы это считалось полной загрузкой"],"explanation":"Цистерну с легковоспламеняющейся жидкостью нельзя заполнять полностью, так как жидкость расширяется при нагреве и нуждается в свободном пространстве."},"239":{"q":"Рано холодным утром я загружаю автоцистерну легковоспламеняющейся жидкостью и планирую ехать на юг в гораздо более теплую погоду по мере того, как день становится жарче. Чтобы решить, насколько полно я могу безопасно наполнить цистерну, какой факт о грузе должен определять мое решение?","options":["Я могу заполнить цистерну полностью до верха, потому что жидкость сжимается и занимает меньше места по мере повышения наружной температуры в течение дня","Уровень наполнения не имеет значения для жидкостей, потому что только сжатые газы меняют объем при изменении температуры вокруг цистерны","Мне следует долить ее сейчас, пока холодно, потому что более холодная жидкость расширяется и переполнила бы цистерну, если бы я подождал до полудня","Я должен оставить пустое пространство (недолив) в цистерне, потому что жидкость будет расширяться при нагревании и ей нужно место, чтобы не переполниться"],"explanation":"Оставьте свободное пространство в цистерне, потому что жидкость расширяется при нагреве и нуждается в месте, чтобы не перелиться."},"240":{"q":"Я загружаю на доке две коробки с маркированным опасным грузом (HazMat), и в документах грузоотправителя есть предупреждение, что эти два материала могут опасно прореагировать при контакте друг с другом. Прицеп заполнен наполовину, и я хочу закончить побыстрее. Как мне безопасно загрузить эту партию груза?","options":["Загрузить оба материала так, чтобы они были отделены друг от друга в прицепе","Загрузить оба материала рядом, чтобы их было удобно выгружать вместе","Перемешать рассыпной продукт из обеих упаковок, чтобы он равномерно осел при перевозке","Уложить оба материала плотно вплотную, чтобы ни один не смещался в пути"],"explanation":"Два опасных груза, которые могут реагировать друг с другом, должны загружаться так, чтобы они были разделены в прицепе."},"241":{"q":"Я нахожусь на погрузочной платформе и готовлюсь загрузить опасный груз, требующий табличек (placards). Перед погрузкой груза я провожу финальный обход. Оценивая, в каком состоянии должно находиться оборудование ДО того, как любой опасный груз будет загружен в мой прицеп, что из перечисленного обязательно должно быть верным?","options":["Я могу грузить сейчас, а проверку регулировки тормозов и работы фонарей выполнить на первой проверке шин через 2 часа в пути","Тормоза и фонари должны быть уже проверены и подтверждены как полностью исправные до того, как будет загружен любой опасный груз","Должны работать только рабочие тормоза прицепа; фонари можно проверить позже, ведь погрузка идёт днём на платформе","Тормоза и фонари важны только после установки табличек, поэтому я могу сначала загрузить, а проверить после размещения табличек"],"explanation":"Тормоза и фонари должны быть проверены и подтверждены в исправном состоянии до загрузки любого опасного груза."},"242":{"q":"Я вручную загружаю поддон с упаковками коррозийного вещества на погрузочной площадке грузоотправителя, и несколько коробок тяжёлые и неудобные для захвата. Чтобы обращаться с ними безопасно и не повредить тару, за какую часть каждой упаковки мне следует браться, чтобы поднимать и перемещать её?","options":["Браться за напечатанные знаки опасности, ведь эти панели усилены и выдерживают нагрузку при переноске","Тянуть за отклеившиеся проклеенные клапаны или обвязку, ведь они дают самый надёжный захват коробки","Поднимать за прочную, крепкую часть упаковки, ни в коем случае не за слабые места или знаки","Волочить по площадке за ближайший край, ведь коррозийное вещество устойчиво к потёртостям"],"explanation":"Поднимайте упаковки с опасным грузом за прочную, надёжную часть, а не за слабые места или этикетки, чтобы сохранить целостность тары."},"243":{"q":"Меня только что приняли на работу для перевозки опасных грузов с табличками, и диспетчер вручает мне толстую папку с внутренними правилами компании по погрузке и маршрутам. Читая её, я замечаю, что правила компании иногда строже того, что я учил для своего разрешения. Чтобы оставаться в рамках закона в каждом рейсе, что ещё, помимо соблюдения внутренних правил перевозчика, я ОБЯЗАН выполнять всегда?","options":["Только внутренние правила моего перевозчика, ведь папка компании уже включает всё, что закон от меня требует","Устные указания по маршруту, которые диспетчер даёт мне по рации и которые отменяют любую письменную инструкцию","То, что говорят местные дорожные знаки и ограничения, ведь для опасных грузов они заменяют федеральные правила","Федеральные и местные правила перевозки опасных грузов (HMR), которые действуют дополнительно к собственным правилам перевозчика"],"explanation":"Водитель обязан соблюдать федеральные и штатные правила перевозки опасных грузов (HMR), которые действуют в дополнение к правилам перевозчика."},"244":{"q":"Я забираю груз с опасными материалами с табличками-плакатами, и в транспортных документах есть подписанное сертификационное заявление грузоотправителя. Прежде чем подписать как водитель, я хочу точно понять, о чём мне говорит эта сертификация. Что юридически подтверждает подписанное сертификационное заявление грузоотправителя в транспортных документах?","options":["Что груз был правильно классифицирован, описан, упакован, промаркирован и снабжён этикетками в соответствии с нормативными требованиями","Что перевозчик проверил правильность стоимости перевозки и что клиент уже оплатил доставку","Что водитель лично осмотрел каждую упаковку и принял полную ответственность за любые утечки, обнаруженные в пути","Что груз был независимо взвешен дважды и общий вес точно совпадает с транспортной накладной"],"explanation":"Подписанная грузоотправителем сертификация юридически подтверждает, что груз правильно классифицирован, описан, упакован, маркирован и снабжён этикетками согласно правилам."},"245":{"q":"Во время предрейсового осмотра я замечаю, что четыре таблички (плаката) на прицепе ярко-оранжевые, а маленькие ромбовидные этикетки на отдельных упаковках внутри тёмно-красные. Другой водитель говорит мне, что цвета нужны лишь для того, чтобы грузоотправители вели учёт товара. Согласно правилам информирования об опасности, о чём на самом деле говорит мне цвет ромбовидной этикетки опасности?","options":["Он указывает перевозчика и грузоотправителя, ответственных за груз","Он обозначает общий тип или класс опасности, которую представляет материал","Он показывает общий вес продукта, загруженного в эту упаковку","Он показывает идентификационный номер ООН/NA, присвоенный материалу"],"explanation":"Цвет ромбовидной этикетки опасности указывает на общий тип или класс опасности, например красный для легковоспламеняющихся и жёлтый для окислителей."},"246":{"q":"Я гружу прицеп на погрузочной площадке, и в транспортных документах указан небольшой пакет ядовитого газа подкласса 2.3 весом всего около 40 фунтов, а также несколько бочек коррозийного вещества из Таблицы 2 общим весом 600 фунтов. Начальник площадки говорит, что мне не нужно вешать никаких табличек (плакатов), потому что весь мой груз намного меньше порога в 1 001 фунт. Что мне следует сделать с размещением табличек перед выездом?","options":["Полностью обойтись без табличек, так как суммарный вес обоих материалов меньше 1 001 фунта.","Повесить таблички только для бочек с коррозийным веществом, потому что они составляют наибольшую долю веса груза.","Повесить таблички для ядовитого газа независимо от его веса, потому что этот материал требует табличек при любом количестве.","Подождать, пока общий вес груза достигнет 1 001 фунта, прежде чем вешать таблички на прицеп."],"explanation":"Материалы из Таблицы 1, такие как ядовитый газ подкласса 2.3, требуют табличек при любом весе, каким бы малым ни был груз."},"247":{"q":"Я только что доставил груз легковоспламеняющейся жидкости, и указатель на моей цистерне показывает «пусто», поэтому я заезжаю на стоянку для грузовиков пообедать. Знакомый говорит мне, что раз цистерна разгружена, я могу снять все четыре таблички (плаката) и обращаться с тягачом как с обычным прицепом без опасного груза. Прежде чем что-либо предпринять, какое самое безопасное предположение мне следует сделать о моей «пустой» цистерне?","options":["Раз указатель показывает «пусто», в цистерне больше нет опасного материала, и с ней полностью безопасно работать.","Раз продукт выгружен, я могу законно сразу снять таблички, ведь таблички нужны только пока жидкость реально перевозится.","Раз груз доставлен, остаток внутри полностью испарился и не может создать ни горючих паров, ни опасности.","Раз внутри могут оставаться остаток и пары, цистерна всё ещё может быть опасна, и с ней нужно обращаться так, будто в ней по-прежнему есть опасный груз."],"explanation":"Опорожненная цистерна может содержать опасные остатки жидкости и пары, поэтому её считают и снабжают табличками как гружёную до надлежащей очистки."},"248":{"q":"Я получаю эндорсмент X, и экзаменатор просит меня объяснить разницу между «грузовой цистерной» (cargo tank) и переносной цистерной на терминале. Обходя двор, я вижу несколько цистерн с жидкими опасными грузами. Какую из них я должен правильно определить как «грузовую цистерну»?","options":["Объёмную цистерну, которая постоянно прикреплена к грузовику или прицепу и является его неотъемлемой частью","Автономную стальную цистерну, которую погрузили на прицеп вилочным погрузчиком и которую можно снять обратно","Любую цистерну, содержащую 1 001 фунт или более жидкости, независимо от того, как она установлена на транспортном средстве","Отдельную бочку на 55 галлонов, закреплённую ремнями внутри кузова прицепа для перевозки"],"explanation":"Грузовая цистерна постоянно закреплена и составляет неотъемлемую часть грузовика или прицепа, в отличие от съёмной переносной цистерны."},"249":{"q":"Я провожу предрейсовый осмотр транспортного средства с грузом, требующим табличек об опасности (placard), и проверяю огнетушитель, закреплённый в кабине. Манометр показывает полный заряд, и огнетушитель надёжно закреплён, но перед выездом я хочу убедиться, что само устройство соответствует требованиям. Какой класс огнетушителя является НАИМЕНЬШИМ, удовлетворяющим требованию для моего транспортного средства с табличками об опасности?","options":["Класс 1 A, поскольку огнетушитель должен справляться с обычными горючими материалами, такими как дерево и бумага","Не менее класса 10 B:C","Подойдёт любой исправный огнетушитель, если манометр показывает полный заряд и он надёжно закреплён","Водяной огнетушитель, рассчитанный на количество галлонов топлива, вмещаемое моим баком"],"explanation":"Транспортное средство с табличками опасных грузов должно иметь огнетушитель с классом не ниже 10 B:C."},"250":{"q":"Я перевожу груз легковоспламеняющейся жидкости с размещенными табличками (плакардами) по сельской двухполосной дороге и приближаюсь к нерегулируемому железнодорожному переезду без шлагбаумов, светофоров и знака 'СТОП'. Что из перечисленного требует от меня закон Техаса?","options":["Продолжать движение с обычной скоростью, поскольку нет сигнала или знака 'СТОП', обязывающего меня остановиться","Снизить скорость почти до остановки, переключить передачу прямо на путях и проехать, чтобы сохранить инерцию","Остановиться за 15–50 футов до ближайшего рельса и пересекать пути только при возможности полностью их освободить без остановки","Остановиться в пределах 5 футов от ближайшего рельса, затем продолжить движение, убедившись, что путь свободен"],"explanation":"Транспортное средство с табличками всегда обязано остановиться в 15–50 футах перед ближайшим рельсом и пересекать пути, только если может полностью их освободить без остановки."},"251":{"q":"Я перевожу груз легковоспламеняющейся жидкости с размещёнными табличками (плакатами) и сделал обязательную остановку за 15-50 футов до железнодорожного переезда. Сигнальные огни выключены, поезда нет, и я вижу, что противоположная сторона свободна и места хватает для всего автопоезда. Когда я выезжаю на пути, как правильно их пересечь?","options":["Переключиться на пониженную передачу на середине переезда, чтобы у двигателя было больше тяги на рельсах","Повышать передачи по мере проезда, чтобы набрать скорость и провести меньше времени на путях","Сбросить скорость почти до ползком на рельсах, чтобы прощупать неровности перед продолжением","Пересечь пути на одной передаче, не переключаясь ни разу, пока полностью не освобожу переезд"],"explanation":"Пересекайте железнодорожные пути на одной выбранной передаче и никогда не переключайтесь на путях, чтобы не заглохнуть на рельсах."},"252":{"q":"Я перевожу груз с табличками - взрывчатые вещества категории 1.1 - и мне нужно остановиться на ночь. Обходя стоянку в поисках места, какое из этих условий должно заставить меня отказаться от площадки и поехать дальше?","options":["Место прямо рядом с бочкой для сжигания мусора, куда рабочие бросают тлеющие отходы","Ровная, хорошо выровненная гравийная площадка на расстоянии более 5 футов от проезжей части дороги","Затенённый угол стоянки, который остаётся прохладным благодаря ряду высоких деревьев","Место с гладким, свежеуложенным асфальтом и хорошим водоотводом"],"explanation":"Взрывчатые вещества необходимо держать вдали от активных источников воспламенения, таких как горящая мусорная бочка, выбрасывающая пламя и искры."},"253":{"q":"Я загружаю несколько запечатанных бочек с коррозийной жидкостью класса 8 в свой фургон-прицеп на погрузочной площадке грузоотправителя. Оператор погрузчика спрашивает, как разместить их для перевозки. Чтобы перевозить этот груз безопасно и правильно, как следует размещать бочки?","options":["Уложить на бок, чтобы они плотнее прилегали и меньше смещались в пути","Вертикально, крышкой вверх, так же как их наполнили и запечатали","Сложить вверх дном, чтобы при утечке жидкость задерживалась запечатанной крышкой","Уложить на бок, но плотно зафиксировать упорами, чтобы они не катались"],"explanation":"Бочки с опасными материалами следует перевозить вертикально, крышкой вверх, поскольку их затворы и уплотнения рассчитаны на положение вверх."},"254":{"q":"Я готовлю наливную грузовую цистерну с расплавленной серой, которая перевозится при температуре, достаточно высокой, чтобы считаться материалом с повышенной температурой. Перед выездом я хочу убедиться, что на цистерне есть дополнительная маркировка, которую правила требуют для такого груза. Какую маркировку я проверяю?","options":["Маркировку \"COLD\" (ХОЛОДНЫЙ), так как предупреждение сообщает спасателям, что содержимое нужно держать охлажденным ниже температуры окружающей среды","Маркировку \"MOLTEN\" (РАСПЛАВЛЕННЫЙ), написанную рядом с надлежащим транспортным наименованием, чтобы обозначить сжиженное состояние груза","Маркировку \"HOT\" (ГОРЯЧИЙ), которая обозначает груз как материал с повышенной температурой для всех, кто приближается к нему","Маркировку \"WET\" (МОКРЫЙ), так как правила относятся к любой перегретой жидкости как к веществу, опасному при намокании"],"explanation":"Материалы с повышенной температурой должны иметь маркировку HOT, чтобы предупредить приближающихся об опасности ожогов и теплового воздействия."},"255":{"q":"Во время предрейсового осмотра я проверяю товарно-транспортные документы на бочку с веществом, о котором грузоотправитель предупреждает, что оно опасно для рыб и водоёмов при разливе рядом с рекой. Прежде чем принять груз, я должен убедиться, что упаковка маркирована правильно. Какая маркировка должна быть на этой упаковке, чтобы обозначить вещество как опасное для водной среды?","options":["KEEP DRY (ХРАНИТЬ В СУХОМ МЕСТЕ), потому что контакт с водой делает такое вещество опаснее","DANGEROUS WHEN WET (ОПАСНО ПРИ НАМОКАНИИ), поскольку опасность связана с водой и водоёмом","THIS SIDE UP (ЭТОЙ СТОРОНОЙ ВВЕРХ), чтобы вредная жидкость не вытекла в сторону воды","MARINE POLLUTANT (ЗАГРЯЗНИТЕЛЬ МОРСКОЙ СРЕДЫ), что обозначает вещество, опасное для водной среды"],"explanation":"Вещество, опасное для водоёмов и водной среды, обозначается маркировкой MARINE POLLUTANT."},"256":{"q":"Я новый водитель с CDL, готовлюсь к получению допуска HazMat, и диспетчер говорит мне, что я по закону обязан знать правила, регулирующие классификацию, упаковку, маркировку и перевозку опасных материалов. Когда я спрашиваю, где именно записаны эти обязательные правила, какой источник является правильным юридическим авторитетом, который мне следует изучать?","options":["Федеральные нормативы (49 CFR), которые содержат юридически обязательные Правила перевозки опасных материалов","Руководство по реагированию в чрезвычайных ситуациях (ERG), которое содержит юридически обязательные правила классификации опасностей","Руководство CDL штата Техас (DL-7C), которое является официальным юридическим источником всех правил перевозки HazMat","Транспортная накладная и грузосопроводительные документы, где перевозчик записывает действующие правила HazMat"],"explanation":"Правила перевозки опасных грузов — это юридически обязательные нормы, закреплённые в Разделе 49 Свода федеральных правил (49 CFR)."},"257":{"q":"Я только что забрал груз коррозийных веществ с табличками-плакардами и остановился на стоянке для грузовиков, чтобы привести в порядок документы перед длинной поездкой по межштатной автомагистрали. Где я обязан хранить Руководство по реагированию в чрезвычайных ситуациях (ERG), чтобы соблюдать требования во время движения?","options":["В офисе терминала перевозчика, чтобы диспетчер мог обратиться к нему во время инцидента","Внутри транспортного средства, где я могу до него дотянуться во время управления груженым плакардами автомобилем","Вместе с документами грузоотправителя, поскольку именно грузоотправитель готовит информацию об опасности","Запертым в прицепе вместе с коррозийными веществами, чтобы оно оставалось рядом с самим грузом"],"explanation":"Возите Руководство по реагированию в чрезвычайных ситуациях в кабине, где до него можно дотянуться при движении, ведь оно полезно только при вас."},"258":{"q":"Вы перевозите груз с табличками опасности и замечаете, что небольшое количество жидкости капает из одной из герметичных бочек на пол прицепа. Утечка незначительна, и ничья жизнь не находится под непосредственной угрозой. Какое действие лучше всего соответствует процедуре DPS по опасным грузам?","options":["Продолжить маршрут до ближайшей стоянки грузовиков, где механик сможет осмотреть и снова загерметизировать бочку","Медленно доехать до ближайшей ремонтной мастерской, чтобы устранить утечку, пока она не распространилась дальше","Оставить транспортное средство на месте, не перемещать его и вызвать квалифицированную помощь для устранения утечки","Накрыть капли впитывающей ветошью, продолжить движение и сообщить об утечке по окончании рейса"],"explanation":"При обнаружении утечки опасного груза никогда не перемещайте машину, а вызывайте квалифицированную помощь, ведь движение может распространить загрязнение."},"259":{"q":"Я собираюсь отправиться в дальний рейс с легковоспламеняющейся жидкостью под табличками-плакардами и хочу, чтобы мой предрейсовый осмотр соответствовал требованиям для опасных грузов, прежде чем я выеду. Что из перечисленного ЛУЧШЕ всего описывает, что я обязан осмотреть до начала этого рейса?","options":["Только товаросопроводительные документы и четыре плаката, поскольку само транспортное средство было проверено в предыдущем рейсе","Только шины, так как это единственный элемент, который правила обязывают меня перепроверять каждые 2 часа или 100 миль","Только тормозную систему, поскольку тормоза — самый критически важный узел гружёной машины с опасным грузом","Тормоза и всё транспортное средство целиком, выполнив полный предрейсовый осмотр всей машины"],"explanation":"Перевозка маркированного опасного груза добавляет обязанностей, поэтому перед поездкой проведите полный предрейсовый осмотр тормозов и всей машины."},"260":{"q":"Я перевожу груз хлора с табличками опасности (класс 2.3, ядовитый газ) по сельскому шоссе в Техасе и приближаюсь к необозначенному железнодорожному переезду без шлагбаума, без мигающих огней и без другого транспорта поблизости. Что требует от меня закон в этой ситуации?","options":["Остановиться на расстоянии от 15 до 50 футов до ближайшего рельса, а затем пересекать пути только если я смогу полностью их освободить","Снизить скорость и отнестись к переезду как к знаку «уступи дорогу», проехав через него, раз нет сигналов и приближающихся поездов","Останавливаться только если я вижу установленный знак STOP или знак железнодорожного переезда, иначе ехать с разрешённой скоростью шоссе","Переключиться на пониженную передачу перед рельсами и держать двигатель в тяге без остановки на всём протяжении переезда"],"explanation":"Машина с маркированным ядовитым газом обязана останавливаться за 15–50 футов до ближайшего рельса на каждом переезде и переезжать, только полностью освободив пути."},"261":{"q":"Я получил допуск HazMat (H) и с тех пор перевожу грузы с табличками-плакатами. Мой приятель уверяет, что после прохождения проверки безопасности (TSA) и письменного экзамена ты обеспечен на всю жизнь и больше никогда не нужно возвращаться к материалу по HazMat. С какой периодичностью транспортный департамент Штата (DPS) на самом деле требует повторять обучение по HazMat, чтобы оставаться в курсе?","options":["Примерно каждый 1 год, привязано к ежегодному продлению медицинской справки","Примерно каждые 3 года","Примерно каждые 10 лет, совпадая со стандартным циклом продления CDL","Больше никогда — после получения допуска и проверки TSA переподготовка не требуется"],"explanation":"Обучение по опасным грузам нужно проходить примерно каждые 3 года, чтобы водитель знал актуальные правила обращения, маркировки и аварийных действий."},"262":{"q":"Я провожу предрейсовый осмотр, и в товарно-транспортных документах указан груз класса 6.1; на прицепе уже стоит ромбовидная табличка с надписью 'POISON' (ЯД/ТОКСИЧНО). Менее опытный водитель спрашивает меня, о чём на самом деле предупреждает эта табличка. Какое утверждение мне следует ему дать?","options":["Она предупреждает, что груз — легковоспламеняющаяся жидкость, поэтому главная опасность — возгорание рядом с открытым огнём","Она предупреждает, что груз — коррозийное вещество, поэтому главная опасность — химические ожоги кожи и глаз при контакте","Она предупреждает, что вещество вредно или смертельно опасно для людей, поэтому контакт с ним может отравить или убить","Она предупреждает, что груз — окислитель, поэтому главная опасность в том, что он заставляет другие материалы гореть быстрее"],"explanation":"Знак POISON или TOXIC предупреждает, что вещество вредно или смертельно для людей и при контакте может отравить или убить."},"263":{"q":"Я перевожу груз с табличкой 'OXYGEN' (КИСЛОРОД, класс 2.2) и во время остановки на обочине замечаю дым, идущий от одной из шин. Оценивая обстановку, что из перечисленного должно играть НАИБОЛЬШУЮ роль в том, как я отношусь к нагреву и любому открытому пламени рядом с этим грузом?","options":["Кислород задушит и погасит любое небольшое возгорание до того, как оно распространится, поэтому у меня есть запас времени на реакцию.","Поскольку это негорючий газ, кислород никак не влияет на огонь, так что меня должна беспокоить только шина.","Кислород охладит окружающий груз и понизит температуру, уменьшив опасность от перегретой шины.","Кислород может питать и усиливать огонь, поэтому даже небольшое пламя рядом с этим грузом я должен считать серьёзной угрозой."],"explanation":"Кислород питает и усиливает огонь, поэтому любое пламя или перегрев рядом с кислородным грузом нужно считать серьёзной угрозой."},"264":{"q":"Вы перевозите груз с табличками — взрывчатые вещества подкласса 1.2 — и вам нужно остановиться для обязательного по федеральным правилам отдыха. Подыскивая разрешённое место для стоянки, от какого объекта вы ОБЯЗАНЫ держаться на расстоянии не менее 300 футов, прежде чем заглушить двигатель?","options":["Придорожный склад, где постоянно собираются работники и клиенты","Размеченная краевая линия разметки на краю проезжей части","Железнодорожный переезд, пересекающий шоссе впереди","Другой грузовой автомобиль, законно припаркованный в зоне отдыха"],"explanation":"Взрывчатые вещества подкласса 1.1, 1.2 и 1.3 нельзя парковать ближе 300 футов от здания, где собираются люди, например придорожного склада."},"265":{"q":"Я перевожу груз с размещенными плакатами и должен оставить тягач припаркованным на обочине сельской трассы на несколько минут, пока проверяю проблему у дороги. По правилам транспортное средство должно находиться под присмотром. Чтобы законно считаться сопровождающим, на каком расстоянии от припаркованного транспортного средства с плакатами мне разрешено находиться?","options":["В пределах 5 футов от машины — на том же расстоянии, на котором я обязан держаться от проезжей части","В пределах 100 футов от машины, держа её в поле зрения и имея возможность переместить при необходимости","В пределах 300 футов от машины — той же зоны, что требуется вокруг мостов и туннелей","В пределах четверти мили, при условии что я всё ещё вижу плакаты"],"explanation":"Сопровождающий припаркованной маркированной машины должен находиться в пределах 100 футов от неё, держать её на виду и уметь переместить в случае ЧП."},"266":{"q":"Во время предрейсового осмотра диспетчер сообщает мне, что одна из грузовых цистерн на моём автопоезде является «переносной цистерной» (portable tank), а не автоцистерной. Осматривая её для подтверждения, по какому признаку я ПРАВИЛЬНО опознаю переносную цистерну?","options":["Она наглухо приварена к раме (шасси) транспортного средства и не может быть снята","Она является неотъемлемой конструктивной частью самой рамы прицепа","Это объёмная (наливная) ёмкость, которая не закреплена на транспортном средстве постоянно","Это стационарная цистерна, встроенная непосредственно в кабину и кузов грузовика"],"explanation":"Переносная цистерна — это объёмная ёмкость, которая не закреплена постоянно на транспортном средстве, поэтому её можно загружать и снимать."},"267":{"q":"Я загружаю партию сжатого газа класса 2 на химическом складе, и начальник погрузочной площадки спрашивает, в какой таре продукт уже должен находиться, прежде чем я распишусь за него и повезу. Чтобы принять груз законно и безопасно, в какой тип ёмкости должен быть упакован сжатый газ?","options":["Запечатан в плотные картонные коробки, скреплённые лентой на поддоне в термоусадочной плёнке","Уложен навалом в открытый кузов бортового прицепа и закреплён грузовыми ремнями","Засыпан в бункерный прицеп с покрытием так же, как перевозят сухие сыпучие материалы","Помещён в баллоны под давлением или перевозится в трубном прицепе, рассчитанном на этот газ"],"explanation":"Сжатый газ находится под давлением и должен перевозиться в специальных баллонах или в трубном трейлере, рассчитанном на этот газ."},"268":{"q":"Я перевожу автоцистерну со сжиженным горючим газом жарким техасским днём, и пока груз нагревается на солнце, я слышу короткое шипение и вижу небольшое облачко пара, выходящее из подпружиненного устройства наверху цистерны, после чего выход пара прекращается сам собой. Что делает этот предохранительный клапан сброса давления и как мне следует к этому отнестись?","options":["Он автоматически сбрасывает накопившееся внутреннее давление, чтобы цистерна не разорвалась, поэтому я не трогаю его и даю ему работать так, как задумано.","Это признак того, что цистерна переполнена сверх номинальной вместимости, поэтому я должен остановиться и стравливать продукт, пока шипение не прекратится.","Он нагнетает давление в цистерну, чтобы газ оставался сжатым, поэтому мне следует ожидать, что он будет постоянно срабатывать, и полностью игнорировать пар.","Он неисправен и выпускает груз, поэтому на следующей остановке мне следует затянуть или закрыть клапан заглушкой, чтобы наглухо закупорить цистерну и остановить утечку."],"explanation":"Предохранительный клапан автоматически сбрасывает накопившееся внутреннее давление, чтобы цистерна не разорвалась, поэтому дайте ему работать как задумано."},"270":{"q":"Я только что закончил разгрузку партии опасных грузов с размещёнными знаками опасности, и при обходе автомобиля замечаю, что у одной из коробок, оставленных на погрузочной площадке, по дну расползается влажное обесцвеченное пятно и ощущается слабый химический запах. Получатель уже расписался за груз. Согласно правилам DPS по опасным грузам, как мне правильно поступить?","options":["От меня больше ничего не требуется — получатель расписался за груз, поэтому ответственность за протекающую коробку полностью перешла к нему","Немедленно сообщить о протечке и обеспечить, чтобы коробка была локализована и обработана безопасно, даже если доставка формально завершена","Тихо отставить коробку подальше от глаз и ничего не говорить, ведь сообщение о протечке после подписанной доставки только создаст бумажную волокиту и задержит меня","Заклеить коробку скотчем, записать её стоимость и организовать утилизацию или перепродажу содержимого со скидкой, чтобы возместить убыток"],"explanation":"Об обнаруженной утечке необходимо немедленно сообщить, а упаковку локализовать и безопасно обработать, даже если доставка уже завершена."},"271":{"q":"Бочка с едкой (класс 8) жидкостью в моём прицепе лопается во время остановки для доставки, и лужа растекается по площадке. Я уже предупредил окружающих, не подпускал людей и уведомил CHEMTREC. Кто должен фактически выполнять физическую очистку разлитого вещества?","options":["Я должен взять перчатки и сорбент и убрать всё сам, ведь я водитель, отвечающий за груз","Грузоотправитель должен приехать и убрать разлив, потому что именно он классифицировал и упаковал вещество","Очистку должны выполнять обученные аварийные службы или квалифицированные подрядчики по ликвидации","Любого прохожего можно попросить помочь быстро локализовать и убрать вещество"],"explanation":"Уборка разлива — это специализированная работа для обученных аварийных служб или квалифицированных подрядчиков, способных безопасно обращаться с материалом."},"272":{"q":"Я только что прошёл обязательное обучение по основам безопасности (security awareness), необходимое для получения допуска на перевозку опасных грузов, и коллега спрашивает меня, в чём вообще был смысл этого обучения. Исходя из того, для чего предназначено это обучение, какое из приведённых ниже описаний ЛУЧШЕ всего отражает, чему оно меня научило?","options":["Запомнить четыре класса опасности, которые всегда требуют табличек, чтобы быстрее размещать таблички на погрузочной площадке","Корректировать дистанцию и точки торможения, чтобы быстрее провозить груз с табличками через транспортный поток","Пропускать повторные проверки в пути после того, как документы уже были проверены на терминале","Распознавать подозрительное поведение или потенциальные угрозы безопасности рядом с моим грузом и сообщать об этих угрозах надлежащим органам"],"explanation":"Обучение безопасности учит водителей распознавать подозрительное поведение или угрозы безопасности груза и сообщать о них соответствующим органам."},"273":{"q":"Я перевожу груз коррозийных веществ с размещёнными табличками-плакатами, и на весовой станции дорожный инспектор просит меня указать \"базовое описание\" материала в моих транспортных документах. Какое сочетание записей я должен показать инспектору как базовое описание?","options":["Надлежащее транспортное наименование, класс опасности, идентификационный номер и группу упаковки","Надлежащее транспортное наименование, общий вес, аварийный номер телефона и страницу руководства ERG","Класс опасности, цвет плаката, подпись грузоотправителя и количество мест груза","Идентификационный номер, регистрацию транспортного средства, название перевозчика и план маршрута"],"explanation":"Базовое описание опасного материала включает надлежащее транспортное наименование, класс опасности, идентификационный номер и группу упаковки."},"274":{"q":"Я перевожу груз легковоспламеняющейся жидкости класса 3 с табличками-плакардами, когда возле протекающей бочки в грузовом отсеке вспыхивает небольшой пожар. У меня есть несколько средств тушения. Чтобы сбить это пламя максимально эффективно, что мне следует использовать?","options":["Залить его мощной постоянной струёй воды, чтобы охладить горящую жидкость","Накрыть пеной или применить огнетушитель класса B:C, чтобы перекрыть доступ кислорода","Засыпать пламя рыхлым придорожным песком, пока оно не будет погребено","Дать ему выгореть самому, отойдя в сторону и ожидая спасателей"],"explanation":"Пожар горючей жидкости (класс 3) нужно тушить пеной или огнетушителем класса B:C, чтобы перекрыть доступ кислорода, и никогда — водой."},"275":{"q":"Я перевожу легковоспламеняющуюся жидкость класса 3 (бочки с бензином), когда из-за утечки одна бочка вызывает небольшой пожар в грузовом отсеке. Прохожий подбегает с ведром воды и предлагает помочь сбить пламя, пока оно не разгорелось. Прежде чем разрешить ему вылить воду, чего мне следует ожидать от воды при таком пожаре легковоспламеняющейся жидкости?","options":["Быстро затушит пламя, потому что вода перекроет доступ кислорода к огню","Охладит горящий бензин ниже температуры вспышки и сразу потушит пожар","Распространит огонь, так как горящая жидкость всплывает на воде и разносится ею","Почти не повлияет, поэтому это самое безопасное, что можно попробовать в ожидании помощи"],"explanation":"Вода распространяет горящую горючую жидкость, например бензин, потому что жидкость всплывает на поверхность воды и уносится вместе с ней."},"276":{"q":"Я везу груз класса 5 (окислитель) с табличками-плакардами, и вдруг в грузе начинается небольшой пожар. Прохожий хватает огнетушитель и говорит: \"Не волнуйся, перекроем доступ воздуха и быстро его потушим\". Исходя из химических свойств того, что я везу, почему это предположение ошибочно?","options":["Потому что окислители коррозийны и разъедают огнетушитель раньше, чем он успеет перекрыть пламя","Потому что огонь слишком холодный, чтобы на него повлиять, ведь окислители горят только при минусовых температурах","Потому что окислители впитывают воду, и любая влага из огнетушителя заставит огонь распространяться быстрее","Потому что окислитель выделяет собственный кислород, и поэтому огонь может продолжать гореть даже при малом количестве воздуха вокруг"],"explanation":"Окислитель (класс 5) выделяет собственный кислород, поэтому огонь может продолжать гореть даже при малом количестве воздуха, и его нельзя потушить удушением."},"277":{"q":"Во время предрейсового осмотра у погрузочной платформы я замечаю небольшое влажное пятно и слабый химический запах от одной из коррозийных упаковок (класс 8), которую только что загрузил грузоотправитель. Товарно-транспортная накладная выглядит заполненной, а доставка срочная. Какова НАИЛУЧШАЯ причина отказаться от перевозки этой упаковки?","options":["Протекающая упаковка может причинить вред людям и загрязнить окружающую территорию, поэтому её нельзя перевозить","Небольшая течь влияет только на своевременность доставки, поэтому я могу её везти, если поеду быстрее, чтобы наверстать график","Грузоотправитель уже подписал накладную, поэтому течь — это бумажная проблема перевозчика, а не моя","Небольшое пятно — это нормально для груза класса 8, поэтому я могу протереть упаковку и загрузить её без дальнейших действий"],"explanation":"Протекающая упаковка с опасным грузом может травмировать людей и загрязнить территорию, поэтому водитель обязан отказаться её перевозить."},"278":{"q":"На моём автоцистерне с табличками возникает утечка коррозийного вещества, пока я припаркован на придорожной зоне отдыха. Правильная реакция — оставить машину на месте, не подпускать людей и уведомить аварийные службы. При каких обстоятельствах я был бы вправе фактически переместить машину с утечкой?","options":["Чтобы доехать до ближайшей заправки, пока цистерна не опустела","Чтобы вывести людей из непосредственной опасности от распространяющейся угрозы","Чтобы быстрее добраться до ремонтной мастерской и избежать долгой задержки","Чтобы поставить грузовик ближе к зданию для удобства уборки"],"explanation":"Транспортное средство с протекающим опасным грузом следует перемещать только для того, чтобы вывести людей из зоны непосредственной опасности."},"279":{"q":"Я перевожу груз коррозийных веществ с табличками опасности, когда из-за поломки сцепного устройства происходит утечка на обочину. После того как я устранил непосредственную опасность, отвёл посторонних, не допустил курения и вызвал аварийные службы и CHEMTREC, федеральные правила всё равно требуют, чтобы об инциденте сообщили. Какую сторону я обязан уведомить, чтобы был составлен этот обязательный отчёт об инциденте?","options":["Грузоотправителя, поскольку именно он классифицировал, упаковал и подготовил товарно-транспортные документы на коррозийные вещества","Местного пожарного инспектора, который обязан подать официальный письменный отчёт о любом разливе на дороге","Моего работодателя/перевозчика — сторону, ответственную за перевозку груза и за сообщение об инциденте","Инспектора весовой станции DPS, ближайшей к месту разлива, поскольку грузы с табличками отслеживаются на весах"],"explanation":"Перевозчик является стороной, ответственной за транспортировку груза и подачу требуемого отчёта об инциденте с опасным грузом."},"280":{"q":"Я обхожу свой прицеп при предрейсовом осмотре груза, который требует таблички (плаката) опасного класса 3 — легковоспламеняющаяся жидкость. Чтобы убедиться, что табличка правильная, я смотрю на ромб, где указан номер класса опасности. В каком месте таблички мне искать этот номер?","options":["В самой верхней точке ромба, прямо над символом","По центру ромба, внутри символа","В крайнем правом углу ромба","В нижней точке ромба, под символом"],"explanation":"На табличке DOT номер класса или подкласса опасности располагается в нижнем углу ромба, под символом."},"281":{"q":"Я провожу предрейсовый осмотр и проверяю ромбовидную табличку (плакат) на прицепе, чтобы убедиться, что она правильная. Чтобы быстро определить тип опасности с одного взгляда, в какой части таблички мне следует искать символ опасности (например, пламя, череп или знак радиации в виде трилистника)?","options":["В верхнем углу таблички, над написанным названием класса опасности","В нижнем углу таблички, где напечатан номер класса опасности","У правого края таблички, рядом с четырёхзначным идентификационным номером","В центре таблички, прямо над диагональной линией раздела цветов"],"explanation":"На табличке DOT символ опасности располагается в верхнем углу ромба, над написанным названием класса опасности."},"282":{"q":"На погрузочной площадке диспетчер сообщает, что мой следующий груз будет отправлен в «таре для перевозки навалом/наливом» (bulk packaging), и я должен проверить его перед подписанием документов. Обходя прицеп, какая из этих ёмкостей правильно соответствует определению такой тары?","options":["Поддон с уложенными запечатанными картонными ящиками, в каждом из которых несколько маленьких бутылок в амортизирующей упаковке","Большая переносная цистерна, в которую продукт залит напрямую, без внутренней упаковки, удерживающей содержимое","Одна пластиковая бочка на 5 галлонов с навинчивающейся крышкой, стоящая у стенки прицепа","Маленький пакет с гранулами на застёжке-молнии, вложенный в маркированную картонную коробку"],"explanation":"Наливная (балк) тара — это крупная ёмкость, например переносной танк, загружаемая продуктом напрямую, без внутренней упаковки."},"283":{"q":"Я загружаю свой прицеп на химическом складе, и грузоотправитель просит меня расписаться за несколько 'немассовых' (non-bulk) упаковок коррозийного вещества класса 8. Разбирая груз на погрузочной площадке, какую тару мне следует ожидать под это описание 'немассовой' упаковки?","options":["Грузовая цистерна на 6 000 галлонов, стационарно установленная на отдельном прицепе","Переносная железнодорожная цистерна, подаваемая на складскую подъездную ветку","Запечатанные стальные бочки по 55 галлонов, уложенные вместе на одном поддоне","Отсек речной баржи, ожидающий приёма того же продукта"],"explanation":"Нерасфасованная (нон-балк) тара — это меньшие ёмкости для перевозки опасных грузов, такие как бочки, ящики, канистры и мешки."},"284":{"q":"Во время предрейсового осмотра автоцистерны, загруженной легковоспламеняющейся жидкостью, я поднимаюсь наверх, чтобы проверить зону купола на крыше цистерны. Прежде чем выехать на шоссе, в каком состоянии должны находиться крышки люков, чтобы груз был надёжно закреплён и не протекал?","options":["Слегка приоткрыты, чтобы внутреннее давление паров могло стравливаться в пути","Сняты и убраны в кабину, чтобы они не дребезжали и не открутились в дороге","Оставлены полностью открытыми до следующей остановки для осмотра по маршруту","Полностью закрыты и надлежащим образом загерметизированы до начала движения"],"explanation":"Крышки люков (купола) автоцистерны должны быть полностью закрыты и плотно загерметизированы до начала движения, чтобы груз оставался внутри."},"285":{"q":"Я водитель автоцистерны и собираюсь загружать легковоспламеняющуюся жидкость класса 3 через перекачивающий шланг. Во время предзагрузочной проверки я замечаю, что у одного шланга изношен внешний слой и есть небольшая поверхностная трещина возле муфты. Прежде чем подсоединить его и начать подачу продукта, что требует руководство в отношении шлангов, используемых для загрузки или разгрузки?","options":["Использовать только шланги в хорошем состоянии, поэтому я должен отложить этот треснувший шланг и выбрать неповрежденный до начала загрузки","Продолжить загрузку с этим шлангом, так как трещина только на внешнем слое, а двигатель останется работающим для поддержания стабильного давления","Использовать треснувший шланг, но снизить скорость подачи, потому что более медленная перекачка не даст шлангу в пограничном состоянии разрушиться","Подсоединить шланг как есть и просто поставить второго человека в 25 футах для наблюдения за утечками во время перекачки"],"explanation":"Шланги для загрузки или выгрузки опасных грузов должны быть в исправном состоянии, поэтому треснувший шланг нужно отложить и взять неповреждённый."},"286":{"q":"Я на терминале готовлю свой прицеп с табличками (плакардами), и передо мной несколько задач: нужно заправить тягач, заменить перегоревший габаритный фонарь, подписать товарно-транспортные документы и проконтролировать бригаду, перегружающую бочки с легковоспламеняющейся жидкостью класса 3 в прицеп. Во время какой из этих задач я должен СТРОЖЕ всего держать все источники воспламенения — зажжённые сигареты, открытый огонь, искрящий инструмент — полностью вдали от операции?","options":["Во время заправки тягача, ведь двигатель остаётся включённым, чтобы я мог следить за указателем уровня топлива по мере наполнения бака","Во время того, как бригада загружает в прицеп бочки с легковоспламеняющейся жидкостью класса 3, ведь пары могут воспламениться при перегрузке","Во время замены перегоревшего габаритного фонаря, ведь я буду работать с электропроводкой рядом с грузом","Во время проверки и подписания товарно-транспортных документов, ведь я обязан держать их сверху и в пределах досягаемости перед поездкой"],"explanation":"Во время загрузки легковоспламеняющихся жидкостей класса 3 держите все источники возгорания подальше, так как выходящие пары могут воспламениться."},"287":{"q":"Я провожу предрейсовый осмотр грузовика, загруженного взрывчатыми веществами подкласса 1.1, перед выездом на установленный маршрут перевозки опасных грузов. Во время обхода я замечаю несколько вещей. Какая из перечисленных находок сама по себе сделает это транспортное средство непригодным к эксплуатации и потребует устранения до перевозки этого груза?","options":["Одно из задних брызговиков треснуло и слегка погнуто по нижнему краю","Светоотражающий треугольник в аварийном комплекте имеет выцветшую, тусклую поверхность","Из штуцера возле бака равномерно капает топливо — есть течь топлива","Зеркало со стороны пассажира закреплено слабо и вибрирует на холостом ходу"],"explanation":"Транспортное средство, перевозящее взрывчатые вещества, не должно иметь утечек топлива или масла, так как любая утечка создаёт недопустимую опасность пожара и воспламенения рядом с грузом."},"288":{"q":"Инспектор на дороге останавливает меня и требует подтверждения того, что я имею право перевозить цистерну с коррозийными веществами, на которой установлены таблички (placard). Несколько месяцев назад я прошёл проверку угрозы безопасности TSA и снятие отпечатков пальцев и успешно сдал всё. Какой ОДИН документ я предъявляю, который действительно подтверждает, что моя пометка (endorsement) HazMat (H/X) сейчас действительна?","options":["Письмо об одобрении проверки угрозы безопасности TSA, которое я получил по почте после прохождения проверки данных","Моё действующее медицинское свидетельство врача-эксперта DOT, поскольку именно оно подтверждает, что я физически допущен к управлению","Квитанцию о снятии отпечатков пальцев и пакет документов заявления, которые я подал в офисе выдачи прав для получения пометки","Моё коммерческое водительское удостоверение (CDL), потому что пометка H или X напечатана непосредственно на самом удостоверении"],"explanation":"Допуск на перевозку опасных грузов — это код (H, или X для цистерны с опасным грузом), напечатанный прямо на лицевой стороне коммерческих водительских прав."},"289":{"q":"Я перевожу маркированный знаками груз коррозийных веществ и должен ненадолго остановиться, чтобы проверить документы. Все доступные места находятся рядом с двухполосным шоссе. Согласно правилам стоянки транспортного средства с размещёнными знаками опасности, какое из этих мест будет нарушением?","options":["Обочина, где мой грузовик будет стоять всего в 3 футах от проезжей части дороги","Гравийная площадка, отведённая примерно на 20 футов от края проезжей части дороги","Место на стоянке для отдыха, отмеренное в 10 футах от проезжей части дороги","Широкий съезд, оставляющий мой грузовик в целых 8 футах от проезжей части дороги"],"explanation":"Транспортное средство с табличками опасности нельзя парковать ближе чем в 5 футах от проезжей части дороги."},"290":{"q":"Я забираю груз с табличками-плакатами, и грузоотправитель передаёт мне документы с надлежащим наименованием груза, классом опасности и идентификационным номером. Перевозчик оформил рейс и сообщит о любом происшествии. Размышляя о том, кто ещё юридически отвечает за безопасную перевозку этого опасного груза, какая сторона замыкает цепочку совместной ответственности вместе с грузоотправителем и перевозчиком?","options":["Клиент-получатель груза, поскольку именно он принимает груз на складе","Водитель, который осматривает груз, отказывается от течей, устанавливает плакаты и едет безопасно","Сотрудник TSA, который выдал мне допуск после проверки благонадёжности","Диспетчер, который лишь назначает маршрут и никогда не касается груза"],"explanation":"Водитель завершает цепочку безопасности при перевозке опасных грузов, осматривая груз, отказываясь от протекающих или неправильно маркированных отправлений, размещая таблички со всех сторон и управляя безопасно."},"291":{"q":"Я загружаю радиоактивный груз класса 7, и грузоотправитель просит меня проверить, чтобы метки соответствовали транспортному индексу, прежде чем я подпишу документы. Глядя на упаковку, я вижу две метки с категорией, обозначенной римскими цифрами, которая указывает уровень радиации. Какой набор обозначений категорий я должен ожидать увидеть на этих радиоактивных метках?","options":["Категории A, B или C, буквами в соответствии с группой упаковки","Категории 1, 2 или 9, соответствующие номерам класса опасности","Категории I, II или III, указывающие уровень радиации","Категории X, Y или Z, обозначающие диапазон транспортного индекса"],"explanation":"Метки радиоактивных материалов (класс 7) содержат категорию римскими цифрами — I, II или III, — указывающую уровень радиации и транспортный индекс."},"292":{"q":"Я загружаю прицеп двумя разными упаковками с опасными грузами, и в товарно-транспортных документах указано, что они реагируют друг с другом. Грузоотправитель не сказал держать их раздельно, и есть место, чтобы поставить их рядом. Прежде чем закрепить их вплотную, какую реальную угрозу безопасности я должен учесть?","options":["Ставить их рядом нормально, потому что сама упаковка сделана так, чтобы любые два материала никогда не взаимодействовали","Единственное беспокойство в том, что суммарный вес может превысить порог в 1 001 фунт, при котором требуются таблички (плакарды)","Ничего существенного не произойдёт; реактивные материалы просто нейтрализуют друг друга при хранении в одном пространстве","Загрузка двух реагирующих химикатов вместе может вызвать пожар или химическую реакцию, поэтому их нужно держать раздельно"],"explanation":"Несовместимые реактивные материалы должны быть разделены при погрузке, так как их контакт может вызвать пожар или опасную химическую реакцию."},"293":{"q":"Бочка на моём прицепе с табличками-плакардами протекает неизвестной жидкостью на обочину, а в товарно-транспортных документах неясно, что именно это за вещество. Чтобы определить, что это за вещество, и передать спасателям точную информацию, что из перечисленного мне НИКОГДА нельзя делать?","options":["Попробовать на вкус или потрогать вещество, чтобы помочь определить, что это такое","Проверить надлежащее транспортное наименование и идентификационный номер в товарно-транспортных документах","Найти четырёхзначный идентификационный номер в Руководстве по реагированию на чрезвычайные ситуации (ERG)","Отметить класс опасности, указанный на плакарде и этикетках"],"explanation":"Никогда не пробуйте на вкус и не трогайте материал для его опознания, так как даже малое количество может вызвать серьёзную травму, отравление или химические ожоги."},"294":{"q":"Вы перевозите груз легковоспламеняющейся жидкости с табличками (плакардами) и останавливаетесь на придорожной зоне отдыха. Находясь вне кабины, вы замечаете пламя в задней части прицепа рядом с грузом. Огонь уже слишком велик, чтобы сбить его вашим небольшим огнетушителем. Что вы должны сделать В ПЕРВУЮ ОЧЕРЕДЬ?","options":["Сесть в кабину и попытаться отогнать горящий прицеп на открытое поле подальше от зоны отдыха","Не подпускать людей к транспортному средству и вызвать аварийно-спасательные службы для помощи","Открыть двери прицепа, чтобы выпустить дым и добраться до горящего груза внутри","Отложить транспортные документы в кабине, чтобы огонь не уничтожил их"],"explanation":"При пожаре опасных грузов, который нельзя потушить ручным огнетушителем, в первую очередь защищайте жизнь людей, удерживая их подальше и оповещая аварийные службы."},"295":{"q":"Я провожу предрейсовый осмотр прицепа с табличками опасности, который докеры загрузили ночью, а в документах на сиденье водителя указан коррозионный груз класса 8. Прежде чем тронуться, что ОДНО я ОБЯЗАН проверить относительно табличек, уже размещенных на всех четырех сторонах?","options":["Что цвет таблички совпадает с окраской и надписями на борту моего тягача","Что табличка размещена на каждой из четырех сторон и читается с любого направления","Что таблички правильно указывают фактически перевозимый материал, как обозначено в товаросопроводительных документах","Что таблички соответствуют типу топлива, на котором работает тягач, тянущий груз"],"explanation":"Водитель должен убедиться, что таблички правильно указывают на фактически перевозимый материал, сверив их с грузовыми документами."},"296":{"q":"Я загружаю партию коррозийных веществ (класс 8), требующую размещения табличек (плакардов), но в моём ящике закончились таблички класса 8. У меня есть оставшиеся таблички класса 3 (легковоспламеняющиеся вещества) от предыдущего рейса, и грузовик уже на несколько часов отстаёт от графика. Как правильно следует поступить с размещением табличек на этом грузе перед выездом?","options":["Использовать таблички класса 3 допустимо для короткой поездки, поскольку любая отображаемая табличка всё равно предупреждает других водителей, что я везу опасный груз","Я могу ехать вообще без табличек, если держу в пределах досягаемости на сиденье транспортные документы, указывающие класс 8","Разместить таблички класса 3 на двух сторонах, а две другие стороны оставить пустыми, допустимо, потому что груз помечен лишь частично","Размещение неправильных табличек (класса 3) незаконно и небезопасно, поэтому я не должен трогать груз с места, пока не получу правильные таблички класса 8"],"explanation":"Таблички должны быть правильными со всех четырёх сторон, поэтому груз нельзя перевозить с неверными табличками; для коррозийного груза класса 8 нужны таблички класса 8."},"297":{"q":"Вы перевозите по Техасу груз легковоспламеняющейся жидкости с табличками (placards), и режим труда и отдыха вынуждает вас сделать перерыв в ближайшие 20 минут. Впереди вы видите забитую парковку торгового центра, переполненную семьями зону отдыха у дороги и тихую гравийную площадку для остановки в стороне от любого скопления людей. Где вам следует запланировать остановку?","options":["На тихой гравийной площадке, выбирая безопасное место вдали от людей всякий раз, когда вы останавливаетесь с грузом, помеченным табличками","В переполненной зоне отдыха у дороги, потому что зоны отдыха — единственные законно разрешённые места остановки для транспорта с табличками","На забитой парковке торгового центра, ведь нахождение в людном, хорошо освещённом месте со свидетелями надёжнее защищает груз от кражи","Там, где вы окажетесь, когда истечёт время, припарковавшись прямо у края проезжей части, чтобы не терять время на вождение"],"explanation":"При перевозке груза с табличками всегда планируйте остановки в безопасном месте вдали от людей, чтобы свести к минимуму последствия при аварии."},"298":{"q":"Я только что получил отметку H и перед первым рейсом с табличками-плакардами повторяю, зачем вообще существуют все правила перевозки опасных грузов. Опытный водитель говорит, что правила сводятся к трём главным целям: удержать продукт, сообщить об опасности и ещё одна цель. КРОМЕ одной из перечисленных ниже целей, все они отражают истинное назначение правил перевозки опасных грузов. Какой вариант НЕ относится к ним, потому что неверно описывает третью цель?","options":["Удержать материал, чтобы предотвратить или ограничить его утечку","Перевозить груз быстрее и снизить расходы перевозчика на доставку","Сообщить об опасности с помощью плакардов, ярлыков и грузовых документов","Обеспечить, чтобы продукт прибыл к месту назначения безопасно и без вреда"],"explanation":"Цели правил перевозки опасных грузов — удержать продукт, сообщить о риске и обеспечить безопасную транспортировку, а не ускорить доставку или снизить затраты."},"299":{"q":"Я новый водитель опасных грузов и забираю партию коррозионных веществ. Бочки выглядят запечатанными, но я замечаю, что транспортные документы были заполнены до моего приезда, и я никак не влиял на то, как продукт классифицировали и упаковали. Разбираясь, кто за что отвечает, какая из перечисленных обязанностей лежит на ГРУЗООТПРАВИТЕЛЕ, а не на мне как на водителе?","options":["Останавливаться за 15-50 футов до железнодорожного переезда и не переключать передачи при пересечении путей","Размещать таблички-плакарды на всех четырёх сторонах прицепа и держать документы в пределах досягаемости во время движения","Правильно определять надлежащее транспортное наименование и подбирать подходящую упаковку для материала","Отказываться от груза, если бочка протекает, и осматривать груз перед перевозкой"],"explanation":"Грузоотправитель классифицирует материал, определяет надлежащее транспортное наименование и выбирает правильную упаковку до того, как груз попадёт к водителю."}},"tr":{"0":{"q":"H onayımı yeni aldım ve yeni bir sürücü bana tüm bu plaka (placard), taşıma belgesi ve ambalaj kurallarının neden var olduğunu soruyor. Aşağıdakilerden hangisi tehlikeli madde düzenlemelerinin temel amacını EN İYİ şekilde açıklar?","options":["Maddeyi dışarı sızamayacak şekilde içeride tutmak ve tehlikeyi bildirmek; böylece başkaları uzak durabilir ve güvenli müdahale edebilir","Plakalı yüklere otoyol şeritlerine ve güzergâhlarına öncelikli erişim vererek daha hızlı teslimat zamanlarını garanti etmek","Her sevkiyatı belgelemek; böylece taşıyıcı müşteriye doğru tehlikeli madde işleme ek ücretini fatura edebilir","Ağır tehlikeli yükleri mevcut en kısa yollara yönlendirerek taşıyıcının yakıt maliyetlerini düşürmek"],"explanation":"Tehlikeli madde kuralları, maddeyi kaçamayacak şekilde içeride tutmak ve tehlikeyi bildirerek diğerlerinin uzak durup güvenle müdahale etmesini sağlamak için vardır."},"1":{"q":"Plakart (placard) gerektiren bir aşındırıcı (corrosive) madde yükünü taşıyan bir güzergah için yeni işe alındım ve halihazırda tanker onayı olan A Sınıfı bir CDL'ye sahibim. Bu seferi yasal olarak yapabilmem için aşağıdakilerden hangisini yapmam gerekir?","options":["Ekstra hiçbir şey — tanker onaylı A Sınıfı CDL'm zaten taşıdığım her plakartlı yükü kapsıyor","TSA güvenlik tehdidi değerlendirmesi ve parmak izi alınmasını gerektiren tehlikeli maddeler (H) onayını almak","İkili/üçlü römork onayı eklemek, çünkü plakartlı yükler birden fazla römorka bölüştürülmelidir","Yolcu onayı eklemek, çünkü plakartlı yükler yolcu taşımacılığı ile aynı şekilde düzenlenir"],"explanation":"Plaka gerektiren herhangi bir miktarda tehlikeli madde taşımak, TSA güvenlik tehdit değerlendirmesi ve parmak izi gerektiren tehlikeli madde (H) onayını zorunlu kılar."},"2":{"q":"Halihazırda Teksas A Sınıfı CDL ehliyetim ve geçerli bir DOT sağlık sertifikam var. Yeni işverenim, plakart gerektiren aşındırıcı (korozif) yükler taşımamı istiyor, bu yüzden H onayını eklemem gerekiyor. DPS memuruna, mevcut ehliyetimin gerektirmediği hangi ek adımın bu onay için gerekli olduğunu sorduğumda, bana büyük olasılıkla ne söyler?","options":["Fazladan hiçbir şey gerekmez; geçerli bir DOT sağlık kartınızla A Sınıfı CDL ehliyetiniz olduğunda, H onayı hiçbir ek koşul olmadan ehliyetinize basılır","Onay verilmeden önce ikinci ve daha ayrıntılı bir DOT fiziksel muayenesinden geçmeli ve güncellenmiş bir tıbbi muayene sertifikası sunmalısınız","Onay verilmeden önce, geçmiş kontrolü ve parmak izi alınmasını içeren bir TSA güvenlik tehdit değerlendirmesinden geçmelisiniz","Plakartları uzaktan hâlâ okuyabildiğinizi doğrulamak için yalnızca standart CDL görme taramasını tekrar geçmeniz yeterlidir"],"explanation":"Tehlikeli madde onayı verilmeden önce, sabıka kontrolü ve parmak izi dahil olmak üzere TSA güvenlik tehdit değerlendirmesinin geçilmesi gerekir."},"3":{"q":"Bir parti aşındırıcı (korozif) madde taşımak üzere işe alındım ve yola çıkmadan önce iskelede evrakları inceliyorum. Tehlike sınıfının, doğru sevkiyat adının ve UN kimlik numarasının sevkiyat belgelerine zaten girilmiş olduğunu fark ediyorum, ancak bunu doğru tarafın yaptığından emin olmak istiyorum. Tehlikeli madde kurallarına göre, malzemeyi tehlikeli olarak tanımlamak ve bu sevkiyat belgelerini en başta hazırlamak kimin göreviydi?","options":["Taşıyıcı firma, çünkü seferi taşıyıcı yürütür ve yükü taşımaktan ve her türlü olayı bildirmekten sorumludur","Sürücü, çünkü belgeleri elimin altında tutmak ve bir sorun görürsem yükü reddetmek zorunda olan kişi benim","Alıcı, çünkü teslimatı kabul eden şirket içeriği doğrular ve tehlikeli madde için imza atar","Gönderici, çünkü gönderici malzemeyi sınıflandırır, adlandırır, paketler ve etiketler ve sevkiyat belgelerini hazırlar"],"explanation":"Yük sürücüye ulaşmadan önce, tehlikeli maddeyi sınıflandıran, adlandıran, paketleyen, etiketleyen ve sevkiyat belgelerini hazırlayan taraf yükleyicidir."},"4":{"q":"Teksas genelinde plakartlı (tehlike levhalı) bir aşındırıcı madde yükü taşıyorum ve az önce otoyola girdim. Sürüş sırasında tehlikeli madde sevkiyat belgeleri kurallarına uymak için bu belgeler şu anda nerede olmalı?","options":["Emniyet kemerim takılıyken uzanabileceğim mesafede ya da sürücü kapısındaki cepte, ve diğer belgelerimin en üstünde","Açık pencereden gelen rüzgârın dağıtmaması için yatak bölmesinde sabitlenmiş halde","Römorkun dış tarafında, plakartların yakınına monte edilmiş belge kutusunda","Asıl yükle birlikte kalsın diye römorkta yükün altına yerleştirilmiş halde"],"explanation":"Araç hareket halindeyken, tehlikeli madde sevkiyat belgeleri emniyet kemeri takılıyken sürücünün erişebileceği yerde veya sürücü kapısı cebinde ve diğer belgelerin üstünde olmalıdır."},"5":{"q":"Yeni bir sürücüyüm ve birkaç düzenlemeye tabi olmayan ürünle birlikte bir tehlikeli madde (HazMat) içeren karışık yük dorsesini yüklüyorum. Yükleme rampasından ayrılmadan önce birleşik sevkiyat belgesini incelediğimde, evrakın yasal olması için tehlikeli madde bu belgede nasıl tanımlanmalıdır?","options":["Sıradan yük satırlarından ayrı kalması için sayfada en son yazılmalı","İlk sırada yazılmalı, ya vurgulanmalı ya da HM sütununda 'X' ile işaretlenmeli","Yalnızca yük listesinin arkasına zımbalanmış ayrı bir arka sayfada yazılmalı","Dorsedeki plakartlar tehlikeyi zaten belirttiğinden normal yazıyla bırakılmalı"],"explanation":"Karışık bir sevkiyat belgesinde, tehlikeli madde girişi ilk sıraya yazılarak, vurgulanarak veya HM sütununda 'X' ile işaretlenerek ayırt edilebilir hale getirilmelidir."},"6":{"q":"Tablo 2 kapsamında aşındırıcı (korozif) bir yük taşıyorum ve terminalden çıkmadan önce dört adet elmas biçimli plakartı römorkun her tarafına yeni taktım. Yeni bir sürücü, bu elmasların neden bu kadar önemli olduğunu, onlar olmadan yola çıkmayı neden reddedeceğimi soruyor. Bu plakartların asıl amacını hangi açıklama doğru şekilde belirtir?","options":["Yükleyicinin yükü doğru sınıflandırıp paketlediğini belgelerler, böylece sevkiyatı kendim incelemem gerekmez","Bu yükü taşımak için gereken geçerli H onayına sahip olduğumu ve TSA güvenlik taramasından geçtiğimi kanıtlarlar","Aracın çevresindeki herkesi yükün oluşturduğu tehlikeye karşı uyarırlar, böylece müdahale ekipleri ve halk güvenle tepki verebilir","Düzenlemeye tabi malzemenin toplam brüt ağırlığını kaydederler, böylece kantar görevlileri 1.001 lb altında olduğumu doğrulayabilir"],"explanation":"Plakalar, araç çevresindeki herkesi yükün taşıdığı tehlikeye karşı uyarır, böylece müdahale ekipleri ve halk güvenle tepki verebilir."},"7":{"q":"Plakartlı (tehlike levhalı) aşındırıcı madde yükü taşıyorum ve saha amiri, bir iş arkadaşımın gerekli plakartları römorkun her iki yanına ve arkasına çoktan taktığını söylüyor. Kapıdan çıkmadan önce, plakart yerleşimi konusunda yasal olmak için daha ne yapmam gerektiğini hangi ifade doğru biçimde belirtir?","options":["Başka bir şeye gerek yok; her iki yan ve arka kaplandığına göre, üç plakart aşındırıcı yük için plakart kuralını karşılar.","Yukarıdan görünmesi için römorkun çatısına bir plakart ekle, ancak kabin görüşü engellediğinden ön taraf gerekli değildir.","Arka plakartı ön tampona taşı, çünkü ön ve iki yan, bir memurun gerçekten denetlediği tek konumlardır.","Aracın önüne de bir plakart ekle, böylece yük ön, arka ve her iki yanda plakartlı olsun."],"explanation":"Plakalar aracın dört tarafına da -ön, arka ve her iki yan- takılmalı ve her biri baktığı yönden okunabilir olmalıdır."},"8":{"q":"Plakartlı bir aşındırıcı yük taşırken varillerimden biri banketin üzerine sızmaya başlıyor. Çevredekileri uyardım ve müdahale ekiplerini aradım, ancak sevkiyat sorumlusu bana, tam olarak bu maddenin dökülmesinin nasıl ele alınacağını gösteren belgedeki referans numarasını itfaiyecilere okumamı söylüyor. Kabinde hangi öğeyi kullanmam gerekiyor?","options":["Acil Müdahale Kılavuzu (ERG), müdahale ekiplerinin maddeyi tehlikesi ve koruyucu önlemlerle eşleştirmesini sağlar","Sevkiyat belgeleri, çünkü yükün doğru sevkiyat adı ve UN/NA numarası zaten orada listelidir","Aracın kullanım kılavuzu, kamyonun sistemlerini ve üreticinin acil durum prosedürlerini kapsar","Konşimento, çünkü yükü ve taşıyıcının olay bildirim iletişim bilgilerini belgeler"],"explanation":"Her tehlikeli madde sürücüsü, müdahale ekiplerinin maddeyi tehlikesi ve koruyucu önlemleriyle eşleştirmesini sağlayan Acil Müdahale Kılavuzu'nu (ERG) bulundurmalıdır."},"9":{"q":"Plakart takılı 3. Sınıf yanıcı sıvı yükü taşıyarak terminalden ayrılmak üzereyim. Programın gerisinde kaldığım için sevkiyatçım yola çıkmam için beni sıkıştırıyor. Yola çıkmadan önce işimi güvenli ve yasal şekilde yapmak için bunlardan hangisini yapmalıyım?","options":["Otoyolda diğer sürücülerin dikkatini çekmemek için plakartları römorktan sökmek","Yola çıkmadan önce aracı, lastikleri ve yük emniyetini dikkatlice kontrol etmek","Rıhtımda beklerken kaybettiğim zamanı telafi etmek için bu seferlik yol öncesi kontrolü atlamak","Araç daha kolay yuvarlansın ve seferde daha az yakıt harcayayım diye römork frenlerini sökmek"],"explanation":"Tehlikeli madde taşımak, yola çıkmadan önce aracın, lastiklerin ve yük emniyetinin dikkatlice kontrol edilmesini gerektirir; zaman baskısı bunu atlamayı mazur göstermez."},"11":{"q":"Tehlikeli madde taşıyan ve plakart takılı yükümde yol sırasında zorunlu lastik kontrolü yaparken, römorktaki bir lastiğin tehlikeli şekilde aşırı ısındığını fark ediyorum. Teksas tehlikeli madde kurallarına göre, yola devam etmeden önce ne yapmam gerekir?","options":["Lastiğin üzerine su dökerek soğutmak ve kontrol ettirmek için bir sonraki servis istasyonuna kadar sürmeye devam etmek","Doğru basıncı sağlamak için hava ekleyip lastik kendi kendine soğuyana dek dikkatli şekilde sürmek","Aşırı ısınan lastiği çıkarıp aracın güvenli bir mesafesine koymak ve sorun giderilene kadar sürmemek","Hızımı düşürüp, bir sonraki zorunlu kontrole kadar hava akışının lastiği soğutması için sürmeye devam etmek"],"explanation":"Plakartlı yükteki aşırı ısınan bir lastik yangın ve patlama riski oluşturur; bu yüzden onu çıkarın, araçtan güvenli bir mesafeye koyun ve onarılana kadar sürmeyin."},"12":{"q":"Oksitleyici (oxidizer) yük için plakart takılı bir aracım var ve mola için bir dinlenme alanına girdim. Başka bir kamyondaki bir arkadaşım yanıma gelip benimle sigara içmek istiyor. Yasalara uygun kalmak için, sigara içerken ikimiz de römorkumdan en az ne kadar uzakta durmalıyız?","options":["En az 5 fit — yoldan uzakta park ederken gereken aynı tampon mesafe","En az 10 fit — hiçbir alevin römorka ulaşamayacağı kadar uzak","En az 100 fit — bir binanın yakınındaki patlayıcılar için kullanılan aynı tampon mesafe","Araçtan en az 25 fit, çünkü oksitleyici (oxidizer) taşıyor"],"explanation":"Sigara içmek veya herhangi bir açık alev, patlayıcı, oksitleyici veya yanıcı madde taşıyan plakartlı bir araçtan en az 25 fit uzakta olmalıdır."},"13":{"q":"Bölüm 1.2 patlayıcılarını römorkuma yüklemek için bir yükleme rampasına yanaştım. Rampadaki ekip, kasaları taşımaya başlamadan önce kamyonu hazırlamamı bekliyor. Patlayıcılar yüklenmeye başlamadan önce aracımla ilgili ne yapmam gerekir?","options":["Yükleme başlamadan önce motoru kapatıp el frenini çekerek aracı emniyete almak","Yükleme sırasında hava frenleri basınçta kalsın ve kabin kliması çalışsın diye motoru rölantide çalışır durumda bırakmak","Motor kendi başına gerçek bir ateşleme kaynağı olmadığından motoru çalışır bırakıp sadece el frenini çekmek","Tüm camları açıp, yüklemenin başladığını rampa ekibine bildirmek için kornaya iki kez basmak"],"explanation":"Patlayıcıları yüklemeden veya boşaltmadan önce, ateşleme kaynağını ortadan kaldırmak için motoru kapatın ve aracı sabitlemek için el frenini çekin."},"14":{"q":"Bir yakıt terminalinde varillerde benzin yükü alıyorum ve sevk görevlim, plaka takmadan önce sevk belgelerindeki tehlike sınıfını doğrulamamı istiyor. Tehlike sınıflarının tanımlanma şekline göre, bu benzin yükünün yanında hangi tehlike sınıfı numarası yer almalıdır?","options":["Sınıf 1, çünkü yanıcı sıvılar en yüksek patlama tehlikesini taşır ve patlayıcılarla birlikte gruplandırılır","Sınıf 3, çünkü benzin yanıcı bir sıvıdır ve bu sınıfın kapsadığı tam olarak budur","Sınıf 8, çünkü benzin temas halinde cildi yakabilir ve malzemelere aşındırıcı gibi zarar verebilir","Sınıf 2, çünkü benzin yanıcı buharlar çıkarır ve yanıcı bir gaz olarak ele alınır"],"explanation":"Benzin yanıcı bir sıvıdır ve bu tam olarak Tehlike Sınıfı 3'ün kapsadığı şeydir."},"15":{"q":"Bir yükleme rampasında sevkiyat yüklüyorum ve sevk irsaliyesinde bir patlayıcı yükü için uygun sevk adı, tehlike sınıfı ve UN numarası listeleniyor. Römorkuma plaka takıp yola çıkmadan önce, bu yükü patlayıcı olarak tanımlayan tehlike sınıfı numarasını doğrulamam gerekiyor. Hangi tehlike sınıfı doğrudur?","options":["Akü asidi gibi aşındırıcıları kapsayan Sınıf 8","Benzin gibi yanıcı sıvıları kapsayan Sınıf 3","Dinamit gibi patlayıcıları kapsayan Sınıf 1","Uranyum gibi radyoaktif maddeleri kapsayan Sınıf 7"],"explanation":"Dinamit gibi patlayıcılar, dokuz tehlike sınıfının ilki olan Tehlike Sınıfı 1'dir."},"16":{"q":"Terminalde iki tehlikeli madde yükü alıyorum. Birincisi yalnızca 300 lb ağırlığında, Tablo 2 kapsamındaki küçük bir aşındırıcı (korozif) varili; ikincisi ise tek bir zehirli gaz tüpü (Sınıf 2.3). Sevkiyatçım bana \"plaka gerektiren miktar için plaka takman gerekecek\" diyor. Bu ifade plakaların ne zaman gerektiği konusunda aslında bana ne anlatıyor?","options":["Tehlikeli madde taşıyan her araç daima plaka göstermek zorundadır, bu yüzden hem 300 lb korozif hem de zehirli gaz ağırlık veya sınıf fark etmeksizin plaka gerektirir","Plakalar yalnızca araç karanlık bastıktan sonra veya düşük görüş mesafesinde kamuya açık karayolunda hareket halindeyken yasal olarak gereklidir","İki sevkiyat da bu yolculuk için 1.001 lb toplam eşiğinin altında kaldığından hiçbirinin plakasına gerek yoktur","Plakalar yalnızca belirli miktarlar veya sınıflar için gereklidir — zehirli gaz herhangi bir miktarda plaka gerektirirken, korozif yalnızca 1.001 lb ve üzerinde gerektirir"],"explanation":"Zehirli gaz gibi Tablo 1 maddeleri her miktarda plakart gerektirir, oysa aşındırıcılar gibi Tablo 2 maddeleri yalnızca 1.001 lb ve üzerinde plakart gerektirir."},"17":{"q":"Plakart taşıyan, aşındırıcı (korozif) bir yükü teslim alıyorum. Gönderici bana taşıma belgelerini veriyor ve her şeyin doğru sınıflandırıldığını, paketlendiğini ve etiketlendiğini söylüyor. Bu yükü taşımadan önce, göndericinin sevkiyatın doğru tanımlandığını, paketlendiğini, işaretlendiğini ve etiketlendiğini resmî olarak onayladığını bana ne gösterir?","options":["Göndericinin imzaladığı, taşıma belgesinin üzerinde yer alan onay (sertifikasyon) beyanı","Göndericinin yükleme rampasında bana verdiği sözlü güvence","Aracın dört tarafına zaten takılmış olan doğru tehlike sınıfı plakartlarının bulunması","Mühürleri ve etiketleri kendi denetleyerek hiçbir sızıntı olmadığını doğrulamam"],"explanation":"Gönderici, tehlikeli madde sevkiyatının doğru şekilde adlandırıldığını, paketlendiğini, işaretlendiğini ve etiketlendiğini, sevk belgesindeki bir sertifika beyanını imzalayarak onaylar."},"19":{"q":"Tehlike levhalı aşındırıcı madde tankerim kırsal bir karayolunda devriliyor ve Sınıf 8 ürün banket üzerine sızıyor. İnsanları uzaklaştırıp sigara içilmesini durdurup Acil Müdahale Kılavuzu'nu (ERG) aldıktan sonra, şirketimin ciddi olayı telefonla bildirmesi gerekiyor. Ciddi bir tehlikeli madde olayının raporunu almak için özel olarak var olan iletişim noktası hangisidir?","options":["İlk aradığım CHEMTREC, çünkü resmi olay raporunu almaya yetkili tek kurum odur","Ulusal Müdahale Merkezi (National Response Center), ciddi tehlikeli madde olaylarının raporlarını almak için var olan federal acil hat","Evrakımda listelenen gönderici, çünkü yükü paketleyen şirket raporu sunmak zorundadır","Aracın devrilmesi ve tank arızasının resmi olarak belgelenmesi için araç üreticisinin acil hattı"],"explanation":"Ciddi tehlikeli madde olayları, 1-800-424-8802 numaralı federal yardım hattı olan Ulusal Müdahale Merkezi'ne bildirilmelidir."},"20":{"q":"Pazar günü saat gece 2:30 ve plakartlı varillerimden biri bir dinlenme tesisinde aşındırıcı (korozif) madde sızdırmaya başladı. Çevredekileri zaten uyardım, insanları uzak tuttum ve sigara içilmesini engelledim. Şimdi acil kimyasal müdahale rehberliği için CHEMTREC'i (1-800-424-9300) aramak istiyorum, ancak hafta sonu bu saatte kimsenin cevap vermeyeceğinden endişeleniyorum. Hangi ifade doğrudur?","options":["CHEMTREC yalnızca normal mesai saatlerinde çağrı yanıtlar, bu yüzden rehberlik almak için Pazartesi sabahını beklemem gerekir.","CHEMTREC yalnızca hafta içi hizmet verir, bu yüzden bugün Pazar olduğundan bunun yerine taşıyıcımın ofisini aramalıyım.","CHEMTREC günde 24 saat, her gün kesintisiz hizmet verir, bu yüzden hemen şimdi arayıp bir acil durum uzmanına ulaşabilirim.","CHEMTREC'e yalnızca gece saatlerinde ulaşılabilir, bu yüzden gece 2:30'da aramak işe yarayan tek zaman dilimidir."],"explanation":"CHEMTREC (1-800-424-9300), acil müdahale bilgisi sağlamak için her gün 24 saat hizmet verir."},"21":{"q":"Plaka levhalı (patlayıcı değil) aşındırıcı madde yükü taşıyorum ve telefon görüşmesi yapıp evraklarımı kontrol etmek için kenara çekmem gerekiyor. Yakında dinlenme tesisi yok, bu yüzden iki şeritli bir karayolunun banketine bakıyorum. Tehlikeli madde park kurallarına uymak için aşağıdakilerden hangisini yapmam gerekir?","options":["Diğer trafiğe banket üzerinde en fazla yeri bırakmak için aracı seyir şeridinin kenarına olabildiğince yakın park etmek","Yoldan 300 fit mesafe içinde park etmek ama yükü yalnızca birkaç dakikalığına gözetimsiz bırakmak","Aracı banket kaplamasının üzerine çıkarıp doğrudan şeridin beyaz kenar çizgisinin yanında durdurmak","Durup park etmeden önce aracı yolun seyir kısmından en az 5 fit uzakta tutmak"],"explanation":"Plakartlı bir araç asla yolun trafiğe açık kısmının 5 fit yakınına park edilmemelidir."},"22":{"q":"Bölüm 1.2 patlayıcı madde taşıyorum ve zorunlu lastik kontrolü için kenara çekiyorum. İleride banketten yanan bir araç görüyorum ve yakınında bir grup insan toplanmış izliyor. Bu yükle yasal ve güvenli şekilde park etmek için, kamyonum ile orada toplanan kalabalık arasında tutmam gereken asgari mesafe nedir?","options":["Toplanan insanlardan en az 300 fit","Toplanan insanlardan en az 25 fit","Toplanan insanlardan en az 50 fit","Toplanan insanlardan en az 5 fit"],"explanation":"Patlayıcı yükler (Bölüm 1.1, 1.2, 1.3) insanların toplandığı bir yere 300 fitten daha yakın park edilmemelidir."},"23":{"q":"Bölüm 1.2 patlayıcı maddelerden oluşan plakartlı (placard) bir yük taşıyorum ve bir dinlenme tesisinde birkaç dakikalığına aracımdan uzaklaşmam gerekiyor. Kurallara göre bu yük asla gözetimsiz bırakılamaz. Aracımın yasal olarak 'gözetim altında' sayılması için, onu gözetleyen kişi hakkında aşağıdakilerden hangisi doğru olmalıdır?","options":["Kamyonu duyabildiği ve bir şey olursa müdahale edebildiği sürece yatak bölmesinde dinlenebilir","Uyanıktır, araçtan 100 fit mesafe içindedir, aracı açıkça görebilir ve gerekirse onu hızla hareket ettirebilir","En az iki saatte bir aracın yanından geçip onu denetler — lastik kontrolüyle aynı aralıkta","Dinlenme tesisinin herhangi bir yerinde kalır ve acil durumda cep telefonuyla ulaşılabilir durumdadır"],"explanation":"Patlayıcı yük ancak kişi uyanıksa, 100 fit içindeyse, aracı net görüyorsa ve hızlıca hareket ettirebiliyorsa gözetim altındadır."},"24":{"q":"Plakartlanmış (placard'lı) aşındırıcı madde yükü taşıyan bir CDL şoförüyüm. Yükleme rampasında bir görevli bana bir pano uzatıyor ve yola çıkmadan önce \"benim işime\" neyin dahil olduğunu sıralıyor. Şoför olarak gerçek yasal sorumluluk alanımda kalmak için, bu listedeki tek görevi, yani şoförün sorumluluğu OLMAYIP zincirdeki başka birine ait olan görevi tespit etmem gerekiyor. Bu görev hangisidir?","options":["Sızdırdığını ya da yanlış işaretlendiğini tespit ettiğim bir paketi kabul etmeyi reddetmek","Yola çıkmadan önce gerekli plakartları (placard) aracın dört tarafına da yerleştirmek","Taşınan tehlikeli maddeyi üretmek ve kimyasal formülünü hazırlamak","Araç sürerken sevk evraklarını elimin uzanabileceği bir yerde tutmak"],"explanation":"Sürücünün görevleri yükü denetlemek, hatalı sevkiyatları reddetmek, plaka takmak, sevk belgelerini elinin altında tutmak ve güvenli sürmektir; maddeyi üretmek değildir."},"25":{"q":"Hava donma noktasının altında ve uzun bir sefer için bir römork yüklüyorum. Kamyonumda çalışan bir kargo bölmesi ısıtıcısı var ve yükü soğuktan korumak için onu çalıştırmak istiyorum. Yükleme rampasında bekleyen dört sevkiyattan hangisi için kargo ısıtıcısını KAPALI tutmalıyım?","options":["Soğukta donup patlayabilecek konserve çorba ve şişe suyu paleti","Soğuk havada nem tutan, kutulanmış ev mobilyası ve ambalaj malzemeleri","Alıcının taşıma sırasında donmamasını istediği soğutulmuş taze sebze ve meyveler","Patlayıcı madde kutularıyla birlikte yüklenmiş Sınıf 3 yanıcı sıvı varilleri"],"explanation":"Patlayıcı veya yanıcı sıvı taşırken kargo ısıtıcıları kapalı kalmalıdır, çünkü alev veya ısı buharları tutuşturabilir ya da patlayıcıları ateşleyebilir."},"26":{"q":"Plakartlı bir aşındırıcı (corrosive) yükü teslim edeli üç hafta oldu ve sefer çoktan bitti. Sevkiyat sorumlum, şirketin o yükün tehlikeli madde sevkiyat belgelerini (shipping papers) hâlâ bir dosyada sakladığını söylüyor. Aşağıdakilerden hangisi, taşıyıcının sefer bittikten sonra bu tamamlanmış belgeleri saklamasının EN İYİ nedenidir?","options":["Federal ve eyalet denetçileri kayıtları incelemek için isteyebileceğinden, taşıyıcı bunları gerekli süre boyunca saklamak zorundadır","Yükü taşıyan sürücü, bu orijinal belgeleri kariyeri boyunca şahsen dosyasında saklamakla yükümlüdür","Teslimat onaylanıp yük araçtan indirildikten sonra belgelerin artık hiçbir işlevi kalmaz ve atılabilir","Belgelerin yalnızca madde yoldayken saklanması gerekir ve sürücünün kapı cebine ulaşması yeterlidir"],"explanation":"Taşıyıcı, federal ve eyalet denetçileri inceleme için isteyebileceğinden, tamamlanmış sevk belgelerini gerekli süre boyunca saklamalıdır."},"27":{"q":"Bir yük için sevk evrakını hazırlıyorum ve ürünümün kaydına ait ayrıntıları çekmek için yönetmelikteki Tehlikeli Maddeler Tablosu'nu açıyorum. Maddeme ait satırı okurken gördüğüm her sütun doğrudan bu Tablo'dan geliyor; ANCAK Tablo dışında bir kaynaktan almam gereken tek bir bilgi var. Aşağıdakilerden hangisini Tehlikeli Maddeler Tablosu'nu okuyarak bulamam?","options":["Maddeyi sevk evrakımda tanımlamak için kullanmam gereken doğru sevkiyat adı","Tablo'nun hiçbir yerinde yer almayan, sürücü olarak ev adresim","Taşıdığım maddeye atanan tehlike sınıfı veya bölümü","Kayıtla birlikte listelenmesi gereken kimlik numarası (UN/NA)"],"explanation":"Tehlikeli Maddeler Tablosu, sürücünün kişisel bilgilerini değil, maddenin kendisini tanımlar: sevk adı, tehlike sınıfı, kimlik numarası, ambalaj grubu ve etiketler."},"28":{"q":"Bir göndericinin yükleme rampasında Sınıf 3 yanıcı sıvı yükü alıyorum. Sevkiyat belgeleri malzemeyi doğru şekilde tanımlıyor ve plaka (placard) gerektiğini gösteriyor, ancak gönderici aracı bana hiç plaka takılmadan teslim ediyor ve \"stokta kalmadı\" diyor. Yola çıkmadan önce ne yapmam gerekir?","options":["Yük zaten yüklü ve belgeler doğru olduğu için ilk planlı durağıma kadar gidip alıcıdan eksik plakaları temin etmesini istemek","Plakasız devam etmek ama sevkiyat belgelerini erişim mesafesinde en üstte tutmak, çünkü doğru evraklar eksik plakaların yerine yasal olarak geçer","Doğru plakaları temin edip aracı yola çıkarmadan önce dört tarafına da takmak","Eksik bir plaka yükü kabul etmeyi yasadışı kıldığı için sevkiyatın tamamını reddedip rampada bırakmak"],"explanation":"Gönderici plaka sağlamazsa, sürücü doğru plakaları temin edip aracı yola çıkarmadan önce dört tarafına da takmalıdır."},"29":{"q":"Römorkuma kutulanmış aşındırıcı (korozif) madde yüklüyorum ve gönderici her bir paketin üzerine bir işaret uygulamış. Yükleme rampasında başka bir sürücü bana bu paket işaretlerinin, aracın dört tarafına asacağım plakartlarla (placard) tamamen aynı şey olduğunu söylüyor. Yükü doğru şekilde denetlemek için hangi ifadeye güvenmeliyim?","options":["Paket işaretleri tam boyutlu plakartlardır ve federal kurallar, dört taraf plakartlama gerekliliğini karşılamak için bunları aracın yanlarına taşımama izin verir","Paket işaretleri göndericinin isteğe bağlı notlarıdır, bu yüzden gerçekten yasal geçerliliği olan tek baklava şeklindeki işaretler araç plakartlarıdır","ABD'de tehlike bildirimi yalnızca plakartlarla yapılır, bu nedenle kutuların üzerindeki baklava şekilleri sadece süstür ve göz ardı edilebilir","Her paketin üzerindeki baklavalar, göndericinin uyguladığı tehlike etiketleridir ve araca takılan daha büyük plakartlardan ayrıdır"],"explanation":"Etiketler, göndericinin tek tek paketlere koyduğu küçük baklava işaretlerdir; plakalar ise aracın dört tarafına yerleştirilen büyük baklava işaretlerdir."},"30":{"q":"Soğutulmuş bir susuz amonyak tankı ve bir sıkıştırılmış oksijen tüpü içeren bir yük hazırlıyorum. Sevkiyat belgelerinde her iki kalem de Tehlike Sınıfı 2 olarak işaretlenmiş. Belgeleri fiilen yüklediğim malzemeyle karşılaştırırken, her Sınıf 2 malzemesinin hangi fiziksel durumda olmasını beklemeliyim?","options":["Gaz (sınıf yanıcı, yanıcı olmayan ve zehirli gazları kapsar)","Düşük sıcaklıkta buhar veren yanıcı bir sıvı","Yalnızca ıslandığında tehlikeli hâle gelen bir katı","Sıvı veya katı hâlde olabilen aşındırıcı bir madde"],"explanation":"Tehlike Sınıfı 2, yanıcı, yanıcı olmayan ve zehirli gazları kapsayan gazlar sınıfıdır."},"31":{"q":"Aşındırıcı bir temizlik ürünü yükleyen yeni bir tehlikeli madde sürücüsüyüm. Varillerin üzerindeki etikette üreticinin marka adı büyük harflerle yazılı, gönderici bana evrakları verdi ve sevkiyat görevlisi yükü sürekli katalog ürün adıyla anıyor. Sevkiyat belgelerimdeki uygun sevkiyat adının doğru olduğunu kontrol ederken, bu ad hangi isimle eşleşmelidir?","options":["Varil etiketlerinde büyük harflerle yazılı marka adı, çünkü asıl ürünü tanımlayan budur","O madde için Tehlikeli Maddeler Tablosu'nda listelenen uygun sevkiyat adı, herhangi bir ticari veya marka adı değil","Sevkiyat görevlisinin kullandığı katalog ürün adı, çünkü şirket yükü bu şekilde takip eder","Ürünün herhangi bir yaygın adı, yeter ki belgelerdeki tehlike sınıfı ve kimlik numarası doğru olsun"],"explanation":"Sevk belgeleri, ticari veya marka adını değil, doğru sevk adını Tehlikeli Maddeler Tablosu'nda göründüğü şekliyle aynen listelemelidir."},"32":{"q":"Yanıcı sıvı yükü taşımadan önce plakartlı tankerimde sefer öncesi muayene yapıyorum. Kabin bölgesine tırmanıp kapının yanına monte edilmiş yangın söndürücüyü kontrol ediyorum. Hangi durum söndürücünün kabul edilebilir olduğunu ve yola çıkmaya yasal olarak uygun olduğumu gösterir?","options":["Söndürücü monte edilmiş ve mühürlü, bu yüzden yola çıkmadan önce göstergeyi veya sınıfını kontrol etmeme gerek yok","Gösterge ibresi kırmızı bölgede olsa bile söndürücü alışık olduğum boyutta","Söndürücü tamamen dolu ve taşıdığım tehlike için yeterince yüksek bir sınıfa sahip","Söndürücü kabinde mevcut, çünkü çalışan herhangi bir söndürücü taşımak gereksinimi karşılar"],"explanation":"Plakart taşıyan bir araçta, hem tam dolu hem de taşınan tehlike için yeterli sınıfa sahip bir yangın söndürücü bulunmalıdır."},"33":{"q":"Plakartlı (tehlike levhalı) yanıcı sıvı yükü taşıyorum ve deponun üstünü doldurmak için bir yakıt adasına giriyorum. Yardımcı sürücüm daha hızlı bitirelim diye yardım teklif ediyor. Aracı doğru ve güvenli bir şekilde yakıt ile doldurmak için aşağıdakilerden hangisi MUTLAKA yapılmalıdır?","options":["Tabancayı açık konumda kilitleyip ön camı silmek için uzaklaşabilirim, yeter ki farları beslemek için motor çalışır durumda kalsın","Yakıt pompası daha hızlı basınçlansın diye motoru rölantide çalışır bırakmalı ve depo dolarken yaklaşık 25 fit geride durmalıyım","Yakıt doldurmaya başlayıp ödemek için içeri girebilirim, çünkü pompadaki otomatik kapatma depo dolunca akışı durduracaktır","Motoru kapatmak zorundayım ve ikimizden biri tüm süre boyunca tabancanın başında kalıp yakıt akışını kontrol etmelidir"],"explanation":"Plakart taşıyan bir aracı yakıt ikmali yaparken motor kapalı olmalı ve biri tüm süre boyunca hortum başında yakıt akışını kontrol etmelidir."},"34":{"q":"Plakartlı bir Bölüm 1.1 patlayıcı yükü taşıyorum ve navigasyonum öğleden sonra şehir merkezindeki iş bölgesinden ve büyük bir nehir tünelinden doğrudan geçen en hızlı rotayı öneriyor. Zorunlu Tehlikeli Madde rota kurallarına göre ne yapmalıyım?","options":["Fazladan kilometre eklese bile, gerektiği yerlerde kalabalık bölgelerden ve tünellerden kaçınan bir rota planlamak","Tünel beni sıkışık yüzey yollarından uzak tutup zaman kazandırdığı için navigasyon rotasını izlemek","Şehir merkezi rotasını kullanmak, ancak yalnızca duraklarda yolun kullanılan kısmından en az 5 fit uzakta park edersem","Demir yolu raylarını vites değiştirmeden geçtiğim sürece en hızlı rotayı izlemek"],"explanation":"Plakart taşıyan patlayıcı maddeleri taşıyan sürücü, yol uzasa bile tüneller ve kalabalık bölgelerden kaçınarak belirlenmiş tehlikeli madde güzergahını izlemelidir."},"35":{"q":"Plakartlı bir tehlikeli madde seferi için römorkumu yüklüyorum ve sevk belgelerimde, ayrıştırma (segregasyon) tablosuna göre birbirine temas ederse tehlikeli şekilde reaksiyona girebilecek iki madde listeli. Yükleme rampasındaki ekip acele ediyor ve hemen yola çıkmamı istiyor. Hangi davranış beni yasal ve güvende tutar?","options":["İki uyumsuz maddeyi aynı palete bağlayarak, yolculuk sırasında kaymayacak şekilde sıkıca taşınmalarını sağlamak","İki maddeyi, ayrıştırma kurallarının gerektirdiği gibi ayrı yükleyerek reaksiyona girebilen maddeleri birbirinden uzak tutmak","İki maddeyi tek bir mühürlü kutuda birleştirerek tek bir sızıntının yükün geri kalanına yayılmasını önlemek","Kısa ve doğrudan bir güzergahta gittiğim için ayrıştırma kontrolünü atlayıp her iki maddeyi de normal şekilde yüklemek"],"explanation":"Ayrıştırma tablosunda yer alan birbiriyle uyumsuz maddeler, temas halinde tepkimeye girmemeleri için ayrı yüklenmeli ve ayrı tutulmalıdır."},"36":{"q":"Taşımak için akü asidi varilleri yüklüyorum. Sevkiyat belgelerinde yük bir tehlike sınıfı numarasıyla listelenmiş ve plaka takmadan önce bu aşındırıcı malzemeye doğru tehlike sınıfını eşleştirdiğimden emin olmak istiyorum. Asit gibi bir aşındırıcı için plakalarda hangi tehlike sınıfı numarası bulunmalıdır?","options":["Sınıf 3, çünkü varillerdeki yanıcı sıvılar ve asitler birlikte gruplandırılır","Sınıf 5, çünkü asitler güçlü tepki verir ve oksitleyiciler gibi davranır","Sınıf 8, çünkü asitler gibi aşındırıcılar bu tehlike sınıfına girer","Sınıf 1, çünkü basınçlı asit varilleri patlayıcı olarak kabul edilir"],"explanation":"Asitler gibi aşındırıcı maddeler Tehlike Sınıfı 8'e girer."},"37":{"q":"Bir gönderici rampasında bana bir yük için sevk belgeleri veriliyor ve kayıtta doğru sevk adı ile bir BM kimlik numarasının yanında 7 tehlike sınıfı yer alıyor. Römorkuma plaka asıp yola çıkmadan önce, bu 7. sınıf tanımı bana aslında hangi tür malzemeyi taşıdığımı söylüyor?","options":["Yakıt ve solvent yüklerinde bulunan türden yanıcı sıvılar","Tüplerde basınç altındaki sıkıştırılmış ve sıvılaştırılmış gazlar","Güçlü asitler ve aşındırıcı sıvılar gibi korozif maddeler","Taşıma sırasında iyonlaştırıcı radyasyon yayan radyoaktif maddeler"],"explanation":"Tehlike Sınıfı 7, taşıma sırasında iyonlaştırıcı radyasyon yayan radyoaktif maddelerdir."},"38":{"q":"Yükleme rampasında, bir gönderici bana bir malzemeyi 'Tehlike Sınıfı 6' olarak listeleyen belgeler veriyor. Plaka takıp yola çıkmadan önce, ne tür bir tehlike taşıdığımı tam olarak anlamak istiyorum. Sınıf 6 tanımlaması bu yük hakkında bana ne söyler?","options":["Zehirli (toksik) bir maddedir, bu yüzden maruz kalma ve soluma tehlikelerine karşı korunmalıyım","Yangını şiddetlendirebilen bir oksitleyicidir, bu yüzden onu yanıcı maddelerden uzak tutmalıyım","Cildi ve metali yakabilen aşındırıcı bir maddedir, bu yüzden sızıntı olup olmadığını kontrol etmeliyim","Yanıcı olmayan sıkıştırılmış bir gazdır, bu yüzden basınç boşalmasına karşı tedbir almalıyım"],"explanation":"Tehlike Sınıfı 6, zehirli (toksik) maddeleri kapsar; bu nedenle maruz kalma ve soluma tehlikelerine karşı korunulmalıdır."},"39":{"q":"Bir sevkiyatı hazırlıyorum ve evraklarımdaki uygun sevkiyat adının ardından \"5.1\" tehlike sınıfı numarası ve UN formatında bir kimlik numarası geliyor. Nakliyeci bana aracın dört tarafına asmam için bir plaka (placard) veriyor. Hangi plaka, Tehlike Sınıfı 5 maddesiyle doğru şekilde eşleşir?","options":["CORROSIVE (aşındırıcı) plakası, çünkü Sınıf 5 metali aşındıran asitleri ve akü sıvısını kapsar","OXIDIZER (oksitleyici) plakası, çünkü Sınıf 5 oksitleyicileri ve organik peroksitleri kapsar","EXPLOSIVES (patlayıcı) plakası, çünkü Sınıf 5 patlayıcı maddeleri ve fünyeleri kapsar","RADIOACTIVE (radyoaktif) plakası, çünkü Sınıf 5 radyasyon yayan maddeleri kapsar"],"explanation":"Tehlike Sınıfı 5, oksitleyicileri ve organik peroksitleri kapsar; bu nedenle sınıf 5.1 yük için OXIDIZER (OKSİTLEYİCİ) plakartı gerekir."},"40":{"q":"Tek bir römorka, iki farklı tehlike sınıfına giren çeşitli dökme olmayan paketler yüklüyorum ve her sınıf için ayrı bir plaka yerine dört tarafa da tek bir 'DANGEROUS' (TEHLİKELİ) plakası asmayı tercih ediyorum. DPS Tehlikeli Madde kurallarına göre, 'DANGEROUS' plakasının kullanılmasına gerçekte ne zaman izin verilir?","options":["Yalnızca yükteki her paket tek bir tehlike sınıfına ait olduğunda","Yalnızca sevkiyat tamamen kutulanmış veya paletlenmiş gıda sınıfı ürünlerden oluştuğunda","Yük, kuralların tek bir plakayı paylaşmasına izin verdiği iki veya daha fazla tehlike sınıfı içerdiğinde","Sınıfa özgü plakaların yerine kullanışlı bir genel karşılık olarak, neredeyse her durumda"],"explanation":"Yük, kuralların birleştirilmesine izin verdiği iki veya daha fazla tehlike sınıfı içerdiğinde, tek bir DANGEROUS plakartı ayrı plakartların yerini alabilir."},"41":{"q":"Plakartlı bir tankeri taşırken bir devlet polisi beni durduruyor, plakart üzerindeki dört haneli numarayı gösteriyor ve bunun ne anlama geldiğini soruyor. Bu numaranın acil durumda nasıl kullanıldığına bakarak, bu dört haneli kimlik numarası aslında neyi tanımlar?","options":["Müdahale ekiplerinin döküntü hacmini bilmesi için yüklü tankın toplam brüt ağırlığını","Yanıcı sıvılar için 3 gibi tehlike sınıfı bölümünü, sayısal biçimde","Taşıyıcının terminale kadar izlememi atadığı belirlenmiş Tehlikeli Madde rotasını","Taşınan belirli tehlikeli maddeyi; Acil Durum Müdahale Kılavuzu'nda (ERG) aranır"],"explanation":"Dört haneli UN/NA numarası belirli tehlikeli maddeyi tanımlar; müdahale ekipleri bunu Acil Müdahale Kılavuzu'nda (ERG) arar."},"42":{"q":"Yükümün sevkiyat belgelerini inceliyorum ve her tehlikeli madde girişinde I, II veya III ambalaj grubunun listelendiğini fark ediyorum. Yeni bir sürücü bana bu Roma rakamının aslında ne anlattığını soruyor. Tehlikeli madde eğitimime göre, ambalaj grubu malzeme hakkında neyi gösterir?","options":["Malzemenin ne kadar büyük bir tehlike oluşturduğunu; Grup I en tehlikeli olandır","Yanıcı veya aşındırıcı gibi tehlike türünü belirleyen tehlike sınıfı numarasını","Yükün dört tarafına da plaket asılması gereken asgari ağırlığı","Girişlerin sevkiyat belgesinde listelenmesi gereken sırayı"],"explanation":"Paketleme grubu, malzemenin tehlike derecesini gösterir; Grup I en tehlikeli, Grup II orta, Grup III en az tehlikelidir."},"43":{"q":"Teksas genelinde plakartlanmış bir aşındırıcı (korozif) madde yükü taşıyorum ve bir tartı istasyonunda eyalet trafik polisi, sevkiyatım için 24 saat acil müdahale telefon numarasının nerede belgelendiğini göstermemi istiyor. Memura hangi yeri göstermeliyim?","options":["Römorkun dört tarafına da takılan plakartların üzerinde","Kabinde elimin erişebileceği yerde tuttuğum sevk belgesinde (taşıma kağıdında)","Tehlikeli Maddeler (H) onay belgesi kartımın üzerinde","Kabinde saklanan Acil Müdahale Kılavuzu'nda (ERG)"],"explanation":"24 saat acil müdahale telefon numarası, sürücünün kabinde erişebileceği yerde tutması gereken sevk belgesine yazılır."},"44":{"q":"Bir yükün sevkiyat belgelerini inceliyorum ve bir kayıt tehlike sınıfı 4 olarak listelenmiş. Plaka takıp denetim yapmadan önce, gerçekte ne tür bir tehlike taşıdığımı doğrulamak istiyorum. Aşağıdakilerden hangisi Tehlike Sınıfı 4 maddelerini doğru şekilde tanımlar?","options":["Basınçlı tüpten salındığında tutuşabilen yanıcı gazlar","Benzin gibi tutuşabilen buharlar yayan yanıcı sıvılar","Kendiliğinden tutuşan ve ıslandığında tehlikeli olan maddeler dahil yanıcı katılar","Cildi yakabilen veya metal kapları aşındırabilen aşındırıcı (korozif) maddeler"],"explanation":"Tehlike Sınıfı 4, kendiliğinden yanabilen ve ıslandığında tehlikeli olan maddeler dahil yanıcı katıları kapsar."},"45":{"q":"Römorkuma \"Islandığında Tehlikeli\" olarak işaretlenmiş bir Sınıf 4.3 madde yüklüyorum ve tüm güzergah için yağmur bekleniyor. Kapıları kapatmadan önce, özellikle bu tehlike için EN ÖNEMLİ önlem hangisidir?","options":["Yükün fazla soğumasını önlemek, çünkü bu katıları kararsız hale getiren şey soğumadır","Kutuların toza karşı sızdırmaz olduğundan emin olmak, çünkü havadaki partiküller reaksiyonu tetikler","Yükün yeni boyanmış ve mühürlenmiş olduğunu doğrulamak, böylece taşıma sırasında buharlar dışarı çıkamaz","Maddeyi tamamen kuru ve mühürlü tutmak, çünkü suyla temas onun tutuşmasına neden olabilir"],"explanation":"Islandığında tehlikeli maddeler suyla tepkimeye girip tutuşabilir, bu yüzden tamamen kuru tutulmalı ve neme karşı sızdırmaz şekilde kapatılmalıdır."},"46":{"q":"Tehlikeli madde seferi için römorkuma birkaç basınçlı gaz tüpü yüklüyorum. Kapıları kapatıp yola çıkmadan önce, hangi yükleme yöntemi hem kurallara uygunluğu hem de yük güvenliğini sağlar?","options":["Her tüpü dik konumda durdurup, taşıma sırasında devrilemeyecek, yuvarlanamayacak veya kayamayacak şekilde sabitlemek","Tüpleri yatay yatırıp, engebeli yollarda yerleşmeleri için gevşek bir şekilde istiflemek","Yola çıkmadan önce her tüpün vanasını hafifçe açarak iç basıncın yolda dengelenmesini sağlamak","Yalnızca römork tabanı düzse yan yatırmak, aksi takdirde dik durdurmak"],"explanation":"Sıkıştırılmış gaz tüpleri dik durmalı ve taşıma sırasında devrilemeyecek, yuvarlanamayacak veya kayamayacak şekilde sabitlenmelidir."},"47":{"q":"Römorkuma Sınıf 6.1 (zehir/toksik) bir sevkiyat yüklüyorum ve hâlâ boş zemin alanım var. İkinci bir sefer yapmamak için, aynı terminale giden başka yükle aracı doldurmak istiyorum. Zehirle aynı araca koymamam gereken yük hangisidir?","options":["Mühürlü karton kutularda otomobil yedek parçaları paleti","Bir market için çuvallanmış kuru köpek maması ve kutulanmış mısır gevreği","Bir sandık tamirci el aleti ve bağlama ekipmanı","Birkaç çuval temiz, kuru inşaat kumu"],"explanation":"Zehirli ve toksik (Sınıf 6.1) maddeler, bulaşma riski nedeniyle insan veya hayvan gıdalarıyla birlikte asla yüklenmemelidir."},"48":{"q":"Sefer öncesi kontrolümde, plakart taşıyan yükümde Sınıf 8 olarak işaretlenmiş bir varil buluyorum ve yanındaki zemine az miktarda sıvı sızmış. Bu sızıntıyı nasıl ele alacağıma karar verirken, ona yaklaşmadan önce hesaba katmam gereken EN önemli tehlike aşağıdakilerden hangisidir?","options":["Madde römork içindeki sıcaklığı hızla düşüreceği için önce havalandırma yapmalıyım","Madde hava ile temasta son derece patlayıcı olduğu için 300 fitlik bir alanı boşaltmalıyım","Madde temas ettiğinde cildimi ve gözlerimi kimyasal olarak yakabileceği için ona dokunmaktan kaçınmalı ve kendimi korumalıyım","Madde sıvı halde aslında etkisizdir, bu yüzden bir bezle silip yoluma devam edebilirim"],"explanation":"Sınıf 8 aşındırıcılar temas halinde cildi ve gözleri kimyasal olarak yakabilir, bu yüzden sürücü dokunmaktan kaçınmalı ve kendini korumalıdır."},"49":{"q":"Treylerıme bir parti Sınıf 3 yanıcı sıvı yükleyeceğim. Yüklemeye başlamadan önce, kargo bölmesinde bir önceki seferden kalan döküntüler ve sağa sola çarpan açıkta metal parçalar olduğunu fark ediyorum. Tehlikeli madde kurallarına göre, yüklemeye başlamadan önce kargo bölmesinin hangi koşulu sağlaması gerekir?","options":["Nem kazara tutuşma olasılığını düşürdüğü için boğuna kadar ıslak olmalı","El aletlerim ön duvara sabitlenmiş şekilde taşınsın diye önce onlarla yüklenmeli","Yanıcı buharlar kabin bölümüne kaçamasın diye sızdırmaz ve havalandırmasız kapatılmalı","Yük içeri girmeden önce temiz ve kıvılcım çıkaran her türlü tehlikeden arındırılmış olmalı"],"explanation":"Yanıcı sıvılar yüklenmeden önce kargo bölmesi temiz ve kıvılcım üreten tehlikelerden arınmış olmalıdır, çünkü gevşek metal buharları tutuşturabilir."},"50":{"q":"Sefere çıkmadan önce plakart taşıyan tankerimi hazırlıyorum ve elmas şeklindeki plakartları römorka monte ediyorum. Her birinin baktığı yönden temiz ve okunabilir kalmasını sağlamanın yanı sıra, DPS gerekliliklerini karşılaması için her plakartı tam olarak nasıl konumlandırmam gerekir?","options":["Bir köşesi tam yukarı bakacak şekilde döndürülmüş bir kare olarak, elmas gibi yerleştirmek","Bir tam kenarı altta düz duracak biçimde yatık olarak yerleştirmek","Yalnızca sürücü ve yolcu taraflarına monte etmek, ön veya arkaya değil","Yükleme rampasına varana kadar şeffaf bir filmle örtmek"],"explanation":"Plakartlar, bir köşesi tam yukarı bakacak şekilde köşesi üzerine döndürülmüş kare biçiminde, temiz ve okunabilir tutulan elmas şekillerdir."},"51":{"q":"Plakartlı (tehlike levhalı) römorkumu göndericinin yükleme rampasında yüklerken, aşındırıcı madde içeren bir varilin yan tarafından taze ıslak bir leke aktığını ve paket etiketinin kısmen yırtık olduğunu fark ediyorum. Gönderici bunun 'sadece biraz' olduğunu söyleyip, sefer programdan sapmasın diye varili yüklememi istiyor. Ne yapmalıyım?","options":["Paketi gönderici hazırlayıp belgelediği için olduğu gibi yükle; her türlü bildirim teslimattan sonra taşıyıcının işidir","Paketi reddet ve taşıma; çünkü sürücü, sızdıran veya hasarlı her tehlikeli madde sevkiyatını geri çevirmek zorundadır","Yükle ama sızıntı kontrol altında ve römork duvarlarından uzak kalsın diye diğer yükün tam ortasına derinlemesine göm","Yükle ama varış sırasında alıcının sızıntı konusunda uyarılması için sevk belgelerine bir not düş"],"explanation":"Sürücü, sevkiyatları kontrol etmeli ve sızdıran veya hasarlı herhangi bir tehlikeli madde paketini taşımayı reddetmelidir."},"52":{"q":"Az önce yanıcı bir sıvı yükünü tankerle teslim ettim ve gösterge tankın 'boş' olduğunu gösteriyor. Terminale geri dönmeden önce plakartları çıkarabilir miyim diye karar veriyorum. Tank bu 'boş' durumdayken, plakartları çıkarmak için EN AZ hangi koşulda gerekçem olur?","options":["Tank buharla temizlenmiş, tahliye edilmiş ve üründen tamamen arınmış olarak sertifikalandırıldığında","Hem sevkiyat belgeleri hem de taşıyıcı, tankın artık 'temizlenmiş ve tahliye edilmiş' standardını karşıladığını doğruladığında","Tankta son yükten kalan yapışkan kalıntı veya tehlikeli buharlar hâlâ bulunduğunda","Tank terminalde üç kez durulanmış ve boş olarak yeniden tartılmış olduğunda"],"explanation":"Bir tank yalnızca son yükten kalan yapışmış kalıntı veya tehlikeli buhar kalmadığında 'boş' sayılır, bu yüzden gerçekten temizlenene kadar plakartlar üzerinde kalmalıdır."},"53":{"q":"Göndericinin yalnızca sıradan tehlikeli madde değil, tehlikeli ATIK olarak sınıflandırdığı bir yükü teslim alıyorum ve tesisten, düzenlemelerin bu tür sevkiyat için özel olarak gerektirdiği o tek belgeyle ayrıldığımdan emin olmak istiyorum. Bu tehlikeli atık yüküne hangi belge MUTLAKA eşlik etmelidir?","options":["Sıradan ticari bir yük sevkiyatı için hazırlanmış standart bir konşimento (bill of lading)","Yalnızca olay anında başvurmak için kabinde tutulan Acil Müdahale Kılavuzu (ERG)","Kimyasalın özelliklerini ve elleçleme adımlarını açıklayan bir Güvenlik Bilgi Formu (SDS)","Atık sevkiyatıyla birlikte taşınan bir Tekdüze Tehlikeli Atık Manifestosu (Uniform Hazardous Waste Manifest)"],"explanation":"Tehlikeli atık sevkiyatları, atığı üretiminden taşınmasına ve nihai imhasına kadar izleyen bir Tek Tip Tehlikeli Atık Manifestosu ile birlikte taşınmalıdır."},"54":{"q":"Bölüm 1.1 patlayıcı maddeler taşıyan plakartlı bir yük taşıyorum ve römork içindeki bir yük bağlama elemanının gevşediğini fark ediyorum. Güvenle devam etmeden önce bağlantıları sıkmam gerekiyor. Bu işi yapmak için aşağıdakilerden hangisini kullanmalıyım?","options":["Patlayıcıları tutuşturabilecek herhangi bir kıvılcımı önlemek için pirinç veya bronzdan yapılmış kıvılcım çıkarmayan aletler","Standart çelik aletler, çünkü bağlantıları en sıkı kavrar ve işi en hızlı bitirirler","En yakındaki ağır çelik manivela, çünkü daha fazla kaldıraç gücü işi daha çabuk bitirmemi sağlar","Kırmızı güvenlik işareti ile boyanmış herhangi bir alet, çünkü kırmızı işaretli aletler tehlikeli madde işleri için onaylıdır"],"explanation":"Sınıf 1 patlayıcıların yakınındaki işler, metal metale çarpmasından çıkan tek bir kıvılcım patlayıcıları tutuşturabileceği için kıvılcım çıkarmayan pirinç veya bronz aletlerle yapılmalıdır."},"55":{"q":"Yükleme rampasında römorkumun dört tarafına da plaka levhalarını taktım ve yola çıkmadan önce her birinin okunabilir olduğunu doğruladım. Uzun yolun üçüncü saatinde yakıt almak için durdum ve yardımcı şoföre plakaların 'zaten halledildiğini' söyledim. Plakaların yerinde olduğunu doğrulamaktan ne zaman sorumlu olduğum konusunda hangi ifade doğrudur?","options":["Plakaları rampada doğruladıktan sonra sorumluluğum biter, çünkü plakalama yol öncesi muayenede kontrol edilir.","Plakaların yerinde olduğunu hem yolculuktan önce hem de yol boyunca seyir sırasında doğrulamak zorundayım.","Plakaları yalnızca teslimat noktasına vardığımda, alıcıyı tatmin etmek için yeniden kontrol etmem gerekir.","Plakalama yükleyicinin görevidir, bu yüzden yolda doğrulamak benim sürüş sorumluluğumun parçası değildir."],"explanation":"Plakartların hem yolculuk öncesinde hem de yolculuk sırasında yerinde olduğundan emin olmalısınız, çünkü sürüş sırasında gevşeyebilir, düşebilir veya görünmez hale gelebilirler."},"56":{"q":"Plakartlı bir aşındırıcı madde yükü taşırken, varillerden biri banketin üzerine sızmaya başlıyor. Sevkiyat belgelerini koltuktan çıkarırken, gönderenin bunlara acil durum müdahale bilgilerini iliştirdiğini fark ediyorum. İtfaiye ve tehlikeli madde ekibi olay yerine geldiğinde, gönderenin bu acil durum bilgisinin BİRİNCİL amacı nedir?","options":["Yükün perakende değerini listeler, böylece müdahale ekipleri önce hangi yükleri koruyacaklarına öncelik verebilir","Sıcak havada uzun mesafeli yolculuklar için taşıyıcının tercih ettiği yakıt türünü ve lastik basıncını söyler","Müdahale ekiplerine, tam olarak bu maddeden kaynaklanan sızıntı veya yangını güvenle ele almak için gereken ayrıntıları verir","TSA güvenlik taramamı tamamladığımı ve geçerli bir H onayına sahip olduğumu belgeler"],"explanation":"Acil müdahale bilgileri, müdahale ekiplerine o malzemeden kaynaklanan bir dökülme, sızıntı veya yangını güvenle ele almak için gereken özel verileri sağlamak üzere sevkiyat belgelerine eşlik eder."},"57":{"q":"Birkaç paket 7. sınıf radyoaktif madde yüklüyorum ve gönderici, her paketin etiketinde basılı bir sayıyı göstererek bu rakamları toplamam ve toplamı aracım için belirlenmiş bir sınırın altında tutmam gerektiğini söylüyor. Takip etmem söylenen bu sayının amacı nedir?","options":["Eşleşen plakartı römorkun hangi tarafına yerleştireceğimi gösteren bir renk kodudur","Radyoaktif yük araçtayken ne kadar hızlı sürebileceğimi sınırlayan bir hız derecelendirmesidir","Hangi belirlenmiş karayollarını kullanmama izin verildiğini gösteren bir güzergah indeksidir","Aracımda izin verilen toplam radyasyon maruziyetini sınırlayan bir taşıma indeksidir (transport index)"],"explanation":"Her radyoaktif paket bir taşıma indeksi taşır ve sürücü, araçtaki radyasyon maruziyetini kontrol etmek için bu indeksleri toplayıp toplamı belirli bir sınırın altında tutmalıdır."},"58":{"q":"Plakart taşıyan aşındırıcı (korozif) madde yükü taşırken bir tekerlek rulmanı arızası beni banket kenarına çekip yedek çekici beklemeye zorluyor. Sevkiyat görevlisi telsizle yakında başka bir şirket kamyonu olduğunu söylüyor ve teslimatın gecikmemesi için ürünü ona aktarmamı öneriyor. Hangi yanıt doğru tehlikeli madde uygulamasına en uygundur?","options":["Yol kenarındaki aktarmayı reddetmek; tehlikeli madde araçlar arasında yalnızca gerçek bir acil durumda taşınmalıdır, bu yüzden onarımı veya uygun düzenlemeleri beklemeliyim","Aktarmayı yapmak, çünkü teslimatı programa uygun tutmak taşıyıcının birinci önceliğidir","Yalnızca her iki araca yeniden plakart taktıktan sonra aktarmak; bu, yol kenarındaki aktarmayı tamamen kabul edilebilir kılar","Yük zaten durdurulmuş ve yolun kullanılan kısmının dışına güvenle park edilmiş olduğu için aktarmayı yapmak"],"explanation":"Tehlikeli madde araçlar arasında yalnızca gerçek bir acil durumda aktarılmalıdır, bu yüzden rutin bir arıza veya geç teslimat yol kenarında aktarım için bir neden değildir."},"59":{"q":"Limana yapacağım sefer öncesinde, göndericinin belgelerinde deniz kirletici madde olarak tanımlanan bir yükü yüklüyorum. Muayenemi tamamlayan sürücü olarak, bu yükü taşımayı kabul etmeden önce aşağıdaki koşullardan hangisi sağlanmalıdır?","options":["Deniz kirletici etiketleri, deniz terminaline varana kadar örtülü kalabilir","Paket, ben taşımadan önce gerekli deniz kirletici işaretlerini taşımalıdır","Yük önce karayoluyla gittiği için deniz kirletici işaretleri konulmayabilir","Yükü yolda güvende tutmak için konteyner görüş alanından gizlenmelidir"],"explanation":"Bir deniz kirletici, taşımadan önce ambalaj üzerinde gerekli işaretleri göstermelidir ve sürücü, uygunsuz işaretlenmiş herhangi bir tehlikeli madde sevkiyatını reddetmelidir."},"63":{"q":"Yanıcı sıvı yükü için plaka (placard) takılmış bir çekici-römork üzerinde sefer öncesi muayenemi yapıyorum. Yola çıkmadan önce yangın söndürücümün federal şartı karşıladığından emin olmak istiyorum. Aşağıdakilerden hangisi kuralı gerçekten karşılar?","options":["Söndürücü, mühürlü römorkun içinde yükle birlikte kilitli kalabilir, çünkü yangın büyük olasılıkla orada başlar.","Tam dolu bir söndürücü, yük için doğru sınıfta olduğu sürece yük kayışlarının arkasına gömülü olsa bile uygundur.","Söndürücü, yükün sınıfına uygun, tam dolu ve hızlıca ulaşabileceğim bir yere monte edilmiş olmalıdır.","Küçük dolu herhangi bir söndürücü işe yarar, çünkü sınıf yalnızca alıcının rıhtım ekipmanı için önemlidir, kamyon için değil."],"explanation":"Plakartlı bir aracın yangın söndürücüsü, yük için uygun şekilde derecelendirilmiş, tam dolu ve sürücünün hızlıca ulaşabileceği bir yere monte edilmiş olmalıdır."},"67":{"q":"Plakartı takılı yanıcı sıvı yükü taşıyorsunuz ve 2 saatlik lastik kontrolü için bir dinlenme alanına giriyorsunuz. Römorkunuzun lastiklerinden birinin dokunulamayacak kadar sıcak olduğunu ve açıkça aşırı ısındığını fark ediyorsunuz. Aşağıdakilerden hangisi yapılması gereken doğru harekettir?","options":["Sıcak lastiğin üzerine su dökerek hızlıca soğutun, ardından teslimat programına yetişmek için yola devam edin.","Sıcak lastiği doğru basınca getirmek için hava basın ve planlanan güzergaha devam edin.","Tam yüklü, plakartı takılı bir römorkta bir miktar ısınma normal olduğu için lastiği yerinde bırakıp yola devam edin.","Aşırı ısınmış lastiği söküp araçtan güvenli bir mesafeye koyun, ardından yola devam etmeden önce kontrol edin."],"explanation":"Plakartlı bir yükte bir lastik aşırı ısınırsa yangın tehlikesi oluşturur, bu yüzden onu çıkarın, araçtan güvenli bir mesafeye koyun ve devam etmeden önce kontrol edin."},"69":{"q":"Son tehlikeli madde paletimi alıcıya yeni teslim ettim ve römork artık tamamen boş ve kalıntısız, ancak dört plaka hâlâ takılı duruyor. Şimdi otoyoldan boş olarak depoya geri döneceğim. Bu boş yolculukta yasalara uygun kalmamı hangi davranış sağlar?","options":["Plakaları şimdi sökmek veya kapatmak, çünkü römork artık bunları gerektiren bir yük taşımıyor.","Plakaları dönüş yolunun tamamında takılı bırakmak, çünkü plakalı bir römork diğer sürücüler tarafından her zaman daha güvenli kabul edilir.","Plakaları yalnızca ilk demiryolu geçidine kadar takılı bırakmak, sonra durakta sökmek.","Aslında ikisi de fark etmez, bu yüzden zaman kazandırıyorsa plakaları boş römorkta bırakabilirim."],"explanation":"Araç artık yasal olarak plakart gerektiren bir yük taşımadığında, kargoyu yanlış göstermemesi için plakartlar çıkarılmalı veya kapatılmalıdır."},"70":{"q":"Plakartlı bir yükün sefer öncesi kontrolünü yapıyorum ve imzalamadan önce taşıma belgesini paketle karşılaştırıyorum. Kayıtta zaten uygun taşıma adı ve tehlike sınıfı yer alıyor. Kaydın eksiksiz ve yasal olması için aynı kayıtta MUTLAKA bulunması gereken KALAN bilgi hangisidir?","options":["Belirlenen tehlikeli madde güzergâhımda kat edeceğim toplam mesafe","Maddenin kimlik (ID) numarası (UN/NA)","Taşıyıcı için 24 saat açık CHEMTREC telefon numarası","Dış varilin üzerine basılmış paketleme grubu harfi"],"explanation":"Eksiksiz bir sevkiyat belgesi girişi; uygun sevkiyat adını, tehlike sınıfını ve UN/NA kimlik numarasını bu sırayla içerir."},"71":{"q":"Bir tartı istasyonunda durdum ve müfettiş, römorkumdaki elmas şeklindeki plaka (placard) altındaki turuncu panele işaret ediyor; panelde kalın siyah \"1203\" sayısı yazılı. Bu dört haneli sayının acil müdahale ekiplerine ne anlattığını soruyor. Doğru açıklama hangisidir?","options":["Bu, o bölmeye yüklenen tehlikeli maddenin libre cinsinden brüt ağırlığıdır","Bu, yükün tehlikesini 1'den 9'a kadar sıralayan tehlike sınıfı bölüm kodudur","Bu, taşınan belirli maddeyi adlandıran UN/NA kimlik numarasıdır","Bu, ekiplerin yük hakkında CHEMTREC'e ulaşmak için aradığı acil telefon kodudur"],"explanation":"Plakart veya turuncu panel üzerindeki dört haneli numara, taşınan belirli maddeyi belirten UN/NA kimlik numarasıdır."},"72":{"q":"Bir nakliye aracısı, römorkumun dört tarafında da plakart (tehlike levhası) gerektirecek aşındırıcı (korozif) bir madde yükü teklif ediyor. CDL ehliyetimde zaten Tanker (N) ve İkili/Üçlü Römork (T) onayları var ve sağlık raporumu yeni yeniledim. Bu sevkiyatı yasal olarak kabul edip taşıyabilmem için neyi tamamlamış olmam gerekir?","options":["Başka hiçbir şey — yüküm aşındırıcı (Sınıf 8) olduğundan ve patlayıcı olmadığından, plakartlar tek başına yasal gerekliliği karşılar ve özel bir onaya gerek yoktur.","Yalnızca zaten sahip olduğum Tanker (N) onayı, çünkü federal kurallara göre plakartlı herhangi bir madde, dökme sıvı tehlikesi olarak kabul edilir.","Güncel bir Yolcu (P) onayı, çünkü kamu güvenliğini etkileyen düzenlenmiş bir yükü taşımak, yolcu taşımakla aynı şekilde değerlendirilir.","Tehlikeli Madde (H) onayı; herhangi bir plakartlı tehlikeli maddeyi taşıyabilmem için parmak izi alınarak yapılan bir TSA güvenlik tehdidi değerlendirmesini geçmemi gerektirir."],"explanation":"Plakart gerektiren herhangi bir tehlikeli maddeyi taşımak, parmak izi alınarak yapılan TSA güvenlik tehdit değerlendirmesini zorunlu kılan HazMat (H) onayını gerektirir."},"73":{"q":"Zaten A Sınıfı CDL ehliyetim var ve yol sınavımı geçtim, ancak şimdi plaka (placard) gerektiren tehlikeli madde taşımak istiyorum. Yazılı Tehlikeli Madde bilgi sınavını geçmenin yanı sıra, H onayı ehliyetime eklenmeden önce yerine getirmem gereken TEK ek şart nedir?","options":["Parmak izi alımı ve geçmiş kontrolü içeren bir TSA güvenlik tehdit değerlendirmesini tamamlamalıyım","Plakalı bir araçta ikinci, ayrı bir yol sınavını geçmeliyim","Ön koşul olarak önce tanker (N) onayımı almalıyım","Ehliyetime ikili/üçlü römork (T) onayını eklemeliyim"],"explanation":"HazMat (H) onayı, başvuru sahiplerinin parmak izi alma ve sicil kontrolü içeren bir TSA güvenlik tehdit değerlendirmesini geçmesini gerektiren tek onaydır."},"76":{"q":"Yanıcı sıvı yüküm ve plaka (placard) etiketlerimle bir dinlenme tesisine park ettim. Başka bir sürücü sohbet etmek için yanıma geliyor ve aracıma yaklaşırken bir sigara yakıyor. Güvenliğimiz için, plakalı aracımın yakınında en fazla ne kadar yakına kadar sigara içmesine izin verilmelidir?","options":["Yaklaşık 15 fitten daha yakın olmamalı — demir yolu rayları öncesindeki mesafeyle aynı","Plakalı araçtan yaklaşık 25 fitten daha yakın olmamalı","Yaklaşık 5 fitten daha yakın olmamalı — yoldan park etme mesafesiyle aynı","Yük sızdırmaz şekilde kapalı olduğundan kabin dışında herhangi bir yer uygundur"],"explanation":"Patlayıcı, oksitleyici veya yanıcı madde taşıyan plakartlı bir aracın yaklaşık 25 fit yakınında sigara içmek yasaktır."},"77":{"q":"Bir yük alıyorum ve sevkiyat belgesinde malzeme 7. tehlike sınıfı olarak listelenmiş. Plaka takıp paketleri incelemeden önce, gerçekte hangi tehlikeyi taşıyacağımı doğrulamak istiyorum. Belirtilen tehlike sınıfına göre dorsemde ne var?","options":["Benzin veya motorin gibi yanıcı bir sıvı","Cildi yakabilen ve metale zarar verebilen aşındırıcı (korozif) bir sıvı","Radyoaktif bir madde","Yüksek basınç altında sıkıştırılmış bir gaz"],"explanation":"Federal tehlike sınıfı sisteminde Sınıf 7 her zaman radyoaktif maddeler anlamına gelir."},"78":{"q":"Plakartlı bir yük hazırlıyorum ve sevk belgemde kargonun tehlike sınıfı 'Sınıf 1' olarak yazılı. Doğru park edip yükü doğru taşımak için gerçekte ne taşıdığımı bilmem gerekiyor. Sınıf 1 ibaresi bana yükün şu olduğunu söyler:","options":["Sınıf 3 kapsamına giren benzin veya motorin gibi yanıcı sıvılar","Sınıf 8 altında toplanan asit ve bazlar gibi aşındırıcı (korozif) sıvılar","Sınıf 2'ye ait olan sıkıştırılmış veya yanıcı gazlar","Sınıf 1 kapsamına giren patlayıcı maddeler"],"explanation":"Sabit tehlike sınıfı numaralandırmasında Sınıf 1 her zaman patlayıcılar anlamına gelir."},"79":{"q":"Yükümün sevkiyat belgelerini inceliyorum ve bir kayıtta tehlike sınıfı, malzemenin BM numarasıyla birlikte \"2.1\" olarak listelenmiş. Tehlike sınıfı numaralandırma sistemine göre aslında ne tür bir malzeme taşıyorum?","options":["Yanıcı bir gaz, çünkü Sınıf 2 gazları kapsar (2.1 ise yanıcı olanıdır)","Yanıcı bir sıvı, çünkü bu en yaygın yanıcı kargo sınıfıdır","Bir patlayıcı, çünkü düşük sınıf numarası şiddetli tutuştuğu anlamına gelir","Radyoaktif bir malzeme, çünkü özel bir BM kimlik numarası taşıyor"],"explanation":"Sınıf 2 gazları kapsar ve 2.1 bölümü özellikle yanıcı gazı belirtir."},"80":{"q":"Bir yük alıyorum ve sevkiyat belgesinde kayıt \"Aseton, 3, UN1090\" olarak listelenmiş. Sevkiyatçı, doğru levhaları (plakartları) almam için ortadaki bu sayının bana hangi tehlike türünü taşıdığımı anlattığını onaylamamı istiyor. Gösterilen tehlike sınıfına göre ne taşıyorum?","options":["Sürtünmeyle tutuşabilen yanıcı bir katı","Tutuşabilir buharlar yayan yanıcı bir sıvı","Basınç altında yanıcı bir sıkıştırılmış gaz","Yangını şiddetlendiren oksitleyici bir madde"],"explanation":"Sınıf 3 her zaman, tutuşabilir buharlar açığa çıkaran yanıcı sıvılar anlamına gelir."},"81":{"q":"Bir yük için sevk evrakı hazırlıyorum ve girişteki tehlike sınıfı \"Sınıf 4\" olarak yazıyor. Doğru levhayı takmadan önce, bu maddenin hangi genel kategoriye girdiğini doğrulamak istiyorum. Tehlike sınıfı sistemine göre Sınıf 4 bir madde aşağıdakilerden hangisi olarak tanımlanır?","options":["Cildi ve metali tahrip edebilen aşındırıcı bir sıvı","Benzin veya akaryakıt gibi yanıcı bir sıvı","Kendiliğinden yanabilen ve ıslandığında tehlikeli maddeler dahil olmak üzere yanıcı bir katı","Darbe veya ısı altında patlayan patlayıcı bir madde"],"explanation":"Sınıf 4, kendiliğinden yanabilen ve ıslanınca tehlikeli olan maddeler dahil yanıcı katıları kapsar."},"82":{"q":"Bir sonraki yüküm için sevkiyat belgelerini inceliyorum ve tehlike sınıfı sütununda Sınıf 5 tehlikeli madde yazıyor. Sevkiyatı kabul edip plaka takmadan önce, gerçekte ne tür bir madde taşıyacağımı doğrulamam gerekiyor. Hangi açıklama Sınıf 5 maddesine doğru şekilde uyar?","options":["Benzin, dizel katkı maddeleri ve çözücüler gibi yanıcı sıvılar","Akü asidi ve diğer güçlü sıvılar gibi aşındırıcı maddeler","Soluma tehlikesi oluşturan zehirler ve toksik sıvılar","Oksitleyiciler ve organik peroksitler"],"explanation":"Sınıf 5, oksitleyiciler ve organik peroksitler grubudur."},"83":{"q":"Terminalden ayrılmadan önce bir yük için sevkiyat belgelerini inceliyorum ve bir kayıt Sınıf 6 olarak işaretlenmiş. Gönderici henüz doğru sevkiyat adını yazmadı ve belgelerin tehlikeyle eşleşmesi için Sınıf 6 plakasının hangi tür maddeyi kapsadığını doğrulamamı istiyor. Hangi tanım Sınıf 6 kapsamına gireni doğru şekilde belirtir?","options":["Zehirler (toksik) ve bulaşıcı maddeler","Benzin ve yaygın çözücüler gibi yanıcı sıvılar","Cildi ve metali yakabilen aşındırıcı sıvılar","Yangını şiddetlendiren oksitleyiciler ve organik peroksitler"],"explanation":"Sınıf 6, zehirli (toksik) maddeleri ve bulaşıcı maddeleri kapsar."},"84":{"q":"Sefer öncesi kontrolümü yapıyorum ve 8. sınıf tehlike içerdiği belirtilen bir yük için taşıma evraklarını inceliyorum. Konteynerlere dokunmadan ve doğru eldiven ile göz korumasını seçmeden önce, bu maddenin gerçekte ne tür bir tehlike taşıdığını bilmem gerekiyor. Hangi ifade 8. sınıf bir maddenin ne olduğunu doğru şekilde tanımlar?","options":["Kıvılcımdan tutuşabilen yanıcı bir sıvıdır, bu yüzden asıl endişem tüm tutuşturucu kaynakları yükten uzak tutmaktır.","Cildi, gözleri ve metali kimyasal olarak yakabilen aşındırıcı (korozif) bir maddedir, bu yüzden asıl endişem teması önlemek ve yüzeyleri korumaktır.","Şiddetli şekilde patlayabilen basınç altındaki sıkıştırılmış bir gazdır, bu yüzden asıl endişem tüpleri serin ve sabitlenmiş tutmaktır.","Zararlı radyasyon yayan radyoaktif bir maddedir, bu yüzden asıl endişem yükün yakınında geçirdiğim süreyi sınırlamaktır."],"explanation":"Sınıf 8 aşındırıcılardır; temas hâlinde deriyi, gözleri ve metali kimyasal olarak yakar, bu yüzden öncelik teması önlemek ve yüzeyleri korumaktır."},"85":{"q":"Bir yükün taşıma evraklarını inceliyorum ve Sınıf 9 tehlikeli madde olarak sınıflandırılmış bir kayıt görüyorum. Eğitmenim, bu sınıflandırmanın kargo hakkında bana gerçekte ne anlattığını soruyor. Sınıf 9 tanımının ne anlama geldiğini hangi ifade doğru şekilde açıklar?","options":["Bölüm 2.3 ürününü tanımlar, yani yük herhangi bir miktarda plaka gerektiren zehirli gazdır","Yanıcı sıvıyı tanımlar; taşıma evrakındaki tehlike Sınıf 3 ile aynı kategoridir","Diğer sekiz tehlike sınıfının hiçbirine tam olarak uymayan muhtelif (çeşitli) tehlikeli maddeyi tanımlar","Patlayıcı bir maddeyi tanımlar; tehlike Sınıf 1 plaka kurallarının kapsadığı kargo ailesiyle aynıdır"],"explanation":"Sınıf 9, diğer sekiz tehlike sınıfının hiçbirine uymayan tehlikeli maddeler için çeşitli (muhtelif) kategoridir."},"86":{"q":"Plakart gerektiren aşındırıcı (korozif) bir yük taşıyorum ve bir trafik polisi beni kantar istasyonuna alıyor. Durduğu yerden yalnızca bir plakart görebildiğini söyleyip aracımın nasıl plakartlanması gerektiğini doğrulamamı istiyor. Hangi ifade doğru plakart yerleşimini anlatır?","options":["Plakart yalnızca römorkun arkasında gereklidir, çünkü arkamdaki trafik ve müfettişler onu okur","Sürücü tarafındaki tek bir plakart, baktığı yönden okunabildiği sürece yeterlidir","Plakartlar yalnızca çekicinin önünde ve römorkun arkasında bulunur, böylece önden ve arkadan görülür","Plakartlar aracın dört tarafına da yerleştirilmeli ve her biri baktığı yönden okunabilir olmalıdır"],"explanation":"Plakartlar aracın dört tarafına da takılmalı ve her biri baktığı yönden okunabilir olmalıdır."},"87":{"q":"Yola çıkmadan önce ön kontrol yapıyorum ve tehlikeli madde (HazMat) plakartı gerektiren bir yük taşımadan önce römorkumdaki uyarı işaretlerinin doğru olduğunu teyit etmem gerekiyor. Aracın her bir tarafına doğru şekilde yerleştirilmiş bir HazMat plakartına baktığımda, genel olarak hangi şekilde olmasını beklemeliyim?","options":["Eşkenar dörtgen, yani köşelerinden birinin (ucunun) üzerinde duracak şekilde döndürülmüş bir kare","Üçgen, yanımda taşıdığım yansıtıcı uyarı üçgenleriyle aynı şekil","Eninden daha geniş, kimlik numarası paneli gibi bir dikdörtgen","Trafik işareti sembolü gibi renkli bir halkayla çevrelenmiş bir daire"],"explanation":"Tehlikeli madde plakartı baklava (eşkenar dörtgen) biçimindedir — bir köşesi üzerinde duran, dik konuma getirilmiş bir karedir."},"88":{"q":"Plakartlı (tehlike levhalı) bir yük taşıyorum ve sefer öncesi kontrolde, römorkumun sağ tarafındaki plakartın yol kiriyle bulaşmış ve bir kayış askısıyla kısmen kapanmış olduğunu fark ediyorum; diğer üç plakart ise temiz. Yola çıkmadan önce Texas DPS bu sağ taraftaki plakartla ilgili benden ne yapmamı ister?","options":["Ekstra bir şey yok, çünkü ön ve arka plakartlar temiz ve okunaklı kaldığı sürece yan plakartların görünürlüğü düzenlemeye tabi değildir","Onu temizlemek ve kayış askısını yeniden konumlandırmak, böylece plakart okunaklı ve kapanmamış olur; çünkü dört taraftaki plakartların hepsi baktıkları yönden görünür olmalıdır","O plakartı tamamen çıkarmak, çünkü kısmen kirli bir plakart hiç plakart yokmuş gibi sayılır ve kalan üçü yükü işaretlemeye yeter","Olduğu gibi bırakmak ve durumu sevk belgelerime not etmek, böylece müfettiş benim bunun farkında olduğumu bilir"],"explanation":"Dört taraftaki plakartlar baktıkları yönden okunabilir olmalı, bu yüzden kirli ya da engellenmiş bir plakart sürüşten önce temizlenip açığa çıkarılmalıdır."},"89":{"q":"Karışık yük yüklüyorum ve paletlerden biri, plaka (etiket) kurallarının 2. Tablosunda listelenen tehlikeli bir maddedir. Bir iş arkadaşım bana, 'Tehlikeli madde tehlikeli maddedir — ondan herhangi bir miktarı römorka girer girmez plaka asmak zorundasın' diyor. Dört tarafa herhangi bir şey asmadan önce, bu yük için gerçekten plaka gerekip gerekmediğine nasıl karar vermeliyim?","options":["Herhangi bir miktar plakayı gerektirir, bu yüzden tek bir tehlikeli madde paketi araca girdiği anda dört tarafa da plaka asmalıyım","Plakalar yalnızca ambalaja bağlıdır, bu yüzden sadece gıda ve gıda dışı ürünler birlikte yüklendiği için plaka asarım","Maddenin sınıfına ve miktarına bağlıdır — bazı sınıflar herhangi bir miktarda plaka gerektirirken, bu 2. Tablo maddeleri yalnızca toplam brüt ağırlık 1.001 lb veya daha fazla olduğunda plaka gerektirir","Karışık yük için plaka yasal olarak asla gerekmez, bu yüzden bu seferde tamamen atlayabilirim"],"explanation":"Plakart takma sınıfa ve miktara bağlıdır; bazı sınıflar her miktarda plakart gerektirir, Tablo 2 maddeleri ise yalnızca toplam brüt ağırlık 1.001 lb veya üzeri olduğunda gerektirir."},"90":{"q":"Treyleri bir rampada, Tablo 2'deki farklı tehlike sınıflarına ait dökme olmayan (ambalajlı) birkaç paketle yüklüyorum. Araçtaki hiçbir tek tehlike sınıfı tek başına 1.001 pounda ulaşmıyor, ancak birleşik Tablo 2 yükü bu eşiği aşıyor. Bir iş arkadaşım, her sınıf için ayrı bir plaka yerine tüm karışık yük için tek bir DANGEROUS plakası asabileceğimi söylüyor. Plaka kurallarına göre DANGEROUS plakasını kullanmak gerçekte ne zaman izinlidir?","options":["Yalnızca treylerin tamamı, ağırlığı 1.001 pound veya daha fazla olan tek bir Tablo 2 malzemesinden oluşan tek bir tam yük olduğunda","Asla, çünkü araçtaki her tehlike sınıfı istisnasız olarak her zaman kendi özel plakasını taşımak zorundadır","Yalnızca yük, herhangi bir miktarda plakalandırma gerektiren Sınıf 1 patlayıcılardan oluştuğunda","İki veya daha fazla Tablo 2 tehlike sınıfından oluşan belirli dökme olmayan yükleri taşıdığımda, bu karışık küçük yük için DANGEROUS plakası kullanılabilir"],"explanation":"TEHLİKELİ (DANGEROUS) plakartı, iki veya daha fazla Tablo 2 tehlike sınıfını karıştıran dökme olmayan yükler için ayrı sınıf plakartlarının yerine kullanılabilir."},"91":{"q":"Sınıf 3 yanıcı sıvı yüklüyorum ve malzeme kutumda kalan tek plakartlar, önceki seferimden kalan Sınıf 8 (aşındırıcı) plakartları. Yola çıkmadan önce, aracımdaki plakartlarla ilgili yapmam gerekeni hangi ifade doğru biçimde yansıtır?","options":["Taktığım plakartlar gerçekten taşıdığım malzemenin tehlike sınıfını göstermelidir, bu yüzden Sınıf 3 yükü için Sınıf 8 plakartlarını kullanamam.","Elmas (baklava) biçiminde olup aracın dört tarafına da takıldığı sürece her DOT tipi plakart kabul edilebilir.","Doğru Sınıf 3 sevkiyat belgelerini kabinde elimin ulaşabileceği yerde tuttuğum sürece Sınıf 8 plakartlarıyla yola çıkabilirim.","Plakartların yükle eşleşmesi yalnızca eyalet sınırını geçerken gereklidir, bu nedenle eyalet içi sefer için Sınıf 8 plakartları sorun değildir."],"explanation":"Plakartlar taşıdığınız maddenin gerçek tehlike sınıfına uymalıdır, bu yüzden sınıf 3 yük için sınıf 3 plakart gerekir."},"92":{"q":"Plakart gerektiren 3. sınıf yanıcı sıvı yüklü kapalı kasa römorkumun yola çıkmadan önceki kontrolünü bitiriyorum ve plakartlarımın doğru şekilde takılı olduğunu teyit etmek istiyorum. Yasal olarak yola çıkabilmem için bu koşullardan hangisinin sağlanması gerekir?","options":["Plakartlar yalnızca ön ve arkada olsun, çünkü diğer sürücülerin gerçekte okuduğu taraflar bunlardır","Aracın dört tarafının her birinde birer plakart bulunmalı ve her biri baktığı yönden okunabilecek şekilde sabitlenmiş olmalı","Römorkun her iki yanında plakartlar, artı her birinin yanına yapıştırılmış bir sevk belgesi kopyası","Römork tavanına düz şekilde monte edilmiş tek bir plakart, böylece görünür kalır ve yol sıçramalarından korunur"],"explanation":"Plakartlı tehlikeli madde aracı dört tarafın tümünde plakart taşımalı; her biri sabitlenmiş ve baktığı yönden okunabilir olmalıdır."},"93":{"q":"Plakartlı (placard) bir yükün sefer öncesi muayenesinde, dört zorunlu plakarttan birinin güneşte o kadar solduğunu, tehlike sınıfı numarasının zar zor okunabildiğini, yine de güçlükle seçebildiğimi fark ediyorum. Sefere başlamadan önce doğru hareket nedir?","options":["Plakart dikkatlice bakıldığında hâlâ silik de olsa okunabildiği için yerinde bırakmak","Daha fazla solmasını önlemek için solmuş plakartı şeffaf bantla kaplamak","Solmuş plakartı, sefere başlamadan önce yeni ve tam okunabilir bir plakartla değiştirmek","Diğer üç plakart net olduğu sürece yola devam edip bir sonraki durakta değiştirmek"],"explanation":"Solmuş veya hasarlı bir plakart, yolculuk başlamadan önce tam okunabilir yenisiyle değiştirilmelidir."},"94":{"q":"Plakartlı bir yük alıyorum ve gönderici bana sevkiyat belgelerini veriyor. İmzalayıp yola çıkmadan önce bu belgelerle ilgili neyi doğrulamam gerekir?","options":["Yalnızca uygun sevkiyat adının yazılı olduğunu, tehlike sınıfı ve kimlik numarasının sonradan eklenebileceğini","Bir kopyanın terminalde bırakıldığını, çünkü kısa eyalet içi taşımalarda asıl nüshanın isteğe bağlı olduğunu","Bazı tehlikeli madde bilgileri hâlâ eksik olsa bile en az bir kaydın doldurulmuş olduğunu","Yükü taşımadan önce her tehlikeli madde kaydının doğru ve eksiksiz olduğunu"],"explanation":"Tehlikeli madde sevk belgeleri yükü taşımadan önce doğru ve eksiksiz olmalı; her kayıt uygun sevk adı, tehlike sınıfı ve kimlik numarasını göstermelidir."},"95":{"q":"Eyaletler arası otoyolda, plakartlı bir aşındırıcı madde yükü taşıyorum, emniyet kemerim bağlı. Bir devriye memuru beni herhangi bir mil işaretinde durdurabilir. Texas DPS kurallarına göre, ben sürüş halindeyken tehlikeli madde sevk belgelerim TAM ŞU ANDA nerede bulunmalıdır?","options":["Emniyet kemeri bağlıyken erişebileceğim mesafede ya da sürücü kapısındaki cepte, diğer belgelerimin en üstünde","Temiz kalsınlar ve asıl yükle birlikte taşınsınlar diye römorkun içinde yüke kilitlenmiş halde","Sert frende koltuktan kaymasınlar diye yolcu tarafındaki torpido gözüne yerleştirilmiş halde","Yalnızca her seferden önce taşıyıcının sevkiyat birimine bir kopyasını faksla gönderen gönderici tarafından tutuluyor"],"explanation":"Sürüş sırasında tehlikeli madde sevk belgelerini emniyet kemeri takılıyken erişebileceğiniz yerde veya sürücü kapısı cebinde, diğer kağıtların üstünde tutun."},"96":{"q":"Plakartlı bir yükü yüklüyorum ve dock'tan ayrılmadan önce sevk irsaliyesini kontrol ediyorum. Tehlikeli madde, aynı sayfada birkaç tehlikesiz yük kaydının arasına karışmış durumda. İrsaliyenin kabul edilebilir olması için tehlikeli madde kaydı diğer kalemler arasında nasıl görünmelidir?","options":["Doğru sevkiyat adı, tehlike sınıfı ve kimlik numarası bulunduğu sürece yükler arasında herhangi bir yere yazılabilir","İlk sırada listelenmeli ya da vurgulama veya HM sütununda bir 'X' ile açıkça tanımlanarak tehlikesiz yükten ayırt edilecek şekilde öne çıkmalıdır","Tehlikesiz yükün toplam ağırlığı üstte toplanacak şekilde sayfanın en son satırına yerleştirilmelidir","Yalnızca gönderici veya teslim alan tesis özellikle talep ederse ayrıca işaretlenmesi gerekir"],"explanation":"Karışık sevk belgesinde tehlikeli madde kaydı, ilk sırada yazılarak ya da HM sütununda renklendirme veya 'X' işaretiyle belirginleştirilmelidir."},"97":{"q":"Plakartlı bir aşındırıcı madde yükü taşırken, varillerimden birindeki bir bağlantı parçası sızmaya başlıyor ve dumanlar banketin üzerine doğru savruluyor. Güvenli bir şekilde kenara çekiyorum, başkalarını uyarıyorum ve kabinde tuttuğum Acil Müdahale Kılavuzu'na (ERG) uzanıyorum. ERG bu anda bana aslında hangisini yapmamda yardımcı olmak için tasarlanmıştır?","options":["Kantarlardan ve ücretli yollardan kaçınan en hızlı sapağı ileride belirlemek","Evrak işlerim için uygun sevkiyat adını, tehlike sınıfını ve kimlik numarasını doğrulamak","Dökülen madde için başlangıç izolasyon mesafesini ve koruyucu önlemleri belirlemek","Hangi plakartların gerektiğini ve römorkun hangi taraflarına ait olduklarını doğrulamak"],"explanation":"Acil Müdahale Kılavuzu (ERG), dökülen veya sızan madde için başlangıç izolasyon mesafesini ve koruyucu önlemleri verir."},"98":{"q":"Plakartlı bir aşındırıcı (korozif) madde yükü alıyorum ve elimdeki taşıma belgelerinde doğru taşıma adı, tehlike sınıfı ve kimlik numarası ile en altta imzalı bir sertifikasyon beyanı yer alıyor. Bir CDL sürücüsü olarak görevimin yükü incelemek, sızdıran herhangi bir şeyi reddetmek, aracı plakartlamak ve bu belgeleri erişebileceğim mesafede tutmak olduğunu biliyorum. Ama malzemenin doğru tanımlandığını ve taşımaya uygun şekilde hazırlandığını onaylayan o imzalı satıra baktığımda, aslında kimin sertifikasyonuna bakıyorum?","options":["Taşıyıcının, çünkü nakliye şirketi yükü sevk eder ve taşıma sırasında meydana gelen herhangi bir olayı bildirmekten sorumludur","Sürücü olarak benim, çünkü yükü inceleyen, aracı plakartlayan ve sürerken belgeleri erişimimde tutan kişi benim","Belirli olarak kimsenin değil, çünkü sertifikasyon satırı sadece bir formaliteden ibarettir ve gerçek yasal sorumluluk tamamen yükü teslim alan kişiye aittir","Gönderenin (sevkiyatçının), çünkü gönderen malzemeyi sınıflandırır, paketler, işaretler ve taşıma belgelerini hazırlar, sonra malzemenin doğru tanımlandığını onaylar"],"explanation":"Gönderici maddeyi sınıflandırır, paketler, işaretler ve sevk belgelerini hazırlar, sonra maddenin doğru tanımlandığını onaylar."},"99":{"q":"Yükleme rampasındayım ve bir varil aşındırıcı sıvıyı teslim almak üzereyim. Sevk belgesini imzalamadan önce, tehlikeli madde kaydının doğru tanımlandığından emin olmak istiyorum. Kaydın geçerli bir tehlikeli madde tanımı sayılması için o satırda gerçekte hangi bilgilerin bulunması gerekir?","options":["Uygun sevkiyat adı, tehlike sınıfı ve kimlik (UN/NA) numarası, tam olarak bu sırayla listelenmiş hâlde","Tehlike sınıfı etiketinin rengi, plaka üzerindeki yazı ve plakada gösterilen dört haneli numara","Yükün perakende değeri, toplam brüt ağırlığı ve varış yerinin posta kodu","Yalnızca HM sütunundaki bir 'X' işareti, çünkü tehlikeli bir kaydı yasal olarak tanımlayan tek şey bu işarettir"],"explanation":"Tehlikeli madde kaydı, uygun sevk adını, tehlike sınıfını ve kimlik (UN/NA) numarasını tam olarak bu sırayla içermelidir."},"100":{"q":"Plakartlı bir aşındırıcı madde yükü taşıyorum ve tuvaleti kullanmak için bir dinlenme tesisine giriyorum. Kabinden çıkıp birkaç dakikalığına kamyonumdan uzaklaşacağım. Tehlikeli madde kurallarına göre, araçtan uzaktayken sevkiyat belgelerimi nerede bırakmalıyım?","options":["Görünmesin diye mandalı kapatılmış torpido gözünün içinde katlanmış halde","Sürücü koltuğunun üzerinde veya sürücü kapısının cebinde","Tanımladıkları yükle birlikte römorkta kilitli halde","Yolcu tarafındaki güneşliğin arkasına sıkıştırılmış halde"],"explanation":"Kamyondan ayrılırken tehlikeli madde sevk belgelerini, müdahale ekiplerinin hızla bulabilmesi için sürücü koltuğuna veya sürücü kapısı cebine bırakın."},"101":{"q":"Levhalı bir yükle kantar istasyonundayım ve müfettiş benden yalnızca taşıma evraklarına bakarak taşıdığım tehlikeli maddenin toplam miktarını göstermemi istiyor. Uygun sevkiyat adı, tehlike sınıfı ve kimlik numarası dışında, taşıma evraklarım o kayıt için aslında hangi değeri gösterir?","options":["Kamyonumun tüm akslarının toplam ağırlığı","Yük için önerilen soğuk lastik basıncı","Taşınan tehlikeli maddenin toplam miktarı","Sefer başından beri kaydedilen motor saatleri"],"explanation":"Sevkiyat belgeleri her kalem için tehlikeli maddenin toplam miktarını listeler, bu nedenle araçtaki miktar doğrudan bu rakamdan alınır."},"102":{"q":"Plakartlı tankerimi yükleme rampasına geri geri yanaştırdım ve gönderici ekibi ürünü dorseye pompalamaya hazır. Yüklemenin başlamasına izin vermeden önce, aracın kendiliğinden hareket etmesini önlemek için yapmam gereken en önemli işlem hangisidir?","options":["Tüm süre boyunca tam hava basıncına sahip olmak için motoru yüksek rölantide çalışır halde bırakmak","Rampa ekibinin dolum vanalarına daha kolay ulaşması için ön ve arka plakartları sökmek","Aktarım sırasında basıncın dengelenmesi için önce dorsenin boşaltma ve havalandırma vanalarını açmak","El frenini çekmek ve tekerleklerin önüne takoz koymak, böylece çekici-dorse yükleme sırasında yerinden oynamaz"],"explanation":"Tehlikeli madde yüklemeden veya boşaltmadan önce el frenini çekmeli ve aracın kaymaması için tekerleklere takoz koymalısınız."},"103":{"q":"Bir terminalde, plakart asili römorkuma Sınıf 3 yanıcı sıvı dolu variller yüklüyorum. Bir çalışma arkadaşım yanan bir sigarayla yanıma gelip yükleme sırasında sigarasını bitirmesinin sorun olup olmadığını soruyor. Hangi yanıt doğrudur?","options":["Hayır — yanıcı maddelerin yüklenmesinin yakınında sigara içmek yasaktır ve yanan sigarayı işlemden iyice uzak tutmalıdır","Evet — açık römork kapılarından en az 5 fit geride durduğu sürece sigara içebilir","Evet — kural yalnızca işaret fişeği gibi açık alevleri sınırlar, sigaraları değil","Evet — variller yüklenip plakartlanana kadar mühürlü olduğu için sigara içmek serbesttir"],"explanation":"Yanıcı maddelerin yüklenmesi yakınında sigara içmek yasaktır, bu yüzden yanan sigara işlem alanından uzak tutulmalıdır."},"104":{"q":"Bir depoda, 1.1 Bölümü patlayıcı madde kutularını elimle römorkun tabanına yüklüyorum. Kargo alanını hazırlarken ve her kutuyu taşırken, yükü en güvenli tutan ve tehlikeli madde taşıma kurallarına uyan uygulama hangisidir?","options":["Kasaları çıplak çelik zeminde sürükleyip keskin metal bir kargo kancasıyla sıkıca çekmek","Kargo bölümüne kıvılcım çıkarmayan bir taban kaplaması sermek ve her kutuyu nazikçe yere koyup her kasayı dikkatle taşımak","Hiçbir taban kaplaması kullanmadan kapılar daha çabuk mühürlensin diye kasaları hızlıca yerine fırlatmak","Römorku kapatmadan önce yüklü kasaları sıkıştırmak için forklifti doğrudan üzerlerinden geçirmek"],"explanation":"Bölüm 1.1 patlayıcılar, yükü patlatabilecek sürtünme, kıvılcım veya darbeyi önlemek için kıvılcım çıkarmayan zemin kaplaması ve her kasanın dikkatli taşınmasını gerektirir."},"105":{"q":"Tehlikeli madde taşıması için kapalı kasa kamyonuma aşındırıcı madde kutularını yüklüyorum. Paketler doğru şekilde işaretlenmiş ve plakartlarım takılı. Yükü kargo alanında düzenlerken, kapların kendisini nasıl ele almam gerektiğini EN İYİ aşağıdakilerden hangisi tanımlar?","options":["İlk birkaç durakta yerlerine oturmaları için onları öne doğru gevşekçe istifle","Acil müdahale ekiplerinin hızlıca ulaşabilmesi için onları kapıların yanına bağlanmamış halde koy","Hareket halindeyken kayamayacak, sürüklenemeyecek veya düşemeyecek şekilde onları takozla, destekle ve sabitle","Tamamen zeminden uzak tutmak için onları römorkun üst raylarından as"],"explanation":"Tehlikeli madde kapları, taşıma sırasında kayamaması, hareket edememesi veya düşememesi için engellenmeli, desteklenmeli ve sabitlenmelidir."},"106":{"q":"Bir dökme terminalde tankerime 3. Sınıf yanıcı sıvı olan benzin yüklüyorum. Transfer hattı terminalin kendi pompasına bağlı, bu yüzden ürünü aktarmak için kamyonumun motoruna ihtiyacım olmayacak. Hortumlar bağlanıp ürün akmaya başladığında motorumu ne yapmalıyım?","options":["Yükleme biter bitmez öne çekebilmek için düşük viteste rölantide çalışır halde bırakmak","Hava basıncını korumak ve alternatörün aküleri şarj etmesini sağlamak için hızlı rölantide çalışır halde bırakmak","Yalnızca terminal personeli alanın iyi havalandırıldığını söylerse çalışır halde bırakmak","Bu transfer sırasında bir ürün pompasını çalıştırmaya ihtiyacım olmadığından motoru kapatmak"],"explanation":"Yanıcı sıvıları yüklerken veya boşaltırken, ürün pompasını çalıştırmak gerekmedikçe motor kapalı olmalıdır."},"107":{"q":"Bir terminalde, kargo tankımdan bir depolama tankına Sınıf 3 yanıcı bir sıvı aktarmak üzereyim. Herhangi bir vanayı açmadan veya akışı başlatmadan önce, kamyon ile depolama tankı arasına bir bağlama (bonding) teli bağlıyorum ve bir topraklama takıyorum. Yanıcı sıvıyı elleçlemeden önce bunu yapmamın BAŞLICA nedeni nedir?","options":["Kamyon ile tank arasındaki elektrik yükünü eşitlemek, böylece statik bir kıvılcım oluşup buharları tutuşturamasın diye","Motor kapalıyken kamyonun farlarını ve göstergelerini çalışır tutan yedek bir elektrik yolu oluşturmak için","Akış sırasında sıvının sıcaklığını düşürmek, böylece yakıt genleşip alıcı tanktan taşmasın diye","Akış hızını yavaşlatmak, böylece aktarma sırasında buharlaşma ve dökülme nedeniyle daha az ürün kaybedilsin diye"],"explanation":"Bağlama ve topraklama, kamyon ile tank arasındaki elektrik yükünü eşitleyerek statik kıvılcım oluşup yanıcı buharları tutuşturmasını önler."},"108":{"q":"380 millik bir güzergâhta, iki planlı dinlenme molasıyla, plakartlı bir aşındırıcı madde yükü taşıyorum. Yola çıkmadan önce sahada römorkun etrafında dolaştım ve tüm bağlama ile destekleme düzeneklerimi kontrol ettim, her şey sağlamdı. Tehlikeli madde yük kurallarına uymak için, yolculuğun geri kalanında yükü ve emniyet düzeneklerini denetleme konusunda yönetmelik benden ne yapmamı istiyor?","options":["Sahadaki sefer öncesi denetim yükün ve bağlamaların sağlam olduğunu doğruladıktan sonra başka bir şey gerekmez; çünkü yol boyunca yeniden kontrol yalnızca büyük boyutlu veya aşırı ağır yükler için zorunludur.","Yükü ve emniyet düzeneklerini yalnızca başlangıçta bir kez değil, hem yolculuktan önce hem de yolculuk sırasında belirli noktalarda denetlemeye devam etmek.","Emniyet düzeneklerini yalnızca son teslimat noktasında yeniden denetlemek; çünkü yük tazminat talepleri açısından yasal olarak boşaltmadan önce yapılan kontroller geçerlidir.","Yükün ve bağlamaların tam denetimini, herhangi bir tek seferin sefer öncesi turundan ayrı olarak, taşıyıcının belgelediği kesin bir yıllık takvime göre tekrarlamak."],"explanation":"Yükü ve bağlama tertibatlarını yalnızca başlangıçta bir kez değil, hem yolculuktan önce hem de yolculuk sırasında belirli noktalarda kontrol etmelisiniz."},"109":{"q":"Bölüm 1.1 patlayıcı madde taşıyan plakartlı bir yük taşıyorum ve bir kayış gevşedi, bu yüzden römorktaki bir sandığı yeniden yerleştirmem gerekiyor. Patlayıcıların yakınında kullanacağım aletlerle ilgili aşağıdakilerden hangisi EN önemli kuraldır?","options":["Aletler, sandıkları kaydırmadan sıkıca kavraması için ağır çelikten yapılmış olmalıdır","Aletler kabinde bırakılmalı ve herhangi bir temastan kaçınmak için sandık elle taşınmalıdır","Aletler kıvılcım çıkaramamalı veya patlayıcı ambalajlarına zarar verememelidir","Aletlerin keskin bir kenarı olmalı ki gevşeyen kayışı hızlıca kesip yeniden bağlayabileyim"],"explanation":"Patlayıcıların yakınında kullanılan aletler kıvılcım çıkarmayan ve paketlere zarar veremeyecek nitelikte olmalıdır, çünkü kıvılcım veya darbe patlamayı tetikleyebilir."},"110":{"q":"Bir teslimat rampasındayım ve varillerde Sınıf 3 yanıcı sıvı taşıyan plakartlı bir römorku boşaltıyorum. Bir forklift operatörü propan yakıtlı forkliftini açık römork kapılarının hemen yanında rölantide çalıştırmak istiyor, yakındaki bir işçi sigara yakmak üzere ve rampa amiri bana işlem sırasında açık alev ve çalışan motorların nerede olması gerektiğini soruyor. Vermem gereken doğru talimat nedir?","options":["Forkliftin verimli çalışması ve boşaltmayı daha hızlı bitirmesi için ateşleme kaynaklarını römork kapılarının hemen yanında tutun","Yolun kullanılan kısmından en az 5 fit uzakta kaldıkları sürece sigara içmeye ve motorların rölantide çalışmasına izin verin","Variller mühürlü olduğu ve tutuşmayacağı için yüklemeyi hızlandırmak amacıyla çalışan forklifti römorkun içine yerleştirin","Açık alevler ve çalışan motorlar dahil tüm ateşleme kaynaklarını boşaltma alanından iyice uzakta tutun"],"explanation":"Yanıcı maddeleri yüklerken veya boşaltırken, açık alevler ve çalışan motorlar dahil tüm ateşleme kaynaklarını alandan uzak tutun."},"111":{"q":"Bir müşterinin yükleme rampasında plaka gerektiren tehlikeli madde (HazMat) sevkiyatını yüklüyorum. Teslim almadan önce paketleri incelerken, bu yükü yasal olarak kabul edip taşıyabileceğimi hangi koşul gösterir?","options":["Her paket doğru şekilde etiketlenmiş ve sızıntı belirtisi göstermiyor","İçeriği kendim doğrulayabilmem için her paket açılmış durumda","Diğer sürücülerin fark etmesi için paketler parlak renge boyanmış","Paketler, onları izleyebileceğim şekilde kabinin üzerine yüksekçe istiflenmiş"],"explanation":"Tehlikeli madde sevkiyatı, yalnızca her paket doğru şekilde etiketlenmişse ve sızıntı belirtisi göstermiyorsa kabul edilebilir."},"112":{"q":"Bir dağıtım rampasında karışık bir römork yüklüyorum. Sevkiyat belgelerimde, ülke genelinde taşıyacağım Sınıf 6.1 zehirli (toksik) maddeden birkaç varil listeleniyor. Rampa şefi, ikinci bir sefer yapmamak için römorktaki kalan boşluğu doldurmak istiyor. Sunduğu yükler arasından, zehir varillerimin yanına yüklemem yasak olan hangisidir?","options":["Aynı bölgeye giden torbalanmış tarımsal gübre paletleri","Bir market deposu için paketlenmiş insan gıdası ve hayvan yemi sandıkları","Aynı Sınıf 6.1 zehirli maddeden ek mühürlü variller","Boş, etiketsiz plastik nakliye kaplarının bulunduğu kutular"],"explanation":"Sınıf 6.1 zehirli (toksik) maddeler, insan veya hayvan gıdası ya da yemiyle asla aynı araçta yüklenmemeli veya taşınmamalıdır."},"113":{"q":"Römorkuma aşındırıcı maddeler ve oksitleyicilerden oluşan karışık bir tehlikeli madde yükü yüklüyorum ve bu iki maddenin yan yana taşınmasına izin verilip verilmediğini ya da ayrı tutulmaları gerekip gerekmediğini doğrulamam gerekiyor. Hangi tehlikeli maddelerin aynı araçta birlikte yüklenemeyeceğini hangi başvuru kaynağı bana söyler?","options":["Sevk belgesindeki HM sütunu, çünkü 'X' işaretleri hangi yüklerin ayrı tutulması gerektiğini gösterir","Acil Müdahale Kılavuzu (ERG), çünkü hangi maddelerin birbirleriyle reaksiyona girdiğini listeler","Ayırma (segregasyon) tablosu, çünkü hangi maddelerin birlikte yüklenemeyeceğini belirtir","Plaka kurallarının 1 No'lu Tablosu, çünkü herhangi bir miktarda plaka gerektiren maddeleri listeler"],"explanation":"Ayrıştırma (segregasyon) tablosu, sürücüye hangi tehlikeli maddelerin birlikte yüklenip taşınmasının yasak olduğunu gösterir."},"114":{"q":"İçinde zaten birkaç varil Sınıf 5 oksitleyici bulunan bir römorku yüklüyorum ve yükleme rampası sorumlusu aynı alana sığdırmam için bana dört palet daha veriyor. Yükü güvende tutmak için bu maddelerden hangisini oksitleyici varillerinin hemen yanına KOYMAMAM gerekir?","options":["Su dolu, ağzı kapalı bidonlardan oluşan bir palet","Boş plastik varillerden oluşan bir palet","Torbalanmış kumdan oluşan bir palet","Yanıcı çözücü tenekelerinden oluşan bir palet"],"explanation":"Sınıf 5 oksitleyiciler oksijen açığa çıkarır ve yangını şiddetlendirebilir veya başlatabilir, bu yüzden yanıcı maddelerden uzak tutulmalıdır."},"115":{"q":"Plakartlı römorkumu yüklerken, gönderici bana ayrıştırma tablosuna göre birbirinden ayrı tutmam gereken iki HazMat maddesi veriyor ve neden yan yana taşınamayacaklarını soruyor. El kitabına göre, bu uyumsuz maddelerin ayrılması gerekmesinin EN İYİ nedeni nedir?","options":["Bir arada bulunduklarında birbirleriyle tepkimeye girebilir, alev alabilir veya tehlikeli bir gaz açığa çıkarabilirler","Onları bir arada tutmak yükü 1.001 lb plakart sınırının üzerine çıkarır","Karışmaları belgelerdeki uygun sevkiyat adını ve tehlike sınıfını bulaştırır","Birlikte istiflenmeleri arkada saklanan yansıtıcı üçgenlerin önünü kapatır"],"explanation":"Uyumsuz tehlikeli maddeler ayrı tutulur çünkü bir araya geldiklerinde tepkimeye girebilir, alev alabilir veya tehlikeli gaz açığa çıkarabilirler."},"116":{"q":"Karışık bir tehlikeli madde sevkiyatı yüklüyorum ve evraklarımda aynı müşteriye gidecek bir varil siyanür bileşiği ile birkaç kap aşındırıcı asit (Sınıf 8) listeleniyor. Hangi yükleme kararı beni kurallara uygun ve güvende tutar?","options":["Eşleşen sevkiyat evraklarıyla birlikte kalsınlar diye onları aynı bölmede yan yana yüklemek","Siyanürleri ve asitleri ayrı tutmak ve asla aynı yükte birlikte yüklememek","Yalnızca her ikisini tek bir sızdırmaz dış kap içinde sabitlersem onları birlikte yüklemek","Demir yolu raylarını vites değiştirmeden geçtiğim sürece onları birlikte yüklemek"],"explanation":"Siyanürler ve asitler asla birlikte yüklenmemelidir çünkü temas ettiklerinde öldürücü hidrojen siyanür gazı açığa çıkar."},"117":{"q":"Plakartlı bir aşındırıcı madde yükü taşırken keskin bir koku alıyorsunuz ve römorkunuzdaki bir varilin altında yayılan ıslak bir leke fark ediyorsunuz. Bankete çekip paketin sızdırdığını doğruluyorsunuz. Başka bir şey yapmadan önce İLK önceliğiniz nedir?","options":["İçindeki kimyasalı belirlemek için sızdıran varili açıp ardından doğru sevkiyat adını öğrenmek için Acil Müdahale Kılavuzu'na (ERG) bakmak","Daha fazla yayılmadan önce dökülen ürünü seyreltip en yakın yağmur suyu giderine doğru yıkamak için kendi su kaynağınızı kullanmak","Aracı durdurmak, sızıntının çevresindeki alanı güvenliğe almak ve etraftaki kişileri ve diğer insanları olay yerinden uzak tutmak","Eğitimli personelin ve uygun ekipmanın sızdıran varili kontrol altına alıp boşaltabileceği teslimat noktasına yavaşça devam etmek"],"explanation":"Herhangi bir tehlikeli madde sızıntısında ilk yapılacak şey durmak, alanı güvenceye almak ve insanları olay yerinden uzak tutmaktır."},"118":{"q":"Rüzgârlı bir öğleden sonra yol kenarı molasında, plakart taşıyan aşındırıcı madde yükünüzdeki varillerden biri sızdırmaya ve buhar yaymaya başlıyor. Başkalarını uyarıp insanları uzak tuttuktan sonra, acil müdahale ekipleri ve CHEMTREC gelene kadar nerede durmalısınız?","options":["Sızan varili yakından izleyebilmek için römorkun rüzgâr altı tarafında","Sevk belgelerini ekiplere hızlıca verebilmek için yük kapılarının hemen yanında","Sızan sıvının sizden uzağa akması için yamaçta dökülen maddenin alt tarafında","Aracın rüzgâr üstü tarafında ve sızan yükten güvenli bir mesafede"],"explanation":"Tehlikeli madde acil durumunda rüzgar üstünde ve güvenli mesafede kalın ki buharlar size doğru değil, sizden uzağa savrulsun."},"119":{"q":"Plakartlı bir aşındırıcı madde yükü taşırken bir varil sızmaya başlıyor ve dumanlar yol kenarı boyunca yayılmaya başlıyor. Ben zaten çevredekileri uyardım, insanları uzak tuttum ve yakındaki sigara içimini durdurdum. Şimdi bu belirli kimyasalı nasıl ele alacağım konusunda uzman teknik rehberliğe ihtiyacım var. Bu uzman yardımı için kime başvurmalıyım?","options":["Kimyasalın nasıl ele alınacağı konusunda uzman rehberlik verebilen CHEMTREC'e veya yerel acil müdahale ekiplerine","Olay bildirimini yapması gereken taşıyıcı olduğu için taşıyıcı firmamın sevkiyat ofisine","Varilleri sınıflandırıp paketleyen ve sevkiyat belgelerini hazırlayan göndericiye","Telefonla hiç kimseye — Acil Müdahale Rehberi (ERG) tek başına atmam gereken her adımı kapsıyor"],"explanation":"Sızan bir kimyasalın ele alınması konusunda uzman ve anlık rehberlik için CHEMTREC'i veya yerel acil müdahale ekiplerini arayın."},"120":{"q":"Kırsal bir Teksas otoyolunda plakartlı (tehlike levhalı) yanıcı sıvı yükü taşıyorsunuz ve römorkunuzun altından alevler çıktığını fark ediyorsunuz. Banketе çekiyorsunuz ve yangın açıkça yayılıyor. Küçük yangınlar için derecelendirilmiş bir yangın söndürücünüz var, ancak alevler kargo bölmesine ulaşmaya başladı. İLK olarak ne yapmalısınız?","options":["Yangın büyümeden önce kargoyu kontrol etmek ve ısı ile dumanın çıkmasını sağlamak için römork kapılarını açmak","Önce araçtan güvenli bir mesafeye uzaklaşmak, ardından acil müdahale ekiplerini aramak ve CHEMTREC'e haber vermek","Yangın söndürücüyü kargo bölmesindeki alevlere boşaltmak ve yangın tekrar alevlenirse diye yakınında kalmak","Kabinde kalıp motoru çalışır durumda tutarak çekiciyi yayılan alevlerden uzaklaştırabilmek"],"explanation":"Tehlikeli madde yükü yangınıyla asla tek başınıza mücadele etmeyin; araçtan güvenli bir mesafeye gidin, ardından acil müdahale ekiplerini arayın ve CHEMTREC'i bilgilendirin."},"121":{"q":"Plakalanmış bir aşındırıcı (korozif) yük taşırken bir dinlenme tesisinde bir varilden sıvı damladığını ve römorkömün altında biriktigini fark ediyorum. İnsanları zaten uzaklaştırdım, sigarayı bıraktım ve acil durum ekiplerini bilgilendirdim. Sızıntı yapan aracı hareket ettirmeyle ilgili yapmam gereken TEK doğru şey hangisidir?","options":["Bir tamircinin sızdıran varili tekrar conta etmesi için aracı yavaşça en yakın kamyon durağına sürmek","Dinlenme tesisinin çıkış rampasını açmaya yetecek kadar aracı hafifçe kaydırmak","Bir yetkili can güvenliğini korumak için hareket ettirmemi emretmedikçe aracı olduğu yerde bırakmak","Sızıntıyı diğer park etmiş kamyonlardan uzak tutmak için aracı hızla alandan çıkarmak"],"explanation":"Sızıntı yapan tehlikeli madde aracını kendi kararınızla asla hareket ettirmeyin; bir yetkili can güvenliği için hareket ettirmenizi emretmedikçe olduğu yerde bırakın."},"122":{"q":"Plakartlı aşındırıcı madde taşırken, bir varilden ürün sızdığını ve kenara çektiğim banketteki yolda biriktiğini fark ediyorum. Yanımda Acil Durum Müdahale Kılavuzu (ERG) ve telefonum var. Acil müdahale ekiplerini beklerken İLK önceliğim ne olmalı?","options":["Aşındırıcı maddenin emilip yayılmayı durdurması için birikintinin üzerine gevşek toprak ve çakıl atmak","Sızıntıyı suyla yıkayıp seyrelterek hendeğe ve uzağa doğru itmek","Birikintinin etrafına yansıtıcı üçgenler dizmek ve sızıntıyı işaretlemek için rüzgar üstüne bir işaret fişeği koymak","Etraftakileri bölgeden uzak tutmak ve sızıntının daha fazla yayılmasını durduracak şekilde hareket etmek"],"explanation":"Tehlikeli madde olayında, eğitimli müdahale ekipleri gelene kadar insanları uzak tutun ve sızıntının yayılmasını önleyin; temizliği kendiniz yapmaya çalışmayın."},"123":{"q":"Tehlikeli madde plakartlı bir yük taşırken, bir dinlenme tesisinde römorkumun altında yangın çıkıyor. Harekete geçmeden veya gelen itfaiye ekibiyle konuşmadan önce, sevk belgelerimin ve Acil Müdahale Kılavuzu'nun (ERG) doğru kullanımı nedir?","options":["Tam olarak hangi maddeyi taşıdığımı ve oluşturduğu özel tehlikeleri belirlemek, böylece müdahale ekipleri güvenli şekilde tepki verebilsin","Yükün yolculuktan önce doğru yüklendiğini ve belgelendiğini taşıyıcıya kanıtlamak için","En yakın onaylı tehlikeli madde park güzergahını bulup yanan römorku başka yere çekebilmek için","Yükün 1.001 lb veya daha fazla olduğunu ve bu nedenle yasal olarak plakart gerektirdiğini doğrulamak için"],"explanation":"Sevkiyat belgeleri ve ERG, taşınan maddeyi ve onun belirli tehlikelerini tam olarak tanımlar, böylece siz ve müdahale ekipleri güvenli şekilde hareket edebilir."},"124":{"q":"Tehlikeli madde plakartı taşıyan römorkunuzdaki bir varil yarıldı ve içeriği banketin üzerine sızıyor. Aracı çoktan kenara çektiniz, yansıtıcı üçgenlerinizi yerleştirdiniz ve acil müdahale ekiplerini beklerken çevredeki insanları uzak tutuyorsunuz. Yoldan geçenlerden biri sigara yakıyor, yardım için duran başka bir sürücü ise kamyonunuzun çok arkasında durduğu için hızlıca bir sigara içmesinin sakıncası olup olmadığını soruyor. Bu olay yerinde sigara içme konusunda doğru hareket nedir?","options":["Herkes sızıntı yapan römorkun en az 25 fit arkasında durduğu sürece hızlıca sigara içmeye izin vermek","Sigara içmeyi tamamen yasaklamak ve yakındaki herkesten sigaralarını derhal söndürmesini istemek","Yardım için duran sürücünün sigara içmesine izin vermek, çünkü yardım edenler bu kuraldan muaftır","Sadece rüzgar üstü tarafta, ürünün bankete sızdığı yerden uzakta sigara içmeye izin vermek"],"explanation":"Tehlikeli madde olayında sigara içmeye asla izin verilmez, çünkü sızan ürün veya buharları yanıcı olabilir; bu yüzden her türlü alev veya kor derhal söndürülmelidir."},"125":{"q":"Plakartlı (levhalı) bir aşındırıcı (korozif) madde yükü taşırken bir konteyner yırtılıyor ve ürün kırsal bir karayolunun banketine sızmaya başlıyor. Çevredekileri uyardıktan, insanları sızıntıdan uzak tuttuktan ve yakında kimsenin sigara içmesine izin vermedikten sonra, yasa olayın bildirilmesini gerektiriyor. Bu olay, gerektiği şekilde kime bildirilmelidir?","options":["Yalnızca göndericiye (shipper), çünkü maddeyi sınıflandıran, paketleyen ve sevk belgelerini hazırlayan gönderici olduğu için konteynerin içindekilerden sorumlu olan taraf odur","Hiç kimseye; yeter ki sızıntıyı bizzat kontrol altına alayım, alanı soğutayım ve teslimat noktasına devam etmeden önce hasarı fotoğraflarla belgeleyeyim","Acil müdahale ekipleri veya CHEMTREC gibi yetkili makamlara; taşıyıcı (carrier) ise gerekli olay raporunu ilgili kurumlara iletir","Yalnızca en yakın yerel televizyon veya radyo istasyonuna, böylece bölgedeki diğer sürücüler uyarılıp etkilenen yol kesimini kullanmaktan kaçınabilir"],"explanation":"Acil müdahale ekipleri veya CHEMTREC gibi yetkili makamları bilgilendirin; taşıyıcı ise ilgili kurumlara gerekli olay raporunu sunar."},"126":{"q":"Tehlike levhalı (placard) yanıcı sıvı yükünü şehrin içinden taşıyorsunuz ve GPS, uzun bir karayolu tüneli ile yoğun bir şehir merkezinden geçen ve 20 dakika kazandıran hızlı bir rota öneriyor. Güvenli tehlikeli madde rota planlamasına en uygun seçenek hangisidir?","options":["En kısa olduğu ve en çok zaman kazandırdığı için tünel ve şehir merkezi rotasını seçmek","Rotada kalmak ama yüke dikkat çekmemek için zorunlu kantar (tartı) istasyonunu atlamak","Rotayı kullanmak ama tehlike levhalarını yeniden kontrol etmek için şehir merkezinde park etmeyi planlamak","Bu rotayı reddetmek ve tüneli ile yoğun nüfuslu şehir merkezini önleyen bir güzergah seçmek"],"explanation":"Tehlikeli madde güzergahı planlarken tünellerden ve yoğun nüfuslu bölgelerden kaçının, çünkü oradaki bir sızıntı veya yangın halka yönelik tehlikeyi büyütür."},"127":{"q":"Tehlikeli madde plakartı (placard) takılı, yanıcı sıvı yükü taşıyan bir aracı Teksas'ta kırsal bir ilçede, birkaç farklı geçit türünün bulunduğu bir güzergahta sürüyorum. DPS tehlikeli madde kurallarına uymak için, devam etmeden önce aşağıdakilerden hangisinde aracı tamamen durdurmam ZORUNLUDUR?","options":["En yakın raya 15 ila 50 fit kala tamamen durmam gereken bir demir yolu geçidinde","Kırsal bir dört yollu kavşaktaki yanıp sönen sarı uyarı sinyalinde","Dizel deposunu doldurmak için girmeden önce, açık bir yakıt istasyonunda","Güzergah boyunca geçtiğim her özel araç yolu ve tarla girişinde"],"explanation":"Plakart taşıyan bir araç, demiryolu geçidinde en yakın raydan 15 ila 50 fit önce tamamen durmalı ve geçerken asla vites değiştirmemelidir."},"128":{"q":"Teksas genelinde plakartlı bir Bölüm 1.2 patlayıcı yükü taşıyorum ve öğle yemeği için kısa bir mola vermem gerekiyor. Yanımda ikinci bir sürücü yok. DPS kurallarına göre bu yükle ilgili ne yapmam gerekir?","options":["Kapılar kilitli olduğu sürece, ben içeride yemek yerken kamyonu restoran otoparkına park edip kilitli bırakabilirim","Patlayıcı yükün başında her zaman bulunmam gerekir, bu yüzden yemek yemek için içeri girerken onu başıboş (gözetimsiz) bırakamam","Herhangi bir binadan 300 fitten fazla uzağa park edersem, kısa molalarda gözetimsiz bırakabilirim","Gitmeden önce motoru kapatıp el frenini çekersem gözetimsiz bırakabilirim"],"explanation":"Bölüm 1.1, 1.2 ve 1.3 patlayıcıları asla gözetimsiz bırakılmamalıdır; sürücü veya nitelikli bir görevli her zaman araçla birlikte kalmalıdır."},"129":{"q":"Plakartlı (tehlike levhalı) yanıcı sıvı yükü taşıyorum ve geceyi geçirmek için durmam gerekiyor. İleride, bir dinlenme alanının yakınında birinin yanar halde bıraktığı bir yol kenarı ateşi görüyorum. Park edecek bir yer seçmeden önce, el kitabına göre plakartlı aracımla bu açık ateş arasında bırakmam gereken asgari mesafe nedir?","options":["En az 25 fit — yükün yanında sigara içme yasağı için gereken mesafeyle aynı","En az 50 fit — demir yolu raylarından önceki azami durma mesafesiyle aynı","Araç ile açık ateş arasında en az 300 fit","Motor kapalı olduğu sürece belirli bir mesafe gerekmez"],"explanation":"Plakart taşıyan bir araç açık ateşten en az 300 fit uzağa park edilmelidir, çünkü açık alev yük için doğrudan bir tutuşma tehlikesidir."},"130":{"q":"Plakartlı bir tehlikeli madde yükü taşırken, tanımadığım bir eyaletler arası otoyolda navigasyonum beni hiç sürmediğim bir yola yönlendiriyor. Bu güzergâhta yoğun bir kamyon durağından, açık bir kantar istasyonundan ve bir dağın içinden kazılmış uzun bir yer altı geçidinden geçeceğim. Tehlikeli madde yüküyle yasal olarak girmemin EN olası şekilde engelleneceği ve beni alternatif bir güzergâh aramaya zorlayacak yer hangisidir?","options":["Kamyon durağı, çünkü plakartlı araçlar halkın toplandığı yerlere park edemez","Açık kantar istasyonu, çünkü tehlikeli madde yükleri tüm denetim kantarlarını atlamak zorundadır","Burada hiçbir şey kısıtlı değildir, çünkü işaretli bir otoyol güzergâhı her zaman tehlikeli maddeye izin verir","Yer altı geçidi, çünkü bazı tehlikeli maddeler belirli tünellerden men edilmiştir"],"explanation":"Tehlikeli madde güzergahında tünellerden kaçının, çünkü yetkililer belirli tehlikeli maddeleri belirli tünellerden tamamen yasal olarak yasaklayabilir."},"131":{"q":"Plakartlı bir aşındırıcı madde yükünü şehrin içinden taşırken, atanmış tehlikeli madde güzergahımda iki şeridi kapatan ve trafiği kilometrelerce tıkayan beklenmedik bir yol çalışmasıyla karşılaşıyorum. Bir sapak işareti şehir merkezindeki iş bölgesinden geçen daha kısa bir yolu gösteriyor ve navigasyonum alçak bir köprüden geçen daha da hızlı bir kestirme öneriyor. Nerede süreceğime hangi seçim yön vermeli?","options":["Belirlenmiş veya zorunlu tehlikeli madde güzergahında kalmak ve yol koşulları izin verir vermez ona geri dönmek","Şehir merkezi sapağını kullanmak, çünkü levhalı sapak işaretlerine uymak her zaman tehlikeli madde güzergah kurallarının önüne geçer","Navigasyonun alçak köprüden geçen kestirmesini izlemek, çünkü en çok zaman kazandırır ve en yoğun trafiği önler","Fiziksel olarak en kısa olan yolu seçmek, çünkü yasa yalnızca toplam kat edilen mesafeyi en aza indirmeyi gerektirir"],"explanation":"Tehlikeli madde sürücüleri, kısa yollardan veya trafikten bağımsız olarak belirlenen veya zorunlu güzergahı izlemeli ve yol koşulları el verir vermez ona geri dönmelidir."},"132":{"q":"Plakart (tehlike levhası) takılı bir yük taşıyorum ve birkaç dakika telefonla ilgilenip bacaklarımı açmak için kenara çekmem gerekiyor. Güzergahıma yakın dört yer var. Park yeri olarak hangisini seçmekten KAÇINMALIYIM?","options":["Çevresinde hiçbir yapı görünmeyen, kırsal bir kesimde geniş çakıllı bir cep","Yayaların toplandığı bir tünel girişinin hemen yanındaki kaldırım kenarı","Binanın ana girişinden iyice uzakta, işaretli bir kamyon durağı alanı","Yolun trafik kısmından 5 fitten daha uzaktaki açık tarla kenarı banketi"],"explanation":"Plakartlı yükler tüneller, köprüler ve kalabalıklardan uzak tutulmalıdır; bu yüzden yayaların toplandığı bir tünel girişi kaçınılması gereken iki tehlikeyi bir araya getirir."},"133":{"q":"Bölüm 1.2 patlayıcı madde taşıyorsunuz ve yakıt göstergeniz düşük, bu yüzden yakıt almak için bir tır durağına giriyorsunuz. Depo dolarken, aşağıdaki davranışlardan hangisi bu yük için sorumluluklarınızı EN İYİ şekilde karşılar?","options":["Hızlıca doldurup çıkabilmek için motoru pompada rölantide bırakmak, sonra ödeme yapmak üzere içeri girmek","Yüklü dorseyi personelin gözü önünde tutmak için aracı ışıkların altında kalabalık mağaza girişinin hemen yanına park etmek","Tüm süre boyunca aracın yanında kalmak ve onu kalabalıklardan ve insanların toplandığı yerlerden uzak tutmak","Kabini kilitleyip aracı pompada bırakmak ve otomatik kapama valfi yakıt almayı bitirirken içeri kahve almaya gitmek"],"explanation":"Bölüm 1.1, 1.2 ve 1.3 patlayıcıları asla gözetimsiz bırakılamaz; bu nedenle sürücü araçla birlikte kalmalı ve onu kalabalıklardan ve toplanma yerlerinden uzak tutmalıdır."},"134":{"q":"Zaten A Sınıfı bir CDL'ye sahibim ve plakartlı (tehlikeli madde levhalı) aşındırıcı sıvı yükleri taşımak üzere yeni işe alındım. Arkadaşım, yasal olarak başlayabilmem için yapmam gereken tek şeyin, bu onayı (endorsement) eklemek üzere DPS ofisinde kısa bir yazılı sınavı geçmek olduğunu söylüyor. İhtiyacım olan Tehlikeli Madde (HazMat, H) onayını almak için atlayamayacağım TEK zorunluluk aşağıdakilerden hangisidir?","options":["Özellikle plakartlı bir tanker dorseyle direksiyon başında bir yol sınavını tamamlamak","Herhangi bir plakartlı yükü taşımadan önce onayı en az 30 gün boyunca elde tutmak","DOT sağlık sertifikamı, onayı eklediğim hafta içinde yenilemek","Geçmiş kontrolü ve parmak izi alınması dahil olmak üzere bir TSA güvenlik tehdit değerlendirmesini geçmek"],"explanation":"HazMat onayı için yalnızca yazılı sınav değil, geçmiş kontrolü ve parmak izi alımını içeren bir TSA güvenlik tehdit değerlendirmesini geçmek gerekir."},"135":{"q":"Plakartlı (tehlike levhalı) yanıcı sıvı yükü taşıyorum ve öğle yemeği için yol kenarındaki bir lokantada kısa bir mola vermek istiyorum. Aşağıdaki davranışlardan hangisi tehlikeli madde kurallarını ihlal eder?","options":["Ben lokantanın içinde oturup yemek yerken plakartlı aracı park yerinde gözetimsiz bırakmak","Park hâlindeyken sevkiyat belgelerimi kapı cebinde, ulaşabileceğim yerde tutmak","Tekrar otoyola çıkmadan önce lastikleri kontrol etmek","Yolun trafiğe açık kısmından 5 fitten daha uzağa park etmek"],"explanation":"Plakartlı tehlikeli madde aracı asla gözetimsiz bırakılamaz; bu yüzden yük gözetimsizken kamyondan uzaklaşmak yasak bir ihlaldir."},"136":{"q":"Plakartlı bir aşındırıcı madde yükü taşıyorum ve gece bir kamyon durağında konaklıyorum. Sabah sefer öncesi muayenemi başlatmak için aracıma döndüğümde, aşağıdaki gözlemlerden hangisi özellikle dikkat etmek üzere eğitildiğim bir güvenlik sorunu olarak beni EN ÇOK endişelendirmelidir?","options":["Gece boyunca ön cama ince bir buz tabakası oluşmuş","Bir kargo mührü kesilmiş ve bir plakart kısmen sökülmüş görünüyor","Yakıt göstergesi bir önceki geceye göre biraz daha düşük gösteriyor","Yanımdaki boşluğa şimdi başka bir kamyon park etmiş"],"explanation":"Kesilmiş bir kargo mührü ve kısmen sökülmüş bir plakart, tehlikeli madde sürücülerinin dikkat etmek üzere eğitildiği klasik kurcalama veya hırsızlık işaretleridir."},"137":{"q":"Plaka (placard) gerektiren tehlikeli madde yükleri taşıyan bir nakliyeci tarafından yeni işe alındım ve oryantasyon sırasında sevkiyat sorumlum bana bir şirket belgeleri klasörü verip federal kuralların bizim gibi birçok nakliyecinin bu belgelerden birini yazılı olarak dosyada tutmasını gerektirdiğini söylüyor. Düzenleyici bir zorunluluk olarak büyük olasılıkla hangi belgeden bahsediyor?","options":["Her sürücünün avludan çıkmadan önce imzalaması gereken yazılı bir günlük öğle yemeği ve dinlenme molası programı","Şirketin plakalı araçlar için onayladığı tercih edilen yakıt istasyonlarının yazılı bir listesi","Şirketin tehlikeli madde hırsızlığına ve kötüye kullanımına karşı nasıl korunduğunu ele alan yazılı bir güvenlik planı (security plan)","Sürücülerin yükü taşırken dinleyebileceği radyo istasyonlarının yazılı bir kaydı"],"explanation":"Tehlikeli madde taşıyan birçok taşıyıcı; personel, yetkisiz erişim ve yol güvenliğini kapsayan yazılı bir güvenlik planı geliştirmeli ve sürdürmelidir."},"138":{"q":"Kış mevsimi ve römorkum otomatik bir kargo ısıtıcısıyla donatılmış. Terminalden ayrılmadan önce sevkiyat görevlisi bana bir yük verip yol boyunca yükü sıcak tutmamı söylüyor. Aşağıdaki yüklerden hangisiyle kargo ısıtıcısını kesinlikle çalıştırMAMALIYIM?","options":["Soğukta donabilecek, kuru kasada mühürlü bir konserve gıda yükü","Bir sonraki yükleme noktasına götürdüğüm boş bir römork","Donmaya duyarlı, paletlenmiş şişe içme suyu yükü","Isındıkça buhar yayan, yanıcı sıvı dolu varillerden oluşan bir yük"],"explanation":"Kargo ısıtıcısı yanıcı sıvı yüklerinde kullanılmamalıdır; çünkü ısındıkça çıkan buharlar tutuşarak yangına veya patlamaya yol açabilir."},"140":{"q":"Plaka (placard) gerektiren bir yük yüklüyorum ve sevk belgelerinde, taşıyıcımın tehlikeli madde yönetmeliklerine göre \"yasak\" (forbidden) madde olarak işaretlediği bir kalem var. Yükü teslim almadan önce, bu kalemle ilgili yükümlülüğümü doğru şekilde hangi ifade açıklar?","options":["Bu maddeyi hiçbir şekilde taşımamalıyım, çünkü yasak maddeler hiçbir araçta ve hiçbir koşulda taşınamaz.","Doğru plakaları aracın dört tarafına da takıp belgeleri elimin erişebileceği yerde tutarsam taşıyabilirim.","Yalnızca yolculuk boyunca toplam brüt ağırlığı 1.001 librenin altında kalırsa taşıyabilirim.","Gönderici belgelere doğru sevkiyat adını, tehlike sınıfını ve kimlik numarasını ekler eklemez taşıyabilirim."],"explanation":"Yasaklı maddeler hiçbir koşulda taşınamaz; bu nedenle tek doğru hareket onları hiç taşımamaktır."},"141":{"q":"Bir yükü hazırlıyorum ve gönderici, yükün bir kısmının \"sınırlı miktar\" (limited quantity) sevkiyatı olarak nitelendiğini söylüyor. İmzalamadan önce, yükün bu kısmı hakkında aşağıdakilerden hangisinin DOĞRU olmasını beklemeliyim?","options":["Özel bir kategori olduğu için tüm Tehlikeli Madde kurallarından muaftır ve hiç evrak olmadan taşıyabilirim","Maddenin daha küçük miktarlarını içerdiğinden, paketleme ve işaretleme gereklilikleri azaltılmıştır","Ağırlıktan bağımsız olarak her zaman dört yüzde de en fazla sayıda plaka (placard) gerektirir","Bu terim yalnızca sıvılar için geçerlidir, bu nedenle yükteki herhangi bir katı madde sınırlı miktar olamaz"],"explanation":"Sınırlı miktar, belirlenen eşiklerin altında kalan daha küçük miktarlarda taşınır; bu yüzden azaltılmış ambalaj ve işaretleme gereksinimlerine tabidir."},"142":{"q":"Tehlikeli madde yükümde sefer öncesi kontrolümü yapıyorum ve her koliyi taşıma evrakımla karşılaştırmak için kasanın arkasını açıyorum. Gönderici her şeyi mühürleyip paketledi, ancak yine de her bir paketin ne taşıması gerektiğini doğrulamam gerekiyor. Kolileri evrakımdaki uygun sevkiyat adı, tehlike sınıfı ve kimlik numarasıyla eşleştirmek için, her paketin üzerinde basılı olarak ne bulmayı beklemeliyim?","options":["Paket ve evrakın daima birlikte seyahat etmesi için her koliye yapıştırılmış bir taşıma evrakı kopyası","Müdahale ekiplerinin yükü hangi sürücü ve şirketin taşıdığını bilmesi için taşıyıcının adı ve benim tam adım","Paketi evrakımdaki kayıtlarla doğrulayabilmem için maddeyi tanımlayan bir tehlike etiketi ve işaretler","Alıcının teslimatta yükün değerini doğrulayabilmesi için ürün maliyetini gösteren bir perakende fiyat etiketi"],"explanation":"Gönderici her paketi tehlike sınıfı ve sevkiyat adıyla etiketler ve işaretler; böylece her paketi sevkiyat belgelerinizle karşılaştırabilirsiniz."},"143":{"q":"Sınıf 7 radyoaktif madde sevkiyatını yüklüyorum ve göndericiyle belgeleri imzalamadan önce paket etiketlerini gözden geçiriyoruz. Bu malzemeden römorkuma birlikte ne kadar koyabileceğimi hesaplarken dikkate almam gereken, etikette basılı bir sayıyı gösteriyor. Radyoaktif paketlerin taşıyabileceği bu belirleyici değer aşağıdakilerden hangisidir?","options":["Yükü her miktarda plaka takma zorunluluğundan muaf tutan bir teneffüsle zehirlenme tehlikesi derecesi","Yükün kantar istasyonlarını ve güzergâh kısıtlamalarını atlamasını sağlayan bir geçiş kodu","Herhangi bir paket işaretine olan ihtiyacı ortadan kaldıran bir bildirilebilir miktar (RQ) sınırı","Birlikte ne kadar taşınabileceğini kısıtlayan bir taşıma indeksi sınırı"],"explanation":"Sınıf 7 radyoaktif paketler bir taşıma indeksi taşır; bu indeksin sınırı, birlikte yüklenip taşınabilecek radyoaktif madde miktarını belirler."},"144":{"q":"Sevkiyat belgelerinde reaktif (tepkimeye girebilen) madde olarak tanımlanan, plakartlı bir yük yüklüyorum ve bunu taşıma boyunca treylerin neresine, nasıl yerleştireceğime karar veriyorum. Bu reaktif maddeyi güvenli şekilde taşımak için, aşağıdakilerden hangisinden uzak tutmam gerekir?","options":["Isı kaynaklarından, su veya nemden ve taşınan diğer her türlü reaktif maddeden","Yükü taşıma sırasında yastıklamak için kullanılan yumuşak sıcak battaniye veya dolgudan","Paketin kayabileceği, treylerdeki herhangi bir geniş boş ve açık alandan","Treyler kapılarından gelen çok parlak ışığın doğrudan etkisinden"],"explanation":"Reaktif maddeler, temas şiddetli bir tepkimeye yol açabileceğinden ısıdan, su veya nemden ve diğer reaktif maddelerden uzak tutulmalıdır."},"145":{"q":"Uzun bir sefer için, kriyojenik (çok soğuk) bir sıvı olan soğutulmuş sıvı azot yüklü bir tankeri teslim almakla görevlendirildim. Yükü kabul etmeden önce römorku incelerken, bu tür bir kargonun doğru taşındığını bana hangi durum gösterir?","options":["Tank, soğuk kaçmasın ve ürün donmuş kalsın diye havalandırması olmadan tamamen sızdırmaz şekilde kapatılmıştır","Tank özel yalıtımlı ekipman kullanır ve oluşan basıncı güvenli şekilde tahliye eden çalışan bir havalandırması vardır","Sıvının vanaları dondurarak kapatmasını önlemek için tankın içine küçük bir ısıtıcı ünitesi monte edilmiştir","Soğuk özel bir bakım gerektirmediği için tank, ekstra bağlantısı olmayan standart bir kuru dökme yük tankeridir"],"explanation":"Kriyojenik sıvılar sürekli ısı emer ve basınç oluşturur; bu nedenle özel yalıtımlı ekipman ve basıncı güvenle boşaltacak çalışan bir tahliye valfi gerektirir."},"146":{"q":"Plakartlı römorkum Teksas'ta kırsal bir karayolunda devriliyor ve bir varilden sızıntı başlıyor. İlk itfaiye ekibi ben daha fazla bir şey söyleyemeden geliyor, sevkiyat belgelerimi alıyor ve yük için listelenen tehlike sınıfını ve UN/NA kimlik numarasını hemen okuyor. Olay yerindeki müdahale ekipleri için bu tehlike sınıfının ve kimlik numarasının bu kadar önemli olmasının ANA nedeni nedir?","options":["Yükümün, başlangıçta plakart gerektiren 1.001 librelik eşiğin üzerinde olup olmadığını ekiplerin hesaplamasını sağlarlar","Sürücü olarak benim CHEMTREC'i çoktan aradığımı ve taşıyıcının yardım gelmeden önce olay raporunu sunduğunu kanıtlarlar","Müdahale ekiplerinin tehlikenin tam olarak ne olduğunu hızla belirleyip bu maddeye doğru şekilde tepki vermesini sağlarlar","Plakartların dört tarafa da takıldığını ve baktıkları yönden okunabilir olduğunu doğrularlar"],"explanation":"Doğru sevkiyat adı, tehlike sınıfı ve kimlik numarası, acil müdahale ekiplerinin tehlikeyi hızla belirleyip maddeye doğru şekilde müdahale etmesini sağlar."},"148":{"q":"Zaten Teksas A Sınıfı CDL'ye sahibim ve iki yıldır kuru yük taşıyorum. Önümüzdeki ay nakliyecim, römorkun dört tarafının da plakart (tehlike levhası) gerektirdiği yükleri taşımaya başlamamı istiyor. İlk plakartlı seferi yasal olarak kabul edebilmem için önce neyi tamamlamam gerekir?","options":["Ekstra hiçbir şey — A Sınıfı CDL tek başına zaten her türlü plakartlı tehlikeli madde yüküne izin verir","Sadece Tanker (N) onayı; çünkü plakartlı yükler dökme halinde tanklarda taşınır","Eklenen römork ağırlığını karşılamak için yalnızca ikili/üçlü (T) onayı","Parmak izi alınarak yapılan TSA güvenlik tehdidi değerlendirmesini geçmeyi gerektiren Tehlikeli Madde (H) onayı"],"explanation":"Plakart gerektiren miktarda tehlikeli madde taşımak, ancak parmak izi alınan bir TSA güvenlik tehdit değerlendirmesini geçtikten sonra verilen HazMat (H) onayını gerektirir."},"149":{"q":"Az önce plakartlı bir aşındırıcı madde yükü aldım. Sevkiyat belgelerinde tehlike sınıfında bir hata var ve bunu terminalden ayrılmadan önce fark ettim. Bir sevkiyat görevlisi bana, \"O evrak yüzde 100 göndericinin sorunu — senin tek işin araç sürmek\" diyor. Tehlikeli madde kurallarına göre hangi ifade DOĞRUDUR?","options":["Güvenli taşıma paylaşılan bir sorumluluktur — gönderici, taşıyıcı ve sürücünün her birinin belirli görevleri vardır ve ben bilerek yanlış işaretlenmiş bir sevkiyatı taşıyamam.","Yükü yalnızca gönderici sınıflandırıp belgeleri hazırladığı için, sürücü evrak hatalarından sorumlu değildir ve yükü olduğu gibi yasal olarak taşıyabilir.","Taşıyıcı yükü sevk ettiğinde, sevkiyatın tüm yasal sorumluluğu taşıyıcıya geçer, bu yüzden sürücü tamamen sevkiyat görevlisine güvenebilir.","Sürücünün tek görevi güvenli sürüştür, dolayısıyla evrakların doğruluğu yalnızca göndericinin işidir ve sürücünün bunu hiçbir zaman doğrulaması gerekmez."],"explanation":"Tehlikeli madde güvenliği gönderici, taşıyıcı ve sürücü arasında paylaşılan bir sorumluluktur ve sızdıran veya yanlış işaretlenmiş bir sevkiyatı bilerek taşımayı reddetmelisiniz."},"150":{"q":"Sıkıştırılmış propan tüplerinden oluşan bir yük alıyorum ve rıhtım amiri bana malzemeyi Tehlike Sınıfı 2 olarak gösteren sevk belgelerini veriyor. Levhaları takmadan önce Sınıf 2'nin gerçekte neyi temsil ettiğini doğrulamak istiyorum. Hangi ifade doğrudur?","options":["Sınıf 2, bazen taşıdığım akü asidi ve sodyum hidroksit gibi aşındırıcı maddeleri kapsar.","Sınıf 2, propanım gibi yanıcı, yanıcı olmayan ve zehirli gaz maddeleri dahil gazları kapsar.","Sınıf 2 patlayıcıları kapsar, bu yüzden bu yük dinamit ve havai fişeklerle aynı kurallara tabidir.","Sınıf 2 radyoaktif maddeleri kapsar, bu yüzden bu tüplerin ekstra zırhlamaya ihtiyacı var."],"explanation":"Tehlike Sınıfı 2 gazlardır; 2.1 yanıcı, 2.2 yanıcı olmayan ve 2.3 zehirli gaz olarak ayrılır ve propan bu sınıftaki yanıcı bir gazdır."},"151":{"q":"Teslimat için akü asidi varilleri yüklüyorum ve sevk belgelerinde tehlike sınıfı 8 olarak belirtilmiş. Römorkuma plaka asmadan önce bu yükün gerçekte ne tür bir tehlike oluşturduğunu doğrulamam gerekiyor. Aşağıdakilerden hangisi Tehlike Sınıfı 8 maddesini doğru şekilde tanımlar?","options":["Sızabilen ve solunum tehlikesi yaratabilen sıkıştırılmış veya sıvılaştırılmış bir gaz","Cilt temasıyla veya solunarak bir kişiyi zehirleyebilen toksik bir madde","Cildi, metali veya diğer malzemeleri kimyasal olarak yakabilen aşındırıcı (korozif) bir madde","Isı, darbe veya sürtünmeyle patlayabilen patlayıcı bir madde"],"explanation":"Tehlike Sınıfı 8 aşındırıcılardır; akü asidi gibi cildi, metali ve diğer maddeleri kimyasal olarak yakan veya aşındıran maddelerdir."},"152":{"q":"Römorkumu yüklerken, gönderici bana UN numarası ve doğru sevkiyat adıyla birlikte 'Tehlike Sınıfı 7' olarak işaretlenmiş bir sevkiyat için belgeleri veriyor. Plakaları yerleştirmeden önce, taşıdığım tehlikenin tam olarak ne olduğunu anlamam gerekiyor. Tehlike sınıfı sistemine göre, Sınıf 7 bu yük hakkında bana ne söylüyor?","options":["Aşındırıcı bir maddedir, bu yüzden sızdıran kaplar cildi yakabilir ve metal yüzeyleri çürütebilir","Yanıcı bir sıvıdır, bu yüzden tüm tutuşma kaynaklarını ve açık alevleri ondan uzak tutmalıyım","Sıkıştırılmış veya zehirli bir gazdır, bu yüzden basınç boşalması bir soluma tehlikesi yaratabilir","Radyoaktif bir maddedir, bu yüzden radyasyon yayan ve özel muamele gerektiren bir yük taşıyorum"],"explanation":"Tehlike Sınıfı 7 her zaman Radyoaktif maddeler anlamına gelir; bu nedenle yük, gösterilen sevkiyat adı ne olursa olsun radyasyon yayar ve özel taşıma gerektirir."},"153":{"q":"Bir römork yüklüyorum ve sevkiyat belgelerimde Tehlike Sınıfı 5 bir madde listeleniyor. Plaka (placard) yerleştirmeden önce, bu yükün gerçekte ne tür bir tehlike taşıdığını doğrulamak istiyorum. Sınıf 5 bir madde şu özelliktedir:","options":["Oksijen açığa çıkararak bir yangını şiddetlendirebilen bir oksitleyici veya organik peroksittir","Cilt dokusunu tahrip edebilen ya da çelik ve alüminyumu aşındırabilen bir aşındırıcıdır","Isıya veya darbeye maruz kaldığında kütlesel patlamaya yol açabilen bir patlayıcıdır","Yanıcı, yanıcı olmayan veya zehirli olabilen sıkıştırılmış bir gazdır"],"explanation":"Tehlike Sınıfı 5 oksitleyiciler ve organik peroksitler oksijen açığa çıkarır ve dış bir tutuşturma kaynağı olmadan bile yangını başlatabilir veya şiddetlendirebilir."},"154":{"q":"Rıhtımda az miktarda Zehirli Soluma Tehlikesi (PIH) maddesi yüklüyorum ve toplam ağırlık 1.001 librenin epeyce altında. Dağıtım sorumlum yükün çok hafif olduğunu, onu normal bir yük taşıması gibi götürebileceğimi söylüyor. Bu PIH sevkiyatını işlemenin doğru yolu aşağıdakilerden hangisidir?","options":["Yük 1.001 librenin altında olduğu için herhangi bir plaka gerekmez ve onu sıradan yük gibi taşıyabilirim","Ekstra dikkatle davranmalı ve uygun plakaları takmalıyım, çünkü PIH maddeleri herhangi bir miktarda plaka takmayı gerektirir","Yalnızca eyalet sınırını geçersem plaka takmam gerekir; eyalet içi 1.001 librenin altındaki PIH yükleri özel işlem gerektirmez","Miktar çok az olduğu için evrak işlerini azaltmalı ve sevkiyat belgelerini atlamalıyım"],"explanation":"Soluma Yoluyla Zehirlenme Tehlikesi (PIH) maddeleri, herhangi bir miktarda plakart gerektiren ve asgari ağırlık sınırı olmayan Tablo 1 tehlikeleridir."},"155":{"q":"Römorkumu, sevk belgesinde Tehlike Sınıfı 9 altında listelenen bir maddenin birkaç kutusuyla yüklüyorum. Yanıcı değil, aşındırıcı değil ve basınçlı gaz da değil, ancak yine de bir plaka (placard) gerektirdi. Tehlike Sınıfı 9'un neyi kapsadığını EN İYİ hangi ifade açıklar?","options":["Basınç altında yanıcı olmayan sıkıştırılmış ve sıvılaştırılmış gazlar","Cildi veya metali hasara uğratabilen aşındırıcı sıvılar ve katılar","Diğer sekiz sınıfa uymayan çeşitli (muhtelif) tehlikeli maddeler","Patlayıcı maddeler — patlayıcı karışımlardan havai fişeklere ve fünyelere kadar"],"explanation":"Tehlike Sınıfı 9, taşıma tehlikesi oluşturan ancak 1 ila 8. sınıflara uymayan düzenlemeye tabi maddeler için kullanılan genel Çeşitli kategorisidir."},"156":{"q":"Bir yük için taşıma evraklarını hazırlıyorum ve kayıtta Tehlike Sınıfı 4 görünüyor. Plaka takmadan önce, doğru plakayı almak için aslında ne tür bir madde taşıdığımı doğrulamak istiyorum. Aşağıdakilerden hangisi Sınıf 4 maddesini doğru şekilde tanımlar?","options":["Benzin veya motorin gibi yanıcı bir sıvı","Yanıcı ya da yanıcı olmayan bir sıkıştırılmış gaz","Cilde ve metale zarar verebilen aşındırıcı bir madde","Kolayca tutuşabilen veya yanabilen yanıcı bir katı"],"explanation":"Tehlike Sınıfı 4, kendiliğinden yanabilen ve ıslandığında tehlikeli olanlar dahil, kolayca tutuşabilen veya yanabilen yanıcı katıları kapsar."},"157":{"q":"Plakartlı bir araçla Teksas'ta bir tartı istasyonunda durdum ve bir müfettiş römorkumdaki turuncu panelde görünen 1203 dört haneli numarasını göstererek bu numaranın ona ne söylediğini soruyor. Hangi cevap doğrudur?","options":["Bu, taşıdığım belirli maddeyi tanımlayan kimlik (UN/NA) numarasıdır","Bu, taşıyıcı tarafından yüke atanan uygun sevkiyat adı kodudur","Bu, dokuz sınıftan hangisinin geçerli olduğunu gösteren tehlike sınıfı numarasıdır","Bu, 1.001 lb kuralının uygulanıp uygulanmadığını gösteren plakart tablo numarasıdır"],"explanation":"Sevkiyat belgelerindeki veya plakart üzerindeki 4 haneli sayı, taşınan tam maddeyi tanımlayan UN/NA kimlik numarasıdır."},"158":{"q":"Sefer öncesi kontrolümde, bir devlet polisi taşıdığım yük için 4 haneli UN/NA kimlik numarasını okumamı istiyor ki bunu Acil Müdahale Kılavuzu'nda (ERG) çapraz kontrol edebilsin. Numarayı bulmak için plakartlı römorkumun yan tarafına gidiyorum. Bu 4 haneli kimlik numarasını doğru şekilde nereden okumama izin verilir?","options":["Yalnızca sevk belgelerinde yazılı uygun sevkiyat adından; römorkun dış yüzeyinde asla görünmez","Ya doğrudan plakartın (etiketin) üzerinde ya da plakartın yanına monte edilmiş turuncu bir panel üzerinde","Yalnızca elmas plakartın alt köşesinde gösterilen tehlike sınıfı numarasından","Yalnızca römork şasisinde iniş takımı yakınına damgalanmış üretici bilgi plakasından"],"explanation":"4 haneli UN/NA kimlik numarası, ya plakartın ortasında ya da plakartın yanına monte edilmiş turuncu bir panelde gösterilebilir."},"159":{"q":"Yol kenarı denetiminde bir memur, römorkumun arkasındaki elmas şeklindeki plakartı (placard) işaret ederek, taşıdığım maddeyi tanımlayan tehlike sınıfı numarasını okumamı istiyor. Plakartın üstünde bir sembol, orta bandında yazılı kelimeler ve tek bir rakam var. Bu tehlike sınıfı numarasını bulmak için plakartın neresine bakmalıyım?","options":["Plakartın tam ortasında, maddenin yazılı adının basılı olduğu yerde","Elmasın en üst köşesinde, tehlike sembolünün veya piktografın hemen üstünde","Elmasın alt köşesinde, sembolün ve maddenin yazılı adının altında","Elmasın sol veya sağ kenarı boyunca, tehlike sembolünün yanında"],"explanation":"Bir plakartta tek haneli tehlike sınıfı numarası, sembolün ve yazılı tehlike adının altında, elmasın alt köşesinde yer alır."},"160":{"q":"Bir yük terminalinde, her biri farklı bir Tablo 2 tehlike sınıfına ait birkaç dökme olmayan paketle römorkumu yüklüyorum ve hiçbiri tek başına ayrı bir plaka gerektirecek 1.001 lb eşiğine ulaşmıyor. Her sınıf için ayrı bir plaka asmak yerine, tüm karışık sevkiyat için tek bir 'DANGEROUS' (TEHLİKELİ) plakası kullanmak istiyorum. Bu tek 'DANGEROUS' plakasını kullanmak hangi koşulda gerçekten izinlidir?","options":["Yalnızca römorktaki her paket tam olarak aynı tek tehlike sınıfına ait olduğunda","Yalnızca römork hiçbir düzenlemeye tabi tehlikeli madde taşımadığında","Yalnızca yük, navlunun yanında gönderilen tüketici gıda maddeleriyle sınırlı olduğunda","Yük, birlikte taşınan iki veya daha fazla farklı Tablo 2 tehlike sınıfı içerdiğinde"],"explanation":"DANGEROUS plakartı, dökme olmayan bir yük iki veya daha fazla Tablo 2 tehlike sınıfını bir araya getirdiğinde ayrı plakartların yerine kullanılabilir."},"161":{"q":"Kısa bir yerel sefer için Tablo 1 malzemesinden (Bölüm 2.3 zehirli gaz) tek bir küçük varil yüklüyorum. Tehlikeli maddenin toplam ağırlığı 1.000 librenin oldukça altında. Yola çıkmadan önce aracı nasıl plakartlamalıyım?","options":["Ne kadar az taşıdığıma bakılmaksızın plakartları aracın dört tarafına da takmalıyım, çünkü Tablo 1 malzemeleri herhangi bir miktarda plakart gerektirir.","Bu seferde plakarta gerek yok, çünkü plakartlamayı tetikleyen 1.001 librelik toplam brüt ağırlıktan daha azını taşıyorum.","Plakartlara ancak birleşik tehlikeli yüküm 1.001 libreye veya daha fazlasına ulaştığında ihtiyacım var, bu yüzden tek bir küçük varil muaftır.","Plakartlara yalnızca sefer eyaletler arasıysa veya kalabalık bir bölgeye giriyorsa ihtiyaç var, çünkü kısa bir yerel sefer bunları gerektirmez."],"explanation":"Bölüm 2.3 zehirli gaz, ağırlığa bakılmaksızın herhangi bir miktarda dört tarafa da plakart gerektiren bir Tablo 1 maddesidir."},"162":{"q":"Karışık yük taşıyan bir römork yüklüyorum ve araçtaki tek tehlikeli madde bir Tablo 2 ürünü. Sevkiyat belgelerim toplam brüt ağırlığın tam olarak 900 lb olduğunu gösteriyor. DPS plaka kurallarına göre, yola çıkmadan önce ne yapmam gerekir?","options":["Dört tarafa da plaka asmalıyım, çünkü Tablo 2'de listelenen tehlikeli bir maddenin herhangi bir miktarı her zaman plaka gerektirir","Plaka gerekmez, çünkü Tablo 2 maddeleri yalnızca 1.001 lb veya daha fazla toplam brüt ağırlıkta plaka gerektirir","Dört tarafa da plaka asmalıyım, çünkü yük Tablo 2 sevkiyatları için 100 lb raporlama eşiğinin üzerinde","Yalnızca arkaya plaka asmalıyım, çünkü 900 lb kısmi plaka gerektirir ancak dört taraflı tam plaka için yeterli değildir"],"explanation":"Tablo 2 maddeleri yalnızca toplam brüt ağırlıkları 1.001 pound veya daha fazlasına ulaştığında plakart gerektirir."},"163":{"q":"Bir göndericinin yükleme rampasında bir treyleri yüklüyorum ve göndericinin içeriği belirtmek için yapıştırdığı elmas şeklindeki tehlike uyarılarını fark ediyorum. Bu tehlike etiketlerinin nerede gösterilmesi gerekir?","options":["Treylerin dört tarafında, baktıkları yönden okunabilir şekilde","Taşıma belgelerinde, her kaydın yanındaki HM sütununda","Tek tek paketlerin ve konteynerlerin kendi üzerinde","Belgelerin saklandığı sürücü kapısındaki cepte"],"explanation":"Tehlike etiketleri, içeriğin tehlike sınıfını belirtmek için gönderici tarafından doğrudan her bir ambalaj ve kabın üzerine uygulanır."},"164":{"q":"Plaka gerektiren aşındırıcı (korozif) bir yük yüklüyorum ve yardımcı sürücüm bana dört adet baklava şeklinde AŞINDIRICI plakası veriyor. Bunların nereye konması gerektiğini düşündüğünü söylüyor, ama yola çıkmadan önce doğru yapmak istiyorum. Bu plakalar gerçekte nereye yerleştirilmelidir?","options":["Müfettişler kapılar açıldığında tehlikeyi görebilsin diye römork içindeki her bir paket ve ambalaja yapıştırılır","Sevk belgelerinde HM sütununda uygun sevkiyat adı, tehlike sınıfı ve kimlik numarasının yanına iliştirilir","Sürüş sırasında elimin ulaşabileceği yerde kalsın diye evraklarla birlikte sürücü kapısındaki cebe takılır","Aracın dört tarafına da takılır ve her biri baktığı yönden okunabilir olur"],"explanation":"Plakartlar aracın dört tarafına da yerleştirilir ve her biri baktığı yönden okunabilir olmalıdır."},"165":{"q":"Römorkumu yüklerken, iki karşılıklı yüzünde yukarı bakan bir çift siyah dikey okla işaretlenmiş mühürlü bir paket alıyorum. Gönderenin evrakları düzenli, ancak doğru yerleştirdiğimden emin olmak istiyorum. Bu yönlendirme okları bu paketle ne yapmamı gerektiriyor?","options":["Paketi her zaman dik tutmak, oklar yukarı bakacak şekilde, böylece kapaklar üstte kalır","Paketi yan yatırarak okların römork duvarına doğru yatay olarak bakmasını sağlamak","Nasıl sığarsa öyle istiflemek, çünkü oklar yalnızca forkliftin nereden kaldıracağını gösterir","Paketi baş aşağı çevirerek mühürlü ucun römork zeminine dayanmasını sağlamak"],"explanation":"Ambalaj yönlendirme okları, ambalajın okları yukarı bakacak şekilde dik tutulması ve kapakların üstte kalması gerektiği anlamına gelir."},"166":{"q":"Aşındırıcı bir yük için sevk belgesinin sefer öncesi incelemesini yapan yeni bir Tehlikeli Madde sürücüsüyüm. Her kayıt için doğru sevkiyat adını ve tehlike sınıfını açıkça görebiliyorum. Yola çıkmadan önce tanımın eksiksiz ve federal mevzuata uygun olduğunu doğrulamak için, bu temel sevkiyat tanımında AYRICA bulunması GEREKEN kalan bilgi hangisidir?","options":["Aşındırıcı yükün toplam beyan edilen dolar değeri","Madde için kimlik numarası (UN veya NA)","CDL belgemde gösterilen brüt araç ağırlık derecesi","Tehlikeli Madde onayımın son kullanma tarihi"],"explanation":"Eksiksiz bir temel sevkiyat tanımı, sırasıyla uygun sevkiyat adını, tehlike sınıfını ve UN veya NA kimlik numarasını içerir."},"167":{"q":"Bir yük için sevkiyat belgelerini inceliyorum ve malzemenin kaydının yanında Paketleme Grubu (Packing Group) olarak 'II' Roma rakamının yazılı olduğunu fark ediyorum. Yeni bir sürücü bana bu 'II' işaretinin sevkiyat hakkında aslında ne söylediğini soruyor. Aşağıdakilerden hangisi Paketleme Grubu'nun neyi gösterdiğine dair doğru açıklamadır?","options":["Malzemeye atanan tehlike sınıfı numarasını (1 ila 9) belirtir","Plaka (placard) zorunluluğunu tetikleyen asgari brüt ağırlığı verir","Malzemenin sunduğu göreceli tehlike derecesini gösterir (I, II veya III)","Sevkiyat adından sonra gelen UN/NA kimlik numarasını belirtir"],"explanation":"Roma rakamı I, II veya III ile gösterilen Paketleme Grubu, malzemenin sunduğu göreceli tehlike derecesini belirtir."},"168":{"q":"Bir tehlikeli madde sevkiyatını yüklüyorum ve sevk irsaliyesinde malzemenin ambalaj grubu \"PG I\" (Ambalaj Grubu I) olarak belirtilmiş. Yeni bir sürücü bana Romen rakamı \"I\"nin sadece listedeki ilk madde olduğu anlamına geldiğini ve üç ambalaj grubu içinde en düşük tehlike seviyesini temsil ettiğini söylüyor. Yükü teslim alıp imzalamadan ve plaka levhalarını takmadan önce, \"Ambalaj Grubu I\" bana bu malzemenin tehlike derecesi hakkında gerçekte ne söyler?","options":["En düşük tehlike derecesini gösterir, çünkü Ambalaj Grubu I en alt kademedir ve Ambalaj Grubu III en tehlikeli olandır","Yalnızca orta düzeyde bir tehlike gösterir ve Ambalaj Grubu II ile Ambalaj Grubu III arasında yer alır","Gerçek bir tehlike göstermez ve yalnızca maddenin sevk irsaliyesindeki sırasını belirtmek için kullanılır","En yüksek tehlike derecesini gösterir, çünkü Ambalaj Grubu I üç ambalaj grubu içinde en tehlikeli olanıdır"],"explanation":"Paketleme Grubu I, üç paketleme grubunun en tehlikelisi olduğundan en yüksek tehlike derecesini gösterir."},"169":{"q":"Karışık tehlikeli madde taşıyan bir dorse yüklüyorum ve iki paketimin farklı tehlike sınıflarına sahip olduğunu fark ediyorum. Onları yan yana istiflemeden önce ayrıştırma (segregasyon) tablosuna bakıyorum. Bu tablo bana aslında ne söylüyor?","options":["Hangi maddelerin birbiriyle uyumsuz olduğunu ve aynı yükte birlikte YÜKLENMEMESİ gerektiğini","Plakartları eşleşsin diye hangi maddelerin her zaman birlikte yüklenmesi gerektiğini","Sorumluluğumu azaltmak için hangi maddelerin önce satılması veya teslim edilmesi gerektiğini","Kapıları kapatmadan önce hangi maddelerin ikinci kez etiketlenmesi gerektiğini"],"explanation":"Ayrıştırma tablosu, hangi malzemelerin birbiriyle uyumsuz olduğunu ve aynı yükte birlikte yüklenmemesi gerektiğini gösterir."},"170":{"q":"Gönderici firmanın yükleme rampasındayım ve plakalı römorkuma birkaç varil Sınıf 8 aşındırıcı (korozif) madde yüklemek üzereyim. İlk varili hareket ettirirken, alt dikiş çevresinde ıslak, parlak bir film tabakası ve palet üzerinde küçük bir birikinti fark ediyorum. Bu paketlerden HERHANGİ birini yüklemeden önce, yükleme öncesi muayenemin doğrulaması gereken en önemli tek şey nedir?","options":["Her varilin römorkta kolayca fark edilebilmesi için parlak, yüksek görünürlüklü bir renge boyandığı","Paketlerin sızdırmadığı ve hasarsız olduğu, çünkü sızıntı ya da hasar belirtisi gösteren her kabı reddetmek zorundayım","Yükün sıkı kalması ve taşıma sırasında kaymaması için varillerin mümkün olduğunca yüksek istiflendiği","Yolculuk sırasında iç basıncın boşalabilmesi için tapaların gevşek ya da açık bırakıldığı"],"explanation":"Yüklemeden önce her ambalajı sızıntı veya hasar olmadığından emin olmak için kontrol edin ve sızıntı ya da hasar gösteren herhangi bir kabı reddedin."},"171":{"q":"Yoğun bir terminal sahasında römorkuma yanıcı sıvı (Sınıf 3) yüklüyorum. Etrafımda aynı anda birçok şey oluyor ve güvenli bir şekilde yükleme yapmak istiyorum. Bu tehlikeli maddeyi yüklerken aşağıdakilerden hangisini kargo alanından UZAK tutmam gerekir?","options":["Rıhtım ekibinin kullandığı bir palet transpaleti","Yan rıhtımda rölantide çalışan bir teslimat kamyonu","Açık alev veya kıvılcım çıkaran bir kaynak","Bir yığın boş ahşap palet"],"explanation":"Yanıcı malzemeler herhangi bir tutuşma kaynağından alev alabileceğinden, yükleme sırasında açık alev ve kıvılcım çıkaran kaynakları tehlikeli maddelerden uzak tutun."},"172":{"q":"Uzun bir eyaletler arası sefer için kapalı kasa kamyonuma plaka gerektiren birkaç varil ve kutu tehlikeli madde yüklüyorum. Onları kasaya aldıktan sonra, kapıları kapatıp yola çıkmadan önce bu kaplarla ne yapmam gerekir?","options":["Onları römorkun ön duvarına sıkıca dayayıp, yolculuk boyunca yerlerinde tutması için ön duvara güvenmek","Ağırlığı dengelemek için onları zemine eşit şekilde yaymak, sonra normal zemin sürtünmesinin onları yerinde tutmasına bırakmak","Yükün geri kalanı için zemin alanı açmak amacıyla onları tek bir yan duvara olabildiğince yüksek istiflemek","Her kabı, araç hareket halindeyken kayamayacak, sürüklenemeyecek veya devrilemeyecek şekilde destekleyip sabitlemek"],"explanation":"Her tehlikeli madde kabını, araç hareket halindeyken kayamayacak, yer değiştiremeyecek veya devrilemeyecek şekilde destekleyin ve sabitleyin."},"173":{"q":"Tehlikeli atık yükü taşıyorum ve terminalden ayrılmadan önce gönderici, diğer evraklarımla birlikte bana bir tehlikeli atık manifestosu veriyor. Tehlikeli madde kurallarına uymak için bu manifestoyla ne yapmam gerekir?","options":["İmzalamak ve bir kopyasını sevkiyat belgelerimle birlikte elimin uzanabileceği yerde tutmak","Taşıyıcının benim adıma dosyalaması için imzalanmış halde terminalde bırakmak","Teslimatta alıcı tesis imzalayana kadar imzasız olarak taşımak","Yolculuk bittikten sonra imzalı kopyayı posta ile devlet kurumuna göndermek"],"explanation":"Tehlikeli atık manifestosu sürücü tarafından imzalanmalı ve sürüş sırasında erişilebilir mesafede sevkiyat belgeleriyle birlikte saklanmalıdır."},"174":{"q":"H onaylı yeni bir sürücüyüm ve bir gönderici bana, yönetmeliklerin özellikle hiçbir koşulda hiçbir ticari araçla taşınamayacak maddelerden biri olarak listelediği bir madde için evrak veriyor. Başka bir şey yapmadan önce, bu yük hakkında doğru düşünme şekli nedir?","options":["Römorkun dört tarafına da tehlike levhası asarsam her miktarda taşınabilir","Taşınması yasaktır, bu yüzden hiçbir sürücü onu yasal olarak hiç taşıyamaz","Serbestçe taşınabilir çünkü H onayım her tehlike sınıfını kapsar","Asla levha gerektirmez, bu yüzden kimseye haber vermeden taşıyabilirim"],"explanation":"Bazı maddeler o kadar tehlikelidir ki taşınması tamamen yasaktır ve hiç kimse tarafından yasal olarak taşınamaz."},"175":{"q":"Sınıf 1 patlayıcılar olarak işaretlenmiş bir sevkiyatı yüklüyorum ve sevk belgesinde malzeme, sınıftan hemen sonra bir bölüm numarasıyla listelenmiş. Bir iş arkadaşım bana Sınıf 1'in tek ve bölünmemiş bir kategori olduğunu, bu yüzden bölüm numarasının yazım hatası olması gerektiğini söylüyor. Sınıf 1'in nasıl yapılandırıldığını hangi ifade doğru şekilde tanımlar?","options":["Sınıf 1 tek ve bölünmemiş bir kategoridir, bu nedenle sonrasındaki herhangi bir bölüm numarası bir hatadır","Sınıf 1, ambalaj renk kodlarına göre tam olarak iki gruba ayrılır","Sınıf 1, 1.1'den 1.6'ya kadar numaralandırılmış birkaç bölüme ayrılır","Sınıf 1'in alt grubu yoktur; bölümler yalnızca Sınıf 2'deki gazlar için vardır"],"explanation":"Tehlike Sınıfı 1 (Patlayıcılar) 1.1'den 1.6'ya kadar numaralandırılmış birkaç bölüme ayrılır."},"176":{"q":"Bir yük terminalinde, sevkiyat görevlisi bana \"Bölüm 1.1\" olarak etiketlenmiş bir yük için sevk belgelerini veriyor ve plaka takıp güzergâhı belirlemeden önce patlama potansiyelini ne kadar ciddiye almam gerektiğini soruyor. Tehlike bölümünün bana söylediğine göre, kararımı hangi ifade yönlendirmeli?","options":["Yalnızca fırlatma tehlikesi taşır, bu yüzden tam bir patlamadan çok uçan parçalara karşı plan yaparım","Sadece küçük bir yangın riski oluşturur, bu yüzden standart bir yangın söndürücü ve dikkatli yakıt ikmali tek ihtiyacım olan şeydir","Yalnızca ambalajla sınırlı hafif bir patlama tehlikesi vardır, bu yüzden binalardan uzaklık büyük bir endişe değildir","Kitlesel patlama tehlikesi taşır, yani tüm yük aynı anda patlayabilir, bu yüzden onu en tehlikeli patlayıcı bölümü olarak ele almalıyım"],"explanation":"Bölüm 1.1 patlayıcıları kütle patlaması tehlikesi taşır; tüm yük aynı anda patlayabilir, bu da onları en tehlikeli patlayıcı bölümü yapar."},"177":{"q":"Plakartlı Bölüm 1.2 patlayıcı yük taşıyorum ve küçük bir kasabada yemek molası için durmam gerekiyor. Sürücü olarak hangi davranış bu yük için kuralları ihlal etmez?","options":["Araçla kalmak ya da yetkili bir kişiye gözetletmek, böylece yük asla başıboş bırakılmaz","Kabini kilitlemek, frenleri çekmek ve ben içeride yemek yerken aracı restoranın otoparkında bırakmak","Pencereden göz kulak olabilmek için aracı yolun trafiğe açık kısmından 5 fit içinde park etmek","Bir binanın yanında durduğu sürece yükü 2 saate kadar başıboş bırakmak"],"explanation":"Bölüm 1.1, 1.2 ve 1.3 patlayıcıları asla gözetimsiz bırakılmamalıdır; sürücü veya başka bir yetkili kişi her zaman yükün yanında kalmalı ve onu gözetmelidir."},"178":{"q":"Bölüm 1.1 patlayıcı madde taşırken, iki şeritli bir kamuya açık karayolunda römorkumda mekanik bir arıza oluşuyor. İkinci bir şirket kamyonu olay yerine geliyor ve sevkiyatçım, yükün hareket etmeye devam edebilmesi için patlayıcı yükü diğer araca aktarmamı istiyor. Tehlikeli madde kurallarına göre, araçlar arasındaki bu aktarmayı nerede yapmama izin verilir?","options":["Tam burada karayolu banketinde, çünkü ikinci kamyon zaten olay yerinde ve yükü almaya hazır","Gerçek bir acil durum olmadıkça kesinlikle kamuya açık yolda değil — aktarma, terminal veya depo gibi yoldan uzak güvenli bir yerde yapılmalıdır","Aktarma sırasında her iki aracın dört tarafına da uygun tehlike levhalarını yerleştirdiğim sürece güzergah boyunca herhangi bir yerde","Yolda yapmak burada sorun değil, çünkü sevkiyatçım yükü hareket halinde tutmam için doğrudan emir verdi"],"explanation":"Sınıf 1 patlayıcılar, gerçek bir acil durum dışında kamuya açık yolda araçlar arasında aktarılamaz; aktarma terminal gibi güvenli, yol dışı bir yerde yapılmalıdır."},"179":{"q":"Bölüm 1.2 patlayıcı madde taşıyorum ve dinlenmek için kenara çekmem gerekiyor. İleride birinin yol kenarında kamp ateşi yaktığı bir dinlenme alanı görüyorum. Mesafe kuralları aklımdan geçiyor. Park ettiğim patlayıcı yüküm ile o açık ateş arasında korumam gereken en az mesafe nedir?","options":["5 feet, yolun trafiğe açık kısmından korumam gereken aynı asgari mesafe","10 feet, savrulan kıvılcımlardan uzak kalmaya yetecek kadar","300 feet, patlayıcı ile açık ateş arasında gereken ayrım mesafesi","1 feet, çünkü ateş bir kamp ateşi halkasının içinde sınırlı"],"explanation":"Patlayıcı taşıyan bir araç açık ateşten en az 300 fit uzakta park edilmelidir."},"180":{"q":"Yola çıkmadan önce, hangi bölümü taşıdığımı doğrulamak için bir Sınıf 2 gaz yükünün sevkiyat belgelerini inceliyorum. Sınıf 2'nin birden fazla gaz türünü kapsadığını biliyorum ve taşıyıcı bana Sınıf 2'nin tanınan üç bölümünün yanıcı gaz (2.1), yanıcı olmayan gaz (2.2) ve plaka (placard) takmak için belirlemem gereken üçüncü bir bölüm olduğunu söyledi. Aşağıdakilerden hangisi Sınıf 2 gazlarının bu tanınan üçüncü bölümüdür?","options":["Yanıcı katı gaz, çünkü bazı Sınıf 2 gazları yanabilen katı bir forma dönüşebilir","Aşındırıcı gaz, çünkü tanklardaki basınçlı gazlar Sınıf 8 aşındırıcı malzeme gibi davranır","Yalnızca sıvı gaz, çünkü basınç altında depolanan gazlar her zaman sıvı halde taşınır","Zehirli (toksik) gaz, bu Bölüm 2.3'tür ve herhangi bir miktarda plaka gerektirebilir"],"explanation":"Sınıf 2 gazlar, herhangi bir miktarda plaka gerektiren bir Tablo 1 maddesi olan Bölüm 2.3 zehirli (toksik) gazı içerir."},"181":{"q":"Bir mola sırasında, plakartlı yüküm üzerindeki sıkıştırılmış gaz tüplerinden birinin valf yakınında yavaşça sızdırdığını ve tısladığını fark ediyorum. Yakındaki park alanında yolcular dolaşıyor. Aşağıdakilerden hangisi alınacak EN uygun acil önlemdir?","options":["İnsanları tüpten uzaklaştırmak, alanı boş tutmak ve acil yardım çağırmak","Valfi sıkıştırıp sızıntıyı kendiniz mühürleyerek gazın çıkışını durdurmak","Basıncın dengelenmesi ve tıslamanın durması için tüpü hafifçe ısıtmak","Valfin yerine oturması ve basıncın düşmesi için tüpü yuvarlayıp sallamak"],"explanation":"Sızıntı yapan bir basınçlı gaz tüpünde insanları uzaklaştırın, alanı boş tutun, ateşleme kaynaklarını önleyin ve kendiniz onarmaya çalışmak yerine acil yardım çağırın."},"182":{"q":"7. sınıf radyoaktif bir sevkiyat yüklüyorum ve nakliyeci bana radyoaktif etiketli paketler veriyor. Her etiket, paketin radyasyon seviyesini bildiren bir numara gösteriyor. Bu 7. sınıf etiketlerinde hangi numaralandırma sistemini göreceğim?","options":["Etiketler, paketin taşıma endeksine uygun olarak A, B veya C ile numaralandırılır","Etiketler, paketin radyasyon seviyesini gösterecek şekilde I, II veya III ile numaralandırılır","Etiketler, tehlike sınıfı sistemine uygun olarak 1'den 9'a kadar numaralandırılır","Etiketler, paketleme grubu harfine uygun olarak X, Y veya Z ile numaralandırılır"],"explanation":"Sınıf 7 radyoaktif madde, paketin radyasyon seviyesini gösteren I, II veya III Roma rakamlarıyla işaretlenmiş üç etiket kategorisi kullanır."},"183":{"q":"Birkaç Sınıf 7 radyoaktif paket yüklüyorum ve gönderici her etikette basılı olan 'taşıma indeksi' sayısını gösteriyor. Römorkumu güvenli ve yasal şekilde yüklemek için bu taşıma indeksi değeri bana aslında ne söyler?","options":["Sigorta amacıyla radyoaktif içeriğin toplam parasal değerini","Araçtaki tüm radyoaktif paketlerin birleşik brüt ağırlığını","Paketi taşırken ve elleçlerken gereken radyasyon kontrolünün derecesini","O radyoaktif maddeye atanan UN/NA kimlik numarasını"],"explanation":"Sınıf 7 radyoaktif paketteki taşıma indeksi, elleçleme ve yükleme sırasında gereken radyasyon kontrol derecesini gösterir."},"184":{"q":"Şehrin karşısına plakartlı bir aşındırıcı madde yükü taşıyorum ve navigasyonum aynı varış noktasına yaklaşık aynı uzunlukta üç olası güzergah sunuyor. Teksas tehlikeli madde güzergah kılavuzuna göre, bunlardan hangisini seçmek için en çok çaba göstermeliyim?","options":["Yüzeydeki trafik ışıklarından kaçınıp birkaç dakika kazandırdığı için uzun bir yeraltı tünelinden geçen güzergah","Bir etkinlik tam dağılırken kalabalık bir şehir merkezi stadyumunun hemen yanından geçen güzergah","Daha geniş ve iyi aydınlatılmış sokaklarda kalmak için birkaç kalabalık alışveriş merkezinin yanından dolanan güzergah","Açık ana yollarda kalan ve hem tüneli hem de kalabalık etkinlik bölgelerini atlayan güzergah"],"explanation":"Tehlikeli madde sürücüleri, mümkün olduğunda tünellerden ve kalabalık ya da yoğun nüfuslu bölgelerden kaçınan belirlenmiş güzergahları izlemelidir."},"185":{"q":"Bölüm 1.1 patlayıcı madde yükünü eyalet boyunca taşımak üzere görevlendirildim. Eğitmenim, bu yolculuktan önce federal kuralların taşıyıcımın hazırlamasını, benim de taşıyıp uymamı zorunlu kıldığı belirli bir yazılı belge olduğunu söylüyor. Söz ettiği belge hangisidir?","options":["Yolculuğun izlemesi gereken yazılı bir güzergah planı","Yazılı bir sürücü günlük yakıt ve kilometre kaydı","Patlayıcı yük için yazılı bir satış sözleşmesi","Yazılı 72 saatlik yol kenarı hava durumu tahmini"],"explanation":"Patlayıcı yükler (Bölüm 1.1, 1.2, 1.3) taşıyıcı tarafından hazırlanan ve sürücünün taşıdığı yazılı bir güzergah planına göre taşınmalıdır."},"186":{"q":"Plakart (placard) takılı aşındırıcı madde yüküyle uzun bir seferin üç saatindeyim ve tuvaleti kullanmak için bir dinlenme alanına girdim. Kamyon, sefer öncesi kontrolümden bu yana sorunsuz çalışıyor ve yola çıktığımda lastiklerim iyi görünüyordu. Otoyola geri dönmeden önce lastiklerimle ilgili ne yapmalıyım?","options":["Hiçbir şey — kapsamlı bir sefer öncesi lastik kontrolü, bir lastik gerçekten patlamadıkça tüm sefer boyunca beni güvende tutar","Lastikleri şimdi kontrol etmeliyim, çünkü onları seferin başında ve ardından her 2 saatte bir veya her 100 milde bir kontrol etmem gerekir","Sadece lastik basıncı uyarı ışığı yanarsa ya da kamyonun bir tarafa çektiğini hissedersem kontrol etmeliyim","Beklemeli ve lastikleri günde bir kez kontrol etmeliyim; uzun bir seferdeki plakartlı yük için bu yeterlidir"],"explanation":"Plakartlı tehlikeli madde yükü taşıyan sürücü, lastikleri yolculuğun başında ve her durakta, yani her 2 saatte veya 100 milde bir kontrol etmelidir."},"187":{"q":"Tehlikeli madde plakartlı tankerimi, güzergâhın bir sonraki bölümünden önce mazotu tamamlamak için yakıt adasına çekiyorum. Pompalamaya başlamaya hazırlanırken, kurallara uygun kalmak için motoru ve yakıt ikmali işlemini nasıl yönetmem gerektiğini aşağıdakilerden hangisi açıklar?","options":["Hava sistemi basınçlı kalsın diye motoru düşük rölantide bırakmak ve tabancayı kendim tutmak","Motoru kapatmak, tabancayı otomatik kilitleyip depo dolarken içeri girip ödeme yapmak","Motoru kapatmak ve tüm işlem boyunca bir kişiyi fiziksel olarak tabancanın başında tutarak akışı kontrol etmek","Aktarma pompasını beslemek için motoru yüksek rölantide çalışır tutmak ve tabancanın başında kimseye gerek olmamak"],"explanation":"Plakartlı bir araca yakıt alırken motor kapalı olmalı ve biri tüm süre boyunca tabancada kalarak yakıt akışını kontrol etmelidir."},"189":{"q":"Plakartlanmış bir aşındırıcı sıvı yükü taşırken, varillerden biri otoyol banketine ciddi şekilde sızmaya başlıyor ve tehlikeli madde dökülmesine yol açıyor. Çevredekileri uyardıktan, insanları uzak tuttuktan ve sigara içilmesini önledikten sonra, taşıyıcınız bu ciddi olayı Ulusal Müdahale Merkezi'ne (National Response Center) bildirmeniz talimatını veriyor. Olayı bildirmek için hangi numarayı ararsınız?","options":["411, sizi en yakın tehlikeli madde müdahale birimine bağlamak için bilinmeyen numaralar danışma hattı","911, yerel acil durum hattı; bu hat Ulusal Müdahale Merkezi bildirim şartını tamamen karşılar","1-800-555-1212, raporu ilgili federal kuruma yönlendiren ücretsiz hat","1-800-424-8802, ciddi tehlikeli madde olaylarını bildirmek için Ulusal Müdahale Merkezi hattı"],"explanation":"Ciddi tehlikeli madde olayları, 1-800-424-8802 numaralı Ulusal Müdahale Merkezi'ne bildirilmelidir."},"190":{"q":"Tehlikeli madde plakartlı römorkumdaki bir varil, ıssız bir banket üzerinde aşındırıcı (korozif) sıvı sızdırmaya başlıyor ve bu kimyasalla ne yapacağımı ya da nasıl nötralize edeceğimi hiç bilmiyorum. Çevredekileri uyarıp insanları uzak tuttuktan sonra, bu belirli tehlikeli maddenin nasıl ele alınacağına dair 24 saat acil rehberlik almak için hangi numarayı aramalıyım?","options":["1-800-424-9300, CHEMTREC acil hattı","1-800-275-8777, ulusal kargo ve posta yardım hattı","1-888-275-8255, federal karayolu güvenliği bildirim hattı","1-800-829-1040, federal kurum bilgi hattı"],"explanation":"CHEMTREC, 1-800-424-9300 numaralı 24 saat açık acil hatla sürücülere bir olayda tehlikeli maddenin elleçlenmesi için anında teknik rehberlik sağlar."},"191":{"q":"Teksas boyunca aşındırıcı (korozif) yük taşıyan plakartlı bir aracı, emniyet kemerim bağlıyken kullanıyorum. Bir DPS memuru beni durdurup tehlikeli madde sevkiyat belgelerimi soruyor. El kitabı kurallarına göre, ben aracı kullanırken bu belgeler nerede olmalıydı?","options":["Su geçirmez bir zarfa mühürlenmiş ve römorkta yükün yanında saklanmış olmalı","Elimin uzanabileceği yerde ve açıkça görünür şekilde, diğer belgelerimin en üstünde durmalı","Sürücü koltuğunun arkasındaki yatakta, seyir defteri klasörümün içine fermuarlı olarak konmalı","Kabin kırılıp girilse bile güvende kalması için torpido gözüne kilitlenmiş olmalı"],"explanation":"Sürüş sırasında tehlikeli madde sevkiyat belgeleri sürücünün erişebileceği bir yerde ve diğer kağıtların üzerinde, açıkça görünür şekilde bulunmalıdır."},"192":{"q":"Plakart takılmış tehlikeli madde yükü taşıyorum ve tuvaleti kullanmak için bir dinlenme alanına giriyorum. Motoru kapatıp birkaç dakikalığına kabinden ayrılacağım. Texas DPS kurallarına göre, ben kamyondan uzaktayken sevkiyat belgelerim nerede olmalıdır?","options":["Ben yokken kimse kurcalayamasın diye torpido gözüne kilitlenmeli","Gömlek cebime katlanıp dinlenme alanına benimle birlikte taşınmalı","Görünür şekilde sürücü koltuğunun üzerinde veya sürücü kapısı cebinde bırakılmalı","Acil Müdahale Kılavuzu'nun (ERG) yanında yan kargo bölmesinde saklanmalı"],"explanation":"Sürücü kabinden ayrıldığında, tehlikeli madde sevkiyat belgeleri müdahale ekiplerinin bulabilmesi için sürücü koltuğunda görünür şekilde veya sürücü kapısı cebinde bırakılmalıdır."},"193":{"q":"Bir dinlenme tesisinde park hâlindeyim ve römorkum Sınıf 3 yanıcı sıvılar için plakart (placard) taşıyor. Birkaç sürücü aracımın yanında sohbet ediyor ve biri sigara yakıyor. Plakartlı yüküm için federal sigara kuralına uymak amacıyla, herkesin yanan sigarayı aracımdan en az ne kadar uzakta tutması gerekir?","options":["En az 5 fit; bu, plakartlı bir yükle yolun kullanılan kısmından uzakta park ederken gereken aynı tampon mesafedir","En az 2 fit; çünkü yanıcı sıvı tankın içinde sızdırmaz şekilde kapalıdır ve çok az risk oluşturur","En az 100 yarda; bu, demir yolu geçidinde başıboş bırakılan patlayıcılardan korunan aynı mesafedir","Araçtan en az 25 fit; çünkü yanıcı bir yükün bu menzili içinde sigara içmeye izin verilmez"],"explanation":"Patlayıcı, oksitleyici veya yanıcı madde taşıyan plakartlı bir aracın 25 fit yakınında sigara içmek yasaktır."},"194":{"q":"Texas genelinde Bölüm 1.1 patlayıcı yükü taşımakla görevlendirilen yeni bir sürücüyüm. Gönderici yükü sınıflandırıp etiketledi ve taşıyıcı seferi bana verdi. Avludan çıkmadan önce, aşağıdakilerden hangisini kabinde YAZILI olarak hazır bulundurmam gerekir?","options":["Yolculuk için yazılı bir güzergah planı ve yükün sevkiyat belgeleri","Kantardan imzalı bir ağırlık fişi ve yakıt makbuzumun bir kopyası","Güzergah boyunca dinleyeceğim radyo kanallarının yazılı bir listesi","Geçeceğim her ilçeyi kapsayan noter onaylı bir hava durumu tahmini"],"explanation":"Sınıf 1.1 patlayıcıları taşımadan önce sürücü, yük için sevk belgeleriyle birlikte yazılı bir güzergah planı bulundurmalıdır."},"195":{"q":"Bir rampada plakart taşıyan tehlikeli madde sevkiyatını yüklüyorum ve her paketi römorkuma koymadan önce inceliyorum. Gönderici bana dört kap veriyor. Taşımayı reddetmem gereken HANGİSİDİR?","options":["Dikişinde veya kapağında görünür hasar olmayan, sıkıca mühürlenmiş bir varil","Tabanındaki bir çatlaktan aşındırıcı bir ürünün yavaşça sızdığı bir kova","Dış yüzeyine doğru tehlike sınıfı etiketi uygulanmış bir karton kutu","Düzgünce kapatılmış ve sevkiyat belgelerimdeki açıklamayla eşleşen bir kutu"],"explanation":"Sürücü, çatlaktan ürün sızan bir paket gibi sızıntı yapan herhangi bir tehlikeli madde sevkiyatını reddetmelidir."},"196":{"q":"Zaten A Sınıfı CDL'ye sahibim ve şimdi plakartlı aşındırıcı madde yükleri taşıyabilmek için H onayını eklemek istiyorum. Texas DPS bu onayı vermeden önce, temel CDL'm için gerekli OLMAYAN hangi ek koşulu yerine getirmem gerekir?","options":["İkinci bir DOT sağlık muayenesinden geçmek ve güncellenmiş bir sağlık muayene sertifikası sunmak","Plakartlı bir tanker aracı kullanarak ayrı bir direksiyon başında beceri sınavını tamamlamak","Parmak izi alınması ve geçmiş araştırmasını içeren bir TSA güvenlik tehdidi değerlendirmesini geçmek","DPS'te CDL görme taramasını ve genel bilgi yazılı sınavını yeniden yapmak"],"explanation":"Tehlikeli madde onayı, parmak izi alma ve geçmiş kontrolünü içeren bir TSA güvenlik tehdit değerlendirmesinden geçmeyi özellikle gerektirir."},"197":{"q":"Texas CDL ehliyetimi Tehlikeli Madde (H) onayıyla birkaç yıldır taşıyorum ve her sağlık muayenesini zamanında geçiyorum. Daha yeni bir sürücü bana, TSA güvenlik tehdit değerlendirmesini geçerek H onayını bir kez kazandıktan sonra belgemin o kısmının kalıcı olduğunu ve temel CDL'im geçerli kaldığı sürece bununla bir daha hiç uğraşmam gerekmediğini söylüyor. Tehlikeli Madde onayım hakkında hangi ifade doğrudur?","options":["TSA tehdit değerlendirmesi geçildikten sonra ömür boyu sabitlenir, bu nedenle o kısımla ilgili başka hiçbir işlem asla gerekmez.","Yalnızca DOT sağlık muayenemi geçmeye devam ettiğim sürece geçerli kalır; onayı belirleyen şey budur.","Temel Texas CDL'imi aktif tuttuğum sürece otomatik olarak aktarılır ve asla sona ermez.","Periyodik olarak yenilenmesi gerekir; bu da yeni bir TSA güvenlik tehdit değerlendirmesinden / arka plan kontrolünden geçmeyi gerektirir."],"explanation":"Tehlikeli madde onayı süreyle sınırlıdır ve yeni bir TSA güvenlik tehdit değerlendirmesi geçilerek periyodik olarak yenilenmelidir."},"198":{"q":"Plakartlı (aşındırıcı/korozif) bir yük taşırken bir valf arızalanıyor ve ürün banketin üzerine sızmaya başlıyor. Kabinden Acil Müdahale Kılavuzu'nu (ERG) alıyorum. Bu durumda ERG aslında bana ne yapmamda yardımcı olmak için tasarlanmıştır?","options":["Maddenin tehlikelerini ve dökülme için doğru ilk müdahale adımlarını belirleyerek kendimi ve halkı korumam için","Taşıyıcının doğru bir sigorta talebi düzenleyebilmesi için kaybedilen ürünün parasal değerini hesaplamak için","Dizel israf etmemek adına olay yerinin etrafından en yakıt verimli alternatif güzergahı belirlemek için","Temizlik ekibini beklerken en yakın onaylı konaklama ve dinlenme alanını bulmak için"],"explanation":"Acil Müdahale Kılavuzu, sürücünün bir maddenin tehlikelerini ve kendisini ve halkı korumak için doğru ilk dökülme önlemlerini belirlemesini sağlar."},"199":{"q":"Plakartlı tankımdan bir kaza yerinde sızıntı var. Bir itfaiyeci koşarak gelip taşıma belgelerimdeki dört haneli kimlik numarasını okumamı istiyor. Biri HARİÇ, aşağıdakilerin tümü bu numaranın onun için neden önemli olduğunu açıklıyor. Onun bu numaraya gerçekte hangi amaçla ihtiyacı var?","options":["Kargonun dolar değerini ona söyler, böylece taşıyıcının hasar talebini düzenleyebilir","Malzemeyi Acil Durum Müdahale Kılavuzu'nda (ERG) aramasına ve doğru müdahale prosedürlerini bulmasına olanak tanır","H onayımın ve TSA güvenlik taramamın bu yük için geçerli olduğunu doğrular","Uygun sevkiyat adını gösterir, böylece telsizle merkeze yüksek sesle okuyabilir"],"explanation":"Dört haneli UN/NA kimlik numarası, müdahale ekibinin maddeyi Acil Müdahale Kılavuzu'nda arayarak doğru müdahale prosedürlerini bulmasını sağlar."},"200":{"q":"Plakart taşıyan bir yük taşırken römorkumun altından duman çıkmaya başlıyor ve alevlerin lastikler boyunca yayıldığını görüyorum. Kabinde küçük bir yangın söndürücüm var, ama yangın güvenli bir şekilde kontrol edebileceğimden çoktan büyük. Aşağıdaki bir seçenek DIŞINDA, listelenen her eylem bu durumu daha tehlikeli hale getirir. Gerçekte yapmam gereken eylem hangisidir?","options":["Hangi varillerin yandığını tam olarak görüp müdahale ekiplerine anlatabilmek için kargo kapılarını açmak","Söndürücümü kapıp yangın tamamen sönene veya yardım gelene kadar yangınla kendim mücadele etmeye devam etmek","Çevredekileri uzakta tutmak, rüzgar üstünde durmak ve hemen acil müdahale ekiplerini aramak","İtfaiyenin bana ulaşması daha kısa olsun diye yanan aracı en yakın kasabaya sürmek"],"explanation":"Plakalı tehlikeli madde yükü yandığında ve kontrolünüzün dışındaysa, etraftakileri uzak tutun, rüzgar üstünde durun ve hemen acil müdahale ekiplerini arayın."},"201":{"q":"Plakartlı (placard) bir tehlikeli madde yükü taşıyorsunuz ve GPS sizi neredeyse bir saat kazandıracak uzun bir karayolu tünelinden geçirmek istiyor. Taşıdığınız maddenin o tünelde izinli olup olmadığından emin değilsiniz. Tünel girişine varmadan ÖNCE İLK olarak ne yapmalısınız?","options":["Hızınızı düşürün ve her iki şeridi açık tutun, böylece tünelden hızlı ve güvenli şekilde geçin","İçeride tünel görevlilerinin sizi durdurmaması için girmeden önce plakartları çıkarın","Tünel girişinin hemen içinde durun ve devam edip edemeyeceğinizi sormak için taşıyıcı firmanızı arayın","Belirlenmiş güzergah kurallarını kontrol edin, çünkü bazı tehlikeli maddeler tünellerde yasaktır ve farklı bir güzergah gerekebilir"],"explanation":"Bazı tehlikeli maddeler tünellerde yasaktır, bu yüzden sürücü önce belirlenmiş güzergah kurallarını kontrol etmelidir çünkü farklı bir güzergah gerekebilir."},"202":{"q":"Taşıyıcım, plakartlı tehlikeli madde seferinden önce bana yazılı bir güvenlik planı verdi ve sevkiyat belgelerini korumak, güzergâhımı doğrulamak ve römorka yetkisiz erişimi sınırlamak için planın prosedürlerini uygulamamı istedi. Teksas DPS açısından, bu güvenlik planının asıl amacı (PRIMARY) nedir?","options":["Tehlikeli maddelerin yetkisiz kişilerce çalınması veya kötüye kullanılması olasılığını azaltmak","Yükleme ve boşaltmayı hızlandırarak teslimatın planlanan saatten önce varmasını sağlamak","Duraklar arasında mümkün olan en kısa güzergâhı çizerek yakıt tüketimini düşürmek","Kargo bölümünü temiz tutarak maddelerin taşıma sırasında kirlenmesini önlemek"],"explanation":"Bir tehlikeli madde güvenlik planı, tehlikeli maddelerin yetkisiz kişilerce çalınma veya kötüye kullanılma olasılığını azaltmak için vardır."},"203":{"q":"Tabelalı (placard) bir aşındırıcı madde yükünü tanımadığım bir şehirden geçirerek taşıyorum ve bir gece önce durup rotamı planlıyorum. Texas CDL El Kitabına göre, rotamı önceden planlamanın bir tehlikeli madde sürücüsü için bu kadar önemli olmasının ASIL nedeni nedir?","options":["Yolculuğun ne kadar süreceğini zaten bildiğim için yol boyunca yapılan lastik kontrollerini atlamama olanak tanır","Tabelalı yükümün yasak olduğu kısıtlı bölgeleri belirleyip onlardan uzak durmama yardımcı olur","Yakıttan tasarruf etmek için açık otoyol kesimlerinde tabelalarımı çıkarmama izin verir","Güzergah boyunca en ucuz yakıt istasyonlarını ve dinlenme yerlerini bulmamı garanti eder"],"explanation":"Güzergahı önceden planlamak, sürücünün plakalı yükün yasak olduğu kısıtlı bölgeleri belirlemesine ve bunlardan uzak durmasına yardımcı olur."},"204":{"q":"Bir yük terminalinde römork yüklüyorum ve sevk irsaliyemde, yükleme rampasında bekleyen diğer tehlikeli maddelerle birlikte birkaç palet Sınıf 1 (Bölüm 1.1) patlayıcı madde bulunuyor. Rampa ekibinin her şeyi üst üste istiflemesine izin vermeden önce, hangi ürünlerin patlayıcılarla aynı yükte taşınabileceğine karar verirken neyi esas almalıyım?","options":["Patlayıcılar, her palet ayrı ayrı sabitlenip kaymayacak şekilde desteklendiği sürece herhangi bir tehlike sınıfıyla aynı yükte taşınabilir","Birleşik yük, römork için 1.001 librelik plaka takma eşiğinin altında kaldığı sürece patlayıcılar her şeyle birlikte yüklenebilir","Ayrıştırma (yükleme/boşaltma) tablosu, patlayıcıların belirli diğer tehlikeli maddelerle birlikte yüklenmesini yasaklar, bu yüzden birleştirmeden önce tabloyu kontrol etmeliyim","Patlayıcılar tamamen tek başına yüklenmeli ve hiçbir başka yükle asla aynı römorku paylaşmamalıdır"],"explanation":"Bazı ürünlerin birlikte yüklenmesi yasak olduğundan, patlayıcıları diğer tehlikeli maddelerle birleştirmeden önce daima ayrıştırma (yükleme/boşaltma) tablosuna bakın."},"205":{"q":"Yükleme rampasındayım ve römorkuma 8. sınıf aşındırıcı sıvı dolu birkaç varil ve kovayı elle yüklemek üzereyim. Rampa görevlisi, kayışlarla bağlamadan önce her kabı nasıl yerleştirmek istediğimi soruyor. Yükü güvenli paketlemek ve sıvının içeride sızdırmaz biçimde kalması için her kabı nasıl konumlandırmalıyım?","options":["Variller sıkıca iç içe geçip yolda daha az kaysın diye yan yatırılmış olarak","Sızan herhangi bir sıvı kapaktan uzağa aksın diye ağızları aşağı dönük olarak","Çizilmesinler diye tehlike etiketleri duvara dönük olarak","Dik durur şekilde, ağızları yukarı bakacak biçimde, kapaklar sıvı seviyesinin üstünde kalsın diye"],"explanation":"Sıvı tehlikeli maddeleri, ağızları sıvı seviyesinin üstünde kalsın ve contalar sızdırmasın diye kapakları yukarı bakacak şekilde dik yükleyin."},"206":{"q":"Bir treyleri aşındırıcı (Sınıf 8) malzeme kolileriyle elle yüklüyorum ve bir rıhtım işçisi ağır kutuları daha hızlı yerine sürüklemem için bana metal bir yük kancası uzatıyor. Hiçbir şeye dokunmadan önce, bu kancayı bu paketler üzerinde kullanmamı hangi kural engellemeli?","options":["Tehlikeli madde paketlerini delebilecek, yırtabilecek veya başka şekilde hasar verebilecek hiçbir kanca veya alet kullanmamalıyım","Kutuları dik tuttuğum ve etiketleri dışa dönük bıraktığım sürece kancayı serbestçe kullanabilirim","Kancalar Sınıf 8 için yalnızca treylerin dört tarafına da plaket taktıktan sonra kullanılabilir","Kancalara yalnızca yüklemeden sonraki ilk 100 mil içinde lastikleri kontrol edersem izin verilir"],"explanation":"Ambalajın zarar görmesi içeriğin sızmasına yol açabileceğinden, tehlikeli madde ambalajını delebilecek, yırtabilecek veya hasar verebilecek kanca ya da hiçbir alet kullanmayın."},"207":{"q":"Sıcak bir öğleden sonra römorkuma basınçlı gaz tüplerini (Sınıf 2) yüklüyorum. Bunları kurallara uygun şekilde taşımak için, yola çıkmadan önce bu tüplere ne yapmalıyım?","options":["Yük yolda yerine oturdukça kayabilmeleri için onları gevşek bir şekilde yatırmak","Hareket edemeyecek şekilde sıkıca sabitlemek ve ısı kaynaklarından korunmalarını sağlamak","İç basıncın yavaşça boşalması için vanaları hafif açık şekilde dik durmalarını sağlamak","Onları sıcak römork duvarına dayayarak yüksekçe istiflemek ve yalnızca alt sırayı takozlamak"],"explanation":"Sıkıştırılmış gaz tüplerini kayıp düşmeyecek şekilde sabitleyin ve ısıdan uzak tutun; çünkü ısı iç basıncı artırarak patlamaya yol açabilir."},"208":{"q":"Teksas'ta bir sefer öncesi tankere tehlike levhaları (placard) takıyorum ve iki levha olduğunu fark ediyorum: ana tehlike sınıfı için büyük bir birincil levha ve alt köşede sınıf numarası yazmayan daha küçük ikinci bir levha. Eğitmenim ikincisine 'yan (subsidiary)' levha diyor. Bu yük hakkında bana ne anlatıyor?","options":["Yük yeniden yüklenmeden önce gönderenin kullandığı eski, 'önceki' sınıflandırmayı doğrular","Tankın boş olduğunu ve içinde yalnızca kalıntı bulunduğunu gösterir","Maddenin birincil tehlike sınıfının ötesinde ek bir tehlike taşıdığını uyarır","Müdahale ekiplerinin ne kadar ürün olduğunu bilmesi için mevcut yakıt seviyesini işaretler"],"explanation":"Yardımcı (ikincil) plaka, maddenin birincil tehlike sınıfının ötesinde taşıdığı ek bir tehlikeyi belirtir."},"209":{"q":"Plakartlı (placard) bir aşındırıcı madde yükü taşımaya hazırlanıyorum ve nakliyeci bana, üst kısmında bir acil müdahale telefon numarası bulunan sevkiyat belgelerini veriyor. Belgeleri imzalayıp yola çıkmadan önce, bu acil müdahale numarasının hangi şartı sağlaması gerekir?","options":["Yalnızca nakliyecinin normal hafta içi mesai saatlerinde ulaşılabilir olması yeterlidir","Birisi daha sonra geri ararsa, kayıtlı bir sesli mesaj kutusuna yönlendirilebilir","Belgelerde adı geçen sürücünün kişisel cep telefonu numarası olmasına izin verilir","Tehlikeli madde taşınırken her zaman görevli personelle donatılmış ve sürekli izlenen bir numara olmalıdır"],"explanation":"Sevkiyat belgelerindeki acil durum telefon numarası, tehlikeli madde taşınırken her zaman görevli biri tarafından izlenip yanıtlanmalıdır."},"210":{"q":"Plakart (tehlike levhası) takılı bir aşındırıcı (korozif) madde yükü taşırken bir bağlantı parçası arızalanır ve römorkunuzun altından iki şeritli bir karayolunun banketine doğru bir birikinti yayılmaya başlar. Diğer araçlar hâlâ yakından geçmektedir. Yolun tamamen dışına çektikten sonra, başka bir şey yapmadan önceki İLK önceliğiniz nedir?","options":["Çevredekileri sızıntıdan uzak tutmak ve yaklaşan trafiği tehlike konusunda uyarmak","Aşağı doğru yayılmasını durdurmak için dökülen maddeyi yıkayıp yoldan temizlemek","Meraklı seyircilerin yük yüzünden paniğe kapılmaması için plakartları çıkarmak veya örtmek","Kabine geri dönüp olay yerini hızla boşaltmak için bir sonraki çıkışa kadar sürmek"],"explanation":"Bir tehlikeli madde olayında sürücünün ilk görevi, insanları sızıntıdan uzak tutmak ve yaklaşan trafiği tehlikeye karşı uyarmaktır."},"211":{"q":"Plakartlı (placard) yükümle bir dinlenme alanına girdim ve sigara molası için dışarı çıkmak istiyorum. Aşağıdakilerden hangisinin yanında kesinlikle sigara YAKMAMALIYIM?","options":["Az önce bıraktığım, boş ve tamamen havalandırılmış römorkun yanında","Yanıcı sıvı plakartı taşıyan römorkun yanında","Yan bölmedeki park halindeki bir binek otomobilin yanında","Çekicimin temiz, süpürülmüş kabininin yanında"],"explanation":"Buharlar açık alev veya yanan bir sigaradan tutuşabileceğinden, yanıcı madde plakası taşıyan bir aracın 25 fit yakınında asla sigara içmeyin."},"212":{"q":"Yanıcı sıvı taşıyan plakartlı tankeriniz kırsal iki şeritli bir yolda makaslama yapıyor ve römorkun yakınında biriken güçlü bir kimyasal koku alıyorsunuz. İki sürücü durmuş ve enkaza doğru yürüyor, biri sigara yakıyor. İLK olarak hangi eylemi yapmalısınız?","options":["Kabine geri tırmanıp sızıntı yayılmadan önce römorku yoldan çekmek","Sevkiyat belgelerini ve Acil Müdahale Kılavuzu'nu (ERG) toplayıp dökülmeyi temizlemeye başlamak","Etraftakileri güvenli mesafede tutmak, sigara içilmesini engellemek ve acil müdahale ekiplerini ve CHEMTREC'i bilgilendirmek","Yaklaşan trafiği tehlike konusunda uyarmak için enkazın arkasına yanan işaret fişekleri yerleştirmek"],"explanation":"Bir tehlikeli madde kazasından sonra çevredekileri iyice uzak tutun, sigara içilmesini önleyin ve hemen acil müdahale ekiplerine ve CHEMTREC'e haber verin."},"213":{"q":"Laredo deposunda plakartlı römorkumda sefer öncesi kontrol yapıyorum ve arka plakartın iyice solduğunu, sağ yandaki bir plakartın da çamurluk braketinin arkasında kısmen gizlendiğini fark ediyorum. Ortağım, karşıdan gelen trafik ve arkamdaki polisin asıl gördüğü ön ve arka plakartlar temiz olduğu sürece sorun olmadığını söylüyor. DPS plakart kurallarına göre hangi ifade doğrudur?","options":["Ortağın haklı; sadece ön ve arka önemlidir, çünkü diğer sürücülerin yaklaştığı yönlere bakarlar, bu yüzden solmuş yan plakart sürmeden önce göz ardı edilebilir.","Araçta en az bir plakart kabin dışından tam okunabilir kaldığı sürece kabul edilebilir, yani tek bir temiz ön plakart bugün sürmene izin verirdi diyebiliriz.","Plakartların yalnızca sürücü tarafından kabin içinden net görülmesi yeterlidir; böylece dıştaki solma veya engellenme sürmeden önce önemli olmaz diye düşünebilirsin.","Dört plakartın da bulunması ve her birinin baktığı yönden okunabilir olması gerekir; bu yüzden solmuş arka ve kısmen gizli yan plakart sürmeden önce düzeltilmelidir."],"explanation":"Plakalar dört yüzün hepsinde gereklidir ve her biri baktığı yönden okunabilir olmalıdır; bu nedenle solmuş veya kısmen kapalı her plaka, sürüşten önce düzeltilmelidir."},"214":{"q":"Plaka (placard) takılı bir yükte sefer öncesi muayene yapıyorum ve plakaların yönetmeliğin gerektirdiği şekilde takıldığını doğrulamak istiyorum. İçindeki basılı sembolü ve sınıf numarasını dikkate almazsak, römorkumun yan tarafında doğru takılmış her plaka genel olarak hangi şekli oluşturmalıdır?","options":["Köşelerinden birinin üzerine oturtulmuş, ucu yukarı bakan bir baklava (eşkenar dörtgen) gibi görünen bir kare","Bir yol levhası paneli gibi, düz kenarlarından birinin üzerine düz oturtulmuş bir kare","Uyarının her açıdan görülebilmesi için yuvarlak dairesel bir disk","Kutumdaki yansıtıcı uyarı cihazlarıyla aynı, ucu yukarı bakan bir üçgen"],"explanation":"Tehlike levhası, 45 derece döndürülüp bir köşesi üzerine oturtulmuş, ucu yukarı bakan bir baklava (eşkenar dörtgen) biçimindeki karedir."},"215":{"q":"Tehlikeli madde plakartı takılmış bir sevkiyatı yüklüyorum ve teslim almadan önce her paketin doğru işaretlendiğini iki kez kontrol ediyorum. Pakette basılı olan uygun sevkiyat adının yanı sıra, paket işaretlemesinde başka hangi bilgi de mutlaka bulunmalıdır?","options":["Yükü teslim alan sürücü olarak benim adım","Maddenin kimlik (UN/NA) numarası","Römorktaki plakartla eşleşen renk kodu","Taşıyıcının çekicisinin kullandığı yakıt türü"],"explanation":"Paket işaretleri, doğru sevkiyat adıyla birlikte malzemenin kimlik (UN/NA) numarasını da içermelidir."},"216":{"q":"Terminalden ayrılmadan önce bir yükün taşıma belgelerini inceliyorum ve listelenen malzemelerden birinin tam yanında HM sütununa girilmiş \"RQ\" harflerini fark ediyorum. Belgeleri imzalayıp elimin ulaşabileceği yere koymadan önce, bu \"RQ\" ibaresi o kayıt hakkında bana aslında ne söylüyor?","options":["Bu malzemeyi yerleşim alanlarından uzak tutmak için izlemem gereken önerilen düşük trafikli güzergahı işaretler","Göndericinin paketi tekrar kontrol ettiğini ve yükleme için sızdırmaz olarak belgelediğini doğrular","Malzemenin bildirilebilir miktarda (reportable quantity) bulunduğunu ve dökülmesinin bildirilmesi gerektiğini gösterir","Kaydın incelenip onaylandığı anlamına gelir, böylece onu evraklarımın en altına taşıyabilirim"],"explanation":"\"RQ\", Bildirilmesi Gereken Miktar (Reportable Quantity) anlamına gelir; yani malzeme, dökülmesi halinde bildirim gerektiren bir miktarda bulunmaktadır."},"217":{"q":"Karışık bir yük yüklüyorum ve rıhtım amiri bana Sınıf 6 (Bölüm 6.1) zehir olarak işaretlenmiş birkaç paket veriyor. Boş bir römorkum var ve bunları yükün geri kalanına göre nereye koyacağıma karar vermem gerekiyor. Bu zehri güvenli ve yasal şekilde yüklemek için, onu kesinlikle neyden uzak tutmam gerekir?","options":["Acil durumlar için taşıdığım yansıtıcı uyarı üçgenleri","Kargo kapılarının yanına monte edilmiş yangın söndürücü","Römork gövdesinin altında saklanan yedek lastik","Yükteki herhangi bir gıda, yiyecek maddesi veya yenilebilir ürün"],"explanation":"Zehirli (Bölüm 6.1) maddeler, bulaşmayı önlemek için hiçbir gıda, gıda maddesi veya yenilebilir ürünle birlikte ya da yakınına asla yüklenmemelidir."},"218":{"q":"Sınıf 5 oksitleyici (yükseltgen) madde taşıyan plakartlı bir yük taşırken römorkumun yakınında küçük bir elektrik yangını başlıyor. Durumu değerlendirirken, bu maddeyi her türlü alevden uzak tutmam neden özellikle aciliyet taşır?","options":["Oksitleyiciler oksijen açığa çıkarır, bu yüzden yangının daha sıcak ve daha şiddetli yanmasına neden olurlar","Oksitleyiciler alevi boğup söndürür, ancak açığa çıkan dumanlar zehirlidir","Oksitleyiciler ısıyla temas ettiğinde donar, bu da römorku çatlatıp yükün dökülmesine yol açabilir","Oksitleyiciler ateşin yanında zararsızdır, ancak plakartların kendisi yanıcıdır"],"explanation":"Oksitleyiciler, yangını besleyen oksijen açığa çıkararak ateşin daha sıcak ve daha şiddetli yanmasına neden olur."},"219":{"q":"Plakartlı bir Sınıf 3 yanıcı sıvı yükü taşıyorum ve sevk irsaliyesinde maddenin parlama noktası belirtilmiş. Sefer öncesi güvenlik kontrolü sırasında eğitmenim bana bu parlama noktası değerinin bu yük hakkında gerçekte ne anlattığını soruyor. Parlama noktasının neyi gösterdiğini hangi ifade doğru olarak tanımlar?","options":["Sıvının donup tankın içinde çalkalanmayı durduğu sıcaklıktır","Sıvının tutuşabilir bir karışım oluşturmaya yetecek kadar buhar verdiği en düşük sıcaklıktır","Sıvının kıvılcım veya açık alev olmadan kendiliğinden tutuştuğu sıcaklıktır","Sıvının kaptan sızmaya başlayacak kadar genleştiği sıcaklıktır"],"explanation":"Parlama noktası, bir sıvının tutuşabilir bir karışım oluşturacak kadar buhar verdiği en düşük sıcaklıktır."},"220":{"q":"Çimento tozuyla yüklü bir kuru dökme yük tankeri kullanıyorum ve işaretli bir virajı olan yonca yaprağı çıkışına yaklaşıyorum. Bu tür yükün davranışı göz önüne alındığında, bu virajı nasıl alacağımı en çok hangi etken belirlemeli?","options":["Yük alçakta ve oturmuş durumda, bu yüzden virajı hiçbir ayarlama yapmadan işaretli karayolu hızında alabilirim","Tanker sıvı tankeri gibi bölmelidir, bu yüzden çalkalanma tamamen kontrol altındadır ve yalnızca fren mesafesi önemlidir","Yük yüksekte durur ve araç hareket ettikçe kayar, bu yüzden virajdan iyice önce yavaşlamalı ve direksiyonu yumuşak kullanmalıyım","Toz hareket halindeyken sıkışıp katılaşır, bu yüzden virajın içinde ani direksiyon düzeltmeleri tamamen güvenlidir"],"explanation":"Kuru dökme yük tankları yüksek ağırlık merkezine ve kayan yüke sahiptir, bu yüzden virajdan çok önce yavaşlayın ve direksiyonu yumuşak kullanın."},"222":{"q":"Dört tarafına da plaka (placard) takılması gereken bir yük kabul ettim ve taşıyıcının sevkiyat görevlisi yola çıkmam için beni sıkıştırıyor. Sahadan ayrılmadan önce, plakalı bu yükü yasal olarak kullanabilmek için şahsen hangi belgeye sahip olmam gerekir?","options":["Geçerli bir DOT tıbbi muayene sertifikası; bu tek başına plakalı her türlü yükü taşımama izin verir","Tanker (N) onayı, çünkü plakalı yükler her zaman dökme tank dorselerinde taşınır","Ehliyetimde fazladan hiçbir şey, çünkü gönderici belgeleri hazırladı ve plakaları taktı bile","TSA arka plan kontrolü ve parmak izi alımından sonra elde edilen geçerli bir Tehlikeli Madde (HazMat, H) onayı"],"explanation":"Levhalı tehlikeli madde yükü taşımak, TSA güvenlik taraması ve parmak izi alımından geçilerek edinilen geçerli bir Tehlikeli Madde (H) onayı gerektirir."},"223":{"q":"Plakart takılı bir aşındırıcı madde yükü taşıyorum ve yola çıkmadan önce sevkiyat belgelerimi doğru şekilde hazırlamak istiyorum. Tehlikeli madde girdilerini sekmeleyip açıkça işaretlemek için birkaç dakika ayırıyorum. Bir denetçi veya ilk müdahale ekibi bunları istediğinde, belgeleri bu şekilde sekmeleyip işaretlemenin asıl amacı nedir?","options":["Tehlikeli madde belgelerinin bir acil durumda veya denetimde hızlı ve kolayca bulunabilmesi için","Tehlikeli madde belgelerinin özellikle istenene kadar katlanmış ve gözden uzak saklanabilmesi için","Tehlikeli madde girdilerinin yükün geri kalan evrakından ayrılıp bir kenara konulması için","Tehlikeli madde belgelerinin teslimat tamamlanıp imzalandıktan sonra atılabilmesi için"],"explanation":"Tehlikeli madde sevkiyat belgeleri, acil durumda veya denetimde hızlı ve kolayca bulunabilmesi için sekmeli ya da işaretli olmalıdır."},"224":{"q":"Plakartlı bir aşındırıcı (korozif) madde yükü taşırken bir bağlantı arızalanıyor ve madde işlek bir karayolunun banketine sızmaya başlıyor. Römorkunuzun yakınında çevredekiler toplanmaya başlıyor. Aşağıdaki eylemlerden hangisi her şeyden önce İLK önceliğiniz olmalıdır?","options":["Sevkiyat belgelerini çıkarıp CHEMTREC'i arayarak ürünün tam adını ve miktarını bildirmek","Sızıntıdan uzak durmak ve çevredekileri uzaklaştırarak herkesi maruz kalmaktan korumak","Acil Müdahale Kılavuzu'nu (ERG) açıp o kimlik numarası için döküntü temizleme prosedürüne bakmak","Taşıyıcı firmanızla iletişime geçerek şirketin yetkililere gerekli olay raporunu sunmasını sağlamak"],"explanation":"Herhangi bir tehlikeli madde olayında öncelikle can güvenliğini sağlayın: sızıntıdan uzak durun ve çevredekileri maruz kalmaktan uzaklaştırın."},"225":{"q":"Tanker kamyonunuzu yanıcı bir sıvı yüklemek için dolum rampasına yanaştırıyorsunuz. Ürün kargo tankına akmaya başlamadan önce, buharları tutuşturabilecek bir statik elektrik kıvılcımını önlemek için EN önemli adım hangisidir?","options":["Dolum sırasında alternatörün tankın seviye sensörlerini beslemesi için kamyonun motorunu rölantide bırakmak","Başka araçlar yaklaşabilir diye dolum rampasının etrafına yansıtıcı uyarı üçgenlerinizi yerleştirmek","Dolum hattını açmadan önce tankı dolum ekipmanına bağlamak (eş potansiyel) ve her ikisini de topraklamak","Birikmiş buharların çıkıp içerideki basıncı düşürmesi için kubbe kapağını erkenden açmak"],"explanation":"Dolum hattını açmadan önce bağlama ve topraklama, yanıcı sıvı akışının ürettiği statik elektriği boşaltarak buharı tutuşturabilecek kıvılcımı önler."},"227":{"q":"Sürekli gözetim gerektiren plakartlı (tehlikeli madde levhalı) bir yük taşıyorum ve gece için belirlenmiş bir durağa park ettim. Ben yakındaki bir motelde dinlenirken, yardımcı sürücüm aracın yanında nöbetçi olarak kalmayı kabul etti. Aşağıdakilerden hangisi, bu nöbet görevinin geçerli sayılması için yardımcı sürücümün görevini nasıl yerine getirmesi gerektiğini en iyi açıklar?","options":["Yükün 100 fit yakınında kaldığı sürece yatakhane bölmesinde kestirebilir","Römorku hâlâ görebildiği için park alanının karşısındaki kapalı bir restoranda oturabilir","Etrafta kimse yoksa, kendi aracına yakıt almak için kısa bir süre ayrılabilir","Uyanık ve tetikte kalmalı, aracın 100 fit yakınında olmalı ve araca engelsiz bir görüş açısına sahip olmalıdır"],"explanation":"Plakartlı yükün gözcüsü uyanık ve tetikte kalmalı, araca 100 fit mesafede olmalı ve aracı engelsiz görebilmelidir."},"228":{"q":"Eyaletler arası uzun bir yolculukta plakartlı (tehlike levhalı) yanıcı sıvı yükü taşıyorum ve terminalden ayrılmadan önce sefer öncesi lastik kontrolümü yeni bitirdim. Yol üzeri denetim kuralına uymak için yolculuk sırasında lastiklerimi ne sıklıkta yeniden kontrol etmek için durmalıyım?","options":["En az her 2 saatte bir veya her 100 milde bir, hangisi önce gerçekleşirse","En az her 100 milde bir, ancak otoyola çıktığımda 2 saatlik süre artık geçerli olmaz","En az her 3 saatte bir veya her 150 milde bir, hangisi önce gerçekleşirse","Yalnızca yakıt almak için durduğumda veya zorunlu 30 dakikalık molamda"],"explanation":"Plakartlı yük taşırken lastikleri yolda en az her 2 saatte bir veya her 100 milde bir, hangisi önce gelirse kontrol etmelisiniz."},"229":{"q":"Plakartlı yük taşıyan bir devrilme kazasına olay yerine ilk ben ulaştım. Sevkiyat görevlisi duman yüzünden doğru sevkiyat adını okuyamıyor, ancak paketin üzerine şablonla basılmış 4 haneli BM kimlik numarasını telsizle bana bildiriyor. Yalnızca bu numarayı kullanarak acil müdahale bilgisini EN HIZLI şekilde bulmak için ERG'nin hangi bölümüne bakmalıyım?","options":["Malzemeleri atanmış tehlike rengine göre gruplayan, turuncu kenarlıklı kılavuz sayfaları","Malzemeleri kimlik numarasına göre sayısal sırayla listeleyen sarı kenarlıklı sayfalar","Malzemeleri sevkiyat adına göre alfabetik olarak listeleyen mavi kenarlıklı sayfalar","Malzemeleri paket ağırlığı ve miktarına göre listeleyen beyaz kenarlıklı sayfalar"],"explanation":"ERG'nin sarı kenarlı sayfaları malzemeleri kimlik numarasına göre sayısal sırayla listeler; bu yüzden yalnızca 4 haneli kimlik numarasını bildiğinizde en hızlısıdır."},"230":{"q":"Plakartlı (placard) yüküm üzerinde bir sızıntı mahallindeyim. Sevkiyat belgeleri imha edildi, bu yüzden UN/NA kimlik numaram yok, ancak konteynerin üzerinde açıkça \"KLOR\" (CHLORINE) yazısı kabartmalı olarak yazılı. Bu malzemeyi ERG'nin mavi kenarlıklı sayfalarında hızlıca bulmak için kaydı ararken neye dayanıyorum?","options":["Konteyner üzerine kabartmalı olarak yazılmış dört haneli UN/NA kimlik numarası","Tankın üzerinde gösterilen plakart (placard) tehlike sınıfı numarası","Alfabetik olarak sıralanmış malzemenin uygun sevkiyat adı (proper shipping name)","Ambalaj etiketinin üzerine basılı DOT renk kodu"],"explanation":"ERG'nin mavi kenarlı sayfaları malzemeleri uygun sevkiyat adına göre alfabetik sıralar; bu yüzden adı bilip kimlik numarasını bilmediğinizde kullanılacak araçtır."},"231":{"q":"Plakartlı (uyarı levhalı) bir aşındırıcı madde yükü taşırken bir bağlantı parçası arıza yapıyor ve ürün banketin üzerine sızmaya başlıyor. Acil Müdahale Kılavuzumu (ERG) alıyorum, maddenin kimlik numarasını buluyorum ve olay yerinde insanları nasıl koruyacağımı ve güvenli şekilde nasıl müdahale edeceğimi öğrenmem gerekiyor. Bu bilgi için ERG'nin hangi bölümüne başvurmalıyım?","options":["Mavi kenarlıklı sayfalara, çünkü her maddeye ait müdahale eylem kılavuzları orada uygun sevkiyat adına göre alfabetik olarak düzenlenmiştir","Yeşil kenarlıklı sayfalara, çünkü koruyucu eylem mesafelerini listeler ve sızıntıyı tam olarak nasıl ele alacağımı söyler","Sarı kenarlıklı sayfalara, çünkü olay yerinde ne yapılacağını açıklayan numaralı kılavuzlar orada UN/NA numarasına göre dizinlenmiştir","Turuncu kenarlıklı sayfalara, çünkü bunlar insanları nasıl koruyacağımı ve olayı nasıl kontrol altına alacağımı anlatan numaralı müdahale eylem kılavuzlarını içerir"],"explanation":"ERG'nin turuncu kenarlı sayfaları, tehlikeleri ve insanları korumak ile olayı kontrol etmek için yapılacak güvenlik önlemlerini açıklayan numaralı müdahale kılavuzlarını içerir."},"232":{"q":"Önümdeki bir tankerin devrilmesiyle zehirli gaz sızıyor. CHEMTREC'i ararken, insanları nereye taşıyacağıma karar vermek için Acil Müdahale Kılavuzumu (ERG) yeşil kenarlıklı sayfalardan açıyorum. Bu yeşil sayfaların bana vermek için tasarlandığı bilgi nedir?","options":["İnsanları sızıntıdan ne kadar uzağa tahliye edip uzak tutacağımı gösteren başlangıç izolasyon ve koruyucu eylem mesafeleri","Dört haneli UN/NA kimlik numaralarıyla eşleştirilmiş uygun taşıma adlarının listesi","O maddenin kılavuz numarası için yangın, dökülme ve ilk yardım eylemlerini açıklayan genel müdahale rehberi","Olay sırasında teknik destek için aranacak CHEMTREC ve acil durum telefon numaraları"],"explanation":"ERG'nin yeşil kenarlı sayfaları, sızıntıdan insanları ne kadar uzağa tahliye edip uzak tutacağınızı bildiren ilk izolasyon ve koruyucu eylem mesafelerini verir."},"233":{"q":"Bir terminalde römorkumu yüklüyorum ve rıhtım amiri bana, taşıma evraklarındaki bir kalemde tehlike bölümünün hemen ardına basılmış bir harf kodu (\"uyumluluk grubu\" harfi) içeren evrakları veriyor. Bu harfin, aynı tehlike sınıfındaki diğer maddelerden hangilerinin aynı araçta birlikte yüklenebileceğini ya da yüklenemeyeceğini gösterdiğini söylüyor. Tehlikeli madde mevzuatına göre, bu uyumluluk grubu harfi hangi madde sınıfını ifade ediyor?","options":["Sınıf 8 Aşındırıcılar, böylece römorkta asitlerle bazların birbiriyle reaksiyona girmesini önleyebilirim","Sınıf 1 Patlayıcılar, böylece hangi bölümlerin ve türlerin birlikte yüklenip taşınabileceğini anlayabilirim","Sınıf 2 Gazlar, böylece yükleme sırasında yanıcı gazları zehirli gazlardan ayırabilirim","Sınıf 7 Radyoaktif, böylece taşıma indeksi toplamlarını bir araç için belirlenen sınırlar içinde tutabilirim"],"explanation":"Uyumluluk grubu harfleri yalnızca Sınıf 1 Patlayıcılara aittir ve hangi patlayıcı bölümlerinin ve türlerinin birlikte güvenle yüklenip taşınabileceğini gösterir."},"234":{"q":"Plaka (placard) gerektiren bir yük için taşıma belgelerini hazırlıyorum ve bir kaydın kimlik numarasının 'UN' yerine 'NA' harfleriyle başladığını fark ediyorum. Yeni bir sürücü bana bu ön ekin numaranın nerede geçerli olduğu hakkında ne anlama geldiğini soruyor. Aşağıdakilerden hangisi ona söylenecek doğru şeydir?","options":["Bu, Avrupa ve Asya'nın her yerindeki taşımalar için tanınan, uluslararası uyumlaştırılmış bir numaradır","Bu, yükün yalnızca belirlenmiş denizaşırı ihracat güzergahlarında taşınabileceği, asla yurt içinde taşınamayacağı anlamına gelir","Bu, Amerika Birleşik Devletleri ve Kanada dahil olmak üzere Kuzey Amerika içinde kullanılmak üzere atanmış bir kimlik numarasıdır","Bu 'Uygulanamaz' (Not Applicable) anlamına gelir, bu nedenle o satır için tehlike sınıfı veya doğru sevkiyat adı gerekmez"],"explanation":"'NA' ön eki, yalnızca Kuzey Amerika'da, yani Amerika Birleşik Devletleri ve Kanada'da kullanılmak üzere atanmış bir kimlik numarasını belirtir."},"235":{"q":"Houston'dan denizaşırı ihracat için bir limana doğru, plakartlanmış bir yanıcı sıvı yükü taşıyorum ve sevkiyat belgelerimde malzeme uygun sevkiyat adı, tehlike sınıfı ve bir 'UN' kimlik numarasıyla listelenmiş. Yanımda seyahat eden yeni bir sürücü, bu 'UN' numarasının yalnızca burada, Teksas'ta önemli olduğunu ve yük eyaletten ayrıldığında göz ardı edilebileceğini savunuyor. Bu 'UN' kimlik numarası hakkında hangi ifade doğrudur?","options":["'UN' numarası yalnızca Teksas içinde geçerlidir, bu yüzden yeni sürücü haklı: eyalet sınırında önemini yitirir","'UN' numarası yalnızca deniz yoluyla taşınan sevkiyatlar için geçerlidir, bu yüzden yük limana ulaştığında uygulanır","'UN' numarası yalnızca hava yoluyla taşınan sevkiyatlar için geçerlidir, bu yüzden bu kamyon için farklı bir kod gerekir","'UN' numarası uluslararası olarak tanınır, bu yüzden yük nereye giderse gitsin malzemeyi aynı şekilde tanımlar"],"explanation":"'UN' kimlik numarası uluslararası olarak tanınır; bu nedenle yük nereye giderse gitsin malzemeyi aynı şekilde tanımlar."},"236":{"q":"Sefer öncesi muayenemi yaparken bir paketimde tanımadığım elmas şeklinde bir etiket fark ediyorum. Yükü kabul etmeden önce bunun bir zehir (toksik) madde işareti olup olmadığını doğrulamak için o etikette hangi sembolü aramalıyım?","options":["Elmasın içinde kurukafa ve çapraz kemikler","Tehlike sınıfı numarasının üstünde bir alev sembolü","Elmasın içinde ışınlar saçan yanan siyah bir top","Pervane biçimli üç kanatlı yonca (trefoil) sembolü"],"explanation":"Zehirli veya toksik madde (Bölüm 6.1), elmas etiketin içindeki kuru kafa ve çapraz kemik sembolüyle tanımlanır."},"237":{"q":"Bir yükleme rampasında yükü denetliyorum ve sarı-beyaz baklava şeklinde Sınıf 7 tehlike etiketi taşıyan bir paket alıyorum. Yükü imzalamadan önce içeriği doğrulamak için baklavanın içindeki yazıyı inceliyorum. Bu baklava etiketinin üzerine basılı hangi tek kelime bunun bir Sınıf 7 sevkiyatı olduğunu doğrular?","options":["KIRILGAN (FRAGILE), çünkü pakette kırılabilen hassas sızdırmaz kaynak kapları bulunur","RADYOAKTİF (RADIOACTIVE), çünkü Sınıf 7 baklava etiketine basılı kelime tehlikeyi doğrudan belirtir","AŞINDIRICI (CORROSIVE), çünkü Sınıf 7 sızdırmaz kaynaklar aside dayanıklı dış muhafazalarda saklanır","OKSİTLEYİCİ (OXIDIZER), çünkü radyoaktif madde yanmayı destekleyebilecek enerji yayar"],"explanation":"Sınıf 7 etiketinde elmasın içine RADIOACTIVE kelimesi yazılıdır ve tehlike sınıfını doğrudan belirtir."},"238":{"q":"Sıcak bir Teksas öğleden sonrasında dolum rampasında kargo tankımı benzinle dolduruyorum ve dolum görevlisi pompayı kapatmadan önce ürünü ne kadar yükseğe getirmemi istediğimi soruyor. Bu yanıcı sıvıyı güvenli ve yasal şekilde taşımak için tankı nasıl yüklemeliyim?","options":["Fren yaparken sıvının çalkalanıp bölmelere çarpmaması için ağzına kadar doldurulmuş halde","Yarısına kadar doldurulmuş halde, çünkü yanıcı sıvı tankı yasal olarak hiçbir zaman yüzde 50'den fazla doldurulamaz","Ürünün yol boyunca ısındıkça genleşmesi için boş alan kalacak şekilde tam doldurulmadan bırakılmış halde","Tamamen ağzına kadar doldurulup, ardından dolu sayılması için kapağın üzerine doğru tehlike etiketi yapıştırılarak mühürlenmiş halde"],"explanation":"Yanıcı sıvı taşıyan kargo tankı tamamen doldurulmamalıdır çünkü sıvı ısındıkça genleşir ve boş alana ihtiyaç duyar."},"239":{"q":"Soğuk bir sabahın erken saatlerinde bir tankerı yanıcı bir sıvıyla yüklüyorum ve gün ısındıkça çok daha sıcak havaya doğru güneye sürmeyi planlıyorum. Tankı ne kadar güvenli bir şekilde doldurabileceğime karar vermek için, yükle ilgili hangi gerçek kararıma yön vermeli?","options":["Tankı tamamen tepesine kadar doldurabilirim, çünkü gün içinde dış sıcaklık yükseldikçe sıvı büzülür ve daha az yer kaplar","Sıvılar için doldurma seviyesi önemli değildir, çünkü yalnızca sıkıştırılmış gazlar tankın çevresindeki sıcaklık değiştiğinde hacim değiştirir","Şimdi soğukken ağzına kadar doldurmalıyım, çünkü daha soğuk sıvı genleşir ve öğlene kadar beklersem taşardı","Tankta boş alan (taşma payı) bırakmalıyım, çünkü sıvı ısındıkça genleşecek ve taşmaması için yere ihtiyaç duyar"],"explanation":"Tankta boş alan (outage) bırakın çünkü sıvı ısındıkça genleşir ve taşmayı önlemek için yere ihtiyaç duyar."},"240":{"q":"Bir yükleme rampasında plakartlı iki kutu tehlikeli madde (HazMat) yüklüyorum ve göndericinin evrakları, bu iki maddenin birbirine temas ederse tehlikeli şekilde reaksiyona girebileceği konusunda uyarıyor. Römork yarı boş ve işi çabuk bitirmek istiyorum. Bu sevkiyatı güvenli şekilde yüklemek için ne yapmalıyım?","options":["İki maddeyi römorkta birbirinden ayrı tutulacak şekilde yükleyeyim","İki maddeyi birlikte kolayca boşaltılacak şekilde yan yana yükleyeyim","Her iki paketteki dökme ürünü, taşıma sırasında eşit otursun diye birbirine karıştırayım","İki maddeyi, yolda hiçbiri kaymasın diye sıkıca üst üste istifleyeyim"],"explanation":"Birbiriyle reaksiyona girebilen iki tehlikeli madde, römorkta birbirinden ayrı tutulacak şekilde yüklenmelidir."},"241":{"q":"Yükleme rampasındayım ve plaka (placard) gerektiren bir Tehlikeli Madde sevkiyatını yüklemek üzereyim; yük araca konmadan önce son kontrol turumu yapıyorum. Herhangi bir Tehlikeli Madde römorkuma yüklenmeden ÖNCE ekipmanın hangi durumda olması gerektiğini değerlendirirken, aşağıdakilerden hangisi mutlaka doğru olmalıdır?","options":["Şimdi yükleyebilirim, fren ayarını ve lamba çalışmasını yolda ilk 2 saatlik lastik kontrolünde doğrularım","Frenler ve lambalar, herhangi bir Tehlikeli Madde yüklenmeden önce zaten denetlenmiş ve düzgün çalışır durumda olduğu teyit edilmiş olmalıdır","Yalnızca römork servis frenlerinin çalışması yeterli; yükleme gündüz rampada yapıldığı için lambalar sonra kontrol edilebilir","Frenler ve lambalar yalnızca plakalar takıldıktan sonra önemli olur, bu yüzden önce yükleyip plakalamadan sonra kontrol edebilirim"],"explanation":"Frenler ve farlar, herhangi bir tehlikeli madde yüklenmeden önce kontrol edilip düzgün çalıştığı doğrulanmalıdır."},"242":{"q":"Bir göndericinin yükleme rampasında elle aşındırıcı madde paketlerinden oluşan bir paleti yüklüyorum ve bazı kutular ağır ve tutması zor. Bunları güvenli bir şekilde taşımak ve kapları zarar görmekten korumak için her paketi kaldırıp taşırken hangi kısmından tutmalıyım?","options":["Basılı tehlike etiketlerinden tutmalıyım, çünkü o paneller taşımaya dayanacak şekilde güçlendirilmiştir","Gevşek bantlı kapaklardan veya çemberlemeden çekmeliyim, çünkü bunlar kutuda en sağlam tutuşu sağlar","Paketin sağlam, güçlü bir kısmından kaldırmalıyım, asla zayıf yerlerinden veya etiketlerinden değil","En yakın kenarından rampada sürüklemeliyim, çünkü aşındırıcı madde sürtünmeye dayanıklıdır"],"explanation":"Tehlikeli madde paketlerini sağlam, güçlü bir bölümden kaldırın; asla zayıf kısımlardan veya etiketlerden tutmayın ki kap bütünlüğünü korusun."},"243":{"q":"Plakartlı tehlikeli madde taşımak için yeni işe alındım ve sevkiyat görevlisi bana şirketin kendi yükleme ve güzergâh prosedürlerini içeren kalın bir klasör verdi. Okurken, şirket kurallarının bazen onay belgem için öğrendiklerimden daha ileri gittiğini fark ediyorum. Her seferde yasal kalmak için, taşıyıcımın şirket kurallarına uymanın ötesinde, her zaman uymakla YÜKÜMLÜ olduğum başka ne var?","options":["Yalnızca taşıyıcımın iç kuralları, çünkü şirket klasörü zaten yasanın benden istediği her şeyi içeriyor","Sevkiyat görevlisinin telsizle verdiği sözlü güzergâh talimatları, çünkü bunlar herhangi bir yazılı prosedürü geçersiz kılar","Yerel trafik işaretleri ve konulan limitlerin söylediği her şey, çünkü bunlar tehlikeli maddeler için federal kuralların yerine geçer","Taşıyıcının kendi kurallarına ek olarak geçerli olan federal ve eyalet tehlikeli madde yönetmelikleri (HMR)"],"explanation":"Sürücü, taşıyıcının kendi kurallarına ek olarak geçerli olan federal ve eyalet tehlikeli madde düzenlemelerine (HMR) uymalıdır."},"244":{"q":"Plakartlı bir tehlikeli madde yükünü alıyorum ve sevkiyat belgelerinde imzalı bir gönderici sertifikasyonu var. Sürücü olarak imzalamadan önce, bu sertifikasyonun bana gerçekte ne anlattığından emin olmak istiyorum. Sevkiyat belgesindeki imzalı gönderici sertifikasyonu yasal olarak neyi temsil eder?","options":["Sevkiyatın yönetmeliklere uygun olarak doğru şekilde sınıflandırıldığını, tanımlandığını, paketlendiğini, işaretlendiğini ve etiketlendiğini","Taşıyıcının navlun ücretlerinin doğru olduğunu doğruladığını ve müşterinin sevkiyatı zaten ödediğini","Sürücünün her paketi bizzat denetlediğini ve yolda bulunan herhangi bir sızıntı için tüm sorumluluğu kabul ettiğini","Yükün bağımsız olarak iki kez tartıldığını ve toplam brüt ağırlığın irsaliyeyle tam olarak eşleştiğini"],"explanation":"Gönderenin imzaladığı sertifika, sevkiyatın düzenlemelere uygun şekilde doğru sınıflandırıldığını, tanımlandığını, paketlendiğini, işaretlendiğini ve etiketlendiğini yasal olarak beyan eder."},"245":{"q":"Sefer öncesi araç turunda römorktaki dört plakartın parlak turuncu, içerideki ambalajların üzerindeki küçük baklava (elmas) etiketlerinin ise koyu kırmızı olduğunu fark ediyorum. Başka bir sürücü bana renklerin sadece göndericilerin stok takibi yapmasına yardımcı olmak için olduğunu söylüyor. Tehlike bildirimi kurallarına göre, baklava şeklindeki tehlike etiketinin rengi bana aslında neyi söylüyor?","options":["Yükten sorumlu taşıyıcıyı ve göndericiyi belirtir","Maddenin oluşturduğu tehlikenin genel türünü veya sınıfını gösterir","O ambalaja yüklenen ürünün toplam ağırlığını gösterir","Maddeye atanan BM/NA (UN/NA) kimlik numarasını gösterir"],"explanation":"Elmas tehlike etiketinin rengi, örneğin yanıcılar için kırmızı ve oksitleyiciler için sarı gibi, tehlikenin genel türünü veya sınıfını gösterir."},"246":{"q":"Römorkumu yükleme rampasında yüklüyorum ve sevkiyat belgeleri yalnızca yaklaşık 40 librelik küçük bir Bölüm 2.3 zehirli gaz paketini, ayrıca toplam 600 libre ağırlığında Tablo 2 aşındırıcı madde içeren birkaç varili gösteriyor. Rampa sorumlusu, tüm yükümün 1.001 libre sınırının çok altında olduğu için hiçbir şey için plaka (placard) asmama gerek olmadığını söylüyor. Yola çıkmadan önce plakalandırma konusunda ne yapmalıyım?","options":["Hiç plaka asmayın, çünkü her iki maddenin toplam ağırlığı 1.001 librenin altındadır.","Yalnızca aşındırıcı variller için plaka asın, çünkü kargo ağırlığının en büyük payını onlar oluşturuyor.","Ağırlığı ne olursa olsun zehirli gaz için plaka asın, çünkü bu madde herhangi bir miktarda plaka gerektirir.","Römorka herhangi bir plaka eklemeden önce yükün toplam 1.001 libreye ulaşmasını bekleyin."],"explanation":"Bölüm 2.3 zehirli gaz gibi Tablo 1 maddeleri, paket ne kadar hafif olursa olsun her miktarda plaka gerektirir."},"247":{"q":"Az önce bir parti yanıcı sıvı teslim ettim ve tank göstergem boş gösteriyor, bu yüzden öğle yemeği için bir mola tesisine giriyorum. Bir arkadaşım, tank boşaltıldığına göre dört taraftaki plakartların hepsini sökebileceğimi ve aracı tehlikeli madde taşımayan herhangi bir römork gibi kullanabileceğimi söylüyor. Hiçbir şeye dokunmadan önce, 'boş' tankım hakkında yapmam gereken en güvenli varsayım nedir?","options":["Gösterge boş gösterdiği için tankta artık hiç tehlikeli madde yoktur ve onunla çalışmak tamamen güvenlidir.","Ürün boşaltıldığı için plakartları hemen yasal olarak sökebilirim, çünkü plakartlar yalnızca sıvı gerçekten taşınırken geçerlidir.","Yük teslim edildiği için içindeki kalıntı tamamen buharlaşmıştır ve hiçbir yanıcı buhar veya tehlike oluşturamaz.","İçeride kalıntı ve buharlar kalabileceği için tank hâlâ tehlikeli olabilir ve sanki içinde hâlâ tehlikeli madde varmış gibi muamele edilmelidir."],"explanation":"Boşaltılmış bir kargo tankında tehlikeli sıvı kalıntısı ve buhar kalabilir; bu yüzden tam temizlenene kadar dolu gibi muamele edilip plakalanmalıdır."},"248":{"q":"X onayımı alıyorum ve sınav görevlisi terminalde bir 'kargo tankı' (cargo tank) ile taşınabilir tank arasındaki farkı açıklamamı istiyor. Sahayı dolaşırken sıvı tehlikeli madde taşıyan birkaç tank görüyorum. Bunlardan hangisini doğru şekilde 'kargo tankı' olarak tanımlamalıyım?","options":["Kamyonun veya römorkun kendisine kalıcı olarak bağlı olan ve onun ayrılmaz bir parçasını oluşturan dökme tank","Forklift ile römorka yüklenen ve tekrar kaldırılarak indirilebilen, kendi başına duran çelik tank","Araca nasıl yerleştirildiğine bakılmaksızın 1.001 pound veya daha fazla sıvı içeren herhangi bir tank","Taşımak için römorkun kasası içine kayışlarla sabitlenmiş, ayrı duran 55 galonluk bir varil"],"explanation":"Kargo tankı, çıkarılabilir taşınabilir tankın aksine, kamyon ya da römorka kalıcı olarak bağlı ve onun ayrılmaz bir parçasıdır."},"249":{"q":"Tehlike levhası (placard) taşıyan bir HazMat yüküyle sefer öncesi kontrolümü yapıyorum ve kabine monte edilmiş yangın söndürücüyü kontrol ediyorum. Gösterge dolu okuyor ve söndürücü sağlam şekilde monte edilmiş, ancak yola çıkmadan önce cihazın gereksinimi karşıladığından emin olmak istiyorum. Levhalı aracım için gereksinimi karşılayan EN DÜŞÜK söndürücü derecesi hangisidir?","options":["1 A derecesi, çünkü söndürücü ahşap ve kâğıt gibi sıradan yanıcı maddelerle başa çıkabilmelidir","En az 10 B:C derecesi","Gösterge dolu okuduğu ve sağlam şekilde monte edildiği sürece çalışan herhangi bir söndürücü kabul edilebilir","Deponun alabileceği galon yakıt miktarına göre derecelendirilmiş su tipi bir söndürücü"],"explanation":"Plakalı tehlikeli madde aracında en az 10 B:C dereceli bir yangın söndürücü bulunmalıdır."},"250":{"q":"Kırsal iki şeritli bir yolda yanıcı sıvı taşıyan plakartlı (tehlike levhalı) bir yük taşıyorum ve bariyeri, ışığı veya 'DUR' tabelası olmayan kontrolsüz bir demiryolu geçidine yaklaşıyorum. Aşağıdakilerden hangisi Teksas yasalarının benden yapmamı istediği şeydir?","options":["Beni durmaya zorlayan bir sinyal veya 'DUR' tabelası olmadığı için yol hızında devam etmek","Neredeyse durana kadar yavaşlamak, raylar üzerindeyken vites küçültmek ve momentumu korumak için geçip gitmek","En yakın raydan 15 ila 50 fit önce durmak ve yalnızca durmadan rayları tamamen geçebileceksem geçmek","En yakın raya 5 fit mesafede durmak, ardından yolun açık olduğunu doğrulayınca ilerlemek"],"explanation":"Plakalı bir araç, en yakın raydan 15 ila 50 fit önce daima durmalı ve ancak durmadan rayları tamamen geçebilecekse karşıya geçmelidir."},"251":{"q":"Plakartlı (levha takılı) yanıcı sıvı yükü taşıyorum ve demiryolu geçidinden 15 ila 50 fit önce zorunlu duruşumu yaptım. Işıklar kapalı, gelen tren yok ve karşı tarafın boş olduğunu, tüm aracım için yeterli yer bulunduğunu görüyorum. Rayların üzerinden ilerlerken doğru geçiş şekli nedir?","options":["Motorun raylarda daha fazla çekiş gücüne sahip olması için geçidin ortasında küçük vitese düşürmek","Geçerken vitesleri yükselterek hız kazanmak ve raylarda daha az zaman geçirmek","Devam etmeden önce pürüzleri hissetmek için rayların üzerinde neredeyse sürünür hıza yavaşlamak","Geçidi tamamen geçene kadar hiç vites değiştirmeden tek viteste geçmek"],"explanation":"Demiryolu raylarını seçilen tek bir vitesle geçin ve rayların üzerinde asla vites değiştirmeyin, böylece raylarda stop etmeyi önlersiniz."},"252":{"q":"Plakartlı bir yük - Bölüm 1.1 patlayıcılar - taşıyorum ve gece konaklamak için durmam gerekiyor. Park yerinde bir nokta seçmek için dolaşırken, bu koşullardan hangisi bir konumu reddedip yola devam etmemi gerektirir?","options":["İşçilerin için için yanan atıkları attığı bir çöp yakma varilinin hemen yanındaki bir nokta","Yolun trafiğe açık kısmından 5 fitten daha geride, düz ve iyi tesviye edilmiş çakıl bir zemin","Bir sıra uzun ağaç sayesinde serin kalan, gölgeli bir park köşesi","Düzgün, yeni asfaltlanmış ve iyi drenaja sahip bir nokta"],"explanation":"Patlayıcılar, alev ve kıvılcım saçan çöp yakma varili gibi aktif ateşleme kaynaklarından uzak tutulmalıdır."},"253":{"q":"Gönderici rampasında, 8. sınıf aşındırıcı sıvı dolu birkaç mühürlü varili van römorkuma yüklüyorum. Forklift operatörü taşıma için varilleri nasıl yerleştirmek istediğimi soruyor. Bu yükü güvenli ve doğru şekilde taşımak için variller nasıl yerleştirilmelidir?","options":["Daha sıkı istiflenip yolda daha az kaymaları için yan yatırılarak","Dolduruldukları ve mühürlendikleri gibi, dik ve doğru tarafı yukarıda olacak şekilde","Sızıntı olursa mühürlü üst kısımda tutulsun diye ters çevrilerek istiflenmiş halde","Yan yatırılmış ama yuvarlanamayacak şekilde takozlarla sıkıca sabitlenmiş halde"],"explanation":"Tehlikeli madde varilleri, kapakları ve contaları yukarı bakacak şekilde tasarlandığından dik, doğru tarafı yukarıda taşınmalıdır."},"254":{"q":"Yüksek sıcaklıkta taşınan ve bu nedenle yüksek sıcaklıklı madde sayılan erimiş kükürt taşıyan bir dökme kargo tankını hazırlıyorum. Yola çıkmadan önce, kuralların bu tür yük için gerektirdiği ek işaretin tankta bulunduğundan emin olmak istiyorum. Hangi işareti kontrol ediyorum?","options":["\"COLD\" (SOĞUK) işareti, çünkü uyarı, müdahale ekiplerine içeriğin ortam sıcaklığının altında soğuk tutulması gerektiğini bildirir","Kargonun sıvılaşmış halini belirtmek için uygun sevkiyat adının yanına yazılmış \"MOLTEN\" (ERİMİŞ) işareti","\"HOT\" (SICAK) işareti, yaklaşan herkese yükü yüksek sıcaklıklı bir madde olarak tanımlar","\"WET\" (ISLAK) işareti, çünkü kurallar aşırı ısınmış her sıvıyı ıslandığında tehlikeli bir madde gibi değerlendirir"],"explanation":"Yüksek sıcaklıktaki maddeler, yaklaşan herkesi yanma ve ısı tehlikesine karşı uyarmak için HOT yazısını taşımalıdır."},"255":{"q":"Sefer öncesi kontrolümde, gönderenin bir nehrin yakınında dökülürse balıklara ve su yollarına zararlı olduğu konusunda uyardığı bir madde varilinin sevk belgelerini inceliyorum. Yükü kabul etmeden önce paketin doğru işaretlendiğini doğrulamam gerekiyor. Bu maddeyi su ortamına zararlı olarak tanımlamak için pakette hangi işaret bulunmalıdır?","options":["KEEP DRY (KURU TUTUN), çünkü suyla temas bu tür maddeyi daha tehlikeli hale getirir","DANGEROUS WHEN WET (ISLANDIĞINDA TEHLİKELİ), çünkü tehlike suyla ve su yoluyla ilgilidir","THIS SIDE UP (BU TARAF YUKARI), zararlı sıvının suya doğru sızmasını önlemek için","MARINE POLLUTANT (DENİZ KİRLETİCİSİ), su ortamına zararlı bir maddeyi tanımlar"],"explanation":"Su yollarına ve sucul yaşama zararlı bir madde, MARINE POLLUTANT işaretiyle tanımlanır."},"256":{"q":"Ben HazMat onayı için çalışan yeni bir CDL sürücüsüyüm ve sevkiyat sorumlum bana, tehlikeli maddelerin nasıl sınıflandırıldığını, paketlendiğini, işaretlendiğini ve taşındığını düzenleyen kuralları yasal olarak bilmem gerektiğini söylüyor. Bu bağlayıcı kuralların gerçekte nerede yazılı olduğunu sorduğumda, çalışmam gereken doğru yasal otorite hangi kaynaktır?","options":["Yasal olarak bağlayıcı Tehlikeli Madde Yönetmeliklerini içeren federal düzenlemeler (49 CFR)","Yasal olarak bağlayıcı tehlike sınıflandırma kurallarını içeren Acil Durum Müdahale Kılavuzu (ERG)","Tüm HazMat taşıma kurallarının resmi yasal kaynağı olan Texas CDL El Kitabı (DL-7C)","Taşıyıcının geçerli HazMat kurallarını yazdığı konşimento ve sevkiyat belgeleri"],"explanation":"Tehlikeli Madde Yönetmelikleri, Federal Yönetmelikler Kanunu'nun 49. Başlığında (49 CFR) yer alan yasal olarak bağlayıcı kurallardır."},"257":{"q":"Plakartlı bir aşındırıcı (korozif) madde yükünü yeni aldım ve uzun bir eyaletler arası yola çıkmadan önce evraklarımı düzenlemek için bir kamyon durağında durdum. Yola çıktığımda kurallara uygun olmam için Acil Müdahale Kılavuzu'nu (ERG) nerede bulundurmam gerekir?","options":["Bir olay sırasında sevkiyat birimi başvurabilsin diye taşıyıcının terminal ofisinde dosyalanmış olarak","Plakartlı yükü kullanırken uzanabileceğim şekilde aracın içinde","Tehlike bilgilerini gönderici hazırladığı için göndericinin evraklarıyla birlikte","Gerçek ürünle birlikte kalsın diye aşındırıcı maddelerle birlikte römorkta kilitli olarak"],"explanation":"Acil Müdahale Kılavuzu'nu, sürüş sırasında ulaşabileceğiniz şekilde kabin içinde taşıyın; çünkü yalnızca yanınızdaysa işe yarar."},"258":{"q":"Plakartlı bir yük taşırken, mühürlü varillerinizden birinden römork zeminine az miktarda sıvı damladığını fark ediyorsunuz. Sızıntı küçük ve kimsenin hayatı doğrudan tehlikede değil. Hangi eylem DPS Tehlikeli Madde prosedürüne en uygun olanıdır?","options":["Bir tamircinin varili inceleyip yeniden mühürleyebileceği en yakın kamyon durağına kadar rotanıza devam edin","Sızıntı daha fazla yayılmadan giderilebilmesi için en yakın tamir atölyesine yavaşça gidin","Aracı bulunduğu yerde bırakın, hareket ettirmeyin ve sızıntıyla ilgilenmesi için nitelikli yardım çağırın","Damlayan yeri emici bezlerle örtün, yola devam edin ve seferi bitirince sızıntıyı bildirin"],"explanation":"Tehlikeli madde sızıntısı bulunduğunda aracı asla hareket ettirmeyin, bunun yerine yetkili yardım çağırın; çünkü hareket etmek kirliliği yayabilir."},"259":{"q":"Plakartlı yanıcı sıvı taşıyan uzun bir sefere çıkmak üzereyim ve yola çıkmadan önce sefer öncesi muayenemin tehlikeli madde standardını karşılamasını istiyorum. Aşağıdakilerden hangisi bu sefer başlamadan önce muayene etmem GEREKENİ EN İYİ şekilde tanımlar?","options":["Yalnızca sevk belgelerini ve dört plakartı, çünkü aracın kendisi bir önceki seferde kontrol edilmişti","Yalnızca lastikleri, çünkü kuralların bana her 2 saatte bir veya 100 milde bir yeniden kontrol etmemi zorunlu kıldığı tek parça onlardır","Yalnızca fren sistemini, çünkü frenler yüklü bir tehlikeli madde aracındaki en kritik tek bileşendir","Frenleri ve aracın tamamını, tüm ünitenin eksiksiz bir sefer öncesi muayenesini yaparak"],"explanation":"Plakart taşıyan tehlikeli madde nakliyesi görevlerinize eklenir, bu yüzden yolculuktan önce frenlerin ve tüm aracın tam bir sefer öncesi muayenesini yapın."},"260":{"q":"Teksas'ta kırsal bir karayolunda plakartlı bir klor yükü (Sınıf 2.3 zehirli gaz) taşıyorum ve bariyeri, yanıp sönen ışığı ve çevrede başka trafik olmayan işaretsiz bir demiryolu geçidine yaklaşıyorum. Kanun burada benden ne yapmamı istiyor?","options":["En yakın raydan 15 ila 50 fit önce durmak, ardından geçidi ancak rayları tamamen geçebileceksem geçmek","Yavaşlayıp bunu bir yol ver işareti gibi değerlendirmek ve sinyal ya da yaklaşan tren olmadığı için yavaşça geçip gitmek","Yalnızca yerleştirilmiş bir DUR veya demiryolu geçidi tabelası görürsem durmak, aksi halde izin verilen karayolu hızında devam etmek","Raylardan önce düşük vitese geçmek ve motoru geçidin tamamı boyunca düzenli olarak çekişte tutmak"],"explanation":"Plakart taşıyan zehirli gaz yükü her geçitte en yakın raydan 15 ila 50 fit önce durmalı ve yalnızca rayları tamamen geçebiliyorsa karşıya geçmelidir."},"261":{"q":"HazMat (H) onayımı aldım ve o zamandan beri plakartlı yükler taşıyorum. Bir arkadaşım, güvenlik tehdit değerlendirmesini ve yazılı sınavı geçtikten sonra artık ömür boyu hazır olduğunu ve bir daha asla HazMat konusuna dönmen gerekmediğini söylüyor. Texas DPS, güncel kalmam için HazMat eğitimimi gerçekte hangi aralıkla tekrarlamamı bekliyor?","options":["Her yıllık sağlık sertifikası yenilemesine bağlı olarak yaklaşık her 1 yılda bir","Yaklaşık her 3 yılda bir","Standart CDL yenileme döngüsüyle eşleşerek yaklaşık her 10 yılda bir","Bir daha asla — onay ve TSA kontrolü bir kez geçildikten sonra yeniden eğitim gerekmez"],"explanation":"Tehlikeli madde eğitimi, sürücüyü güvenli taşıma, plakart ve acil durum prosedürleri konusunda güncel tutmak için yaklaşık her 3 yılda bir tekrarlanmalıdır."},"262":{"q":"Sefer öncesi kontrolümü yapıyorum ve sevk belgelerinde Sınıf 6.1 bir yük listeli; römorkta zaten 'POISON' (ZEHİR/TOKSİK) yazan elmas bir plaka var. Daha yeni bir sürücü bana bu plakanın aslında bizi neye karşı uyardığını soruyor. Ona hangi ifadeyi vermeliyim?","options":["Yükün yanıcı bir sıvı olduğunu uyarır, yani asıl tehlike açık aleve yakın tutuşması durumunda yangındır","Yükün aşındırıcı olduğunu uyarır, yani asıl tehlike temas hâlinde cilt ve gözlerde kimyasal yanıklardır","Maddenin insanlar için zararlı veya öldürücü olduğunu uyarır, yani ona maruz kalmak zehirleyebilir veya öldürebilir","Yükün bir yükseltgen olduğunu uyarır, yani asıl tehlike diğer maddelerin daha hızlı yanmasına yol açmasıdır"],"explanation":"POISON veya TOXIC plakartı, maddenin insanlar için zararlı ya da öldürücü olduğunu ve temasta zehirleyip öldürebileceğini uyarır."},"263":{"q":"'OXYGEN' (OKSİJEN, Sınıf 2.2) plakartlı bir yük taşıyorum ve yol kenarındaki kontrolde lastiklerimden birinden duman geldiğini fark ediyorum. Durumu değerlendirirken, bu yükün yanındaki ısıyı ve olası alevi nasıl ele alacağım konusunda aşağıdakilerden hangisi EN ÇOK ağırlık taşımalıdır?","options":["Oksijen, yayılmadan önce küçük bir yangını boğup söndürür, bu yüzden tepki vermek için fazladan zamanım var.","Yanıcı olmayan bir gaz olduğundan oksijen yangını hiçbir şekilde etkilemez, dolayısıyla tek endişem lastiktir.","Oksijen çevredeki yükü soğutup sıcaklığı düşürür ve sıcak lastikten gelen tehlikeyi azaltır.","Oksijen bir yangını besleyip şiddetlendirebilir, bu yüzden bu yükün yanındaki küçük bir alevi bile ciddi bir tehdit olarak görmeliyim."],"explanation":"Oksijen ateşi besler ve şiddetlendirir, bu yüzden oksijen yükü yakınındaki herhangi bir alev veya aşırı ısınma ciddi bir tehlike olarak görülmelidir."},"264":{"q":"Bölüm 1.2 patlayıcı madde yüklü, plakartlı bir araç kullanıyorsunuz ve federal kurallarca zorunlu mola için durmanız gerekiyor. Yasal bir park yeri ararken, motoru kapatmadan önce hangi yerden en az 300 fit (300 feet) uzakta durmak ZORUNDASINIZ?","options":["İşçilerin ve müşterilerin düzenli olarak toplandığı yol kenarındaki bir depo binası","Taşıt yolunun kenarındaki boyalı sınır çizgisi","İleride karayolunu kesen bir demiryolu hattı","Dinlenme alanına yasalara uygun park etmiş başka bir ticari araç"],"explanation":"Sınıf 1.1, 1.2 ve 1.3 patlayıcılar, yol kenarındaki bir depo gibi insanların toplandığı bir binadan 300 fit içinde asla park edilemez."},"265":{"q":"Plakartlı bir yük taşıyorum ve yol kenarındaki bir sorunu kontrol ederken kamyonumu kırsal bir karayolunun banketinde birkaç dakika park halinde bırakmam gerekiyor. Yönetmeliklere göre araç gözetim altında olmalı. Yasal olarak gözetmen sayılabilmem için, park halindeki plakartlı aracımdan ne kadar uzakta bulunmama izin verilir?","options":["Aracın 5 fit yakınında, yani yolun trafiğe açık kısmından uzak durmam gereken mesafeyle aynı","Aracın 100 fit yakınında, aracı net görüş alanımda tutarak ve gerekirse hareket ettirebilecek durumda","Aracın 300 fit yakınında, yani köprü ve tüneller çevresinde gereken tampon mesafeyle aynı","Çeyrek mil mesafede, plakartları hâlâ görebildiğim sürece"],"explanation":"Park edilmiş plakartlı bir aracın görevlisi, araçtan 100 fit içinde kalmalı, onu açıkça görebilmeli ve acil durumda hareket ettirebilmelidir."},"266":{"q":"Sefer öncesi kontrolümde, dispeçerim aracımdaki kargo tanklarından birinin kargo tankeri değil, bir \"taşınabilir tank\" (portable tank) olduğunu söylüyor. Bunu doğrulamak için incelerken, hangi özellik onu DOĞRU şekilde taşınabilir tank olarak tanımlar?","options":["Aracın şasisine kalıcı olarak kaynaklanmıştır ve sökülemez","Römork şasisinin kendisinin ayrılmaz bir yapısal parçasıdır","Araca kalıcı olarak bağlı olmayan bir dökme yük kabıdır","Kamyonun kabinine ve gövdesine doğrudan monte edilmiş sabit bir tanktır"],"explanation":"Taşınabilir tank, araca kalıcı olarak sabitlenmemiş, yüklenip çıkarılabilen bir dökme kaptır."},"267":{"q":"Bir kimya deposunda Sınıf 2 sıkıştırılmış gaz sevkiyatını yüklüyorum ve rampa sorumlusu, ben teslim alıp taşımadan önce ürünün hangi ambalajda hazır olması gerektiğini soruyor. Yükü yasal ve güvenli şekilde kabul edebilmek için sıkıştırılmış gaz hangi tür kaba paketlenmiş olmalıdır?","options":["Shrink-wrap paletin üzerinde bantlanmış, ağır mukavva kutulara mühürlenmiş halde","Düz platformlu bir römorkun açık kasasına gevşek yüklenmiş ve kargo kayışlarıyla sabitlenmiş","Kuru dökme malzemeler gibi astarlı bir hazneli (hopper) römorka dökülmüş halde","Basınçlı tüplerin içine konulmuş ya da o gaz için yapılmış bir tüp römorkunda taşınmış halde"],"explanation":"Sıkıştırılmış gaz basınç altında tutulur ve özel tasarlanmış tüplerde veya gaza uygun tüp römorkta taşınmalıdır."},"268":{"q":"Sıcak bir Teksas öğleden sonrasında sıvılaştırılmış yanıcı gaz taşıyan bir kargo tankı çekiyorum ve yük güneşte ısınırken kısa bir tıslama duyuyorum ve tankın üstündeki yaylı bir cihazdan küçük bir buhar bulutunun çıktığını görüyorum, ardından bu kendiliğinden duruyor. Bu basınç tahliye valfi ne yapıyor ve buna nasıl davranmalıyım?","options":["Tankın patlamasını önlemek için birikmiş iç basıncı otomatik olarak tahliye ediyor, bu yüzden ona dokunmuyorum ve tasarlandığı gibi çalışmasına izin veriyorum.","Tankın nominal kapasitesinin üzerinde aşırı doldurulduğunun bir işareti, bu yüzden durup tıslama kesilene kadar üründen boşaltmam gerekiyor.","Gazı sıkıştırılmış tutmak için tanka basınç ekliyor, bu yüzden sürekli devreye girmesini beklemeli ve buharı tamamen görmezden gelmeliyim.","Arızalanıp kargoyu dışarı veriyor, bu yüzden bir sonraki durağımda valfi sıkmalı veya kapaklamalı, tankı sımsıkı kapatıp kaybı durdurmalıyım."],"explanation":"Basınç tahliye valfi, tankın patlamasını önlemek için biriken iç basıncı otomatik olarak boşaltır, bu yüzden tasarlandığı gibi çalışmasına izin verin."},"270":{"q":"Tehlikeli madde plakartı taşıyan bir teslimatı yeni boşaltırdım ve araç çevresi kontrolünü yaparken rıhtımda bırakılan paketlerden birinin altında yayılan ıslak, rengi değişmiş bir leke ve hafif bir kimyasal koku fark ettim. Alıcı yükü zaten imzaladı. DPS tehlikeli madde kurallarına göre yapmam gereken doğru şey nedir?","options":["Benden başka bir şey beklenmez — alıcı sevkiyatı imzaladığı için sızıntılı paketin sorumluluğu tamamen ona geçmiştir","Teslimat teknik olarak tamamlanmış olsa bile sızıntıyı hemen bildirmeli ve paketin kontrol altına alınıp güvenli bir şekilde taşınmasını sağlamalıyım","İmzalanmış bir teslimattan sonra sızıntı bildirmek yalnızca evrak işi yaratıp beni geciktireceği için paketi sessizce göz önünden çekip hiçbir şey söylememeliyim","Paketi bantla yeniden kapatıp değerini not etmeli ve zararı telafi etmek için içeriği indirimli olarak imha etmeli ya da yeniden satmalıyım"],"explanation":"Tespit edilen bir sızıntı, teslimat tamamlanmış olsa bile derhal bildirilmeli ve ambalaj güvenli şekilde kontrol altına alınıp ele alınmalıdır."},"271":{"q":"Bir teslimat durağında römorkumdaki bir varil aşındırıcı (Sınıf 8) sıvı patlıyor ve bir gölet park alanına yayılıyor. Etraftakileri zaten uyardım, insanları uzak tuttum ve CHEMTREC'i bilgilendirdim. Dökülen maddenin fiziksel temizliğini gerçekte kim yapmalıdır?","options":["Eldivenlerimi ve emici malzememi alıp kendim temizlemeliyim, çünkü yükün kontrolündeki sürücü benim","Maddeyi sınıflandırıp paketleyen gönderici gelip temizliği yapmalıdır","Eğitimli acil müdahale ekipleri veya nitelikli temizlik yüklenicileri temizliği üstlenmelidir","Maddeyi hızlıca sınırlandırıp kaldırmak için etraftaki herhangi biri yönlendirilebilir"],"explanation":"Dökülen maddenin temizliği, malzemeyi güvenle ele alabilen eğitimli acil müdahale ekipleri veya yetkili temizlik müteahhitleri için özel bir iştir."},"272":{"q":"Tehlikeli madde (HazMat) onayım için gereken güvenlik farkındalığı eğitimini yeni tamamladım ve bir iş arkadaşım bana bu eğitimin asıl amacının ne olduğunu soruyor. Eğitimin gerçekleştirmek üzere tasarlandığı amaca göre, aşağıdakilerden hangisi bana neyi öğrettiğinin EN İYİ tanımıdır?","options":["Yükleme alanında daha hızlı plaka takabilmek için her zaman plaka gerektiren dört tehlike sınıfını ezberlemek","Plakalı bir yükü trafikte daha hızlı hareket ettirebilmek için takip mesafemi ve fren noktalarımı ayarlamak","Evrakım terminalde zaten doğrulandıktan sonra yol üstündeki tekrar eden kontrolleri atlamak","Yüküm çevresindeki şüpheli davranışları veya olası güvenlik tehditlerini fark etmek ve bu tehditleri yetkili makamlara bildirmek"],"explanation":"Güvenlik farkındalığı eğitimi, sürücülere yüklerine yönelik şüpheli davranışları veya güvenlik tehditlerini fark etmeyi ve bunları yetkililere bildirmeyi öğretir."},"273":{"q":"Plakartlı bir aşındırıcı madde yükü taşıyorum ve tartı istasyonunda bir devriye polisi, sevkiyat belgelerimde maddenin \"temel tanımını\" göstermemi istiyor. Temel tanım olarak polise hangi kayıt kombinasyonunu göstermeliyim?","options":["Uygun sevkiyat adı, tehlike sınıfı, kimlik numarası ve ambalaj grubu","Uygun sevkiyat adı, toplam ağırlık, acil durum telefon numarası ve ERG kılavuz sayfası","Tehlike sınıfı, plakart rengi, gönderici imzası ve paket sayısı","Kimlik numarası, araç tescili, taşıyıcı adı ve güzergah planı"],"explanation":"Tehlikeli maddenin temel tanımı; doğru sevkiyat adı, tehlike sınıfı, tanımlama numarası ve ambalaj grubudur."},"274":{"q":"Plakartlanmış 3. Sınıf yanıcı sıvı yükü taşırken kargo bölümünde sızdıran bir varilin yanında küçük bir yangın çıkıyor. Birkaç söndürme seçeneğine erişimim var. Bu yangını en etkili şekilde bastırmak için ne kullanmalıyım?","options":["Yanan sıvıyı soğutmak için üzerine sürekli ve yoğun bir su akıtmak","Köpükle örtmek veya oksijeni kesmek için B:C sınıfı bir yangın söndürücü kullanmak","Aleve gömülene kadar üzerine yol kenarından gevşek kum atmak","Geri çekilip müdahale ekiplerini beklerken kendi kendine sönmesine izin vermek"],"explanation":"Yanıcı sıvı (Sınıf 3) yangını, oksijeni kesmek için köpük veya B:C sınıfı söndürücüyle boğulmalı, asla suyla soğutulmamalıdır."},"275":{"q":"Sınıf 3 yanıcı sıvı (benzin varilleri) taşıyorum ve bir sızıntı sonrası varillerden biri kargo bölümünde küçük bir yangın başlatıyor. Yoldan geçen biri bir kova suyla koşarak gelip alevler büyümeden bastırmama yardım etmeyi öneriyor. Suyu dökmesine izin vermeden önce, suyun bu yanıcı sıvı yangınına ne yapmasını beklemeliyim?","options":["Su ateşin oksijenini kestiği için alevleri hızla boğar","Yanan benzini parlama noktasının altına soğutur ve yangını hemen söndürür","Yangını yayar, çünkü yanan sıvı suyun üzerinde yüzer ve su tarafından taşınır","Pek bir etki etmez, bu yüzden yardım beklerken denenecek en güvenli şeydir"],"explanation":"Su, benzin gibi yanan yanıcı sıvıyı yayar; çünkü sıvı suyun üzerinde yüzer ve onunla birlikte taşınır."},"276":{"q":"Plakartlı bir Sınıf 5 oksitleyici (yükseltgen) yükü taşırken kargoda küçük bir yangın çıkıyor. Bir yoldan geçen yangın söndürücüyü kapıp şöyle diyor: \"Merak etme, havayı keserek boğarsak hemen söner.\" Taşıdığım maddenin kimyasına göre bu varsayım neden yanlıştır?","options":["Çünkü oksitleyiciler aşındırıcıdır, alevi boğmadan önce yangın söndürücüyü eritir","Çünkü yangın etkilenemeyecek kadar soğuktur, çünkü oksitleyiciler yalnızca donma sıcaklıklarında yanar","Çünkü oksitleyiciler suyu emer, bu yüzden söndürücüden gelen herhangi bir nem yangının daha hızlı yayılmasına neden olur","Çünkü bir oksitleyici kendi oksijenini açığa çıkarır, bu nedenle çevrede az hava olsa bile yangın yanmaya devam edebilir"],"explanation":"Oksitleyici (Sınıf 5) kendi oksijenini sağladığından, yangın çevrede az hava olsa bile yanmaya devam eder ve boğularak söndürülemez."},"277":{"q":"Yükleme rampasında araç öncesi muayenemi yaparken, bir göndericinin az önce yüklediği aşındırıcı (Sınıf 8) paketlerden birinden gelen küçük ıslak bir leke ve hafif bir kimyasal koku fark ediyorum. Taşıma irsaliyesi eksiksiz görünüyor ve teslimat zaman açısından kritik. Bu paketi taşımayı reddetmem için EN İYİ neden nedir?","options":["Sızdıran bir paket insanlara zarar verebilir ve çevredeki alanı kirletebilir, bu yüzden taşınmamalıdır","Küçük bir sızıntı yalnızca zamanında teslimatı etkiler, bu yüzden programı telafi etmek için daha hızlı sürdüğüm sürece taşıyabilirim","Gönderici irsaliyeyi zaten imzaladı, bu yüzden sızıntı benim değil, taşıyıcının evrak sorunu olur","Sınıf 8 yükü için küçük bir leke normaldir, bu yüzden paketi silip başka bir işlem yapmadan yükleyebilirim"],"explanation":"Sızdıran tehlikeli madde ambalajı insanlara zarar verebilir ve çevreyi kirletebilir, bu yüzden sürücü onu kabul etmemeli ve taşımamalıdır."},"278":{"q":"Yol kenarındaki bir dinlenme alanında park hâlindeyken plakartlı tankerimde aşındırıcı bir sızıntı oluşuyor. Doğru tepki, aracı yerinde bırakmak, insanları uzak tutmak ve acil müdahale ekiplerine haber vermektir. Sızıntı yapan aracı hangi durumda gerçekten hareket ettirmem haklı görülür?","options":["Tank tamamen boşalmadan en yakın yakıt istasyonuna ulaşmak için","İnsanları yayılan tehlikeden kaynaklanan ani tehlikeden uzaklaştırmak için","Bir tamirhaneye daha hızlı varmak ve uzun bir gecikmeden kaçınmak için","Temizliği kolaylaştırmak amacıyla kamyonu bir binaya daha yakın konumlandırmak için"],"explanation":"Sızdıran bir tehlikeli madde aracı yalnızca insanları yayılan tehlikeden uzaklaştırmak gerektiğinde hareket ettirilmelidir."},"279":{"q":"Plakartlı bir aşındırıcı (korozif) madde yükü taşırken bir bağlantı arızası nedeniyle banket üzerine sızıntı meydana geliyor. Acil tehlikeyi kontrol altına aldıktan, çevredekileri uzak tuttuktan, sigara içilmesini önledikten ve acil müdahale ekiplerini ile CHEMTREC'i aradıktan sonra bile federal kurallar olayın raporlanmasını zorunlu kılıyor. Bu zorunlu olay raporunun yapılabilmesi için kimi bilgilendirmekle sorumluyum?","options":["Aşındırıcı maddeleri sınıflandırıp paketleyen ve sevk belgelerini hazırlayan gönderici (shipper)","Yoldaki herhangi bir dökülme için resmi yazılı olay raporunu sunmak zorunda olan yerel itfaiye amiri","İşverenim/taşıyıcı (carrier) — yükü taşımaktan ve olayı raporlamaktan sorumlu olan taraf","Dökülme yerine en yakın DPS kantar istasyonu müfettişi, çünkü plakartlı yükler kantarlarda takip edilir"],"explanation":"Yükü taşımaktan ve gerekli tehlikeli madde olay raporunu yapmaktan sorumlu olan taraf taşıyıcıdır."},"280":{"q":"Sınıf 3 yanıcı sıvı plakartı gerektiren bir yükte sefer öncesi kontrol yaparken römorkumun etrafında dolaşıyorum. Plakartın doğru olduğunu teyit etmek için baklava (eşkenar dörtgen) şeklindeki işaretteki tehlike sınıfı numarasına bakıyorum. Bu numarayı okumak için plakartın neresine bakmalıyım?","options":["Baklavanın en üst köşesinde, sembolün hemen üstünde","Baklavanın tam ortasında, sembolün içinde","Baklavanın en sağ köşesi boyunca","Baklavanın alt köşesinde, sembolün altında"],"explanation":"Bir DOT plakartında tehlike sınıfı veya bölüm numarası, eşkenar dörtgenin alt köşesine, sembolün altına yerleştirilir."},"281":{"q":"Sefer öncesi kontrolümü yapıyorum ve doğru olduğundan emin olmak için römorktaki elmas şeklindeki plakartı (tehlike levhasını) inceliyorum. Tehlike türünü bir bakışta hızlıca anlamak için, tehlike sembolüne (alev, kafatası veya radyoaktif yonca işareti gibi) plakartın hangi bölümünde bakmalıyım?","options":["Plakartın üst köşesinde, yazılı tehlike sınıfı adının üzerinde","Plakartın alt köşesinde, tehlike sınıfı numarasının yazılı olduğu yerde","Plakartın sağ kenarında, dört haneli kimlik numarasının yanında","Plakartın ortasında, çapraz renk ayrımının tam üzerinde"],"explanation":"Bir DOT plakartında tehlike sembolü, yazılı tehlike sınıfı adının üstünde, eşkenar dörtgenin üst köşesine yerleştirilir."},"282":{"q":"Yükleme rampasında sevkiyat görevlisi, bir sonraki yükümün \"dökme ambalaj\" (bulk packaging) içinde gönderileceğini ve belgeleri imzalamadan önce bunu doğrulamam gerektiğini söylüyor. Römorku dolaşırken, bu kaplardan hangisi dökme ambalaj tanımına doğru şekilde uyar?","options":["Her biri yastıklama içinde birkaç küçük şişe barındıran, mühürlü mukavva kutularla istiflenmiş bir palet","Ürünün doğrudan içine yüklendiği, içeriği tutan herhangi bir iç ambalaj bulunmayan büyük bir taşınabilir tank","Römork duvarının yanında duran, vidalı kapaklı tek bir 5 galonluk plastik varil","Etiketli bir karton kutu içine yerleştirilmiş, fermuarla kapatılmış küçük bir granül torbası"],"explanation":"Dökme ambalaj, taşınabilir tank gibi büyük bir kaptır ve ürün, içeriği tutan iç ambalaj olmadan doğrudan içine yüklenir."},"283":{"q":"Bir kimyasal depoda römorkumu yüklüyorum ve gönderici, 8. sınıf aşındırıcı bir maddenin birkaç 'dökme olmayan' (non-bulk) paketi için imza atmamı istiyor. Yükü rampada ayırırken, bu 'dökme olmayan' tanımına hangi kabın uymasını beklemeliyim?","options":["Ayrı bir römorka kalıcı olarak monte edilmiş 6.000 galonluk kargo tankı","Depo yan hattına manevrayla alınan taşınabilir demiryolu tank vagonu","Tek bir palet üzerine birlikte istiflenmiş, mühürlü 55 galonluk çelik variller","Aynı ürünü almayı bekleyen nehir mavnasının bölmesi"],"explanation":"Dökme olmayan ambalaj, tehlikeli madde taşımakta kullanılan variller, kutular, bidonlar ve torbalar gibi daha küçük kaplardır."},"284":{"q":"Yanıcı sıvı yüklü bir tankerde sefer öncesi kontrolü yaparken, tankın üstündeki kubbe bölgesini incelemek için yukarı tırmanıyorum. Otoyola çıkmadan önce, yükün güvenli ve sızıntısız kalması için menhol (insan giriş deliği) kapakları hangi durumda olmalıdır?","options":["İç buhar basıncının yolculuk sırasında tahliye olabilmesi için hafifçe aralık bırakılmış","Yolda gevşeyip takırdamamaları için çıkarılıp kabinde saklanmış","Rota üzerindeki bir sonraki kontrol durağına kadar tamamen açık bırakılmış","Araç hareket ettirilmeden önce tamamen kapatılmış ve usulüne uygun şekilde sızdırmaz hale getirilmiş"],"explanation":"Tankerin menhol (dome) kapakları, yükü içeride tutmak için araç hareket ettirilmeden önce tamamen kapatılmalı ve düzgünce sızdırmaz hale getirilmelidir."},"285":{"q":"Bir tanker sürücüsüyüm ve aktarma hortumu üzerinden Sınıf 3 yanıcı sıvı yükleyeceğim. Yükleme öncesi kontrolümde bir hortumun dış katmanının aşınmış olduğunu ve kaplin yakınında küçük bir yüzey çatlağı bulunduğunu fark ediyorum. Hortumu bağlayıp ürün akışını başlatmadan önce, el kitabı yükleme veya boşaltmada kullanılan hortumlar konusunda benden ne yapmamı istiyor?","options":["Yalnızca iyi durumdaki hortumları kullanmak; bu nedenle çatlak hortumu bir kenara ayırıp yüklemeden önce hasarsız bir hortum seçmeliyim","Çatlak yalnızca dış katmanda olduğu ve motor basıncı sabit tutmak için çalışır kalacağı için bu hortumla yüklemeye devam etmek","Çatlak hortumu kullanmak ama akış hızını düşürmek, çünkü daha yavaş aktarım sınırda durumdaki bir hortumun arızalanmasını önler","Hortumu olduğu gibi bağlamak ve aktarım sırasında sızıntıları izlemesi için 25 fit uzağa ikinci bir kişi yerleştirmek"],"explanation":"Tehlikeli madde yükleme veya boşaltmada kullanılan hortumlar iyi durumda olmalıdır, bu yüzden çatlak hortum bir kenara konulup hasarsız bir hortum kullanılmalıdır."},"286":{"q":"Plakartlı (tehlike levhalı) römorkumu bir terminalde hazırlıyorum ve önümde birkaç iş var: çekiciyi yakıt ile doldurmam, yanmış bir gabari lambasını değiştirmem, sevk belgelerini imzalamam ve Sınıf 3 yanıcı sıvı varillerini römorka aktaran ekibi denetlemem gerekiyor. Bu işlerden hangisi sırasında tüm ateşleme kaynaklarını — yanan sigaralar, açık alev, kıvılcım çıkaran aletler — operasyondan tamamen uzak tutma konusunda EN katı olmalıyım?","options":["Çekiciye yakıt doldururken, çünkü depo dolarken yakıt göstergesini izleyebilmem için motor çalışır halde kalıyor","Ekip Sınıf 3 yanıcı sıvı varillerini römorka yüklerken, çünkü aktarma sırasında buharlar tutuşabilir","Yanmış gabari lambasını değiştirirken, çünkü yükün yakınındaki elektrik tesisatıyla çalışacağım","Sevk belgelerini incelerken ve imzalarken, çünkü sürmeden önce belgeleri üstte ve erişebileceğim yerde tutmam gerekiyor"],"explanation":"Sınıf 3 yanıcı sıvılar yüklenirken tüm ateşleme kaynaklarını uzak tutun, çünkü transfer sırasında kaçan buharlar tutuşabilir."},"287":{"q":"Belirlenmiş bir tehlikeli madde güzergâhına çıkmadan önce, Bölüm 1.1 patlayıcılarla yüklü bir kamyonda sefer öncesi muayene yapıyorum. Aracın etrafında dolaşırken birkaç şey dikkatimi çekiyor. Aşağıdaki tespitlerden hangisi tek başına bu aracı kullanılmaz hâle getirir ve bu yükü taşımadan önce düzeltilmesini gerektirir?","options":["Arka çamurluklardan biri çatlamış ve alt kenarından hafifçe bükülmüş","Acil durum çantasındaki yansıtıcı üçgenin yüzeyi solmuş ve matlaşmış","Depo yakınındaki bir bağlantı parçasından sürekli yakıt damlıyor — yakıt sızıntısı var","Yolcu tarafı aynası gevşek takılı ve rölantide titriyor"],"explanation":"Patlayıcı taşıyan bir araçta yakıt veya yağ sızıntısı bulunmamalıdır, çünkü her sızıntı yükün yakınında kabul edilemez bir yangın ve tutuşma tehlikesidir."},"288":{"q":"Yol kenarında bir memur beni durduruyor ve plakartlı bir aşındırıcı madde tankını taşımaya yetkili olduğumu kanıtlamamı istiyor. TSA güvenlik tehdit değerlendirmemi ve parmak izi işlemimi aylar önce tamamladım ve hepsini geçtim. HazMat (H/X) onayımın şu anda geçerli olduğunu gerçekten gösteren TEK belgeyi hangisini veririm?","options":["Geçmiş kontrolüm onaylandıktan sonra postayla aldığım TSA güvenlik tehdit değerlendirmesi onay mektubu","Geçerli DOT tıbbi muayene uzmanı sertifikam, çünkü araç kullanmaya fiziksel olarak uygun olduğumu kanıtlayan budur","Onay için ruhsat dairesinde teslim ettiğim parmak izi makbuzu ve başvuru evrak paketi","Ticari sürücü belgem, çünkü H veya X onayı doğrudan belgenin üzerine basılıdır"],"explanation":"Tehlikeli madde onayı, ticari sürücü belgenizin ön yüzüne doğrudan basılan bir koddur (H, veya tank artı tehlikeli madde için X)."},"289":{"q":"Plakartlı bir aşındırıcı madde yükü taşıyorum ve evraklarımı kontrol etmek için kısa bir mola vermem gerekiyor. Bulabildiğim tek yerlerin hepsi iki şeritli bir karayolunun yakınında. Plakartlı bir aracın park kurallarına göre, bu yerlerden hangisi beni ihlale düşürür?","options":["Kamyonumun yolun trafiğe açık kısmına yalnızca 3 fit mesafede duracağı bir banket cebi","Yolun trafiğe açık kısmının kenarından yaklaşık 20 fit geride bir çakıl alan","Yolun trafiğe açık kısmından 10 fit geride ölçülen bir dinlenme alanı yeri","Kamyonumu yolun trafiğe açık kısmından tam 8 fit uzakta tutan geniş bir yan cep"],"explanation":"Levha taşıyan bir araç, yolun kullanılan kısmına 5 fitten daha yakın park edilmemelidir."},"290":{"q":"Plakartlı bir yük alıyorum ve gönderici bana doğru sevkiyat adını, tehlike sınıfını ve kimlik numarasını gösteren evrakları veriyor. Taşıyıcı seferi düzenledi ve herhangi bir kazayı bildirecek. Bu tehlikeli maddenin güvenli taşınmasından yasal olarak başka kimin sorumlu olduğunu düşünürken, gönderici ve taşıyıcının yanında paylaşılan sorumluluk zincirini hangi taraf tamamlar?","options":["Yükü iskelede teslim aldığı için yükü teslim alan müşteri","Yükü denetleyen, sızıntıları reddeden, plakart asan ve güvenli süren sürücü","Güvenlik soruşturmamı onaylayan TSA görevlisi","Yalnızca rotayı atayan ve kargoya hiç dokunmayan sevkiyat görevlisi"],"explanation":"Sürücü, yükü inceleyerek, sızdıran veya yanlış işaretlenmiş gönderileri reddederek, tüm yönlere levha asarak ve güvenli sürerek tehlikeli madde güvenlik zincirini tamamlar."},"291":{"q":"Sınıf 7 radyoaktif bir sevkiyatı yüklüyorum ve gönderici, belgeleri imzalamadan önce etiketlerin taşıma indeksiyle eşleştiğini doğrulamamı söylüyor. Paketе baktığımda, radyasyon seviyesini belirten Romen rakamıyla yazılmış bir kategoriye sahip iki etiket görüyorum. Bu radyoaktif etiketlerde hangi kategori tanımlamaları kümesini bulmayı beklemeliyim?","options":["Paket grubuyla eşleşen harflerle A, B veya C kategorileri","Tehlike sınıfı numaralarıyla eşleşen 1, 2 veya 9 kategorileri","Radyasyon seviyesini gösteren I, II veya III kategorileri","Taşıma indeksi aralığını belirten X, Y veya Z kategorileri"],"explanation":"Radyoaktif (Sınıf 7) etiketler, radyasyon seviyesini ve taşıma endeksini gösteren Romen rakamlarıyla bir kategori taşır — I, II veya III."},"292":{"q":"Bir römorka birbirleriyle reaksiyona giren iki farklı tehlikeli madde paketi yüklüyorum ve sevk belgeleri bunların reaktif olduğunu gösteriyor. Gönderici onları ayrı tutmamı söylemedi ve yan yana koyacak yer var. Onları yan yana sabitlemeden önce tartmam gereken gerçek güvenlik endişesi nedir?","options":["Yan yana koymak sorun değil, çünkü ambalajın kendisi herhangi iki maddenin asla etkileşime girmemesini sağlayacak şekilde yapılmıştır","Tek endişe, toplam ağırlığın plaka (placard) gerektiren 1.001 lb eşiğini aşabilmesidir","Anlamlı bir şey olmaz; reaktif maddeler aynı alanda depolandığında birbirlerini basitçe nötralize eder","İki reaktif kimyasalı birlikte yüklemek yangına veya kimyasal reaksiyona yol açabilir, bu yüzden ayrı tutulmalıdırlar"],"explanation":"Uyumsuz reaktif maddeler yükleme sırasında ayrı tutulmalıdır, çünkü temas yangına veya tehlikeli bir kimyasal reaksiyona yol açabilir."},"293":{"q":"Plakart taşıyan römorkumdaki bir varil, banketin üzerine bilinmeyen bir sıvı sızdırıyor ve sevk belgelerinde maddenin tam olarak ne olduğu net değil. Maddenin ne olduğunu anlayıp müdahale ekiplerine doğru bilgi verebilmek için, aşağıdakilerden hangisini ASLA yapmamalıyım?","options":["Maddenin ne olduğunu anlamaya yardımcı olmak için tadına bakmak veya ona dokunmak","Sevk belgelerindeki doğru sevkiyat adını ve kimlik numarasını kontrol etmek","Dört haneli kimlik numarasını Acil Durum Müdahale Kılavuzu'nda (ERG) aramak","Plakart ve etiketlerde gösterilen tehlike sınıfını not etmek"],"explanation":"Bir maddeyi tanımlamak için asla tatmayın veya dokunmayın, çünkü çok küçük bir miktar bile ciddi yaralanmaya, zehirlenmeye veya kimyasal yanıklara neden olabilir."},"294":{"q":"Plakartlı (etiketli) yanıcı sıvı yükü taşıyorsunuz ve yol kenarındaki bir dinlenme alanında duruyorsunuz. Kabinin dışındayken, römorkun arka kısmında yüke yakın alevler fark ediyorsunuz. Yangın, küçük yangın söndürücünüzle bastırılamayacak kadar büyük durumda. İLK olarak ne yapmalısınız?","options":["Kabine binip yanan römorku dinlenme alanından uzakta açık bir araziye sürmeye çalışmak","İnsanları araçtan uzak tutmak ve yardım için acil müdahale ekiplerine haber vermek","Dumanı tahliye etmek ve içerideki yanan yüke ulaşmak için römork kapılarını açmak","Yangının yok etmemesi için sevkiyat belgelerini kabinde bir kenara koymak"],"explanation":"El yangın söndürücüsüyle kontrol edilemeyen bir tehlikeli madde yangınında önce can güvenliğini koruyun; insanları uzak tutun ve acil müdahale ekiplerini bilgilendirin."},"295":{"q":"Rıhtım ekibinin gece yüklediği plakartlı bir römorkta sefer öncesi kontrolümü yapıyorum ve sürücü koltuğundaki evrak Sınıf 8 aşındırıcı bir yük gösteriyor. Yola çıkmadan önce, dört tarafa zaten asılmış olan plakartlarla ilgili teyit etmem GEREKEN tek şey nedir?","options":["Plakart renginin çekicimin yan tarafındaki boya düzeni ve yazılarla uyuştuğu","Her yönden okunabilecek şekilde dört tarafın her birinde bir plakart bulunduğu","Plakartların sevk evrakında gösterildiği gibi gerçekte taşıdığım malzemeyi doğru şekilde tanımladığı","Plakartların yükü çeken çekicinin yaktığı yakıt türüyle uyuştuğu"],"explanation":"Sürücü, levhaların taşınan gerçek maddeyi doğru şekilde tanımladığını sevkiyat belgeleriyle karşılaştırarak doğrulamalıdır."},"296":{"q":"Aşındırıcı maddelerden (Sınıf 8) oluşan, plaka (placard) gerektiren bir yük yüklüyorum, ancak malzeme kutumda Sınıf 8 plakaları kalmadı. Önceki seferden kalan Sınıf 3 (Yanıcı) plakalarım var ve kamyon programın zaten birkaç saat gerisinde. Yola çıkmadan önce bu yükü plakalama konusunda doğru düşünme şekli aşağıdakilerden hangisidir?","options":["Kısa bir yolculuk için Sınıf 3 plakalarını kullanmak kabul edilebilir, çünkü herhangi bir plaka göstermek diğer sürücüleri tehlikeli madde taşıdığım konusunda yine de uyarır","Sınıf 8'i gösteren sevk belgelerini koltukta elimin ulaşabileceği yerde tuttuğum sürece hiç plaka olmadan yola çıkabilirim","Sınıf 3 plakalarını iki tarafa takıp diğer iki tarafı boş bırakmak kabul edilebilir, çünkü yük yalnızca kısmen plakalanmıştır","Yanlış (Sınıf 3) plakaları göstermek yasa dışı ve güvensizdir, bu yüzden doğru Sınıf 8 plakalarını edinene kadar yükü hareket ettirmemeliyim"],"explanation":"Levhalar dört tarafta da doğru olmalıdır, bu yüzden yük yanlış levhalarla taşınamaz; Sınıf 8 aşındırıcı için Sınıf 8 levhaları gerekir."},"297":{"q":"Teksas genelinde plakartlı (placard) bir yanıcı sıvı yükü taşıyorsunuz ve hizmet saatleri sayacınız sizi önümüzdeki 20 dakika içinde mola vermeye zorluyor. İleride tıka basa dolu bir alışveriş merkezi otoparkı, ailelerle dolu kalabalık bir yol kenarı dinlenme alanı ve her türlü kalabalıktan iyice uzak, sessiz bir çakıllı durak yeri görüyorsunuz. Durağınızı nerede planlamalısınız?","options":["Sessiz çakıllı durak yerinde; plakartlı bir yükle durduğunuzda her zaman insanlardan uzak, güvenli bir yer seçerek","Kalabalık yol kenarı dinlenme alanında; çünkü dinlenme alanları plakartlı araçlar için yasal olarak onaylanmış tek durak noktalarıdır","Tıka basa dolu alışveriş merkezi otoparkında; çünkü tanıkların bulunduğu yoğun ve iyi aydınlatılmış bir yerde kalmak yükü hırsızlığa karşı daha güvende tutar","Süre dolduğunda nerede olursanız orada; sürüş süresinden kaybetmemek için doğrudan yolun gidiş kısmının kenarına park ederek"],"explanation":"Plakartlı yuk taşırken, bir sorun çıkması halinde maruziyeti en aza indirmek için daima insanlardan uzak guvenli bir yerde durmayı planlayın."},"298":{"q":"H onayımı yeni aldım ve ilk plakartlı seferimden önce tüm tehlikeli madde kurallarının neden var olduğunu gözden geçiriyorum. Deneyimli bir sürücü kuralların üç temel amaca dayandığını söylüyor: ürünü içermek, riski bildirmek ve bir amaç daha. Aşağıdaki amaçlardan biri HARİÇ, hepsi tehlikeli madde kurallarının gerçek amacını yansıtır. Üçüncü amacı yanlış ifade ettiği için hangi seçenek bunlara DAHİL DEĞİLDİR?","options":["Bir sızıntının önlenmesi veya sınırlandırılması için maddeyi içermek","Yükü daha hızlı taşımak ve taşıyıcının teslimat maliyetlerini azaltmak","Tehlikeyi plakartlar, etiketler ve sevkiyat belgeleriyle bildirmek","Ürünün varış noktasına güvenli ve zarar görmeden ulaşmasını sağlamak"],"explanation":"Tehlikeli madde kurallarının amaçları urunu içermek, riski bildirmek ve guvenli taşımayı sağlamaktır; teslimatı hızlandırmak veya maliyeti dusurmek değildir."},"299":{"q":"Aşındırıcı (korozif) madde yükü alan yeni bir tehlikeli madde sürücüsüyüm. Variller mühürlü görünüyor ama sevkiyat belgelerinin ben gelmeden doldurulduğunu ve ürünün nasıl sınıflandırılıp paketlendiği konusunda hiçbir söz hakkım olmadığını fark ediyorum. Kimin hangi görevden sorumlu olduğunu çözerken, aşağıdakilerden hangisi sürücü olarak benim değil, GÖNDERİCİNİN sorumluluğudur?","options":["Demiryolu geçidinden 15 ila 50 fit önce durmak ve geçiş sırasında vites değiştirmemek","Römorkun dört tarafına da plakart yerleştirmek ve sürüş sırasında belgeleri erişebileceğim mesafede tutmak","Maddenin doğru sevkiyat adını belirlemek ve uygun ambalajı seçmek","Bir varil sızdırıyorsa sevkiyatı reddetmek ve taşımadan önce yükü incelemek"],"explanation":"Yukleyici, malzemeyi sınıflandırır, doğru sevkiyat adını belirler ve yuk surucuye ulaşmadan once doğru ambalajı seçer."}},"es":{"0":{"q":"Acabo de obtener mi endoso H y un conductor nuevo me pregunta por qué existen todas estas reglas de placas (placards), documentos de embarque y empaque. De las siguientes, ¿cuál describe MEJOR el propósito principal de las normas sobre materiales peligrosos?","options":["Contener el material para que no pueda escaparse y comunicar el peligro para que los demás puedan mantenerse alejados y responder con seguridad","Garantizar plazos de entrega más rápidos al dar a las cargas con placas acceso prioritario a los carriles y rutas de la carretera","Documentar cada envío para que el transportista pueda cobrar al cliente el recargo correcto por manejo de materiales peligrosos","Reducir los costos de combustible del transportista al dirigir las cargas peligrosas pesadas por las rutas más cortas disponibles"],"explanation":"Las normas de materiales peligrosos existen para contener el material para que no se escape y comunicar el peligro para que los demás se mantengan alejados y respondan con seguridad."},"1":{"q":"Acaban de contratarme para una ruta transportando una carga de material corrosivo que requiere rótulos (placards), y ya tengo una CDL Clase A con endoso de cisterna (tanque). Antes de poder hacer este viaje legalmente, ¿cuál de las siguientes opciones debo cumplir?","options":["Nada adicional: mi CDL Clase A con endoso de cisterna ya cubre cualquier carga con rótulos que transporte","Obtener el endoso de materiales peligrosos (H), que exige aprobar una evaluación de amenaza de seguridad de la TSA y la toma de huellas dactilares","Agregar el endoso de remolques dobles/triples, ya que las cargas con rótulos deben repartirse entre varios remolques","Agregar el endoso de pasajeros, porque las cargas con rótulos se regulan igual que el transporte de pasajeros"],"explanation":"Transportar cualquier cantidad de materiales peligrosos que requiera rótulos exige el endoso de materiales peligrosos (H), que requiere una evaluación de amenaza de seguridad de la TSA y toma de huellas dactilares."},"2":{"q":"Ya tengo una licencia CDL Clase A de Texas y un certificado médico DOT vigente. Mi nuevo empleador quiere que empiece a transportar cargas de corrosivos que requieren rótulos (placards), así que necesito agregar el endoso H. Cuando le pregunto al empleado del DPS qué paso adicional exige este endoso que mi licencia actual NO exigía, ¿qué es lo MÁS probable que me responda?","options":["No se necesita nada adicional; una vez que tiene una licencia CDL Clase A con una tarjeta médica DOT vigente, el endoso H simplemente se imprime en su licencia sin ningún requisito adicional","Debe aprobar un segundo examen físico DOT más detallado y presentar un certificado del examinador médico actualizado antes de que se pueda emitir el endoso","Debe aprobar una evaluación de amenazas a la seguridad de la TSA, que incluye una verificación de antecedentes y toma de huellas dactilares, antes de que se pueda emitir el endoso","Solo necesita volver a aprobar el examen estándar de visión del CDL para confirmar que aún puede leer los rótulos a distancia"],"explanation":"El endoso de materiales peligrosos requiere aprobar una evaluación de amenaza de seguridad de la TSA, incluida una verificación de antecedentes y toma de huellas dactilares, antes de emitirse."},"3":{"q":"Me contratan para transportar una carga de material corrosivo y estoy revisando la documentación en el muelle antes de partir. Noto que la clase de peligro, el nombre de embarque apropiado y el número de identificación ONU ya figuran en los documentos de embarque, pero quiero asegurarme de que la parte correcta se haya encargado de ello. Según las normas de materiales peligrosos, ¿de quién era la tarea de identificar el material como peligroso y preparar esos documentos de embarque en primer lugar?","options":["El transportista, ya que el transportista es responsable del viaje, de transportar la carga y de reportar cualquier incidente","El conductor, ya que yo soy quien debe mantener los documentos al alcance y rechazar la carga si algo parece estar mal","El receptor, ya que la empresa que acepta la entrega confirma el contenido y firma por el material peligroso","El expedidor, ya que el expedidor clasifica, nombra, embala y etiqueta el material y prepara los documentos de embarque"],"explanation":"El expedidor clasifica, nombra, empaca y etiqueta el material peligroso y prepara los documentos de embarque antes de que la carga llegue al conductor."},"4":{"q":"Estoy transportando una carga con carteles (placards) de materiales corrosivos por Texas y acabo de incorporarme a la autopista. Para cumplir con las reglas de los documentos de embarque de materiales peligrosos mientras conduzco, ¿dónde deben estar esos documentos en este momento?","options":["A mi alcance con el cinturón de seguridad puesto, o en una bolsa en la puerta del conductor, y encima de mis demás documentos","Asegurados en la litera para que el viento de una ventana abierta no los disperse","Archivados en la caja de documentos montada en el exterior del remolque, cerca de los carteles","Metidos debajo de la carga en el remolque para que permanezcan junto a la mercancía"],"explanation":"Mientras el vehículo está en movimiento, los documentos de embarque de materiales peligrosos deben estar al alcance del conductor con el cinturón puesto, o en la bolsa de la puerta, y encima de los demás papeles."},"5":{"q":"Soy un conductor nuevo y estoy cargando un remolque de carga mixta que incluye un artículo de materiales peligrosos (HazMat) junto con varias mercancías no reguladas. Cuando reviso el documento de embarque combinado antes de salir del muelle, ¿cómo debe identificarse el material peligroso en ese documento para que la documentación sea legal?","options":["Anotado de último en la página para que quede separado de las líneas de carga común","Anotado primero, o resaltado, o marcado con una 'X' en la columna HM","Escrito únicamente en una página trasera aparte engrapada detrás de la lista de carga","Dejado en letra normal ya que los carteles del remolque ya señalan el peligro"],"explanation":"En un documento de embarque mixto, la anotación de materiales peligrosos debe distinguirse anotándola primero, resaltándola o marcándola con una 'X' en la columna HM."},"6":{"q":"Transporto una carga de corrosivos de la Tabla 2 y acabo de fijar los cuatro rótulos (placards) en forma de rombo en todos los lados de mi remolque antes de salir de la terminal. Un conductor nuevo me pregunta por qué esos rombos importan tanto como para que yo me niegue a salir sin ellos. ¿Qué explicación indica correctamente el propósito principal de esos rótulos?","options":["Certifican que el expedidor clasificó y embaló correctamente la carga, así que no tengo que inspeccionar el envío yo mismo","Demuestran que poseo un endoso H válido y que aprobé la verificación de antecedentes de la TSA exigida para transportar esta carga","Advierten a todos los que rodean el vehículo sobre el peligro que representa la carga, para que los socorristas y el público reaccionen con seguridad","Registran el peso bruto total del material regulado, para que los inspectores de la báscula confirmen que estoy por debajo de 1,001 lb"],"explanation":"Los rótulos advierten a todos los que rodean el vehículo del peligro que presenta la carga para que los socorristas y el público puedan reaccionar con seguridad."},"7":{"q":"Estoy transportando una carga de corrosivos con carteles de riesgo (placards), y el supervisor del patio me dice que un compañero ya colocó los carteles requeridos en ambos lados del remolque y en la parte trasera. Antes de salir por el portón, ¿qué afirmación me indica correctamente lo que todavía debo hacer para cumplir con la colocación de carteles?","options":["No se necesita nada más; con ambos lados y la parte trasera cubiertos, tres carteles cumplen la regla de carteles para una carga corrosiva.","Colocar un cartel en el techo del remolque para que se vea desde arriba, pero el frente no es necesario porque la cabina bloquea la vista.","Mover el cartel trasero al parachoques delantero, porque el frente y los dos lados son las únicas posiciones que un oficial realmente inspecciona.","Colocar también un cartel en el frente del vehículo, de modo que la carga lleve carteles en el frente, la parte trasera y ambos lados."],"explanation":"Los rótulos deben colocarse en los cuatro lados del vehículo —frente, parte trasera y ambos lados— cada uno legible desde la dirección hacia la que apunta."},"8":{"q":"Estoy transportando una carga rotulada de corrosivos cuando uno de mis tambores empieza a fugar sobre el arcén. He advertido a los presentes y llamado a los socorristas, pero el despachador me dice que les lea a los bomberos el número de referencia del documento que indica cómo manejar el derrame exacto de este material. ¿Qué elemento de mi cabina debo usar?","options":["La Guía de Respuesta a Emergencias (ERG), que permite a los socorristas asociar el material con su peligro y las acciones de protección","Los documentos de embarque, ya que el nombre de embarque correcto y el número UN/NA ya figuran allí para la carga","El manual del propietario del vehículo, que cubre los sistemas del camión y los procedimientos de emergencia del fabricante","El conocimiento de embarque, ya que documenta la carga y los datos de contacto del transportista para reportar incidentes"],"explanation":"Todo conductor de materiales peligrosos debe llevar la Guía de Respuesta a Emergencias (ERG), que permite a los socorristas identificar el material con su peligro y las acciones de protección."},"9":{"q":"Estoy a punto de salir de la terminal transportando una carga con placas (placards) de líquido inflamable Clase 3. Mi despachador me presiona para arrancar porque voy atrasado. Para hacer mi trabajo de forma segura y legal antes de salir, ¿cuál de estas opciones debo hacer?","options":["Quitar las placas del remolque para no llamar la atención de otros conductores en la autopista","Inspeccionar cuidadosamente el vehículo, las llantas y el aseguramiento de la carga antes de iniciar el viaje","Saltarme la inspección previa al viaje solo esta vez para recuperar el tiempo que perdí esperando en el muelle","Desconectar los frenos del remolque para que la unidad ruede más fácil y gaste menos combustible en el trayecto"],"explanation":"Transportar materiales peligrosos exige inspeccionar cuidadosamente el vehículo, los neumáticos y la sujeción de la carga antes de iniciar el viaje, sin que la presión del horario justifique omitirlo."},"11":{"q":"Durante una revisión obligatoria de neumáticos en ruta con mi carga de materiales peligrosos con carteles, descubro que un neumático del remolque está peligrosamente sobrecalentado. Según las normas de materiales peligrosos de Texas, ¿qué debo hacer antes de continuar?","options":["Echar agua sobre el neumático para enfriarlo y seguir conduciendo hasta el próximo taller para que lo revisen","Agregar aire para restaurar la presión correcta y conducir con cuidado hasta que el neumático se enfríe solo","Retirar el neumático sobrecalentado y colocarlo a una distancia segura del vehículo, y no conducir hasta que esté reparado","Reducir la velocidad y seguir conduciendo para que el flujo de aire enfríe el neumático antes de la próxima revisión obligatoria"],"explanation":"Un neumático sobrecalentado en una carga con carteles es un riesgo de incendio y explosión, así que retírelo, colóquelo a distancia segura del vehículo y no conduzca hasta repararlo."},"12":{"q":"Llevo un cargamento de oxidantes con rótulos (placards) y entré a un área de descanso para mi pausa. Un compañero de otro camión quiere acercarse a fumar conmigo. Para no infringir la ley, ¿a qué distancia de mi remolque debemos mantenernos los dos mientras fumamos?","options":["Al menos 5 pies, el mismo margen exigido al estacionar fuera de la parte transitada de la vía","Al menos 10 pies, lo bastante lejos para que ninguna llama alcance el remolque","Al menos 100 pies, el mismo margen usado para explosivos cerca de un edificio","Al menos 25 pies del vehículo, ya que transporta oxidantes"],"explanation":"Fumar o cualquier llama abierta debe mantenerse al menos a 25 pies de un vehículo con carteles que transporte explosivos, oxidantes o inflamables."},"13":{"q":"Me he acercado a un muelle de carga para cargar explosivos de la División 1.2 en mi remolque. La cuadrilla del muelle espera a que prepare el camión antes de empezar a subir las cajas. Antes de que se cargue cualquier explosivo, ¿qué debo hacer con mi vehículo?","options":["Apagar el motor y poner el freno de estacionamiento para asegurar el vehículo antes de comenzar la carga","Dejar el motor en ralentí para que los frenos de aire sigan cargados y el climatizador de la cabina funcione durante la carga","Dejar el motor encendido pero aplicar el freno de estacionamiento, ya que el motor en sí no es una verdadera fuente de ignición","Bajar todas las ventanillas y tocar la bocina dos veces para avisar a la cuadrilla del muelle de que empieza la carga"],"explanation":"Antes de cargar o descargar explosivos, apague el motor para eliminar la fuente de ignición y ponga el freno de estacionamiento para asegurar el vehículo."},"14":{"q":"Estoy recogiendo una carga de gasolina en tambores en una terminal de combustible, y mi despachador me pide que confirme la clase de peligro en los documentos de embarque antes de colocar los carteles. Según cómo se definen las clases de peligro, ¿qué número de clase de peligro debe aparecer junto a esta carga de gasolina?","options":["Clase 1, porque los líquidos inflamables conllevan el mayor peligro de explosión y se agrupan con los explosivos","Clase 3, porque la gasolina es un líquido inflamable y eso es exactamente lo que abarca esta clase","Clase 8, porque la gasolina puede quemar la piel y dañar materiales al contacto como un corrosivo","Clase 2, porque la gasolina desprende vapores inflamables y se maneja como un gas inflamable"],"explanation":"La gasolina es un líquido inflamable, que es exactamente lo que abarca la Clase de Peligro 3."},"15":{"q":"Estoy en el muelle cargando un envío, y el documento de embarque indica el nombre de embarque apropiado, la clase de peligro y el número UN para una carga de explosivos. Antes de colocar los carteles en mi remolque y salir, necesito confirmar el número de clase de peligro que identifica esta carga como explosivos. ¿Cuál clase de peligro es correcta?","options":["Clase 8, que cubre corrosivos como el ácido de batería","Clase 3, que cubre líquidos inflamables como la gasolina","Clase 1, que cubre explosivos como la dinamita","Clase 7, que cubre materiales radiactivos como el uranio"],"explanation":"Los explosivos como la dinamita son de la Clase de Peligro 1, la primera de las nueve clases de peligro."},"16":{"q":"Estoy recogiendo dos cargas de materiales peligrosos en la terminal. La primera es un tambor pequeño de un corrosivo de la Tabla 2 que pesa solo 300 lb; la segunda es un único cilindro de gas venenoso (Clase 2.3). Mi despachador me dice que \"necesitaré rótulos para la cantidad rotulable\". ¿Qué me indica realmente esa frase sobre cuándo se exigen los rótulos?","options":["Todo vehículo que transporte materiales peligrosos siempre debe mostrar rótulos, así que tanto el corrosivo de 300 lb como el gas venenoso los requieren sin importar el peso o la clase","Los rótulos solo son legalmente obligatorios cuando el vehículo circula por una vía pública de noche o con visibilidad reducida","No se necesitan rótulos para ninguna carga porque ambos envíos están por debajo del umbral total de 1,001 lb para el viaje","Los rótulos solo se exigen para ciertas cantidades o clases — el gas venenoso los necesita en cualquier cantidad, mientras que el corrosivo solo a partir de 1,001 lb"],"explanation":"Los materiales de la Tabla 1, como el gas venenoso, requieren carteles en cualquier cantidad, mientras que los de la Tabla 2, como los corrosivos, los requieren solo a partir de 1,001 libras."},"17":{"q":"Estoy recogiendo una carga de corrosivos con rótulos (placards). El expedidor me entrega los documentos de embarque y me dice que todo ha sido clasificado, empacado y etiquetado correctamente. Antes de transportar esta carga, ¿qué me indica que el expedidor ha certificado formalmente que el envío está correctamente descrito, empacado, marcado y etiquetado?","options":["La declaración de certificación firmada por el expedidor que aparece en el propio documento de embarque","Una garantía verbal que el expedidor me da en el muelle de carga","La presencia de los rótulos de clase de riesgo correctos ya colocados en los cuatro lados","Mi propia inspección de los sellos y etiquetas que confirma que nada tiene fugas"],"explanation":"El expedidor certifica que un envío de materiales peligrosos está correctamente nombrado, embalado, marcado y etiquetado al firmar una declaración de certificación en el documento de embarque."},"19":{"q":"Mi camión cisterna con rótulos de peligro y carga corrosiva vuelca en una carretera rural y el producto de Clase 8 se está derramando sobre el arcén. Después de alejar a la gente, detener el tabaco y tomar la Guía de Respuesta a Emergencias (ERG), mi empresa necesita reportar el incidente grave por teléfono. ¿Cuál contacto existe específicamente para recibir el reporte de un incidente grave con materiales peligrosos?","options":["CHEMTREC, al que llamo primero porque es la única agencia autorizada para tomar un reporte oficial del incidente","El Centro Nacional de Respuesta (National Response Center), la línea directa federal que existe para recibir reportes de incidentes graves con materiales peligrosos","El expedidor que figura en mis documentos, porque la empresa que empacó la carga debe presentar el reporte","La línea directa del fabricante del vehículo, para que la volcadura y la falla del tanque queden documentadas formalmente"],"explanation":"Los incidentes graves con materiales peligrosos deben reportarse al Centro Nacional de Respuesta, la línea directa federal 1-800-424-8802."},"20":{"q":"Son las 2:30 de la madrugada de un domingo y uno de mis tambores con carteles (placards) ha comenzado a derramar material corrosivo en un área de descanso. Ya advertí a los presentes, mantuve a la gente alejada y evité que fumaran. Ahora quiero llamar a CHEMTREC (1-800-424-9300) para obtener orientación de emergencia sobre el manejo de químicos, pero me preocupa que nadie conteste a esta hora en un fin de semana. ¿Cuál afirmación es correcta?","options":["CHEMTREC solo contesta llamadas durante el horario laboral normal, así que debo esperar hasta el lunes por la mañana para obtener orientación.","CHEMTREC solo atiende entre semana, así que como es domingo debería llamar mejor a la oficina de mi transportista (carrier).","CHEMTREC atiende las 24 horas del día, todos los días, así que puedo llamar ahora mismo y comunicarme con un experto en emergencias.","A CHEMTREC solo se le puede contactar durante las horas nocturnas, así que llamar a las 2:30 de la madrugada es la única franja que funciona."],"explanation":"CHEMTREC (1-800-424-9300) está atendido las 24 horas del día, todos los días, para brindar información de respuesta a emergencias."},"21":{"q":"Transporto una carga rotulada de corrosivos (no explosivos) y necesito orillarme para hacer una llamada y revisar mi documentación. No hay área de descanso cerca, así que estoy considerando el acotamiento de una carretera de dos carriles. Para cumplir con las reglas de estacionamiento de materiales peligrosos, ¿qué debo hacer?","options":["Estacionarme lo más cerca posible del borde del carril transitado para dejar el mayor espacio en el acotamiento para el resto del tránsito","Estacionarme a menos de 300 pies de la carretera pero dejar la carga desatendida solo por unos minutos","Subir el vehículo al pavimento del acotamiento y detenerme justo junto a la línea blanca del borde del carril","Mantener el vehículo a por lo menos 5 pies de la parte transitada de la carretera antes de detenerme y estacionarme"],"explanation":"Un vehículo con carteles nunca debe estacionarse a menos de 5 pies de la parte transitada de la carretera."},"22":{"q":"Transporto explosivos de la División 1.2 y me detengo para una inspección obligatoria de los neumáticos. Más adelante veo un vehículo en llamas en el arcén, con una multitud de personas reunidas cerca observando. Para estacionar de forma legal y segura con esta carga, ¿cuál es la distancia mínima que debo mantener entre mi camión y esa multitud reunida en el lugar?","options":["Al menos 300 pies de la multitud de personas","Al menos 25 pies de la multitud de personas","Al menos 50 pies de la multitud de personas","Al menos 5 pies de la multitud de personas"],"explanation":"Las cargas de explosivos (División 1.1, 1.2, 1.3) nunca deben estacionarse a menos de 300 pies de un lugar donde se reúna gente."},"23":{"q":"Transporto una carga con placas (placards) de explosivos de la División 1.2 y necesito alejarme de mi camión unos minutos en un área de descanso. Las regulaciones dicen que esta carga nunca debe dejarse sin vigilancia. Para que mi vehículo cuente legalmente como 'vigilado', ¿cuál de las siguientes condiciones debe cumplir la persona que lo vigila?","options":["Puede descansar en el compartimento para dormir siempre que pueda oír el camión y responder si algo ocurre","Está despierta, a no más de 100 pies del vehículo, lo tiene a la vista despejada y es capaz de moverlo rápidamente si es necesario","Pasa e inspecciona el vehículo al menos una vez cada dos horas, el mismo intervalo que se usa para revisar los neumáticos","Permanece en cualquier punto del área de descanso y sigue localizable por teléfono celular en caso de emergencia"],"explanation":"Una carga de explosivos está vigilada solo si la persona está despierta, a menos de 100 pies, la ve con claridad y puede moverla rápidamente."},"24":{"q":"Soy un conductor con CDL transportando una carga de corrosivos con carteles (placards). En el muelle, un empleado me entrega una tablilla y enumera lo que incluye \"mi trabajo\" antes de que arranque. Para mantenerme dentro de mis verdaderas responsabilidades legales como conductor, debo identificar la única tarea de esta lista que NO es responsabilidad del conductor, sino que le corresponde a otra parte de la cadena. ¿Cuál de estas es esa tarea?","options":["Rechazar un paquete que encuentro con fugas o marcado incorrectamente","Colocar los carteles (placards) requeridos en los cuatro lados antes de conducir","Producir y formular químicamente el material peligroso que se transporta","Mantener los documentos de embarque a mi alcance mientras conduzco"],"explanation":"Las funciones del conductor son inspeccionar, rechazar envíos defectuosos, colocar carteles, tener a mano los documentos de embarque y conducir con seguridad, nunca producir el material."},"25":{"q":"Hace un frío bajo cero y estoy cargando un remolque para un viaje largo. Mi camión tiene un calentador del compartimiento de carga que funciona, y me gustaría encenderlo para proteger la carga del frío. De los cuatro envíos que esperan en el muelle, ¿para cuál debería mantener APAGADO el calentador de carga?","options":["Una tarima de sopa enlatada y agua embotellada que podrían congelarse y reventar con el frío","Muebles del hogar y material de embalaje en cajas que retienen humedad con el frío","Productos frescos refrigerados que el receptor quiere evitar que se congelen durante el transporte","Bidones de un líquido inflamable de Clase 3 cargados junto con cajas de explosivos"],"explanation":"Los calentadores de carga deben permanecer apagados al transportar explosivos o líquidos inflamables, porque la llama o el calor pueden encender vapores o detonar los explosivos."},"26":{"q":"Han pasado tres semanas desde que entregué una carga de corrosivos con carteles (placards) y el viaje terminó hace mucho. Mi despachador me dice que la empresa todavía conserva en un archivo los documentos de embarque (shipping papers) de ese envío peligroso. ¿Cuál de las siguientes es la MEJOR razón por la que el transportista guarda esos documentos completados después de finalizar el viaje?","options":["Los reguladores federales y estatales pueden exigir los registros para inspección, por lo que el transportista debe conservarlos durante el período requerido","El conductor que llevó la carga debe guardar personalmente esos documentos originales durante el resto de su carrera","Una vez confirmada la entrega y descargada la carga, los documentos ya no sirven para nada y pueden desecharse","Los documentos solo deben conservarse mientras el material está en tránsito y deben llegar a la bolsa de la puerta del conductor"],"explanation":"El transportista debe conservar los documentos de embarque completados durante el período requerido, porque los reguladores federales y estatales pueden exigirlos para inspección."},"27":{"q":"Estoy preparando los documentos de embarque de una carga y abro la Tabla de Materiales Peligrosos del reglamento para sacar los detalles de la entrada de mi producto. Al leer la fila de mi material, cada columna que veo proviene directamente de esa Tabla, EXCEPTO un dato que tendría que conseguir en otra fuente distinta de la Tabla. ¿Cuál de los siguientes NO encontraría al leer la Tabla de Materiales Peligrosos?","options":["El nombre de embarque apropiado que debo usar para describir el material en mis documentos de embarque","Mi domicilio particular como conductor, que nunca aparece en ninguna parte de la Tabla","La clase o división de peligro asignada al material que transporto","El número de identificación (UN/NA) que debe figurar junto con la entrada"],"explanation":"La Tabla de Materiales Peligrosos describe el material en sí —nombre de embarque, clase de peligro, número de identificación, grupo de embalaje y etiquetas—, nunca la información personal del conductor."},"28":{"q":"Estoy recogiendo una carga de líquido inflamable de Clase 3 en el muelle de un expedidor. Los documentos de embarque identifican correctamente el material e indican que requiere rótulos (placards), pero el expedidor me entrega el camión sin ningún rótulo colocado y dice que están \"agotados\". Antes de salir a la carretera, ¿qué debo hacer?","options":["Conducir hasta mi primera parada programada y pedir al destinatario que suministre los rótulos faltantes, ya que la carga ya está cargada y los documentos son correctos","Continuar sin rótulos pero mantener los documentos de embarque encima y a mi alcance, porque la documentación correcta sustituye legalmente a los rótulos faltantes","Obtener los rótulos correctos y colocarlos en los cuatro lados del vehículo antes de salir a la carretera","Rechazar el envío por completo y dejarlo en el muelle, ya que la falta de un rótulo hace ilegal aceptar la carga"],"explanation":"Si el expedidor no proporciona carteles, el conductor debe obtener los correctos y colocarlos en los cuatro lados antes de sacar el vehículo a la carretera."},"29":{"q":"Estoy cargando material corrosivo en cajas en mi remolque, y el expedidor ha aplicado una marca a cada paquete individual. En el muelle, otro conductor me dice que estas marcas en los paquetes son exactamente lo mismo que los rótulos (placards) que colgaré en los cuatro lados de mi vehículo. Para inspeccionar la carga correctamente, ¿en qué afirmación debo confiar?","options":["Las marcas de los paquetes son rótulos de tamaño completo, y las normas federales me permiten trasladarlas a los lados del vehículo para cumplir con el requisito de rotulado en los cuatro lados","Las marcas de los paquetes son notas opcionales del expedidor, así que los rótulos del vehículo son las únicas marcas en forma de diamante con valor legal","La comunicación de peligros en EE. UU. se hace solo con rótulos, así que cualquier diamante en las cajas es meramente decorativo y puede ignorarse","Los diamantes en cada paquete son etiquetas de peligro que aplica el expedidor, y son distintas de los rótulos más grandes que se colocan en el vehículo"],"explanation":"Las etiquetas son los rombos pequeños que el expedidor coloca en cada paquete, mientras que los carteles son los rombos más grandes que van en los cuatro lados del vehículo."},"30":{"q":"Estoy armando una carga que incluye un tanque refrigerado de amoníaco anhidro y un cilindro de oxígeno comprimido. En los documentos de embarque ambas entradas están marcadas como Clase de Peligro 2. Al verificar la documentación contra lo que realmente estoy cargando, ¿en qué estado físico debo esperar que esté cada material de la Clase 2?","options":["Un gas (la clase abarca gases inflamables, no inflamables y venenosos)","Un líquido inflamable que desprende vapores a baja temperatura","Un sólido que se vuelve peligroso solo cuando se moja","Un corrosivo que puede estar en forma líquida o sólida"],"explanation":"La Clase de Peligro 2 es la clase de gases, que abarca gases inflamables, no inflamables y venenosos."},"31":{"q":"Soy un conductor nuevo de materiales peligrosos y estoy cargando un producto de limpieza corrosivo. La etiqueta de los tambores muestra la marca comercial del fabricante en letras grandes, el remitente me entregó los documentos y el despachador insiste en llamar la carga por su nombre de catálogo. Cuando verifico que el nombre de embarque apropiado en mis documentos de embarque es correcto, ¿con qué nombre debe coincidir?","options":["La marca comercial impresa en letras grandes en las etiquetas de los tambores, ya que eso identifica el producto real","El nombre de embarque apropiado que figura en la Tabla de Materiales Peligrosos para ese material, no un nombre comercial o de marca","El nombre de catálogo del producto que usa el despachador, porque así es como la empresa rastrea la carga","Cualquier nombre común del producto, siempre que la clase de riesgo y el número de identificación en los documentos sean correctos"],"explanation":"Los documentos de embarque deben indicar el nombre de embarque correcto tal como aparece en la Tabla de Materiales Peligrosos, no un nombre comercial o de marca."},"32":{"q":"Estoy haciendo una inspección previa al viaje en mi camión cisterna con carteles de peligro antes de transportar una carga de líquidos inflamables. Subo a la zona de la cabina y reviso el extintor montado junto a la puerta. ¿Qué condición significa que el extintor es aceptable y que puedo circular legalmente?","options":["El extintor está montado y sellado, así que no necesito revisar el manómetro ni su clasificación antes de salir","El extintor es del tamaño al que estoy acostumbrado, aunque la aguja del manómetro está en la zona roja","El extintor está completamente cargado y tiene una clasificación lo bastante alta para el peligro que transporto","El extintor está presente en la cabina, ya que llevar cualquier extintor que funcione cumple con el requisito"],"explanation":"Un vehículo con carteles de peligro debe llevar un extintor totalmente cargado y con una clasificación suficiente para el peligro transportado."},"33":{"q":"Transporto una carga de líquido inflamable con rótulos (placards) y me detengo en una isla de combustible para llenar el tanque. Mi copiloto se ofrece a ayudar para terminar más rápido. Para cargar combustible de forma correcta y segura, ¿cuál de las siguientes acciones DEBE ocurrir?","options":["Puedo dejar la boquilla trabada en posición abierta y alejarme para limpiar el parabrisas, siempre que el motor siga encendido para alimentar las luces","Debo dejar el motor al ralentí para que la bomba de combustible cargue presión más rápido, y apartarme unos 25 pies mientras se llena","Puedo empezar a cargar combustible y entrar a pagar, ya que el corte automático del surtidor detendrá el flujo cuando el tanque esté lleno","Debo apagar el motor, y uno de nosotros tiene que permanecer en la boquilla controlando el flujo de combustible durante todo el proceso"],"explanation":"Al cargar combustible en un vehículo con carteles de peligro, el motor debe estar apagado y alguien debe permanecer en la boquilla controlando el flujo todo el tiempo."},"34":{"q":"Transporto una carga con cartel de explosivos de la División 1.1 y mi GPS me ofrece la ruta más rápida, que atraviesa directamente un distrito comercial del centro y un gran túnel sobre el río por la tarde. Según las normas obligatorias de rutas para materiales peligrosos, ¿qué debo hacer?","options":["Planificar una ruta que evite las zonas pobladas y los túneles donde así se exija, aunque sume kilómetros","Tomar la ruta del GPS, ya que el túnel me aleja de las calles congestionadas y ahorra tiempo","Usar la ruta del centro, pero solo si en las paradas me estaciono al menos a 5 pies de la parte transitada de la vía","Seguir la ruta más rápida mientras cruce las vías del tren sin cambiar de marcha"],"explanation":"Un conductor que transporta explosivos con carteles de peligro debe seguir la ruta designada para materiales peligrosos, evitando túneles y zonas pobladas aunque sume kilómetros."},"35":{"q":"Estoy cargando mi remolque para un viaje con materiales peligrosos con placas, y mis documentos de embarque indican dos materiales que la tabla de segregación muestra que pueden reaccionar peligrosamente si entran en contacto. El personal del muelle tiene prisa y quiere que arranque cuanto antes. ¿Qué acción me mantiene legal y seguro?","options":["Sujetar los dos materiales incompatibles en la misma tarima para que viajen bien apretados y no se desplacen durante el trayecto","Mantener los dos materiales cargados por separado como exigen las reglas de segregación, para que los materiales reactivos queden apartados","Combinar los dos materiales en una sola caja sellada para que un derrame no se extienda al resto de la carga","Cargar ambos materiales con normalidad y omitir la verificación de segregación ya que hago una ruta corta y directa"],"explanation":"Los materiales incompatibles indicados en la tabla de segregación deben cargarse y mantenerse separados para que no reaccionen si entran en contacto."},"36":{"q":"Estoy cargando tambores de ácido de batería para transportarlos. Los documentos de embarque indican la carga con un número de clase de riesgo, y antes de colocar los carteles quiero confirmar que he asignado la clase de riesgo correcta a este material corrosivo. ¿Qué número de clase de riesgo corresponde a los carteles para un corrosivo como el ácido?","options":["Clase 3, porque los líquidos inflamables en tambores y los ácidos se agrupan juntos","Clase 5, porque los ácidos reaccionan fuertemente y se comportan como oxidantes","Clase 8, porque los corrosivos como los ácidos pertenecen a esa clase de riesgo","Clase 1, porque los tambores de ácido presurizados se tratan como explosivos"],"explanation":"Los corrosivos como los ácidos pertenecen a la Clase de Peligro 8."},"37":{"q":"En el muelle de un expedidor me entregan los documentos de embarque de una carga, y la entrada indica una clase de peligro 7 junto al nombre de embarque correcto y un número de identificación de la ONU. Antes de colocar los rótulos en mi remolque y salir, ¿qué tipo de material me indica realmente esa designación de clase 7 que estoy transportando?","options":["Líquidos inflamables, como los de las cargas de combustible y disolventes","Gases comprimidos y licuados a presión dentro de los cilindros","Sustancias corrosivas como ácidos fuertes y líquidos cáusticos","Materiales radiactivos que emiten radiación ionizante durante el transporte"],"explanation":"La Clase de Peligro 7 corresponde a materiales radiactivos, que emiten radiación ionizante durante el transporte."},"38":{"q":"En el muelle de carga, un expedidor me entrega documentos que describen un material clasificado como 'Clase de Peligro 6'. Antes de colocar los rótulos y salir, quiero estar seguro de qué tipo de peligro estoy transportando. ¿Qué me indica una designación de Clase 6 sobre esta carga?","options":["Es un material venenoso (tóxico), por lo que debo protegerme contra la exposición y los peligros de inhalación","Es un oxidante que puede intensificar un incendio, por lo que debo mantenerlo lejos de materiales inflamables","Es un material corrosivo que puede quemar la piel y el metal, por lo que debo revisar si hay fugas","Es un gas comprimido no inflamable, por lo que debo protegerme contra la liberación de presión"],"explanation":"La Clase de Peligro 6 abarca materiales venenosos (tóxicos), por lo que hay que protegerse contra la exposición y la inhalación."},"39":{"q":"Estoy preparando un cargamento y el nombre de embarque correcto en mis documentos va seguido del número de clase de peligro \"5.1\", con un número de identificación en formato ONU. El expedidor me entrega un rótulo (placard) para colocar en los cuatro lados. ¿Qué rótulo corresponde correctamente a un material de Clase de Peligro 5?","options":["Un rótulo CORROSIVE (corrosivo), porque la Clase 5 abarca ácidos y líquido de batería que corroen el metal","Un rótulo OXIDIZER (oxidante), porque la Clase 5 abarca oxidantes y peróxidos orgánicos","Un rótulo EXPLOSIVES (explosivos), porque la Clase 5 abarca agentes explosivos y detonadores","Un rótulo RADIOACTIVE (radiactivo), porque la Clase 5 abarca materiales que emiten radiación"],"explanation":"La Clase de Peligro 5 abarca oxidantes y peróxidos orgánicos, por lo que una carga clase 5.1 requiere un cartel de OXIDANTE."},"40":{"q":"Estoy cargando un solo remolque con varios paquetes no a granel que pertenecen a dos clases de peligro diferentes, y preferiría colgar un único cartel 'DANGEROUS' (PELIGROSO) en los cuatro lados en lugar de un cartel separado para cada clase. Según las reglas de materiales peligrosos del DPS, ¿cuándo se permite realmente usar el cartel 'DANGEROUS'?","options":["Solo cuando cada paquete de la carga pertenece a una sola clase de peligro","Solo cuando el envío consiste exclusivamente en productos alimenticios en cajas o paletizados","Cuando la carga contiene dos o más clases de peligro que las reglas permiten compartir un mismo cartel","En prácticamente cualquier situación, como un cómodo reemplazo comodín de los carteles específicos de cada clase"],"explanation":"Un solo cartel DANGEROUS puede reemplazar los carteles individuales cuando una carga lleva dos o más clases de peligro que las normas permiten combinar."},"41":{"q":"Estoy transportando un tanque con carteles de materiales peligrosos cuando un policía estatal me detiene, señala el número de cuatro dígitos del cartel y pregunta qué le indica. Según cómo se usa ese número en una emergencia, ¿qué identifica realmente ese número de identificación de cuatro dígitos?","options":["El peso bruto total del tanque cargado para que los rescatistas conozcan el volumen del derrame","La división de la clase de peligro, como 3 para líquidos inflamables, en forma numérica","La ruta de materiales peligrosos designada que el transportista me asignó hacia la terminal","El material peligroso específico transportado, que se busca en la Guía de Respuesta a Emergencias (ERG)"],"explanation":"El número UN/NA de cuatro dígitos identifica el material peligroso específico, que los rescatistas buscan en la Guía de Respuesta a Emergencias (ERG)."},"42":{"q":"Estoy revisando los documentos de embarque de mi carga y noto que cada entrada de material peligroso indica un grupo de embalaje I, II o III. Un conductor nuevo me pregunta qué nos dice realmente ese número romano. Según mi capacitación en materiales peligrosos, ¿qué indica el grupo de embalaje sobre el material?","options":["Cuán grande es el peligro que representa el material, siendo el Grupo I el más peligroso","El número de clase de peligro que identifica el tipo de peligro, como inflamable o corrosivo","El peso mínimo a partir del cual la carga debe llevar carteles en los cuatro lados","El orden en que las entradas deben aparecer en el documento de embarque"],"explanation":"El grupo de embalaje indica el grado de peligro del material, siendo el Grupo I el más peligroso, el II medio y el III el menos."},"43":{"q":"Estoy transportando una carga de corrosivos con placas (rótulos) por Texas cuando un policía estatal en una estación de pesaje me pide que le señale dónde está documentado el número telefónico de respuesta de emergencia de 24 horas para mi envío. ¿Qué lugar debo mostrarle al oficial?","options":["En las placas (rótulos) montadas en los cuatro lados del remolque","En el documento de embarque que mantengo a mi alcance en la cabina","En la tarjeta de mi endoso de Materiales Peligrosos (H)","En la Guía de Respuesta a Emergencias (ERG) guardada en la cabina"],"explanation":"El número de teléfono de respuesta de emergencia las 24 horas figura en el documento de embarque, que debe mantenerse al alcance del conductor en la cabina."},"44":{"q":"Estoy revisando los documentos de embarque de una carga y una entrada aparece con clase de peligro 4. Antes de colocar los rótulos e inspeccionar, quiero confirmar qué tipo de peligro estoy transportando realmente. ¿Cuál de las siguientes describe correctamente los materiales de la Clase de Peligro 4?","options":["Gases inflamables que pueden encenderse si se liberan de un cilindro presurizado","Líquidos inflamables como la gasolina que despiden vapores inflamables","Sólidos inflamables, incluidos los materiales de combustión espontánea y los peligrosos al mojarse","Materiales corrosivos que pueden quemar la piel o corroer los envases de metal"],"explanation":"La Clase de peligro 4 abarca sólidos inflamables, incluidos los materiales de combustión espontánea y los peligrosos al mojarse."},"45":{"q":"Estoy cargando en mi remolque un material de Clase 4.3 marcado como \"Peligroso cuando está mojado\", y se pronostica lluvia para toda la ruta. Antes de cerrar las puertas, ¿qué precaución importa MÁS para este peligro específico?","options":["Evitar que la carga se enfríe demasiado, ya que el enfriamiento es lo que desestabiliza estos sólidos","Asegurarme de que las cajas estén selladas contra el polvo, porque las partículas en el aire activan la reacción","Confirmar que la carga esté recién pintada y sellada para que los vapores no escapen durante el transporte","Mantener el material completamente seco y sellado, porque el contacto con el agua puede hacer que se inflame"],"explanation":"Los materiales peligrosos al mojarse reaccionan con el agua y pueden inflamarse, por lo que deben mantenerse completamente secos y sellados contra la humedad."},"46":{"q":"Estoy cargando varios cilindros de gas comprimido en mi remolque para un viaje con materiales peligrosos. Antes de cerrar las puertas y salir, ¿qué práctica de carga me mantiene en cumplimiento y asegura la carga?","options":["Colocar cada cilindro en posición vertical y sujetarlo para que no pueda volcarse, rodar ni desplazarse durante el transporte","Acostar los cilindros horizontalmente y empacarlos sueltos para que tengan espacio al asentarse en caminos irregulares","Abrir ligeramente la válvula de cada cilindro antes de salir para que la presión interna se iguale en ruta","Apilarlos de lado solo si el piso del remolque está nivelado; de lo contrario, pararlos verticalmente"],"explanation":"Los cilindros de gas comprimido deben colocarse en posición vertical y asegurarse para que no se vuelquen, rueden ni se desplacen durante el transporte."},"47":{"q":"Estoy cargando mi remolque con un envío de Clase 6.1 (veneno/tóxico) y todavía me queda espacio libre en el piso. Para evitar un segundo viaje, quiero completar la carga con otra mercancía que va a la misma terminal. ¿Cuál es la carga que NO debo poner en el mismo vehículo que el veneno?","options":["Una tarima de cajas de cartón selladas con autopartes","Alimento seco para perros en sacos y cereal en cajas para una tienda de comestibles","Una caja de herramientas manuales de mecánico y equipo de amarre","Varios sacos de arena de construcción limpia y seca"],"explanation":"Los materiales venenosos y tóxicos (Clase 6.1) nunca deben cargarse junto con alimentos para personas o animales por el riesgo de contaminación."},"48":{"q":"Durante mi inspección previaje, encuentro en mi carga con carteles (placards) un tambor marcado como Clase 8, y una pequeña cantidad de líquido se ha derramado en el piso cerca de él. Al decidir cómo manejar esta fuga, ¿cuál de los siguientes es el peligro MÁS importante que debo considerar antes de acercarme?","options":["El material bajará rápidamente la temperatura dentro del remolque, así que primero debo ventilar","El material es altamente explosivo al contacto con el aire, así que debo evacuar un radio de 300 pies","El material puede quemar químicamente mi piel y mis ojos al contacto, por lo que debo evitar tocarlo y protegerme","El material es prácticamente inerte en forma líquida, así que puedo limpiarlo con un trapo y continuar mi viaje"],"explanation":"Los corrosivos de la Clase 8 pueden quemar químicamente la piel y los ojos al contacto, por lo que el conductor debe evitar tocarlos y protegerse."},"49":{"q":"Estoy a punto de cargar un envío de líquidos inflamables de Clase 3 en mi remolque. Antes de empezar a cargar, noto que el espacio de carga todavía tiene algunos restos sueltos y piezas metálicas expuestas sonando del viaje anterior. Según las normas de materiales peligrosos, ¿qué condición debe cumplir el espacio de carga antes de comenzar a cargar?","options":["Estar húmedo en toda su superficie, ya que la humedad reduce la posibilidad de una ignición accidental durante la carga","Estar cargado primero con mis herramientas de mano para que viajen sujetas contra la pared delantera","Estar sellado y sin ventilación para que los vapores inflamables no escapen hacia la zona de la cabina","Estar limpio y libre de cualquier peligro que produzca chispas antes de meter la carga"],"explanation":"La zona de carga debe estar limpia y libre de peligros que generen chispas antes de cargar líquidos inflamables, ya que el metal suelto puede inflamar los vapores."},"50":{"q":"Estoy preparando mi cisterna con carteles (placards) antes de un viaje y estoy montando los carteles en forma de rombo en el remolque. Además de asegurarme de que cada uno se mantenga limpio y legible desde la dirección hacia la que apunta, ¿cómo debo posicionar realmente cada cartel para cumplir con los requisitos del DPS?","options":["Colocarlo como un cuadrado girado de modo que una punta quede mirando directamente hacia arriba, como un rombo","Ponerlo plano con un lado completo apoyado nivelado a lo largo de la parte inferior","Montarlo solo en los lados del conductor y del pasajero, no al frente ni atrás","Cubrirlo con una película transparente hasta llegar al muelle de carga"],"explanation":"Los carteles son rombos colocados como un cuadrado girado sobre una punta, con una esquina apuntando hacia arriba, y se mantienen limpios y legibles."},"51":{"q":"Mientras cargo mi remolque con carteles de peligro (placards) en el muelle del expedidor, noto que un tambor de material corrosivo tiene una mancha húmeda reciente que escurre por su costado y la etiqueta del paquete está parcialmente rasgada. El expedidor insiste en que es 'solo un poco' y me dice que lo cargue para que el viaje no se atrase. ¿Qué debo hacer?","options":["Cargarlo tal como está, ya que el expedidor preparó y certificó el paquete, y cualquier reporte es tarea del transportista después de la entrega","Rechazar el paquete y no transportarlo, porque el conductor debe rechazar todo envío de materiales peligrosos que tenga fugas o esté dañado","Cargarlo pero enterrarlo en el centro del resto de la carga para que la fuga quede contenida y lejos de las paredes del remolque","Cargarlo pero escribir una nota en los documentos de embarque para advertir al destinatario sobre la fuga al llegar"],"explanation":"El conductor debe inspeccionar los envíos y negarse a transportar cualquier paquete de materiales peligrosos que tenga fugas o esté dañado."},"52":{"q":"Acabo de entregar una carga de líquido inflamable en un camión cisterna y el indicador marca que el tanque está 'vacío'. Antes de regresar a la terminal, estoy decidiendo si puedo quitar los carteles (placards). ¿Bajo qué condición tengo MENOS fundamento para quitarlos mientras el tanque sigue en este estado 'vacío'?","options":["Cuando el tanque ha sido limpiado con vapor, purgado y certificado como libre de todo producto","Cuando tanto los documentos de embarque como el transportista confirman que el tanque ya cumple con el estándar de 'limpiado y purgado'","Cuando el tanque todavía contiene residuos adheridos o vapores peligrosos de la última carga","Cuando el tanque ha sido enjuagado tres veces en la terminal y vuelto a pesar como vacío"],"explanation":"Un tanque se considera 'vacío' solo cuando no quedan residuos adheridos ni vapores peligrosos de la última carga, por lo que los carteles deben permanecer hasta que esté realmente limpio."},"53":{"q":"Estoy recogiendo una carga que el expedidor ha clasificado como RESIDUO peligroso, no solo como material peligroso común, y quiero asegurarme de salir de la instalación con el único documento que las regulaciones exigen específicamente para este tipo de envío. ¿Qué documento DEBE acompañar esta carga de residuos peligrosos?","options":["Un conocimiento de embarque estándar preparado para un envío comercial de carga corriente","Solo la Guía de Respuesta a Emergencias (ERG) que se guarda en la cabina como referencia ante incidentes","Una Hoja de Datos de Seguridad (SDS) que describe las propiedades del químico y los pasos de manejo","Un Manifiesto Uniforme de Residuos Peligrosos (Uniform Hazardous Waste Manifest) que viaja con el envío de residuos"],"explanation":"Los envíos de desechos peligrosos deben viajar con un Manifiesto Uniforme de Desechos Peligrosos que rastrea el desecho desde su generación y transporte hasta su disposición final."},"54":{"q":"Transporto una carga con cartel de la División 1.1 (explosivos) y noto que un soporte de la carga dentro del remolque se ha aflojado. Necesito apretar los sujetadores antes de poder continuar con seguridad. ¿Cuál de las siguientes opciones debo usar para hacer el trabajo?","options":["Herramientas que no producen chispas, hechas de latón o bronce, para evitar cualquier chispa que pueda encender los explosivos","Herramientas comunes de acero, ya que sujetan los sujetadores con más firmeza y terminan el trabajo más rápido","Cualquier barra pesada de acero que tenga más cerca, porque a mayor palanca termino antes","Cualquier herramienta pintada con una marca roja de seguridad, ya que las herramientas con marca roja están autorizadas para materiales peligrosos"],"explanation":"El trabajo cerca de explosivos de Clase 1 debe realizarse con herramientas antichispa de latón o bronce, ya que una sola chispa de metal contra metal podría encender los explosivos."},"55":{"q":"Coloqué los carteles (placards) en los cuatro lados de mi remolque en el muelle de carga y confirmé que cada uno era legible antes de salir. Tres horas después de iniciar un viaje largo, me detengo a cargar combustible y le digo a mi copiloto que los carteles 'ya están resueltos'. Respecto a cuándo soy responsable de verificar que los carteles estén colocados, ¿qué afirmación es correcta?","options":["Mi responsabilidad termina una vez que confirmo los carteles en el muelle, ya que la colocación se verifica en la inspección previa al viaje.","Debo verificar que los carteles estén colocados tanto antes del viaje como durante el viaje mientras circulo.","Solo necesito revisar los carteles al llegar al punto de entrega para satisfacer al receptor.","Colocar los carteles es deber del expedidor, así que verificarlos en ruta no forma parte de mi responsabilidad de conducir."],"explanation":"Debe asegurarse de que los carteles estén en su lugar tanto antes del viaje como durante el mismo, ya que pueden aflojarse, caerse u oscurecerse mientras conduce."},"56":{"q":"Estoy transportando una carga de corrosivos con rótulos cuando uno de los tambores empieza a gotear sobre el arcén. Mientras saco los documentos de embarque del asiento, noto que el expedidor les ha adjuntado información de respuesta ante emergencias. Cuando llegan los bomberos y un equipo de materiales peligrosos a la escena, ¿cuál es el propósito PRINCIPAL de esa información de emergencia del expedidor?","options":["Indica el valor comercial de la carga para que los rescatistas decidan qué cargas proteger primero","Me dice qué tipo de combustible y presión de neumáticos prefiere el transportista para viajes largos en calor","Da a los rescatistas los datos que necesitan para manejar con seguridad el derrame o incendio de este material específico","Certifica que completé mi verificación de antecedentes de la TSA y que tengo un endoso H válido para conducir"],"explanation":"La información de respuesta a emergencias acompaña a los documentos de envío para dar a los socorristas los datos específicos necesarios para manejar con seguridad un derrame, fuga o incendio de ese material."},"57":{"q":"Estoy cargando varios paquetes de material radiactivo de Clase 7, y el expedidor señala un número impreso en la etiqueta de cada paquete y me dice que debo sumar estas cifras y mantener el total dentro de un límite establecido para mi vehículo. ¿Cuál es el propósito de este número que me indican que controle?","options":["Es un código de color que me indica en qué lado del remolque colocar el cartel (placard) correspondiente","Es una calificación de velocidad que limita qué tan rápido puedo conducir mientras la carga radiactiva está a bordo","Es un índice de ruta que me indica qué carreteras designadas tengo permitido usar","Es un índice de transporte que limita la exposición total a la radiación permitida en mi vehículo"],"explanation":"Cada paquete radiactivo lleva un índice de transporte, y el conductor debe sumar estos índices y mantener el total por debajo de un límite establecido para controlar la exposición a la radiación en el vehículo."},"58":{"q":"Transporto una carga de corrosivos con placas (placards) cuando una falla en el rodamiento de una rueda me obliga a detenerme en el arcén y esperar un tractor de reemplazo. El despachador me avisa por radio que hay otro camión de la empresa cerca y sugiere que trasvase el producto a ese vehículo para que la entrega no se retrase. ¿Qué respuesta se ajusta mejor a la práctica correcta de materiales peligrosos?","options":["Rechazar el trasvase en la carretera; los materiales peligrosos solo deben moverse entre vehículos en una verdadera emergencia, así que debo esperar la reparación o las gestiones adecuadas","Realizar el trasvase, ya que mantener la entrega a tiempo es la prioridad principal del transportista","Trasvasarlo solo después de volver a colocar las placas en ambos vehículos, lo que hace que el trasvase en la carretera sea totalmente aceptable","Hacer el trasvase porque la carga ya está detenida y estacionada de forma segura fuera de la parte transitada de la vía"],"explanation":"El material peligroso debe transferirse entre vehículos solo en una emergencia genuina, por lo que una avería rutinaria o una entrega tardía no justifican una transferencia al borde de la carretera."},"59":{"q":"Estoy cargando un envío que los documentos del expedidor identifican como contaminante marino antes de mi viaje al puerto. Como conductor que completa mi inspección, ¿cuál de estas condiciones debe cumplirse antes de aceptar transportar esta carga?","options":["Las etiquetas de contaminante marino pueden cubrirse hasta que llegue a la terminal marítima","El paquete debe mostrar las marcas requeridas de contaminante marino antes de que yo lo transporte","Las marcas de contaminante marino pueden omitirse ya que primero viaja por carretera","El contenedor debe ocultarse de la vista para mantener la carga segura en la carretera"],"explanation":"Un contaminante marino debe mostrar las marcas requeridas en el paquete antes del transporte, y el conductor debe rechazar cualquier envío de material peligroso marcado incorrectamente."},"63":{"q":"Estoy haciendo la inspección previa al viaje en un tractocamión con remolque que lleva rótulos (placards) por una carga de líquido inflamable. Quiero asegurarme de que mi extintor cumpla el requisito federal antes de arrancar. ¿Cuál de estas opciones realmente cumpliría la norma?","options":["El extintor puede quedarse cerrado dentro del remolque sellado junto con la carga, ya que es ahí donde más probablemente se iniciaría un incendio.","Un extintor totalmente cargado sirve aunque esté enterrado detrás de las correas de la carga, siempre que sea de la clasificación correcta para la carga.","El extintor debe tener la clasificación adecuada para la carga, estar totalmente cargado y montado donde yo pueda alcanzarlo rápidamente.","Cualquier extintor pequeño y cargado sirve, porque la clasificación solo importa para el equipo del muelle del destinatario, no para el camión."],"explanation":"El extintor de un vehículo con carteles debe estar clasificado adecuadamente para la carga, completamente cargado y montado donde el conductor pueda alcanzarlo rápidamente."},"67":{"q":"Usted transporta una carga rotulada de líquido inflamable y entra a un área de descanso para su revisión de neumáticos cada 2 horas. Descubre que uno de los neumáticos de su remolque está caliente al tacto y claramente se está sobrecalentando. ¿Cuál de las siguientes es la acción correcta que debe tomar?","options":["Echar agua sobre el neumático caliente para enfriarlo rápido y seguir hasta la entrega para no atrasar el envío.","Agregar aire para devolver el neumático caliente a su presión correcta y continuar conduciendo por la ruta planificada.","Dejar el neumático en su lugar y seguir conduciendo, ya que algo de calentamiento es normal en un remolque rotulado a plena carga.","Quitar el neumático sobrecalentado y colocarlo a una distancia segura del vehículo, y luego revisarlo antes de continuar."],"explanation":"Si un neumático se sobrecalienta en una carga con carteles, representa un riesgo de incendio, así que quítelo, colóquelo a una distancia segura del vehículo y revíselo antes de continuar."},"69":{"q":"Acabo de descargar mi última tarima de materiales peligrosos en el consignatario, y el remolque ahora está completamente vacío y sin residuos, pero las cuatro placas siguen atornilladas. Estoy a punto de regresar en vacío a la terminal por la autopista. ¿Qué acción me mantiene dentro de la ley en este viaje sin carga?","options":["Quitar o cubrir las placas ahora, ya que el remolque ya no transporta una carga que las requiera.","Dejar las placas puestas durante todo el regreso, porque un remolque con placas siempre lo consideran más seguro los demás conductores.","Dejarlas puestas solo hasta el primer cruce de ferrocarril y quitarlas durante esa parada.","En realidad no hay diferencia, así que puedo dejar las placas en el remolque vacío si me ahorra tiempo."],"explanation":"Los carteles (placards) deben retirarse o cubrirse cuando el vehículo ya no transporta una carga que legalmente los exige, para que no representen erróneamente la carga."},"70":{"q":"Estoy haciendo la inspección previaje de una carga con carteles de peligro y comparo el documento de embarque con el paquete antes de firmarlo. La entrada ya muestra el nombre de embarque apropiado y la clase de peligro. Para que sea completa y legal, ¿qué dato RESTANTE DEBE aparecer en esa misma entrada?","options":["El kilometraje total que recorreré en mi ruta designada para materiales peligrosos","El número de identificación (ID) (UN/NA) del material","El teléfono de CHEMTREC disponible las 24 horas para el transportista","La letra del grupo de embalaje estampada en el tambor exterior"],"explanation":"Una entrada completa del documento de embarque indica el nombre de embarque adecuado, la clase de peligro y el número de identificación UN/NA en ese orden."},"71":{"q":"Estoy detenido en una estación de pesaje y el inspector señala el panel naranja debajo del rótulo (placard) en forma de diamante de mi remolque, que muestra el número en negro \"1203\". Me pregunta qué le indica ese número de cuatro dígitos a los equipos de emergencia. ¿Cuál es la explicación correcta?","options":["Es el peso bruto, en libras, del material peligroso cargado en ese compartimento","Es el código de división de la clase de peligro que clasifica la carga del 1 al 9","Es el número de identificación UN/NA que nombra el material específico que se transporta","Es el código telefónico de emergencia que marcan los equipos para contactar a CHEMTREC sobre la carga"],"explanation":"El número de cuatro dígitos en un cartel o panel naranja es el número de identificación UN/NA que designa el material específico transportado."},"72":{"q":"Un agente de carga me ofrece un cargamento de material corrosivo que requerirá placas de identificación (placards) en los cuatro lados de mi remolque. Ya tengo mi CDL con los endosos de Tanque (N) y Remolques Dobles/Triples (T), y acabo de renovar mi tarjeta médica. Antes de poder aceptar y transportar legalmente este envío, ¿qué debo haber completado?","options":["Nada más — como mi carga es corrosiva (Clase 8) y no explosiva, las placas por sí solas satisfacen el requisito legal y no se necesita ningún endoso especial.","Solo el endoso de Tanque (N), que ya poseo, ya que cualquier material con placas se considera un peligro de líquido a granel según las normas federales.","Un endoso vigente de Pasajeros (P), porque transportar una carga regulada que afecta la seguridad pública se trata igual que transportar pasajeros.","El endoso de Materiales Peligrosos (H), que exige aprobar una evaluación de amenaza de seguridad de la TSA con toma de huellas dactilares antes de poder transportar cualquier material peligroso con placas."],"explanation":"Transportar cualquier material peligroso con carteles exige el endoso HazMat (H), que requiere una evaluación de amenaza de seguridad de la TSA con toma de huellas dactilares."},"73":{"q":"Ya tengo una CDL Clase A y aprobé mi examen de manejo, pero ahora quiero transportar materiales peligrosos que requieren rótulos (placards). Además de aprobar el examen escrito de conocimientos sobre materiales peligrosos, ¿cuál es el ÚNICO requisito adicional que debo cumplir antes de que el endoso H se agregue a mi licencia?","options":["Debo completar una evaluación de amenaza de seguridad de la TSA, que incluye toma de huellas dactilares y una verificación de antecedentes","Debo aprobar un segundo examen de manejo independiente en un vehículo con rótulos","Debo obtener primero mi endoso de cisterna (N) como requisito previo","Debo agregar el endoso de remolques dobles/triples (T) a mi licencia"],"explanation":"El endoso HazMat (H) es el único que exige al solicitante aprobar una evaluación de amenaza de seguridad de la TSA que incluye toma de huellas dactilares y verificación de antecedentes."},"76":{"q":"Estoy estacionado en un área de descanso con mi carga de líquido inflamable y mis carteles (placards) colocados. Otro conductor se acerca a conversar y enciende un cigarrillo mientras se aproxima a mi camión. Para mantenernos seguros, ¿cuál es la distancia más cercana a la que se le debe permitir fumar junto a mi vehículo con carteles?","options":["No más cerca de unos 15 pies, el mismo margen usado antes de las vías del ferrocarril","No más cerca de unos 25 pies del vehículo con carteles","No más cerca de unos 5 pies, igual que el margen de estacionamiento desde la carretera","Cualquier lugar fuera de la cabina es aceptable porque la carga está sellada"],"explanation":"Está prohibido fumar a menos de unos 25 pies de un vehículo con carteles que transporta explosivos, oxidantes o inflamables."},"77":{"q":"Estoy recogiendo una carga y el documento de embarque indica el material con clase de riesgo 7. Antes de colocar los rótulos e inspeccionar los paquetes, quiero confirmar qué tipo de peligro voy a transportar. Según la clase de riesgo indicada, ¿qué hay en mi remolque?","options":["Un líquido inflamable como gasolina o diésel","Un líquido corrosivo que puede quemar la piel y dañar el metal","Un material radiactivo","Un gas comprimido a alta presión"],"explanation":"En el sistema federal de clases de peligro, la Clase 7 siempre significa materiales radiactivos."},"78":{"q":"Estoy preparando una carga con carteles (placards) y mi documento de embarque indica la clase de peligro de la carga como 'Clase 1'. Para estacionar y manejarla correctamente, necesito saber qué material transporto realmente. Una designación de Clase 1 me indica que la carga es:","options":["Líquidos inflamables, como la gasolina o el diésel, que corresponden a la Clase 3","Líquidos corrosivos, los ácidos y las bases agrupados en la Clase 8","Gases comprimidos o inflamables, que pertenecen a la Clase 2","Explosivos, los materiales que corresponden a la Clase 1"],"explanation":"En la numeración fija de clases de peligro, la Clase 1 siempre significa explosivos."},"79":{"q":"Estoy revisando los documentos de embarque de mi carga y una entrada indica la clase de peligro como \"2.1\" con un número ONU para el material. Según el sistema de numeración de clases de peligro, ¿qué tipo de material estoy transportando en realidad?","options":["Un gas inflamable, porque la Clase 2 abarca los gases (siendo 2.1 el inflamable)","Un líquido inflamable, porque es la clase de carga inflamable más común","Un explosivo, porque el número de clase bajo significa que se enciende con violencia","Un material radiactivo, ya que lleva un número de identificación ONU especial"],"explanation":"La Clase 2 abarca los gases, y la división 2.1 designa específicamente un gas inflamable."},"80":{"q":"Estoy recogiendo un envío y el documento de embarque registra la entrada como \"Acetona, 3, UN1090\". El despachador me pide que confirme qué tipo de peligro me indica ese número del medio para que tome los letreros (carteles) correctos. Según la clase de peligro mostrada, ¿qué estoy transportando?","options":["Un sólido inflamable que puede encenderse por fricción","Un líquido inflamable que desprende vapores inflamables","Un gas comprimido inflamable a presión","Un agente oxidante que intensifica un incendio"],"explanation":"La Clase 3 siempre significa líquidos inflamables, que desprenden vapores inflamables."},"81":{"q":"Estoy preparando los documentos de embarque de una carga y la clase de peligro en el registro indica \"Clase 4\". Antes de colocar los carteles (placards), quiero confirmar a qué categoría general pertenece este material para elegir el cartel correcto. Según el sistema de clases de peligro, un material de Clase 4 se identifica como cuál de los siguientes?","options":["Un líquido corrosivo que puede dañar la piel y el metal","Un líquido inflamable como la gasolina o el combustible diésel","Un sólido inflamable, incluidos los materiales de combustión espontánea y peligrosos al mojarse","Un artículo explosivo que detona bajo impacto o calor"],"explanation":"La Clase 4 abarca los sólidos inflamables, incluidos los materiales de combustión espontánea y los peligrosos cuando se mojan."},"82":{"q":"Estoy revisando los documentos de envío de mi próxima carga y la entrada indica un material peligroso de Clase 5 en la columna de clase de peligro. Antes de aceptar y colocar los carteles en el envío, necesito confirmar qué tipo de sustancia voy a transportar realmente. ¿Qué descripción corresponde correctamente a un material de Clase 5?","options":["Líquidos inflamables como gasolina, aditivos de diésel y solventes","Materiales corrosivos como el ácido de batería y otros líquidos fuertes","Venenos y líquidos tóxicos que presentan un peligro de inhalación","Oxidantes y peróxidos orgánicos"],"explanation":"La Clase 5 es el grupo de los oxidantes y peróxidos orgánicos."},"83":{"q":"Antes de salir de la terminal estoy revisando los documentos de envío de una carga, y una entrada está marcada como Clase 6. El expedidor aún no ha escrito el nombre de envío correcto y me pide confirmar qué tipo de material cubre un cartel de Clase 6 para que el papeleo coincida con el peligro. ¿Qué descripción identifica correctamente lo que corresponde a la Clase 6?","options":["Venenos (tóxicos) y sustancias infecciosas","Líquidos inflamables como la gasolina y los disolventes comunes","Líquidos corrosivos que pueden quemar la piel y el metal","Oxidantes y peróxidos orgánicos que intensifican el fuego"],"explanation":"La Clase 6 abarca las sustancias venenosas (tóxicas) e infecciosas."},"84":{"q":"Estoy haciendo mi inspección previaje y revisando los documentos de embarque de una carga que indica un riesgo de Clase 8. Antes de manipular los contenedores y elegir los guantes y la protección ocular adecuados, necesito saber qué tipo de peligro presenta realmente este material. ¿Qué afirmación describe correctamente qué es un material de Clase 8?","options":["Es un líquido inflamable que puede encenderse con una chispa, por lo que mi principal preocupación es mantener todas las fuentes de ignición lejos de la carga.","Es un corrosivo que puede quemar químicamente la piel, los ojos y el metal, por lo que mi principal preocupación es evitar el contacto y proteger las superficies.","Es un gas comprimido a presión que puede reventar violentamente, por lo que mi principal preocupación es mantener los cilindros fríos y asegurados.","Es un material radiactivo que emite radiación dañina, por lo que mi principal preocupación es limitar mi tiempo de exposición cerca de la carga."],"explanation":"La Clase 8 son corrosivos que queman químicamente la piel, los ojos y el metal al contacto, por lo que la prioridad es evitar el contacto y proteger las superficies."},"85":{"q":"Estoy revisando los documentos de embarque de una carga y veo una entrada clasificada como material peligroso de Clase 9. Mi instructor me pregunta qué me indica realmente esa clasificación sobre la carga. ¿Qué afirmación describe correctamente lo que significa una designación de Clase 9?","options":["Identifica un producto de la División 2.3, lo que significa que la carga es un gas venenoso que requiere rótulos en cualquier cantidad","Identifica un líquido inflamable, la misma categoría cubierta por la Clase de peligro 3 en el documento de embarque","Identifica una mercancía peligrosa diversa que no encaja claramente en ninguna de las otras ocho clases de peligro","Identifica un artículo explosivo, la misma familia de carga cubierta por las reglas de rotulado de la Clase de peligro 1"],"explanation":"La Clase 9 es la categoría miscelánea para mercancías peligrosas que no encajan en ninguna de las otras ocho clases de peligro."},"86":{"q":"Estoy transportando una carga de corrosivos que requiere rótulos (placards) y un policía estatal me indica entrar a la estación de pesaje. Me dice que desde donde estaba solo pudo ver un rótulo y me pide confirmar cómo debe estar rotulado mi vehículo. ¿Qué afirmación describe correctamente la colocación adecuada de los rótulos?","options":["Los rótulos solo se requieren en la parte trasera del remolque, ya que eso es lo que leen el tráfico y los inspectores que vienen detrás de mí","Un solo rótulo del lado del conductor es suficiente mientras sea legible desde la dirección hacia la que apunta","Los rótulos van solo en el frente del tractor y en la parte trasera del remolque, para que se vean de frente y por detrás","Los rótulos deben colocarse en los cuatro lados del vehículo, y cada uno debe ser legible desde la dirección hacia la que apunta"],"explanation":"Los carteles deben colocarse en los cuatro lados del vehículo, cada uno legible desde la dirección a la que mira."},"87":{"q":"Estoy haciendo mi inspección previaje y necesito confirmar que las marcas de advertencia en mi remolque sean correctas antes de transportar una carga de materiales peligrosos (HazMat) que requiere rótulos. Cuando observo un rótulo de HazMat colocado correctamente en cada lado de la unidad, ¿qué forma general debería esperar que tenga?","options":["Un rombo, es decir, un cuadrado girado para apoyarse sobre una de sus puntas (esquina)","Un triángulo, la misma forma que los triángulos reflectantes de advertencia que llevo conmigo","Un rectángulo más ancho que alto, como el panel del número de identificación","Un círculo bordeado por un anillo de color, como el símbolo de una señal de tránsito"],"explanation":"Un cartel de materiales peligrosos tiene forma de rombo: un cuadrado apoyado sobre una de sus esquinas."},"88":{"q":"Transporto una carga con carteles de peligro (placards) y, durante mi inspección previaje, noto que el cartel del lado derecho de mi remolque está manchado con suciedad del camino y parcialmente cubierto por un colgador de correa, aunque los otros tres carteles están limpios. Antes de conducir, qué exige el Texas DPS que haga con ese cartel del lado derecho?","options":["Nada adicional, porque mientras los carteles delantero y trasero permanezcan limpios y legibles, la visibilidad de los carteles laterales no está regulada","Limpiarlo y reubicar el colgador de la correa para que el cartel quede legible y sin obstrucción, ya que los carteles de los cuatro lados deben verse desde la dirección a la que apuntan","Retirar por completo ese cartel, porque un cartel parcialmente sucio se considera como si no hubiera cartel y los tres restantes ya cubren la carga","Dejarlo como está y simplemente anotar su estado en mis documentos de embarque para que el inspector sepa que estoy enterado"],"explanation":"Como los carteles en los cuatro lados deben ser legibles desde su dirección, un cartel sucio u obstruido debe limpiarse y despejarse antes de conducir."},"89":{"q":"Estoy cargando carga mixta y una tarima es un material peligroso que figura en la Tabla 2 de las reglas de rótulos (placards). Un compañero me dice: 'Material peligroso es material peligroso; en cuanto cualquier cantidad sube al remolque, hay que poner rótulos'. Antes de colocar algo en los cuatro lados, ¿cómo debo decidir si realmente se requieren rótulos para esta carga?","options":["Cualquier cantidad obliga a poner rótulos, así que en el momento en que un solo paquete de material peligroso está a bordo debo rotular los cuatro lados","Los rótulos se basan solo en el embalaje, así que rotulo únicamente porque se cargan juntos artículos alimentarios y no alimentarios","Depende de la clase y la cantidad del material: algunas clases requieren rótulos en cualquier cantidad, mientras que estos materiales de la Tabla 2 los requieren solo a partir de 1.001 lb o más de peso bruto agregado","Los rótulos nunca se exigen legalmente para una carga mixta, así que puedo omitirlos por completo en este viaje"],"explanation":"El uso de carteles depende de la clase y la cantidad: algunas clases los requieren en cualquier cantidad, mientras que los materiales de la Tabla 2 solo a partir de 1,001 lb de peso bruto total."},"90":{"q":"Estoy cargando mi remolque en un muelle con varios paquetes no a granel de diferentes clases de peligro de la Tabla 2. Ninguna clase de peligro por sí sola alcanza las 1,001 libras a bordo, pero la carga combinada de la Tabla 2 supera ese umbral. Un compañero dice que puedo usar un solo cartel DANGEROUS para toda la carga mixta en lugar de un cartel distinto para cada clase. Según las reglas de carteles, ¿cuándo se permite realmente usar el cartel DANGEROUS?","options":["Solo cuando todo el remolque es una única carga completa de un solo material de la Tabla 2 que pesa 1,001 libras o más","Nunca, porque cada clase de peligro a bordo siempre debe mostrar su propio cartel específico sin excepciones","Solo cuando la carga está compuesta por explosivos de la Clase 1 que requieren cartel en cualquier cantidad","Cuando transporto ciertas cargas no a granel compuestas por dos o más clases de peligro de la Tabla 2, se puede usar el cartel DANGEROUS para esa carga mixta pequeña"],"explanation":"El cartel DANGEROUS puede usarse en una carga no a granel que mezcla dos o más clases de peligro de la Tabla 2, en lugar de carteles por clase separados."},"91":{"q":"Estoy cargando un líquido inflamable de Clase 3 y los únicos carteles (placards) que me quedan en la caja son carteles de Clase 8 (corrosivos) sobrantes de mi viaje anterior. Antes de salir, ¿qué afirmación refleja correctamente lo que debo hacer respecto a los carteles de mi vehículo?","options":["Los carteles que coloque deben identificar la clase de peligro del material que realmente transporto, así que no puedo usar los carteles de Clase 8 para una carga de Clase 3.","Cualquier cartel tipo DOT es aceptable siempre que tenga forma de rombo y esté colocado en los cuatro lados del vehículo.","Puedo circular con los carteles de Clase 8 mientras mantenga los documentos de embarque correctos de Clase 3 al alcance de la mano en la cabina.","Los carteles solo deben coincidir con la carga cuando cruzo una línea estatal, así que los de Clase 8 sirven para un viaje dentro del estado."],"explanation":"Los carteles deben coincidir con la clase de peligro real del material que transporta, por lo que una carga Clase 3 necesita carteles Clase 3."},"92":{"q":"Estoy terminando la inspección previa al viaje de mi remolque tipo furgón cargado con un líquido inflamable de Clase 3 que requiere rótulos (placards), y quiero confirmar que mis rótulos están colocados correctamente antes de salir. ¿Cuál de estas condiciones debe cumplirse para que pueda iniciar el viaje legalmente?","options":["Rótulos solo al frente y atrás, ya que esos son los lados que los demás conductores realmente leen","Un rótulo en cada uno de los cuatro lados del vehículo, sujeto de modo que cada uno sea legible desde la dirección hacia la que apunta","Rótulos en ambos lados del remolque más una copia de los documentos de embarque pegada junto a cada uno","Un solo rótulo montado plano sobre el techo del remolque para que permanezca visible y protegido de las salpicaduras de la carretera"],"explanation":"Un vehículo de materiales peligrosos con carteles debe llevar un cartel en los cuatro lados, cada uno fijo y legible desde la dirección que mira."},"93":{"q":"Durante la inspección previaje de una carga con placas (placards), noto que una de las cuatro placas obligatorias está tan desteñida por el sol que el número de clase de peligro apenas se lee, aunque todavía logro distinguirlo con dificultad. ¿Cuál es la acción correcta antes de iniciar el viaje?","options":["Dejarla en su lugar, ya que la placa aún se lee débilmente si uno mira de cerca","Cubrir la placa desteñida con cinta transparente para protegerla de más decoloración","Reemplazar la placa desteñida por una nueva y totalmente legible antes de iniciar el viaje","Continuar y reemplazarla en la próxima parada, siempre que las otras tres placas estén claras"],"explanation":"Un cartel descolorido o dañado debe reemplazarse por uno totalmente legible antes de iniciar el viaje."},"94":{"q":"Estoy recogiendo una carga con placas y el remitente me entrega los documentos de embarque. Antes de firmar y salir, ¿qué debo confirmar sobre esos documentos?","options":["Que solo figure el nombre de embarque correcto, ya que la clase de peligro y el número de identificación se pueden agregar después","Que se dejó una copia en la terminal, pues el original es opcional en viajes cortos dentro del estado","Que al menos una entrada esté completada, aunque falten algunos datos del material peligroso","Que cada entrada de material peligroso sea exacta y completa antes de transportar la carga"],"explanation":"Los documentos de embarque de materiales peligrosos deben ser exactos y completos antes de transportar la carga, mostrando el nombre de embarque, la clase de peligro y el número de identificación."},"95":{"q":"Voy por la autopista interestatal transportando una carga de corrosivos con rótulos (placards), con el cinturón de seguridad abrochado. Un agente podría detenerme en cualquier marcador de milla. Según las reglas del DPS de Texas, ¿dónde deben estar AHORA MISMO mis documentos de embarque de materiales peligrosos mientras conduzco?","options":["A mi alcance con el cinturón puesto, o en una bolsa de la puerta del conductor, encima de mis demás documentos","Cerrados con llave dentro del remolque junto con la carga para que se mantengan limpios y viajen con la mercancía misma","Metidos en la guantera del lado del pasajero para que no se deslicen del asiento en una frenada brusca","En poder únicamente del expedidor, que envía una copia por fax al despacho del transportista antes de cada viaje"],"explanation":"Mientras conduce, mantenga los documentos de embarque de materiales peligrosos a su alcance con el cinturón puesto, o en la bolsa de la puerta del conductor, encima de sus otros papeles."},"96":{"q":"Estoy cargando un envío con placas de identificación y reviso el documento de embarque antes de salir del muelle. El material peligroso está mezclado con varias entradas de carga no peligrosa en la misma página. Para que el documento sea aceptable, ¿cómo debe aparecer la entrada de material peligroso entre los demás artículos?","options":["Puede anotarse en cualquier parte entre la carga siempre que estén presentes el nombre de embarque correcto, la clase de riesgo y el número de identificación","Debe figurar en primer lugar, o estar claramente identificada mediante resaltado o una 'X' en la columna HM para que destaque frente a la carga no peligrosa","Debe colocarse en último lugar en la página para que el peso total de la carga no peligrosa quede sumado encima de ella","Solo necesita marcarse por separado si el remitente o la instalación receptora lo solicitan expresamente"],"explanation":"En un documento de embarque mixto, la entrada de material peligroso debe destacarse apareciendo primero o marcada con resaltado o una 'X' en la columna HM."},"97":{"q":"Estoy transportando una carga de corrosivos con placas (placards) cuando un acoplamiento de uno de mis tambores empieza a gotear y los vapores se desplazan hacia el acotamiento. Me orillo de forma segura, advierto a los demás y tomo la Guía de Respuesta a Emergencias (ERG) que llevo en la cabina. ¿Para cuál de las siguientes cosas está realmente diseñada la ERG para ayudarme en este momento?","options":["Identificar el desvío más rápido que evita las básculas y las casetas de peaje más adelante","Confirmar el nombre de embarque correcto, la clase de peligro y el número de identificación para mi documentación","Determinar la distancia de aislamiento inicial y las acciones de protección para el material derramado","Verificar qué placas (placards) se requieren y en qué lados del remolque deben colocarse"],"explanation":"La Guía de Respuesta a Emergencias indica la distancia de aislamiento inicial y las acciones de protección para un material derramado o con fugas."},"98":{"q":"Estoy recogiendo una carga de corrosivos con cartel (placard), y los documentos de embarque que tengo en la mano indican el nombre de embarque correcto, la clase de peligro y el número de identificación, con una declaración de certificación firmada al final. Como conductor con CDL, sé que mi trabajo es inspeccionar la carga, rechazar cualquier cosa que tenga fugas, colocar los carteles en el vehículo y mantener estos documentos a mi alcance. Pero cuando reviso esa línea firmada que certifica que el material está descrito correctamente y debidamente preparado para el transporte, ¿de quién es la certificación que en realidad estoy viendo?","options":["Del transportista, ya que la empresa de transporte despacha la carga y es responsable de reportar cualquier incidente que ocurra durante el transporte","Mía como conductor, ya que soy quien inspecciona el envío, coloca los carteles en el camión y mantiene los documentos a mi alcance mientras conduzco","De nadie en particular, porque la línea de certificación es solo una formalidad y la verdadera responsabilidad legal recae por completo en quien recibe la carga","Del expedidor (shipper), porque el expedidor clasifica, empaca, marca y prepara los documentos de embarque, y luego certifica que el material está descrito correctamente"],"explanation":"El expedidor clasifica, empaca, marca y prepara los documentos de embarque, luego certifica que el material está descrito correctamente."},"99":{"q":"Estoy en el muelle de carga a punto de aceptar un tambor de líquido corrosivo y, antes de firmar el documento de embarque, quiero confirmar que la entrada de material peligroso está descrita correctamente. ¿Qué conjunto de datos debe aparecer realmente en esa línea para que la entrada sea una descripción válida de material peligroso?","options":["El nombre de embarque correcto, la clase de peligro y el número de identificación (UN/NA), enumerados exactamente en esa secuencia","El color de la etiqueta de la clase de peligro, el texto del cartel (placard) y el número de cuatro dígitos que aparece en el cartel","El valor comercial de la carga, su peso bruto total y el código postal del destino","Solo una 'X' en la columna HM, ya que esa marca es lo único que identifica legalmente una entrada peligrosa"],"explanation":"Una entrada de material peligroso debe indicar el nombre de embarque, la clase de peligro y el número de identificación (UN/NA) en ese orden exacto."},"100":{"q":"Estoy transportando una carga de corrosivos con placas (rótulos) y entro a un área de descanso para usar el baño. Voy a salir de la cabina y alejarme de mi camión por unos minutos. Según las reglas de materiales peligrosos, ¿dónde debo dejar mis documentos de embarque mientras estoy fuera del vehículo?","options":["Doblados dentro de la guantera, con el pestillo cerrado para que queden fuera de la vista","Sobre el asiento del conductor o en la bolsa de la puerta del conductor","Bajo llave en el remolque junto con la carga que describen","Metidos detrás de la visera del lado del pasajero"],"explanation":"Al salir del camión, deje los documentos de embarque de materiales peligrosos en el asiento del conductor o en la bolsa de la puerta del conductor para que los rescatistas los encuentren rápido."},"101":{"q":"Estoy en una estación de pesaje con una carga rotulada, y el inspector me pide que señale, solo con los documentos de embarque, la cantidad total de material peligroso que transporto. Además del nombre de embarque correcto, la clase de peligro y el número de identificación, ¿qué valor mostrarán realmente mis documentos de embarque para esa entrada?","options":["El peso combinado de todos los ejes de mi camión","La presión recomendada de las llantas en frío para la carga","La cantidad total del material peligroso que se transporta","Las horas de motor registradas desde que comenzó el viaje"],"explanation":"Los documentos de embarque indican la cantidad total de material peligroso por cada entrada, así que la cantidad a bordo se toma directamente de esa cifra."},"102":{"q":"Estacioné en reversa mi cisterna con rótulos de peligro contra el muelle de carga y la cuadrilla del expedidor está lista para empezar a bombear el producto al remolque. Antes de permitir que comience la carga, ¿cuál acción es la más importante que debo tomar para evitar que el vehículo se mueva por sí solo?","options":["Dejar el motor acelerado en ralentí alto para tener presión de aire completa todo el tiempo","Quitar los rótulos de peligro del frente y la parte trasera para que la cuadrilla alcance mejor las válvulas de llenado","Abrir primero las válvulas de descarga y de ventilación del remolque para que la presión se iguale durante el trasvase","Poner el freno de estacionamiento y colocar calzos contra las ruedas para que el conjunto no se mueva mientras cargamos"],"explanation":"Antes de cargar o descargar materiales peligrosos debe poner el freno de estacionamiento y colocar calzos en las ruedas para que el vehículo no pueda rodar."},"103":{"q":"Estoy en una terminal cargando bidones de un líquido inflamable de Clase 3 en mi remolque con placas. Un compañero se acerca con un cigarrillo encendido y pregunta si puede terminar de fumar mientras me ayuda a cargar. ¿Cuál respuesta es la correcta?","options":["No — no se permite fumar cerca de la carga de inflamables, y debe mantener cualquier cigarrillo encendido bien alejado de la operación","Sí — puede fumar siempre que se mantenga al menos a 5 pies de las puertas abiertas del remolque","Sí — la regla solo restringe las llamas abiertas como bengalas o fósforos de señal, no los cigarrillos","Sí — se permite fumar porque los bidones siguen sellados hasta que se cargan y se colocan las placas"],"explanation":"Está prohibido fumar cerca de la carga de inflamables, así que todo cigarrillo encendido debe mantenerse bien alejado de la operación."},"104":{"q":"Estoy en un depósito cargando a mano cajas de explosivos de la División 1.1 sobre el piso de mi remolque. Al preparar el área de carga y mover cada caja, ¿qué práctica mantiene la carga más segura y cumple con las reglas de manejo de materiales peligrosos?","options":["Arrastrar las cajas sobre el piso de acero desnudo y ajustarlas bien con un gancho de carga metálico afilado","Colocar un revestimiento de piso que no produzca chispas en el área de carga y apoyar cada caja con suavidad, manejando cada bulto con cuidado","Omitir cualquier revestimiento del piso y arrojar las cajas en su lugar rápidamente para poder sellar las puertas antes","Pasar un montacargas directamente sobre las cajas cargadas para comprimirlas bien antes de cerrar el remolque"],"explanation":"Los explosivos de la división 1.1 requieren un revestimiento de piso antichispas y manejo cuidadoso de cada caja para evitar fricción, chispas o impactos que puedan detonar la carga."},"105":{"q":"Estoy cargando cajas de material corrosivo en mi furgón cerrado para un viaje con materiales peligrosos. Los paquetes están correctamente marcados y mis carteles están colocados. Mientras acomodo la carga en el área de carga, ¿cuál de estas opciones describe MEJOR cómo debo manejar los contenedores en sí?","options":["Apilarlos sueltos hacia el frente para que se asienten en su lugar durante las primeras paradas","Colocarlos cerca de las puertas sin sujetar para que los servicios de emergencia puedan alcanzarlos rápido","Calzarlos, apuntalarlos y asegurarlos para que no puedan moverse, deslizarse ni caer mientras el camión circula","Suspenderlos de los rieles superiores del remolque para mantenerlos totalmente separados del piso"],"explanation":"Los contenedores de materiales peligrosos deben bloquearse, asegurarse y sujetarse para que no se desplacen, deslicen ni caigan durante el transporte."},"106":{"q":"Estoy en una terminal de carga a granel llenando una cisterna con gasolina, un líquido inflamable de Clase 3. La línea de transferencia se conecta a la propia bomba de la terminal, así que no necesitaré el motor de mi camión para mover el producto. Mientras se conectan las mangueras y el producto empieza a fluir, ¿qué debo hacer con el motor?","options":["Dejarlo al ralentí en marcha baja para poder avanzar en cuanto termine la carga","Dejarlo a ralentí acelerado para mantener la presión de aire y que el alternador cargue las baterías","Dejarlo encendido solo si el personal de la terminal me dice que la zona está bien ventilada","Apagar el motor, ya que no lo necesito para accionar una bomba de producto durante esta transferencia"],"explanation":"Al cargar o descargar líquidos inflamables el motor debe estar apagado a menos que se necesite para hacer funcionar una bomba de producto."},"107":{"q":"Estoy en una terminal a punto de trasvasar un líquido inflamable de Clase 3 desde mi tanque de carga a un tanque de almacenamiento. Antes de abrir cualquier válvula o iniciar el flujo, conecto un cable de continuidad (bonding) entre el camión y el tanque de almacenamiento y coloco una conexión a tierra. ¿Cuál es la razón PRINCIPAL por la que hago esto antes de manipular el líquido inflamable?","options":["Para igualar la carga eléctrica entre el camión y el tanque de modo que no se forme una chispa estática que encienda los vapores","Para crear una vía eléctrica de respaldo que mantenga encendidas las luces y los indicadores del camión mientras el motor está apagado","Para reducir la temperatura del líquido mientras fluye, de modo que el combustible no se expanda y desborde el tanque receptor","Para frenar la velocidad del flujo de modo que se pierda menos producto por evaporación y derrame durante el trasvase"],"explanation":"La conexión equipotencial y la puesta a tierra igualan la carga eléctrica entre el camión y el tanque para que no se forme una chispa estática que encienda los vapores inflamables."},"108":{"q":"Transporto una carga de corrosivos con placas en un recorrido de 380 millas con dos paradas de descanso programadas. Antes de salir, caminé alrededor del remolque en el patio y revisé todas mis amarras y soportes, y todo estaba seguro. Para cumplir con las normas de carga de materiales peligrosos, ¿qué exige el reglamento que haga respecto a la inspección de la carga y sus dispositivos de sujeción durante el resto del viaje?","options":["No se requiere nada más una vez que la inspección previa en el patio confirma que la carga y las amarras están seguras, ya que volver a revisar en ruta solo es obligatorio para cargas sobredimensionadas o con sobrepeso.","Seguir inspeccionando la carga y sus dispositivos de sujeción tanto antes del viaje como en puntos durante el viaje, no solo una vez al inicio.","Reinspeccionar los dispositivos de sujeción únicamente en el punto final de entrega, porque las revisiones hechas antes de descargar son las que legalmente cuentan para los reclamos de carga.","Repetir una inspección completa de la carga y las amarras según un calendario anual estricto que documenta el transportista, aparte de la revisión previa de cualquier viaje individual."],"explanation":"Debe inspeccionar la carga y sus dispositivos de sujeción tanto antes del viaje como en puntos durante este, no solo una vez al inicio."},"109":{"q":"Transporto una carga con carteles (placards) de explosivos de la División 1.1 y una correa se ha aflojado, así que necesito reubicar una caja en el remolque. ¿Cuál de las siguientes es la regla MÁS importante sobre las herramientas que uso para este trabajo cerca de los explosivos?","options":["Las herramientas deben ser de acero pesado para sujetar firmemente las cajas sin resbalar","Las herramientas deben dejarse en la cabina y mover la caja a mano para evitar todo contacto","Las herramientas no deben poder producir chispas ni dañar los embalajes de los explosivos","Las herramientas deben tener un filo afilado para poder cortar y reasegurar rápidamente la correa floja"],"explanation":"Las herramientas usadas cerca de explosivos deben ser antichispas e incapaces de dañar los paquetes, ya que las chispas o impactos pueden provocar una detonación."},"110":{"q":"Estoy en un muelle de entrega descargando un remolque con carteles de identificación que transporta líquido inflamable de Clase 3 en barriles. Un operador de montacargas quiere dejar su montacargas de propano en ralentí justo al lado de las puertas abiertas del remolque, un trabajador cercano está a punto de encender un cigarrillo, y el supervisor del muelle me pregunta dónde deben estar las llamas abiertas y los motores en marcha durante la operación. ¿Cuál es la instrucción correcta que debo dar?","options":["Mantener las fuentes de ignición justo en las puertas del remolque para que el montacargas trabaje eficientemente y termine la descarga más rápido","Permitir fumar y los motores en ralentí siempre que se mantengan al menos a 5 pies de la parte transitada de la carretera","Colocar el montacargas en marcha dentro del remolque para acelerar la carga, ya que los barriles están sellados y no se encenderán","Mantener todas las fuentes de ignición, incluidas las llamas abiertas y los motores en marcha, bien alejadas del área de descarga"],"explanation":"Al cargar o descargar materiales inflamables, mantenga todas las fuentes de ignición, incluidas llamas abiertas y motores en marcha, bien alejadas del área."},"111":{"q":"Estoy cargando un envío de materiales peligrosos (HazMat) que requiere carteles en el muelle de un cliente. Al inspeccionar los paquetes antes de firmar la recepción, ¿qué condición me indica que puedo aceptar y transportar legalmente esta carga?","options":["Cada paquete está correctamente etiquetado y no muestra señales de fuga","Cada paquete ha sido abierto para que yo mismo confirme el contenido","Los paquetes están pintados de un color brillante para que otros conductores los vean","Los paquetes están apilados muy por encima de la cabina, donde puedo vigilarlos"],"explanation":"Un envío de materiales peligrosos solo puede aceptarse cuando cada paquete está debidamente etiquetado y no muestra señales de fuga."},"112":{"q":"Estoy cargando un remolque mixto en un muelle de distribución. Mis documentos de embarque indican varios tambores de un material venenoso (tóxico) de Clase 6.1 que transportaré por todo el país. El supervisor del muelle quiere llenar el espacio restante del remolque para ahorrarse un segundo viaje. De las cargas que me ofrece, ¿cuál tengo prohibido cargar junto a mis tambores de veneno?","options":["Tarimas de fertilizante agrícola en sacos con destino a la misma región","Cajas de alimentos envasados para consumo humano y alimento para animales para un almacén de comestibles","Tambores sellados adicionales del mismo material venenoso de Clase 6.1","Cajas de envases de embalaje plásticos vacíos y sin etiquetar"],"explanation":"Los materiales venenosos (tóxicos) de la Clase 6.1 nunca deben cargarse ni transportarse en el mismo vehículo con alimentos o piensos para personas o animales."},"113":{"q":"Estoy cargando en mi remolque un envío mixto de materiales peligrosos compuesto por corrosivos y oxidantes, y necesito confirmar si estos dos materiales pueden viajar uno al lado del otro o deben mantenerse separados. ¿Qué referencia me indica qué materiales peligrosos NO se pueden cargar juntos en el mismo vehículo?","options":["La columna HM del documento de embarque, ya que las marcas 'X' indican qué cargas deben mantenerse separadas","La Guía de Respuesta a Emergencias (ERG), ya que enumera qué materiales reaccionan entre sí","La tabla de segregación (separación), ya que especifica qué materiales no se pueden cargar juntos","La Tabla 1 de las reglas de carteles, ya que enumera los materiales que requieren carteles en cualquier cantidad"],"explanation":"La tabla de segregación (separación) indica al conductor qué materiales peligrosos no pueden cargarse ni transportarse juntos."},"114":{"q":"Estoy cargando un remolque que ya lleva varios bidones de un oxidante de Clase 5, y el supervisor del muelle me entrega cuatro tarimas más para acomodar en el mismo espacio. Para mantener la carga segura, ¿cuál de estos artículos debo asegurarme de NO estibar justo al lado de los bidones de oxidante?","options":["Una tarima de garrafas selladas llenas de agua","Una tarima de bidones de plástico vacíos","Una tarima de arena ensacada","Una tarima de latas de solvente inflamable"],"explanation":"Los oxidantes de la Clase 5 liberan oxígeno y pueden intensificar o iniciar un incendio, por lo que deben mantenerse alejados de los materiales inflamables."},"115":{"q":"Mientras cargo mi remolque con carteles de materiales peligrosos, el expedidor me entrega dos artículos HazMat que la tabla de segregación dice que debo mantener separados, y pregunta por qué no pueden ir uno al lado del otro. Según el manual, ¿cuál es la MEJOR razón por la que estos materiales incompatibles deben separarse?","options":["Colocados juntos podrían reaccionar entre sí, incendiarse o liberar un gas peligroso","Mantenerlos juntos superaría el umbral de carteles de 1,001 libras","Mezclarlos emborronaría el nombre de embarque y la clase de peligro en los documentos","Apilarlos juntos bloquearía los triángulos reflectantes guardados en la parte trasera"],"explanation":"Los materiales peligrosos incompatibles se mantienen separados porque, si se combinan, podrían reaccionar, incendiarse o liberar un gas peligroso."},"116":{"q":"Estoy cargando un envío mixto de materiales peligrosos y mi documentación incluye un bidón de un compuesto de cianuro y varios recipientes de ácido corrosivo (Clase 8) que van al mismo cliente. ¿Qué decisión de carga me mantiene en cumplimiento y seguro?","options":["Cargarlos uno al lado del otro en el mismo compartimento para que permanezcan con sus documentos de embarque correspondientes","Mantener los cianuros y los ácidos separados y nunca cargarlos juntos en la misma carga","Cargarlos juntos solo si aseguro ambos dentro de un único contenedor exterior sellado","Cargarlos juntos siempre que cruce las vías del ferrocarril sin cambiar de marcha"],"explanation":"Los cianuros y los ácidos nunca deben cargarse juntos porque el contacto libera gas de cianuro de hidrógeno mortal."},"117":{"q":"Transporta una carga de corrosivos con carteles (placards) cuando percibe un olor penetrante y nota una mancha húmeda que se extiende debajo de un tambor en su remolque. Se detiene en el acotamiento y confirma que el paquete tiene una fuga. Antes de hacer cualquier otra cosa, ¿cuál es su PRIMERA prioridad?","options":["Abrir el tambor con fuga para identificar el químico que contiene y luego consultar la Guía de Respuesta a Emergencias para hallar el nombre de embarque correcto","Usar agua de su reserva para diluir y arrastrar el producto derramado hacia el desagüe pluvial más cercano antes de que se extienda más","Detener el vehículo, asegurar el área alrededor de la fuga y mantener a los curiosos y demás personas bien alejados del lugar","Continuar despacio hasta el sitio de entrega, donde el personal capacitado y el equipo adecuado podrán contener y descargar el tambor con fuga"],"explanation":"Ante cualquier fuga de materiales peligrosos, la primera acción es detenerse, asegurar el área y mantener a las personas bien alejadas del lugar."},"118":{"q":"Usted transporta una carga de corrosivos con placas reglamentarias cuando uno de los tambores comienza a tener una fuga y a liberar vapor en una parada al borde de la carretera durante una tarde con mucho viento. Después de haber advertido a los demás y mantener alejada a la gente, ¿dónde debe ubicarse mientras espera que lleguen los servicios de emergencia y CHEMTREC?","options":["Justo a sotavento del remolque para poder vigilar de cerca el tambor con fuga","Junto a las puertas de la carga para entregar rápido los documentos de embarque","Cuesta abajo del derrame para que el líquido escurra lejos de donde usted está","Bien a barlovento del vehículo y a una distancia segura de la carga con fuga"],"explanation":"En una emergencia con materiales peligrosos, manténgase a barlovento y a una distancia segura para que los vapores se alejen de usted en lugar de acercarse."},"119":{"q":"Estoy transportando una carga con rótulos de corrosivos cuando un tambor empieza a tener una fuga y los vapores comienzan a esparcirse por el acotamiento. Ya advertí a los demás, mantuve a la gente alejada e impedí que se fumara cerca. Ahora necesito orientación técnica experta sobre cómo manejar este químico en específico. ¿A quién debo contactar para obtener esa ayuda experta?","options":["A CHEMTREC o a los servicios locales de emergencia, que pueden dar orientación experta sobre el manejo del químico","A la oficina de despacho de mi transportista, ya que el transportista es quien debe encargarse de reportar el incidente","Al expedidor que clasificó y empacó los tambores, ya que él preparó los documentos de embarque","A nadie por teléfono — la Guía de Respuesta a Emergencias (ERG) por sí sola cubre cada paso que necesito seguir"],"explanation":"Para obtener orientación experta en tiempo real sobre el manejo de un químico con fuga, comuníquese con CHEMTREC o con los servicios de emergencia locales."},"120":{"q":"Transporta una carga de líquido inflamable con carteles (placards) por una carretera rural de Texas cuando nota llamas saliendo de debajo del remolque. Se detiene en el arcén y el fuego se está extendiendo claramente. Tiene un extintor clasificado para incendios pequeños, pero las llamas ya están alcanzando el área de carga. ¿Qué debe hacer PRIMERO?","options":["Abrir las puertas del remolque para revisar la carga y dejar salir el calor y el humo antes de que el fuego crezca más","Alejarse a una distancia segura del vehículo y luego llamar a los servicios de emergencia y notificar a CHEMTREC","Vaciar el extintor sobre las llamas del área de carga y quedarse cerca por si el fuego se reaviva","Quedarse en la cabina y mantener el motor encendido para poder alejar el camión de las llamas que se extienden"],"explanation":"Nunca combata solo un incendio de carga de materiales peligrosos; aléjese a una distancia segura del vehículo y luego llame a los servicios de emergencia y notifique a CHEMTREC."},"121":{"q":"Estoy transportando una carga rotulada de corrosivos cuando noto que gotea líquido de un tambor y se acumula bajo mi remolque en un área de descanso. Ya alejé a las personas, dejé de fumar y notifiqué a los servicios de emergencia. ¿Cuál es la ÚNICA cosa que debo hacer respecto a mover el vehículo con fuga?","options":["Conducirlo despacio hasta la próxima parada de camiónes para que un mecánico selle el tambor que tiene fuga","Reposicionarlo lo justo para terminar de despejar la rampa de salida del área de descanso","Dejarlo donde está a menos que un oficial me ordene moverlo para proteger vidas","Sacarlo rápido del estacionamiento para alejar el derrame de los demás camiones estacionados"],"explanation":"Nunca mueva un vehículo con materiales peligrosos que tiene fugas por su propio criterio; déjelo donde está a menos que una autoridad le ordene moverlo para proteger vidas."},"122":{"q":"Estoy transportando corrosivos con placas cuando noto que el producto se fuga de un tambor y se acumula en el arcén donde me he detenido. Tengo mi Guía de Respuesta a Emergencias (ERG) y un teléfono. ¿Cuál debe ser mi PRIMERA prioridad mientras espero a los servicios de emergencia?","options":["Echar tierra suelta y grava sobre el charco para que el corrosivo se absorba y deje de moverse","Regar el derrame con agua para diluirlo y empujarlo hacia la cuneta y lejos","Encender triángulos reflectantes alrededor del charco y colocar una bengala a barlovento para marcar la fuga","Mantener a los curiosos alejados de la zona y actuar para impedir que la fuga se siga extendiendo"],"explanation":"En un incidente con materiales peligrosos, mantenga a las personas alejadas y evite que el derrame se extienda hasta que lleguen los rescatistas capacitados; no intente limpiarlo usted mismo."},"123":{"q":"Estoy transportando una carga de materiales peligrosos con carteles (placards) cuando se desata un incendio bajo mi remolque en un área de descanso. Antes de actuar o hablar con la dotación de bomberos que responde, ¿cuál es el uso correcto de mis documentos de embarque y la Guía de Respuesta a Emergencias (ERG)?","options":["Identificar exactamente qué material transporto y los peligros específicos que representa, para que los socorristas puedan reaccionar de forma segura","Demostrar al transportista que la carga se cargó y documentó correctamente antes del viaje","Encontrar la ruta de estacionamiento de materiales peligrosos aprobada más cercana para mover el remolque en llamas fuera del lugar","Confirmar que la carga pesa 1,001 lb o más y, por lo tanto, requiere carteles legalmente"],"explanation":"Los documentos de embarque y la GRE identifican el material exacto y sus peligros específicos para que usted y los rescatistas puedan reaccionar de forma segura."},"124":{"q":"Un tambor en su remolque con carteles de materiales peligrosos se ha partido y está derramándose sobre el arcén. Ya se ha detenido en el arcén, ha colocado sus triángulos reflectantes y está manteniendo alejados a los curiosos mientras espera a los servicios de emergencia. Uno de los curiosos enciende un cigarrillo, y otro conductor que se detuvo a ayudar pregunta si está bien fumar rápidamente ya que está bastante detrás de su camión. ¿Cuál es la acción correcta respecto a fumar en este incidente?","options":["Permitir un cigarrillo rápido siempre que todos se mantengan al menos a 25 pies detrás del remolque con fugas","Prohibir fumar por completo y pedir a todos los presentes que apaguen cualquier cigarrillo de inmediato","Permitir fumar solo al conductor que se detuvo a ayudar, ya que los ayudantes están exentos de la regla","Permitir fumar solo en el lado de barlovento, lejos de donde el producto se derrama sobre el arcén"],"explanation":"Nunca se permite fumar en un incidente con materiales peligrosos porque el producto que tiene fugas o sus vapores pueden ser inflamables, así que toda llama o brasa debe apagarse de inmediato."},"125":{"q":"Estoy transportando una carga con carteles (placas) de materiales corrosivos cuando un contenedor se rompe y el producto comienza a derramarse sobre el arcén de una carretera rural. Después de haber advertido a los demás, mantener a las personas alejadas del derrame y evitar que alguien fume cerca, la ley exige que el incidente se reporte. ¿A quién debe reportarse este incidente, según lo requerido?","options":["Solo al expedidor (shipper), ya que fue el expedidor quien clasificó, empacó y preparó los documentos de embarque y, por lo tanto, es el responsable del contenido del contenedor","A nadie, siempre que yo personalmente contenga la fuga, enfríe la zona y documente los daños con fotos antes de continuar hacia el punto de entrega","A las autoridades correspondientes, como los servicios de emergencia o CHEMTREC, mientras que el transportista (carrier) presenta el reporte de incidente exigido ante los organismos involucrados","Solo a la estación de televisión o radio local más cercana, para que otros conductores de la zona queden advertidos y eviten el tramo afectado de la carretera"],"explanation":"Notifique a las autoridades correspondientes, como los rescatistas o CHEMTREC, mientras el transportista presenta el informe de incidente requerido a las agencias involucradas."},"126":{"q":"Usted transporta una carga de líquido inflamable con carteles de identificación (placards) por la ciudad y su GPS ofrece una ruta rápida que pasa por un túnel largo de la autopista y un centro urbano densamente poblado, ahorrando 20 minutos. ¿Qué opción cumple mejor con la planificación segura de rutas para materiales peligrosos?","options":["Tomar la ruta del túnel y el centro urbano, ya que es la más corta y ahorra más tiempo","Seguir la ruta pero saltarse la estación de pesaje obligatoria para no llamar la atención sobre la carga","Tomar la ruta pero planear estacionar dentro del centro urbano para volver a revisar los carteles","Rechazar esa ruta y elegir un camino que evite el túnel y el centro urbano densamente poblado"],"explanation":"Al planificar la ruta de materiales peligrosos, evite túneles y zonas muy pobladas porque una fuga o incendio allí aumenta el peligro para el público."},"127":{"q":"Estoy transportando una carga de líquido inflamable con carteles (placards) por un condado rural de Texas, en una ruta con varios tipos de cruces. Para cumplir con las normas de materiales peligrosos del DPS, ¿ante cuál de las siguientes situaciones estoy OBLIGADO a detener por completo el vehículo antes de continuar?","options":["Ante un cruce de vías de ferrocarril, donde debo detenerme entre 15 y 50 pies antes del riel más cercano","Ante una señal amarilla intermitente de precaución en una intersección rural de cuatro vías","Ante una estación de combustible abierta, antes de entrar a llenar el tanque de diésel","Ante cada entrada privada y acceso a campo que paso a lo largo de la ruta"],"explanation":"Un vehículo con carteles de peligro debe detenerse por completo de 15 a 50 pies antes del riel más cercano en un cruce de ferrocarril y nunca cambiar de marcha al cruzar."},"128":{"q":"Estoy transportando una carga con rótulos (placards) de explosivos de la División 1.2 por Texas y necesito hacer una parada rápida para almorzar. No llevo un segundo conductor. Según las reglas del DPS, ¿qué estoy obligado a hacer con esta carga?","options":["Puedo dejar el camión estacionado y cerrado con llave en el lote del restaurante mientras como adentro, siempre que las puertas estén aseguradas","Debo mantener la carga de explosivos atendida en todo momento, así que no puedo dejarla sin vigilancia para entrar a comer","Puedo dejarla sin vigilancia en paradas cortas siempre que estacione a más de 300 pies de cualquier edificio","Puedo dejarla sin vigilancia si apago el motor y pongo el freno de estacionamiento antes de alejarme"],"explanation":"Los explosivos de la división 1.1, 1.2 y 1.3 nunca deben dejarse sin vigilancia; el conductor o un encargado calificado debe permanecer con el vehículo en todo momento."},"129":{"q":"Transporto una carga de líquido inflamable con placas (rótulos de peligro) y necesito detenerme a pasar la noche. Más adelante veo una fogata al borde del camino que alguien dejó encendida cerca de un área de descanso. Antes de elegir un lugar para estacionar, ¿qué distancia mínima exige el manual que mantenga entre mi vehículo con placas y ese fuego abierto?","options":["Al menos 25 pies, la misma distancia exigida para no fumar cerca de la carga","Al menos 50 pies, igual a la distancia máxima de parada antes de las vías del tren","Al menos 300 pies entre el vehículo y el fuego abierto","No se exige una distancia fija mientras el motor esté apagado"],"explanation":"Un vehículo con carteles de peligro debe estacionarse al menos a 300 pies de un fuego abierto porque una llama abierta es un peligro directo de ignición para la carga."},"130":{"q":"Estoy transportando una carga de material peligroso con carteles (placards) por una autopista interestatal que no conozco cuando mi GPS me desvía a un camino que nunca he conducido. En este tramo pasaré por una parada de camiones concurrida, una estación de pesaje abierta y un largo paso subterráneo excavado a través de una montaña. ¿A cuál de estos lugares es MÁS probable que se me prohíba legalmente entrar con mi carga peligrosa, obligándome a buscar una ruta alterna?","options":["La parada de camiones, porque los vehículos con carteles no pueden estacionarse donde se reúne el público","La estación de pesaje abierta, porque las cargas peligrosas deben evitar todas las básculas de inspección","Nada aquí está restringido, ya que una ruta interestatal señalizada siempre permite el material peligroso","El paso subterráneo, porque algunos materiales peligrosos están prohibidos en ciertos túneles"],"explanation":"Evite los túneles en una ruta de materiales peligrosos porque las autoridades pueden prohibir legalmente ciertos materiales peligrosos en túneles específicos por completo."},"131":{"q":"Estoy transportando una carga de corrosivos con carteles de peligro a través de la ciudad cuando me topo con obras de construcción inesperadas en la autopista que han cerrado dos carriles y han generado un atasco de kilómetros en mi ruta asignada para materiales peligrosos. Una señal de desvío apunta hacia un camino más corto a través del centro comercial del centro de la ciudad, y mi GPS sugiere un atajo aún más rápido por un puente bajo. ¿Qué criterio debe guiar por dónde conduzco?","options":["Permanecer en la ruta designada u obligatoria para materiales peligrosos, regresando a ella en cuanto las condiciones del camino lo permitan","Tomar el desvío por el centro de la ciudad porque seguir las señales de desvío indicadas siempre prevalece sobre las reglas de rutas para materiales peligrosos","Seguir el atajo del GPS por el puente bajo, ya que ahorra más tiempo y evita la peor congestión","Elegir el camino físicamente más corto, porque la ley solo exige minimizar el total de millas recorridas"],"explanation":"Los conductores de materiales peligrosos deben seguir la ruta designada u obligatoria y volver a ella en cuanto las condiciones del camino lo permitan, sin importar atajos o tráfico."},"132":{"q":"Transporto una carga con carteles de identificación (placards) y necesito detenerme unos minutos para atender una llamada y estirar las piernas. Hay cuatro lugares cerca de mi ruta. ¿Cuál debería EVITAR elegir para estacionar?","options":["Un amplio apartadero de grava en un tramo rural sin ninguna estructura a la vista","El borde de la acera justo al lado de la entrada de un túnel donde se reúnen peatones","Un estacionamiento de camiones señalizado, bien apartado de la entrada principal del edificio","Un arcén junto a un campo abierto, a más de 5 pies de la parte transitada de la carretera"],"explanation":"Las cargas con carteles deben mantenerse lejos de túneles, puentes y multitudes, por lo que una entrada de túnel con peatones reunidos combina dos peligros que evitar."},"133":{"q":"Transporta explosivos de la División 1.2 y su indicador de combustible está bajo, por lo que entra a una parada de camiones para repostar. Mientras se llena el tanque, ¿cuál de las siguientes acciones cumple MEJOR con sus responsabilidades para esta carga?","options":["Dejar el motor en ralentí junto al surtidor para terminar de llenar y salir rápido, y entrar a pagar","Estacionar justo al lado de la concurrida entrada de la tienda, bajo las luces, para que el remolque cargado quede a la vista del personal","Permanecer junto al vehículo todo el tiempo y mantenerlo alejado de las multitudes y los lugares de reunión","Cerrar la cabina con llave, dejar el camión en el surtidor e ir adentro por un café mientras el corte automático termina de cargar"],"explanation":"Los explosivos de las divisiones 1.1, 1.2 y 1.3 nunca pueden dejarse sin vigilancia, por lo que el conductor debe permanecer con el vehículo y mantenerlo lejos de multitudes."},"134":{"q":"Ya tengo una CDL Clase A y acaban de contratarme para transportar cargas con placas (rótulos) de líquido corrosivo. Mi compañero dice que lo único que debo hacer antes de poder empezar legalmente es aprobar un breve examen escrito en la oficina del DPS para añadir el endoso. ¿Cuál de los siguientes es el ÚNICO requisito que no puedo omitir para obtener el endoso de Materiales Peligrosos (HazMat, H) que necesito?","options":["Completar un examen de manejo en la carretera específicamente con un remolque cisterna con placas (rótulos)","Tener el endoso durante al menos 30 días antes de transportar cualquier carga con placas","Renovar mi certificado médico del DOT dentro de la misma semana en que añado el endoso","Aprobar una evaluación de amenaza de seguridad de la TSA, que incluye una verificación de antecedentes y toma de huellas dactilares"],"explanation":"El endoso HazMat exige aprobar una evaluación de amenazas de seguridad de la TSA que incluye verificación de antecedentes y toma de huellas, no solo un examen escrito."},"135":{"q":"Estoy transportando una carga con carteles (placards) de líquido inflamable y necesito hacer una parada rápida en un restaurante de carretera para almorzar. ¿Cuál de las siguientes acciones me pondría en infracción de las normas de materiales peligrosos?","options":["Dejar el vehículo con carteles sin vigilancia en el estacionamiento mientras me siento adentro del restaurante a comer","Mantener mis documentos de embarque en el bolsillo de la puerta y al alcance mientras estoy estacionado","Inspeccionar las llantas antes de volver a entrar a la autopista","Estacionarme a más de 5 pies de la parte transitada de la carretera"],"explanation":"Un vehículo con materiales peligrosos y carteles nunca debe dejarse sin vigilancia, por lo que alejarse del camión mientras la carga queda sin custodia es una infracción."},"136":{"q":"Transporto una carga rotulada (placardada) de corrosivos y me detengo a pasar la noche en una parada de camiones. Cuando regreso a mi unidad por la mañana para comenzar mi inspección en ruta, ¿cuál de las siguientes observaciones debería preocuparme MÁS como un problema de seguridad que estoy específicamente entrenado para vigilar?","options":["Se ha formado una fina capa de escarcha en el parabrisas durante la noche","Un sello de la carga ha sido cortado y un rótulo (placard) parece despegado parcialmente","El indicador de combustible marca un poco menos que la noche anterior","Ahora hay otro camión estacionado en el espacio junto al mío"],"explanation":"Un sello de carga cortado y un cartel parcialmente despegado son señales clásicas de manipulación o robo que los conductores de materiales peligrosos deben vigilar."},"137":{"q":"Acaban de contratarme en un transportista que lleva cargas de materiales peligrosos que requieren rótulos (placards), y durante la orientación mi despachador me entrega una carpeta de documentos de la empresa y dice que las normas federales exigen que muchos transportistas como el nuestro mantengan uno de estos por escrito. ¿A qué documento se refiere muy probablemente como un requisito reglamentario?","options":["Un horario diario por escrito de almuerzos y paradas de descanso que cada conductor debe firmar antes de salir del patio","Una lista por escrito de las estaciones de combustible preferidas por la empresa aprobadas para vehículos con rótulos","Un plan de seguridad por escrito que aborda cómo la empresa se protege contra el robo y el uso indebido de materiales peligrosos","Un registro por escrito de las emisoras de radio que los conductores pueden escuchar mientras transportan la carga"],"explanation":"Muchos transportistas de materiales peligrosos deben elaborar y mantener un plan de seguridad escrito que abarque al personal, el acceso no autorizado y la seguridad en ruta."},"138":{"q":"Es invierno y mi remolque está equipado con un calefactor de carga automático. Antes de salir de la terminal, el despachador me entrega una carga y me dice que la mantenga caliente durante el trayecto. ¿Con cuál de las siguientes cargas NO debo, bajo ninguna circunstancia, hacer funcionar el calefactor de carga?","options":["Una carga sellada de alimentos enlatados en caja seca que podría congelarse con el frío","Un remolque vacío que estoy reposicionando hacia el siguiente punto de recogida","Una carga paletizada de agua potable embotellada sensible a la congelación","Una carga de bidones de líquido inflamable que desprenden vapores al calentarse"],"explanation":"No debe usarse un calentador de carga con cargas de líquido inflamable, porque los vapores que estas liberan al calentarse pueden inflamarse y causar incendio o explosión."},"140":{"q":"Estoy cargando un envío que requiere carteles (placards) y los documentos de embarque incluyen una entrada que mi transportista marcó como material \"prohibido\" (forbidden) según las normas de materiales peligrosos. Antes de firmar la recepción de la carga, ¿qué afirmación describe correctamente mi obligación respecto a esa entrada?","options":["No debo transportar este material de ninguna manera, porque los materiales prohibidos nunca pueden trasladarse en ningún vehículo bajo ninguna condición.","Puedo transportarlo siempre que coloque los carteles correctos en los cuatro lados y mantenga los documentos al alcance.","Puedo transportarlo solo si su peso bruto total se mantiene por debajo de 1,001 libras durante el viaje.","Puedo transportarlo una vez que el expedidor agregue a los documentos el nombre de embarque correcto, la clase de peligro y el número de identificación."],"explanation":"Los materiales prohibidos nunca pueden transportarse bajo ninguna condición, por lo que la única acción correcta es negarse por completo a moverlos."},"141":{"q":"Estoy preparando una carga y el remitente me dice que parte de ella califica como un envío de \"cantidad limitada\" (limited quantity). Antes de firmar por ella, ¿cuál de las siguientes opciones debería esperar que sea VERDADERA respecto a esa parte de la carga?","options":["Como es una categoría especial, está exenta de toda regla de Materiales Peligrosos y puedo transportarla sin ningún documento","Involucra cantidades más pequeñas del material, por lo que conlleva requisitos reducidos de embalaje y marcado","Siempre exige la cantidad máxima de carteles (placards) en los cuatro lados sin importar el peso","El término solo se aplica a líquidos, así que cualquier sólido en la carga no puede ser de cantidad limitada"],"explanation":"Una cantidad limitada se transporta en menores volúmenes que quedan por debajo de ciertos umbrales, por lo que tiene requisitos reducidos de embalaje y marcado."},"142":{"q":"Estoy haciendo mi inspección previa al viaje en una carga de materiales peligrosos y abro la parte trasera para comparar cada caja con mis documentos de embarque. El expedidor selló y empacó todo, pero aún necesito confirmar qué debe contener cada paquete individual. Para hacer coincidir las cajas con el nombre de embarque correcto, la clase de peligro y el número de identificación en mis documentos, ¿qué debería esperar encontrar impreso en cada paquete?","options":["Una copia de los documentos de embarque pegada a cada caja, para que el paquete y la documentación siempre viajen juntos","El nombre del transportista y mi nombre completo, para que los rescatistas sepan qué conductor y empresa transportan la carga","Una etiqueta de peligro y marcas que identifican el material, para poder verificar el paquete con las entradas de mis documentos de embarque","Una etiqueta de precio minorista con el costo del producto, para que el destinatario confirme el valor del envío en la entrega"],"explanation":"El expedidor etiqueta y marca cada paquete con su clase de peligro y nombre de embarque para que puedas cotejar cada paquete con tus documentos de embarque."},"143":{"q":"Estoy cargando un envío de material radiactivo de Clase 7 y el expedidor revisa conmigo las etiquetas de los paquetes antes de que firme los documentos. Me señala un número impreso en la etiqueta que tendré que tener en cuenta cuando calcule cuánto de este material puede ir junto en mi remolque. ¿Cuál de las siguientes es esa cifra determinante que los paquetes radiactivos pueden llevar?","options":["Una clasificación de peligro de inhalación tóxica que exime la carga de llevar carteles en cualquier cantidad","Un código de autorización que permite a la carga evitar las estaciones de pesaje y las restricciones de ruta","Un límite de cantidad reportable (RQ) que elimina la necesidad de cualquier marca en el paquete","Un límite de índice de transporte que restringe cuánto se puede llevar junto"],"explanation":"Los paquetes radiactivos de Clase 7 llevan un índice de transporte cuyo límite controla cuánto material radiactivo se puede cargar y transportar junto."},"144":{"q":"Estoy cargando un envío con carteles de peligro que los documentos de embarque identifican como material reactivo, y debo decidir dónde y cómo colocarlo dentro del remolque para el viaje. Para manejarlo de forma segura, ¿de cuál de los siguientes debo mantener alejado este material reactivo?","options":["De fuentes de calor, del agua o la humedad, y de cualquier otro material reactivo que se transporte","De las mantas o el acolchado suaves y tibios que se usan para amortiguar la carga durante el transporte","De cualquier espacio amplio, vacío y abierto del remolque donde el paquete pudiera desplazarse","De la exposición directa a la luz muy brillante que entra por las puertas del remolque"],"explanation":"Los materiales reactivos deben mantenerse lejos del calor, el agua o la humedad y otros materiales reactivos, ya que el contacto puede provocar una reacción violenta."},"145":{"q":"Me asignan recoger un tanque cargado con nitrógeno líquido refrigerado, un líquido criogénico (muy frío), para un viaje largo. Al inspeccionar el remolque antes de aceptar el envío, ¿qué condición me indica que la carga se maneja correctamente para este tipo de mercancía?","options":["El tanque está completamente sellado sin ventilación para que el frío no escape y el producto siga congelado","El tanque usa equipo especial aislado y tiene una válvula de ventilación que funciona para liberar de forma segura la presión acumulada","Una pequeña unidad calefactora está montada dentro del tanque para evitar que el líquido congele y bloquee las válvulas","El tanque es un remolque estándar de carga seca a granel sin accesorios adicionales, ya que el frío no requiere cuidados especiales"],"explanation":"Los líquidos criogénicos absorben calor constantemente y acumulan presión, por lo que requieren equipo aislado especial y un respiradero funcional para liberar esa presión de forma segura."},"146":{"q":"Mi remolque con carteles de identificación de peligro vuelca en una carretera rural de Texas y un tambor empieza a tener fugas. La primera dotación de bomberos llega antes de que pueda decir mucho, toma mis documentos de embarque y de inmediato lee en voz alta la clase de peligro y el número de identificación ONU/NA indicado para la carga. ¿Cuál es la razón PRINCIPAL por la que esa clase de peligro y ese número de identificación son tan importantes para los socorristas en el lugar?","options":["Permiten que los socorristas calculen si mi carga superaba el umbral de 1,001 libras que exigía colocar los carteles en primer lugar","Demuestran que yo, el conductor, ya llamé a CHEMTREC y que el transportista presentó el informe del incidente antes de que llegara la ayuda","Permiten que los socorristas identifiquen rápidamente cuál es exactamente el peligro para reaccionar de forma correcta ante el material","Confirman que los carteles estaban colocados en los cuatro lados y eran legibles desde la dirección a la que apuntaban"],"explanation":"El nombre de embarque, la clase de peligro y el número de identificación permiten a los socorristas identificar rápidamente el peligro exacto y reaccionar correctamente ante el material."},"148":{"q":"Ya tengo una licencia CDL Clase A de Texas y llevo dos años transportando carga seca. El próximo mes mi transportista quiere que empiece a llevar cargas que requieren rótulos (placards) en los cuatro lados del remolque. Antes de poder aceptar legalmente ese primer viaje con rótulos, ¿qué debo completar?","options":["Nada adicional: una licencia CDL Clase A por sí sola ya autoriza cualquier carga con rótulos de materiales peligrosos","Solo el endoso de Cisterna (N), ya que la carga con rótulos se transporta a granel en tanques","Solo un endoso de dobles/triples (T) para cubrir el peso adicional del remolque","El endoso de Materiales Peligrosos (H), que exige aprobar una evaluación de amenaza de seguridad de la TSA con toma de huellas dactilares"],"explanation":"Transportar una cantidad de material peligroso que requiere rótulos exige el endoso HazMat (H), que solo se emite tras aprobar una evaluación de amenaza de seguridad de la TSA con toma de huellas."},"149":{"q":"Acabo de recoger una carga de corrosivos con rótulos (placards). Los documentos de embarque tienen un error en la clase de peligro, y lo noto antes de salir de la terminal. Un despachador me dice: «Ese papeleo es 100% problema del expedidor; tu única tarea es conducir». Según las reglas de materiales peligrosos, ¿qué afirmación es VERDADERA?","options":["El transporte seguro es una responsabilidad compartida: el expedidor, el transportista y el conductor tienen cada uno deberes específicos, y no debo transportar a sabiendas un envío mal marcado.","Como solo el expedidor clasifica y prepara los documentos, el conductor no tiene responsabilidad por los errores en el papeleo y puede transportar legalmente la carga tal como está.","Una vez que el transportista despacha la carga, toda la responsabilidad legal del envío se transfiere al transportista, así que el conductor puede confiar por completo en el despacho.","El único deber del conductor es conducir con seguridad, por lo que la exactitud del papeleo es tarea exclusiva del expedidor y nunca algo que el conductor deba verificar."],"explanation":"La seguridad de materiales peligrosos es una responsabilidad compartida entre el expedidor, el transportista y el conductor, y debes negarte a transportar a sabiendas un envío con fugas o mal marcado."},"150":{"q":"Estoy recogiendo una carga de cilindros de propano comprimido y el supervisor del muelle me entrega los documentos de embarque que muestran el material como Clase de Riesgo 2. Antes de colocar los rótulos, quiero confirmar qué representa realmente la Clase 2. ¿Cuál afirmación es correcta?","options":["La Clase 2 abarca corrosivos, como las cargas de ácido de batería e hidróxido de sodio que a veces transporto.","La Clase 2 abarca gases, incluidos los materiales gaseosos inflamables, no inflamables y venenosos como mi propano.","La Clase 2 abarca explosivos, por lo que esta carga se rige por las mismas reglas que la dinamita y los fuegos artificiales.","La Clase 2 abarca materiales radiactivos, razón por la cual estos cilindros necesitan blindaje adicional."],"explanation":"La Clase de peligro 2 son los gases, subdivididos en 2.1 inflamables, 2.2 no inflamables y 2.3 gas venenoso, y el propano es un gas inflamable de esta clase."},"151":{"q":"Estoy cargando bidones de ácido de batería para una entrega, y los documentos de embarque indican la clase de peligro como 8. Antes de colocar los rótulos en mi remolque, necesito confirmar qué tipo de peligro representa realmente esta carga. ¿Cuál de las siguientes opciones describe correctamente un material de Clase de Peligro 8?","options":["Un gas comprimido o licuado que puede fugarse y crear un peligro respiratorio","Una sustancia tóxica que puede envenenar a una persona por contacto con la piel o inhalación","Un material corrosivo que puede quemar químicamente la piel, el metal u otros materiales","Un material explosivo que puede detonar por calor, impacto o fricción"],"explanation":"La Clase de peligro 8 son los corrosivos, materiales como el ácido de batería que queman o corroen químicamente la piel, el metal y otros materiales."},"152":{"q":"Estoy cargando mi remolque cuando el expedidor me entrega los documentos de un envío marcado como 'Clase de Peligro 7', con un número ONU y el nombre de embarque apropiado. Antes de colocar los carteles, necesito entender exactamente qué tipo de peligro transporto. Según el sistema de clases de peligro, ¿qué me indica la Clase 7 sobre esta carga?","options":["Es un material corrosivo, así que los recipientes con fugas podrían quemar la piel y corroer las superficies metálicas","Es un líquido inflamable, así que debo mantener todas las fuentes de ignición y llamas abiertas lejos de él","Es un gas comprimido o venenoso, así que una liberación de presión podría crear un peligro de inhalación","Es un material radiactivo, así que transporto una carga que emite radiación y requiere manejo especial"],"explanation":"La Clase de peligro 7 siempre significa materiales radiactivos, por lo que la carga emite radiación y requiere manejo especial sin importar el nombre de embarque mostrado."},"153":{"q":"Estoy cargando un remolque y mis documentos de embarque indican un material de Clase de Peligro 5. Antes de colocar los rótulos (placards), quiero confirmar qué tipo de peligro presenta realmente esta carga. Un material de Clase 5 es uno que:","options":["Es un oxidante o peróxido orgánico que puede intensificar un incendio al liberar oxígeno","Es un corrosivo que puede destruir el tejido de la piel o carcomer el acero y el aluminio","Es un explosivo capaz de una detonación en masa si se expone al calor o a un golpe","Es un gas comprimido que puede ser inflamable, no inflamable o venenoso"],"explanation":"Los oxidantes y peróxidos orgánicos de la Clase de Riesgo 5 liberan oxígeno, lo que puede iniciar o intensificar un incendio incluso sin una fuente de ignición externa."},"154":{"q":"Estoy cargando una pequeña cantidad de material con Peligro de Inhalación Tóxica (PIH) en el muelle, y el peso total está muy por debajo de las 1,001 libras. Mi despachador me dice que la carga es tan ligera que puedo transportarla como un flete normal. ¿Cuál es la forma correcta de manejar este envío de PIH?","options":["Como la carga pesa menos de 1,001 libras, no se requieren carteles y puedo transportarla como flete ordinario","Debo manejarla con precaución adicional y colocar los carteles apropiados, porque los materiales PIH requieren carteles en cualquier cantidad","Solo necesito carteles si cruzo una línea estatal; las cargas PIH dentro del estado bajo 1,001 libras no requieren manejo especial","Debo reducir mi papeleo y omitir los documentos de embarque ya que la cantidad es muy pequeña"],"explanation":"Los materiales con Peligro por Inhalación de Veneno (PIH) son un riesgo de la Tabla 1 que requiere rótulos en cualquier cantidad, sin umbral mínimo de peso."},"155":{"q":"Estoy cargando mi remolque con varias cajas de un artículo que en el documento de embarque aparece bajo la Clase de Peligro 9. No es inflamable, no es corrosivo y no es un gas comprimido, pero aun así requirió un cartel (placard). ¿Qué afirmación describe MEJOR lo que abarca la Clase de Peligro 9?","options":["Gases comprimidos y licuados que no son inflamables bajo presión","Líquidos y sólidos corrosivos que pueden dañar la piel o el metal","Materiales peligrosos misceláneos que no encajan en las otras ocho clases","Explosivos, desde agentes de voladura hasta fuegos artificiales y detonadores"],"explanation":"La Clase de Riesgo 9 es la categoría general Misceláneos para materiales regulados que presentan un riesgo de transporte pero no encajan en las Clases 1 a 8."},"156":{"q":"Estoy preparando los documentos de embarque para una carga y la entrada indica Clase de Peligro 4. Antes de colocar los carteles, quiero confirmar qué tipo de material realmente transporto para usar el cartel correcto. ¿Cuál de las siguientes opciones describe correctamente un material de Clase 4?","options":["Un líquido inflamable como gasolina o combustible diésel","Un gas comprimido, ya sea inflamable o no inflamable","Un material corrosivo que puede dañar la piel y el metal","Un sólido inflamable que puede encenderse o arder con facilidad"],"explanation":"La Clase de Riesgo 4 abarca sólidos inflamables, incluidos los espontáneamente combustibles y los peligrosos al mojarse, que pueden encenderse o arder con facilidad."},"157":{"q":"Voy con rótulos de materiales peligrosos y me detengo en una estación de pesaje en Texas cuando un inspector señala un número de 4 dígitos, 1203, que aparece en un panel naranja de mi remolque y me pregunta qué le indica ese número. ¿Cuál es la respuesta correcta?","options":["Es el número de identificación (UN/NA) que identifica el material específico que transporto","Es el código del nombre de embarque correcto asignado a la carga por el transportista","Es el número de la clase de peligro que indica cuál de las nueve clases aplica","Es el número de la tabla de rótulos que muestra si aplica la regla de las 1,001 lb"],"explanation":"Un número de 4 dígitos en los documentos de embarque o en un rótulo es el número de identificación UN/NA que identifica el material exacto que se transporta."},"158":{"q":"Durante mi inspección previaje, un policía estatal me pide que le lea el número de identificación UN/NA de 4 dígitos de la carga que transporto para poder verificarlo en la Guía de Respuesta a Emergencias (ERG). Camino hasta el costado de mi remolque con carteles (placards) para encontrarlo. ¿Dónde se me permite correctamente leer ese número de identificación de 4 dígitos?","options":["Solo en el nombre de embarque apropiado impreso en los documentos de embarque; nunca aparece en el exterior del remolque","Ya sea directamente sobre el cartel (placard) mismo o en un panel naranja montado junto al cartel","Solo en el número de clase de peligro mostrado en la esquina inferior del cartel en forma de diamante","Solo en la placa de datos del fabricante grabada en el chasis del remolque cerca del tren de aterrizaje"],"explanation":"El número de identificación UN/NA de 4 dígitos puede mostrarse en el centro del propio rótulo o en un panel naranja colocado junto al rótulo."},"159":{"q":"En una inspección al borde de la carretera, un oficial señala el cartel (placard) en forma de diamante en la parte trasera de mi remolque y me pide que lea el número de clase de peligro que identifica lo que transporto. El cartel muestra un símbolo arriba, palabras escritas en la banda central y un solo dígito. ¿Dónde del cartel debo buscar ese número de clase de peligro?","options":["Centrado en medio del cartel, justo donde está impreso el nombre escrito del material","En la punta más alta del diamante, directamente encima del símbolo de peligro o pictograma","En la esquina inferior del diamante, debajo del símbolo y del nombre escrito del material","A lo largo del borde izquierdo o derecho del diamante, junto al símbolo de peligro"],"explanation":"En un rótulo, el número de un solo dígito de la clase de riesgo va en la esquina inferior del rombo, debajo del símbolo y del nombre escrito del peligro."},"160":{"q":"Estoy cargando mi remolque en una terminal de carga con varios paquetes no a granel, cada uno de una clase de peligro distinta de la Tabla 2, y ninguno de ellos alcanza por separado el umbral de 1,001 libras que obligaría a colocar un rótulo aparte. En lugar de colgar un rótulo diferente para cada clase, me gustaría usar un solo rótulo 'DANGEROUS' (PELIGROSO) para todo el envío mixto. ¿Bajo qué condición está realmente permitido usar ese único rótulo 'DANGEROUS'?","options":["Solo cuando cada paquete del remolque pertenece exactamente a la misma clase única de peligro","Solo cuando el remolque no transporta ningún material peligroso regulado en absoluto","Solo cuando la carga se limita a productos alimenticios de consumo enviados junto con el flete","Cuando la carga contiene dos o más clases de peligro distintas de la Tabla 2 transportadas juntas"],"explanation":"El rótulo DANGEROUS puede usarse en lugar de rótulos separados cuando una carga no a granel combina dos o más clases de riesgo de la Tabla 2."},"161":{"q":"Estoy cargando un solo tambor pequeño de un material de la Tabla 1 (un gas venenoso de la División 2.3) para un recorrido local corto. El peso total del material peligroso está muy por debajo de las 1,000 libras. Antes de salir, ¿cómo debo colocar los rótulos (placards) en el vehículo?","options":["Debo colocar los rótulos en los cuatro lados sin importar lo poco que transporte, porque los materiales de la Tabla 1 requieren rótulos en cualquier cantidad.","No necesito rótulos en este viaje, porque transporto menos del peso bruto agregado de 1,001 libras que activa la rotulación.","Solo necesito rótulos cuando mi carga peligrosa combinada alcance 1,001 libras o más, así que un solo tambor pequeño está exento.","Solo necesito rótulos si el recorrido es interestatal o entra en una zona poblada, ya que un viaje local corto no los requiere."],"explanation":"Un gas venenoso de la División 2.3 es un material de la Tabla 1 que debe rotularse en los cuatro lados en cualquier cantidad, sin importar el peso."},"162":{"q":"Estoy cargando un remolque de carga mixta y el único material peligroso a bordo es un producto de la Tabla 2. Mis documentos de embarque muestran que el peso bruto agregado suma exactamente 900 libras. Según las reglas de rótulos de DPS, ¿qué debo hacer antes de salir?","options":["Colocar rótulos en los cuatro lados, porque cualquier cantidad de un material peligroso listado en la Tabla 2 siempre requiere rótulos","No se requieren rótulos, porque los materiales de la Tabla 2 solo necesitan rótulos a partir de 1,001 libras o más de peso bruto agregado","Colocar rótulos en los cuatro lados, porque la carga supera el umbral de reporte de 100 libras para los embarques de la Tabla 2","Colocar rótulo solo en la parte trasera, ya que 900 libras es suficiente para requerir rótulos parciales pero no rótulos completos en los cuatro lados"],"explanation":"Los materiales de la Tabla 2 requieren rótulos solo cuando su peso bruto total alcanza las 1,001 libras o más."},"163":{"q":"Estoy cargando un remolque en el muelle de un expedidor y noto las advertencias de peligro en forma de diamante que el expedidor aplicó para identificar el contenido. ¿Dónde deben colocarse estas etiquetas de peligro?","options":["En los cuatro lados del remolque, legibles desde la dirección a la que apunta cada uno","En los documentos de embarque, en la columna HM junto a cada entrada","En los paquetes y contenedores individuales mismos","En la bolsa de la puerta del conductor donde se guardan los documentos"],"explanation":"El expedidor coloca las etiquetas de peligro directamente en cada paquete y contenedor individual para identificar la clase de peligro del contenido."},"164":{"q":"Estoy cargando un envío de corrosivos que requiere carteles (placards), y mi co-conductor me entrega cuatro carteles romboidales de CORROSIVO. Me dice dónde cree que van, pero quiero hacerlo bien antes de arrancar. ¿Dónde deben colocarse realmente estos carteles?","options":["Pegados a cada paquete individual y sobreembalaje dentro del remolque para que los inspectores vean el peligro al abrir las puertas","Adjuntados a los documentos de embarque en la columna HM junto al nombre de embarque correcto, la clase de peligro y el número de identificación","Sujetados a una bolsa en la puerta del conductor junto a la documentación para que queden a mi alcance mientras conduzco","Colocados en los cuatro lados del vehículo, legibles desde la dirección hacia la que apunta cada uno"],"explanation":"Los carteles de peligro se colocan en los cuatro lados del vehículo y cada uno debe ser legible desde la dirección hacia la que mira."},"165":{"q":"Mientras cargo mi remolque, tomo un paquete sellado marcado con un par de flechas negras verticales que apuntan hacia arriba en dos lados opuestos. Los documentos del expedidor están en orden, pero quiero confirmar que lo estoy colocando correctamente. ¿Qué me exigen hacer estas flechas de orientación con este paquete?","options":["Mantener el paquete siempre en posición vertical, con las flechas hacia arriba, para que los cierres queden en la parte superior","Acostar el paquete de lado para que las flechas apunten horizontalmente hacia la pared del remolque","Apilarlo como quepa, ya que las flechas solo indican dónde debe levantarlo el montacargas","Voltear el paquete boca abajo para que el extremo sellado quede apoyado contra el piso del remolque"],"explanation":"Las flechas de orientación del paquete indican que debe mantenerse en posición vertical con las flechas hacia arriba para que los cierres queden arriba."},"166":{"q":"Soy un nuevo conductor de materiales peligrosos haciendo mi revisión previaje del documento de embarque para una carga corrosiva. Puedo ver claramente el nombre de embarque apropiado y la clase de peligro listados para cada entrada. Para confirmar que la descripción está completa y cumple con las normas federales antes de salir, ¿qué información restante DEBE también aparecer en esa descripción básica de embarque?","options":["El valor total declarado en dólares de la carga corrosiva","El número de identificación (UN o NA) del material","La clasificación de peso bruto vehicular que aparece en mi CDL","La fecha de vencimiento de mi endoso de materiales peligrosos"],"explanation":"Una descripción básica de embarque completa incluye el nombre de embarque correcto, la clase de peligro y el número de identificación UN o NA, en ese orden."},"167":{"q":"Estoy revisando los documentos de embarque de una carga y noto un número romano 'II' indicado junto a la entrada del material como su Grupo de Embalaje (Packing Group). Un conductor nuevo me pregunta qué nos dice en realidad ese 'II' sobre el envío. ¿Cuál de las siguientes es la explicación correcta de lo que indica el Grupo de Embalaje?","options":["Indica el número de la clase de peligro (del 1 al 9) asignado al material","Da el peso bruto mínimo que activa el requisito de colocar rótulos (placards)","Muestra el grado relativo de peligro que presenta el material (I, II o III)","Indica el número de identificación UN/NA que sigue al nombre de embarque"],"explanation":"El Grupo de Embalaje, indicado con número romano I, II o III, señala el grado relativo de peligro que presenta el material."},"168":{"q":"Estoy cargando un envío de materiales peligrosos y el documento de embarque indica que el grupo de embalaje del material es \"PG I\" (Grupo de Embalaje I). Un conductor novato me dice que el número romano \"I\" solo significa que es el primer artículo de la lista y que representa el nivel de peligro más bajo de los tres grupos de embalaje. Antes de firmar la carga y colocar los rótulos, ¿qué me indica realmente \"Grupo de Embalaje I\" sobre el grado de peligro de este material?","options":["Indica el menor grado de peligro, ya que el Grupo de Embalaje I es el nivel más bajo y el Grupo de Embalaje III es el más peligroso","Indica solo un grado de peligro medio, ubicándose entre el Grupo de Embalaje II y el Grupo de Embalaje III","Indica que no hay peligro real y se usa únicamente para mostrar la posición del artículo en el documento de embarque","Indica el mayor grado de peligro, ya que el Grupo de Embalaje I es el más peligroso de los tres grupos de embalaje"],"explanation":"El Grupo de Embalaje I indica el mayor grado de peligro, ya que es el más peligroso de los tres grupos de embalaje."},"169":{"q":"Estoy cargando un remolque con materiales peligrosos mixtos y noto que dos de mis paquetes tienen clases de riesgo diferentes. Antes de apilarlos uno al lado del otro, saco la tabla de segregación. ¿Qué me está diciendo realmente esta tabla?","options":["Qué materiales son incompatibles y NO deben cargarse juntos en la misma carga","Qué materiales deben cargarse siempre juntos para que sus carteles (placards) coincidan","Qué materiales deben venderse o entregarse primero para reducir mi responsabilidad","Qué materiales deben etiquetarse una segunda vez antes de cerrar las puertas"],"explanation":"La tabla de segregación muestra qué materiales son incompatibles y no deben cargarse juntos en la misma carga."},"170":{"q":"Estoy en el muelle del expedidor a punto de cargar varios bidones de un material corrosivo de Clase 8 en mi remolque con carteles (placards). Al mover el primer bidón, noto una película húmeda y brillante alrededor de su costura inferior y un pequeño charco sobre la tarima. Antes de cargar CUALQUIERA de estos paquetes, ¿cuál es la única cosa más importante que mi inspección previa a la carga debe confirmar?","options":["Que cada bidón esté pintado de un color brillante y muy visible para poder localizarlo fácilmente en el remolque","Que los paquetes no tengan fugas ni estén dañados, ya que debo rechazar cualquier contenedor que muestre una fuga o rotura","Que los bidones estén apilados lo más alto posible para mantener la carga apretada y evitar que se mueva durante el viaje","Que los tapones se dejen flojos o abiertos para que la presión interna pueda ventilarse durante el trayecto"],"explanation":"Antes de cargar, inspeccione cada paquete para confirmar que no tenga fugas ni daños, y rechace cualquier contenedor que muestre una fuga o rotura."},"171":{"q":"Soy un conductor que está cargando un líquido inflamable (Clase 3) en mi remolque en un patio de terminal muy concurrido. Suceden varias cosas a mi alrededor al mismo tiempo y quiero cargar de forma segura. ¿Cuál de los siguientes debo asegurarme de mantener LEJOS de la zona de carga mientras cargo este material peligroso?","options":["Una transpaleta usada por el personal del muelle","Un camión de reparto en ralentí en el muelle de al lado","Una fuente de llama abierta o que produce chispas","Una pila de tarimas de madera vacías"],"explanation":"Mantenga las llamas abiertas y las fuentes que producen chispas lejos del material peligroso durante la carga, ya que los materiales inflamables pueden encenderse con cualquier fuente de ignición."},"172":{"q":"Estoy cargando varios tambores y cajas de materiales peligrosos con placas en mi furgón cerrado para un viaje largo interestatal. Después de subirlos al remolque, ¿qué debo hacer con estos contenedores antes de cerrar las puertas y arrancar?","options":["Colocarlos bien apretados contra la pared frontal del remolque y confiar en que esa pared los mantenga en su lugar durante el viaje","Repartirlos de manera uniforme por el piso para equilibrar el peso y luego confiar en que la fricción normal del piso los mantenga asentados","Apilarlos lo más alto posible contra una pared lateral para liberar espacio en el piso para el resto de la carga","Apuntalar y asegurar cada contenedor de modo que no pueda desplazarse, deslizarse ni volcarse mientras el vehículo está en movimiento"],"explanation":"Apuntale y asegure cada contenedor de material peligroso para que no pueda desplazarse, deslizarse ni volcarse mientras el vehículo está en movimiento."},"173":{"q":"Estoy transportando una carga de residuos peligrosos y, antes de salir de la terminal, el remitente me entrega un manifiesto de residuos peligrosos junto con el resto de mis documentos. Para cumplir con las normas de materiales peligrosos, ¿qué debo hacer con ese manifiesto?","options":["Firmarlo y conservar una copia con mis documentos de embarque al alcance de la mano","Dejarlo firmado en la terminal para que el transportista lo archive por mí","Llevarlo sin firmar hasta que la instalación receptora lo firme en la entrega","Enviar por correo la copia firmada a la agencia estatal después de terminar el viaje"],"explanation":"El manifiesto de desechos peligrosos debe ser firmado por el conductor y guardarse con los documentos de embarque al alcance mientras conduce."},"174":{"q":"Soy un conductor nuevo con endoso H, y un expedidor me entrega la documentación de un material que los reglamentos enumeran específicamente como uno que sencillamente no puede transportarse en ningún vehículo comercial bajo ninguna circunstancia. Antes de hacer cualquier otra cosa, ¿cuál es la forma correcta de considerar esta carga?","options":["Puede transportarse en cualquier cantidad mientras coloque carteles en los cuatro lados del remolque","Está prohibido su transporte, así que ningún conductor puede llevarlo legalmente en absoluto","Puede transportarse libremente porque mi endoso H cubre todas las clases de peligro","Nunca necesita carteles, así que puedo transportarlo sin notificar a nadie"],"explanation":"Algunos materiales son tan peligrosos que están totalmente prohibidos para el transporte y nadie puede transportarlos legalmente."},"175":{"q":"Estoy cargando un envío marcado como explosivos de Clase 1, y el documento de embarque indica el material con un número de división justo después de la clase. Un compañero me dice que la Clase 1 es una categoría única e indivisible, por lo que el número de división debe ser un error de tipeo. ¿Qué afirmación describe correctamente cómo está estructurada la Clase 1?","options":["La Clase 1 es una categoría única e indivisible, así que cualquier número de división después de ella es un error","La Clase 1 se divide en exactamente dos grupos según códigos de color del embalaje","La Clase 1 se divide en varias divisiones, numeradas de 1.1 a 1.6","La Clase 1 no tiene subgrupos; las divisiones solo existen para los gases de la Clase 2"],"explanation":"La Clase de Peligro 1 (Explosivos) se subdivide en varias divisiones numeradas del 1.1 al 1.6."},"176":{"q":"En una terminal de carga, un despachador me entrega los documentos de embarque de una carga etiquetada como \"División 1.1\" y me pregunta qué tan en serio debo tomar el potencial de explosión antes de colocar los carteles y planificar la ruta. Según lo que me indica la división de peligro, ¿qué afirmación debe guiar mi decisión?","options":["Solo conlleva un peligro de proyección, así que planifico principalmente para fragmentos voladores en lugar de una detonación completa","Solo representa un riesgo menor de incendio, así que un extintor estándar y un repostaje cuidadoso es todo lo que realmente necesito","Tiene un peligro de explosión leve limitado al propio paquete, así que la distancia a los edificios no es una gran preocupación","Presenta un peligro de explosión en masa, lo que significa que toda la carga puede detonar a la vez, así que debo tratarla como la división de explosivos más peligrosa"],"explanation":"Los explosivos de la División 1.1 presentan un peligro de explosión en masa en el que toda la carga puede detonar a la vez, siendo la división de explosivos más peligrosa."},"177":{"q":"Transporto una carga de explosivos de la División 1.2 con carteles (placards) y necesito parar a comer en un pueblo pequeño. Como conductor, ¿qué acción me mantiene dentro de la ley para esta carga?","options":["Quedarme con el vehículo, o que una persona calificada lo vigile, para que la carga nunca quede sin atención","Cerrar la cabina, poner los frenos y dejarlo en el estacionamiento del restaurante mientras como adentro","Estacionarlo a menos de 5 pies de la parte transitada de la vía para vigilarlo desde la ventana","Dejarlo sin atención hasta por 2 horas siempre que quede junto a un edificio"],"explanation":"Los explosivos de las Divisiones 1.1, 1.2 y 1.3 nunca deben dejarse desatendidos; el conductor u otra persona calificada debe permanecer con la carga y vigilarla en todo momento."},"178":{"q":"Estoy transportando explosivos de la División 1.1 cuando mi remolque sufre una falla mecánica en una carretera pública de dos carriles. Llega un segundo camión de la empresa, y mi despachador quiere que traslade la carga explosiva al otro vehículo para que la carga pueda seguir su camino. Según las reglas de materiales peligrosos, ¿dónde se me permite realizar este trasvase entre vehículos?","options":["Aquí mismo en el arcén de la carretera, ya que el segundo camión ya está en el lugar y listo para recibir la carga","De ninguna manera en la vía pública salvo que sea una emergencia real — el trasvase debe hacerse en un lugar seguro fuera de la carretera, como una terminal o un depósito","En cualquier punto de la ruta, siempre que coloque los rótulos correspondientes en los cuatro lados de ambos vehículos durante el trasvase","En la carretera está bien en este caso, porque mi despachador me dio la orden directa de mantener la carga en movimiento"],"explanation":"Los explosivos de Clase 1 no pueden transferirse entre vehículos en una vía pública salvo en una emergencia real; la transferencia debe hacerse en un sitio seguro fuera de la vía como una terminal."},"179":{"q":"Transporto explosivos de la División 1.2 y necesito detenerme a descansar. Más adelante veo un área de descanso donde alguien tiene una fogata encendida junto al camino. Las reglas de distancia me pasan por la cabeza. ¿Cuál es la distancia mínima que debo mantener entre mi carga de explosivos estacionada y ese fuego abierto?","options":["5 pies, el mismo mínimo que debo mantener de la parte transitada del camino","10 pies, apenas lo suficiente para alejarme de las brasas que se desvían","300 pies, la separación requerida entre los explosivos y un fuego abierto","1 pie, ya que el fuego está contenido dentro de un anillo de fogata"],"explanation":"Un vehículo que transporta explosivos debe estacionarse al menos a 300 pies de un fuego abierto."},"180":{"q":"Estoy revisando los documentos de embarque de una carga de gas de Clase 2 antes de salir, tratando de confirmar qué división estoy transportando. Sé que la Clase 2 abarca más de un tipo de gas, y el transportista me dijo que las tres divisiones reconocidas de la Clase 2 son gas inflamable (2.1), gas no inflamable (2.2) y una tercera división que debo identificar para colocar los carteles (placards). ¿Cuál de las siguientes es esa tercera división reconocida de los gases de Clase 2?","options":["Gas sólido inflamable, ya que algunos gases de Clase 2 pueden asentarse en una forma sólida combustible","Gas corrosivo, porque los gases presurizados en tanques se comportan como material corrosivo de Clase 8","Gas solo líquido, ya que los gases almacenados bajo presión siempre se transportan en estado líquido","Gas venenoso (tóxico), que es la División 2.3 y puede requerir carteles en cualquier cantidad"],"explanation":"Los gases de Clase 2 incluyen el gas venenoso (tóxico) como División 2.3, un material de la Tabla 1 que requiere rótulos en cualquier cantidad."},"181":{"q":"Durante una parada de descanso, noto que uno de los cilindros de gas comprimido de mi carga con carteles de peligro ha desarrollado una fuga lenta y silba cerca de la válvula. Hay viajeros caminando por el área de estacionamiento cercana. ¿Cuál de las siguientes es la acción inmediata MÁS apropiada?","options":["Alejar a las personas del cilindro, mantener el área despejada y llamar a ayuda de emergencia","Apretar la válvula y sellar la fuga usted mismo para que el gas deje de escapar","Calentar ligeramente el cilindro para que la presión se equilibre y cese el silbido","Rodar y sacudir el cilindro para reasentar la válvula y reducir la presión"],"explanation":"Ante un cilindro de gas comprimido con fugas, aleje a las personas, mantenga el área despejada, evite fuentes de ignición y llame a ayuda de emergencia en vez de intentar repararlo usted mismo."},"182":{"q":"Estoy cargando un envío radiactivo de Clase 7, y el expedidor me entrega paquetes con etiquetas radiactivas. Cada etiqueta muestra un número que me indica el nivel de radiación del paquete. ¿Qué sistema de numeración veré en estas etiquetas de Clase 7?","options":["Las etiquetas se numeran A, B o C, según el índice de transporte del paquete","Las etiquetas se numeran I, II o III, indicando el nivel de radiación del paquete","Las etiquetas se numeran del 1 al 9, según el sistema de clases de peligro","Las etiquetas se numeran X, Y o Z, según la letra del grupo de embalaje"],"explanation":"El material radiactivo de Clase 7 usa tres categorías de etiquetas marcadas con números romanos I, II o III para indicar el nivel de radiación del paquete."},"183":{"q":"Estoy cargando varios paquetes radiactivos de Clase 7, y el remitente me señala el número de 'índice de transporte' impreso en cada etiqueta. Para cargar mi remolque de forma segura y legal, ¿qué me indica en realidad ese valor del índice de transporte?","options":["El valor monetario total del contenido radiactivo para fines de seguro","El peso bruto combinado de todos los paquetes radiactivos a bordo","El grado de control de radiación necesario al manipular y transportar el paquete","El número de identificación UN/NA asignado a ese material radiactivo"],"explanation":"El índice de transporte en un paquete radiactivo de Clase 7 indica el grado de control de radiación necesario al manipularlo y cargarlo."},"184":{"q":"Estoy transportando una carga de corrosivos con placas (rótulos) a través de la ciudad y mi GPS me ofrece tres rutas posibles hacia el mismo destino, todas de aproximadamente la misma distancia. Según la guía de rutas para materiales peligrosos de Texas, ¿cuál de estas debería esforzarme más por elegir?","options":["La ruta que atraviesa un largo túnel subterráneo, ya que evita los semáforos de superficie y ahorra unos minutos","La ruta que pasa justo al lado de un estadio del centro repleto de gente justo cuando termina un evento","La ruta que rodea varias plazas comerciales concurridas para mantenerse en calles más anchas y bien iluminadas","La ruta que permanece en calles de paso abiertas y evita tanto el túnel como las zonas concurridas del evento"],"explanation":"Los conductores de materiales peligrosos deben seguir rutas designadas que eviten túneles y zonas muy pobladas o concurridas siempre que sea posible."},"185":{"q":"Me asignaron transportar una carga de explosivos de la División 1.1 a través del estado. Mi instructor dice que, antes de este viaje, las normas federales exigen que mi transportista prepare cierto documento escrito que yo debo llevar y seguir. ¿De qué documento está hablando?","options":["Un plan de ruta por escrito que el viaje debe seguir","Un registro diario por escrito de combustible y kilometraje del conductor","Un contrato de compraventa por escrito de la carga explosiva","Un pronóstico del tiempo por escrito de 72 horas para la carretera"],"explanation":"Las cargas de explosivos (División 1.1, 1.2, 1.3) deben transportarse conforme a un plan de ruta escrito preparado por el transportista y llevado por el conductor."},"186":{"q":"Llevo tres horas en un viaje largo con una carga de corrosivos con carteles (placards) y acabo de entrar a un área de descanso para usar el baño. El camión ha funcionado bien desde mi inspección previa al viaje, y las llantas se veían bien cuando salí. Antes de volver a la carretera, ¿qué debo hacer con las llantas?","options":["Nada — una inspección minuciosa de las llantas antes del viaje me cubre durante todo el trayecto a menos que una llanta realmente se desinfle","Inspeccionar las llantas ahora, ya que debo revisarlas al inicio del viaje y luego cada 2 horas o cada 100 millas","Revisarlas solo si se enciende la luz de advertencia de presión de las llantas o si siento que el camión se desvía hacia un lado","Esperar e inspeccionar las llantas una vez al día, lo cual es suficiente para una carga con carteles en un viaje largo"],"explanation":"Un conductor que transporta una carga de materiales peligrosos con placas debe inspeccionar los neumáticos al inicio del viaje y en cada parada, es decir, cada 2 horas o 100 millas."},"187":{"q":"Entro con mi cisterna con placas de materiales peligrosos a una isla de combustible para completar el diésel antes del siguiente tramo de mi ruta. Cuando me dispongo a empezar a bombear, ¿cuál de las siguientes opciones describe cómo debo manejar el motor y la operación de carga para cumplir con la norma?","options":["Dejar el motor a ralentí bajo para que el sistema de aire siga cargado, y operar yo mismo la boquilla","Apagar el motor, fijar la boquilla en automático y entrar a pagar mientras se llena el tanque","Apagar el motor y mantener a una persona físicamente en la boquilla controlando el flujo durante todo el proceso","Mantener el motor a ralentí alto para alimentar la bomba de trasiego, sin que nadie tenga que estar en la boquilla"],"explanation":"Al cargar combustible en un vehículo con placas, el motor debe estar apagado y alguien debe permanecer en la boquilla controlando el flujo de combustible todo el tiempo."},"189":{"q":"Usted transporta una carga con carteles de peligro (líquido corrosivo) cuando uno de los tambores empieza a tener una fuga grave sobre el arcén de la autopista, provocando un derrame serio de material peligroso. Después de haber advertido a los demás, mantener a las personas alejadas e impedir que se fume, su transportista le indica que haga la notificación obligatoria de este incidente grave al Centro Nacional de Respuesta (National Response Center). ¿A qué número llama para reportarlo?","options":["411, la línea de asistencia de directorio, para que lo conecten con la unidad de respuesta de materiales peligrosos más cercana","911, la línea de emergencia local, que cumple plenamente con el requisito de notificación al Centro Nacional de Respuesta","1-800-555-1212, la línea gratuita que dirige el reporte a la agencia federal correspondiente","1-800-424-8802, la línea del Centro Nacional de Respuesta para reportar incidentes graves de materiales peligrosos"],"explanation":"Los incidentes graves con materiales peligrosos deben reportarse al Centro Nacional de Respuesta al 1-800-424-8802."},"190":{"q":"Un tambor en mi remolque con placas de materiales peligrosos empieza a tener una fuga de líquido corrosivo en un arcén apartado, y no tengo ni idea de qué hacer con el químico ni de cómo neutralizarlo. Después de advertir a los demás y mantener a las personas alejadas, ¿a qué número debo llamar para obtener orientación de emergencia las 24 horas sobre el manejo de este material peligroso en concreto?","options":["1-800-424-9300, la línea de emergencia de CHEMTREC","1-800-275-8777, la línea nacional de envíos y correos","1-888-275-8255, la línea federal de reportes de seguridad vial","1-800-829-1040, la línea de información de la agencia federal"],"explanation":"CHEMTREC opera una línea de emergencia las 24 horas al 1-800-424-9300 que da a los conductores orientación técnica inmediata para manejar un material peligroso en un incidente."},"191":{"q":"Estoy transportando una carga con placas de materiales corrosivos por Texas con el cinturón de seguridad abrochado. Un oficial del DPS me detiene y me pregunta por los documentos de embarque de materiales peligrosos. Según las reglas del manual, ¿dónde debían estar esos documentos mientras yo conducía?","options":["Sellados en un sobre impermeable y guardados en el remolque junto con la carga","Al alcance de mi mano y a la vista, colocados encima de mis demás documentos","Guardados con cierre dentro de la carpeta de mi bitácora, en la litera detrás del conductor","Bajo llave en la guantera para que estén seguros si fuerzan la entrada a la cabina"],"explanation":"Mientras se conduce, los documentos de embarque de materiales peligrosos deben estar al alcance del conductor y colocados encima de los demás papeles, a la vista."},"192":{"q":"Transporto una carga de materiales peligrosos con rótulos y entro a un área de descanso para usar el baño. Saldré de la cabina por unos minutos con el motor apagado. Según las reglas del DPS de Texas, ¿dónde deben estar mis documentos de embarque mientras estoy fuera del camión?","options":["Guardados bajo llave en la guantera para que nadie los manipule mientras no estoy","Doblados en el bolsillo de mi camisa y llevados conmigo al área de descanso","Dejados a la vista en el asiento del conductor o en el bolsillo de la puerta del conductor","Guardados en el compartimento lateral de carga junto a la Guía de Respuesta a Emergencias (ERG)"],"explanation":"Cuando el conductor sale de la cabina, los documentos de embarque de materiales peligrosos deben dejarse a la vista en el asiento del conductor o en el bolsillo de su puerta."},"193":{"q":"Estoy estacionado en un área de descanso con mi remolque rotulado (con placards) para líquidos inflamables de Clase 3. Varios conductores conversan cerca de mi camión y uno enciende un cigarrillo. Para cumplir con la regla federal de no fumar para mi carga rotulada, ¿cuál es la distancia mínima a la que todos deben mantener el cigarrillo encendido respecto a mi vehículo?","options":["Al menos 5 pies, el mismo margen exigido al estacionar lejos de la parte transitada de la vía","Al menos 2 pies, ya que el líquido inflamable está sellado dentro del tanque y representa poco riesgo","Al menos 100 yardas, la misma distancia que se mantiene de explosivos dejados sin vigilancia en un cruce ferroviario","Al menos 25 pies del vehículo, ya que no se permite fumar dentro de ese rango de una carga inflamable"],"explanation":"Está prohibido fumar a menos de 25 pies de un vehículo con placas que transporta explosivos, oxidantes o materiales inflamables."},"194":{"q":"Soy un conductor nuevo asignado para transportar una carga de explosivos de la División 1.1 por todo Texas. El expedidor ya clasificó y etiquetó la carga, y mi transportista me asignó el viaje. Antes de salir del patio, ¿cuál de los siguientes debo tener ya por ESCRITO en la cabina?","options":["Un plan de ruta escrito para el viaje más los documentos de embarque de la carga","Un comprobante de peso firmado de la báscula y una copia de mi recibo de combustible","Un registro escrito de los canales de radio que monitorearé a lo largo de la ruta","Un pronóstico del tiempo certificado ante notario que cubra cada condado que cruzaré"],"explanation":"Antes de transportar explosivos de la División 1.1, el conductor debe llevar un plan de ruta por escrito junto con los documentos de embarque de la carga."},"195":{"q":"Estoy cargando un envío de materiales peligrosos con placas en un muelle e inspeccionando cada paquete antes de subirlo a mi remolque. El expedidor me entrega cuatro contenedores. ¿Cuál de ellos debo rechazar transportar?","options":["Un tambor sellado herméticamente sin daños visibles en la costura ni en la tapa","Un cubo del cual un producto corrosivo se filtra lentamente por una grieta en su base","Una caja de cartón con la etiqueta de clase de peligro correcta aplicada en la superficie exterior","Una caja debidamente cerrada que coincide con la descripción en mis documentos de embarque"],"explanation":"El conductor debe rechazar cualquier envío de materiales peligrosos que tenga fugas, como un paquete que deja escapar producto por una grieta."},"196":{"q":"Ya tengo una CDL de Clase A y ahora quiero agregar el endoso H para poder transportar cargas con carteles de materiales corrosivos. Antes de que el DPS de Texas emita este endoso, ¿qué requisito adicional debo cumplir que NO se exige para mi CDL básica?","options":["Aprobar un segundo examen médico del DOT y presentar un certificado médico actualizado del examinador","Completar una prueba de manejo práctica separada usando un vehículo cisterna con carteles","Aprobar una evaluación de amenaza de seguridad de la TSA, que incluye toma de huellas dactilares y verificación de antecedentes","Repetir el examen de visión de la CDL y el examen escrito de conocimientos generales en el DPS"],"explanation":"El endoso de materiales peligrosos exige aprobar una evaluación de amenazas de seguridad de la TSA, que incluye toma de huellas y verificación de antecedentes."},"197":{"q":"He tenido mi CDL de Texas con el endoso de Materiales Peligrosos (H) durante varios años y apruebo cada examen médico a tiempo. Un conductor más nuevo me dice que, una vez que obtuve el endoso H al pasar la evaluación de amenaza de seguridad de la TSA, esa parte de mi credencial es permanente y nunca tendré que volver a ocuparme de ella mientras mi CDL base siga vigente. ¿Qué afirmación sobre mi endoso de Materiales Peligrosos es correcta?","options":["Queda fijado de por vida una vez que se aprueba la evaluación de la TSA, por lo que nunca se requiere ninguna otra gestión sobre esa parte.","Solo se mantiene vigente mientras siga aprobando mi examen médico del DOT, que es lo que controla el endoso.","Se transfiere automáticamente y nunca caduca mientras mantenga activo mi CDL base de Texas.","Debe renovarse periódicamente, lo que requiere pasar por una nueva evaluación de amenaza de seguridad / verificación de antecedentes de la TSA."],"explanation":"El endoso de materiales peligrosos tiene vigencia limitada y debe renovarse periódicamente aprobando una nueva evaluación de amenazas de seguridad de la TSA."},"198":{"q":"Estoy transportando una carga con carteles (corrosivos) cuando falla una válvula y el producto comienza a derramarse sobre el acotamiento. Tomo la Guía de Respuesta a Emergencias (ERG) de mi cabina. En esta situación, ¿para qué está diseñada realmente la ERG?","options":["Identificar los peligros del material y las acciones iniciales correctas ante el derrame para protegerme a mí mismo y al público","Calcular el valor monetario del producto perdido para que el transportista pueda presentar un reclamo de seguro preciso","Determinar la ruta alterna más eficiente en combustible alrededor del incidente para no desperdiciar diésel","Localizar el hospedaje y la zona de descanso aprobados más cercanos mientras espero al equipo de limpieza"],"explanation":"La Guía de Respuesta a Emergencias permite al conductor identificar los peligros de un material y las acciones iniciales correctas ante un derrame para protegerse y proteger al público."},"199":{"q":"Hay una fuga de mi cisterna con carteles (placards) en el lugar de un accidente. Un bombero llega corriendo y me pide que le lea el número de identificación de cuatro dígitos de mis documentos de embarque. EXCEPTO una, todas las siguientes explican por qué ese número le importa. ¿Cuál es la opción para la que realmente lo necesita?","options":["Le indica el valor en dólares de la carga para que pueda tramitar la reclamación de daños del transportista","Le permite buscar el material en la Guía de Respuesta a Emergencias (ERG) para encontrar los procedimientos de respuesta correctos","Confirma que mi endoso H y mi verificación de antecedentes de la TSA son válidos para esta carga","Muestra el nombre de embarque apropiado para que pueda leerlo en voz alta por radio al despachador"],"explanation":"El número de identificación UN/NA de cuatro dígitos permite al personal de emergencia buscar el material en la Guía de Respuesta a Emergencias y hallar los procedimientos correctos."},"200":{"q":"Estoy transportando una carga con rótulos (placards) cuando empieza a salir humo por debajo de mi remolque y veo que las llamas se extienden por las llantas. Tengo un pequeño extintor en la cabina, pero el fuego ya es demasiado grande para controlarlo de forma segura. EXCEPTO una opción de abajo, cada acción de la lista haría esta situación más peligrosa. ¿Cuál es la acción que realmente debo tomar?","options":["Abrir las puertas de la carga para ver exactamente qué tambores se están quemando y describírselos a los equipos de emergencia","Tomar mi extintor y seguir combatiendo el fuego yo mismo hasta apagarlo por completo o hasta que finalmente llegue ayuda","Mantener a los transeúntes bien alejados, ubicarme contra el viento y llamar de inmediato a los equipos de emergencia","Conducir el camión en llamas hasta el pueblo más cercano para que los bomberos de allí tengan menos distancia que recorrer"],"explanation":"Cuando una carga peligrosa rotulada se incendia y está fuera de su control, mantenga a los curiosos lejos, ubíquese contra el viento y llame de inmediato a los servicios de emergencia."},"201":{"q":"Transporta una carga de materiales peligrosos con carteles (placards) y su GPS lo dirige directamente por un túnel largo de la autopista que le ahorraría casi una hora. No está seguro de si su material está permitido en ese túnel. Antes de llegar a la entrada del túnel, ¿qué debe hacer PRIMERO?","options":["Reducir la velocidad y mantener ambos carriles despejados para cruzar el túnel de forma rápida y segura","Quitar los carteles antes de entrar para que los encargados del túnel no lo detengan adentro","Detenerse justo dentro de la entrada del túnel y llamar a su transportista para preguntar si puede continuar","Consultar las reglas de la ruta designada, porque algunos materiales peligrosos están prohibidos en los túneles y puede requerirse una ruta diferente"],"explanation":"Algunos materiales peligrosos están prohibidos en túneles, por lo que el conductor debe verificar primero las reglas de la ruta designada, ya que puede requerirse otra ruta."},"202":{"q":"Mi transportista acaba de entregarme un plan de seguridad escrito antes de un viaje con materiales peligrosos con carteles (placards) y me pidió que siguiera sus procedimientos para resguardar los documentos de embarque, verificar mi ruta y limitar el acceso no autorizado al remolque. Desde la perspectiva del DPS de Texas, ¿cuál es el propósito PRINCIPAL de este plan de seguridad?","options":["Reducir la probabilidad de que los materiales peligrosos sean robados o usados indebidamente por personas no autorizadas","Agilizar la carga y descarga para que la entrega llegue antes de su horario programado","Disminuir el consumo de combustible trazando la ruta más corta posible entre las paradas","Mantener limpia la zona de carga para que los materiales no se contaminen durante el transporte"],"explanation":"Un plan de seguridad de materiales peligrosos existe para reducir la posibilidad de que personas no autorizadas roben o usen indebidamente los materiales peligrosos."},"203":{"q":"Transporto una carga de corrosivos con placas (placards) a través de una ciudad que no conozco y la noche anterior me detengo a trazar mi ruta. Según el Manual CDL de Texas, ¿cuál es la razón PRINCIPAL por la que planificar la ruta con anticipación es tan importante para un conductor de materiales peligrosos?","options":["Me permite omitir las inspecciones de neumáticos en ruta porque ya sé cuánto durará el viaje","Me ayuda a identificar y mantenerme fuera de las zonas restringidas donde mi carga con placas está prohibida","Me permite retirar las placas en tramos de carretera abierta para ahorrar combustible","Me garantiza encontrar las estaciones de combustible y áreas de descanso más baratas del trayecto"],"explanation":"Planificar la ruta con anticipación ayuda al conductor a identificar y mantenerse fuera de las zonas restringidas donde está prohibida una carga rotulada."},"204":{"q":"Estoy cargando un remolque en una terminal de carga y mi manifiesto incluye varias tarimas de explosivos de Clase 1 (División 1.1) junto con otros materiales peligrosos que esperan en la plataforma. Antes de dejar que el personal apile todo junto, ¿qué debe guiar mi decisión sobre qué productos pueden viajar en la misma carga que los explosivos?","options":["Los explosivos pueden compartir carga con cualquier clase de peligro siempre que cada tarima esté bloqueada y sujeta por separado para que no se desplace durante el transporte","Los explosivos pueden cargarse con cualquier cosa siempre que la carga combinada se mantenga por debajo del umbral de 1,001 libras para colocar carteles en el remolque","La tabla de segregación (de carga/descarga) prohíbe cargar explosivos junto con ciertos otros materiales peligrosos, así que debo consultarla antes de combinarlos","Los explosivos deben cargarse completamente solos y nunca pueden compartir un remolque con ninguna otra carga"],"explanation":"Consulte siempre la tabla de segregación (carga/descarga) antes de combinar explosivos con otros materiales peligrosos, ya que algunos productos no pueden cargarse juntos."},"205":{"q":"Estoy en el muelle de carga a punto de cargar a mano varios tambores y cubetas de un líquido corrosivo de Clase 8 en mi remolque. El operario del muelle me pregunta cómo quiero colocar cada recipiente antes de amarrarlos. Para empacar la carga de forma segura y que el líquido quede sellado dentro, ¿cómo debo colocar cada recipiente?","options":["Acostados de lado para que los tambores encajen apretados y se muevan menos durante el transporte","Con las aberturas hacia abajo para que cualquier filtración escurra lejos del cierre","Con las etiquetas de peligro hacia la pared para que no se rayen","De pie con las aberturas hacia arriba para que los cierres queden por encima del líquido"],"explanation":"Cargue los materiales peligrosos líquidos en posición vertical con las aberturas hacia arriba, para que queden por encima del nivel del líquido y los sellos no goteen."},"206":{"q":"Estoy cargando a mano un remolque con cajas de un material corrosivo (Clase 8), y un trabajador del muelle me pasa un gancho metálico de carga para arrastrar las cajas pesadas a su sitio más rápido. Antes de agarrar nada, ¿qué regla debería impedirme usar ese gancho en estos paquetes?","options":["No debo usar ningún gancho ni herramienta que pueda perforar, rasgar o dañar de algún modo los paquetes de materiales peligrosos","Puedo usar el gancho libremente mientras mantenga las cajas en posición vertical y las etiquetas hacia afuera","Los ganchos se permiten en la Clase 8 solo después de colocar los carteles en los cuatro lados del remolque","Los ganchos se permiten solo si reviso los neumáticos dentro de las primeras 100 millas tras la carga"],"explanation":"Nunca use ganchos ni ninguna herramienta que pueda perforar, rasgar o dañar el embalaje de materiales peligrosos, ya que una rotura puede liberar el contenido."},"207":{"q":"Estoy cargando cilindros de gas comprimido (Clase 2) en mi remolque en una tarde calurosa. Para manejarlos correctamente según las normas, ¿qué debo hacer con estos cilindros antes de ponerme en marcha?","options":["Acostarlos sueltos para que se acomoden solos y puedan desplazarse a medida que la carga se asienta en el camino","Asegurarlos firmemente para que no puedan moverse y mantenerlos protegidos de las fuentes de calor","Pararlos en posición vertical con las válvulas entreabiertas para que la presión interna se libere lentamente","Apilarlos alto contra la pared cálida del remolque y calzar solo la fila inferior"],"explanation":"Asegure las botellas de gas comprimido para que no se muevan ni caigan y manténgalas alejadas del calor, porque el calor aumenta la presión interna y puede causar una ruptura."},"208":{"q":"Estoy colocando los carteles de peligro (placards) en un camión cisterna antes de un viaje en Texas y noto que lleva dos carteles: uno principal grande para su clase de peligro principal y otro más pequeño sin número de clase impreso en la esquina inferior. Mi instructor llama al segundo un cartel 'subsidiario' (subsidiary). ¿Qué me indica sobre esta carga?","options":["Confirma la clasificación anterior o 'antigua' que usó el expedidor antes de recargar la carga","Indica que el tanque está vacío y que solo queda residuo en su interior","Advierte de un peligro adicional que presenta el material más allá de su clase de peligro principal","Marca el nivel actual de combustible para que los rescatistas sepan cuánto producto hay a bordo"],"explanation":"Un rótulo subsidiario advierte de un peligro adicional que presenta el material más allá de su clase de peligro principal."},"209":{"q":"Me estoy preparando para transportar una carga de corrosivos con carteles (placards), y el expedidor me entrega los documentos de embarque que incluyen, cerca de la parte superior, un número de teléfono de respuesta a emergencias. Antes de firmar y salir, ¿qué requisito debe cumplir ese número de respuesta a emergencias?","options":["Solo tiene que estar disponible durante el horario laboral habitual del expedidor entre semana","Puede dirigirse a un buzón de voz grabado siempre que alguien devuelva la llamada más tarde","Se permite que sea el número de móvil personal del conductor indicado en los documentos","Debe ser un número atendido por personal y supervisado en todo momento mientras el material peligroso esté en tránsito"],"explanation":"El número de teléfono de respuesta a emergencias en los documentos de embarque debe estar atendido y monitoreado en todo momento mientras se transporta el material peligroso."},"210":{"q":"Usted transporta una carga con carteles (placards) de corrosivos cuando falla una conexión y un charco comienza a extenderse desde debajo de su remolque hacia el arcén de una carretera de dos carriles. Otros vehículos siguen pasando muy cerca. Después de salirse por completo de la vía, ¿cuál es su PRIMERA prioridad antes de hacer cualquier otra cosa?","options":["Mantener a los curiosos alejados de la fuga y advertir del peligro al tránsito que se aproxima","Enjuagar el material derramado del pavimento para que deje de extenderse cuesta abajo","Quitar o cubrir los carteles para que los curiosos no se asusten por la carga","Volver a subir a la cabina y conducir hasta la próxima salida para despejar la escena rápidamente"],"explanation":"En un incidente con materiales peligrosos, el primer deber del conductor es mantener a las personas alejadas de la fuga y advertir del peligro al tránsito que se aproxima."},"211":{"q":"Entré a un área de descanso con mi carga con cartel (placard) y quiero salir a fumar. ¿Junto a cuál de estos NO debo encender un cigarrillo bajo ninguna circunstancia?","options":["Junto al remolque vacío y completamente purgado que acabo de dejar","Junto al remolque con cartel de líquido inflamable","Junto a un automóvil de pasajeros estacionado en el espacio de al lado","Junto a la cabina limpia y barrida de mi tractor"],"explanation":"Nunca fume a menos de 25 pies de un vehículo rotulado para inflamables, ya que los vapores pueden encenderse con una llama abierta o un cigarrillo encendido."},"212":{"q":"Su tanque cisterna con carteles de materiales peligrosos que transporta un líquido inflamable se dobla en tijera en una carretera rural de dos carriles y usted percibe un fuerte olor químico acumulándose cerca del remolque. Dos automovilistas se han detenido y caminan hacia el accidente, uno encendiendo un cigarrillo. ¿Qué acción debe tomar PRIMERO?","options":["Volver a subir a la cabina y reposicionar el remolque fuera de la calzada antes de que se extienda la fuga","Reunir los documentos de embarque y la Guía de Respuesta a Emergencias (ERG) y comenzar a limpiar el derrame","Mantener a los curiosos bien alejados, impedir que se fume y notificar a los servicios de emergencia y a CHEMTREC","Colocar bengalas encendidas detrás del accidente para advertir del peligro al tráfico que se aproxima"],"explanation":"Tras un accidente con materiales peligrosos, mantenga a los curiosos bien alejados, impida fumar y notifique de inmediato a los servicios de emergencia y a CHEMTREC."},"213":{"q":"Estoy haciendo la inspección previaje a mi remolque con carteles de peligro en el patio de Laredo y noto que el cartel trasero está muy descolorido y uno del lado derecho está parcialmente oculto detrás del soporte del guardabarros. Mi compañero dice que está bien mientras los carteles delantero y trasero estén limpios, ya que esos son los que realmente ven el tráfico que viene de frente y el policía detrás de mí. Según las reglas de carteles del DPS, ¿qué afirmación es correcta?","options":["Tu compañero tiene razón en que solo importan el delantero y el trasero, ya que miran hacia donde se acercan otros conductores, así que el lateral descolorido puede ignorarse antes de conducir.","Es aceptable mientras al menos un cartel del vehículo siga siendo totalmente legible desde fuera de la cabina, así que un solo cartel delantero limpio te dejaría conducir hoy.","Los carteles solo deben ser claramente visibles para el conductor desde la cabina para confirmar la marca de la carga, así que el descolorido u obstrucción externa no importa antes de conducir.","Los cuatro carteles deben estar presentes y ser legibles desde la dirección a la que mira cada uno, así que el trasero descolorido y el lateral parcialmente oculto deben corregirse antes de conducir."],"explanation":"Los rótulos son obligatorios en los cuatro lados y cada uno debe ser legible desde la dirección a la que apunta, por lo que cualquier rótulo descolorido u oculto debe corregirse antes de conducir."},"214":{"q":"Estoy haciendo la inspección previaje de una carga con carteles (placards) y quiero confirmar que los carteles están montados como exige el reglamento. Sin tener en cuenta el símbolo impreso ni el número de clase del interior, ¿qué forma general debe formar cada cartel correctamente colocado en el costado de mi remolque?","options":["Un cuadrado apoyado sobre una de sus esquinas, de modo que se ve como un rombo (diamante) con la punta hacia arriba","Un cuadrado apoyado plano sobre uno de sus lados rectos, como el panel de una señal de tránsito","Un disco redondo y circular, para que la advertencia sea visible desde todos los ángulos","Un triángulo con la punta hacia arriba, igual que los dispositivos reflectantes de advertencia de mi equipo"],"explanation":"Un cartel (placard) es un cuadrado girado 45 grados y apoyado sobre una esquina, formando un rombo con la punta hacia arriba."},"215":{"q":"Estoy cargando un envío de materiales peligrosos con carteles (placards) y verifico dos veces que cada paquete esté marcado correctamente antes de firmar. Además del nombre de embarque apropiado impreso en el paquete, ¿qué otra información debe aparecer también en la marca del paquete?","options":["Mi nombre como el conductor que aceptó la carga","El número de identificación (UN/NA) del material","El código de color que coincide con el cartel del remolque","El tipo de combustible que usa el tractocamión del transportista"],"explanation":"Las marcas del paquete deben incluir el número de identificación (UN/NA) del material junto con el nombre de embarque correcto."},"216":{"q":"Estoy revisando los documentos de embarque de una carga antes de salir de la terminal y noto las letras \"RQ\" anotadas en la columna HM justo al lado de uno de los materiales listados. Antes de firmar y colocar los documentos a mi alcance, ¿qué me indica realmente esa anotación \"RQ\" sobre esa entrada?","options":["Marca la ruta sugerida de bajo tránsito que debo seguir para mantener ese material lejos de las zonas pobladas","Confirma que el expedidor volvió a revisar el paquete y lo certificó sin fugas para la carga","Señala que el material está presente en una cantidad reportable, por lo que un derrame debe notificarse","Significa que la entrada fue revisada y aprobada, así que puedo moverla al final de mi papeleo"],"explanation":"\"RQ\" significa Cantidad Reportable (Reportable Quantity), e indica que el material está presente en una cantidad que obliga a reportar un derrame si se libera."},"217":{"q":"Estoy cargando un envío mixto y el supervisor del muelle me entrega varios paquetes marcados como Clase 6 (División 6.1), veneno. Tengo un remolque vacío y debo decidir dónde colocarlos respecto al resto de la carga. Para cargar este veneno de forma segura y legal, ¿de qué debo asegurarme absolutamente de mantenerlo alejado?","options":["Los triángulos reflectantes de advertencia que llevo para emergencias","El extintor de incendios montado cerca de las puertas de carga","La llanta de repuesto guardada debajo del cuerpo del remolque","Cualquier alimento, comestible o producto comestible en la carga"],"explanation":"Los materiales venenosos (División 6.1) nunca deben cargarse junto a ningún alimento, producto alimenticio o comestible para evitar la contaminación."},"218":{"q":"Transporto una carga con carteles (placards) de oxidantes de Clase 5 cuando comienza un pequeño incendio eléctrico cerca de mi remolque. Al evaluar la situación, ¿por qué es especialmente urgente mantener este material alejado de cualquier llama?","options":["Los oxidantes liberan oxígeno, por lo que harán que el fuego arda más caliente e intensamente","Los oxidantes sofocan y apagan las llamas, pero los vapores que liberan son tóxicos","Los oxidantes se congelan al contacto con el calor, lo que puede agrietar el remolque y derramar la carga","Los oxidantes son inofensivos cerca del fuego, pero los carteles en sí son inflamables"],"explanation":"Los oxidantes liberan oxígeno que alimenta el fuego, haciendo que arda con más calor e intensidad."},"219":{"q":"Estoy transportando una carga con rótulos de un líquido inflamable de Clase 3, y el documento de embarque indica el punto de inflamación del material. Durante mi revisión de seguridad previa al viaje, mi instructor me pregunta qué me dice realmente ese número del punto de inflamación sobre esta carga. ¿Cuál enunciado describe correctamente lo que indica el punto de inflamación?","options":["Es la temperatura a la que el líquido se congela y deja de moverse dentro del tanque","Es la temperatura más baja a la que el líquido desprende suficiente vapor para formar una mezcla inflamable","Es la temperatura a la que el líquido se autoenciende sin necesidad de chispa ni llama abierta","Es la temperatura a la que el líquido se expande lo suficiente para empezar a fugarse del recipiente"],"explanation":"El punto de inflamación es la temperatura más baja a la que un líquido emite suficiente vapor para formar una mezcla inflamable."},"220":{"q":"Conduzco un tanque de carga seca a granel cargado con cemento en polvo y me acerco a una salida en trébol con una curva señalizada. Dado cómo se comporta este tipo de carga, ¿qué factor debería influir más en cómo tomo esta curva?","options":["La carga queda baja y asentada, así que puedo tomar la curva a la velocidad señalizada de la autopista sin ajustar nada","El tanque lleva mamparas como un cisterna de líquidos, así que el oleaje está totalmente controlado y solo importa la distancia de frenado","La carga va alta y se desplaza cuando el vehículo se mueve, así que debo reducir la velocidad bastante antes de la curva y girar con suavidad","El polvo se compacta sólido al estar en movimiento, así que las correcciones bruscas de dirección dentro de la curva son perfectamente seguras"],"explanation":"Los tanques de carga seca a granel tienen un centro de gravedad alto y la carga se desplaza, así que reduzca la velocidad mucho antes de la curva y gire suavemente."},"222":{"q":"Acabo de aceptar una carga que debe llevar carteles (placards) en los cuatro lados, y el despachador del transportista me apura para salir. Antes de salir del patio, ¿qué credencial debo tener yo personalmente para conducir legalmente esta carga con carteles?","options":["Un certificado médico vigente del examinador del DOT, que por sí solo me autoriza a transportar cualquier carga con carteles","Un endoso de tanque (N), ya que las cargas con carteles siempre se transportan en remolques cisterna a granel","Nada adicional en mi licencia, porque el remitente ya preparó los documentos y colocó los carteles","Un endoso válido de materiales peligrosos HazMat (H), obtenido tras pasar una verificación de antecedentes de la TSA y la toma de huellas dactilares"],"explanation":"Transportar una carga de materiales peligrosos con carteles requiere un endoso de HazMat (H) válido, obtenido tras aprobar una verificación de antecedentes de la TSA y toma de huellas."},"223":{"q":"Transporto una carga rotulada de corrosivos y quiero preparar correctamente mis documentos de embarque antes de salir. Me tomo unos minutos para colocar pestañas y marcar claramente las entradas de materiales peligrosos. Cuando un inspector o un socorrista los pida, ¿cuál es el verdadero propósito de poner pestañas y marcar así esos documentos?","options":["Para que los documentos de materiales peligrosos puedan ubicarse rápida y fácilmente en una emergencia o inspección","Para que los documentos de materiales peligrosos permanezcan doblados y guardados fuera de la vista hasta que se soliciten específicamente","Para que las entradas de materiales peligrosos queden separadas y apartadas del resto del papeleo de la carga","Para que los documentos de materiales peligrosos puedan desecharse una vez completada y firmada la entrega"],"explanation":"Los documentos de embarque de materiales peligrosos deben estar marcados o señalizados para poder localizarlos rápida y fácilmente en una emergencia o inspección."},"224":{"q":"Usted transporta una carga de corrosivos con carteles (placards) cuando una conexión falla y el material comienza a derramarse sobre el arcén de una carretera concurrida. Los transeúntes empiezan a reunirse cerca de su remolque. De las siguientes acciones, ¿cuál debe ser su PRIMERA prioridad antes que cualquier otra cosa?","options":["Sacar los documentos de embarque y llamar a CHEMTREC para informar el nombre y la cantidad exactos del producto","Mantenerse alejado de la fuga y apartar a los transeúntes para proteger a todos de la exposición","Abrir la Guía de Respuesta a Emergencias (ERG) para buscar el procedimiento de limpieza del derrame según ese número de identificación","Comunicarse con su transportista para que la empresa presente ante las autoridades el informe del incidente requerido"],"explanation":"En cualquier incidente con materiales peligrosos, proteja primero la vida manteniéndose alejado de la fuga y apartando a los presentes de la exposición."},"225":{"q":"Acerca su camión cisterna a la rampa para cargar un líquido inflamable. Antes de que el producto empiece a fluir al tanque de carga, ¿cuál paso es el MÁS importante para evitar que una chispa de electricidad estática encienda los vapores?","options":["Dejar el motor del camión en ralentí para que el alternador alimente los sensores de nivel del tanque durante la carga","Colocar sus triángulos reflectantes de advertencia alrededor de la rampa de carga por si se acercan otros vehículos","Conectar (igualar potencial) el tanque al equipo de carga y poner a tierra ambos antes de abrir la línea de llenado","Abrir la tapa de la cúpula con anticipación para que los vapores acumulados se ventilen y baje la presión interna"],"explanation":"Conectar a masa y aterrizar antes de abrir la línea de llenado descarga la electricidad estática que genera el flujo de líquido inflamable, evitando una chispa que encienda el vapor."},"227":{"q":"Estoy transportando una carga con carteles (placards) que requiere vigilancia constante y he estacionado en una parada designada para pasar la noche. Mi co-conductor acepta quedarse con el vehículo como vigilante mientras yo descanso en un motel cercano. ¿Cuál de las siguientes opciones describe mejor cómo debe desempeñar mi co-conductor esta función de vigilancia para que sea válida?","options":["Puede dormir una siesta en la litera siempre que permanezca a menos de 100 pies de la carga","Puede sentarse en un restaurante cerrado al otro lado del estacionamiento, ya que aún puede ver el remolque","Puede ausentarse brevemente para echar combustible a su auto personal si no hay nadie cerca","Debe permanecer despierto y alerta, a menos de 100 pies del vehículo y con una vista despejada del mismo"],"explanation":"El vigilante de una carga con carteles debe permanecer despierto y alerta, a menos de 100 pies del vehículo y con una vista despejada de este."},"228":{"q":"Estoy transportando una carga de líquido inflamable con rótulos (placards) en un viaje largo por una autopista interestatal y acabo de terminar mi inspección de neumáticos previa al viaje antes de salir de la terminal. Para cumplir con la regla de inspección en ruta, ¿con qué frecuencia debo detenerme para volver a revisar los neumáticos durante el viaje?","options":["Al menos cada 2 horas o cada 100 millas, lo que ocurra primero","Al menos cada 100 millas, pero el plazo de 2 horas ya no aplica una vez que estoy en la autopista","Al menos cada 3 horas o cada 150 millas, lo que ocurra primero","Solo cuando me detengo a cargar combustible o a tomar el descanso obligatorio de 30 minutos"],"explanation":"Al transportar una carga con carteles debe revisar las llantas en ruta al menos cada 2 horas o cada 100 millas, lo que ocurra primero."},"229":{"q":"Soy el primero en llegar a la escena de un vuelco que transporta una carga con carteles (placards). El despachador no puede leer el nombre de embarque apropiado a través del humo, pero me transmite por radio el número de identificación de la ONU de 4 dígitos estarcido en el paquete. Para buscar la información de respuesta a emergencias de la forma MÁS RÁPIDA usando solo ese número, ¿a qué sección de la ERG debo acudir?","options":["Las páginas con borde naranja, las guías que agrupan los materiales por su color de peligro asignado","Las páginas con borde amarillo, que enumeran los materiales en orden numérico por número de identificación","Las páginas con borde azul, que enumeran los materiales alfabéticamente por nombre de embarque","Las páginas con borde blanco, que enumeran los materiales por peso y cantidad del paquete"],"explanation":"Las páginas de borde amarillo de la ERG listan los materiales en orden numérico por número de identificación, por lo que son las más rápidas cuando solo conoce el número de ID de 4 dígitos."},"230":{"q":"Estoy en el lugar de una fuga de mi carga con carteles (placards). Los documentos de embarque fueron destruidos, así que no tengo el número de identificación UN/NA, pero el contenedor tiene grabada claramente la palabra \"CLORO\" (CHLORINE). Para buscar rápidamente este material en las páginas con borde azul de la ERG, ¿en qué me baso para encontrar la entrada?","options":["El número de identificación UN/NA de cuatro dígitos grabado en el contenedor","El número de clase de peligro del cartel (placard) mostrado en el tanque","El nombre de embarque correcto del material, listado en orden alfabético","El código de color del DOT impreso en la etiqueta del paquete"],"explanation":"Las páginas de borde azul de la ERG listan los materiales alfabéticamente por su nombre de embarque, por lo que son la herramienta cuando conoce el nombre pero no el número de ID."},"231":{"q":"Estoy transportando una carga rotulada (con placas) de corrosivos cuando falla un acoplamiento y el producto comienza a fugarse hacia el arcén. Tomo mi Guía de Respuesta a Emergencias (ERG), busco el número de identificación del material y necesito saber cómo proteger a las personas y responder de forma segura en el lugar. ¿A qué sección de la ERG debo acudir para esa información?","options":["A las páginas de borde azul, porque las guías de acción de respuesta de cada material están ordenadas allí alfabéticamente por nombre de embarque apropiado","A las páginas de borde verde, porque indican las distancias de acción protectora y me dicen exactamente cómo manejar el derrame","A las páginas de borde amarillo, porque las guías numeradas que describen qué hacer en el lugar están indexadas allí por número UN/NA","A las páginas de borde naranja, porque contienen las guías numeradas de acción de respuesta que me indican cómo proteger a las personas y controlar el incidente"],"explanation":"Las páginas de borde naranja de la ERG contienen las guías de respuesta numeradas que explican los peligros y las acciones de seguridad pública para proteger a las personas y controlar el incidente."},"232":{"q":"Un camión cisterna delante de mí ha volcado y está derramando gas venenoso. Mientras llamo a CHEMTREC, abro mi Guía de Respuesta a Emergencias (ERG) en las páginas con borde verde para decidir adónde debo trasladar a la gente. ¿Qué información están diseñadas para darme estas páginas verdes?","options":["Las distancias iniciales de aislamiento y de acción protectora que indican qué tan lejos evacuar y mantener a la gente alejada de la fuga","La lista de nombres de embarque apropiados emparejados con sus números de identificación UN/NA de cuatro dígitos","La guía general de respuesta que describe las acciones contra incendios, derrames y primeros auxilios para el número de guía de ese material","Los números de teléfono de CHEMTREC y de emergencia para llamar y obtener asistencia técnica durante el incidente"],"explanation":"Las páginas de borde verde de la ERG dan las distancias de aislamiento inicial y de acción protectora que indican a qué distancia evacuar y mantener alejadas a las personas de una fuga."},"233":{"q":"Estoy cargando mi remolque en una terminal y el supervisor del muelle me entrega los documentos de embarque que incluyen un código de letra (una letra de \"grupo de compatibilidad\") impreso justo después de la división de peligro en una de las entradas. Me dice que esta letra indica cuáles otros artículos de la misma clase de peligro se pueden o no se pueden cargar juntos en el mismo vehículo. Según cómo se regulan los materiales peligrosos, ¿a qué clase de material se refiere esta letra de grupo de compatibilidad?","options":["Clase 8 Corrosivos, para evitar que los ácidos y las bases reaccionen entre sí dentro del remolque","Clase 1 Explosivos, para saber qué divisiones y tipos se pueden cargar y transportar juntos","Clase 2 Gases, para separar los gases inflamables de los gases venenosos durante la carga","Clase 7 Radiactivos, para mantener los totales del índice de transporte dentro de los límites de un vehículo"],"explanation":"Las letras de grupo de compatibilidad pertenecen solo a la Clase 1 Explosivos e indican qué divisiones y tipos de explosivos pueden cargarse y transportarse juntos con seguridad."},"234":{"q":"Estoy preparando los documentos de embarque para una carga que requiere rótulos (placards) y noto que una entrada muestra un número de identificación que comienza con las letras 'NA' en lugar de 'UN.' Un conductor nuevo me pregunta qué indica ese prefijo sobre dónde es válido el número. ¿Cuál de las siguientes es la respuesta correcta que debo darle?","options":["Es un número armonizado internacionalmente, reconocido para envíos en cualquier parte de Europa y Asia","Indica que la carga solo puede transportarse en rutas de exportación designadas en el extranjero, nunca dentro del país","Es un número de identificación asignado para uso dentro de América del Norte, incluidos Estados Unidos y Canadá","Significa 'No Aplica,' por lo que para esa línea no se requiere clase de peligro ni nombre de embarque correcto"],"explanation":"El prefijo 'NA' indica un número de identificación asignado para uso solo dentro de Norteamérica, es decir, los Estados Unidos y Canadá."},"235":{"q":"Estoy transportando una carga rotulada de un líquido inflamable desde Houston hacia un puerto para exportarla al extranjero, y mis documentos de embarque indican el material con un nombre de embarque apropiado, una clase de peligro y un número de identificación 'UN'. Un conductor nuevo que viaja conmigo sostiene que ese número 'UN' solo importa aquí en Texas y puede ignorarse una vez que la carga sale del estado. ¿Cuál afirmación sobre ese número de identificación 'UN' es correcta?","options":["El número 'UN' se aplica solo dentro de Texas, así que el conductor nuevo tiene razón: deja de importar al cruzar la línea estatal","El número 'UN' es válido solo para envíos que se mueven por mar, así que se aplica cuando la carga llega al puerto","El número 'UN' es válido solo para envíos que se mueven por aire, así que se necesita un código distinto para este camión","El número 'UN' se reconoce internacionalmente, así que identifica el material de la misma manera sin importar a dónde viaje la carga"],"explanation":"Un número de identificación 'UN' es reconocido internacionalmente, por lo que identifica el material de la misma manera sin importar a dónde viaje la carga."},"236":{"q":"Estoy haciendo mi inspección previaje y noto que uno de mis paquetes tiene una etiqueta en forma de diamante que no reconozco. Para confirmar si marca un material venenoso (tóxico) antes de aceptar la carga, ¿qué símbolo debería buscar en esa etiqueta?","options":["Una calavera con tibias cruzadas dentro del diamante","Un símbolo de llama sobre el número de la clase de peligro","Una bola negra ardiendo con rayos dentro del diamante","Un símbolo de trébol de tres aspas tipo hélice"],"explanation":"Un material venenoso o tóxico (División 6.1) se identifica por el símbolo de calavera y huesos cruzados dentro del rótulo en forma de diamante."},"237":{"q":"Estoy inspeccionando carga en un muelle de carga y tomo un paquete marcado con una etiqueta de peligro Clase 7 en forma de rombo amarillo y blanco. Para confirmar el contenido antes de firmar por la carga, examino lo impreso dentro del rombo. ¿Qué palabra impresa en esa etiqueta en forma de rombo confirma que se trata de un envío de Clase 7?","options":["FRÁGIL (FRAGILE), porque el paquete contiene contenedores sellados delicados que pueden romperse","RADIACTIVO (RADIOACTIVE), porque la palabra impresa en una etiqueta de rombo Clase 7 indica el peligro directamente","CORROSIVO (CORROSIVE), porque las fuentes selladas de Clase 7 se guardan en carcasas externas resistentes a ácidos","OXIDANTE (OXIDIZER), porque el material radiactivo emite energía que puede mantener la combustión"],"explanation":"La etiqueta de Clase 7 imprime literalmente la palabra RADIOACTIVE dentro del diamante, que indica la clase de peligro directamente."},"238":{"q":"Estoy en la rampa de carga llenando mi tanque cisterna con gasolina en una tarde calurosa de Texas, y el operador me pregunta hasta qué nivel quiero que suba el producto antes de cerrar la bomba. Para transportar este líquido inflamable de forma segura y legal, ¿cómo debería cargar el tanque?","options":["Lleno hasta el borde para que el líquido no se sacuda ni golpee contra los deflectores cuando frene","Lleno solo hasta la mitad, ya que un tanque de líquido inflamable nunca puede llevarse legalmente a más del 50 por ciento","Sin llegar a llenarlo del todo para que quede espacio vacío que permita la expansión del producto al calentarse durante el viaje","Lleno por completo hasta arriba y luego sellado con la etiqueta de peligro correcta sobre la tapa para que cuente como carga completa"],"explanation":"Un tanque de carga con líquido inflamable no debe llenarse por completo porque el líquido se expande al calentarse y necesita espacio vacío."},"239":{"q":"Estoy cargando un tanque de carga con un líquido inflamable temprano en una mañana fría, y planeo conducir hacia el sur a un clima mucho más cálido a medida que el día se calienta. Para decidir qué tan lleno puedo cargar el tanque de forma segura, ¿qué hecho sobre la carga debe guiar mi decisión?","options":["Puedo llenar el tanque completamente hasta arriba, porque el líquido se contrae y ocupa menos espacio a medida que sube la temperatura exterior durante el día","El nivel de llenado no importa para los líquidos, porque solo los gases comprimidos cambian de volumen cuando cambia la temperatura alrededor del tanque","Debería llenarlo hasta el tope ahora que está frío, porque un líquido más frío se expande y se desbordaría si esperara hasta el mediodía para cargarlo","Debo dejar espacio vacío (margen de expansión) en el tanque, porque el líquido se expandirá al calentarse y necesita espacio para no desbordarse"],"explanation":"Deje espacio vacío (espacio de expansión) en el tanque porque el líquido se expande al calentarse y necesita lugar para evitar el derrame."},"240":{"q":"Estoy cargando en un muelle dos cajas de materiales peligrosos (HazMat) con cartel, y los documentos del expedidor advierten que los dos materiales pueden reaccionar peligrosamente si entran en contacto. El remolque está medio vacío y quiero terminar rápido. Para cargar este envío de forma segura, ¿qué debo hacer?","options":["Cargar los dos materiales de modo que queden separados uno del otro en el remolque","Cargar los dos materiales uno al lado del otro para descargarlos juntos con facilidad","Mezclar el producto suelto de ambos para que se asiente de manera uniforme durante el transporte","Apilar los dos materiales bien apretados para que ninguno se mueva en la carretera"],"explanation":"Dos materiales peligrosos que pueden reaccionar entre sí deben cargarse de modo que se mantengan separados en el remolque."},"241":{"q":"Estoy en el muelle a punto de cargar un envío de Materiales Peligrosos que requiere rótulos (placards) y estoy haciendo mi inspección final alrededor del vehículo antes de que suba la carga. Al revisar en qué condición debe estar el equipo ANTES de que se cargue cualquier Material Peligroso en mi remolque, ¿cuál de las siguientes afirmaciones debe ser cierta?","options":["Puedo cargar ahora y verificar el ajuste de los frenos y el funcionamiento de las luces en mi primera revisión de neumáticos a las 2 horas en ruta","Los frenos y las luces ya deben estar inspeccionados y confirmados en correcto funcionamiento antes de que se cargue cualquier Material Peligroso","Solo deben funcionar los frenos de servicio del remolque; las luces se pueden revisar después porque la carga ocurre de día en el muelle","Los frenos y las luces solo importan una vez colocados los rótulos, así que puedo cargar primero e inspeccionar después de rotular"],"explanation":"Los frenos y las luces deben inspeccionarse y confirmarse en buen estado de funcionamiento antes de cargar cualquier material peligroso."},"242":{"q":"Estoy cargando a mano una tarima de paquetes corrosivos en el muelle de un expedidor, y varias cajas son pesadas y difíciles de agarrar. Para manipularlas con seguridad y evitar dañar los envases, ¿de qué parte de cada paquete debo sujetarlo para levantarlo y moverlo?","options":["Agarrarlo por las etiquetas de peligro impresas, ya que esos paneles están reforzados para soportar la manipulación","Tirar de las solapas con cinta suelta o del fleje, ya que dan el agarre más firme de la caja","Levantarlo por una sección sólida y fuerte del paquete, nunca por las partes débiles ni las etiquetas","Arrastrarlo por el muelle por el borde más cercano, ya que el corrosivo resiste las rozaduras"],"explanation":"Levante los paquetes de materiales peligrosos por una sección sólida y resistente, nunca por partes débiles ni por las etiquetas, para mantener intacto el envase."},"243":{"q":"Acaban de contratarme para transportar materiales peligrosos con placas, y el despachador me entrega una carpeta gruesa con los propios procedimientos de carga y rutas de la empresa. Al leerla, noto que las reglas de la empresa a veces van más allá de lo que aprendí para mi endoso. Para mantenerme dentro de la ley en cada viaje, además de seguir las reglas internas de mi transportista, ¿qué más estoy OBLIGADO a cumplir en todo momento?","options":["Solo las reglas internas de mi transportista, ya que la carpeta de la empresa incorpora todo lo que la ley me exige","Las instrucciones verbales de ruta que el despachador me da por radio, que anulan cualquier procedimiento escrito","Lo que digan las señales y límites locales de la vía, ya que reemplazan las reglas federales para materiales peligrosos","Las regulaciones federales y estatales de materiales peligrosos (HMR), que rigen además de las propias reglas del transportista"],"explanation":"El conductor debe cumplir las regulaciones federales y estatales de materiales peligrosos (HMR), que se aplican además de las reglas propias de la empresa."},"244":{"q":"Estoy recogiendo una carga de materiales peligrosos con rótulos y los documentos de embarque incluyen una certificación firmada del expedidor. Antes de firmar como conductor, quiero estar seguro de qué me está indicando realmente esa certificación. ¿Qué representa legalmente la certificación firmada del expedidor en el documento de embarque?","options":["Que el envío fue correctamente clasificado, descrito, embalado, marcado y etiquetado de acuerdo con los reglamentos","Que el transportista ha verificado que los cargos de flete son correctos y que el cliente ya ha pagado el envío","Que el conductor ha inspeccionado personalmente cada paquete y ha aceptado toda la responsabilidad por cualquier fuga hallada en ruta","Que la carga fue pesada dos veces de forma independiente y el peso bruto total coincide exactamente con el conocimiento de embarque"],"explanation":"La certificación firmada del remitente declara legalmente que el envío fue correctamente clasificado, descrito, empacado, marcado y etiquetado conforme a las regulaciones."},"245":{"q":"Durante mi inspección previaje noto que los cuatro carteles (placards) del remolque son de color naranja brillante, mientras que las etiquetas pequeñas en forma de rombo de los paquetes individuales en el interior son de un rojo intenso. Otro conductor me dice que los colores solo sirven para que los expedidores lleven el control del inventario. Según las reglas de comunicación de peligros, ¿qué me indica en realidad el color de una etiqueta de peligro en forma de rombo?","options":["Identifica al transportista y al expedidor responsables de la carga","Señala el tipo o clase general de peligro que presenta el material","Indica el peso total del producto cargado en ese paquete","Muestra el número de identificación ONU/NA asignado al material"],"explanation":"El color de un rótulo de peligro en forma de diamante indica el tipo o clase general de peligro, como rojo para inflamables y amarillo para oxidantes."},"246":{"q":"Estoy cargando mi remolque en el muelle y los documentos de embarque muestran un paquete pequeño de gas venenoso de la División 2.3 que pesa solo unas 40 libras, más varios tambores de un corrosivo de la Tabla 2 que suman 600 libras. El supervisor del muelle me dice que no necesito colocar ningún cartel (placard) porque toda mi carga está muy por debajo del límite de 1,001 libras. ¿Qué debo hacer respecto a la colocación de carteles antes de salir?","options":["No colocar ningún cartel, ya que el peso combinado de ambos materiales es inferior a 1,001 libras.","Colocar carteles solo para los tambores de corrosivo, porque representan la mayor parte del peso de la carga.","Colocar carteles para el gas venenoso sin importar su peso, porque ese material requiere carteles en cualquier cantidad.","Esperar a que la carga alcance las 1,001 libras en total antes de agregar carteles al remolque."],"explanation":"Los materiales de la Tabla 1, como el gas venenoso de la División 2.3, requieren letreros en cualquier cantidad, sin importar lo ligero del paquete."},"247":{"q":"Acabo de entregar una carga de líquido inflamable y el indicador de mi tanque cisterna marca vacío, así que me detengo en una parada de camiones para almorzar. Un amigo me dice que, como el tanque está descargado, puedo quitar los cuatro carteles (placards) y tratar el camión como cualquier remolque sin materiales peligrosos. Antes de tocar nada, ¿cuál es la suposición más segura que debo hacer sobre mi tanque 'vacío'?","options":["Como el indicador marca vacío, el tanque ya no contiene ningún material peligroso y es completamente seguro manipularlo.","Como el producto ya no está, puedo quitar los carteles de inmediato de forma legal, ya que los carteles solo aplican mientras el líquido se transporta realmente.","Como la carga fue entregada, el residuo del interior se ha evaporado por completo y no puede generar ningún vapor inflamable ni peligro.","Como pueden quedar residuos y vapores en el interior, el tanque todavía puede ser peligroso y debe tratarse como si aún contuviera material peligroso."],"explanation":"Un tanque de carga vaciado puede retener residuos líquidos y vapores peligrosos, por lo que debe tratarse y rotularse como cargado hasta purgarlo correctamente."},"248":{"q":"Estoy obteniendo mi endoso X y el examinador me pide que explique la diferencia entre un 'tanque de carga' (cargo tank) y un tanque portátil en la terminal. Recorriendo el patio, veo varios tanques con material peligroso líquido. ¿Cuál debo identificar correctamente como el 'tanque de carga'?","options":["El tanque a granel que está permanentemente sujeto al camión o remolque y forma parte integral del mismo","Un tanque de acero autónomo que se cargó sobre el remolque con un montacargas y se puede volver a retirar","Cualquier tanque que contenga 1,001 libras o más de líquido, sin importar cómo esté colocado sobre el vehículo","Un tambor suelto de 55 galones amarrado con correas dentro de la caja del remolque para transportarlo"],"explanation":"Un tanque de carga está permanentemente unido y forma parte integral del camión o remolque, a diferencia de un tanque portátil removible."},"249":{"q":"Estoy haciendo mi inspección previaje en una carga de HazMat con carteles de identificación (placard) y reviso el extintor montado en la cabina. El manómetro marca lleno y está bien sujeto, pero quiero confirmar que la unidad cumple el requisito antes de arrancar. ¿Cuál es la clasificación MÍNIMA del extintor que satisface el requisito para mi vehículo con carteles?","options":["Una clasificación 1 A, ya que el extintor debe manejar combustibles comunes como madera y papel","Al menos una clasificación 10 B:C","Cualquier extintor que funcione es aceptable mientras el manómetro marque lleno y esté bien sujeto","Un extintor de agua clasificado para los galones de combustible que puede contener mi tanque"],"explanation":"Un vehículo con letreros de materiales peligrosos debe llevar un extintor con clasificación de al menos 10 B:C."},"250":{"q":"Estoy transportando una carga de líquido inflamable con placas (rótulos de materiales peligrosos) por una carretera rural de dos carriles y me acerco a un cruce ferroviario sin control, sin barreras, luces ni señal de 'ALTO'. ¿Cuál de las siguientes opciones describe lo que la ley de Texas me exige hacer?","options":["Continuar a la velocidad de la vía, ya que no hay señal ni 'ALTO' que me obligue a detenerme","Reducir casi hasta detenerme, cambiar de marcha sobre las vías y cruzar para mantener el impulso","Detenerme entre 15 y 50 pies antes del riel más cercano y cruzar solo si puedo despejar las vías por completo sin detenerme","Detenerme a menos de 5 pies del riel más cercano y luego avanzar al confirmar que la vía está despejada"],"explanation":"Un vehículo con letreros siempre debe detenerse de 15 a 50 pies antes del riel más cercano y cruzar solo si puede librar las vías por completo sin detenerse."},"251":{"q":"Transporto una carga de líquido inflamable con placas (rótulos) y he hecho mi parada obligatoria de 15 a 50 pies antes del cruce de ferrocarril. Las luces están apagadas, no viene ningún tren y veo que el otro lado está despejado con espacio suficiente para todo mi equipo. Al avanzar sobre las vías, ¿cuál es la forma correcta de cruzar?","options":["Reducir a una marcha más baja a mitad del cruce para que el motor tenga más fuerza de arrastre sobre los rieles","Subir de marchas a medida que despejo para ganar velocidad y pasar menos tiempo sobre las vías","Bajar a casi paso de tortuga sobre los rieles para palpar irregularidades antes de continuar","Cruzar en una sola marcha sin cambiar de marcha en ningún momento hasta despejar por completo"],"explanation":"Cruce las vías del tren en una sola marcha seleccionada y nunca cambie de marcha sobre las vías para no quedarse parado en los rieles."},"252":{"q":"Estoy transportando una carga con placas de explosivos de la División 1.1 y necesito detenerme a pasar la noche. Mientras recorro el estacionamiento buscando un lugar, ¿cuál de estas condiciones debería hacerme rechazar una ubicación y seguir adelante?","options":["Un lugar justo al lado de un barril para quemar basura donde los trabajadores arrojan desechos al rojo vivo","Una plataforma de grava plana y bien nivelada a más de 5 pies de la parte transitada de la carretera","Un rincón sombreado del estacionamiento que se mantiene fresco gracias a una hilera de árboles altos","Un lugar con asfalto liso recién pavimentado y buen drenaje"],"explanation":"Los explosivos deben mantenerse alejados de fuentes activas de ignición, como un barril donde se quema basura que lanza llamas y chispas."},"253":{"q":"Estoy cargando varios tambores sellados de un líquido corrosivo de Clase 8 en mi remolque tipo furgón en el muelle del expedidor. El operador del montacargas me pregunta cómo quiero colocarlos para el transporte. Para manejar esta carga de forma segura y correcta, ¿cómo deben transportarse los tambores?","options":["Acostados de lado para que encajen más apretados y se muevan menos en el camino","De pie, con el lado correcto hacia arriba, tal como fueron llenados y sellados","Apilados boca abajo para que cualquier fuga quede contenida contra la tapa sellada","De lado pero bien calzados con cuñas para que no puedan rodar sueltos"],"explanation":"Los tambores de materiales peligrosos deben transportarse en posición vertical, con el lado correcto hacia arriba, porque sus cierres y sellos están diseñados para apuntar hacia arriba."},"254":{"q":"Estoy preparando un tanque de carga a granel que transporta azufre fundido, el cual se envía a una temperatura lo bastante alta como para considerarse un material a temperatura elevada. Antes de salir, quiero confirmar que el tanque muestra la marca adicional que las normas exigen para este tipo de carga. ¿Qué marca estoy buscando?","options":["Una marca de \"COLD\" (FRÍO), ya que la advertencia indica a los socorristas que el contenido debe mantenerse enfriado por debajo de la temperatura ambiente","Una marca de \"MOLTEN\" (FUNDIDO) escrita junto al nombre de envío apropiado para señalar el estado líquido de la carga","Una marca de \"HOT\" (CALIENTE), que identifica la carga como un material a temperatura elevada para quien se acerque al vehículo","Una marca de \"WET\" (MOJADO), ya que las normas tratan cualquier líquido sobrecalentado como una sustancia peligrosa cuando se moja"],"explanation":"Los materiales a temperatura elevada deben exhibir la palabra HOT para advertir a quien se acerque del peligro de quemaduras y calor."},"255":{"q":"Durante mi inspección previaje, estoy revisando los documentos de embarque de un tambor con una sustancia que el remitente advierte que es dañina para los peces y las vías fluviales si se derrama cerca de un río. Necesito confirmar que el paquete está marcado correctamente antes de aceptar la carga. ¿Qué marca debe aparecer en este paquete para identificarlo como una sustancia dañina para el medio acuático?","options":["KEEP DRY (MANTÉNGASE SECO), porque el contacto con el agua hace que este tipo de sustancia sea más peligrosa","DANGEROUS WHEN WET (PELIGROSO CUANDO ESTÁ MOJADO), ya que el peligro tiene que ver con el agua y la vía fluvial","THIS SIDE UP (ESTE LADO HACIA ARRIBA), para evitar que el líquido dañino se derrame hacia el agua","MARINE POLLUTANT (CONTAMINANTE MARINO), que identifica una sustancia dañina para el medio acuático"],"explanation":"Una sustancia dañina para las vías fluviales y la vida acuática se identifica con la marca MARINE POLLUTANT."},"256":{"q":"Soy un conductor nuevo con CDL que estudia para el endoso de HazMat, y mi despachador me dice que estoy legalmente obligado a conocer las reglas que rigen cómo se clasifican, empaquetan, marcan y transportan los materiales peligrosos. Cuando pregunto dónde están realmente escritas esas reglas vinculantes, ¿cuál es la fuente que constituye la autoridad legal correcta que debería estudiar?","options":["Las regulaciones federales (49 CFR), que contienen las Regulaciones de Materiales Peligrosos legalmente vinculantes","La Guía de Respuesta a Emergencias (ERG), que contiene las reglas de clasificación de peligros legalmente vinculantes","El Manual de CDL de Texas (DL-7C), que es la fuente legal oficial de todas las reglas de transporte de HazMat","El conocimiento de embarque y los documentos de envío, donde el transportista escribe las reglas vigentes de HazMat"],"explanation":"Las Regulaciones de Materiales Peligrosos son las normas legalmente vinculantes codificadas en el Título 49 del Código de Regulaciones Federales (49 CFR)."},"257":{"q":"Acabo de recoger una carga de corrosivos con carteles (placards) y me detuve en una parada de camiones para organizar mi papeleo antes de salir a un largo recorrido interestatal. ¿Dónde estoy obligado a llevar mi Guía de Respuesta a Emergencias (ERG) para cumplir con las normas una vez que esté en marcha?","options":["Archivada en la oficina de la terminal del transportista para que el despacho pueda consultarla durante un incidente","Dentro del vehículo, donde pueda alcanzarla mientras conduzco la carga con carteles","Junto con el papeleo del remitente, ya que el remitente prepara la información de peligro","Bajo llave en el remolque con los corrosivos para que permanezca con el producto real"],"explanation":"Lleve la Guía de Respuesta a Emergencias dentro de la cabina donde pueda alcanzarla mientras conduce, ya que solo sirve si la tiene consigo."},"258":{"q":"Está transportando una carga con carteles de identificación (placards) cuando nota que una pequeña cantidad de líquido gotea de uno de sus tambores sellados hacia el piso del remolque. La fuga es leve y la vida de nadie corre peligro inmediato. ¿Qué acción cumple mejor con el procedimiento de materiales peligrosos del DPS?","options":["Continuar su ruta hasta la próxima parada de camiones, donde un mecánico pueda inspeccionar y volver a sellar el tambor","Conducir despacio hasta el taller de reparación más cercano para arreglar la fuga antes de que se extienda más","Dejar el vehículo donde está, no moverlo y llamar a ayuda calificada para que se ocupe de la fuga","Cubrir el goteo con trapos absorbentes, seguir conduciendo y reportar la fuga al terminar el viaje"],"explanation":"Si se detecta una fuga de materiales peligrosos, nunca mueva el vehículo y llame a ayuda calificada, ya que moverlo puede esparcir la contaminación."},"259":{"q":"Estoy a punto de iniciar un viaje largo transportando líquido inflamable con carteles (placards), y quiero que mi inspección previa al viaje cumpla con el estándar de materiales peligrosos antes de salir. ¿Cuál de las siguientes opciones describe MEJOR lo que debo inspeccionar antes de que comience este viaje?","options":["Solo los documentos de embarque y los cuatro carteles, ya que el vehículo en sí se revisó en el viaje anterior","Solo los neumáticos, porque son el único elemento que las reglas me exigen volver a revisar cada 2 horas o 100 millas","Solo el sistema de frenos, ya que los frenos son el componente más crítico de una unidad cargada con materiales peligrosos","Los frenos y todo el vehículo, realizando una inspección previa completa de la unidad entera"],"explanation":"Transportar materiales peligrosos con carteles suma a sus deberes, así que realice una inspección completa previaje de los frenos y de todo el vehículo antes de salir."},"260":{"q":"Voy conduciendo una carga rotulada de cloro (Clase 2.3, gas venenoso) por una carretera rural de Texas y me acerco a un cruce ferroviario sin señalizar, sin barrera, sin luces intermitentes y sin otro tránsito alrededor. ¿Qué me exige la ley hacer en este caso?","options":["Detenerme entre 15 y 50 pies antes del riel más cercano y luego cruzar solo si puedo despejar las vías por completo","Reducir la velocidad y tratarlo como un ceda el paso, pasando despacio ya que no hay señales ni trenes que se aproximen","Detenerme solo si veo un letrero de PARE o de cruce ferroviario colocado, y de lo contrario seguir a la velocidad permitida de la carretera","Reducir a una marcha más baja antes de los rieles y mantener el motor traccionando de forma constante durante todo el cruce"],"explanation":"Una carga de gas venenoso con carteles debe detenerse entre 15 y 50 pies antes del riel más cercano en cada cruce y cruzar solo si puede despejar las vías por completo."},"261":{"q":"Obtuve mi endoso HazMat (H) y desde entonces transporto cargas con carteles (placards). Un compañero dice que, una vez que apruebas la evaluación de amenaza de seguridad y el examen escrito, ya estás listo de por vida y nunca más tienes que volver al material de HazMat. ¿Con qué frecuencia espera realmente el DPS de Texas que repita mi capacitación de HazMat para mantenerme al día?","options":["Aproximadamente cada 1 año, vinculado a cada renovación anual del certificado médico","Aproximadamente cada 3 años","Aproximadamente cada 10 años, coincidiendo con el ciclo estándar de renovación de la CDL","Nunca más — una vez aprobados el endoso y la verificación de la TSA, no se requiere recapacitación"],"explanation":"La capacitación en materiales peligrosos debe repetirse aproximadamente cada 3 años para mantener al conductor al día en manejo seguro, carteles y procedimientos de emergencia."},"262":{"q":"Estoy haciendo mi inspección previaje y los documentos de embarque indican una carga de Clase 6.1; el remolque ya muestra un rótulo en forma de diamante que dice 'POISON' (VENENO/TÓXICO). Un conductor más nuevo me pregunta de qué nos está advirtiendo realmente ese rótulo. ¿Qué afirmación debería darle?","options":["Advierte que la carga es un líquido inflamable, así que el verdadero peligro es el fuego si se enciende cerca de una llama abierta","Advierte que la carga es corrosiva, así que el verdadero peligro son las quemaduras químicas en la piel y los ojos al contacto","Advierte que el material es dañino o mortal para las personas, así que la exposición a él puede envenenar o matar","Advierte que la carga es un oxidante, así que el verdadero peligro es que hace que otros materiales ardan más rápido"],"explanation":"Un cartel POISON o TOXIC advierte que el material es dañino o mortal para las personas y puede envenenar o matar por exposición."},"263":{"q":"Transporto una carga con el cartel 'OXYGEN' (OXÍGENO, Clase 2.2) y, durante una inspección en el arcén, noto humo saliendo de una de mis llantas. Al evaluar la situación, ¿cuál de las siguientes opciones debería pesar MÁS en cómo trato el calor y cualquier llama cerca de esta carga?","options":["El oxígeno sofocará y apagará cualquier fuego pequeño antes de que se propague, así que tengo tiempo de sobra para reaccionar.","Al ser un gas no inflamable, el oxígeno no puede afectar al fuego de ninguna manera, así que la llanta es mi única preocupación.","El oxígeno enfriará la carga circundante y bajará la temperatura, reduciendo el peligro de la llanta caliente.","El oxígeno puede alimentar e intensificar un incendio, por lo que debo tratar incluso una pequeña llama cerca de esta carga como una amenaza grave."],"explanation":"El oxígeno alimenta e intensifica el fuego, por lo que cualquier llama o sobrecalentamiento cerca de una carga de oxígeno debe tratarse como una amenaza grave."},"264":{"q":"Está transportando una carga con carteles (placards) de explosivos de la División 1.2 y necesita detenerse para su descanso obligatorio según las normas federales. Al buscar un lugar legal para estacionar, ¿de qué lugar DEBE mantenerse al menos a 300 pies antes de apagar el motor?","options":["Un almacén junto a la carretera donde se reúnen habitualmente trabajadores y clientes","La línea pintada del borde de la parte transitada de la calzada","Unas vías de ferrocarril que cruzan la autopista más adelante","Otro vehículo comercial estacionado legalmente en el área de descanso"],"explanation":"Los explosivos de la División 1.1, 1.2 y 1.3 nunca pueden estacionarse a menos de 300 pies de un edificio donde se reúne gente, como un almacén junto a la carretera."},"265":{"q":"Transporto una carga con carteles (placards) y necesito dejar mi camión estacionado en el arcén de una carretera rural durante unos minutos mientras reviso un problema al borde del camino. El reglamento exige que el vehículo esté vigilado. Para contar legalmente como el encargado de la vigilancia, ¿a qué distancia de mi vehículo con carteles estacionado se me permite estar?","options":["A menos de 5 pies del vehículo, la misma distancia que debo mantener respecto a la parte transitada de la vía","A menos de 100 pies del vehículo, manteniéndolo a la vista y pudiendo moverlo si fuera necesario","A menos de 300 pies del vehículo, el mismo margen exigido alrededor de puentes y túneles","A menos de un cuarto de milla, siempre que aún pueda ver los carteles"],"explanation":"El encargado de un vehículo estacionado con carteles debe permanecer a menos de 100 pies de él, mantenerlo a la vista y poder moverlo en una emergencia."},"266":{"q":"Durante mi inspección previaje, mi despachador me dice que uno de los tanques de carga de mi unidad es un \"tanque portátil\" (portable tank) y no un camión de tanque de carga. Al inspeccionarlo para confirmarlo, ¿qué característica lo identifica CORRECTAMENTE como un tanque portátil?","options":["Está soldado permanentemente al chasis del vehículo y no se puede quitar","Es una parte estructural integral del propio bastidor del remolque","Es un contenedor a granel que no está fijado permanentemente al vehículo","Es un tanque fijo construido directamente en la cabina y la carrocería del camión"],"explanation":"Un tanque portátil es un contenedor a granel que no está fijado permanentemente al vehículo, por lo que puede cargarse y retirarse."},"267":{"q":"Estoy cargando un envío de gas comprimido de Clase 2 en una planta química y el supervisor del muelle me pregunta en qué envase debe venir ya el producto antes de que yo lo firme y lo transporte. Para aceptar la carga de forma legal y segura, ¿en qué tipo de recipiente debe estar envasado el gas comprimido?","options":["Sellado en cajas de cartón grueso unidas con flejes sobre una tarima envuelta en plástico retráctil","Cargado suelto en la plataforma abierta de un remolque plano y asegurado con correas de carga","Vertido en un remolque tolva con revestimiento, igual que se transportan los materiales secos a granel","Contenido en cilindros presurizados o transportado en un remolque de tubos fabricado para ese gas"],"explanation":"El gas comprimido está bajo presión y debe transportarse en cilindros diseñados o en un remolque de tubos fabricado para ese gas."},"268":{"q":"Estoy transportando un tanque de carga con gas inflamable licuado en una calurosa tarde de Texas, y mientras la carga se calienta al sol oigo un breve silbido y veo una pequeña nube de vapor que sale de un dispositivo accionado por resorte en la parte superior del tanque, que luego se detiene por sí solo. ¿Qué está haciendo esta válvula de alivio de presión y cómo debo proceder?","options":["Está liberando automáticamente la presión interna acumulada para evitar que el tanque reviente, así que no la toco y dejo que funcione como fue diseñada.","Es señal de que el tanque está sobrellenado más allá de su capacidad nominal, así que debo detenerme y purgar producto hasta que cese el silbido.","Está añadiendo presión al tanque para mantener el gas comprimido, así que debo esperar que siga activándose e ignorar el vapor por completo.","Está fallando y dejando escapar la carga, así que en mi próxima parada debo apretar o tapar la válvula para sellar el tanque por completo y detener la pérdida."],"explanation":"La válvula de alivio de presión libera automáticamente la presión interna acumulada para evitar que el tanque reviente, así que deja que funcione como está diseñada."},"270":{"q":"Acabo de terminar de descargar una entrega de materiales peligrosos con placas y, mientras hago la inspección alrededor del vehículo, noto que uno de los paquetes dejados en el andén tiene una mancha húmeda y descolorida que se extiende por la base y un leve olor químico. El destinatario ya firmó la recepción de la carga. Según las reglas de materiales peligrosos del DPS, ¿qué es lo correcto que debo hacer?","options":["No se me exige nada más: el destinatario firmó el envío, por lo que la responsabilidad del paquete con fuga ha pasado por completo a él","Reportar la fuga de inmediato y asegurarme de que el paquete quede contenido y se maneje de forma segura, aunque la entrega esté técnicamente completa","Apartar el paquete discretamente fuera de la vista y no decir nada, ya que reportar una fuga tras una entrega firmada solo creará papeleo y me retrasará","Volver a sellar el paquete con cinta, anotar su valor y gestionar el desecho o la reventa del contenido con descuento para recuperar la pérdida"],"explanation":"Una fuga detectada debe reportarse de inmediato y el paquete debe contenerse y manejarse de forma segura, aunque la entrega ya esté completa."},"271":{"q":"Un bidón de líquido corrosivo (Clase 8) en mi remolque se rompe durante una parada de entrega y un charco se está extendiendo por el estacionamiento. Ya advertí a los presentes, mantuve a la gente alejada y notifiqué a CHEMTREC. ¿Quién debe realizar realmente la limpieza física del material derramado?","options":["Debo tomar mis guantes y absorbente y limpiarlo yo mismo, ya que soy el conductor a cargo de la carga","El expedidor debe venir y limpiarlo, porque fue quien clasificó y empacó el material","Personal de emergencia capacitado o contratistas de limpieza calificados deben encargarse de la limpieza","Se puede dirigir a cualquier transeúnte disponible para ayudar a contener y retirar el material rápidamente"],"explanation":"La limpieza de un derrame es una tarea especializada para personal de emergencia capacitado o contratistas de limpieza calificados que puedan manejar el material de forma segura."},"272":{"q":"Acabo de completar la capacitación de concientización sobre seguridad (security awareness) requerida para mi endoso de materiales peligrosos, y un compañero me pregunta cuál era realmente el propósito de esa capacitación. Según lo que la capacitación está diseñada para lograr, ¿cuál de las siguientes opciones describe MEJOR lo que me enseñó a hacer?","options":["Memorizar las cuatro clases de riesgo que siempre requieren carteles para poder colocar los carteles más rápido en el muelle de carga","Ajustar mi distancia de seguimiento y mis puntos de frenado para mover una carga con carteles más rápido a través del tráfico","Omitir las inspecciones repetidas en ruta una vez que mi documentación ya fue verificada en la terminal","Reconocer comportamientos sospechosos o posibles riesgos de seguridad alrededor de mi carga e informar esas amenazas a las autoridades competentes"],"explanation":"La capacitación en conciencia de seguridad enseña a los conductores a reconocer comportamientos sospechosos o amenazas de seguridad a su carga y a reportarlas a las autoridades correspondientes."},"273":{"q":"Transporto una carga rotulada de corrosivos y, en una estación de pesaje, un agente estatal me pide que señale la \"descripción básica\" del material en mis documentos de embarque. ¿Qué combinación de datos debo mostrarle al agente como la descripción básica?","options":["El nombre de embarque correcto, la clase de peligro, el número de identificación y el grupo de embalaje","El nombre de embarque correcto, el peso total, el número de teléfono de emergencia y la página de la guía ERG","La clase de peligro, el color del rótulo, la firma del expedidor y la cantidad de bultos","El número de identificación, el registro del vehículo, el nombre del transportista y el plan de ruta"],"explanation":"La descripción básica de un material peligroso es el nombre de embarque correcto, la clase de peligro, el número de identificación y el grupo de embalaje."},"274":{"q":"Estoy transportando una carga con cartel (placard) de líquido inflamable de Clase 3 cuando se desata un pequeño incendio cerca de un tambor con fugas en la zona de carga. Tengo acceso a varias opciones de extinción. Para sofocar este fuego de la manera más eficaz, ¿qué debo usar?","options":["Rociarlo con un chorro de agua fuerte y constante para enfriar el líquido en llamas","Sofocarlo con espuma o usar un extintor con clasificación B:C para cortar el oxígeno","Echar arena suelta del borde de la carretera sobre las llamas hasta cubrirlas","Dejar que se consuma solo mientras te alejas y esperas a los equipos de emergencia"],"explanation":"Un incendio de líquido inflamable (Clase 3) debe sofocarse con espuma o un extintor clasificado B:C para cortar el oxígeno, nunca enfriarse con agua."},"275":{"q":"Estoy transportando un líquido inflamable de Clase 3 (tambores de gasolina) cuando, tras una fuga, uno de los tambores provoca un pequeño incendio en la zona de carga. Un transeúnte se acerca corriendo con un cubo de agua y se ofrece a ayudarme a sofocar las llamas antes de que crezcan. Antes de dejar que la arroje, ¿qué debo esperar que le haga el agua a este incendio de líquido inflamable?","options":["Sofocará las llamas rápidamente porque el agua corta el suministro de oxígeno del fuego","Enfriará la gasolina ardiendo por debajo de su punto de inflamación y apagará el fuego de inmediato","Propagará el fuego, ya que el líquido ardiendo flota sobre el agua y es arrastrado por ella","Apenas hará efecto, por lo que es lo más seguro que se puede intentar mientras llega la ayuda"],"explanation":"El agua propaga un líquido inflamable en llamas como la gasolina, porque el líquido flota sobre el agua y es arrastrado con ella."},"276":{"q":"Estoy transportando una carga con rótulos de un oxidante de Clase 5 cuando se produce un pequeño incendio en la carga. Un transeúnte agarra un extintor y dice: \"Tranquilo, si lo asfixiamos cortando el aire se apagará rápido\". Según la química de lo que llevo, ¿por qué es errónea esa suposición?","options":["Porque los oxidantes son corrosivos, así que corroen el extintor antes de poder sofocar las llamas","Porque el fuego está demasiado frío para verse afectado, ya que los oxidantes solo arden a temperaturas bajo cero","Porque los oxidantes absorben agua, así que cualquier humedad del extintor hace que el fuego se propague más rápido","Porque un oxidante libera su propio oxígeno, así que el fuego puede seguir ardiendo incluso con poco aire alrededor"],"explanation":"Un oxidante (Clase 5) libera su propio oxígeno, por lo que el fuego puede seguir ardiendo incluso con poco aire alrededor y no puede sofocarse."},"277":{"q":"Durante mi inspección previaje en el muelle, noto una pequeña mancha húmeda y un leve olor químico que sale de uno de los paquetes corrosivos (Clase 8) que un expedidor acaba de cargar. La carta de porte parece completa y la entrega es urgente. ¿Cuál es la MEJOR razón para negarme a transportar este paquete?","options":["Un paquete con fuga puede dañar a las personas y contaminar el área circundante, por lo que no debe transportarse","Una fuga pequeña solo afecta la puntualidad de la entrega, así que puedo llevarla mientras conduzca más rápido para recuperar el horario","El expedidor ya firmó la carta de porte, así que la fuga se convierte en un problema de papeleo del transportista, no mío","Una mancha leve es normal en la carga de Clase 8, así que puedo limpiar el paquete y cargarlo sin más trámite"],"explanation":"Un paquete de material peligroso con fugas puede dañar a las personas y contaminar el área, por lo que el conductor debe rechazarlo y no transportarlo."},"278":{"q":"Mi camión cisterna con carteles desarrolla una fuga de material corrosivo mientras estoy estacionado en un área de descanso al borde de la carretera. La respuesta correcta es dejar el vehículo en su lugar, mantener alejada a la gente y avisar a los servicios de emergencia. ¿En qué circunstancia estaría justificado mover realmente el vehículo con la fuga?","options":["Para llegar a la gasolinera más cercana antes de que el tanque se vacíe","Para alejar a las personas del peligro inmediato del riesgo que se propaga","Para llegar más rápido a un taller y evitar una larga demora","Para colocar el camión más cerca de un edificio y facilitar la limpieza"],"explanation":"Un vehículo con material peligroso con fugas solo debe moverse cuando sea necesario para alejar a las personas del peligro inmediato."},"279":{"q":"Transporto una carga rotulada (con carteles) de corrosivos cuando una falla del acople provoca un derrame sobre la banquina. Después de contener el peligro inmediato, mantener alejados a los curiosos, evitar que se fume y llamar a los servicios de emergencia y a CHEMTREC, las normas federales aún exigen que se informe el incidente. ¿A qué parte estoy obligado a notificar para que se pueda hacer este informe obligatorio del incidente?","options":["Al expedidor (shipper), ya que él clasificó, empacó y preparó los documentos de embarque de los corrosivos","Al jefe de bomberos local, quien debe presentar el informe oficial por escrito de cualquier derrame en la carretera","A mi empleador/transportista (carrier), que es la parte responsable de transportar la carga e informar el incidente","Al inspector de la estación de pesaje del DPS más cercana al derrame, ya que las cargas rotuladas se controlan en las básculas"],"explanation":"El transportista es la parte responsable de transportar la carga y de presentar el informe requerido del incidente con material peligroso."},"280":{"q":"Estoy caminando alrededor de mi remolque haciendo la inspección previaje de una carga que requiere un cartel (placard) de la Clase 3, líquido inflamable. Para confirmar que el cartel es correcto, reviso el rombo en busca del número de clase de peligro. ¿En qué parte del cartel debo mirar para leer ese número?","options":["En el punto superior del rombo, justo encima del símbolo","Centrado en el medio del rombo, dentro del símbolo","A lo largo de la esquina del extremo derecho del rombo","En el punto inferior del rombo, debajo del símbolo"],"explanation":"En un rótulo del DOT, el número de clase o división de peligro se coloca en la punta inferior del rombo, debajo del símbolo."},"281":{"q":"Estoy haciendo mi inspección previaje y reviso una placa (cartel) en forma de diamante en el remolque para confirmar que es la correcta. Para identificar rápidamente el tipo de peligro de un vistazo, ¿en qué zona de la placa debo buscar el símbolo de peligro (como la llama, la calavera o el trébol radiactivo)?","options":["La esquina superior de la placa, encima del nombre escrito de la clase de peligro","La esquina inferior de la placa, donde está impreso el número de la clase de peligro","El borde derecho de la placa, junto al número de identificación de cuatro dígitos","El centro de la placa, justo sobre la división diagonal de colores"],"explanation":"En un rótulo del DOT, el símbolo de peligro se coloca en la punta superior del rombo, encima del nombre escrito de la clase de peligro."},"282":{"q":"En el muelle de carga, mi despachador me dice que mi próxima carga se enviará en \"embalaje a granel\" (bulk packaging) y que debo verificarlo antes de firmar los documentos. Mientras recorro el remolque, ¿cuál de estos recipientes se ajusta correctamente a la definición de embalaje a granel?","options":["Una tarima apilada con cajas de cartón selladas, cada una con varias botellas pequeñas dentro de un material de amortiguación","Un tanque portátil grande cargado directamente con el producto, sin ningún embalaje interno que contenga el contenido","Un solo tambor de plástico de 5 galones con tapa de rosca apoyado junto a la pared del remolque","Una pequeña bolsa con cierre hermético llena de gránulos metida dentro de una caja de cartón etiquetada"],"explanation":"El embalaje a granel es un recipiente grande, como un tanque portátil, cargado directamente con el producto sin embalaje interior que contenga el contenido."},"283":{"q":"Estoy cargando mi remolque en un almacén químico y el expedidor me pide que firme por varios paquetes 'no a granel' (non-bulk) de un corrosivo de Clase 8. Mientras clasifico la carga en mi muelle, ¿qué contenedor debería esperar que coincida con esa descripción 'no a granel'?","options":["El tanque de carga de 6,000 galones montado permanentemente en un remolque aparte","El vagón cisterna de ferrocarril portátil que están maniobrando hacia el apartadero del almacén","Los tambores de acero sellados de 55 galones apilados juntos sobre un solo palé","El compartimento de la barcaza fluvial que espera recibir el mismo producto"],"explanation":"El embalaje no a granel son los recipientes más pequeños usados para transportar material peligroso, como tambores, cajas, jerricanes y bolsas."},"284":{"q":"Durante mi inspección previaje en una cisterna de carga cargada con un líquido inflamable, subo para revisar la zona de la cúpula en la parte superior del tanque. Antes de salir a la carretera, ¿en qué condición deben estar las tapas de las bocas de inspección para que la carga quede segura y sin fugas?","options":["Entreabiertas levemente para que la presión interna de vapor pueda ventilarse durante el viaje","Retiradas y guardadas en la cabina para que no vibren ni se suelten en la carretera","Dejadas completamente abiertas hasta llegar a la próxima parada de inspección en la ruta","Totalmente cerradas y debidamente selladas antes de mover el vehículo"],"explanation":"Las tapas de las bocas (cúpula) de un tanque de carga deben estar completamente cerradas y bien selladas antes de mover el vehículo para contener la carga."},"285":{"q":"Soy conductor de camión cisterna y estoy a punto de cargar un líquido inflamable de Clase 3 a través de una manguera de trasvase. Durante mi revisión previa a la carga noto que una manguera tiene la capa exterior desgastada y una pequeña grieta superficial cerca del acoplamiento. Antes de conectarla e iniciar el flujo del producto, ¿qué exige el manual respecto a las mangueras usadas para cargar o descargar?","options":["Usar solo mangueras en buen estado, por lo que debo apartar esta manguera agrietada y elegir una sin daños antes de cargar","Proceder con la carga usando esta manguera, ya que la grieta está solo en la capa exterior y el motor seguirá encendido para mantener la presión estable","Usar la manguera agrietada pero reducir el caudal, porque un trasvase más lento evita que una manguera en condición marginal falle","Conectar la manguera tal cual y simplemente apostar a una segunda persona a 25 pies para vigilar fugas durante el trasvase"],"explanation":"Las mangueras usadas para cargar o descargar material peligroso deben estar en buen estado, por lo que una manguera agrietada debe apartarse y usar una sin daños."},"286":{"q":"Estoy en una terminal preparando mi remolque con carteles de identificación (placards) y se me acumulan varias tareas: tengo que cargar combustible en el tractor, cambiar una luz de gálibo fundida, firmar los documentos de embarque y supervisar a una cuadrilla que trasvasa tambores de un líquido inflamable de Clase 3 al remolque. ¿Durante cuál de estas tareas debo ser MÁS estricto en mantener todas las fuentes de ignición —cigarrillos encendidos, llamas abiertas, herramientas que chispean— completamente alejadas de la operación?","options":["Mientras cargo combustible en el tractor, ya que el motor sigue encendido para poder vigilar el indicador de combustible mientras se llena el tanque","Mientras la cuadrilla carga los tambores de líquido inflamable de Clase 3 en el remolque, ya que los vapores pueden encenderse durante el trasvase","Mientras reemplazo la luz de gálibo fundida, ya que estaré trabajando con el cableado eléctrico cerca de la carga","Mientras reviso y firmo los documentos de embarque, ya que debo mantenerlos encima y a mi alcance antes de conducir"],"explanation":"Mantenga alejadas todas las fuentes de ignición al cargar líquidos inflamables de Clase 3, porque los vapores que escapan pueden encenderse durante el trasvase."},"287":{"q":"Estoy haciendo la inspección previaje en un camión cargado con explosivos de la División 1.1 antes de salir por una ruta designada para materiales peligrosos. Durante el recorrido alrededor del vehículo me llaman la atención varias cosas. ¿Cuál de los siguientes hallazgos, por sí solo, haría que este vehículo no sea seguro para operar y exigiría que yo lo repare antes de transportar esta carga?","options":["Uno de los guardabarros traseros está agrietado y ligeramente doblado en el borde inferior","Un triángulo reflectante de mi kit de emergencia tiene la superficie descolorida y opaca","Hay una fuga de combustible que gotea de forma constante desde un acople cerca del tanque","El espejo del lado del pasajero está mal sujeto y vibra mientras el motor está en ralentí"],"explanation":"Un vehículo que transporta explosivos no debe tener fugas de combustible ni de aceite, ya que cualquier fuga es un peligro inaceptable de incendio e ignición cerca de la carga."},"288":{"q":"Un oficial en la carretera me detiene y me pide prueba de que estoy autorizado a transportar un tanque con placas (placard) de corrosivos. Completé mi evaluación de amenaza a la seguridad de la TSA y la toma de huellas dactilares hace meses y aprobé todo. ¿Cuál ÚNICO documento entrego que realmente demuestra que mi endoso (endorsement) de HazMat (H/X) está actualmente vigente?","options":["La carta de aprobación de la evaluación de amenaza a la seguridad de la TSA que recibí por correo después de que se aprobó mi verificación de antecedentes","Mi certificado médico vigente del examinador médico del DOT, ya que es lo que prueba que estoy físicamente apto para conducir","El recibo de las huellas dactilares y el paquete de solicitud que entregué en la oficina de licencias para obtener el endoso","Mi licencia de conducir comercial (CDL), porque el endoso H o X está impreso directamente en la propia licencia"],"explanation":"El endoso de materiales peligrosos es un código (H, o X para tanque más materiales peligrosos) impreso directamente en el frente de su licencia de conducir comercial."},"289":{"q":"Transporto una carga con carteles (placards) de corrosivos y necesito hacer una parada corta para revisar mi papeleo. Los únicos lugares que encuentro están cerca de una carretera de dos carriles. Según las reglas para estacionar un vehículo con carteles, ¿cuál de estos lugares me pondría en infracción?","options":["Un acotamiento donde mi camión quedaría a solo 3 pies de la parte transitada de la carretera","Un lote de grava retirado unos 20 pies del borde de la parte transitada de la carretera","Un espacio en área de descanso medido a 10 pies de la parte transitada de la carretera","Un apartadero amplio que mantiene mi camión a 8 pies completos de la parte transitada de la carretera"],"explanation":"Un vehículo con carteles de peligro no debe estacionarse a menos de 5 pies de la parte transitada de la carretera."},"290":{"q":"Estoy recogiendo una carga con placas (placards) y el remitente me entrega la documentación con el nombre de embarque correcto, la clase de peligro y el número de identificación. El transportista despachó el viaje y reportará cualquier incidente. Al pensar en quién más es legalmente responsable del transporte seguro de este material peligroso, ¿qué parte completa la cadena de responsabilidad compartida junto al remitente y el transportista?","options":["El cliente que recibe la carga, ya que la acepta en el muelle","El conductor, que inspecciona la carga, rechaza fugas, coloca las placas y conduce con seguridad","El agente de la TSA que emitió mi autorización tras la verificación de antecedentes","El despachador, que solo asigna la ruta y nunca toca la carga"],"explanation":"El conductor completa la cadena de seguridad de materiales peligrosos al inspeccionar la carga, rechazar envíos con fugas o mal marcados, colocar carteles en todos los lados y conducir con seguridad."},"291":{"q":"Estoy cargando un envío radiactivo de Clase 7, y el expedidor me dice que verifique que las etiquetas coincidan con el índice de transporte antes de firmar los documentos. Al mirar el paquete, veo dos etiquetas impresas con una categoría en números romanos que indica el nivel de radiación. ¿Qué conjunto de designaciones de categoría debería esperar encontrar en esas etiquetas radiactivas?","options":["Categorías A, B o C, con letras que coinciden con el grupo de embalaje","Categorías 1, 2 o 9, que coinciden con los números de clase de peligro","Categorías I, II o III, que indican el nivel de radiación","Categorías X, Y o Z, que marcan el rango del índice de transporte"],"explanation":"Las etiquetas radiactivas (Clase 7) llevan una categoría en números romanos — I, II o III — que indica el nivel de radiación y el índice de transporte."},"292":{"q":"Estoy cargando un remolque con dos paquetes distintos de materiales peligrosos, y los documentos de embarque indican que son reactivos entre sí. El expedidor no me dijo que los mantuviera separados, y hay espacio para ponerlos uno al lado del otro. Antes de asegurarlos juntos, ¿cuál es la verdadera preocupación de seguridad que debo sopesar?","options":["Ponerlos uno al lado del otro está bien porque el embalaje por sí solo está hecho para evitar que dos materiales cualesquiera interactúen","La única preocupación es que el peso combinado pueda superar el umbral de 1,001 libras que obliga a colocar carteles (placards)","No ocurre nada importante; los materiales reactivos simplemente se neutralizan entre sí cuando se almacenan en el mismo espacio","Cargar los dos químicos reactivos juntos podría iniciar un incendio o una reacción química, por lo que deben mantenerse separados"],"explanation":"Los materiales reactivos incompatibles deben mantenerse separados durante la carga porque el contacto puede provocar un incendio o una reacción química peligrosa."},"293":{"q":"Un tambor en mi remolque con carteles (placards) está derramando un líquido desconocido sobre el arcén, y los documentos de embarque no aclaran exactamente qué es. Para averiguar cuál es la sustancia y poder dar información precisa a los socorristas, ¿cuál de estas cosas NUNCA debo hacer?","options":["Probar o tocar el material para ayudar a identificar qué es","Revisar el nombre de embarque apropiado y el número de identificación en los documentos de embarque","Buscar el número de identificación de cuatro dígitos en la Guía de Respuesta a Emergencias (ERG)","Anotar la clase de peligro que aparece en el cartel (placard) y las etiquetas"],"explanation":"Nunca pruebe ni toque un material para identificarlo, ya que incluso una cantidad mínima puede causar lesiones graves, envenenamiento o quemaduras químicas."},"294":{"q":"Usted transporta una carga de líquido inflamable con placas (carteles de identificación) y se detiene en un área de descanso al costado de la carretera. Mientras está fuera de la cabina, nota llamas en la parte trasera del remolque cerca de la carga. El fuego ya es demasiado grande para sofocarlo con su pequeño extintor. ¿Qué debe hacer PRIMERO?","options":["Subir y tratar de conducir el remolque en llamas hacia un campo abierto lejos del área de descanso","Mantener a las personas alejadas del vehículo y avisar a los servicios de emergencia para pedir ayuda","Abrir las puertas del remolque para ventilar el humo y alcanzar la carga que arde adentro","Apartar los documentos de embarque en la cabina para que el fuego no los destruya"],"explanation":"Ante un incendio de materiales peligrosos que no puede controlar un extintor manual, proteja primero la vida manteniendo a las personas alejadas y notificando a los servicios de emergencia."},"295":{"q":"Estoy haciendo mi inspección previa al viaje en un remolque con rótulos que la cuadrilla del muelle cargó durante la noche, y los documentos sobre el asiento del conductor indican una carga corrosiva de Clase 8. Antes de arrancar, ¿qué es lo ÚNICO que DEBO confirmar sobre los rótulos ya colocados en los cuatro lados?","options":["Que el color del rótulo coincida con el esquema de pintura y las letras del costado de mi tractor","Que haya un rótulo en cada uno de los cuatro lados de modo que se lea desde cualquier dirección","Que los rótulos identifiquen correctamente el material que realmente transporto, tal como figura en los documentos de embarque","Que los rótulos coincidan con el tipo de combustible que quema el tractor que arrastra la carga"],"explanation":"El conductor debe verificar que los carteles identifiquen correctamente el material que realmente transporta, cotejándolos con los documentos de embarque."},"296":{"q":"Estoy cargando un envío de corrosivos (Clase 8) que requiere carteles (placards), pero se me acabaron los carteles de Clase 8 en mi caja de suministros. Sí tengo carteles sobrantes de Clase 3 (Inflamable) de un viaje anterior, y el camión ya lleva varias horas de retraso. ¿Cuál es la forma correcta de pensar sobre cómo rotular esta carga antes de salir?","options":["Usar los carteles de Clase 3 es aceptable para un viaje corto, ya que mostrar cualquier cartel igual advierte a otros conductores que transporto material peligroso","Puedo circular sin ningún cartel siempre que mantenga al alcance en el asiento los documentos de embarque que indican Clase 8","Colocar los carteles de Clase 3 en dos lados y dejar los otros dos lados en blanco está permitido porque la carga solo está parcialmente rotulada","Mostrar los carteles equivocados (Clase 3) es ilegal e inseguro, así que no debo mover la carga hasta tener los carteles correctos de Clase 8"],"explanation":"Los carteles deben ser correctos en los cuatro lados, por lo que no se puede mover una carga con carteles equivocados; un corrosivo de Clase 8 requiere carteles de Clase 8."},"297":{"q":"Está transportando una carga de líquido inflamable con carteles (placards) a través de Texas y su reloj de horas de servicio lo obliga a tomar un descanso en los próximos 20 minutos. Más adelante puede ver un estacionamiento de centro comercial repleto, un área de descanso al borde de la carretera abarrotada de familias y un apartadero de grava tranquilo, bien alejado de cualquier multitud. ¿Dónde debería planificar su parada?","options":["En el apartadero de grava tranquilo, eligiendo un lugar seguro lejos de la gente cada vez que se detiene con una carga con carteles","En el área de descanso abarrotada, porque las áreas de descanso son los únicos puntos de parada legalmente aprobados para vehículos con carteles","En el estacionamiento del centro comercial repleto, ya que permanecer en una zona concurrida y bien iluminada con testigos mantiene la carga más segura frente al robo","Donde se encuentre cuando se acabe el tiempo, estacionando justo al borde de la parte transitada de la carretera para no perder tiempo de conducción"],"explanation":"Al transportar una carga con placas, planifique siempre detenerse en un lugar seguro y alejado de las personas para minimizar la exposicion si algo sale mal."},"298":{"q":"Acabo de obtener mi endoso H y estoy repasando por qué existen todas las normas de materiales peligrosos antes de mi primer viaje con carteles (placards). Un conductor con experiencia me dice que las normas se reducen a tres objetivos centrales: contener el producto, comunicar el riesgo y uno más. EXCEPTO uno de los siguientes objetivos, todos reflejan el verdadero propósito de las normas de materiales peligrosos. ¿Qué opción NO pertenece porque describe mal el tercer objetivo?","options":["Contener el material para que un derrame se prevenga o se limite","Mover la carga más rápido y reducir los costos de entrega del transportista","Comunicar el peligro mediante carteles, etiquetas y documentos de embarque","Asegurar que el producto llegue a su destino de forma segura y sin daños"],"explanation":"Los objetivos de las normas de materiales peligrosos son contener el producto, comunicar el riesgo y garantizar un transporte seguro, no acelerar la entrega ni reducir costos."},"299":{"q":"Soy un conductor nuevo de materiales peligrosos que recoge una carga de corrosivos. Los tambores parecen sellados, pero noto que los documentos de embarque se completaron antes de que yo llegara y no tuve voz en cómo se clasificó ni se empacó el producto. Al determinar quién tiene cada deber, ¿cuál de las siguientes es responsabilidad del EXPEDIDOR y no mía como conductor?","options":["Detenerse de 15 a 50 pies antes de cualquier cruce de ferrocarril y no cambiar de marcha al cruzar","Colocar carteles (placards) en los cuatro lados del remolque y mantener los documentos a mi alcance mientras conduzco","Determinar correctamente el nombre de embarque apropiado y elegir el empaque adecuado para el material","Rechazar el embarque si un tambor tiene fugas e inspeccionar la carga antes de transportarla"],"explanation":"El expedidor clasifica el material, determina el nombre de embarque correcto y selecciona el embalaje adecuado antes de que la carga llegue al conductor."}},"hi":{"0":{"q":"मैंने अभी-अभी अपना H एंडोर्समेंट प्राप्त किया है और एक नया ड्राइवर मुझसे पूछता है कि ये सारे प्लेकार्ड, शिपिंग पेपर और पैकेजिंग के नियम आखिर क्यों बनाए गए हैं। निम्नलिखित में से कौन-सा खतरनाक सामग्री नियमों के मुख्य उद्देश्य का सबसे अच्छा वर्णन करता है?","options":["सामग्री को इस तरह रोककर रखना कि वह बाहर न निकल सके, और खतरे की सूचना देना ताकि दूसरे लोग दूर रह सकें और सुरक्षित रूप से प्रतिक्रिया दे सकें","प्लेकार्ड वाले लदान को राजमार्ग की लेन और मार्गों तक प्राथमिकता पहुंच देकर तेज़ डिलीवरी की गारंटी देना","प्रत्येक शिपमेंट का दस्तावेज़ीकरण करना ताकि वाहक ग्राहक से सही खतरनाक-हैंडलिंग अधिभार वसूल सके","भारी खतरनाक लदान को उपलब्ध सबसे छोटी सड़कों पर भेजकर वाहक की ईंधन लागत को कम करना"],"explanation":"खतरनाक माल के नियम सामग्री को रोककर रखने के लिए हैं ताकि वह बाहर न निकले और खतरे की सूचना देने के लिए हैं ताकि दूसरे दूर रहें और सुरक्षित प्रतिक्रिया दें।"},"1":{"q":"मुझे अभी-अभी एक एसे मार्ग पर काम के लिए रखा गया है जिसमें प्लॅकार्ड (placard) वाले संक्षारक (corrosive) पदार्थ का भार ढोया जाएगा, और मेरे पास पहले से ही टैंकर (tanker) एंडोर्समेंट वाला क्लास A CDL है। इस यात्रा को कानूनी रूप से करने से पहले, निम्न में से मुझे क्या करना आवश्यक है?","options":["कुछ अतिरिक्त नहीं — टैंकर एंडोर्समेंट वाला मेरा क्लास A CDL पहले से ही किसी भी प्लॅकार्ड वाले भार को कवर करता है","खतरनाक सामग्री (H) एंडोर्समेंट प्राप्त करना, जिसके लिए TSA सुरक्षा खतरा मूल्यांकन और उंगलियों के निशान देना आवश्यक है","डबल्स/ट्रिपल्स एंडोर्समेंट जोड़ना, क्योंकि प्लॅकार्ड वाले भार को कई ट्रेलरों में बांटा जाना चाहिए","यात्री (passenger) एंडोर्समेंट जोड़ना, क्योंकि प्लॅकार्ड वाले भार को यात्री परिवहन के समान ही विनियमित किया जाता है"],"explanation":"प्लेकार्ड वाली किसी भी मात्रा के खतरनाक माल को ढोने के लिए खतरनाक माल (H) समर्थन जरूरी है, जिसके लिए TSA सुरक्षा खतरा आकलन और उंगलियों के निशान देना आवश्यक है।"},"2":{"q":"मेरे पास पहले से ही टेक्सास क्लास A CDL और एक वैध DOT मेडिकल प्रमाणपत्र है। मेरा नया नियोक्ता चाहता है कि मैं प्लेकार्ड लगाने योग्य संक्षारक (corrosive) माल ढोना शुरू करूँ, इसलिए मुझे H एंडोर्समेंट जोड़ना है। जब मैं DPS क्लर्क से पूछता हूँ कि इस एंडोर्समेंट के लिए कौन-सा अतिरिक्त कदम आवश्यक है जो मेरे मौजूदा लाइसेंस में नहीं था, तो वह सबसे अधिक संभावना से मुझे क्या बताएगी?","options":["कुछ भी अतिरिक्त आवश्यक नहीं है; एक बार जब आपके पास वैध DOT मेडिकल कार्ड के साथ क्लास A CDL हो, तो H एंडोर्समेंट बिना किसी अतिरिक्त आवश्यकता के आपके लाइसेंस पर छाप दिया जाता है","एंडोर्समेंट जारी होने से पहले आपको दूसरी, अधिक विस्तृत DOT शारीरिक जाँच पास करनी होगी और एक अद्यतन मेडिकल एग्जामिनर प्रमाणपत्र जमा करना होगा","एंडोर्समेंट जारी होने से पहले आपको TSA सुरक्षा खतरा मूल्यांकन पास करना होगा, जिसमें पृष्ठभूमि जाँच और फिंगरप्रिंटिंग शामिल है","आपको केवल मानक CDL दृष्टि जाँच फिर से पास करनी होगी ताकि यह पुष्टि हो सके कि आप अब भी दूरी से प्लेकार्ड पढ़ सकते हैं"],"explanation":"खतरनाक माल समर्थन जारी होने से पहले TSA सुरक्षा खतरा आकलन पास करना आवश्यक है, जिसमें पृष्ठभूमि जांच और उंगलियों के निशान शामिल हैं।"},"3":{"q":"मुझे संक्षारक (कोरोसिव) सामग्री का एक लदान ढोने के लिए रखा गया है और रवाना होने से पहले मैं डॉक पर कागजात की जांच कर रहा हूं। मैं देखता हूं कि खतरा वर्ग, उचित शिपिंग नाम और UN पहचान संख्या पहले से ही शिपिंग कागजात पर दर्ज हैं, लेकिन मैं यह सुनिश्चित करना चाहता हूं कि यह काम सही पक्ष ने किया हो। खतरनाक सामग्री नियमों के तहत, सबसे पहले सामग्री को खतरनाक के रूप में पहचानना और उन शिपिंग कागजातों को तैयार करना किसका काम था?","options":["मोटर कैरियर, क्योंकि कैरियर यात्रा का स्वामी है और लदान को ढोने तथा किसी भी घटना की सूचना देने के लिए जिम्मेदार है","चालक, क्योंकि कागजात अपनी पहुंच में रखना और कुछ गलत दिखने पर लदान को अस्वीकार करना मेरा ही काम है","प्राप्तकर्ता, क्योंकि डिलीवरी स्वीकार करने वाली कंपनी सामग्री की पुष्टि करती है और खतरनाक माल के लिए हस्ताक्षर करती है","प्रेषक (शिपर), क्योंकि प्रेषक सामग्री को वर्गीकृत करता है, उसे नाम देता है, पैक करता है और लेबल लगाता है तथा शिपिंग कागजात तैयार करता है"],"explanation":"शिपर खतरनाक सामग्री का वर्गीकरण, नामकरण, पैकेजिंग और लेबलिंग करता है और माल चालक तक पहुँचने से पहले शिपिंग कागजात तैयार करता है।"},"4":{"q":"मैं टेक्सास में संक्षारक (corrosive) पदार्थों का प्लेकार्ड लगा हुआ भार ढो रहा हूँ और अभी-अभी इंटरस्टेट हाईवे पर आया हूँ। गाड़ी चलाते समय खतरनाक माल के शिपिंग दस्तावेज़ों के नियमों का पालन करने के लिए, ये दस्तावेज़ इस समय कहाँ होने चाहिए?","options":["सीट बेल्ट बँधी होने पर मेरी पहुँच के भीतर, या चालक के दरवाज़े की जेब में, और मेरे बाकी कागज़ातों के ऊपर","स्लीपर बर्थ में सुरक्षित रखे हों ताकि खुली खिड़की की हवा उन्हें बिखेर न दे","ट्रेलर के बाहर प्लेकार्ड के पास लगे दस्तावेज़ बॉक्स में रखे हों","ट्रेलर में माल के नीचे दबे हों ताकि वे असली कार्गो के साथ ही रहें"],"explanation":"वाहन चलते समय खतरनाक माल के शिपिंग कागजात सीट बेल्ट लगाए हुए चालक की पहुँच में, या चालक के दरवाजे की पाउच में, और अन्य कागजात के ऊपर होने चाहिए।"},"5":{"q":"मैं एक नया चालक हूं और एक मिश्रित माल ट्रेलर लोड कर रहा हूं जिसमें कई गैर-विनियमित वस्तुओं के साथ एक खतरनाक सामग्री (HazMat) शामिल है। डॉक से निकलने से पहले जब मैं संयुक्त शिपिंग पेपर की जांच करता हूं, तो कागजात को वैध बनाने के लिए उस दस्तावेज़ पर खतरनाक सामग्री को कैसे पहचाना जाना चाहिए?","options":["पृष्ठ पर सबसे अंत में दर्ज किया गया ताकि यह सामान्य माल की पंक्तियों से अलग रहे","पहले दर्ज किया गया, या हाइलाइट किया गया, या HM कॉलम में 'X' से चिह्नित किया गया","केवल एक अलग पिछले पृष्ठ पर लिखा गया जो माल सूची के पीछे स्टेपल किया गया हो","सामान्य प्रिंट में छोड़ दिया गया क्योंकि ट्रेलर पर लगे प्लेकार्ड पहले से ही खतरे का संकेत देते हैं"],"explanation":"मिश्रित शिपिंग कागज पर खतरनाक माल की प्रविष्टि को पहले लिखकर, हाइलाइट करके, या HM कॉलम में 'X' से चिह्नित करके अलग पहचानने योग्य बनाना चाहिए।"},"6":{"q":"मैं Table 2 का संक्षारक (corrosive) माल ढो रहा हूँ और टर्मिनल से निकलने से पहले मैंने चारों तरफ ट्रेलर पर चार हीरे के आकार के प्लेकार्ड (placards) लगाए हैं। एक नया चालक पूछता है कि ये हीरे इतने महत्वपूर्ण क्यों हैं कि मैं इनके बिना चलने से मना कर दूँगा। कौन-सा स्पष्टीकरण इन प्लेकार्डों के मुख्य उद्देश्य को सही ढंग से बताता है?","options":["ये प्रमाणित करते हैं कि शिपर ने माल को सही ढंग से वर्गीकृत और पैक किया है, इसलिए मुझे खुद शिपमेंट की जाँच करने की ज़रूरत नहीं","ये साबित करते हैं कि मेरे पास वैध H एंडोर्समेंट है और मैंने इस माल को ढोने के लिए आवश्यक TSA पृष्ठभूमि जाँच पास की है","ये वाहन के आसपास सभी को माल से उत्पन्न खतरे के बारे में चेतावनी देते हैं, ताकि आपातकालीन कर्मी और जनता सुरक्षित रूप से प्रतिक्रिया दे सकें","ये विनियमित सामग्री का कुल सकल वजन दर्ज करते हैं, ताकि तौल अधिकारी पुष्टि कर सकें कि मैं 1,001 lb से कम पर हूँ"],"explanation":"प्लेकार्ड वाहन के आसपास सभी को माल से उत्पन्न खतरे की चेतावनी देते हैं ताकि बचावकर्मी और जनता सुरक्षित प्रतिक्रिया दे सकें।"},"7":{"q":"मैं प्लेकार्ड (खतरा-सूचक चिह्न) लगे संक्षारक (corrosive) माल का परिवहन कर रहा हूं, और यार्ड पर्यवेक्षक मुझे बताता है कि एक सहकर्मी ने पहले ही ट्रेलर के दोनों किनारों और पीछे की ओर आवश्यक प्लेकार्ड लगा दिए हैं। गेट से बाहर निकलने से पहले, प्लेकार्ड लगाने के नियम का पालन करने के लिए मुझे अभी भी क्या करना चाहिए, इसे कौन-सा कथन सही ढंग से बताता है?","options":["और कुछ करने की जरूरत नहीं; दोनों किनारे और पीछे की ओर ढके होने पर, तीन प्लेकार्ड संक्षारक माल के लिए नियम को पूरा करते हैं।","ट्रेलर की छत पर एक प्लेकार्ड लगाएं ताकि वह ऊपर से दिखे, लेकिन आगे की ओर जरूरी नहीं क्योंकि केबिन दृश्य को रोक देता है।","पीछे के प्लेकार्ड को आगे के बंपर पर ले जाएं, क्योंकि आगे और दोनों किनारे ही वे एकमात्र स्थान हैं जिनकी अधिकारी वास्तव में जांच करता है।","वाहन के आगे की ओर भी एक प्लेकार्ड लगाएं, ताकि माल आगे, पीछे और दोनों किनारों पर प्लेकार्ड से चिह्नित हो।"],"explanation":"प्लेकार्ड वाहन के चारों ओर — आगे, पीछे और दोनों तरफ — लगाए जाने चाहिए, और प्रत्येक उस दिशा से पढ़ने योग्य हो जिस ओर वह है।"},"8":{"q":"मैं प्लेकार्ड लगा हुआ संक्षारक (corrosive) माल ढो रहा हूँ, तभी मेरे एक ड्रम से किनारे पर रिसाव शुरू हो जाता है। मैंने राहगीरों को सावधान कर दिया और आपातकालीन दल को बुला लिया, लेकिन डिस्पैचर मुझसे कहता है कि मैं अग्निशामकों को उस दस्तावेज़ से संदर्भ संख्या पढ़कर सुनाऊँ जो बताता है कि इसी सामग्री के रिसाव को कैसे संभालना है। मुझे अपने केबिन में कौन-सी वस्तु इस्तेमाल करनी चाहिए?","options":["आपातकालीन प्रतिक्रिया गाइडबुक (ERG), जो राहत दल को सामग्री को उसके खतरे और सुरक्षात्मक कार्रवाइयों से मिलाने में मदद करती है","शिपिंग पेपर, क्योंकि माल का सही शिपिंग नाम और UN/NA संख्या पहले से ही उसमें दर्ज है","वाहन का मालिक मैनुअल, जो ट्रक की प्रणालियों और निर्माता की आपातकालीन प्रक्रियाओं को कवर करता है","बिल ऑफ लैडिंग, क्योंकि यह माल और घटना की रिपोर्टिंग के लिए वाहक के संपर्क विवरण दर्ज करता है"],"explanation":"हर खतरनाक माल चालक को आपातकालीन प्रतिक्रिया गाइडबुक (ERG) रखनी चाहिए, जो बचावकर्मियों को सामग्री को उसके खतरे और सुरक्षात्मक कार्रवाई से मिलाने देती है।"},"9":{"q":"मैं प्लेकार्ड लगे क्लास 3 ज्वलनशील तरल पदार्थ का भार लेकर टर्मिनल से निकलने वाला हूँ। मेरा डिस्पैचर मुझ पर जल्दी निकलने का दबाव डाल रहा है क्योंकि मैं समय से पीछे चल रहा हूँ। निकलने से पहले अपना काम सुरक्षित और कानूनी रूप से करने के लिए, मुझे इनमें से क्या करना चाहिए?","options":["हाईवे पर अन्य चालकों का ध्यान न खींचने के लिए ट्रेलर से प्लेकार्ड हटा देना","यात्रा शुरू करने से पहले वाहन, टायरों और भार की सुरक्षा (securement) की सावधानीपूर्वक जाँच करना","डॉक पर इंतज़ार में खोया समय पूरा करने के लिए इस बार प्री-ट्रिप निरीक्षण छोड़ देना","ट्रेलर के ब्रेक अलग कर देना ताकि यूनिट आसानी से चले और रास्ते में कम ईंधन लगे"],"explanation":"खतरनाक माल ढोने के लिए यात्रा शुरू करने से पहले वाहन, टायरों और लोड सुरक्षा का सावधानीपूर्वक निरीक्षण आवश्यक है, और समय का दबाव इसे छोड़ने का बहाना नहीं बनता।"},"10":{"q":"प्लेकार्ड वाले लोड को चलाते समय, आपको अपने टायरों की जांच करनी चाहिए:","options":["केवल एक बार बिल्कुल शुरुआत में","शुरुआत में और हर पड़ाव (स्टॉप) पर","पूरी यात्रा के दौरान कभी नहीं","हफ्ते में सिर्फ एक बार ही काफी है"],"explanation":"यात्रा से पहले और हर बार जब आप रुकें तब टायरों की जांच करें; रिसाव वाले या पंक्चर टायर को हटा दें।"},"11":{"q":"अपने प्लेकार्ड लगे खतरनाक माल (हैज़मैट) के साथ मार्ग में अनिवार्य टायर जाँच के दौरान, मुझे पता चलता है कि ट्रेलर का एक टायर खतरनाक रूप से अधिक गरम हो गया है। टेक्सास के खतरनाक माल नियमों के अनुसार, आगे बढ़ने से पहले मुझे क्या करना चाहिए?","options":["टायर को ठंडा करने के लिए उस पर पानी डालें, फिर जाँच कराने के लिए अगले सर्विस स्टॉप तक गाड़ी चलाते रहें","सही दबाव बहाल करने के लिए हवा भरें, फिर सावधानी से तब तक चलाएँ जब तक टायर अपने आप ठंडा न हो जाए","अधिक गरम टायर को हटा दें और उसे वाहन से सुरक्षित दूरी पर रखें, और जब तक उसे ठीक न कर लिया जाए तब तक गाड़ी न चलाएँ","अपनी गति कम करें और गाड़ी चलाते रहें ताकि अगली अनिवार्य जाँच से पहले हवा का प्रवाह टायर को ठंडा कर दे"],"explanation":"प्लेकार्ड वाले भार पर अधिक गरम टायर आग और विस्फोट का खतरा है, इसलिए उसे हटाएँ, वाहन से सुरक्षित दूरी पर रखें और ठीक होने तक वाहन न चलाएँ।"},"12":{"q":"मेरे पास ऑक्सीकारकों (oxidizers) का माल है और वाहन पर प्लेकार्ड लगे हैं, और मैं अपने ब्रेक के लिए एक विश्राम क्षेत्र में रुका। दूसरे ट्रक का एक साथी मेरे पास आकर मेरे साथ सिगरेट पीना चाहता है। कानून के भीतर रहने के लिए, धूम्रपान करते समय हम दोनों को मेरे ट्रेलर से कम से कम कितनी दूर रहना चाहिए?","options":["कम से कम 5 फीट, वही बफर जो सड़क के चलने वाले हिस्से से दूर पार्किंग करते समय आवश्यक है","कम से कम 10 फीट, इतनी दूर कि कोई लौ ट्रेलर तक न पहुँच सके","कम से कम 100 फीट, वही बफर जो किसी इमारत के पास विस्फोटकों के लिए उपयोग किया जाता है","वाहन से कम से कम 25 फीट, क्योंकि यह ऑक्सीकारक (oxidizers) ले जा रहा है"],"explanation":"विस्फोटक, ऑक्सीकारक या ज्वलनशील पदार्थ ले जाने वाले प्लेकार्ड वाले वाहन से धूम्रपान या किसी भी खुली ज्वाला को कम से कम 25 फुट दूर रखना चाहिए।"},"13":{"q":"मैं अपने ट्रेलर में डिवीजन 1.2 विस्फोटक लादने के लिए एक लोडिंग डॉक पर आ गया हूँ। डॉक का दल बक्से चढ़ाना शुरू करने से पहले मेरे ट्रक को तैयार करने का इंतज़ार कर रहा है। विस्फोटक लादना शुरू होने से पहले मुझे अपने वाहन के साथ क्या करना चाहिए?","options":["लोडिंग शुरू होने से पहले इंजन बंद कर दें और पार्किंग ब्रेक लगाकर वाहन को सुरक्षित कर लें","इंजन को चालू (आइडल) रहने दें ताकि लोडिंग के दौरान एयर ब्रेक में दबाव बना रहे और केबिन का क्लाइमेट कंट्रोल चलता रहे","इंजन चालू रहने दें पर केवल पार्किंग ब्रेक लगा दें, क्योंकि इंजन अपने आप में कोई वास्तविक प्रज्वलन स्रोत नहीं है","सभी खिड़कियाँ नीचे करें और डॉक दल को लोडिंग शुरू होने की सूचना देने के लिए हॉर्न दो बार बजाएँ"],"explanation":"विस्फोटक लादने या उतारने से पहले, प्रज्वलन स्रोत हटाने के लिए इंजन बंद करें और वाहन को सुरक्षित करने के लिए पार्किंग ब्रेक लगाएँ।"},"14":{"q":"मैं एक ईंधन टर्मिनल पर ड्रमों में गैसोलीन (पेट्रोल) का लोड उठा रहा हूँ, और मेरा डिस्पैचर मुझसे प्लेकार्ड लगाने से पहले शिपिंग पेपर्स पर खतरा वर्ग की पुष्टि करने को कहता है। खतरा वर्गों को जिस तरह परिभाषित किया गया है, उसके आधार पर इस गैसोलीन लोड के आगे कौन सा खतरा वर्ग संख्या होनी चाहिए?","options":["वर्ग 1, क्योंकि ज्वलनशील तरल पदार्थ सबसे अधिक विस्फोट खतरा रखते हैं और विस्फोटकों के साथ समूहीकृत होते हैं","वर्ग 3, क्योंकि गैसोलीन एक ज्वलनशील तरल है और यही इस वर्ग के अंतर्गत आता है","वर्ग 8, क्योंकि गैसोलीन संपर्क में आने पर त्वचा को जला सकता है और सामग्री को संक्षारक की तरह नुकसान पहुँचा सकता है","वर्ग 2, क्योंकि गैसोलीन ज्वलनशील वाष्प छोड़ता है और इसे एक ज्वलनशील गैस के रूप में संभाला जाता है"],"explanation":"गैसोलीन एक ज्वलनशील तरल है, जो ठीक वही है जिसे खतरा वर्ग 3 कवर करता है।"},"15":{"q":"मैं डॉक पर एक खेप लोड कर रहा हूँ, और शिपिंग पेपर पर विस्फोटकों की एक खेप के लिए उचित शिपिंग नाम, खतरा वर्ग और UN नंबर सूचीबद्ध है। अपने ट्रेलर पर प्लेकार्ड लगाने और निकलने से पहले, मुझे उस खतरा वर्ग संख्या की पुष्टि करनी है जो इस खेप को विस्फोटक के रूप में पहचानती है। कौन सा खतरा वर्ग सही है?","options":["वर्ग 8, जो बैटरी एसिड जैसे संक्षारक पदार्थों को कवर करता है","वर्ग 3, जो गैसोलीन जैसे ज्वलनशील तरल पदार्थों को कवर करता है","वर्ग 1, जो डायनामाइट जैसे विस्फोटकों को कवर करता है","वर्ग 7, जो यूरेनियम जैसी रेडियोधर्मी सामग्री को कवर करता है"],"explanation":"डायनामाइट जैसे विस्फोटक खतरा वर्ग 1 हैं, जो नौ खतरा वर्गों में से पहला है।"},"16":{"q":"मैं टर्मिनल पर दो खतरनाक सामग्री (हैज़मैट) के लोड उठा रहा हूँ। पहला केवल 300 पाउंड वज़न वाले टेबल 2 के किसी काट करने वाले (कॉरोसिव) पदार्थ का एक छोटा ड्रम है; दूसरा ज़हरीली गैस (क्लास 2.3) का एक सिलेंडर है। मेरा डिस्पैचर मुझसे कहता है कि मुझे \"प्लाकार्ड की जाने वाली मात्रा\" के लिए प्लाकार्ड लगाने होंगे। यह वाक्यांश वास्तव में मुझे क्या बताता है कि प्लाकार्ड कब ज़रूरी होते हैं?","options":["खतरनाक सामग्री ढोने वाले किसी भी वाहन को हमेशा प्लाकार्ड दिखाना चाहिए, इसलिए 300 पाउंड काटक और ज़हरीली गैस दोनों को वज़न या क्लास की परवाह किए बिना प्लाकार्ड चाहिए","प्लाकार्ड कानूनी रूप से केवल तभी ज़रूरी हैं जब वाहन अंधेरे में या कम दृश्यता में सार्वजनिक राजमार्ग पर चल रहा हो","किसी भी लोड के लिए प्लाकार्ड की ज़रूरत नहीं है क्योंकि दोनों शिपमेंट इस यात्रा के लिए 1,001 पाउंड की कुल सीमा से कम हैं","प्लाकार्ड केवल कुछ निश्चित मात्राओं या क्लास के लिए ज़रूरी हैं — ज़हरीली गैस को किसी भी मात्रा में प्लाकार्ड चाहिए, जबकि काटक पदार्थ को केवल 1,001 पाउंड या उससे अधिक पर"],"explanation":"ज़हरीली गैस जैसे टेबल 1 के पदार्थों को किसी भी मात्रा में प्लेकार्ड चाहिए, जबकि संक्षारक जैसे टेबल 2 के पदार्थों को केवल 1,001 पाउंड या अधिक पर प्लेकार्ड चाहिए।"},"17":{"q":"मैं चेतावनी-पट्टियों (प्लेकार्ड) वाला संक्षारक (कॉरोसिव) माल उठा रहा हूँ। माल भेजने वाला (शिपर) मुझे शिपिंग कागज़ात देता है और कहता है कि सब कुछ सही ढंग से वर्गीकृत, पैक और लेबल किया गया है। इस माल को ढोने से पहले, मुझे क्या बताता है कि शिपर ने औपचारिक रूप से प्रमाणित किया है कि शिपमेंट सही ढंग से वर्णित, पैक, चिह्नित और लेबल किया गया है?","options":["शिपिंग कागज़ पर ही मौजूद शिपर द्वारा हस्ताक्षरित प्रमाणन कथन","लोडिंग डॉक पर शिपर द्वारा मुझे दी गई मौखिक आश्वासन","वाहन के चारों ओर पहले से लगे सही खतरा-वर्ग के प्लेकार्ड का होना","सील और लेबल की मेरी अपनी जाँच जो पुष्टि करती है कि कहीं से रिसाव नहीं है"],"explanation":"शिपर शिपिंग पेपर पर प्रमाणन कथन पर हस्ताक्षर करके प्रमाणित करता है कि खतरनाक माल सही ढंग से नामित, पैक, चिह्नित और लेबल किया गया है।"},"18":{"q":"यदि आपको हैज़मैट (खतरनाक सामग्री) का रिसाव मिले, तो आपको चाहिए:","options":["इसे पहचानने के लिए छूना","इसे न छूना और लोगों को दूर रखना","दुकान तक तेज़ी से गाड़ी चलाना","प्लेकार्ड छिपा देना"],"explanation":"रिसाव को कभी न छुएं; लोगों को दूर रखें, प्रज्वलन (आग लगने) के स्रोतों से बचें, और मदद लें।"},"19":{"q":"खतरनाक पट्टिकाओं (placards) वाला मेरा संक्षारक (corrosive) टैंकर एक ग्रामीण राजमार्ग पर पलट जाता है और क्लास 8 का उत्पाद किनारे पर रिस रहा है। लोगों को पीछे हटाने, धूम्रपान रोकने और आपातकालीन प्रतिक्रिया गाइडबुक (ERG) लेने के बाद, मेरी कंपनी को इस गंभीर घटना की सूचना फोन पर देनी है। कौन-सा संपर्क विशेष रूप से किसी गंभीर खतरनाक सामग्री घटना की रिपोर्ट प्राप्त करने के लिए मौजूद है?","options":["CHEMTREC, जिसे मैं पहले फोन करता हूं क्योंकि यही एकमात्र एजेंसी है जो आधिकारिक घटना रिपोर्ट लेने के लिए अधिकृत है","नेशनल रेस्पॉन्स सेंटर (National Response Center), वह संघीय हॉटलाइन जो गंभीर खतरनाक सामग्री घटनाओं की रिपोर्ट प्राप्त करने के लिए मौजूद है","मेरे कागजात पर सूचीबद्ध शिपर, क्योंकि जिस कंपनी ने माल पैक किया है उसे रिपोर्ट दर्ज करनी होगी","वाहन निर्माता की हॉटलाइन, ताकि पलटना और टैंक की विफलता औपचारिक रूप से प्रलेखित हो सके"],"explanation":"गंभीर खतरनाक सामग्री घटनाओं की सूचना नेशनल रिस्पॉन्स सेंटर, संघीय हॉटलाइन 1-800-424-8802 को दी जानी चाहिए।"},"20":{"q":"रविवार की रात के 2:30 बज रहे हैं और एक विश्राम स्थल (rest stop) पर मेरे प्लेकार्ड लगे ड्रमों में से एक से संक्षारक (corrosive) पदार्थ रिसना शुरू हो गया है। मैं पहले ही आसपास के लोगों को सावधान कर चुका हूँ, लोगों को दूर रखा है और धूम्रपान रोका है। अब मैं रसायन से निपटने के आपातकालीन मार्गदर्शन के लिए CHEMTREC (1-800-424-9300) पर कॉल करना चाहता हूँ, लेकिन मुझे चिंता है कि सप्ताहांत पर इस समय कोई जवाब नहीं देगा। कौन-सा कथन सही है?","options":["CHEMTREC केवल सामान्य कार्यालय समय में ही कॉल का जवाब देता है, इसलिए मार्गदर्शन पाने के लिए मुझे सोमवार सुबह तक इंतजार करना होगा।","CHEMTREC केवल सप्ताह के कार्यदिवसों में ही काम करता है, इसलिए चूँकि आज रविवार है, मुझे इसके बजाय अपने वाहक (carrier) के कार्यालय में कॉल करना चाहिए।","CHEMTREC दिन के 24 घंटे, हर दिन उपलब्ध रहता है, इसलिए मैं अभी कॉल करके किसी आपातकालीन विशेषज्ञ से संपर्क कर सकता हूँ।","CHEMTREC से केवल रात के समय ही संपर्क किया जा सकता है, इसलिए रात 2:30 बजे कॉल करना ही एकमात्र काम करने वाला समय है।"],"explanation":"CHEMTREC (1-800-424-9300) आपातकालीन प्रतिक्रिया जानकारी प्रदान करने के लिए हर दिन, 24 घंटे उपलब्ध रहता है।"},"21":{"q":"मैं प्लेकार्ड लगे संक्षारक (विस्फोटक नहीं) माल को ले जा रहा हूँ और मुझे एक फोन कॉल करने तथा अपने कागजात जाँचने के लिए किनारे रुकना है। पास में कोई विश्राम स्थल नहीं है, इसलिए मैं दो-लेन वाले राजमार्ग के किनारे (शोल्डर) पर रुकने की सोच रहा हूँ। खतरनाक माल की पार्किंग नियमों का पालन करने के लिए मुझे निम्नलिखित में से क्या करना चाहिए?","options":["वाहन को चलती लेन के किनारे के यथासंभव पास पार्क करूँ ताकि शोल्डर पर बाकी यातायात के लिए सबसे अधिक जगह बचे","सड़क के 300 फीट के भीतर पार्क करूँ लेकिन माल को केवल कुछ मिनटों के लिए ही बिना निगरानी छोड़ूँ","वाहन को शोल्डर की पक्की सतह पर चढ़ाकर लेन की सफेद किनारा-रेखा के ठीक बगल में रोक दूँ","रुकने और पार्क करने से पहले वाहन को सड़क के चलने वाले हिस्से से कम से कम 5 फीट दूर रखूँ"],"explanation":"प्लेकार्ड वाले वाहन को सड़क के यातायात वाले हिस्से के 5 फुट के भीतर कभी पार्क नहीं करना चाहिए।"},"22":{"q":"मैं डिवीज़न 1.2 के विस्फोटक ले जा रहा हूँ और अनिवार्य टायर जाँच के लिए किनारे रुकता हूँ। आगे मैं किनारे पर एक वाहन को जलते हुए देखता हूँ, और पास में लोगों की भीड़ जमा होकर देख रही है। इस भार के साथ कानूनी और सुरक्षित रूप से पार्क करने के लिए, मुझे अपने ट्रक और वहाँ जमा लोगों की उस भीड़ के बीच कम से कम कितनी दूरी रखनी चाहिए?","options":["लोगों की भीड़ से कम से कम 300 फ़ुट","लोगों की भीड़ से कम से कम 25 फ़ुट","लोगों की भीड़ से कम से कम 50 फ़ुट","लोगों की भीड़ से कम से कम 5 फ़ुट"],"explanation":"विस्फोटक माल (डिवीज़न 1.1, 1.2, 1.3) को लोगों के एकत्र होने वाली जगह से 300 फ़ीट के भीतर कभी पार्क नहीं करना चाहिए।"},"23":{"q":"मैं डिवीजन 1.2 विस्फोटकों का प्लेकार्ड लगा हुआ (placard) भार ले जा रहा हूँ और एक विश्राम क्षेत्र में कुछ मिनटों के लिए अपने ट्रक से दूर जाना है। नियम कहते हैं कि इस भार को कभी भी बिना निगरानी के नहीं छोड़ा जा सकता। मेरे वाहन को कानूनी रूप से 'निगरानी में' माने जाने के लिए, उसकी निगरानी करने वाले व्यक्ति के बारे में निम्नलिखित में से क्या सत्य होना चाहिए?","options":["वह स्लीपर बर्थ में आराम कर सकता है, बशर्ते वह ट्रक को सुन सके और कुछ होने पर प्रतिक्रिया दे सके","वह जागा हुआ है, वाहन से 100 फ़ीट के भीतर है, उसे साफ़ देख सकता है, और आवश्यकता पड़ने पर उसे तेज़ी से हटा सकता है","वह कम से कम हर दो घंटे में एक बार वाहन के पास से गुज़रकर उसका निरीक्षण करता है — वही अंतराल जो टायर जाँच के लिए होता है","वह विश्राम क्षेत्र में कहीं भी रहता है और आपात स्थिति में मोबाइल फ़ोन पर उपलब्ध रहता है"],"explanation":"विस्फोटक माल तभी निगरानी में माना जाता है जब व्यक्ति जागता हो, 100 फ़ीट के भीतर हो, उसे साफ़ देख सके और ज़रूरत पड़ने पर जल्दी हटा सके।"},"24":{"q":"मैं एक CDL चालक हूं जो प्लेकार्ड (placard) लगे संक्षारक (corrosive) माल को ढो रहा हूं। डॉक पर एक क्लर्क मुझे एक क्लिपबोर्ड थमाता है और रवाना होने से पहले बताता है कि \"मेरे काम\" में क्या-क्या शामिल है। चालक के रूप में अपनी वास्तविक कानूनी सीमा के भीतर रहने के लिए, मुझे इस सूची में से वह एकमात्र काम पहचानना है जो चालक की जिम्मेदारी नहीं है, बल्कि श्रृंखला में किसी और की है। इनमें से वह कौन सा काम है?","options":["किसी ऐसे पैकेज को स्वीकार करने से मना करना जिसमें मुझे रिसाव मिले या जो गलत तरीके से चिह्नित हो","गाड़ी चलाने से पहले वाहन की चारों ओर आवश्यक प्लेकार्ड (placard) लगाना","ढोए जा रहे खतरनाक माल का उत्पादन करना और उसका रासायनिक सूत्रीकरण करना","गाड़ी चलाते समय शिपिंग दस्तावेज़ों को अपनी पहुंच के भीतर रखना"],"explanation":"चालक के कर्तव्य हैं माल की जांच करना, खराब शिपमेंट मना करना, प्लेकार्ड लगाना, शिपिंग कागज़ात पास रखना और सुरक्षित गाड़ी चलाना, न कि सामग्री बनाना।"},"25":{"q":"बाहर हिमांक से नीचे तापमान है और मैं एक लंबी यात्रा के लिए ट्रेलर लोड कर रहा हूँ। मेरे ट्रक में एक चालू कार्गो-स्थान हीटर है, और मैं इसे चलाकर माल को ठंड से बचाना चाहता हूँ। डॉक पर प्रतीक्षा कर रहे चार शिपमेंट में से, किसके लिए मुझे कार्गो हीटर बंद रखना चाहिए?","options":["डिब्बाबंद सूप और बोतलबंद पानी का एक पैलेट जो ठंड में जम कर फट सकता है","बक्सों में रखा घरेलू फर्नीचर और पैकिंग सामग्री जो ठंडे मौसम में नमी सोखती है","प्रशीतित ताज़ी सब्ज़ियाँ-फल जिन्हें प्राप्तकर्ता परिवहन के दौरान जमने से बचाना चाहता है","विस्फोटकों के बक्सों के साथ लोड किए गए क्लास 3 ज्वलनशील तरल के ड्रम"],"explanation":"विस्फोटक या ज्वलनशील तरल ले जाते समय कार्गो हीटर बंद रहने चाहिए, क्योंकि लौ या गर्मी वाष्प जला सकती है या विस्फोटकों को फट सकती है।"},"26":{"q":"मुझे प्लेकार्ड लगे संक्षारक (corrosive) माल की डिलीवरी किए तीन सप्ताह हो चुके हैं और वह यात्रा कब की पूरी हो गई। मेरा डिस्पैचर बताता है कि कंपनी अब भी उस खेप के हैज़मैट शिपिंग पेपर्स को एक फ़ाइल में संभाल कर रखे हुए है। यात्रा समाप्त होने के बाद वाहक (carrier) इन पूर्ण किए गए दस्तावेज़ों को फ़ाइल में रखता है, इसका सबसे अच्छा कारण निम्न में से कौन-सा है?","options":["संघीय और राज्य नियामक निरीक्षण के लिए ये रिकॉर्ड मांग सकते हैं, इसलिए वाहक को इन्हें निर्धारित अवधि तक संभालकर रखना अनिवार्य है","जिस चालक ने माल ढोया, उसे ये मूल दस्तावेज़ अपने पूरे करियर तक व्यक्तिगत रूप से अपनी फ़ाइल में रखने होते हैं","डिलीवरी की पुष्टि होने और माल उतर जाने के बाद इन दस्तावेज़ों का कोई उपयोग नहीं रहता और इन्हें नष्ट किया जा सकता है","दस्तावेज़ केवल तभी तक रखने होते हैं जब तक माल रास्ते में है, और उन्हें चालक के दरवाज़े की थैली तक पहुँचना ही पर्याप्त है"],"explanation":"वाहक को पूर्ण शिपिंग कागज़ात आवश्यक अवधि तक रखने चाहिए, क्योंकि संघीय और राज्य नियामक उन्हें जांच के लिए मांग सकते हैं।"},"27":{"q":"मैं एक माल के लिए शिपिंग कागजात तैयार कर रहा हूँ और अपने उत्पाद की प्रविष्टि का विवरण निकालने के लिए नियमों में दी गई खतरनाक सामग्री तालिका (Hazardous Materials Table) खोलता हूँ। अपनी सामग्री की पंक्ति को पढ़ते समय, मुझे जो भी स्तंभ दिखता है वह सीधे इसी तालिका से आता है, सिवाय एक जानकारी के, जो मुझे तालिका के बजाय किसी और स्रोत से लेनी पड़ेगी। निम्न में से कौन-सी जानकारी मुझे खतरनाक सामग्री तालिका पढ़कर नहीं मिलेगी?","options":["उचित शिपिंग नाम (proper shipping name) जिसका उपयोग मुझे अपने शिपिंग कागजात में सामग्री का वर्णन करने के लिए करना होगा","चालक के रूप में मेरा घर का पता, जो तालिका में कहीं भी दर्ज नहीं होता","जिस सामग्री को मैं ढो रहा हूँ उसे सौंपी गई खतरा श्रेणी या प्रभाग (hazard class या division)","पहचान संख्या (UN/NA) जो प्रविष्टि के साथ सूचीबद्ध होनी चाहिए"],"explanation":"खतरनाक सामग्री तालिका सामग्री का ही वर्णन करती है — शिपिंग नाम, खतरा वर्ग, पहचान संख्या, पैकिंग समूह और लेबल — न कि चालक की व्यक्तिगत जानकारी।"},"28":{"q":"मैं एक शिपर के डॉक पर क्लास 3 ज्वलनशील तरल का भार उठा रहा हूँ। शिपिंग कागज़ात सामग्री की सही पहचान करते हैं और दिखाते हैं कि इसके लिए प्लेकार्ड (चेतावनी पट्टिकाएँ) आवश्यक हैं, लेकिन शिपर बिना कोई प्लेकार्ड लगाए मुझे ट्रक सौंप देता है और कहता है कि वे \"स्टॉक में नहीं हैं\"। सड़क पर निकलने से पहले मुझे क्या करना चाहिए?","options":["अपने पहले निर्धारित पड़ाव तक गाड़ी चलाना और प्राप्तकर्ता से छूटे हुए प्लेकार्ड देने को कहना, क्योंकि भार पहले से लदा है और कागज़ात सही हैं","बिना प्लेकार्ड के आगे बढ़ना लेकिन शिपिंग कागज़ात को सबसे ऊपर और अपनी पहुँच में रखना, क्योंकि सही कागज़ात कानूनी रूप से छूटे प्लेकार्ड की जगह ले लेते हैं","सही प्लेकार्ड प्राप्त करना और सड़क पर वाहन निकालने से पहले उन्हें वाहन के चारों ओर (चारों तरफ) लगाना","पूरे शिपमेंट को सिरे से अस्वीकार कर देना और उसे डॉक पर छोड़ देना, क्योंकि एक प्लेकार्ड की कमी भार को स्वीकार करना अवैध बना देती है"],"explanation":"यदि शिपर प्लेकार्ड नहीं देता, तो चालक को सही प्लेकार्ड लेकर वाहन को सड़क पर ले जाने से पहले चारों तरफ लगाने होंगे।"},"29":{"q":"मैं अपने ट्रेलर में डिब्बों में पैक किया गया संक्षारक (corrosive) माल लोड कर रहा हूँ, और शिपर ने हर एक पैकेज पर एक चिह्न लगाया है। डॉक पर एक दूसरा ड्राइवर मुझे बताता है कि ये पैकेज के चिह्न बिल्कुल वैसे ही हैं जैसे वे प्लैकार्ड (placards) जिन्हें मैं अपने वाहन के चारों ओर लगाऊँगा। माल का सही निरीक्षण करने के लिए, मुझे किस कथन पर भरोसा करना चाहिए?","options":["पैकेज के चिह्न पूर्ण-आकार के प्लैकार्ड हैं, और संघीय नियम मुझे चारों ओर प्लैकार्ड लगाने की आवश्यकता पूरी करने के लिए इन्हें वाहन के किनारों पर ले जाने की अनुमति देते हैं","पैकेज के चिह्न शिपर के वैकल्पिक नोट हैं, इसलिए वाहन के प्लैकार्ड ही एकमात्र हीरे के आकार के चिह्न हैं जिनका कानूनी महत्व है","अमेरिका में खतरे की सूचना केवल प्लैकार्ड से दी जाती है, इसलिए डिब्बों पर कोई भी हीरे महज सजावटी हैं और उन्हें नज़रअंदाज़ किया जा सकता है","हर पैकेज पर बने हीरे खतरे के लेबल हैं जिन्हें शिपर लगाता है, और ये वाहन पर लगने वाले बड़े प्लैकार्ड से अलग होते हैं"],"explanation":"लेबल छोटे हीरे होते हैं जो शिपर अलग-अलग पैकेजों पर लगाता है, जबकि प्लेकार्ड बड़े हीरे होते हैं जो वाहन के चारों तरफ लगाए जाते हैं।"},"30":{"q":"मैं एक लदान तैयार कर रहा हूँ जिसमें निर्जल अमोनिया का एक प्रशीतित टैंक और संपीड़ित ऑक्सीजन का एक सिलेंडर शामिल है। शिपिंग पेपरों पर दोनों प्रविष्टियाँ खतरा वर्ग 2 के रूप में चिह्नित हैं। जो मैं वास्तव में लाद रहा हूँ उससे कागज़ात का मिलान करते समय, मुझे प्रत्येक वर्ग 2 सामग्री किस भौतिक अवस्था में मिलने की अपेक्षा करनी चाहिए?","options":["एक गैस (इस वर्ग में ज्वलनशील, गैर-ज्वलनशील और विषैली गैसें शामिल हैं)","एक ज्वलनशील तरल जो कम तापमान पर वाष्प छोड़ता है","एक ठोस जो केवल गीला होने पर ही खतरनाक बनता है","एक संक्षारक जो तरल या ठोस दोनों रूप में हो सकता है"],"explanation":"खतरा वर्ग 2 गैसों का वर्ग है, जिसमें ज्वलनशील, गैर-ज्वलनशील और ज़हरीली गैसें शामिल हैं।"},"31":{"q":"मैं एक नया खतरनाक माल (हैज़मैट) चालक हूँ और एक संक्षारक (कोरोसिव) सफाई उत्पाद लाद रहा हूँ। ड्रमों के लेबल पर निर्माता का ब्रांड नाम बड़े अक्षरों में दिखता है, शिपर ने मुझे कागज़ात दिए हैं, और डिस्पैचर बार-बार इस माल को उसके कैटलॉग उत्पाद नाम से बुलाता है। जब मैं जाँचता हूँ कि मेरे शिपिंग कागज़ात पर उचित शिपिंग नाम सही है, तो वह किस नाम से मेल खाना चाहिए?","options":["ड्रम के लेबल पर बड़े अक्षरों में छपा ब्रांड नाम, क्योंकि वही असली उत्पाद की पहचान कराता है","उस सामग्री के लिए खतरनाक सामग्री तालिका (हैज़र्डस मटेरियल्स टेबल) में सूचीबद्ध उचित शिपिंग नाम, न कि कोई व्यापारिक या ब्रांड नाम","डिस्पैचर द्वारा उपयोग किया जाने वाला कैटलॉग उत्पाद नाम, क्योंकि कंपनी इसी से माल को ट्रैक करती है","उत्पाद का कोई भी आम नाम, बशर्ते कागज़ात पर खतरा वर्ग और पहचान संख्या सही हो"],"explanation":"शिपिंग कागज़ात में सही शिपिंग नाम ठीक वैसा ही लिखना चाहिए जैसा खतरनाक सामग्री तालिका में दिया है, न कि कोई व्यापारिक या ब्रांड नाम।"},"32":{"q":"ज्वलनशील तरल पदार्थ का भार ढोने से पहले मैं अपने प्लेकार्ड लगे टैंकर की यात्रा-पूर्व जांच कर रहा हूं। मैं कैबिन वाले हिस्से पर चढ़कर दरवाजे के पास लगे अग्निशामक यंत्र की जांच करता हूं। कौन सी स्थिति का मतलब है कि अग्निशामक यंत्र स्वीकार्य है और मैं कानूनी रूप से चलने के लिए तैयार हूं?","options":["अग्निशामक यंत्र लगा हुआ और सील किया हुआ है, इसलिए चलने से पहले मुझे गेज या उसकी रेटिंग जांचने की जरूरत नहीं है","अग्निशामक यंत्र उसी आकार का है जिसका मैं आदी हूं, भले ही दबाव गेज की सुई लाल क्षेत्र में हो","अग्निशामक यंत्र पूरी तरह चार्ज है और जिस खतरे को मैं ढो रहा हूं उसके लिए पर्याप्त ऊंची रेटिंग रखता है","अग्निशामक यंत्र कैबिन में मौजूद है, क्योंकि कोई भी काम करने वाला अग्निशामक यंत्र रखना आवश्यकता को पूरा करता है"],"explanation":"प्लेकार्ड लगे वाहन में ऐसा अग्निशामक होना चाहिए जो पूरी तरह चार्ज हो और ढोए जा रहे खतरे के लिए पर्याप्त रेटिंग वाला हो।"},"33":{"q":"मैं प्लॅकार्ड (खतरनाक माल के चिह्न लगे) ज्वलनशील तरल का भार ढो रहा हूँ और अपना टैंक भरने के लिए एक ईंधन स्टेशन पर रुकता हूँ। मेरा सह-चालक जल्दी खत्म करने के लिए मदद करने की पेशकश करता है। ट्रक में सही और सुरक्षित ढंग से ईंधन भरने के लिए, निम्नलिखित में से क्या अवश्य होना चाहिए?","options":["मैं नॉज़ल को खुली स्थिति में लॉक करके विंडशील्ड साफ़ करने के लिए हट सकता हूँ, बशर्ते लाइटों को चलाने के लिए इंजन चालू रहे","मुझे इंजन को निष्क्रिय (आइडल) चलता छोड़ देना चाहिए ताकि ईंधन पंप जल्दी दबाव बनाए, और टैंक भरते समय लगभग 25 फ़ुट पीछे खड़ा रहना चाहिए","मैं ईंधन भरना शुरू करके भुगतान करने अंदर जा सकता हूँ, क्योंकि पंप का ऑटो-शटऑफ़ टैंक भरने पर प्रवाह रोक देगा","मुझे इंजन बंद करना ही होगा, और हम दोनों में से एक को पूरे समय नॉज़ल पर रहकर ईंधन के प्रवाह को नियंत्रित करना चाहिए"],"explanation":"प्लेकार्ड लगे वाहन में ईंधन भरते समय इंजन बंद होना चाहिए और कोई व्यक्ति पूरे समय नोज़ल पर रहकर ईंधन प्रवाह को नियंत्रित करता रहे।"},"34":{"q":"मैं डिवीज़न 1.1 विस्फोटकों का प्लेकार्ड लगा हुआ माल ले जा रहा हूँ और मेरा जीपीएस सबसे तेज़ रास्ता सुझा रहा है, जो दोपहर के समय शहर के व्यापारिक केंद्र और एक बड़ी नदी सुरंग के बीच से सीधे गुज़रता है। अनिवार्य खतरनाक माल मार्ग नियमों के अनुसार मुझे क्या करना चाहिए?","options":["ऐसा मार्ग बनाना जो आवश्यक स्थानों पर आबादी वाले क्षेत्रों और सुरंगों से बचे, भले ही इससे दूरी बढ़ जाए","जीपीएस वाला मार्ग लेना, क्योंकि सुरंग मुझे भीड़भाड़ वाली सड़कों से दूर रखती है और समय बचाती है","शहर के केंद्र वाला मार्ग उपयोग करना, लेकिन केवल तभी जब ठहराव के दौरान मैं सड़क के चलने वाले हिस्से से कम से कम 5 फीट दूर खड़ा रहूँ","सबसे तेज़ मार्ग पर चलना, जब तक मैं गियर बदले बिना रेलवे पटरियाँ पार करता हूँ"],"explanation":"प्लेकार्ड लगे विस्फोटक ढोने वाले चालक को निर्धारित खतरनाक सामग्री मार्ग का पालन करना चाहिए और सुरंगों व आबादी वाले क्षेत्रों से बचना चाहिए, भले ही दूरी बढ़े।"},"35":{"q":"मैं प्लेकार्ड वाले हैज़मैट सफर के लिए अपना ट्रेलर लोड कर रहा हूँ, और मेरे शिपिंग पेपर्स में दो ऐसे पदार्थ दर्ज हैं जिनके बारे में अलगाव (सेग्रिगेशन) तालिका दर्शाती है कि संपर्क में आने पर वे खतरनाक रूप से प्रतिक्रिया कर सकते हैं। डॉक का दल जल्दी में है और चाहता है कि मैं तुरंत निकल जाऊँ। कौन सा कदम मुझे कानूनी और सुरक्षित रखता है?","options":["दोनों असंगत पदार्थों को एक ही पैलेट पर कस कर बाँध दूँ ताकि वे सफर के दौरान खिसकें नहीं","दोनों पदार्थों को अलगाव नियमों के अनुसार अलग-अलग लोड रखूँ ताकि प्रतिक्रिया करने वाले पदार्थ दूर रहें","दोनों पदार्थों को एक ही सीलबंद डिब्बे में मिला दूँ ताकि एक रिसाव बाकी लोड में न फैले","चूँकि रास्ता छोटा और सीधा है, अलगाव जाँच को छोड़ दूँ और दोनों पदार्थ सामान्य रूप से लोड कर लूँ"],"explanation":"पृथक्करण तालिका में सूचीबद्ध असंगत सामग्रियों को अलग लादना और अलग रखना चाहिए ताकि संपर्क में आने पर वे प्रतिक्रिया न कर सकें।"},"36":{"q":"मैं परिवहन के लिए बैटरी एसिड के ड्रम लोड कर रहा हूँ। शिपिंग पेपर में लोड को एक खतरा श्रेणी संख्या के साथ सूचीबद्ध किया गया है, और प्लेकार्ड लगाने से पहले मैं पुष्टि करना चाहता हूँ कि मैंने इस संक्षारक सामग्री के लिए सही खतरा श्रेणी का मिलान किया है। एसिड जैसे संक्षारक के लिए प्लेकार्ड पर कौन सी खतरा श्रेणी संख्या होनी चाहिए?","options":["श्रेणी 3, क्योंकि ड्रम में ज्वलनशील तरल पदार्थ और एसिड एक साथ समूहीकृत होते हैं","श्रेणी 5, क्योंकि एसिड तीव्रता से प्रतिक्रिया करते हैं और ऑक्सीकारक की तरह व्यवहार करते हैं","श्रेणी 8, क्योंकि एसिड जैसे संक्षारक उस खतरा श्रेणी में आते हैं","श्रेणी 1, क्योंकि दबावयुक्त एसिड ड्रम को विस्फोटक माना जाता है"],"explanation":"अम्ल जैसे संक्षारक पदार्थ खतरा वर्ग 8 में आते हैं।"},"37":{"q":"एक शिपर के डॉक पर मुझे एक माल के लिए शिपिंग कागजात दिए जाते हैं, और प्रविष्टि में सही शिपिंग नाम और एक UN पहचान संख्या के बगल में खतरा वर्ग 7 दर्ज है। अपने ट्रेलर पर प्लेकार्ड लगाकर निकलने से पहले, यह वर्ग 7 पदनाम मुझे बताता है कि मैं वास्तव में किस प्रकार की सामग्री ले जा रहा हूँ?","options":["ज्वलनशील तरल पदार्थ, जैसे ईंधन और विलायक के माल में पाए जाते हैं","सिलेंडरों में दबाव के तहत संपीड़ित और द्रवीकृत गैसें","मजबूत अम्ल और कास्टिक तरल जैसे संक्षारक पदार्थ","रेडियोधर्मी सामग्री जो परिवहन के दौरान आयनकारी विकिरण उत्सर्जित करती है"],"explanation":"खतरा वर्ग 7 रेडियोधर्मी सामग्री है, जो परिवहन के दौरान आयनकारी विकिरण उत्सर्जित करती है।"},"38":{"q":"लोडिंग डॉक पर, एक शिपर मुझे ऐसे कागजात देता है जिनमें सामग्री को 'खतरा श्रेणी 6' के रूप में सूचीबद्ध किया गया है। प्लेकार्ड लगाकर रवाना होने से पहले, मैं यह सुनिश्चित करना चाहता हूं कि मैं समझूं कि मैं किस प्रकार का खतरा ढो रहा हूं। श्रेणी 6 का पदनाम इस माल के बारे में मुझे क्या बताता है?","options":["यह एक जहरीली (विषैली) सामग्री है, इसलिए मुझे संपर्क और सांस के जरिए होने वाले खतरों से बचाव करना चाहिए","यह एक ऑक्सीकारक है जो आग को तेज कर सकता है, इसलिए मुझे इसे ज्वलनशील पदार्थों से दूर रखना चाहिए","यह एक संक्षारक सामग्री है जो त्वचा और धातु को जला सकती है, इसलिए मुझे रिसाव की जांच करनी चाहिए","यह एक गैर-ज्वलनशील संपीड़ित गैस है, इसलिए मुझे दबाव निकलने से बचाव करना चाहिए"],"explanation":"खतरा वर्ग 6 में विषैली (टॉक्सिक) सामग्री आती है, इसलिए संपर्क और साँस के ज़रिए होने वाले खतरों से बचाव करें।"},"39":{"q":"मैं एक खेप तैयार कर रहा हूँ और मेरे कागज़ात पर उचित शिपिंग नाम के बाद खतरा वर्ग संख्या \"5.1\" तथा UN प्रारूप में एक पहचान संख्या लिखी है। शिपर मुझे वाहन के चारों ओर लगाने के लिए एक प्लेकार्ड (placard) देता है। कौन-सा प्लेकार्ड खतरा वर्ग 5 की सामग्री से सही ढंग से मेल खाता है?","options":["एक CORROSIVE (संक्षारक) प्लेकार्ड, क्योंकि वर्ग 5 में अम्ल और धातु को गला देने वाला बैटरी द्रव शामिल है","एक OXIDIZER (ऑक्सीकारक) प्लेकार्ड, क्योंकि वर्ग 5 में ऑक्सीकारक और कार्बनिक परॉक्साइड शामिल हैं","एक EXPLOSIVES (विस्फोटक) प्लेकार्ड, क्योंकि वर्ग 5 में विस्फोटक पदार्थ और डेटोनेटर शामिल हैं","एक RADIOACTIVE (रेडियोधर्मी) प्लेकार्ड, क्योंकि वर्ग 5 में विकिरण उत्सर्जित करने वाली सामग्री शामिल है"],"explanation":"खतरा वर्ग 5 में ऑक्सीकारक और कार्बनिक परॉक्साइड आते हैं, इसलिए वर्ग 5.1 के माल के लिए OXIDIZER (ऑक्सीकारक) प्लेकार्ड चाहिए।"},"40":{"q":"मैं एक ही ट्रेलर में कई गैर-थोक पैकेज लाद रहा हूँ जो दो अलग-अलग खतरा वर्गों में आते हैं, और मैं हर वर्ग के लिए अलग प्लेकार्ड के बजाय चारों तरफ एक ही 'DANGEROUS' (खतरनाक) प्लेकार्ड लगाना पसंद करूँगा। DPS खतरनाक माल नियमों के अनुसार, 'DANGEROUS' प्लेकार्ड का उपयोग वास्तव में कब अनुमत है?","options":["केवल तब जब लदान का हर पैकेज एक ही एकल खतरा वर्ग का हो","केवल तब जब खेप पूरी तरह से डिब्बाबंद या पैलेट पर रखे खाद्य-श्रेणी के उत्पादों से बनी हो","जब लदान में दो या अधिक खतरा वर्ग हों जिन्हें नियम एक ही प्लेकार्ड साझा करने की अनुमति देते हैं","लगभग किसी भी स्थिति में, वर्ग-विशिष्ट प्लेकार्ड के सुविधाजनक सर्व-उपयोगी विकल्प के रूप में"],"explanation":"जब माल में दो या अधिक खतरा वर्ग हों जिन्हें नियम एक साथ रखने की अनुमति देते हैं, तो एक ही DANGEROUS प्लेकार्ड अलग-अलग प्लेकार्डों की जगह ले सकता है।"},"41":{"q":"मैं एक प्लेकार्ड लगा टैंकर चला रहा हूँ, तभी एक राज्य पुलिसकर्मी मुझे रोकता है, प्लेकार्ड पर लगे चार अंकों के नंबर की ओर इशारा करता है और पूछता है कि यह उसे क्या बताता है। आपातकाल में इस नंबर का उपयोग कैसे होता है, उसके आधार पर यह चार अंकों का पहचान नंबर वास्तव में किसकी पहचान करता है?","options":["लदे टैंक का कुल सकल वजन ताकि बचावकर्मी रिसाव की मात्रा जान सकें","खतरे की श्रेणी का विभाजन, जैसे ज्वलनशील तरल के लिए 3, संख्यात्मक रूप में","वाहक द्वारा टर्मिनल तक मुझे सौंपा गया निर्धारित खतरनाक माल मार्ग","ले जाया जा रहा विशिष्ट खतरनाक पदार्थ, जिसे आपातकालीन प्रतिक्रिया गाइडबुक (ERG) में खोजा जाता है"],"explanation":"चार अंकों वाला UN/NA नंबर विशिष्ट खतरनाक सामग्री की पहचान करता है, जिसे आपातकालीन प्रतिक्रियाकर्ता आपातकालीन प्रतिक्रिया गाइडबुक (ERG) में देखते हैं।"},"42":{"q":"मैं अपने भार के शिपिंग पेपर्स की जांच कर रहा हूं और देखता हूं कि प्रत्येक खतरनाक सामग्री प्रविष्टि में पैकिंग समूह I, II या III दर्ज है। एक नया चालक मुझसे पूछता है कि वह रोमन अंक वास्तव में हमें क्या बता रहा है। अपने हैज़मैट प्रशिक्षण के आधार पर, पैकिंग समूह सामग्री के बारे में क्या दर्शाता है?","options":["सामग्री कितना बड़ा खतरा पैदा करती है, जिसमें समूह I सबसे खतरनाक होता है","खतरा वर्ग संख्या जो खतरे के प्रकार की पहचान करती है, जैसे ज्वलनशील या संक्षारक","वह न्यूनतम वजन जिस पर भार को चारों ओर प्लेकार्ड लगाना अनिवार्य होता है","वह क्रम जिसमें प्रविष्टियां शिपिंग पेपर पर सूचीबद्ध की जानी चाहिए"],"explanation":"पैकिंग ग्रुप सामग्री के खतरे की मात्रा बताता है, जिसमें ग्रुप I सबसे खतरनाक, ग्रुप II मध्यम और ग्रुप III सबसे कम खतरनाक होता है।"},"43":{"q":"मैं टेक्सास में प्लेकार्ड लगे संक्षारक (corrosive) माल की ढुलाई कर रहा हूँ, तभी एक वज़न स्टेशन पर राज्य पुलिस अधिकारी मुझसे पूछता है कि मेरी खेप के लिए 24 घंटे का आपातकालीन प्रतिक्रिया फ़ोन नंबर कहाँ दर्ज है, उसे दिखाऊँ। मुझे अधिकारी को कौन-सा स्थान दिखाना चाहिए?","options":["ट्रेलर के चारों ओर लगे प्लेकार्ड पर","शिपिंग पेपर (माल दस्तावेज़) पर, जिसे मैं केबिन में अपनी पहुँच के भीतर रखता हूँ","मेरे खतरनाक माल (H) एंडोर्समेंट कार्ड पर","केबिन में रखी आपातकालीन प्रतिक्रिया पुस्तिका (ERG) में"],"explanation":"24 घंटे का आपातकालीन प्रतिक्रिया फोन नंबर शिपिंग पेपर पर लिखा होता है, जिसे चालक की पहुंच के भीतर केबिन में रखना चाहिए।"},"44":{"q":"मैं एक माल के शिपिंग कागजात की जांच कर रहा हूं और एक प्रविष्टि खतरा वर्ग 4 के रूप में सूचीबद्ध है। प्लेकार्ड लगाने और निरीक्षण करने से पहले, मैं यह पुष्टि करना चाहता हूं कि मैं वास्तव में किस प्रकार का खतरा ढो रहा हूं। निम्नलिखित में से कौन सा खतरा वर्ग 4 की सामग्री का सही वर्णन करता है?","options":["ज्वलनशील गैसें जो दबाव वाले सिलेंडर से निकलने पर प्रज्वलित हो सकती हैं","ज्वलनशील तरल पदार्थ जैसे पेट्रोल जो प्रज्वलनशील वाष्प छोड़ते हैं","ज्वलनशील ठोस पदार्थ, जिनमें स्वतः दहनशील और गीला होने पर खतरनाक सामग्री शामिल हैं","संक्षारक सामग्री जो त्वचा को जला सकती है या धातु के कंटेनरों को नष्ट कर सकती है"],"explanation":"खतरा श्रेणी 4 में ज्वलनशील ठोस पदार्थ आते हैं, जिनमें स्वतः ज्वलनशील और गीला होने पर खतरनाक सामग्री शामिल है।"},"45":{"q":"मैं अपने ट्रेलर में \"गीला होने पर खतरनाक\" चिह्नित Class 4.3 सामग्री लोड कर रहा हूँ, और पूरे रास्ते बारिश का पूर्वानुमान है। दरवाजे बंद करने से पहले, इस विशिष्ट खतरे के लिए कौन सी सावधानी सबसे अधिक महत्वपूर्ण है?","options":["माल को बहुत अधिक ठंडा होने से बचाना, क्योंकि ठंडक ही इन ठोस पदार्थों को अस्थिर बनाती है","सुनिश्चित करना कि डिब्बे धूल से सील हों, क्योंकि हवा में मौजूद कण प्रतिक्रिया शुरू करते हैं","पुष्टि करना कि माल ताज़ा रंगा और सील किया गया है ताकि परिवहन के दौरान धुआँ बाहर न निकले","सामग्री को पूरी तरह सूखा और सीलबंद रखना, क्योंकि पानी के संपर्क से वह आग पकड़ सकती है"],"explanation":"गीला होने पर खतरनाक सामग्री पानी के साथ प्रतिक्रिया करती है और आग पकड़ सकती है, इसलिए उसे पूरी तरह सूखा और नमी से सील रखना चाहिए।"},"46":{"q":"मैं हैज़मैट यात्रा के लिए अपने ट्रेलर में कई संपीड़ित गैस सिलेंडर लोड कर रहा हूँ। दरवाजे बंद करके निकलने से पहले, कौन-सी लोडिंग पद्धति मुझे नियमों के अनुरूप रखती है और लोड को सुरक्षित बनाती है?","options":["प्रत्येक सिलेंडर को सीधा खड़ा रखें और इस तरह बांधें कि वह परिवहन के दौरान न पलटे, न लुढ़के और न खिसके","सिलेंडरों को लिटाकर ढीला-ढाला पैक करें ताकि ऊबड़-खाबड़ सड़कों पर उन्हें जमने की जगह मिले","रवाना होने से पहले प्रत्येक सिलेंडर का वाल्व थोड़ा खोल दें ताकि रास्ते में आंतरिक दबाव बराबर हो जाए","उन्हें केवल तभी बगल में रखें जब ट्रेलर का फर्श समतल हो, अन्यथा उन्हें सीधा खड़ा करें"],"explanation":"संपीड़ित गैस सिलेंडरों को सीधा खड़ा करके इस तरह बांधना चाहिए कि वे परिवहन के दौरान न पलटें, न लुढ़कें और न खिसकें।"},"47":{"q":"मैं अपने ट्रेलर में क्लास 6.1 (ज़हर/विषैला) माल लाद रहा हूँ, और फर्श पर अभी भी जगह बची है। दूसरी फेरी से बचने के लिए, मैं उसी टर्मिनल जाने वाले दूसरे माल से गाड़ी को भरना चाहता हूँ। कौन सा माल है जिसे मुझे ज़हर के साथ एक ही गाड़ी में नहीं रखना चाहिए?","options":["ऑटो पार्ट्स के सीलबंद गत्ते के डिब्बों की एक पैलेट","किराना दुकान के लिए बोरियों में सूखा कुत्ते का भोजन और डिब्बों में अनाज (सीरियल)","मैकेनिक के हाथ के औज़ारों और बाँधने के सामान का एक क्रेट","साफ, सूखी निर्माण रेत की कई बोरियाँ"],"explanation":"विषैले और जहरीले (श्रेणी 6.1) पदार्थों को संदूषण के जोखिम के कारण कभी भी मनुष्यों या जानवरों के भोजन के साथ नहीं लादना चाहिए।"},"48":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मुझे अपने प्लेकार्ड लगे लदान पर श्रेणी 8 अंकित एक ड्रम मिलता है, और उसके पास फर्श पर थोड़ी मात्रा में तरल रिस गया है। इस रिसाव को कैसे संभालना है यह तय करते समय, उसके पास जाने से पहले मुझे निम्नलिखित में से किस सबसे महत्वपूर्ण खतरे का ध्यान रखना चाहिए?","options":["यह पदार्थ ट्रेलर के अंदर का तापमान तेजी से घटा देगा, इसलिए मुझे पहले हवादार करना चाहिए","यह पदार्थ हवा के संपर्क में अत्यधिक विस्फोटक है, इसलिए मुझे 300 फुट के दायरे को खाली करा देना चाहिए","यह पदार्थ संपर्क में आने पर मेरी त्वचा और आँखों को रासायनिक रूप से जला सकता है, इसलिए मुझे इसे छूने से बचना चाहिए और स्वयं की रक्षा करनी चाहिए","तरल रूप में यह पदार्थ मूलतः निष्क्रिय है, इसलिए मैं इसे कपड़े से पोंछकर अपनी यात्रा जारी रख सकता हूँ"],"explanation":"श्रेणी 8 के संक्षारक पदार्थ संपर्क में आने पर त्वचा और आंखों को रासायनिक रूप से जला सकते हैं, इसलिए चालक को इन्हें छूने से बचना और स्वयं की रक्षा करनी चाहिए।"},"49":{"q":"मैं अपने ट्रेलर में क्लास  3 ज्वलनशील तरल पदार्थों की एक खेप लोड करने वाला हूँ। लोडिंग शुरू करने से पहले, मैं देखता हूँ कि कार्गो स्पेस में पिछली यात्रा का कुछ मलबा और खुले धातु के पुर्जे खड़कड़ा रहे हैं। खतरनाक माल के नियमों के अनुसार, लोडिंग शुरू करने से पहले कार्गो स्पेस को कौन सी शर्त पूरी करनी चाहिए?","options":["पूरी तरह नम होना चाहिए, क्योंकि नमी लोडिंग के दौरान आकस्मिक आग लगने की संभावना को कम करती है","पहले मेरे हाथ के औजारों से लोड होना चाहिए ताकि वे सामने की दीवार से बंधे रहें","सीलबंद और बिना वेंटिलेशन के होना चाहिए ताकि ज्वलनशील वाष्प कैबिन क्षेत्र में न जा सकें","माल अंदर जाने से पहले साफ़ और चिंगारी पैदा करने वाले किसी भी खतरे से मुक्त होना चाहिए"],"explanation":"ज्वलनशील तरल पदार्थ लादने से पहले कार्गो क्षेत्र साफ और चिंगारी पैदा करने वाले खतरों से मुक्त होना चाहिए, क्योंकि ढीली धातु वाष्प को प्रज्वलित कर सकती है।"},"50":{"q":"मैं अपने प्लेकार्ड लगे टैंकर को सफर से पहले तैयार कर रहा हूँ और ट्रेलर पर हीरे (डायमंड) के आकार के प्लेकार्ड लगा रहा हूँ। यह सुनिश्चित करने के अलावा कि हर एक उस दिशा से साफ और पढ़ने योग्य रहे जिस ओर वह मुड़ा है, DPS की आवश्यकताओं को पूरा करने के लिए मुझे हर प्लेकार्ड को वास्तव में किस तरह लगाना चाहिए?","options":["इसे एक ऐसे वर्ग के रूप में लगाएं जो इस तरह घुमाया गया हो कि एक कोना सीधा ऊपर की ओर हो, हीरे की तरह","इसे सपाट रखें ताकि एक पूरा किनारा नीचे की ओर समतल टिका रहे","इसे केवल चालक और यात्री वाली तरफ लगाएं, आगे या पीछे नहीं","लोडिंग डॉक तक पहुँचने तक इसे पारदर्शी फिल्म से ढक दें"],"explanation":"प्लेकार्ड हीरे के आकार के होते हैं जो एक कोने पर खड़े वर्ग के रूप में लगाए जाते हैं, जिसका एक कोना सीधे ऊपर की ओर हो, और साफ व पठनीय रखे जाते हैं।"},"51":{"q":"शिपर के डॉक पर अपने प्लेकार्ड लगे ट्रेलर को लोड करते समय, मैं देखता हूँ कि संक्षारक (corrosive) पदार्थ के एक ड्रम के किनारे से ताज़ा गीला धब्बा बह रहा है और पैकेज का लेबल आंशिक रूप से फटा हुआ है। शिपर ज़ोर देकर कहता है कि यह 'बस थोड़ा सा' है और मुझसे ड्रम लोड करने को कहता है ताकि यात्रा समय पर रहे। मुझे क्या करना चाहिए?","options":["इसे जैसा है वैसा ही लोड कर दें, क्योंकि पैकेज को शिपर ने तैयार और प्रमाणित किया है, और कोई भी रिपोर्टिंग डिलीवरी के बाद कैरियर का काम है","पैकेज को अस्वीकार करें और उसे न ले जाएं, क्योंकि चालक को किसी भी रिसते या क्षतिग्रस्त खतरनाक माल की खेप को मना करना ही होता है","इसे लोड करें पर बाकी माल के बीच में गहराई में दबा दें ताकि रिसाव सीमित रहे और ट्रेलर की दीवारों से दूर रहे","इसे लोड करें पर शिपिंग दस्तावेज़ों पर एक नोट लिख दें ताकि पहुँचने पर पाने वाले को रिसाव के बारे में चेतावनी मिल जाए"],"explanation":"चालक को शिपमेंट की जांच करनी चाहिए और किसी भी रिसाव वाले या क्षतिग्रस्त खतरनाक सामग्री पैकेज को ले जाने से मना करना चाहिए।"},"52":{"q":"मैंने अभी-अभी एक ज्वलनशील तरल पदार्थ की टैंकर खेप पहुंचाई है और गेज पर टैंक 'खाली' दिखा रहा है। टर्मिनल वापस जाने से पहले, मैं तय कर रहा हूं कि क्या मैं प्लेकार्ड हटा सकता हूं। टैंक के इस 'खाली' अवस्था में रहते हुए, इन्हें हटाने का मेरे पास किस स्थिति में सबसे कम आधार होता है?","options":["जब टैंक को भाप से साफ किया गया हो, शुद्ध किया गया हो और किसी भी उत्पाद से मुक्त प्रमाणित किया गया हो","जब शिपिंग पेपर और वाहक दोनों पुष्टि करें कि टैंक अब 'साफ और शुद्ध' मानक को पूरा करता है","जब टैंक में पिछली खेप से चिपका हुआ अवशेष या खतरनाक वाष्प अभी भी मौजूद हो","जब टैंक को टर्मिनल पर तीन बार धोया गया हो और खाली के रूप में फिर से तौला गया हो"],"explanation":"टैंक तभी 'खाली' माना जाता है जब उसमें पिछले माल से चिपके अवशेष या खतरनाक वाष्प न बचे हों, इसलिए पूरी तरह साफ होने तक प्लेकार्ड लगे रहने चाहिए।"},"53":{"q":"मैं एक ऐसा लोड उठा रहा हूं जिसे शिपर ने केवल सामान्य खतरनाक सामग्री नहीं, बल्कि खतरनाक अपशिष्ट (WASTE) के रूप में वर्गीकृत किया है, और मैं सुनिश्चित करना चाहता हूं कि मैं सुविधा से उस एकमात्र दस्तावेज़ के साथ निकलूं जिसकी नियम इस प्रकार के शिपमेंट के लिए विशेष रूप से मांग करते हैं। इस खतरनाक अपशिष्ट लोड के साथ कौन सा दस्तावेज़ अनिवार्य रूप से होना चाहिए?","options":["एक सामान्य वाणिज्यिक माल शिपमेंट के लिए तैयार किया गया मानक बिल ऑफ लैडिंग","केवल आपातकालीन प्रतिक्रिया गाइडबुक (ERG) जो घटना के संदर्भ के लिए केबिन में रखी जाती है","एक सुरक्षा डेटा शीट (SDS) जो रसायन के गुणों और संभालने के चरणों का वर्णन करती है","एक यूनिफॉर्म हैज़र्डस वेस्ट मेनिफेस्ट (Uniform Hazardous Waste Manifest) जो अपशिष्ट शिपमेंट के साथ चलता है"],"explanation":"खतरनाक कचरे के परिवहन के साथ एक यूनिफॉर्म हैज़र्डस वेस्ट मैनिफेस्ट होना चाहिए, जो कचरे को उत्पादन से लेकर परिवहन और अंतिम निपटान तक ट्रैक करता है।"},"54":{"q":"मैं डिवीजन 1.1 विस्फोटकों का प्लेकार्ड लगा भार ढो रहा हूँ और मुझे दिखता है कि ट्रेलर के अंदर भार बांधने वाला एक ब्रेस ढीला हो गया है। सुरक्षित रूप से आगे बढ़ने से पहले मुझे फास्टनर कसने होंगे। यह काम करने के लिए मुझे निम्नलिखित में से क्या उपयोग करना चाहिए?","options":["पीतल या कांसे से बने चिंगारी न पैदा करने वाले औज़ार, ताकि कोई भी ऐसी चिंगारी न उठे जो विस्फोटकों को आग लगा दे","सामान्य इस्पात (स्टील) के औज़ार, क्योंकि वे फास्टनर को सबसे मज़बूती से पकड़ते हैं और काम सबसे तेज़ी से पूरा करते हैं","जो भी भारी इस्पात की छड़ पास में हो, क्योंकि जितना अधिक लीवरेज, उतनी जल्दी मेरा काम पूरा होगा","लाल सुरक्षा निशान से रंगा कोई भी औज़ार, क्योंकि लाल निशान वाले औज़ार खतरनाक माल के काम के लिए स्वीकृत होते हैं"],"explanation":"क्लास 1 विस्फोटकों के पास काम पीतल या कांसे के नॉन-स्पार्किंग औज़ारों से करना चाहिए, क्योंकि धातु से धातु टकराने की एक चिंगारी विस्फोटकों को प्रज्वलित कर सकती है।"},"55":{"q":"मैंने लोडिंग डॉक पर अपने ट्रेलर के चारों ओर प्लेकार्ड लगाए और निकलने से पहले पुष्टि की कि हर एक पढ़ने योग्य है। लंबी यात्रा के तीन घंटे बाद, मैं ईंधन भरने के लिए रुकता हूँ और अपने सह-चालक से कहता हूँ कि प्लेकार्ड 'पहले ही संभाल लिए गए हैं'। प्लेकार्ड सही जगह पर हैं, इसकी पुष्टि करने के लिए मैं कब जिम्मेदार हूँ, इस बारे में कौन सा कथन सही है?","options":["डॉक पर प्लेकार्ड की पुष्टि करते ही मेरी जिम्मेदारी समाप्त हो जाती है, क्योंकि प्लेकार्ड लगाना यात्रा-पूर्व निरीक्षण में जांचा जाता है।","मुझे यह पुष्टि करनी चाहिए कि प्लेकार्ड सही जगह पर हैं, यात्रा से पहले भी और यात्रा के दौरान चलते समय भी।","मुझे प्लेकार्ड केवल तब दोबारा जांचने की आवश्यकता है जब मैं डिलीवरी स्थान पर पहुँचूँ ताकि प्राप्तकर्ता संतुष्ट हो।","प्लेकार्ड लगाना शिपर का कर्तव्य है, इसलिए रास्ते में इसकी जांच करना मेरी ड्राइविंग जिम्मेदारी का हिस्सा नहीं है।"],"explanation":"आपको सुनिश्चित करना चाहिए कि प्लेकार्ड यात्रा से पहले और यात्रा के दौरान दोनों समय अपनी जगह पर हों, क्योंकि चलते समय वे ढीले हो सकते, गिर सकते या ढक सकते हैं।"},"56":{"q":"मैं प्लेकार्ड लगे संक्षारक (corrosive) माल को ले जा रहा हूँ, तभी एक ड्रम सड़क के किनारे रिसने लगता है। जब मैं सीट से शिपिंग पेपर निकालता हूँ, तो मुझे दिखता है कि शिपर ने उनके साथ आपातकालीन प्रतिक्रिया जानकारी संलग्न की है। जब अग्निशमन दल और एक हज़मत टीम मौके पर पहुँचती है, तो शिपर की उस आपातकालीन जानकारी का प्रमुख उद्देश्य क्या है?","options":["यह माल का खुदरा मूल्य बताती है ताकि बचावकर्मी तय कर सकें कि पहले किस माल की रक्षा करनी है","यह मुझे बताती है कि गर्मी में लंबी यात्राओं के लिए कैरियर किस ईंधन ग्रेड और टायर दबाव को पसंद करता है","यह बचावकर्मियों को वे जानकारी देती है जो इस विशिष्ट सामग्री के रिसाव या आग को सुरक्षित रूप से संभालने के लिए आवश्यक है","यह प्रमाणित करती है कि मैंने अपनी TSA पृष्ठभूमि जाँच पूरी कर ली है और मेरे पास वैध H एंडोर्समेंट है"],"explanation":"आपातकालीन प्रतिक्रिया जानकारी शिपिंग कागज़ात के साथ रहती है ताकि प्रतिक्रियाकर्ताओं को उस सामग्री से रिसाव, फैलाव या आग को सुरक्षित रूप से संभालने के लिए ज़रूरी विशिष्ट डेटा मिल सके।"},"57":{"q":"मैं क्लास 7 रेडियोधर्मी सामग्री के कई पैकेज लोड कर रहा हूँ, और शिपर प्रत्येक पैकेज के लेबल पर छपे एक नंबर की ओर इशारा करता है और मुझसे कहता है कि मुझे इन आँकड़ों को जोड़ना होगा और कुल योग को मेरे वाहन के लिए निर्धारित सीमा के भीतर रखना होगा। मुझे जिस नंबर पर नज़र रखने को कहा जा रहा है, उसका उद्देश्य क्या है?","options":["यह एक रंग कोड है जो बताता है कि मिलान करने वाला प्लेकार्ड ट्रेलर के किस ओर लगाना है","यह एक गति रेटिंग है जो यह सीमित करती है कि रेडियोधर्मी भार होने पर मैं कितनी तेज़ गाड़ी चला सकता हूँ","यह एक मार्ग सूचकांक है जो बताता है कि मुझे कौन-से निर्दिष्ट राजमार्ग उपयोग करने की अनुमति है","यह एक ट्रांसपोर्ट इंडेक्स है जो मेरे वाहन पर अनुमत कुल विकिरण जोखिम (radiation exposure) को सीमित करता है"],"explanation":"प्रत्येक रेडियोधर्मी पैकेज पर एक ट्रांसपोर्ट इंडेक्स होता है, और चालक को वाहन पर विकिरण जोखिम को नियंत्रित करने के लिए इन इंडेक्सों को जोड़कर कुल को निर्धारित सीमा के नीचे रखना चाहिए।"},"58":{"q":"मैं प्लेकार्ड लगा हुआ संक्षारक (corrosive) पदार्थों का भार ले जा रहा हूँ, तभी एक पहिये के बेयरिंग में खराबी के कारण मुझे किनारे रुककर बदली के ट्रैक्टर का इंतज़ार करना पड़ता है। डिस्पैचर रेडियो पर बताता है कि पास में कंपनी का एक और ट्रक है और सुझाव देता है कि डिलीवरी देर न हो इसलिए मैं उत्पाद को उसमें पंप कर दूँ। कौन-सा जवाब सही हज़मत (HazMat) प्रथा के अनुरूप है?","options":["सड़क पर हस्तांतरण से इनकार करना; हज़मत को वाहनों के बीच केवल सच्ची आपात स्थिति में ही ले जाना चाहिए, इसलिए मुझे मरम्मत या उचित व्यवस्था का इंतज़ार करना चाहिए","हस्तांतरण कर देना, क्योंकि डिलीवरी को समय पर रखना वाहक (carrier) की पहली प्राथमिकता है","दोनों वाहनों पर दोबारा प्लेकार्ड लगाने के बाद ही हस्तांतरण करना, जिससे सड़क किनारे का हस्तांतरण पूरी तरह स्वीकार्य हो जाता है","हस्तांतरण करना क्योंकि भार पहले से ही रुका हुआ है और सड़क के चलने वाले हिस्से से बाहर सुरक्षित रूप से खड़ा है"],"explanation":"खतरनाक माल को वाहनों के बीच केवल वास्तविक आपातकाल में ही स्थानांतरित किया जाना चाहिए, इसलिए सामान्य खराबी या देर से डिलीवरी सड़क किनारे स्थानांतरण का कारण नहीं है।"},"59":{"q":"मैं बंदरगाह की अपनी यात्रा से पहले एक खेप लाद रहा हूं जिसे शिपर के दस्तावेज समुद्री प्रदूषक के रूप में पहचानते हैं। अपना निरीक्षण पूरा करने वाले चालक के रूप में, इस माल को ढोने के लिए सहमत होने से पहले इनमें से कौन सी शर्त पूरी होनी चाहिए?","options":["समुद्री प्रदूषक लेबल तब तक ढके रह सकते हैं जब तक मैं समुद्री टर्मिनल नहीं पहुंच जाता","मेरे द्वारा इसे ढोने से पहले पैकेज पर आवश्यक समुद्री प्रदूषक चिह्न होने चाहिए","समुद्री प्रदूषक चिह्न छोड़े जा सकते हैं क्योंकि यह पहले सड़क से जाता है","माल को सड़क पर सुरक्षित रखने के लिए कंटेनर को नजरों से छिपाया जाना चाहिए"],"explanation":"समुद्री प्रदूषक को परिवहन से पहले पैकेज पर आवश्यक चिह्न प्रदर्शित करने चाहिए, और चालक को किसी भी गलत तरीके से चिह्नित खतरनाक माल को अस्वीकार करना चाहिए।"},"60":{"q":"रास्ते में आपको अपने ट्रेलर में किसी पैकेज से खतरनाक सामग्री (हैज़मैट) का रिसाव दिखता है। आपको क्या करना चाहिए?","options":["गंतव्य तक तेज़ी से गाड़ी चलाते रहना ताकि वहां प्राप्तकर्ता (कंसाइनी) रिसाव से निपट सके।","रुकें, क्षेत्र को सुरक्षित करें, लोगों को दूर रखें, और वाहन को अनावश्यक रूप से न हिलाएं।","ट्रेलर के सभी दरवाज़े खोल दें और गाड़ी चलाते रहें ताकि चलते-चलते धुआं/गैस बाहर निकल जाए।","रिसाव वाली सामग्री को पानी से सड़क से धो दें और फिर अपने रास्ते पर आगे बढ़ें।"],"explanation":"रुकें, क्षेत्र को सुरक्षित करें, लोगों को पीछे रखें, और वाहन को अनावश्यक रूप से न हिलाएं।"},"61":{"q":"आप हैज़मैट लोड कर रहे हैं और शिपमेंट की पुष्टि करनी है। कागज़ात पर हैज़मैट का सही वर्णन करना किसका काम है?","options":["वह मैकेनिक जिसने आज इस यात्रा पर भेजे जाने से पहले ट्रक की आखिरी सर्विसिंग की थी।","शिपर (भेजने वाला), जिसे शिपिंग पेपर्स पर हैज़मैट का सही नाम और वर्णन देना चाहिए।","गंतव्य पर प्राप्तकर्ता, जो लोड डिलीवर होने के बाद ही उसकी जांच करता है।","टर्मिनल पर कोई भी अन्य ड्राइवर जो उस समय पास में खड़ा हो।"],"explanation":"शिपर कागज़ात पर हैज़मैट का सही नाम और वर्णन देता है।"},"62":{"q":"आप प्लेकार्ड वाले विस्फोटक (डिवीज़न 1.1) ले जा रहे हैं और ईंधन तथा भोजन के लिए रुकना है। आपको कहां पार्क करना चाहिए?","options":["किसी भीड़भाड़ वाले रेस्टोरेंट की पार्किंग में, ठीक इमारत के सामने वाले प्रवेश द्वार के पास।","खुली आग, पुलों, सुरंगों और भीड़ से दूर, और जहां आवश्यक हो वहां देखरेख में।","किसी व्यस्त शहर की सड़क पर ताकि पास के कैफे के अंदर से ट्रक पर आसानी से नज़र रखी जा सके।","अन्य खड़े ट्रकों के पास जिनके इंजन चालू हों ताकि आपका कार्गो अच्छी तरह गर्म रहे।"],"explanation":"आग, पुलों, सुरंगों और भीड़ से दूर पार्क करें; जहां आवश्यक हो वहां इसकी देखरेख करें।"},"63":{"q":"मैं एक ट्रैक्टर-ट्रेलर पर यात्रा-पूर्व निरीक्षण कर रहा हूँ जिस पर ज्वलनशील तरल माल के लिए प्लेकार्ड (placards) लगे हैं। निकलने से पहले मैं यह सुनिश्चित करना चाहता हूँ कि मेरा अग्निशामक यंत्र संघीय आवश्यकता को पूरा करता है। इनमें से कौन सा विकल्प वास्तव में नियम को पूरा करेगा?","options":["अग्निशामक यंत्र माल के साथ सीलबंद ट्रेलर के अंदर बंद रह सकता है, क्योंकि आग सबसे अधिक संभावना से वहीं शुरू होगी।","पूरी तरह चार्ज किया गया अग्निशामक यंत्र ठीक है, भले ही वह माल की पट्टियों के पीछे दबा हो, बशर्ते वह माल के लिए सही रेटिंग का हो।","अग्निशामक यंत्र माल के लिए सही रेटिंग वाला, पूरी तरह चार्ज किया हुआ, और ऐसी जगह लगा होना चाहिए जहाँ मैं उसे जल्दी पकड़ सकूँ।","कोई भी छोटा चार्ज किया हुआ अग्निशामक यंत्र काम करेगा, क्योंकि रेटिंग केवल प्राप्तकर्ता के डॉक उपकरण के लिए मायने रखती है, ट्रक के लिए नहीं।"],"explanation":"प्लेकार्ड लगे वाहन का अग्निशामक यंत्र माल के लिए उचित रेटिंग वाला, पूरी तरह चार्ज और ऐसी जगह लगा होना चाहिए जहाँ चालक उसे जल्दी पकड़ सके।"},"64":{"q":"प्लेकार्ड वाली खतरनाक सामग्री ले जाते समय आप एक रेलरोड क्रॉसिंग पर पहुंचते हैं। आपको क्या करना चाहिए?","options":["बिना रुके धीरे-धीरे पार कर जाना, जब तक आपको अभी कोई ट्रेन आती हुई न दिखे।","पटरियों से 15 से 50 फीट (ft) पहले रुकें, जांच लें कि रास्ता साफ है, फिर गियर बदले बिना पार करें।","दोनों ओर ध्यान से देखने के लिए ठीक पटरियों पर रुकें, फिर आगे पार करें।","पटरियों को तेज़ी से पार करने के लिए गति बढ़ाएं ताकि प्लेकार्ड वाला लोड पटरियों पर कम समय रहे।"],"explanation":"पटरियों से 15–50 फीट (ft) पहले रुकें, फिर गियर बदले बिना पार करें।"},"65":{"q":"अपने शिपिंग पेपर्स की जांच करते समय, आप पाते हैं कि हैज़मैट सबसे पहले सूचीबद्ध नहीं है या चिह्नित नहीं है। यह आपको क्या बताता है?","options":["कागज़ात सही हैं, क्योंकि हैज़मैट शिपिंग दस्तावेज़ पर कहीं भी आ सकता है।","कागज़ात गलत हैं; हैज़मैट को सबसे पहले दर्ज किया जाना चाहिए या स्पष्ट रूप से चिह्नित या हाइलाइट किया जाना चाहिए।","इसका मतलब है कि गाड़ी में कोई हैज़मैट नहीं है, इसलिए आप ट्रक से प्लेकार्ड हटा सकते हैं।","यह केवल प्राप्तकर्ता के लिए मायने रखता है, इसलिए आप यात्रा शुरू कर सकते हैं और बाद में इसे सुलझा सकते हैं।"],"explanation":"कागज़ात पर हैज़मैट को सबसे पहले दर्ज किया जाना चाहिए या स्पष्ट रूप से चिह्नित/हाइलाइट किया जाना चाहिए।"},"66":{"q":"आप एक लोड परिवहन करने वाले हैं और तय करना है कि प्लेकार्ड की आवश्यकता है या नहीं। प्लेकार्ड लगाने की जिम्मेदारी किसकी है?","options":["केवल पुलिस की, जो सड़क किनारे निरीक्षण के समय यदि उन्हें आवश्यक लगे तो प्लेकार्ड जोड़ती है।","ड्राइवर और कैरियर (वाहक) को वाहन पर प्लेकार्ड लगाना चाहिए जब लोड के लिए प्लेकार्ड आवश्यक हो।","प्राप्तकर्ता शिपमेंट डिलीवर होने के बाद ट्रक पर प्लेकार्ड लगाता है।","प्लेकार्ड वैकल्पिक सजावट हैं और इनके लिए कोई विशेष रूप से जिम्मेदार नहीं है।"],"explanation":"ड्राइवर और कैरियर वाहन पर प्लेकार्ड लगाते हैं जब लोड के लिए यह आवश्यक हो।"},"67":{"q":"आप ज्वलनशील तरल पदार्थ का प्लाकार्ड लगा हुआ भार ढो रहे हैं और अपनी हर 2 घंटे की टायर जांच के लिए एक विश्राम स्थल पर रुकते हैं। आपको पता चलता है कि आपके ट्रेलर का एक टायर छूने पर गरम है और स्पष्ट रूप से ज्यादा गर्म हो रहा है। निम्नलिखित में से कौन सा सही कार्रवाई है?","options":["गरम टायर पर पानी डालकर उसे जल्दी ठंडा करें, फिर शिपमेंट को समय पर पहुंचाने के लिए डिलीवरी तक गाड़ी चलाते रहें।","गरम टायर को उसके सही दबाव पर लाने के लिए हवा भरें और योजनाबद्ध मार्ग पर गाड़ी चलाते रहें।","टायर को उसी जगह छोड़दें और गाड़ी चलाते रहें, क्योंकि पूरी तरह लदे प्लाकार्ड ट्रेलर पर कुछ गर्मी सामान्य होती है।","ज्यादा गर्म हुए टायर को निकालकर वाहन से सुरक्षित दूरी पर रखें, फिर आगे बढ़ने से पहले उसकी जांच करें।"],"explanation":"यदि प्लेकार्ड लगे माल में कोई टायर अधिक गर्म हो जाए तो यह आग का खतरा है, इसलिए उसे हटाकर वाहन से सुरक्षित दूरी पर रखें और आगे बढ़ने से पहले जाँचें।"},"68":{"q":"आप एक मेट्रो क्षेत्र से होकर प्लेकार्ड वाले हैज़मैट लोड के लिए रास्ता (रूट) की योजना बना रहे हैं। सबसे अच्छी प्रथा क्या है?","options":["गंतव्य तक सबसे तेज़ पहुंचने के लिए हमेशा सबसे व्यस्त शहरी केंद्र से होकर गाड़ी चलाना।","जहां आवश्यक हो वहां घनी आबादी वाले क्षेत्रों, भीड़ और सुरंगों से बचें, और पहले से योजना बनाएं।","हमेशा उपलब्ध सबसे लंबे पुल का उपयोग करें ताकि भारी लोड एक चिकनी सतह पर रहे।","कभी भी पहले से रूट की योजना न बनाएं; बस हर बार नेविगेशन ऐप के अनुसार मोड़-दर-मोड़ चलें।"],"explanation":"जहां आवश्यक हो वहां भीड़ और सुरंगों से बचें और रास्ते की योजना पहले से बनाएं।"},"69":{"q":"मैंने अभी-अभी अपना आखिरी खतरनाक माल का स्किड माल पाने वाले को सौंप दिया है, और अब ट्रेलर पूरी तरह खाली और अवशेष-रहित है, लेकिन चारों प्लेकार्ड अभी भी लगे हुए हैं। अब मैं खाली ट्रेलर लेकर इंटरस्टेट से वापस यार्ड जाने वाला हूँ। इस खाली यात्रा में मुझे कानूनी रूप से सही कौन-सी कार्रवाई रखती है?","options":["अभी प्लेकार्ड हटा दें या ढक दें, क्योंकि ट्रेलर अब ऐसा कोई माल नहीं ले जा रहा जिसके लिए इनकी आवश्यकता हो।","पूरे वापसी रास्ते में प्लेकार्ड लगे रहने दें, क्योंकि प्लेकार्ड वाले ट्रेलर को दूसरे चालक हमेशा अधिक सुरक्षित मानते हैं।","इन्हें केवल पहले रेलरोड क्रॉसिंग तक लगे रहने दें, फिर उस ठहराव पर इन्हें उतार दें।","असल में इससे कोई फर्क नहीं पड़ता, इसलिए अगर समय बचता है तो मैं खाली ट्रेलर पर प्लेकार्ड लगे रहने दे सकता हूँ।"],"explanation":"जब वाहन में अब ऐसा माल नहीं रह जाता जिसके लिए कानूनन प्लेकार्ड जरूरी हों, तो उन्हें हटाना या ढकना चाहिए ताकि वे माल का गलत संकेत न दें।"},"70":{"q":"मैं एक प्लेकार्ड लगे लोड की प्री-ट्रिप जांच कर रहा हूं और हस्ताक्षर करने से पहले शिपिंग पेपर का पैकेज से मिलान कर रहा हूं। प्रविष्टि में पहले से ही उचित शिपिंग नाम और खतरा वर्ग दर्शाया गया है। इसे पूर्ण और कानूनी बनाने के लिए, उसी प्रविष्टि में कौन सी शेष जानकारी अवश्य होनी चाहिए?","options":["मेरे निर्धारित हैज़मैट मार्ग पर मैं जितनी कुल दूरी तय करूंगा","सामग्री का पहचान (ID) नंबर (UN/NA)","वाहक के लिए 24 घंटे उपलब्ध CHEMTREC फोन नंबर","बाहरी ड्रम पर अंकित पैकिंग समूह अक्षर"],"explanation":"पूर्ण शिपिंग पेपर प्रविष्टि में सही शिपिंग नाम, खतरा श्रेणी और UN/NA पहचान संख्या इसी क्रम में होते हैं।"},"71":{"q":"मैं एक वज़न जाँच केंद्र (weigh station) पर रुका हूँ और निरीक्षक मेरे ट्रेलर पर हीरे के आकार के प्लेकार्ड के नीचे लगे नारंगी पैनल की ओर इशारा करता है, जिस पर मोटे काले अक्षरों में संख्या \"1203\" लिखी है। वह पूछता है कि यह चार अंकों की संख्या आपातकालीन दल को क्या बताती है। सही व्याख्या कौन-सी है?","options":["यह उस कक्ष में लदे खतरनाक माल का पाउंड में सकल वज़न है","यह खतरा वर्ग का विभाजन कोड है जो माल के खतरे को 1 से 9 तक श्रेणीबद्ध करता है","यह UN/NA पहचान संख्या है जो ले जाए जा रहे विशिष्ट पदार्थ का नाम बताती है","यह आपातकालीन टेलीफोन कोड है जिसे दल माल के बारे में CHEMTREC से संपर्क करने हेतु डायल करते हैं"],"explanation":"प्लेकार्ड या नारंगी पैनल पर चार अंकों की संख्या UN/NA पहचान संख्या है, जो ले जाए जा रहे विशिष्ट पदार्थ को दर्शाती है।"},"72":{"q":"एक मालवाहक ब्रोकर मुझे एक क्षारक (corrosive) सामग्री का लोड देने की पेशकश करता है, जिसके लिए मेरे ट्रेलर के चारों तरफ प्लेकार्ड (चेतावनी चिह्न) लगाने होंगे। मेरे पास पहले से ही Tanker (N) और Doubles/Triples (T) इंडोर्समेंट के साथ CDL है, और मैंने अभी अपना मेडिकल कार्ड नवीनीकृत किया है। इस शिपमेंट को कानूनी रूप से स्वीकार करने और ढोने से पहले मुझे क्या पूरा कर लेना चाहिए?","options":["और कुछ नहीं — चूंकि मेरा लोड क्षारक (वर्ग 8) है और विस्फोटक नहीं, इसलिए केवल प्लेकार्ड ही कानूनी आवश्यकता को पूरा करते हैं और किसी विशेष इंडोर्समेंट की आवश्यकता नहीं है।","केवल Tanker (N) इंडोर्समेंट, जो मेरे पास पहले से है, क्योंकि संघीय नियमों के अनुसार प्लेकार्ड वाली कोई भी सामग्री थोक तरल खतरा मानी जाती है।","एक वर्तमान Passenger (P) इंडोर्समेंट, क्योंकि सार्वजनिक सुरक्षा को प्रभावित करने वाले नियंत्रित लोड को ढोना, यात्रियों को ढोने के समान माना जाता है।","HazMat (H) इंडोर्समेंट, जिसके लिए किसी भी प्लेकार्ड वाली खतरनाक सामग्री को ढोने से पहले फिंगरप्रिंट के साथ TSA सुरक्षा खतरा मूल्यांकन पास करना आवश्यक है।"],"explanation":"प्लेकार्ड वाले किसी भी खतरनाक पदार्थ को ढोने के लिए HazMat (H) एंडोर्समेंट जरूरी है, जिसके लिए फिंगरप्रिंटिंग सहित TSA सुरक्षा खतरा मूल्यांकन अनिवार्य है।"},"73":{"q":"मेरे पास पहले से ही क्लास A CDL है और मैंने अपना रोड टेस्ट पास कर लिया है, लेकिन अब मैं प्लेकार्ड वाले खतरनाक पदार्थों का परिवहन करना चाहता हूँ। लिखित खतरनाक पदार्थ (HazMat) ज्ञान परीक्षा पास करने के अलावा, मेरे लाइसेंस में H एंडोर्समेंट जोड़े जाने से पहले मुझे कौन-सी एक अतिरिक्त शर्त पूरी करनी होगी?","options":["मुझे TSA सुरक्षा खतरा मूल्यांकन पूरा करना होगा, जिसमें उंगलियों के निशान लेना और पृष्ठभूमि जाँच शामिल है","मुझे प्लेकार्ड वाले वाहन में दूसरा, अलग रोड टेस्ट पास करना होगा","मुझे पूर्व-शर्त के रूप में पहले अपना टैंकर (N) एंडोर्समेंट प्राप्त करना होगा","मुझे अपने लाइसेंस में डबल्स/ट्रिपल्स (T) एंडोर्समेंट जोड़ना होगा"],"explanation":"HazMat (H) एंडोर्समेंट अकेला ऐसा है जिसके लिए आवेदक को फिंगरप्रिंटिंग और पृष्ठभूमि जांच सहित TSA सुरक्षा खतरा मूल्यांकन पास करना पड़ता है।"},"74":{"q":"गाड़ी चलाते समय आपको हैजमैट (खतरनाक सामग्री) के शिपिंग पेपर कहाँ रखने चाहिए?","options":["ट्रेलर के अंदर ताला लगाकर रखें","पहुँच के भीतर, दरवाजे की पाउच में या सीट पर","इंजन कंपार्टमेंट क्षेत्र के अंदर","पहले प्राप्तकर्ता को मेल से भेज दें"],"explanation":"गाड़ी चलाते समय शिपिंग पेपर पहुँच के भीतर (दरवाजे की पाउच में) या सीट पर रखें।"},"75":{"q":"यदि आप सुनिश्चित नहीं हैं कि कोई सामग्री खतरनाक है या नहीं, तो आपको चाहिए:","options":["यह मान लें कि यह सुरक्षित है और इसे लोड कर लें","लोड करने से पहले शिपर से जाँच करें","इसे अनदेखा करें और अभी गाड़ी चलाना शुरू करें","पहले सभी प्लेकार्ड हटा दें"],"explanation":"जब अनिश्चित हों, तो लोड करने से पहले शिपर से जाँच करें।"},"76":{"q":"मैं एक विश्राम स्थल पर ज्वलनशील तरल के अपने प्लेकार्ड लगे लदान के साथ खड़ा हूँ। एक अन्य चालक बातचीत करने आता है और मेरे ट्रक के पास आते समय सिगरेट जला लेता है। हमारी सुरक्षा के लिए, मेरे प्लेकार्ड वाले वाहन के पास उसे अधिक से अधिक कितनी नज़दीकी तक धूम्रपान करने की अनुमति होनी चाहिए?","options":["लगभग 15 फीट से अधिक नज़दीक नहीं — रेलवे पटरियों से पहले इस्तेमाल होने वाली वही दूरी","प्लेकार्ड वाले वाहन से लगभग 25 फीट से अधिक नज़दीक नहीं","लगभग 5 फीट से अधिक नज़दीक नहीं — सड़क से पार्किंग की वही दूरी","केबिन के बाहर कहीं भी ठीक है क्योंकि लदान सीलबंद है"],"explanation":"विस्फोटक, ऑक्सीडाइज़र या ज्वलनशील पदार्थ ले जा रहे प्लेकार्ड वाले वाहन के लगभग 25 फीट के भीतर धूम्रपान वर्जित है।"},"77":{"q":"मैं एक माल उठा रहा हूँ और शिपिंग पेपर पर सामग्री को खतरा वर्ग 7 के रूप में दर्शाया गया है। प्लैकार्ड लगाने और पैकेजों का निरीक्षण करने से पहले, मैं पुष्टि करना चाहता हूँ कि मैं वास्तव में किस प्रकार का खतरा ढो रहा हूँ। दर्शाए गए खतरा वर्ग के आधार पर, मेरे ट्रेलर में क्या है?","options":["एक ज्वलनशील तरल जैसे पेट्रोल या डीज़ल","एक संक्षारक (कोरोसिव) तरल जो त्वचा को जला सकता है और धातु को नुकसान पहुँचा सकता है","एक रेडियोधर्मी सामग्री","उच्च दाब के अंतर्गत एक संपीड़ित गैस"],"explanation":"संघीय खतरा श्रेणी प्रणाली में, श्रेणी 7 हमेशा रेडियोधर्मी पदार्थों को दर्शाती है।"},"78":{"q":"मैं प्लेकार्ड लगा हुआ माल तैयार कर रहा हूँ और मेरे शिपिंग पेपर पर माल का खतरा वर्ग 'वर्ग 1' लिखा है। सही तरीके से पार्क करने और संभालने के लिए मुझे पता होना चाहिए कि मैं असल में क्या ढो रहा हूँ। 'वर्ग 1' पदनाम मुझे बताता है कि माल है:","options":["ज्वलनशील तरल पदार्थ, जैसे पेट्रोल या डीज़ल, जो वर्ग 3 में आते हैं","संक्षारक (कोरोसिव) तरल पदार्थ, अम्ल और क्षार जो वर्ग 8 में रखे जाते हैं","संपीड़ित या ज्वलनशील गैसें, जो वर्ग 2 में आती हैं","विस्फोटक, वे पदार्थ जो वर्ग 1 में आते हैं"],"explanation":"निश्चित खतरा श्रेणी क्रमांकन में, श्रेणी 1 हमेशा विस्फोटकों को दर्शाती है।"},"79":{"q":"मैं अपने माल के शिपिंग कागजात की जांच कर रहा हूं और एक प्रविष्टि में खतरा वर्ग को सामग्री के UN नंबर के साथ \"2.1\" के रूप में दर्शाया गया है। खतरा वर्ग क्रमांकन प्रणाली के अनुसार, मैं वास्तव में किस प्रकार की सामग्री ढो रहा हूं?","options":["एक ज्वलनशील गैस, क्योंकि वर्ग 2 गैसों को कवर करता है (जिसमें 2.1 ज्वलनशील है)","एक ज्वलनशील तरल, क्योंकि यह सबसे आम ज्वलनशील माल वर्ग है","एक विस्फोटक, क्योंकि कम वर्ग संख्या का मतलब है कि यह हिंसक रूप से प्रज्वलित होता है","एक रेडियोधर्मी सामग्री, क्योंकि इसमें एक विशेष UN पहचान संख्या होती है"],"explanation":"श्रेणी 2 गैसों को कवर करती है, और प्रभाग 2.1 विशेष रूप से ज्वलनशील गैस को दर्शाता है।"},"80":{"q":"मैं एक खेप उठा रहा हूँ और परिवहन दस्तावेज़ में प्रविष्टि इस प्रकार दर्ज है: \"एसीटोन, 3, UN1090\"। डिस्पैचर मुझसे पुष्टि करने को कहता है कि बीच का यह नंबर मुझे किस प्रकार का खतरा बताता है, ताकि मैं सही प्लेकार्ड (चेतावनी तख्तियाँ) लूं। दिखाए गए खतरा वर्ग के अनुसार, मैं क्या ढो रहा हूँ?","options":["एक ज्वलनशील ठोस जो घर्षण से आग पकड़ सकता है","एक ज्वलनशील तरल जो ज्वलनशील वाष्प छोड़ता है","दबाव में एक ज्वलनशील संपीड़ित गैस","एक ऑक्सीकारक पदार्थ जो आग को तीव्र करता है"],"explanation":"श्रेणी 3 हमेशा ज्वलनशील तरल पदार्थों को दर्शाती है, जो प्रज्वलनशील वाष्प छोड़ते हैं।"},"81":{"q":"मैं एक माल के लिए शिपिंग कागजात तैयार कर रहा हूं और प्रविष्टि पर खतरा वर्ग \"वर्ग 4\" दर्शाता है। प्लेकार्ड लगाने से पहले, मैं यह पुष्टि करना चाहता हूं कि यह सामग्री किस सामान्य श्रेणी में आती है ताकि मैं सही प्लेकार्ड का मिलान कर सकूं। खतरा वर्ग प्रणाली के अनुसार, वर्ग 4 की सामग्री को निम्नलिखित में से किस रूप में पहचाना जाता है?","options":["एक संक्षारक (कोरोसिव) तरल जो त्वचा और धातु को नुकसान पहुंचा सकता है","एक ज्वलनशील तरल जैसे गैसोलीन या ईंधन तेल","एक ज्वलनशील ठोस, जिसमें स्वतः दहनशील और गीला होने पर खतरनाक सामग्री शामिल है","एक विस्फोटक वस्तु जो झटके या गर्मी से विस्फोट करती है"],"explanation":"श्रेणी 4 में ज्वलनशील ठोस पदार्थ आते हैं, जिनमें स्वतः जलने वाले और गीला होने पर खतरनाक पदार्थ शामिल हैं।"},"82":{"q":"मैं अपने अगले माल के लिए शिपिंग दस्तावेज़ों की जाँच कर रहा हूँ और खतरा-श्रेणी कॉलम में एक श्रेणी 5 का खतरनाक पदार्थ दर्ज है। शिपमेंट स्वीकार करने और प्लेकार्ड लगाने से पहले, मुझे पुष्टि करनी है कि मैं वास्तव में किस प्रकार का पदार्थ ढोऊँगा। कौन सा विवरण श्रेणी 5 के पदार्थ से सही ढंग से मेल खाता है?","options":["ज्वलनशील तरल पदार्थ जैसे पेट्रोल, डीज़ल योजक और विलायक","संक्षारक पदार्थ जैसे बैटरी अम्ल और अन्य तीव्र तरल पदार्थ","ज़हर और विषैले तरल पदार्थ जो साँस के ज़रिए खतरा पैदा करते हैं","ऑक्सीकारक और कार्बनिक परॉक्साइड"],"explanation":"श्रेणी 5 ऑक्सीकारक और कार्बनिक पेरोक्साइड का समूह है।"},"83":{"q":"टर्मिनल से निकलने से पहले मैं एक लोड के शिपिंग कागज़ात जांच रहा हूं, और एक प्रविष्टि क्लास 6 के रूप में चिह्नित है। शिपर ने अभी तक सही शिपिंग नाम नहीं लिखा है और मुझसे पुष्टि करने को कहता है कि क्लास 6 का प्लॅकार्ड किस प्रकार की सामग्री को कवर करता है, ताकि कागज़ात खतरे से मेल खाएं। कौन सा विवरण सही ढंग से बताता है कि क्लास 6 में क्या आता है?","options":["ज़हर (विषाक्त) और संक्रामक पदार्थ","ज्वलनशील तरल जैसे गैसोलीन और आम विलायक","संक्षारक तरल जो त्वचा और धातु को जला सकते हैं","ऑक्सीकारक और कार्बनिक पेरॉक्साइड जो आग को तीव्र करते हैं"],"explanation":"श्रेणी 6 में ज़हरीले (विषैले) पदार्थ और संक्रामक पदार्थ आते हैं।"},"84":{"q":"मैं अपनी यात्रा-पूर्व जांच कर रहा हूं और एक ऐसे माल के परिवहन दस्तावेज़ों की समीक्षा कर रहा हूं जिसमें श्रेणी 8 (Class 8) का खतरा दर्ज है। कंटेनरों को संभालने और सही दस्ताने व आंखों की सुरक्षा चुनने से पहले, मुझे यह जानना ज़रूरी है कि यह सामग्री वास्तव में किस प्रकार का खतरा प्रस्तुत करती है। कौन सा कथन सही ढंग से बताता है कि श्रेणी 8 की सामग्री क्या होती है?","options":["यह एक ज्वलनशील तरल है जो चिंगारी से जल सकता है, इसलिए मेरी मुख्य चिंता सभी प्रज्वलन स्रोतों को माल से दूर रखना है।","यह एक संक्षारक (corrosive) पदार्थ है जो त्वचा, आंखों और धातु को रासायनिक रूप से जला सकता है, इसलिए मेरी मुख्य चिंता संपर्क रोकना और सतहों की रक्षा करना है।","यह दबाव में एक संपीड़ित गैस है जो हिंसक रूप से फट सकती है, इसलिए मेरी मुख्य चिंता सिलेंडरों को ठंडा और सुरक्षित रखना है।","यह एक रेडियोधर्मी पदार्थ है जो हानिकारक विकिरण उत्सर्जित करता है, इसलिए मेरी मुख्य चिंता माल के पास अपने संपर्क समय को सीमित करना है।"],"explanation":"श्रेणी 8 संक्षारक पदार्थ हैं जो संपर्क में आने पर त्वचा, आँखों और धातु को रासायनिक रूप से जला देते हैं, इसलिए संपर्क रोकना और सतहों की रक्षा करना प्राथमिकता है।"},"85":{"q":"मैं एक माल के शिपिंग दस्तावेज़ों की जाँच कर रहा हूँ और एक प्रविष्टि देखता हूँ जिसे श्रेणी 9 खतरनाक सामग्री के रूप में वर्गीकृत किया गया है। मेरे प्रशिक्षक मुझसे पूछते हैं कि यह वर्गीकरण वास्तव में माल के बारे में मुझे क्या बताता है। कौन सा कथन सही ढंग से बताता है कि श्रेणी 9 पदनाम का क्या अर्थ है?","options":["यह डिवीज़न 2.3 उत्पाद की पहचान करता है, अर्थात माल एक ज़हरीली गैस है जिसके लिए किसी भी मात्रा में प्लेकार्ड आवश्यक हैं","यह एक ज्वलनशील तरल की पहचान करता है, वही श्रेणी जो शिपिंग दस्तावेज़ पर खतरा श्रेणी 3 के अंतर्गत आती है","यह एक विविध खतरनाक वस्तु की पहचान करता है जो अन्य आठ खतरा श्रेणियों में से किसी में भी ठीक से फिट नहीं बैठती","यह एक विस्फोटक वस्तु की पहचान करता है, वही माल परिवार जो खतरा श्रेणी 1 के प्लेकार्डिंग नियमों के अंतर्गत आता है"],"explanation":"श्रेणी 9 विविध श्रेणी है, जिसमें वे खतरनाक माल आते हैं जो अन्य आठ खतरा श्रेणियों में फिट नहीं होते।"},"86":{"q":"मैं ऐसा संक्षारक (corrosive) माल ढो रहा हूँ जिसके लिए प्लेकार्ड लगाना ज़रूरी है, और एक राज्य पुलिस अधिकारी मुझे वज़न केंद्र (weigh station) में बुलाता है। वह कहता है कि जहाँ वह खड़ा था वहाँ से उसे केवल एक ही प्लेकार्ड दिखा, और मुझसे पुष्टि करने को कहता है कि मेरे वाहन पर प्लेकार्ड कैसे लगने चाहिए। कौन-सा कथन सही प्लेकार्ड लगाने का वर्णन करता है?","options":["प्लेकार्ड केवल ट्रेलर के पीछे ज़रूरी हैं, क्योंकि पीछे आने वाला यातायात और निरीक्षक उसी को पढ़ते हैं","चालक की ओर एक ही प्लेकार्ड पर्याप्त है, बशर्ते वह जिस दिशा की ओर है उस दिशा से पढ़ा जा सके","प्लेकार्ड केवल ट्रैक्टर के आगे और ट्रेलर के पीछे लगते हैं, ताकि वे सामने से और पीछे से दिखें","प्लेकार्ड वाहन के चारों ओर (सभी चार तरफ) लगाए जाने चाहिए, और हर एक उस दिशा से पढ़ा जा सके जिस ओर वह है"],"explanation":"प्लेकार्ड वाहन के चारों ओर लगे होने चाहिए, और प्रत्येक उस दिशा से पढ़ने योग्य होना चाहिए जिस ओर वह मुड़ा है।"},"87":{"q":"मैं अपनी प्री-ट्रिप जांच कर रहा हूं और रोटी जरूरी (HazMat) खतरनाक माल ले जाने से पहले मुझे यह पुष्टि करनी है कि मेरे ट्रेलर पर चेतावनी चिह्न सही हैं। जब मैं वाहन के हर तरफ सही तरीके से लगे HazMat प्लेकार्ड को देखता हूं, तो उसका समग्र आकार कैसा होना चाहिए?","options":["एक हीरा (डायमंड), यानी एक वर्ग जो घुमाकर अपने किसी एक कोने (नोक) पर टिका हो","एक त्रिभुज, उसी आकार का जैसे मेरे साथ रखे परावर्तक चेतावनी त्रिभुज होते हैं","एक आयत जो ऊंचाई से अधिक चौड़ी हो, जैसे पहचान संख्या वाला पैनल","एक वृत्त जिसके किनारे पर रंगीन छल्ला हो, जैसे सड़क संकेत का प्रतीक"],"explanation":"हैज़मैट प्लेकार्ड हीरे के आकार का होता है — एक वर्ग जो अपने एक कोने पर टिका होता है।"},"88":{"q":"मैं प्लेकार्ड (खतरे की पट्टिका) लगा हुआ माल ढो रहा हूँ और अपनी यात्रा-पूर्व जाँच के दौरान देखता हूँ कि मेरे ट्रेलर के दाहिनी ओर का प्लेकार्ड सड़क की गंदगी से सना हुआ है और एक पट्टे के हुक से आंशिक रूप से ढका है, जबकि बाकी तीनों प्लेकार्ड साफ हैं। गाड़ी चलाने से पहले, Texas DPS मुझसे उस दाहिनी ओर के प्लेकार्ड के बारे में क्या करने की अपेक्षा करता है?","options":["कुछ अतिरिक्त नहीं, क्योंकि जब तक आगे और पीछे के प्लेकार्ड साफ और पठनीय रहते हैं, तब तक बगल के प्लेकार्ड की दृश्यता नियंत्रित नहीं होती","उसे साफ करूँ और पट्टे के हुक को हटाऊँ ताकि प्लेकार्ड पठनीय और बिना ढका रहे, क्योंकि चारों ओर के प्लेकार्ड उस दिशा से दिखाई देने चाहिए जिस ओर वे मुड़े हैं","उस एक प्लेकार्ड को पूरी तरह हटा दूँ, क्योंकि आंशिक रूप से गंदा प्लेकार्ड कोई प्लेकार्ड न होने के बराबर माना जाता है और बाकी तीन माल को दर्शाने के लिए पर्याप्त हैं","उसे वैसे ही छोड़ दूँ और बस अपने शिपिंग दस्तावेज़ों में उसकी स्थिति लिख दूँ ताकि निरीक्षक को पता चले कि मैं इसके बारे में जानता हूँ"],"explanation":"चूँकि चारों ओर के प्लेकार्ड अपनी दिशा से पढ़ने योग्य होने चाहिए, गंदे या ढके प्लेकार्ड को गाड़ी चलाने से पहले साफ़ करके खोलना ज़रूरी है।"},"89":{"q":"मैं मिश्रित माल लाद रहा हूँ और एक पैलेट प्लेकार्ड (चेतावनी पट्टिका) नियमों की तालिका 2 में सूचीबद्ध एक खतरनाक पदार्थ है। एक सहकर्मी मुझसे कहता है, 'खतरनाक माल तो खतरनाक माल है — जैसे ही इसका थोड़ा सा भी ट्रेलर में चढ़ता है, प्लेकार्ड लगाना ही पड़ता है।' चारों तरफ कुछ भी लगाने से पहले, मुझे कैसे तय करना चाहिए कि इस माल के लिए वास्तव में प्लेकार्ड आवश्यक हैं या नहीं?","options":["किसी भी मात्रा से प्लेकार्ड जरूरी हो जाते हैं, इसलिए जिस क्षण एक भी खतरनाक माल का पैकेज वाहन में आता है मुझे चारों तरफ प्लेकार्ड लगाने होंगे","प्लेकार्ड केवल पैकेजिंग पर आधारित होते हैं, इसलिए मैं सिर्फ इसलिए प्लेकार्ड लगाता हूँ क्योंकि खाद्य और गैर-खाद्य वस्तुएँ एक साथ लदी हैं","यह पदार्थ के वर्ग और मात्रा पर निर्भर करता है — कुछ वर्गों के लिए किसी भी मात्रा में प्लेकार्ड आवश्यक होते हैं, जबकि ये तालिका 2 के पदार्थ केवल 1,001 पाउंड या उससे अधिक के कुल सकल वजन पर ही उन्हें आवश्यक बनाते हैं","मिश्रित माल की खेप के लिए कानूनन प्लेकार्ड कभी आवश्यक नहीं होते, इसलिए मैं इस यात्रा में इन्हें पूरी तरह छोड़ सकता हूँ"],"explanation":"प्लेकार्ड लगाना श्रेणी और मात्रा पर निर्भर करता है — कुछ श्रेणियों को किसी भी मात्रा में प्लेकार्ड चाहिए, जबकि तालिका 2 की सामग्री को केवल 1,001 पाउंड या अधिक कुल सकल वजन पर चाहिए।"},"90":{"q":"मैं एक डॉक पर अपने ट्रेलर में टेबल 2 के विभिन्न खतरा वर्गों के कई गैर-थोक (नॉन-बल्क) पैकेज लोड कर रहा हूँ। बोर्ड पर कोई भी अकेला खतरा वर्ग अपने आप 1,001 पाउंड तक नहीं पहुँचता, लेकिन टेबल 2 का संयुक्त माल उस सीमा को पार कर जाता है। एक सहकर्मी कहता है कि मैं हर वर्ग के लिए अलग प्लैकार्ड के बजाय पूरे मिश्रित लोड के लिए एक ही DANGEROUS प्लैकार्ड लगा सकता हूँ। प्लैकार्ड नियमों के अनुसार, DANGEROUS प्लैकार्ड का उपयोग वास्तव में कब अनुमत है?","options":["केवल तब जब पूरा ट्रेलर टेबल 2 की एक ही सामग्री का एकल पूर्ण लोड हो जिसका वजन 1,001 पाउंड या उससे अधिक हो","कभी नहीं, क्योंकि बोर्ड पर हर खतरा वर्ग को बिना किसी अपवाद के हमेशा अपना विशिष्ट प्लैकार्ड दिखाना ही होगा","केवल तब जब लोड में क्लास 1 विस्फोटक हों जिन्हें किसी भी मात्रा में प्लैकार्ड की आवश्यकता होती है","जब मैं दो या अधिक टेबल 2 खतरा वर्गों से बने कुछ निश्चित गैर-थोक लोड ढो रहा हूँ, तो उस मिश्रित छोटे लोड के लिए DANGEROUS प्लैकार्ड का उपयोग किया जा सकता है"],"explanation":"जब किसी गैर-थोक माल में तालिका 2 की दो या अधिक खतरा श्रेणियाँ मिली हों, तो अलग-अलग श्रेणी प्लेकार्ड के बजाय DANGEROUS प्लेकार्ड का उपयोग किया जा सकता है।"},"91":{"q":"मैं एक क्लास 3 ज्वलनशील तरल लाद रहा हूँ और मेरे सामान के डिब्बे में बचे एकमात्र प्लेकार्ड पिछली खेप से बचे क्लास 8 (संक्षारक) के प्लेकार्ड हैं। निकलने से पहले, मेरे वाहन पर लगे प्लेकार्ड के बारे में कौन-सा कथन यह सही ढंग से दर्शाता है कि मुझे क्या करना आवश्यक है?","options":["मैं जो प्लेकार्ड लगाऊँ, वे उस सामग्री के खतरे-वर्ग को दर्शाने चाहिए जिसे मैं वास्तव में ढो रहा हूँ, इसलिए क्लास 3 की खेप के लिए मैं क्लास 8 के प्लेकार्ड इस्तेमाल नहीं कर सकता।","कोई भी DOT-शैली का प्लेकार्ड स्वीकार्य है, बशर्ते वह हीरे (डायमंड) के आकार का हो और वाहन के चारों ओर लगा हो।","जब तक मैं सही क्लास 3 के शिपिंग कागज़ात केबिन में अपनी पहुँच के भीतर रखता हूँ, तब तक मैं क्लास 8 के प्लेकार्ड के साथ चल सकता हूँ।","प्लेकार्ड को खेप से तभी मेल खाना ज़रूरी है जब मैं राज्य की सीमा पार करूँ, इसलिए राज्य के भीतर के सफर के लिए क्लास 8 के प्लेकार्ड ठीक हैं।"],"explanation":"प्लेकार्ड आपके द्वारा ले जा रहे माल की वास्तविक खतरा श्रेणी से मेल खाने चाहिए, इसलिए श्रेणी 3 के माल के लिए श्रेणी 3 के प्लेकार्ड चाहिए।"},"92":{"q":"मैं अपने वैन ट्रेलर की यात्रा-पूर्व जांच पूरी कर रहा हूँ, जिसमें एक ऐसा क्लास 3 ज्वलनशील तरल पदार्थ लदा है जिसके लिए प्लेकार्ड (placard) अनिवार्य हैं, और मैं चलने से पहले पुष्टि करना चाहता हूँ कि मेरे प्लेकार्ड सही ढंग से लगे हैं। कानूनी रूप से यात्रा शुरू करने के लिए इनमें से कौन सी शर्त पूरी होनी चाहिए?","options":["प्लेकार्ड केवल आगे और पीछे, क्योंकि यही वे दिशाएँ हैं जिन्हें दूसरे चालक वास्तव में पढ़ते हैं","वाहन के चारों तरफ में से प्रत्येक पर एक प्लेकार्ड, इस तरह सुरक्षित किया गया कि प्रत्येक अपनी दिशा से पढ़ने योग्य हो","ट्रेलर के दोनों किनारों पर प्लेकार्ड, साथ ही प्रत्येक के पास चिपकाई गई शिपिंग कागज़ात की एक प्रति","ट्रेलर की छत पर सपाट लगा एक प्लेकार्ड, ताकि वह दिखता रहे और सड़क के छींटों से सुरक्षित रहे"],"explanation":"प्लेकार्ड वाले खतरनाक माल वाहन पर चारों तरफ प्लेकार्ड होना चाहिए, हर एक सुरक्षित और अपनी दिशा से पढ़ने योग्य।"},"93":{"q":"प्लेकार्ड (placard) लगे लोड के यात्रा-पूर्व निरीक्षण के दौरान, मैं देखता हूँ कि चार अनिवार्य प्लेकार्ड में से एक धूप में इतना फीका पड़ गया है कि खतरा-वर्ग संख्या मुश्किल से पढ़ी जा रही है, हालाँकि मैं उसे बमुश्किल पहचान सकता हूँ। यात्रा शुरू करने से पहले सही कार्रवाई क्या है?","options":["उसे यथावत छोड़ दें, क्योंकि ध्यान से देखने पर प्लेकार्ड अब भी हल्का-सा पढ़ा जा सकता है","और फीका पड़ने से बचाने के लिए फीके प्लेकार्ड को पारदर्शी टेप से ढक दें","यात्रा शुरू करने से पहले फीके प्लेकार्ड को एक नए, पूरी तरह पढ़ने योग्य प्लेकार्ड से बदल दें","जब तक बाकी तीन प्लेकार्ड साफ हैं, आगे बढ़ें और अगले पड़ाव पर उसे बदल दें"],"explanation":"फीका या क्षतिग्रस्त प्लेकार्ड यात्रा शुरू होने से पहले पूरी तरह पढ़ने योग्य नए से बदला जाना चाहिए।"},"94":{"q":"मैं प्लेकार्ड लगा हुआ माल उठा रहा हूँ और शिपर मुझे शिपिंग पेपर देता है। हस्ताक्षर करके निकलने से पहले, मुझे इन पेपरों के बारे में क्या पुष्टि करनी चाहिए?","options":["कि उनमें केवल सही शिपिंग नाम दर्ज है, क्योंकि खतरा वर्ग और पहचान संख्या बाद में जोड़ी जा सकती है","कि एक प्रति टर्मिनल पर छोड़ी गई है, क्योंकि छोटी राज्य-भीतर यात्राओं में मूल प्रति वैकल्पिक है","कि कम से कम एक प्रविष्टि भरी हुई है, भले ही कुछ हैज़मैट विवरण अभी भी अधूरे हों","कि माल ले जाने से पहले हर हैज़मैट प्रविष्टि सटीक और पूर्ण है"],"explanation":"खतरनाक माल के शिपिंग कागज़ माल ले जाने से पहले सटीक और पूर्ण होने चाहिए, हर प्रविष्टि में उचित शिपिंग नाम, खतरा श्रेणी और पहचान संख्या हो।"},"95":{"q":"मैं अंतरराज्यीय राजमार्ग पर प्लेकार्ड लगे संक्षारक (corrosive) माल के साथ चल रहा हूँ, सीट बेल्ट बँधी हुई है। कोई ट्रूपर मुझे किसी भी मील-चिह्न पर रोक सकता है। टेक्सास DPS नियमों के अनुसार, गाड़ी चलाते समय मेरे खतरनाक माल के शिपिंग कागज़ात इस समय कहाँ होने चाहिए?","options":["सीट बेल्ट बँधी होने पर मेरी पहुँच के भीतर, या चालक के दरवाज़े की थैली में, मेरे बाकी कागज़ात के सबसे ऊपर","ट्रेलर के अंदर माल के साथ बंद करके रखे जाएँ ताकि वे साफ़ रहें और असली माल के साथ ही चलें","यात्री की ओर के डैशबोर्ड के डिब्बे (ग्लव बॉक्स) में रखे जाएँ ताकि तेज़ ब्रेक पर सीट से न फिसलें","केवल शिपर के पास रहें, जो हर यात्रा से पहले वाहक के डिस्पैच को एक प्रति फैक्स कर देता है"],"explanation":"गाड़ी चलाते समय खतरनाक माल के शिपिंग कागज़ सीट बेल्ट लगाकर अपनी पहुँच में, या चालक के दरवाज़े की जेब में, अपने अन्य कागज़ों के ऊपर रखें।"},"96":{"q":"मैं एक प्लेकार्ड वाला माल लोड कर रहा हूँ और डॉक से निकलने से पहले शिपिंग पेपर की जाँच कर रहा हूँ। खतरनाक सामग्री उसी पृष्ठ पर कई गैर-खतरनाक माल प्रविष्टियों के बीच मिली-जुली दर्ज है। पेपर के स्वीकार्य होने के लिए, खतरनाक सामग्री की प्रविष्टि बाकी वस्तुओं के बीच कैसी दिखनी चाहिए?","options":["जब तक सही शिपिंग नाम, खतरा वर्ग और पहचान संख्या मौजूद हैं, इसे माल के बीच कहीं भी दर्ज किया जा सकता है","इसे सबसे पहले सूचीबद्ध होना चाहिए, या हाइलाइट करके अथवा HM कॉलम में 'X' लगाकर स्पष्ट रूप से पहचाना जाना चाहिए ताकि यह गैर-खतरनाक माल से अलग दिखे","इसे पृष्ठ पर सबसे अंत में रखा जाना चाहिए ताकि गैर-खतरनाक माल का कुल वजन उसके ऊपर जोड़ा जा सके","इसे अलग से चिह्नित करने की आवश्यकता केवल तभी है जब शिपर या प्राप्त करने वाली सुविधा विशेष रूप से इसका अनुरोध करे"],"explanation":"मिश्रित शिपिंग कागज़ पर खतरनाक माल की प्रविष्टि पहले सूचीबद्ध करके या HM कॉलम में हाइलाइट या 'X' से चिह्नित कर अलग दिखनी चाहिए।"},"97":{"q":"मैं प्लेकार्ड लगे संक्षारक (corrosive) माल को ले जा रहा हूँ, तभी मेरे एक ड्रम का एक फिटिंग रिसने लगता है और धुआं कंधे (shoulder) की ओर बहने लगता है। मैं सुरक्षित रूप से किनारे रुकता हूँ, दूसरों को सावधान करता हूँ, और केबिन में रखी आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) उठाता हूँ। इस समय ERG वास्तव में मुझे निम्नलिखित में से कौन-सा काम करने में मदद के लिए बनाई गई है?","options":["आगे वजन-स्टेशनों और टोल सड़कों से बचने वाला सबसे तेज़ वैकल्पिक मार्ग पहचानना","अपने कागजात के लिए सही शिपिंग नाम, खतरा वर्ग और पहचान संख्या की पुष्टि करना","रिसे हुए पदार्थ के लिए प्रारंभिक पृथक्करण दूरी और सुरक्षात्मक कार्रवाइयाँ निर्धारित करना","यह सत्यापित करना कि कौन-से प्लेकार्ड आवश्यक हैं और वे ट्रेलर के किन किनारों पर लगने चाहिए"],"explanation":"आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) फैले या रिसते पदार्थ के लिए प्रारंभिक अलगाव दूरी और सुरक्षात्मक कार्रवाई बताती है।"},"98":{"q":"मैं प्लेकार्ड लगे संक्षारक (corrosive) माल का लदान उठा रहा हूँ, और मेरे हाथ में जो शिपिंग पेपर हैं उनमें सही शिपिंग नाम, खतरा श्रेणी और पहचान संख्या दर्ज है, और नीचे एक हस्ताक्षरित प्रमाणन कथन है। एक CDL चालक के रूप में, मैं जानता हूँ कि मेरा काम है माल का निरीक्षण करना, रिसाव वाली किसी भी चीज़ को अस्वीकार करना, वाहन पर प्लेकार्ड लगाना और इन कागज़ात को अपनी पहुँच में रखना। लेकिन जब मैं उस हस्ताक्षरित पंक्ति को देखता हूँ जो प्रमाणित करती है कि सामग्री का सही वर्णन किया गया है और परिवहन के लिए उचित रूप से तैयार की गई है, तो वास्तव में मैं किसका प्रमाणन देख रहा हूँ?","options":["वाहक (carrier) का, क्योंकि ट्रकिंग कंपनी माल को रवाना करती है और परिवहन के दौरान होने वाली किसी भी घटना की रिपोर्ट करने के लिए ज़िम्मेदार है","मेरा, चालक के रूप में, क्योंकि मैं ही वह हूँ जो शिपमेंट का निरीक्षण करता है, ट्रक पर प्लेकार्ड लगाता है और गाड़ी चलाते समय कागज़ात अपनी पहुँच में रखता है","किसी का विशेष रूप से नहीं, क्योंकि प्रमाणन पंक्ति केवल एक औपचारिकता है और असली कानूनी ज़िम्मेदारी पूरी तरह उस पर है जो माल प्राप्त करता है","शिपर (shipper) का, क्योंकि शिपर सामग्री को वर्गीकृत करता है, पैक करता है, चिह्नित करता है और शिपिंग पेपर तैयार करता है, फिर प्रमाणित करता है कि सामग्री का सही वर्णन किया गया है"],"explanation":"शिपर माल को वर्गीकृत, पैक, चिह्नित करता है और शिपिंग कागज़ तैयार करता है, फिर प्रमाणित करता है कि सामग्री सही ढंग से वर्णित है।"},"99":{"q":"मैं लोडिंग डॉक पर हूँ और संक्षारक (corrosive) तरल का एक ड्रम स्वीकार करने वाला हूँ। शिपिंग पेपर पर हस्ताक्षर करने से पहले मैं यह पुष्टि करना चाहता हूँ कि खतरनाक माल (HazMat) की प्रविष्टि सही ढंग से वर्णित है। उस प्रविष्टि को एक वैध खतरनाक माल विवरण मानने के लिए उस पंक्ति में वास्तव में कौन-सी जानकारी होनी चाहिए?","options":["उचित शिपिंग नाम, खतरा वर्ग (hazard class), और पहचान (UN/NA) संख्या, ठीक इसी क्रम में सूचीबद्ध","खतरा वर्ग के लेबल का रंग, प्लेकार्ड पर लिखा पाठ, और प्लेकार्ड पर दिखाई गई चार अंकों की संख्या","माल का खुदरा मूल्य, उसका कुल सकल वजन, और गंतव्य का ज़िप कोड","केवल HM कॉलम में एक 'X' का निशान, क्योंकि कानूनी रूप से खतरनाक प्रविष्टि की पहचान यही निशान करता है"],"explanation":"खतरनाक माल की प्रविष्टि में उचित शिपिंग नाम, खतरा श्रेणी और पहचान (UN/NA) संख्या इसी सटीक क्रम में होनी चाहिए।"},"100":{"q":"मैं प्लेकार्ड लगे संक्षारक (corrosive) माल को ढो रहा हूँ और शौचालय का उपयोग करने के लिए एक विश्राम क्षेत्र में रुकता हूँ। मैं केबिन से बाहर निकलकर कुछ मिनटों के लिए अपने ट्रक से दूर चला जाऊँगा। हैज़मैट नियमों के अनुसार, जब मैं वाहन से बाहर रहूँ तो मुझे अपने शिपिंग कागज़ात कहाँ छोड़ने चाहिए?","options":["ग्लव बॉक्स के अंदर मुड़े हुए, कुंडी बंद करके ताकि वे नज़र से ओझल रहें","चालक की सीट पर या चालक के दरवाज़े की पाउच में","जिस माल का वे वर्णन करते हैं, उसी के साथ ट्रेलर में ताला लगाकर","यात्री की ओर के सन वाइज़र के पीछे दबाकर"],"explanation":"ट्रक से बाहर होने पर खतरनाक माल के शिपिंग कागज़ चालक की सीट पर या चालक के दरवाज़े की जेब में छोड़ें ताकि बचावकर्मी उन्हें जल्दी पा सकें।"},"101":{"q":"मैं प्लेकार्ड लगे भार के साथ एक वजन स्टेशन पर हूँ, और निरीक्षक मुझसे कहता है कि केवल शिपिंग कागजात से ही बताऊँ कि मैं कुल कितनी खतरनाक सामग्री ढो रहा हूँ। उचित शिपिंग नाम, खतरा वर्ग और पहचान संख्या के अलावा, उस प्रविष्टि के लिए मेरे शिपिंग कागजात वास्तव में कौन-सा मान दिखाएँगे?","options":["मेरे ट्रक के सभी एक्सल का संयुक्त वजन","भार के लिए अनुशंसित ठंडे टायर का दबाव","ढोई जा रही खतरनाक सामग्री की कुल मात्रा","यात्रा शुरू होने के बाद से दर्ज इंजन के घंटे"],"explanation":"शिपिंग पेपर्स प्रत्येक प्रविष्टि के लिए खतरनाक सामग्री की कुल मात्रा दर्शाते हैं, इसलिए वाहन में मौजूद मात्रा सीधे उसी आँकड़े से ली जाती है।"},"102":{"q":"मैंने अपने प्लेकार्ड लगे टैंकर को लोडिंग डॉक से पीछे लगा दिया है और शिपर की टीम ट्रेलर में उत्पाद पंप करना शुरू करने के लिए तैयार है। लोडिंग शुरू करने की अनुमति देने से पहले, वाहन को अपने आप हिलने से रोकने के लिए मेरे लिए सबसे महत्वपूर्ण कार्य कौन सा है?","options":["इंजन को तेज़ रफ्तार पर चालू छोड़ दूँ ताकि पूरे समय पूरा हवा का दबाव उपलब्ध रहे","आगे और पीछे के प्लेकार्ड हटा दूँ ताकि डॉक टीम भरने वाले वाल्वों तक आसानी से पहुँच सके","पहले ट्रेलर के निकासी और वेंट वाल्व खोल दूँ ताकि स्थानांतरण के दौरान दबाव बराबर हो जाए","पार्किंग ब्रेक लगाऊँ और पहियों के सामने चॉक रखूँ ताकि लोडिंग के दौरान रिग अपनी जगह पर टिका रहे"],"explanation":"खतरनाक माल लादने या उतारने से पहले पार्किंग ब्रेक लगाएँ और पहियों के नीचे चॉक रखें ताकि वाहन लुढ़क न सके।"},"103":{"q":"मैं एक टर्मिनल पर अपने प्लॅकार्ड लगे ट्रेलर पर क्लास 3 ज्वलनशील तरल के ड्रम लोड कर रहा हूँ। एक सहकर्मी जलती हुई सिगरेट लेकर आता है और पूछता है कि क्या लोडिंग में मदद करते समय वह अपनी सिगरेट खत्म कर सकता है। कौन सा जवाब सही है?","options":["नहीं — ज्वलनशील पदार्थों की लोडिंग के पास धूम्रपान की अनुमति नहीं है, और उसे जलती सिगरेट को कार्य से काफी दूर रखना चाहिए","हाँ — जब तक वह खुले ट्रेलर दरवाजों से कम से कम 5 फीट पीछे रहता है, धूम्रपान ठीक है","हाँ — नियम केवल फ्लेयर या फ्यूजी जैसी खुली लौ को सीमित करता है, सिगरेट को नहीं","हाँ — धूम्रपान की अनुमति है क्योंकि ड्रम लोड और प्लॅकार्ड होने तक सीलबंद रहते हैं"],"explanation":"ज्वलनशील पदार्थ लादने के पास धूम्रपान वर्जित है, इसलिए जलती सिगरेट को कार्य से अच्छी तरह दूर रखना चाहिए।"},"104":{"q":"मैं एक डिपो पर डिवीज़न 1.1 विस्फोटकों के डिब्बे हाथ से अपने ट्रेलर के फर्श पर लाद रहा हूँ। कार्गो क्षेत्र तैयार करते समय और हर डिब्बे को हिलाते समय, कौन सी प्रथा भार को सबसे सुरक्षित रखती है और खतरनाक माल संभालने के नियमों का पालन करती है?","options":["डिब्बों को नंगे स्टील फर्श पर घसीटना और एक नुकीले धातु कार्गो हुक से उन्हें कसकर खींचना","कार्गो स्थान में चिंगारी न पैदा करने वाला फर्श का अस्तर बिछाना और हर डिब्बे को धीरे से रखना, हर पेटी को सावधानी से संभालना","किसी भी फर्श कवरिंग को छोड़ देना और डिब्बों को जल्दी से जगह पर फेंकना ताकि दरवाज़े जल्दी सील किए जा सकें","ट्रेलर बंद करने से पहले लदे हुए डिब्बों को कसकर दबाने के लिए फोर्कलिफ्ट को सीधे उनके ऊपर से चलाना"],"explanation":"डिवीजन 1.1 विस्फोटकों के लिए चिंगारी-रहित फर्श लाइनिंग और हर पेटी की सावधानीपूर्वक हैंडलिंग जरूरी है ताकि घर्षण, चिंगारी या टक्कर से माल में विस्फोट न हो।"},"105":{"q":"मैं खतरनाक सामग्री ढुलाई के लिए अपने बंद वैन में संक्षारक सामग्री के डिब्बे लोड कर रहा हूँ। पैकेज सही तरीके से चिह्नित हैं और मेरे प्लेकार्ड लगे हुए हैं। कार्गो क्षेत्र में माल को व्यवस्थित करते समय, इनमें से कौन सा विकल्प सबसे अच्छा बताता है कि मुझे कंटेनरों को स्वयं कैसे संभालना चाहिए?","options":["उन्हें आगे की ओर ढीला-ढाला ढेर कर दें ताकि पहले कुछ पड़ावों के दौरान वे अपनी जगह बैठ जाएँ","उन्हें दरवाज़ों के पास बिना बाँधे रखें ताकि आपातकालीन कर्मी उन तक जल्दी पहुँच सकें","उन्हें इस तरह रोकें, टेक लगाएँ और सुरक्षित करें कि ट्रक चलते समय वे खिसक, फिसल या गिर न सकें","उन्हें ट्रेलर की ऊपरी पटरियों से लटका दें ताकि वे पूरी तरह फर्श से अलग रहें"],"explanation":"खतरनाक सामग्री के कंटेनरों को इस तरह ब्लॉक, ब्रेस और सुरक्षित किया जाना चाहिए कि परिवहन के दौरान वे हिल, खिसक या गिर न सकें।"},"106":{"q":"मैं एक बल्क टर्मिनल पर अपने टैंकर में गैसोलीन भर रहा हूँ, जो एक क्लास 3 ज्वलनशील तरल है। ट्रांसफर लाइन टर्मिनल के अपने पंप से जुड़ी है, इसलिए उत्पाद को स्थानांतरित करने के लिए मुझे अपने ट्रक के इंजन की ज़रूरत नहीं होगी। जैसे ही होज़ जुड़ते हैं और उत्पाद बहना शुरू होता है, मुझे अपने इंजन के साथ क्या करना चाहिए?","options":["इसे लो गियर में चालू (आइडल) रखूँ ताकि लोडिंग खत्म होते ही मैं आगे बढ़ सकूँ","इसे तेज़ आइडल पर चालू रखूँ ताकि हवा का दबाव बना रहे और अल्टरनेटर बैटरियों को चार्ज करता रहे","इसे तभी चालू रखूँ जब टर्मिनल स्टाफ मुझे बताए कि क्षेत्र अच्छी तरह हवादार है","इंजन बंद कर दूँ, क्योंकि इस ट्रांसफर के दौरान मुझे उत्पाद पंप चलाने के लिए इसकी ज़रूरत नहीं है"],"explanation":"ज्वलनशील तरल पदार्थ लादते या उतारते समय इंजन बंद होना चाहिए, जब तक उत्पाद पंप चलाने के लिए उसकी जरूरत न हो।"},"107":{"q":"मैं एक टर्मिनल पर हूँ और अपने कार्गो टैंक से एक भंडारण टैंक में क्लास 3 ज्वलनशील तरल स्थानांतरित करने वाला हूँ। कोई भी वाल्व खोलने या प्रवाह शुरू करने से पहले, मैं ट्रक और भंडारण टैंक के बीच एक बॉन्डिंग तार जोड़ता हूँ और एक ग्राउंड लगाता हूँ। ज्वलनशील तरल को संभालने से पहले मेरे ऐसा करने का प्रमुख कारण क्या है?","options":["ट्रक और टैंक के बीच विद्युत आवेश को बराबर करने के लिए ताकि कोई स्थैतिक चिंगारी न बने और वाष्प को न जला दे","एक बैकअप विद्युत मार्ग बनाने के लिए जो इंजन बंद होने पर ट्रक की लाइटों और गेजों को चालू रखे","प्रवाह के दौरान तरल का तापमान कम करने के लिए ताकि ईंधन फैलकर प्राप्त करने वाले टैंक से न उफने","प्रवाह की गति धीमी करने के लिए ताकि स्थानांतरण के दौरान वाष्पीकरण और छलकाव से कम उत्पाद नष्ट हो"],"explanation":"बॉन्डिंग और ग्राउंडिंग ट्रक और टैंक के बीच विद्युत आवेश को बराबर कर देते हैं ताकि स्थैतिक चिंगारी न बने और ज्वलनशील वाष्प न जल सके।"},"108":{"q":"मैं एक प्लेकार्ड लगे संक्षारक (corrosive) माल को 380 मील के सफर पर ले जा रहा हूँ, जिसमें दो निर्धारित विश्राम पड़ाव हैं। निकलने से पहले मैंने यार्ड में ट्रेलर के चारों ओर घूमकर अपने सभी बंधन (tie-downs) और सहारों (bracing) की जाँच की, और सब कुछ सुरक्षित था। खतरनाक माल (HazMat) के नियमों का पालन करने के लिए, इस सफर के बाकी हिस्से में माल और उसके बंधन उपकरणों के निरीक्षण के बारे में नियम मुझसे क्या करने की माँग करता है?","options":["एक बार यार्ड में यात्रा-पूर्व निरीक्षण माल और बंधनों के सुरक्षित होने की पुष्टि कर दे, तो और कुछ करने की ज़रूरत नहीं, क्योंकि रास्ते में दोबारा जाँच केवल ओवरसाइज़ या ओवरवेट माल के लिए अनिवार्य है।","माल और उसके बंधन उपकरणों का निरीक्षण केवल शुरुआत में एक बार नहीं, बल्कि यात्रा से पहले और यात्रा के दौरान कुछ स्थानों पर भी जारी रखना।","बंधन उपकरणों का दोबारा निरीक्षण केवल अंतिम डिलीवरी स्थान पर करना, क्योंकि माल के दावों के लिए कानूनी रूप से उतराई से पहले की गई जाँच ही मायने रखती है।","माल और बंधन का पूरा निरीक्षण एक सख़्त वार्षिक कार्यक्रम के अनुसार दोहराना जिसे वाहक दस्तावेज़ में दर्ज करता है, किसी एक सफर की यात्रा-पूर्व जाँच से अलग।"],"explanation":"माल और उसके सुरक्षा उपकरणों का निरीक्षण यात्रा से पहले और यात्रा के दौरान भी करना चाहिए, केवल शुरुआत में एक बार नहीं।"},"109":{"q":"मैं डिवीजन 1.1 विस्फोटकों का प्लेकार्ड लगा हुआ माल ढो रहा हूँ और एक पट्टा ढीला हो गया है, इसलिए मुझे ट्रेलर में एक क्रेट को फिर से व्यवस्थित करना है। विस्फोटकों के पास इस काम के लिए मैं जो औज़ार इस्तेमाल करता हूँ, उनके बारे में निम्नलिखित में से कौन-सा नियम सबसे महत्वपूर्ण है?","options":["औज़ार भारी स्टील के होने चाहिए ताकि वे क्रेट को बिना फिसले मज़बूती से पकड़ें","औज़ार केबिन में छोड़ दिए जाने चाहिए और किसी भी संपर्क से बचने के लिए क्रेट को हाथ से हिलाना चाहिए","औज़ार ऐसे होने चाहिए जो चिंगारी न पैदा कर सकें और न ही विस्फोटक पैकेजों को नुकसान पहुँचा सकें","औज़ार की धार तेज़ होनी चाहिए ताकि मैं ढीले पट्टे को जल्दी से काटकर फिर से बाँध सकूँ"],"explanation":"विस्फोटकों के पास उपयोग किए जाने वाले औजार चिंगारी-रहित और पैकेजों को नुकसान न पहुँचाने वाले होने चाहिए, क्योंकि चिंगारी या टक्कर से विस्फोट हो सकता है।"},"110":{"q":"मैं एक डिलीवरी डॉक पर हूं और ड्रमों में क्लास 3 ज्वलनशील तरल ले जा रहे एक प्लेकार्ड वाले ट्रेलर को उतार रहा हूं। एक फोर्कलिफ्ट चालक अपनी प्रोपेन-चालित लिफ्ट को खुले ट्रेलर दरवाजों के ठीक बगल में चालू रखना चाहता है, पास का एक मजदूर सिगरेट जलाने वाला है, और डॉक पर्यवेक्षक मुझसे पूछता है कि ऑपरेशन के दौरान खुली लपटें और चालू इंजन कहां होने चाहिए। मुझे क्या सही निर्देश देना चाहिए?","options":["इग्निशन स्रोतों को ट्रेलर के दरवाजों के ठीक पास रखें ताकि फोर्कलिफ्ट कुशलता से काम करे और उतराई जल्दी पूरी हो","धूम्रपान और इंजन को चालू रखने की अनुमति दें, बशर्ते वे सड़क के चलने वाले हिस्से से कम से कम 5 फीट दूर रहें","लोडिंग को तेज करने के लिए चालू फोर्कलिफ्ट को ट्रेलर के अंदर रखें, क्योंकि ड्रम सीलबंद हैं और नहीं जलेंगे","खुली लपटों और चालू इंजनों सहित सभी इग्निशन स्रोतों को उतराई क्षेत्र से अच्छी तरह दूर रखें"],"explanation":"ज्वलनशील पदार्थ लादते या उतारते समय खुली लपटों और चालू इंजनों सहित सभी प्रज्वलन स्रोतों को क्षेत्र से अच्छी तरह दूर रखें।"},"111":{"q":"मैं एक ग्राहक के लोडिंग डॉक पर प्लेकार्ड लगने वाला खतरनाक माल (HazMat) लोड कर रहा हूँ। हस्ताक्षर करने से पहले पैकेजों का निरीक्षण करते समय, कौन-सी स्थिति बताती है कि मैं इस लोड को कानूनी रूप से स्वीकार और परिवहन कर सकता हूँ?","options":["हर पैकेज ठीक से लेबल किया गया है और रिसाव का कोई संकेत नहीं दिखाता","हर पैकेज खोला गया है ताकि मैं स्वयं सामग्री की पुष्टि कर सकूँ","पैकेजों को चमकीले रंग में रंगा गया है ताकि अन्य चालक उन्हें देख सकें","पैकेजों को कैब के ऊपर ऊँचा रखा गया है जहाँ मैं उन पर नज़र रख सकूँ"],"explanation":"खतरनाक सामग्री का शिपमेंट केवल तभी स्वीकार किया जा सकता है जब हर पैकेज पर सही लेबल लगा हो और रिसाव का कोई संकेत न हो।"},"112":{"q":"मैं एक वितरण डॉक पर मिश्रित ट्रेलर लोड कर रहा हूँ। मेरे शिपिंग कागजात में कक्षा 6.1 के जहरीले (विषाक्त) पदार्थ के कई ड्रम सूचीबद्ध हैं, जिन्हें मैं देश भर में ले जाऊँगा। डॉक पर्यवेक्षक दूसरी यात्रा बचाने के लिए ट्रेलर की बची हुई जगह भरना चाहता है। उसके द्वारा दी जा रही लदानों में से, मुझे अपने जहर के ड्रमों के साथ कौन सी लोड करने की मनाही है?","options":["उसी क्षेत्र की ओर जा रहे बोरीबंद कृषि उर्वरक के पैलेट","किराना गोदाम के लिए पैक किए गए मानव खाद्य पदार्थ और पशु चारे के क्रेट","उसी कक्षा 6.1 जहरीले पदार्थ के अतिरिक्त सीलबंद ड्रम","खाली, बिना लेबल वाले प्लास्टिक शिपिंग कंटेनरों के डिब्बे"],"explanation":"क्लास 6.1 के ज़हरीले (विषैले) पदार्थों को कभी भी मनुष्यों या जानवरों के भोजन या चारे के साथ एक ही वाहन में नहीं लादना या ढोना चाहिए।"},"113":{"q":"मैं अपने ट्रेलर पर संक्षारक (corrosive) और ऑक्सीकारक (oxidizer) पदार्थों का मिश्रित खतरनाक माल लाद रहा हूँ, और मुझे यह पुष्टि करनी है कि क्या इन दोनों पदार्थों को एक-दूसरे के बगल में ले जाया जा सकता है या इन्हें अलग रखना ज़रूरी है। कौन-सा संदर्भ मुझे बताता है कि किन खतरनाक पदार्थों को एक ही वाहन में एक साथ नहीं लादा जा सकता?","options":["शिपिंग पेपर का HM कॉलम, क्योंकि 'X' के निशान बताते हैं कि किन भारों को अलग रखना है","आपातकालीन प्रतिक्रिया गाइडबुक (ERG), क्योंकि यह बताती है कि कौन-से पदार्थ एक-दूसरे के साथ अभिक्रिया करते हैं","पृथक्करण (सेग्रिगेशन) तालिका, क्योंकि यह निर्दिष्ट करती है कि किन पदार्थों को एक साथ नहीं लादा जा सकता","प्लेकार्ड नियमों की तालिका 1, क्योंकि यह उन पदार्थों को सूचीबद्ध करती है जिनके लिए किसी भी मात्रा में प्लेकार्ड आवश्यक है"],"explanation":"पृथक्करण (सेग्रीगेशन) तालिका चालक को बताती है कि कौन सी खतरनाक सामग्रियों को एक साथ लादना और ढोना मना है।"},"114":{"q":"मैं एक ट्रेलर लोड कर रहा हूँ जिसमें पहले से ही क्लास 5 ऑक्सीकारक के कई ड्रम रखे हैं, और डॉक पर्यवेक्षक मुझे उसी जगह में फिट करने के लिए चार और पैलेट देता है। लोड को सुरक्षित रखने के लिए, इनमें से किस वस्तु को मुझे ऑक्सीकारक ड्रमों के ठीक बगल में नहीं रखना चाहिए?","options":["सीलबंद, पानी से भरे जगों का एक पैलेट","खाली प्लास्टिक ड्रमों का एक पैलेट","बोरियों में भरी रेत का एक पैलेट","ज्वलनशील विलायक के डिब्बों का एक पैलेट"],"explanation":"क्लास 5 के ऑक्सीडाइज़र ऑक्सीजन छोड़ते हैं और आग को तेज़ या शुरू कर सकते हैं, इसलिए उन्हें ज्वलनशील सामग्रियों से दूर रखना चाहिए।"},"115":{"q":"अपने प्लेकार्ड लगे ट्रेलर को लोड करते समय, शिपर मुझे दो HazMat वस्तुएं देता है जिन्हें पृथक्करण तालिका के अनुसार मुझे अलग रखना ज़रूरी है, और पूछता है कि उन्हें साथ-साथ क्यों नहीं ले जाया जा सकता। पुस्तिका के अनुसार, इन असंगत पदार्थों को अलग रखने का सबसे अच्छा कारण क्या है?","options":["एक साथ रखे जाने पर वे आपस में प्रतिक्रिया कर सकते हैं, आग पकड़ सकते हैं, या खतरनाक गैस छोड़ सकते हैं","उन्हें एक साथ रखने से भार 1,001 पाउंड की प्लेकार्ड सीमा से ऊपर चला जाएगा","उन्हें मिलाने से दस्तावेज़ों पर उचित शिपिंग नाम और खतरा वर्ग धुंधला हो जाएगा","उन्हें एक साथ ढेर करने से पीछे रखे परावर्तक त्रिकोण अवरुद्ध हो जाएंगे"],"explanation":"असंगत खतरनाक सामग्रियों को अलग रखा जाता है क्योंकि मिलने पर वे प्रतिक्रिया कर सकती हैं, आग पकड़ सकती हैं या खतरनाक गैस छोड़ सकती हैं।"},"116":{"q":"मैं एक मिश्रित खतरनाक माल का शिपमेंट लोड कर रहा हूँ और मेरे कागजात में एक साइनाइड यौगिक का ड्रम और संक्षारक अम्ल (क्लास 8) के कई कंटेनर सूचीबद्ध हैं, जो एक ही ग्राहक के पास जा रहे हैं। कौन सा लोडिंग निर्णय मुझे नियमों के अनुरूप और सुरक्षित रखता है?","options":["उन्हें एक ही कम्पार्टमेंट में अगल-बगल लोड करें ताकि वे अपने मिलान वाले शिपिंग कागजात के साथ रहें","साइनाइड और अम्ल को अलग रखें और उन्हें कभी भी एक ही लोड में एक साथ न लादें","उन्हें एक साथ तभी लादें जब मैं दोनों को एक ही सीलबंद बाहरी कंटेनर में सुरक्षित कर दूँ","उन्हें एक साथ लादें बशर्ते कि मैं रेलवे पटरियों को बिना गियर बदले पार करूँ"],"explanation":"साइनाइड और अम्ल को कभी एक साथ नहीं लादना चाहिए क्योंकि संपर्क से जानलेवा हाइड्रोजन साइनाइड गैस निकलती है।"},"117":{"q":"आप प्लेकार्ड लगे संक्षारक (corrosive) माल को ले जा रहे हैं, तभी आपको तेज़ गंध आती है और अपने ट्रेलर में एक ड्रम के नीचे फैलता हुआ गीला धब्बा दिखाई देता है। आप किनारे पर गाड़ी रोककर पुष्टि करते हैं कि पैकेज से रिसाव हो रहा है। कुछ और करने से पहले, आपकी पहली प्राथमिकता क्या है?","options":["रिसाव वाले ड्रम को खोलकर अंदर के रसायन की पहचान करना और फिर सही शिपिंग नाम जानने के लिए आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) देखना","गिरे हुए पदार्थ को और फैलने से पहले अपने भंडार के पानी से पतला करके निकटतम तूफ़ानी नाली की ओर बहा देना","वाहन को रोकना, रिसाव के आसपास के क्षेत्र को सुरक्षित करना, और दर्शकों तथा अन्य लोगों को घटनास्थल से दूर रखना","धीरे-धीरे डिलीवरी स्थल तक जाते रहना, जहाँ प्रशिक्षित कर्मचारी और उचित उपकरण रिसाव वाले ड्रम को रोक और उतार सकें"],"explanation":"किसी भी खतरनाक सामग्री के रिसाव पर पहला कदम है रुकना, क्षेत्र को सुरक्षित करना और लोगों को घटनास्थल से दूर रखना।"},"118":{"q":"आप प्लेकार्ड लगे संक्षारक (corrosive) माल को ले जा रहे हैं, तभी एक हवादार दोपहर में सड़क किनारे रुकने पर आपका एक ड्रम रिसने और वाष्प छोड़ने लगता है। दूसरों को सचेत करने और लोगों को दूर रखने के बाद, आपातकालीन कर्मियों और CHEMTREC के आने का इंतज़ार करते समय आपको कहाँ खड़ा होना चाहिए?","options":["ट्रेलर की हवा-विमुख (downwind) दिशा में, ताकि आप रिसते ड्रम को पास से देख सकें","माल के दरवाज़ों के ठीक पास, ताकि शिपिंग कागज़ात कर्मियों को तुरंत सौंप सकें","ढलान पर रिसाव से नीचे, ताकि बहता हुआ तरल आपसे दूर बह जाए","वाहन की हवा-अभिमुख (upwind) दिशा में और रिसते माल से सुरक्षित दूरी पर"],"explanation":"खतरनाक सामग्री की आपात स्थिति में हवा की ऊपरी दिशा (अपविंड) में और सुरक्षित दूरी पर रहें ताकि वाष्प आपकी ओर नहीं बल्कि दूर बहें।"},"119":{"q":"मैं क्षारक (corrosives) का एक प्लेकार्ड लोड ढो रहा हूँ, तभी एक ड्रम से रिसाव शुरू हो जाता है और धुआँ सड़क के किनारे फैलने लगता है। मैं पहले ही दूसरों को चेतावनी दे चुका हूँ, लोगों को दूर रख चुका हूँ और आस-पास धूम्रपान रुकवा चुका हूँ। अब मुझे इस खास रसायन को संभालने के लिए विशेषज्ञ तकनीकी मार्गदर्शन चाहिए। इस विशेषज्ञ सहायता के लिए मुझे किससे संपर्क करना चाहिए?","options":["CHEMTREC या स्थानीय आपातकालीन रिस्पॉन्डरों से, जो रसायन को संभालने का विशेषज्ञ मार्गदर्शन दे सकते हैं","अपने कैरियर के डिस्पैच कार्यालय से, क्योंकि घटना की रिपोर्ट करना कैरियर का ही काम है","उस शिपर से जिसने ड्रमों को वर्गीकृत और पैक किया और शिपिंग कागज़ात तैयार किए","फ़ोन पर किसी से नहीं — आपातकालीन प्रतिक्रिया गाइडबुक (ERG) अकेले ही हर ज़रूरी कदम को कवर करती है"],"explanation":"रिसते हुए रसायन को संभालने के लिए विशेषज्ञ और तत्काल मार्गदर्शन हेतु CHEMTREC या स्थानीय आपातकालीन सेवाओं से संपर्क करें।"},"120":{"q":"आप टेक्सास के एक ग्रामीण राजमार्ग पर प्लेकार्ड लगे ज्वलनशील तरल का माल ढो रहे हैं, तभी आप अपने ट्रेलर के नीचे से लपटें निकलती देखते हैं। आप किनारे पर गाड़ी रोकते हैं और आग साफ तौर पर फैल रही है। आपके पास छोटी आग के लिए रेटेड एक अग्निशामक यंत्र है, लेकिन लपटें पहले ही माल वाले हिस्से तक पहुँच रही हैं। आपको सबसे पहले क्या करना चाहिए?","options":["आग के और बड़ा होने से पहले माल की जाँच करने और गर्मी व धुएँ को बाहर निकलने देने के लिए ट्रेलर के दरवाज़े खोल दें","वाहन से सुरक्षित दूरी पर हट जाएँ, फिर आपातकालीन सेवाओं को बुलाएँ और CHEMTREC को सूचित करें","माल वाले हिस्से की लपटों पर पूरा अग्निशामक यंत्र खाली कर दें और आग फिर भड़कने की स्थिति में पास ही रहें","कैब के पास रहें और इंजन चालू रखें ताकि आप ट्रक को फैलती लपटों से दूर ले जा सकें"],"explanation":"खतरनाक माल की आग से कभी अकेले न लड़ें; वाहन से सुरक्षित दूरी पर जाएं, फिर आपातकालीन सेवाओं को बुलाएं और CHEMTREC को सूचित करें।"},"121":{"q":"मैं कोरोसिव (संक्षारक) पदार्थों का प्लेकार्ड लोड ढो रहा हूँ, जब मुझे पता चलता है कि एक ड्रम से तरल टपक रहा है और विश्राम क्षेत्र में मेरे ट्रेलर के नीचे जमा हो रहा है। मैंने पहले ही लोगों को पीछे हटा दिया है, धूम्रपान रोक दिया है और आपातकालीन कर्मचारियों को सूचित कर दिया है। रिसाव वाले वाहन को हटाने के संबंध में मुझे कौन सा एक काम करना चाहिए?","options":["वाहन को धीरे-धीरे अगले ट्रक स्टॉप तक ले जाना ताकि मैकेनिक रिसाव वाले ड्रम को दोबारा सील कर सके","वाहन को केवल इतना ही खिसकाना कि विश्राम क्षेत्र का निकास रैंप खाली हो जाए","वाहन को वहीं छोड़ देना, जब तक कोई अधिकारी जीवन की रक्षा के लिए इसे हटाने का आदेश न दे","रिसाव को दूसरे खड़े ट्रकों से दूर रखने के लिए वाहन को जल्दी से लॉट से बाहर निकालना"],"explanation":"रिसाव वाले हैज़मैट वाहन को अपने निर्णय से कभी न हिलाएं; जब तक कोई अधिकारी जीवन की रक्षा के लिए उसे हटाने का निर्देश न दे, उसे वहीं छोड़ दें।"},"122":{"q":"मैं प्लेकार्ड लगे संक्षारक (corrosive) माल को ले जा रहा हूँ, तभी मुझे दिखता है कि एक ड्रम से उत्पाद रिस रहा है और जहाँ मैंने गाड़ी रोकी है उस किनारे पर जमा हो रहा है। मेरे पास आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) और एक फोन है। आपातकालीन दल के आने तक मेरी पहली प्राथमिकता क्या होनी चाहिए?","options":["रिसाव के पोखर पर ढीली मिट्टी और बजरी डालना ताकि संक्षारक सोख लिया जाए और फैलना रुक जाए","रिसाव पर पानी डालकर उसे पतला करना और बहाकर नाली में तथा दूर धकेल देना","पोखर के चारों ओर परावर्तक त्रिकोण लगाना और रिसाव को चिह्नित करने के लिए हवा की ओर एक भड़की मशाल रखना","आसपास के लोगों को क्षेत्र से दूर रखना और रिसाव को और फैलने से रोकने के लिए कार्रवाई करना"],"explanation":"हैज़मैट घटना में, प्रशिक्षित आपातकालीन कर्मियों के आने तक लोगों को दूर रखें और रिसाव को फैलने से रोकें; सफाई स्वयं करने का प्रयास न करें।"},"123":{"q":"मैं प्लेकार्ड लगा हुआ खतरनाक माल (HazMat) ले जा रहा हूँ, तभी एक विश्राम स्थल पर मेरे ट्रेलर के नीचे आग लग जाती है। कार्रवाई करने या आने वाली अग्निशमन टीम से बात करने से पहले, मेरे शिपिंग कागजात और आपातकालीन प्रतिक्रिया गाइडबुक (ERG) का सही उपयोग क्या है?","options":["यह ठीक-ठीक पहचानना कि मैं कौन-सी सामग्री ले जा रहा हूँ और वह कौन-से विशिष्ट खतरे पैदा करती है, ताकि बचावकर्मी सुरक्षित रूप से प्रतिक्रिया दे सकें","वाहक को यह साबित करना कि यात्रा से पहले माल सही तरीके से लादा और प्रलेखित किया गया था","निकटतम स्वीकृत HazMat पार्किंग मार्ग ढूँढना ताकि मैं जलते ट्रेलर को जगह से हटा सकूँ","यह पुष्टि करना कि माल का वजन 1,001 पाउंड या उससे अधिक है और इसलिए कानूनी रूप से प्लेकार्ड आवश्यक हैं"],"explanation":"शिपिंग पेपर और ERG सटीक सामग्री और उसके विशिष्ट खतरों की पहचान करते हैं ताकि आप और आपातकालीन कर्मी सुरक्षित रूप से प्रतिक्रिया दे सकें।"},"124":{"q":"खतरनाक माल के प्लेकार्ड लगे आपके ट्रेलर पर एक ड्रम फट गया है और उसमें से सामग्री किनारे (शोल्डर) पर रिस रही है। आप पहले ही किनारे रुक चुके हैं, अपने परावर्तक त्रिकोण लगा चुके हैं, और आपातकालीन सेवाओं की प्रतीक्षा करते हुए राहगीरों को दूर रख रहे हैं। एक राहगीर सिगरेट जलाता है, और मदद के लिए रुका एक अन्य चालक पूछता है कि क्या जल्दी से एक सिगरेट पीना ठीक है, क्योंकि वह आपके ट्रक से काफी पीछे खड़ा है। इस घटनास्थल पर धूम्रपान के संबंध में सही कार्रवाई क्या है?","options":["जल्दी से सिगरेट पीने की अनुमति दें, बशर्ते सभी लोग रिसते ट्रेलर से कम से कम 25 फुट पीछे रहें","धूम्रपान पूरी तरह प्रतिबंधित करें और पास के सभी लोगों से तुरंत अपनी सिगरेट बुझाने को कहें","केवल मदद के लिए रुके चालक को धूम्रपान की अनुमति दें, क्योंकि मदद करने वाले इस नियम से छूट प्राप्त हैं","केवल हवा के ऊपरी ओर (अपविंड) धूम्रपान की अनुमति दें, उस स्थान से दूर जहाँ सामग्री किनारे पर रिस रही है"],"explanation":"हैज़मैट घटना में धूम्रपान की कभी अनुमति नहीं है क्योंकि रिसाव वाला उत्पाद या उसके वाष्प ज्वलनशील हो सकते हैं, इसलिए किसी भी लौ या चिंगारी को तुरंत बुझाना चाहिए।"},"125":{"q":"मैं प्लेकार्ड (चेतावनी पट्ट) लगे संक्षारक (corrosive) पदार्थों का भार ढो रहा हूँ, तभी एक कंटेनर फट जाता है और उत्पाद एक ग्रामीण राजमार्ग के किनारे रिसने लगता है। दूसरों को सचेत करने, लोगों को रिसाव से दूर रखने और आसपास किसी को धूम्रपान न करने देने के बाद, कानून के अनुसार इस घटना की सूचना देना आवश्यक है। नियमों के अनुसार इस घटना की सूचना किसे दी जानी चाहिए?","options":["केवल शिपर (माल भेजने वाले) को, क्योंकि शिपर ने ही पदार्थ का वर्गीकरण किया, पैक किया और शिपिंग दस्तावेज़ तैयार किए, इसलिए कंटेनर के अंदर की सामग्री के लिए वही जिम्मेदार पक्ष है","किसी को भी नहीं, बशर्ते मैं स्वयं रिसाव को रोक लूँ, क्षेत्र को ठंडा कर लूँ और डिलीवरी स्थल की ओर आगे बढ़ने से पहले फोटो खींचकर नुकसान का दस्तावेज़ बना लूँ","उचित अधिकारियों को, जैसे आपातकालीन प्रतिक्रियाकर्ताओं या CHEMTREC को, जबकि वाहक (carrier) संबंधित एजेंसियों को आवश्यक घटना रिपोर्ट प्रस्तुत करता है","केवल निकटतम स्थानीय टीवी या रेडियो स्टेशन को, ताकि क्षेत्र के अन्य चालक सचेत हो जाएँ और राजमार्ग के प्रभावित हिस्से से बचें"],"explanation":"उचित अधिकारियों जैसे आपातकालीन कर्मियों या CHEMTREC को सूचित करें, जबकि वाहक संबंधित एजेंसियों को आवश्यक घटना रिपोर्ट दाखिल करता है।"},"126":{"q":"आप शहर के आर-पार ज्वलनशील तरल का प्लेकार्ड लगा हुआ माल ले जा रहे हैं और आपका GPS एक तेज़ रास्ता सुझाता है जो एक लंबी हाईवे सुरंग और घनी आबादी वाले शहर के मध्य भाग से होकर गुज़रता है और 20 मिनट बचाता है। हैज़मैट मार्ग-योजना के सुरक्षित नियमों का सबसे अच्छा पालन कौन-सा विकल्प करता है?","options":["सुरंग और शहर के मध्य वाला रास्ता लें, क्योंकि यह सबसे छोटा है और सबसे ज़्यादा समय बचाता है","रास्ते पर बने रहें लेकिन माल की ओर ध्यान न खींचने के लिए अनिवार्य वज़न (weigh) स्टेशन छोड़ दें","रास्ता लें लेकिन प्लेकार्ड दोबारा जाँचने के लिए शहर के मध्य भाग में पार्क करने की योजना बनाएँ","उस रास्ते को अस्वीकार करें और ऐसा मार्ग चुनें जो सुरंग और घनी आबादी वाले शहर के मध्य भाग से बचाता हो"],"explanation":"हैज़मैट का मार्ग बनाते समय सुरंगों और घनी आबादी वाले क्षेत्रों से बचें, क्योंकि वहां रिसाव या आग जनता के लिए खतरे को कई गुना बढ़ा देती है।"},"127":{"q":"मैं टेक्सास के एक ग्रामीण काउंटी से होकर, कई प्रकार के क्रॉसिंग वाले मार्ग पर, प्लेकार्ड लगे ज्वलनशील तरल पदार्थ का भार ले जा रहा हूं। DPS के खतरनाक माल (हैज़मैट) नियमों का पालन करने के लिए, आगे बढ़ने से पहले निम्नलिखित में से किसके सामने मुझे अपने वाहन को पूरी तरह रोकना अनिवार्य है?","options":["रेलवे ट्रैक क्रॉसिंग के सामने, जहां मुझे निकटतम रेल से 15 से 50 फीट पहले रुकना होगा","ग्रामीण चार-तरफा चौराहे पर चमकती पीली सावधानी संकेत के सामने","खुले ईंधन स्टेशन के सामने, अपने डीज़ल टैंक को भरने के लिए अंदर जाने से पहले","मार्ग में आने वाले हर निजी ड्राइववे और खेत के प्रवेश द्वार के सामने"],"explanation":"प्लेकार्ड वाले वाहन को रेलवे क्रॉसिंग पर निकटतम पटरी से 15 से 50 फीट पहले पूरी तरह रुकना चाहिए और पार करते समय कभी गियर नहीं बदलना चाहिए।"},"128":{"q":"मैं टेक्सास में डिवीजन 1.2 विस्फोटकों का प्लेकार्ड लगा हुआ भार ले जा रहा हूँ और मुझे दोपहर के भोजन के लिए एक छोटा पड़ाव लेना है। मेरे साथ कोई दूसरा चालक नहीं है। DPS नियमों के अनुसार, इस भार के साथ मुझे क्या करना आवश्यक है?","options":["जब तक दरवाज़े सुरक्षित हैं, मैं अंदर खाना खाते समय ट्रक को रेस्तरां की पार्किंग में खड़ा और ताला लगा कर छोड़ सकता हूँ","मुझे विस्फोटक भार के साथ हर समय उपस्थित रहना होगा, इसलिए मैं अंदर खाना खाने जाने के लिए इसे बिना निगरानी के नहीं छोड़ सकता","मैं इसे छोटे पड़ावों के लिए बिना निगरानी के छोड़ सकता हूँ बशर्ते मैं किसी भी इमारत से 300 फीट से अधिक दूर खड़ा करूँ","मैं इसे बिना निगरानी के छोड़ सकता हूँ यदि जाने से पहले इंजन बंद कर दूँ और पार्किंग ब्रेक लगा दूँ"],"explanation":"डिवीजन 1.1, 1.2 और 1.3 विस्फोटकों को कभी बिना निगरानी के नहीं छोड़ना चाहिए; चालक या योग्य परिचारक को हर समय वाहन के साथ रहना चाहिए।"},"129":{"q":"मैं प्लेकार्ड (खतरा सूचक तख्ती) लगा हुआ ज्वलनशील तरल का माल ले जा रहा हूँ और रात भर रुकने के लिए मुझे रुकना है। आगे मुझे एक विश्राम क्षेत्र के पास सड़क किनारे जलती हुई आग दिखती है जिसे किसी ने जलता छोड़ दिया है। पार्क करने की जगह चुनने से पहले, हैंडबुक के अनुसार मेरे प्लेकार्ड वाले वाहन और उस खुली आग के बीच कम से कम कितनी दूरी रखनी ज़रूरी है?","options":["कम से कम 25 फीट, माल के पास धूम्रपान न करने के लिए आवश्यक उतनी ही दूरी","कम से कम 50 फीट, रेलवे पटरियों से पहले रुकने की अधिकतम दूरी के बराबर","वाहन और खुली आग के बीच कम से कम 300 फीट","जब तक इंजन बंद है, तब तक कोई निश्चित दूरी आवश्यक नहीं"],"explanation":"प्लेकार्ड वाले वाहन को खुली आग से कम से कम 300 फीट दूर पार्क करना चाहिए क्योंकि खुली लौ माल के लिए सीधा प्रज्वलन खतरा है।"},"130":{"q":"मैं एक अनजान इंटरस्टेट हाईवे पर प्लेकार्ड लगे खतरनाक माल की खेप ले जा रहा हूँ, तभी मेरा जीपीएस मुझे एक ऐसे रास्ते पर मोड़ देता है जिस पर मैंने कभी गाड़ी नहीं चलाई। इस हिस्से में मैं एक व्यस्त ट्रक स्टॉप, एक खुले वजन-जाँच केंद्र (वेट स्टेशन), और एक पहाड़ के बीच से काटे गए लंबे भूमिगत मार्ग से गुज़रूँगा। इनमें से किस जगह में अपने खतरनाक माल के साथ प्रवेश करने पर मुझ पर कानूनी रूप से रोक लगने की सबसे अधिक संभावना है, जिससे मुझे वैकल्पिक रास्ता खोजना पड़े?","options":["ट्रक स्टॉप, क्योंकि प्लेकार्ड लगे वाहन वहाँ पार्क नहीं कर सकते जहाँ लोग इकट्ठा होते हैं","खुला वजन-जाँच केंद्र, क्योंकि खतरनाक माल की खेपों को सभी निरीक्षण तराजुओं से बचकर निकलना चाहिए","यहाँ कुछ भी प्रतिबंधित नहीं है, क्योंकि चिह्नित इंटरस्टेट मार्ग हमेशा खतरनाक माल की अनुमति देता है","भूमिगत मार्ग, क्योंकि कुछ खतरनाक माल कुछ निश्चित सुरंगों में प्रतिबंधित होते हैं"],"explanation":"हैज़मैट मार्ग पर सुरंगों से बचें क्योंकि अधिकारी कुछ खतरनाक सामग्रियों को विशिष्ट सुरंगों में प्रवेश से पूरी तरह कानूनी रूप से रोक सकते हैं।"},"131":{"q":"मैं संक्षारक पदार्थों का प्लेकार्ड लगा हुआ भार शहर के आर-पार ले जा रहा हूँ, तभी मुझे अप्रत्याशित राजमार्ग निर्माण कार्य मिलता है जिसने दो लेन बंद कर दी हैं और मेरे निर्धारित हैज़मैट मार्ग पर मीलों तक यातायात जाम कर दिया है। एक डायवर्जन का चिह्न शहर के व्यावसायिक केंद्र से होकर जाने वाले छोटे रास्ते की ओर इशारा करता है, और मेरा जीपीएस एक नीचे वाले पुल से होकर और भी तेज़ शॉर्टकट सुझाता है। मुझे कहाँ चलाना है, यह किस आधार पर तय होना चाहिए?","options":["निर्धारित या अनिवार्य हैज़मैट मार्ग पर बने रहें, और सड़क की स्थिति जैसे ही अनुमति दे, उस पर वापस लौट आएँ","शहर के केंद्र वाले डायवर्जन को लें, क्योंकि लगे हुए डायवर्जन चिह्नों का पालन करना हमेशा हैज़मैट मार्ग नियमों पर प्राथमिकता रखता है","जीपीएस के नीचे वाले पुल से जाने वाले शॉर्टकट का अनुसरण करें, क्योंकि यह सबसे अधिक समय बचाता है और सबसे भारी जाम से बचाता है","जो रास्ता शारीरिक रूप से सबसे छोटा हो उसे चुनें, क्योंकि कानून केवल कुल तय की गई मीलों को न्यूनतम करने की माँग करता है"],"explanation":"खतरनाक माल के चालकों को निर्धारित या अनिवार्य मार्ग का पालन करना चाहिए और सड़क की स्थिति अनुमति देते ही उस पर लौट आना चाहिए, चाहे शॉर्टकट या यातायात कुछ भी हो।"},"132":{"q":"मैं प्लेकार्ड (खतरे की पट्टिका) लगा हुआ माल ढो रहा हूँ और मुझे एक फोन कॉल निपटाने तथा कुछ मिनट टाँगें सीधी करने के लिए किनारे रुकना है। मेरे मार्ग के पास चार जगहें हैं। पार्किंग के लिए मुझे किसे चुनने से बचना चाहिए?","options":["ग्रामीण इलाके में एक चौड़ा बजरी वाला पुल-आउट, जहाँ आसपास कोई संरचना नहीं दिखती","एक सुरंग के प्रवेश द्वार के ठीक बगल का किनारा, जहाँ पैदल यात्री इकट्ठा हो रहे हैं","इमारत के मुख्य प्रवेश द्वार से काफी दूर बना एक चिह्नित ट्रक स्टॉप क्षेत्र","खुले खेत की ओर वाली एक किनारी, सड़क के यातायात वाले हिस्से से 5 फीट से अधिक दूर"],"explanation":"प्लेकार्ड वाले माल को सुरंगों, पुलों और भीड़ से दूर रखना चाहिए, इसलिए जहाँ पैदल यात्री जमा हों ऐसा सुरंग का प्रवेश दो खतरों को एक साथ जोड़ता है।"},"133":{"q":"आप डिवीजन 1.2 विस्फोटक ले जा रहे हैं और आपका ईंधन गेज कम है, इसलिए आप ईंधन भरने के लिए एक ट्रक स्टॉप पर रुकते हैं। जब टैंक भर रहा हो, तो निम्नलिखित में से कौन सी कार्रवाई इस माल के लिए आपकी ज़िम्मेदारियों को सबसे अच्छी तरह पूरा करती है?","options":["पंप पर इंजन को चालू (आइडल) छोड़ दें ताकि जल्दी से भरकर निकल सकें, फिर भुगतान करने अंदर जाएँ","लदे हुए ट्रेलर को कर्मचारियों की नज़र में रखने के लिए वाहन को रोशनी के नीचे, भीड़भाड़ वाले स्टोर के प्रवेश द्वार के ठीक बगल में खड़ा करें","पूरे समय वाहन के साथ रहें और उसे भीड़ तथा लोगों के जमावड़े वाली जगहों से दूर रखें","केबिन में ताला लगाएँ, रिग को पंप पर छोड़ दें और जब स्वचालित शट-ऑफ ईंधन भरना पूरा कर रहा हो तब अंदर कॉफ़ी लेने जाएँ"],"explanation":"डिवीजन 1.1, 1.2 और 1.3 के विस्फोटकों को कभी भी बिना निगरानी नहीं छोड़ा जा सकता, इसलिए चालक को वाहन के साथ रहना चाहिए और उसे भीड़ व जमावड़े से दूर रखना चाहिए।"},"134":{"q":"मेरे पास पहले से ही क्लास A का CDL है, और मुझे अभी-अभी प्लेकार्ड लगे (खतरनाक सामग्री के लेबल वाले) संक्षारक (corrosive) तरल के भार ढोने के लिए नौकरी पर रखा गया है। मेरा साथी कहता है कि कानूनी रूप से शुरू करने से पहले मुझे बस इतना करना है कि इस एंडोर्समेंट को जोड़ने के लिए DPS कार्यालय में एक छोटी लिखित परीक्षा पास कर लूँ। मुझे जिस खतरनाक सामग्री (HazMat, H) एंडोर्समेंट की ज़रूरत है, उसे पाने के लिए निम्नलिखित में से कौन-सी एकमात्र आवश्यकता है जिसे मैं छोड़ नहीं सकता?","options":["विशेष रूप से प्लेकार्ड लगे टैंक ट्रेलर के साथ स्टीयरिंग के पीछे बैठकर एक सड़क परीक्षा (road test) पूरी करना","किसी भी प्लेकार्ड लगे भार को ढोने से पहले एंडोर्समेंट को कम से कम 30 दिनों तक रखना","जिस सप्ताह मैं एंडोर्समेंट जोड़ता हूँ, उसी सप्ताह के भीतर अपना DOT मेडिकल प्रमाणपत्र नवीनीकृत करना","पृष्ठभूमि जाँच (background check) और उंगलियों के निशान लेने सहित एक TSA सुरक्षा खतरा मूल्यांकन पास करना"],"explanation":"हजमैट एंडोर्समेंट के लिए केवल लिखित परीक्षा नहीं, बल्कि पृष्ठभूमि जाँच और फिंगरप्रिंटिंग सहित TSA सुरक्षा खतरा मूल्यांकन पास करना ज़रूरी है।"},"135":{"q":"मैं ज्वलनशील तरल का प्लेकार्ड (चेतावनी पट्टी) लगा हुआ माल ढो रहा हूँ और दोपहर का भोजन लेने के लिए सड़क किनारे एक भोजनालय पर थोड़ी देर रुकना चाहता हूँ। निम्नलिखित में से कौन-सा कार्य मुझे खतरनाक सामग्री (हैज़मैट) नियमों के उल्लंघन में डाल देगा?","options":["जब मैं भोजनालय के अंदर बैठकर खाना खा रहा हूँ, तब प्लेकार्ड लगे वाहन को पार्किंग में बिना निगरानी के छोड़ देना","पार्क करते समय अपने शिपिंग दस्तावेज़ों को दरवाज़े की जेब में पहुँच के भीतर रखना","वापस हाईवे पर चढ़ने से पहले टायरों का निरीक्षण करना","सड़क के यातायात वाले हिस्से से 5 फीट से अधिक दूरी पर पार्क करना"],"explanation":"प्लेकार्ड वाले खतरनाक माल के वाहन को कभी बिना निगरानी नहीं छोड़ना चाहिए, इसलिए माल बिना देखभाल के रहते हुए ट्रक से दूर जाना एक निषिद्ध उल्लंघन है।"},"136":{"q":"मैं संक्षारक पदार्थों का प्लेकार्ड लगा हुआ माल ढो रहा हूँ और रात भर के लिए एक ट्रक स्टॉप पर रुकता हूँ। सुबह जब मैं अपनी गाड़ी पर लौटकर अपना मार्ग-मध्य निरीक्षण शुरू करता हूँ, तो निम्नलिखित में से कौन सी बात मुझे एक सुरक्षा समस्या के रूप में सबसे अधिक चिंतित करनी चाहिए जिसे देखने के लिए मुझे विशेष रूप से प्रशिक्षित किया गया है?","options":["रात भर में विंडशील्ड पर बर्फ की एक पतली परत जम गई है","माल की एक सील काट दी गई है और एक प्लेकार्ड आंशिक रूप से उखड़ा हुआ दिखाई देता है","ईंधन गेज पिछली रात की तुलना में थोड़ा कम दिखा रहा है","अब मेरे बगल वाली जगह पर एक और ट्रक खड़ा है"],"explanation":"कटा हुआ कार्गो सील और आंशिक रूप से उखड़ा प्लेकार्ड छेड़छाड़ या चोरी के सामान्य संकेत हैं, जिन्हें खतरनाक माल के चालक पहचानने हेतु प्रशिक्षित होते हैं।"},"137":{"q":"मुझे अभी एक ऐसे कैरियर (वाहक कंपनी) ने काम पर रखा है जो प्लेकार्ड वाले खतरनाक माल (HazMat) ढोता है, और प्रशिक्षण के दौरान मेरा डिस्पैचर मुझे कंपनी के दस्तावेज़ों की एक फ़ाइल थमाता है और कहता है कि संघीय नियमों के अनुसार हमारे जैसे कई वाहकों को इनमें से एक दस्तावेज़ लिखित रूप में रखना अनिवार्य है। एक नियामक आवश्यकता के रूप में वह सबसे अधिक संभावना किस दस्तावेज़ की बात कर रहा है?","options":["एक लिखित दैनिक भोजन और विश्राम-स्थल कार्यक्रम जिस पर हर चालक को यार्ड से निकलने से पहले हस्ताक्षर करने होते हैं","प्लेकार्ड वाले वाहनों के लिए स्वीकृत, कंपनी द्वारा पसंदीदा ईंधन स्टेशनों की एक लिखित सूची","एक लिखित सुरक्षा योजना (security plan) जो बताती है कि कंपनी खतरनाक माल की चोरी और दुरुपयोग से कैसे बचाव करती है","उन रेडियो स्टेशनों का एक लिखित रिकॉर्ड जिन्हें चालक माल ढोते समय सुन सकते हैं"],"explanation":"खतरनाक माल ढोने वाले कई वाहक को कर्मचारी, अनधिकृत पहुँच और मार्ग-सुरक्षा को कवर करने वाली लिखित सुरक्षा योजना बनानी और बनाए रखनी होती है।"},"138":{"q":"सर्दी का मौसम है और मेरे ट्रेलर में स्वचालित कार्गो हीटर लगा है। टर्मिनल से निकलने से पहले डिस्पैचर मुझे एक लोड देता है और रास्ते भर माल को गर्म रखने को कहता है। निम्नलिखित में से किस लोड के साथ मुझे कार्गो हीटर बिल्कुल भी नहीं चलाना चाहिए?","options":["सूखे बक्से में सीलबंद डिब्बाबंद खाद्य पदार्थ का लोड जो ठंड में जम सकता है","एक खाली ट्रेलर जिसे मैं अगले पिकअप स्थान तक ले जा रहा हूँ","जमने के प्रति संवेदनशील बोतलबंद पेयजल का पैलेटयुक्त लोड","ज्वलनशील तरल के ड्रमों का लोड जो गर्म होने पर वाष्प छोड़ते हैं"],"explanation":"ज्वलनशील तरल के माल के साथ कार्गो हीटर का उपयोग नहीं करना चाहिए, क्योंकि गर्म होने पर निकलने वाले वाष्प आग पकड़ सकते हैं जिससे आग या विस्फोट हो सकता है।"},"139":{"q":"जब आपको क्षतिग्रस्त या रिसने वाले हैजमैट पैकेज मिलें, तो आपको चाहिए:","options":["उन्हें फिर भी लोड कर लें","उन्हें स्वीकार या परिवहन न करें","उन्हें जल्दी से टेप लगाकर बंद कर दें","उन्हें पीछे छिपा दें"],"explanation":"रिसने वाले या क्षतिग्रस्त पैकेजों को स्वीकार या परिवहन न करें।"},"140":{"q":"मैं एक ऐसी खेप लाद रहा हूँ जिसके लिए प्लेकार्ड (placard) जरूरी हैं, और शिपिंग कागजात में एक प्रविष्टि दर्ज है जिसे मेरे वाहक ने खतरनाक माल नियमों के तहत \"निषिद्ध\" (forbidden) सामग्री के रूप में चिह्नित किया है। खेप के लिए हस्ताक्षर करने से पहले, इस प्रविष्टि के संबंध में मेरी जिम्मेदारी को कौन-सा कथन सही ढंग से बताता है?","options":["मुझे इस सामग्री को किसी भी हाल में नहीं ले जाना चाहिए, क्योंकि निषिद्ध सामग्री को किसी भी वाहन में और किसी भी परिस्थिति में कभी नहीं ले जाया जा सकता।","मैं इसे तभी ले जा सकता हूँ जब मैं चारों ओर सही प्लेकार्ड लगाऊँ और कागजात अपनी पहुँच के भीतर रखूँ।","मैं इसे केवल तभी ले जा सकता हूँ जब यात्रा के दौरान इसका कुल सकल वजन 1,001 पाउंड से कम रहे।","मैं इसे तभी ले जा सकता हूँ जब शिपर कागजात में सही शिपिंग नाम, खतरा वर्ग और पहचान संख्या जोड़ दे।"],"explanation":"निषिद्ध सामग्री को किसी भी स्थिति में नहीं ले जाया जा सकता, इसलिए एकमात्र सही कार्य है उन्हें ढोने से पूरी तरह इनकार करना।"},"141":{"q":"मैं एक लदान (लोड) तैयार कर रहा हूँ और शिपर मुझे बताता है कि इसका एक हिस्सा \"सीमित मात्रा\" (limited quantity) शिपमेंट के रूप में योग्य है। उसके लिए हस्ताक्षर करने से पहले, लदान के उस हिस्से के बारे में निम्नलिखित में से क्या सत्य होने की अपेक्षा मुझे करनी चाहिए?","options":["चूँकि यह एक विशेष श्रेणी है, यह हर खतरनाक माल नियम से छूट प्राप्त है और मैं इसे बिना किसी कागजात के ढो सकता हूँ","इसमें सामग्री की छोटी मात्राएँ शामिल होती हैं, इसलिए इस पर पैकेजिंग और चिह्नांकन की कम आवश्यकताएँ लागू होती हैं","वजन की परवाह किए बिना यह हमेशा चारों ओर अधिकतम संख्या में प्लाकार्ड की माँग करता है","यह शब्द केवल तरल पदार्थों पर लागू होता है, इसलिए लदान में कोई भी ठोस पदार्थ सीमित मात्रा नहीं हो सकता"],"explanation":"सीमित मात्रा कम मात्रा में भेजी जाती है जो निर्धारित सीमा से नीचे रहती है, इसी कारण इस पर पैकेजिंग और चिह्नांकन की कम आवश्यकताएँ लागू होती हैं।"},"142":{"q":"मैं खतरनाक माल की खेप पर अपना यात्रा-पूर्व निरीक्षण कर रहा हूँ और प्रत्येक कार्टन को अपने शिपिंग कागजात से मिलाने के लिए पीछे का हिस्सा खोलता हूँ। शिपर ने सब कुछ सील और पैक कर दिया है, फिर भी मुझे यह पुष्टि करनी है कि प्रत्येक पैकेज में क्या होना चाहिए। कार्टन को मेरे कागजात पर दिए सही शिपिंग नाम, खतरा वर्ग और पहचान संख्या से मिलाने के लिए, मुझे प्रत्येक पैकेज पर ही क्या छपा हुआ मिलने की उम्मीद करनी चाहिए?","options":["प्रत्येक कार्टन पर चिपकी शिपिंग कागजात की एक प्रति, ताकि पैकेज और कागजात हमेशा साथ-साथ यात्रा करें","वाहक का नाम और मेरा पूरा नाम, ताकि बचावकर्मियों को पता चले कि कौन सा चालक और कंपनी माल ढो रहे हैं","सामग्री की पहचान करने वाला एक खतरा लेबल और चिह्न, ताकि मैं पैकेज को अपने शिपिंग कागजात की प्रविष्टियों से सत्यापित कर सकूँ","उत्पाद की कीमत वाला एक खुदरा मूल्य टैग, ताकि प्राप्तकर्ता डिलीवरी पर खेप का मूल्य पुष्टि कर सके"],"explanation":"शिपर हर पैकेज पर उसकी खतरा श्रेणी और शिपिंग नाम लेबल और चिह्नित करता है ताकि आप हर पैकेज को अपने शिपिंग पेपर से मिला सकें।"},"143":{"q":"मैं क्लास 7 रेडियोधर्मी सामग्री की खेप लोड कर रहा हूँ और शिपर दस्तावेज़ों पर मेरे हस्ताक्षर करने से पहले पैकेज के लेबल मेरे साथ जाँच रहा है। वह लेबल पर छपे एक नंबर की ओर इशारा करता है जिसका मुझे ध्यान रखना होगा जब मैं यह तय करूँ कि इस सामग्री की कितनी मात्रा मेरे ट्रेलर में एक साथ रखी जा सकती है। निम्नलिखित में से कौन-सा वह निर्णायक आँकड़ा है जो रेडियोधर्मी पैकेजों पर हो सकता है?","options":["एक विषैली साँस-खतरा रेटिंग जो लोड को किसी भी मात्रा में प्लेकार्ड लगाने से छूट देती है","एक मंजूरी कोड जो लोड को वज़न स्टेशनों और मार्ग प्रतिबंधों को बायपास करने देता है","एक रिपोर्ट-योग्य मात्रा (RQ) सीमा जो किसी भी पैकेज चिह्न की आवश्यकता को समाप्त कर देती है","एक परिवहन सूचकांक (ट्रांसपोर्ट इंडेक्स) सीमा जो यह प्रतिबंधित करती है कि एक साथ कितना ले जाया जा सकता है"],"explanation":"वर्ग 7 रेडियोधर्मी पैकेजों पर एक परिवहन सूचकांक होता है जिसकी सीमा यह नियंत्रित करती है कि कितना रेडियोधर्मी पदार्थ एक साथ लादा और ढोया जा सकता है।"},"144":{"q":"मैं प्लेकार्ड लगा हुआ एक माल लोड कर रहा हूँ जिसे शिपिंग कागजात में प्रतिक्रियाशील (reactive) पदार्थ बताया गया है, और मैं तय कर रहा हूँ कि इसे ट्रेलर में कहाँ और कैसे रखूँ। इसे सुरक्षित रूप से संभालने के लिए, मुझे इस प्रतिक्रियाशील पदार्थ को निम्नलिखित में से किससे दूर रखना चाहिए?","options":["गर्मी के स्रोतों से, पानी या नमी से, और ढोए जा रहे किसी भी अन्य प्रतिक्रियाशील पदार्थ से","उन मुलायम गर्म कंबलों या गद्दी से जो माल को परिवहन के दौरान सहारा देने के लिए लगाई जाती है","ट्रेलर के किसी भी बड़े खाली खुले स्थान से जहाँ पैकेज खिसक सकता है","ट्रेलर के दरवाज़ों से आने वाली बहुत तेज़ रोशनी के सीधे संपर्क से"],"explanation":"प्रतिक्रियाशील पदार्थों को गर्मी, पानी या नमी और अन्य प्रतिक्रियाशील पदार्थों से दूर रखना चाहिए, क्योंकि संपर्क से तीव्र प्रतिक्रिया हो सकती है।"},"145":{"q":"मुझे एक लंबी ढुलाई के लिए प्रशीतित तरल नाइट्रोजन - एक क्रायोजेनिक (बहुत ठंडा) तरल - से भरा टैंक उठाने का काम सौंपा गया है। शिपमेंट स्वीकार करने से पहले ट्रेलर का निरीक्षण करते समय, कौन सी स्थिति मुझे बताती है कि इस प्रकार के माल को सही ढंग से संभाला जा रहा है?","options":["टैंक पूरी तरह सील है, बिना किसी वेंट के, ताकि ठंडक बाहर न निकले और उत्पाद जमा रहे","टैंक में विशेष इंसुलेटेड उपकरण लगे हैं और एक चालू वेंट है जो जमा हुए दबाव को सुरक्षित रूप से बाहर निकालता है","तरल वाल्वों को जमाकर बंद न कर दे, इसके लिए टैंक के अंदर एक छोटा हीटर यूनिट लगाया गया है","टैंक एक मानक सूखा-थोक वाहक है जिसमें कोई अतिरिक्त फिटिंग नहीं है, क्योंकि ठंडक को किसी विशेष देखभाल की जरूरत नहीं है"],"explanation":"क्रायोजेनिक तरल पदार्थ लगातार गर्मी सोखते हैं और दबाव बनाते हैं, इसलिए उन्हें विशेष इन्सुलेटेड उपकरण और दबाव को सुरक्षित रूप से छोड़ने के लिए काम करने वाला वेंट चाहिए।"},"146":{"q":"टेक्सास के एक ग्रामीण राजमार्ग पर मेरा प्लेकार्ड लगा ट्रेलर पलट जाता है और एक ड्रम से रिसाव शुरू हो जाता है। पहली दमकल टीम मेरे कुछ कहने से पहले ही पहुँच जाती है, मेरे शिपिंग पेपर ले लेती है, और तुरंत माल के लिए दर्ज खतरा वर्ग (hazard class) और UN/NA पहचान संख्या पढ़ती है। घटनास्थल पर मौजूद उन प्रतिक्रियाकर्ताओं के लिए वह खतरा वर्ग और पहचान संख्या इतनी महत्वपूर्ण होने का मुख्य कारण क्या है?","options":["इनसे प्रतिक्रियाकर्ता यह गणना कर सकते हैं कि मेरा माल उस 1,001 पाउंड की सीमा से अधिक था या नहीं जिसके कारण शुरुआत में प्लेकार्ड लगाना ज़रूरी हुआ था","ये साबित करते हैं कि मैं, चालक, पहले ही CHEMTREC को फ़ोन कर चुका था और मदद आने से पहले वाहक ने घटना की रिपोर्ट दर्ज कर दी थी","इनसे प्रतिक्रियाकर्ता शीघ्रता से ठीक-ठीक पहचान सकते हैं कि खतरा क्या है, ताकि वे उस सामग्री के प्रति सही प्रतिक्रिया दे सकें","ये पुष्टि करते हैं कि प्लेकार्ड चारों ओर लगे थे और जिस दिशा की ओर थे, उस दिशा से पढ़े जा सकते थे"],"explanation":"उचित शिपिंग नाम, खतरा श्रेणी और पहचान संख्या आपातकालीन कर्मियों को सटीक खतरे की तुरंत पहचान करने और पदार्थ के प्रति सही प्रतिक्रिया देने में मदद करते हैं।"},"147":{"q":"यदि आप किसी प्लेकार्ड के अर्थ के बारे में अनिश्चित हैं, तो आपको चाहिए:","options":["अनुमान लगाकर आगे बढ़ें","शिपिंग पेपर और ERG की जाँच करें","प्लेकार्ड हटा दें","इसे पूरी तरह से अनदेखा करें"],"explanation":"शिपिंग पेपर और ERG की जाँच करें।"},"148":{"q":"मेरे पास पहले से ही टेक्सास का क्लास A CDL है और मैं दो साल से सूखा माल ढो रहा हूँ। अगले महीने मेरा कैरियर चाहता है कि मैं ऐसे लोड ढोना शुरू करूँ जिन्हें ट्रेलर के चारों तरफ प्लेकार्ड (खतरा चिह्न) लगाना जरूरी हो। उस पहले प्लेकार्ड वाले चक्कर को कानूनी रूप से स्वीकार करने से पहले मुझे क्या पूरा करना होगा?","options":["कुछ अतिरिक्त नहीं — अकेला क्लास A CDL ही पहले से किसी भी प्लेकार्ड वाले खतरनाक माल की अनुमति देता है","केवल टैंकर (N) एंडोर्समेंट, क्योंकि प्लेकार्ड वाला माल थोक में टैंकों में ढोया जाता है","जोड़े गए ट्रेलर के वजन को कवर करने के लिए केवल डबल्स/ट्रिपल्स (T) एंडोर्समेंट","खतरनाक माल (H) एंडोर्समेंट, जिसके लिए फिंगरप्रिंट के साथ TSA सुरक्षा खतरा मूल्यांकन पास करना जरूरी है"],"explanation":"प्लेकार्ड लगाने योग्य मात्रा में खतरनाक माल ढोने के लिए HazMat (H) समर्थन आवश्यक है, जो फिंगरप्रिंटिंग सहित TSA सुरक्षा खतरा मूल्यांकन पास करने के बाद ही जारी होता है।"},"149":{"q":"मैंने अभी-अभी संक्षारक (corrosive) पदार्थों का एक प्लेकार्ड लगा लदान उठाया है। शिपिंग पेपर्स में खतरा वर्ग (hazard class) की एक गलती है, और मैं टर्मिनल छोड़ने से पहले ही इसे देख लेता हूँ। एक डिस्पैचर मुझसे कहता है, \"वह कागजी कार्रवाई 100% शिपर की समस्या है — तुम्हारा एकमात्र काम गाड़ी चलाना है।\" खतरनाक माल (हैज़मैट) के नियमों के अनुसार, कौन-सा कथन सत्य है?","options":["सुरक्षित परिवहन एक साझा जिम्मेदारी है — शिपर, कैरियर और चालक में से प्रत्येक के अपने विशिष्ट कर्तव्य हैं, और मुझे जानबूझकर किसी गलत तरीके से चिह्नित लदान को नहीं ढोना चाहिए।","चूँकि केवल शिपर ही माल का वर्गीकरण करता है और कागजात तैयार करता है, चालक कागजी गलतियों के लिए जिम्मेदार नहीं है और लदान को जैसा है वैसा कानूनी रूप से ढो सकता है।","जैसे ही कैरियर लदान भेज देता है, शिपमेंट की पूरी कानूनी जिम्मेदारी कैरियर को स्थानांतरित हो जाती है, इसलिए चालक पूरी तरह डिस्पैच पर भरोसा कर सकता है।","चालक का एकमात्र कर्तव्य सुरक्षित ड्राइविंग है, इसलिए कागजात की सटीकता केवल शिपर का काम है और यह कभी भी ऐसा कुछ नहीं जिसे चालक को सत्यापित करना पड़े।"],"explanation":"खतरनाक माल की सुरक्षा शिपर, वाहक और चालक की साझा जिम्मेदारी है, और आपको जानबूझकर रिसाव वाला या गलत चिह्नित माल ढोने से इनकार करना चाहिए।"},"150":{"q":"मैं संपीड़ित प्रोपेन सिलेंडरों का एक लोड उठा रहा हूँ और डॉक पर्यवेक्षक मुझे शिपिंग कागज़ात देता है जिनमें सामग्री को खतरा वर्ग 2 के रूप में दिखाया गया है। प्लेकार्ड लगाने से पहले, मैं पुष्टि करना चाहता हूँ कि वर्ग 2 वास्तव में क्या दर्शाता है। कौन सा कथन सही है?","options":["वर्ग 2 में संक्षारक पदार्थ आते हैं, जैसे बैटरी अम्ल और सोडियम हाइड्रॉक्साइड के लोड जिन्हें मैं कभी-कभी ढोता हूँ।","वर्ग 2 में गैसें आती हैं, जिनमें मेरे प्रोपेन जैसी ज्वलनशील, गैर-ज्वलनशील और विषैली गैस सामग्री शामिल हैं।","वर्ग 2 में विस्फोटक आते हैं, इसलिए यह लोड डायनामाइट और आतिशबाज़ी के समान नियमों के अंतर्गत आता है।","वर्ग 2 में रेडियोधर्मी पदार्थ आते हैं, इसीलिए इन सिलेंडरों को अतिरिक्त परिरक्षण की आवश्यकता होती है।"],"explanation":"खतरा वर्ग 2 गैसें हैं, जो 2.1 ज्वलनशील, 2.2 गैर-ज्वलनशील और 2.3 विषैली गैस में विभाजित हैं, और प्रोपेन इस वर्ग की एक ज्वलनशील गैस है।"},"151":{"q":"मैं डिलीवरी के लिए बैटरी एसिड के ड्रम लोड कर रहा हूँ, और शिपिंग पेपर्स में खतरा वर्ग (हैज़र्ड क्लास) 8 लिखा है। अपने ट्रेलर पर प्लेकार्ड लगाने से पहले, मुझे यह पुष्टि करनी है कि यह माल वास्तव में किस प्रकार का खतरा दर्शाता है। निम्नलिखित में से कौन सा कथन खतरा वर्ग 8 की सामग्री का सही वर्णन करता है?","options":["एक संपीड़ित या द्रवीकृत गैस जो रिस सकती है और साँस लेने का खतरा पैदा कर सकती है","एक विषैला पदार्थ जो त्वचा के संपर्क या साँस के द्वारा किसी व्यक्ति को ज़हर पहुँचा सकता है","एक संक्षारक (कोरोसिव) पदार्थ जो त्वचा, धातु या अन्य सामग्रियों को रासायनिक रूप से जला सकता है","एक विस्फोटक पदार्थ जो गर्मी, झटके या घर्षण से विस्फोट कर सकता है"],"explanation":"खतरा वर्ग 8 संक्षारक पदार्थ हैं, जैसे बैटरी एसिड, जो त्वचा, धातु और अन्य पदार्थों को रासायनिक रूप से जलाते या गलाते हैं।"},"152":{"q":"मैं अपना ट्रेलर लोड कर रहा हूँ, तभी शिपर मुझे एक खेप के कागज़ात देता है जिन पर 'खतरा वर्ग 7' अंकित है, साथ में UN संख्या और सही शिपिंग नाम है। प्लेकार्ड लगाने से पहले, मुझे ठीक से समझना है कि मैं किस प्रकार का खतरा ढो रहा हूँ। खतरा वर्ग प्रणाली के अनुसार, वर्ग 7 इस भार के बारे में मुझे क्या बताता है?","options":["यह एक संक्षारक पदार्थ है, इसलिए रिसते कंटेनर त्वचा को जला सकते हैं और धातु की सतहों को गला सकते हैं","यह एक ज्वलनशील तरल है, इसलिए मुझे सभी प्रज्वलन स्रोतों और खुली आग को इससे दूर रखना चाहिए","यह एक संपीड़ित या विषैली गैस है, इसलिए दबाव निकलने से साँस लेने का खतरा पैदा हो सकता है","यह एक रेडियोधर्मी पदार्थ है, इसलिए मैं ऐसा भार ढो रहा हूँ जो विकिरण उत्सर्जित करता है और विशेष देखभाल की आवश्यकता है"],"explanation":"खतरा वर्ग 7 का हमेशा अर्थ रेडियोधर्मी पदार्थ होता है, इसलिए माल विकिरण उत्सर्जित करता है और दिखाए गए शिपिंग नाम की परवाह किए बिना विशेष देखभाल की आवश्यकता होती है।"},"153":{"q":"मैं एक ट्रेलर लोड कर रहा हूँ और मेरे शिपिंग पेपर्स में एक खतरा श्रेणी 5 (Hazard Class 5) सामग्री सूचीबद्ध है। प्लेकार्ड लगाने से पहले, मैं यह पुष्टि करना चाहता हूँ कि यह लोड वास्तव में किस प्रकार का खतरा प्रस्तुत करता है। श्रेणी 5 की सामग्री वह होती है जो:","options":["एक ऑक्सीकारक (ऑक्सीडाइज़र) या कार्बनिक परॉक्साइड है जो ऑक्सीजन छोड़कर आग को और भड़का सकती है","एक संक्षारक (कोरोसिव) है जो त्वचा के ऊतकों को नष्ट कर सकती है या स्टील और एल्युमिनियम को गला सकती है","एक विस्फोटक है जो गर्मी या झटके के संपर्क में आने पर सामूहिक विस्फोट कर सकती है","एक संपीड़ित गैस है जो ज्वलनशील, गैर-ज्वलनशील या विषैली हो सकती है"],"explanation":"खतरा वर्ग 5 के ऑक्सीकारक और कार्बनिक पेरोक्साइड ऑक्सीजन छोड़ते हैं, जो बाहरी प्रज्वलन स्रोत के बिना भी आग शुरू कर सकते हैं या भड़का सकते हैं।"},"154":{"q":"मैं डॉक पर थोड़ी मात्रा में विषैले अंतःश्वसन खतरे (PIH) वाली सामग्री लोड कर रहा हूँ, और कुल वज़न 1,001 पाउंड से काफ़ी कम है। मेरा डिस्पैचर कहता है कि लोड इतना हल्का है कि मैं इसे सामान्य माल की तरह ले जा सकता हूँ। इस PIH खेप को संभालने का सही तरीका निम्नलिखित में से कौन सा है?","options":["चूँकि लोड 1,001 पाउंड से कम है, किसी प्लेकार्ड की ज़रूरत नहीं है और मैं इसे साधारण माल की तरह चला सकता हूँ","मुझे इसे अतिरिक्त सावधानी से संभालना चाहिए और उचित प्लेकार्ड लगाने चाहिए, क्योंकि PIH सामग्री को किसी भी मात्रा में प्लेकार्ड की आवश्यकता होती है","मुझे प्लेकार्ड केवल तभी चाहिए जब मैं राज्य की सीमा पार करूँ; राज्य के भीतर 1,001 पाउंड से कम की PIH खेप को विशेष संभाल की ज़रूरत नहीं","चूँकि मात्रा इतनी कम है, मुझे अपना कागज़ी काम कम करना चाहिए और शिपिंग दस्तावेज़ छोड़ देने चाहिए"],"explanation":"विषैले श्वसन खतरे (PIH) वाली सामग्री तालिका 1 का खतरा है, जिसके लिए किसी भी मात्रा में प्लेकार्ड लगाना अनिवार्य है, बिना किसी न्यूनतम वजन सीमा के।"},"155":{"q":"मैं अपने ट्रेलर में एक वस्तु के कई डिब्बे लाद रहा हूँ, जिसे शिपिंग पेपर पर खतरा वर्ग 9 (Hazard Class 9) के अंतर्गत सूचीबद्ध किया गया है। यह न तो ज्वलनशील है, न संक्षारक (corrosive) है, और न ही संपीड़ित गैस है, फिर भी इसके लिए प्लेकार्ड की आवश्यकता पड़ी। कौन-सा कथन खतरा वर्ग 9 में शामिल चीज़ों का सबसे अच्छा वर्णन करता है?","options":["संपीड़ित और द्रवीकृत गैसें जो दबाव में ज्वलनशील नहीं होतीं","संक्षारक तरल और ठोस पदार्थ जो त्वचा या धातु को नुकसान पहुँचा सकते हैं","विविध (मिश्रित) खतरनाक पदार्थ जो अन्य आठ वर्गों में फिट नहीं होते","विस्फोटक — विस्फोटक मिश्रणों से लेकर आतिशबाज़ी और डेटोनेटर तक"],"explanation":"खतरा वर्ग 9 विविध श्रेणी है, जो उन विनियमित सामग्रियों के लिए है जो परिवहन खतरा पैदा करती हैं पर वर्ग 1 से 8 में नहीं आतीं।"},"156":{"q":"मैं एक माल के लिए शिपिंग पेपर तैयार कर रहा हूँ और प्रविष्टि में खतरा वर्ग 4 दिखाया गया है। प्लेकार्ड लगाने से पहले, मैं यह पुष्टि करना चाहता हूँ कि मैं वास्तव में किस प्रकार का माल ढो रहा हूँ ताकि सही प्लेकार्ड उठा सकूँ। निम्नलिखित में से कौन सा वर्ग 4 के माल का सही वर्णन करता है?","options":["एक ज्वलनशील तरल जैसे पेट्रोल या डीजल ईंधन","एक संपीड़ित गैस, चाहे ज्वलनशील हो या गैर-ज्वलनशील","एक संक्षारक पदार्थ जो त्वचा और धातु को नुकसान पहुँचा सकता है","एक ज्वलनशील ठोस जो आसानी से जल या भड़क सकता है"],"explanation":"खतरा वर्ग 4 में ज्वलनशील ठोस शामिल हैं, जिनमें स्वतः दहनशील और गीला होने पर खतरनाक सामग्री भी आती है, जो आसानी से सुलग या जल सकती हैं।"},"157":{"q":"मैं प्लेकार्ड लगाए हुए हूं और टेक्सास के एक वजन केंद्र पर रुका हूं, तभी एक निरीक्षक मेरे ट्रेलर पर एक नारंगी पैनल पर दिख रहे 4 अंकों के नंबर 1203 की ओर इशारा करता है और पूछता है कि यह नंबर उसे क्या बताता है। कौन सा उत्तर सही है?","options":["यह पहचान (UN/NA) नंबर है जो उस विशिष्ट सामग्री की पहचान करता है जिसे मैं ढो रहा हूं","यह वाहक द्वारा माल को सौंपा गया उचित शिपिंग नाम कोड है","यह खतरा वर्ग संख्या है जो बताती है कि नौ वर्गों में से कौन सा लागू होता है","यह प्लेकार्ड तालिका संख्या है जो दिखाती है कि 1,001 पाउंड का नियम लागू होता है या नहीं"],"explanation":"शिपिंग कागजात या प्लेकार्ड पर लिखा 4 अंकों का नंबर UN/NA पहचान संख्या है, जो ले जाई जा रही सटीक सामग्री की पहचान करता है।"},"158":{"q":"अपनी यात्रा-पूर्व जांच के दौरान, एक राज्य पुलिस अधिकारी मुझसे उस माल का 4-अंकों वाला UN/NA पहचान संख्या पढ़कर बताने को कहता है जिसे मैं ढो रहा हूं, ताकि वह इसे आपातकालीन प्रतिक्रिया गाइडबुक (ERG) में मिला सके। उसे खोजने के लिए मैं अपने प्लेकार्ड लगे ट्रेलर के किनारे जाता हूं। मुझे यह 4-अंकों वाली पहचान संख्या सही तरीके से कहां से पढ़ने की अनुमति है?","options":["केवल शिपिंग कागजात पर छपे उचित शिपिंग नाम से; यह ट्रेलर के बाहरी हिस्से पर कभी नहीं दिखती","या तो सीधे प्लेकार्ड पर ही या प्लेकार्ड के बगल में लगे नारंगी पैनल पर","केवल हीरे के आकार वाले प्लेकार्ड के निचले कोने में दिखाए गए खतरा वर्ग संख्या से","केवल ट्रेलर के ढांचे पर लैंडिंग गियर के पास अंकित निर्माता की डेटा प्लेट से"],"explanation":"4 अंकों की UN/NA पहचान संख्या या तो प्लेकार्ड के बीच में या प्लेकार्ड के बगल में लगे नारंगी पैनल पर दिखाई जा सकती है।"},"159":{"q":"सड़क किनारे जांच के दौरान एक अधिकारी मेरे ट्रेलर के पिछले हिस्से पर लगे हीरे के आकार वाले प्लेकार्ड (placard) की ओर इशारा करता है और मुझसे वह खतरा वर्ग संख्या (hazard class number) पढ़ने को कहता है जो बताती है कि मैं क्या ढो रहा हूँ। प्लेकार्ड पर ऊपर एक प्रतीक, बीच की पट्टी में लिखे हुए शब्द, और एक अंक दिखता है। उस खतरा वर्ग संख्या को ढूँढने के लिए मुझे प्लेकार्ड पर कहाँ देखना चाहिए?","options":["प्लेकार्ड के बिल्कुल बीच में, ठीक वहाँ जहाँ सामग्री का लिखित नाम छपा होता है","हीरे के सबसे ऊपरी सिरे पर, खतरे के प्रतीक या चित्र के ठीक ऊपर","हीरे के निचले कोने में, प्रतीक और सामग्री के लिखित नाम के नीचे","हीरे के बाएँ या दाएँ किनारे के साथ, खतरे के प्रतीक के बगल में"],"explanation":"प्लेकार्ड पर एक अंक का खतरा वर्ग नंबर हीरे के निचले कोने में, प्रतीक और लिखित खतरे के नाम के नीचे होता है।"},"160":{"q":"मैं एक मालवाहक टर्मिनल पर अपने ट्रेलर में कई गैर-बल्क पैकेज लाद रहा हूँ, जिनमें से हर एक तालिका 2 के अलग-अलग खतरा वर्ग का है, और इनमें से कोई भी अकेले 1,001 पाउंड की उस सीमा तक नहीं पहुँचता जो अलग प्लेकार्ड लगाना अनिवार्य कर दे। हर वर्ग के लिए अलग प्लेकार्ड लगाने के बजाय, मैं पूरे मिश्रित शिपमेंट के लिए एक ही 'DANGEROUS' (खतरनाक) प्लेकार्ड का उपयोग करना चाहता हूँ। उस एकल 'DANGEROUS' प्लेकार्ड का उपयोग वास्तव में किस शर्त के तहत अनुमत है?","options":["केवल तब जब ट्रेलर का हर पैकेज ठीक उसी एकमात्र खतरा वर्ग का हो","केवल तब जब ट्रेलर किसी भी विनियमित खतरनाक सामग्री को बिल्कुल भी न ढो रहा हो","केवल तब जब माल मालभाड़े के साथ भेजी जाने वाली उपभोक्ता खाद्य वस्तुओं तक सीमित हो","जब माल में एक साथ ले जाए जा रहे तालिका 2 के दो या अधिक अलग-अलग खतरा वर्ग शामिल हों"],"explanation":"जब कोई गैर-बल्क भार तालिका 2 के दो या अधिक खतरा वर्गों को मिलाता है, तो अलग-अलग प्लेकार्ड के बजाय DANGEROUS प्लेकार्ड का उपयोग किया जा सकता है।"},"161":{"q":"मैं एक छोटे स्थानीय सफर के लिए तालिका 1 की सामग्री (डिवीजन 2.3 की ज़हरीली गैस) का एक ही छोटा ड्रम लाद रहा हूँ। खतरनाक सामग्री का कुल वजन 1,000 पाउंड से काफी कम है। निकलने से पहले, मुझे वाहन पर प्लेकार्ड कैसे लगाने चाहिए?","options":["मुझे प्लेकार्ड वाहन के चारों ओर लगाने होंगे, चाहे मैं कितना भी कम क्यों न ले जा रहा हूँ, क्योंकि तालिका 1 की सामग्री किसी भी मात्रा में प्लेकार्ड की मांग करती है।","इस सफर में प्लेकार्ड की जरूरत नहीं, क्योंकि मैं उस 1,001 पाउंड के कुल सकल वजन से कम ले जा रहा हूँ जो प्लेकार्ड की मांग करता है।","प्लेकार्ड की जरूरत केवल तब है जब मेरा संयुक्त खतरनाक भार 1,001 पाउंड या उससे अधिक पहुँचे, इसलिए एक छोटा ड्रम छूट में है।","प्लेकार्ड की जरूरत केवल तब है जब सफर अंतरराज्यीय हो या आबादी वाले इलाके में जाए, क्योंकि एक छोटा स्थानीय सफर इनकी मांग नहीं करता।"],"explanation":"प्रभाग 2.3 का विषैला गैस तालिका 1 की सामग्री है, जिसे वजन की परवाह किए बिना किसी भी मात्रा में चारों ओर प्लेकार्ड लगाना अनिवार्य है।"},"162":{"q":"मैं एक मिश्रित माल वाला ट्रेलर लोड कर रहा हूँ और वाहन पर एकमात्र खतरनाक सामग्री एक तालिका 2 (Table 2) उत्पाद है। मेरे शिपिंग दस्तावेज़ दिखाते हैं कि कुल सकल वजन ठीक 900 पाउंड है। DPS प्लेकार्ड नियमों के अनुसार, निकलने से पहले मुझे क्या करना चाहिए?","options":["चारों तरफ प्लेकार्ड लगाएँ, क्योंकि तालिका 2 में सूचीबद्ध खतरनाक सामग्री की कोई भी मात्रा हमेशा प्लेकार्ड की आवश्यकता पैदा करती है","किसी प्लेकार्ड की आवश्यकता नहीं है, क्योंकि तालिका 2 सामग्रियों को केवल 1,001 पाउंड या उससे अधिक कुल सकल वजन पर प्लेकार्ड की आवश्यकता होती है","चारों तरफ प्लेकार्ड लगाएँ, क्योंकि यह माल तालिका 2 शिपमेंट के लिए 100 पाउंड की रिपोर्टिंग सीमा से ऊपर है","केवल पीछे प्लेकार्ड लगाएँ, क्योंकि 900 पाउंड आंशिक प्लेकार्ड के लिए पर्याप्त है लेकिन चारों तरफ पूर्ण प्लेकार्ड के लिए नहीं"],"explanation":"तालिका 2 की सामग्री के लिए प्लेकार्ड केवल तभी आवश्यक है जब उनका कुल सकल वजन 1,001 पाउंड या उससे अधिक हो।"},"163":{"q":"मैं एक शिपर के डॉक पर एक ट्रेलर लोड कर रहा हूँ और देखता हूँ कि शिपर ने सामग्री की पहचान के लिए हीरे के आकार की खतरे की चेतावनियाँ लगाई हैं। ये खतरे के लेबल कहाँ लगाए जाने चाहिए?","options":["ट्रेलर के चारों ओर, उस दिशा से पढ़ने योग्य जिस ओर प्रत्येक मुड़ा हो","शिपिंग पेपर्स पर, प्रत्येक प्रविष्टि के बगल में HM कॉलम में","अलग-अलग पैकेजों और कंटेनरों पर ही","ड्राइवर के दरवाजे की पाउच में जहाँ कागजात रखे जाते हैं"],"explanation":"खतरे के लेबल प्रेषक द्वारा सीधे प्रत्येक अलग पैकेज और कंटेनर पर लगाए जाते हैं ताकि सामग्री की खतरा श्रेणी पहचानी जा सके।"},"164":{"q":"मैं संक्षारक (corrosive) पदार्थों का एक माल लाद रहा हूँ जिसके लिए प्लेकार्ड ज़रूरी हैं, और मेरा सह-चालक मुझे चार हीरे के आकार के संक्षारक (CORROSIVE) प्लेकार्ड देता है। वह मुझे बताता है कि उसके हिसाब से ये कहाँ लगने चाहिए, पर मैं चलने से पहले इसे सही करना चाहता हूँ। ये प्लेकार्ड असल में कहाँ प्रदर्शित होने चाहिए?","options":["ट्रेलर के अंदर हर अलग पैकेज और ओवरपैक पर चिपकाए जाएँ ताकि दरवाज़े खुलने पर निरीक्षक खतरा देख सकें","शिपिंग कागज़ात पर HM कॉलम में उचित शिपिंग नाम, खतरा वर्ग और पहचान संख्या के बगल में लगाए जाएँ","चलते समय मेरी पहुँच में रहें इसलिए कागज़ात के साथ चालक के दरवाज़े की थैली में लगाए जाएँ","वाहन के चारों ओर लगाए जाएँ, और हर एक उस दिशा से पढ़ने योग्य हो जिस ओर वह मुड़ा है"],"explanation":"प्लेकार्ड वाहन के चारों ओर लगाए जाते हैं और प्रत्येक उस दिशा से पढ़ा जा सकना चाहिए जिस ओर वह मुख है।"},"165":{"q":"अपने ट्रेलर को लोड करते समय, मैं एक सीलबंद पैकेज उठाता हूँ जिसकी दो विपरीत सतहों पर ऊपर की ओर इशारा करते हुए काले लंबवत तीरों की एक जोड़ी अंकित है। भेजने वाले के कागजात सही हैं, लेकिन मैं पुष्टि करना चाहता हूँ कि मैं इसे सही ढंग से रख रहा हूँ। ये दिशा-तीर मुझसे इस पैकेज के साथ क्या करने की माँग करते हैं?","options":["पैकेज को हर समय सीधा (खड़ा) रखें, तीर ऊपर की ओर हों, ताकि ढक्कन और मुँह ऊपर की ओर रहें","पैकेज को बगल में लिटा दें ताकि तीर क्षैतिज रूप से ट्रेलर की दीवार की ओर इशारा करें","जैसे फिट हो वैसे रख दें, क्योंकि तीर केवल यह दिखाते हैं कि फोर्कलिफ्ट को इसे कहाँ से उठाना है","पैकेज को उल्टा कर दें ताकि सीलबंद सिरा ट्रेलर के फर्श पर टिका रहे"],"explanation":"पैकेज दिशा-तीर का अर्थ है कि पैकेज को तीर ऊपर की ओर रखते हुए सीधा रखना चाहिए ताकि ढक्कन ऊपर रहें।"},"166":{"q":"मैं एक नया हैज़मैट चालक हूँ और एक संक्षारक (कोरोसिव) माल के शिपिंग पेपर की यात्रा-पूर्व समीक्षा कर रहा हूँ। मैं प्रत्येक प्रविष्टि के लिए उचित शिपिंग नाम और खतरा वर्ग स्पष्ट रूप से देख सकता हूँ। निकलने से पहले यह पुष्टि करने के लिए कि विवरण पूर्ण और संघीय नियमों के अनुरूप है, इस बुनियादी शिपिंग विवरण में और कौन सी शेष जानकारी अवश्य होनी चाहिए?","options":["संक्षारक माल का कुल घोषित डॉलर मूल्य","सामग्री के लिए पहचान संख्या (UN या NA)","मेरे CDL पर दर्शाई गई सकल वाहन भार रेटिंग","मेरे हैज़मैट समर्थन की समाप्ति तिथि"],"explanation":"पूर्ण मूल शिपिंग विवरण में उचित शिपिंग नाम, खतरा श्रेणी और UN या NA पहचान संख्या इसी क्रम में होते हैं।"},"167":{"q":"मैं एक माल की शिपिंग पेपर्स (परिवहन दस्तावेज़) की जाँच कर रहा हूँ और देखता हूँ कि सामग्री की प्रविष्टि के पास उसके पैकिंग ग्रुप (Packing Group) के रूप में रोमन अंक 'II' लिखा है। एक नया चालक मुझसे पूछता है कि यह 'II' वास्तव में इस माल के बारे में हमें क्या बता रहा है। निम्नलिखित में से कौन सा पैकिंग ग्रुप के अर्थ की सही व्याख्या है?","options":["यह सामग्री को सौंपा गया खतरा वर्ग संख्या (1 से 9) बताता है","यह वह न्यूनतम सकल वजन बताता है जिस पर प्लेकार्ड लगाना आवश्यक हो जाता है","यह सामग्री द्वारा प्रस्तुत खतरे की सापेक्ष मात्रा (I, II, या III) दर्शाता है","यह शिपिंग नाम के बाद आने वाला UN/NA पहचान संख्या बताता है"],"explanation":"पैकिंग समूह, जो रोमन अंक I, II या III में दर्शाया जाता है, सामग्री द्वारा प्रस्तुत खतरे की सापेक्ष मात्रा बताता है।"},"168":{"q":"मैं एक खतरनाक माल (HazMat) की खेप लोड कर रहा हूँ और शिपिंग पेपर पर सामग्री का पैकिंग समूह \"PG I\" (पैकिंग समूह I) लिखा है। एक नया ड्राइवर मुझसे कहता है कि रोमन अंक \"I\" का मतलब बस यह है कि यह सूची में पहली वस्तु है और यह तीनों पैकिंग समूहों में सबसे कम खतरे के स्तर को दर्शाता है। माल पर हस्ताक्षर करने और प्लेकार्ड लगाने से पहले, \"पैकिंग समूह I\" वास्तव में मुझे इस सामग्री के खतरे की मात्रा के बारे में क्या बताता है?","options":["यह सबसे कम खतरे की मात्रा दर्शाता है, क्योंकि पैकिंग समूह I सबसे निचला स्तर है और पैकिंग समूह III सबसे अधिक खतरनाक है","यह केवल मध्यम खतरे की मात्रा दर्शाता है, जो पैकिंग समूह II और पैकिंग समूह III के बीच आता है","यह किसी वास्तविक खतरे को नहीं दर्शाता और इसका उपयोग केवल शिपिंग पेपर पर वस्तु की स्थिति दिखाने के लिए होता है","यह सबसे अधिक खतरे की मात्रा दर्शाता है, क्योंकि पैकिंग समूह I तीनों पैकिंग समूहों में सबसे अधिक खतरनाक है"],"explanation":"पैकिंग समूह I सबसे अधिक खतरे की मात्रा दर्शाता है, क्योंकि यह तीनों पैकिंग समूहों में सबसे खतरनाक है।"},"169":{"q":"मैं एक मिश्रित खतरनाक माल वाला ट्रेलर लोड कर रहा हूँ और देखता हूँ कि मेरे दो पैकेजों के खतरा वर्ग (हैज़र्ड क्लास) अलग-अलग हैं। उन्हें अगल-बगल रखने से पहले, मैं पृथक्करण (सेग्रिगेशन) तालिका निकालता हूँ। यह तालिका वास्तव में मुझे क्या बता रही है?","options":["कौन-से माल असंगत हैं और एक ही लोड में एक साथ लोड नहीं किए जाने चाहिए","कौन-से माल हमेशा एक साथ लोड किए जाने चाहिए ताकि उनके प्लेकार्ड मेल खाएँ","मेरी देयता कम करने के लिए कौन-से माल पहले बेचे या डिलीवर किए जाने चाहिए","दरवाज़े बंद करने से पहले कौन-से माल को दूसरी बार लेबल किया जाना चाहिए"],"explanation":"पृथक्करण तालिका दर्शाती है कि कौन-सी सामग्रियां असंगत हैं और एक ही लदान में एक साथ नहीं लादी जानी चाहिए।"},"170":{"q":"मैं शिपर के लोडिंग डॉक पर हूँ और अपने प्लेकार्ड लगे ट्रेलर में क्लास 8 के संक्षारक (corrosive) पदार्थ के कई ड्रम लादने वाला हूँ। पहला ड्रम हिलाते समय मुझे उसके निचले जोड़ के चारों ओर एक गीली, चमकती परत और पैलेट पर एक छोटा सा रिसाव का तालाब दिखता है। इनमें से कोई भी पैकेज लादने से पहले, मेरे लोडिंग-पूर्व निरीक्षण को जिस एकमात्र सबसे महत्वपूर्ण बात की पुष्टि करनी चाहिए, वह क्या है?","options":["कि प्रत्येक ड्रम चमकीले, अत्यधिक दिखने वाले रंग से पुता हो ताकि उसे ट्रेलर में आसानी से देखा जा सके","कि पैकेज रिस नहीं रहे और क्षतिग्रस्त नहीं हैं, क्योंकि रिसाव या टूट-फूट दिखाने वाले किसी भी कंटेनर को मुझे अस्वीकार करना होगा","कि ड्रम जितना संभव हो उतना ऊँचा रखे गए हों ताकि लदान कसा रहे और रास्ते में न खिसके","कि बंग (ढक्कन) ढीले या खुले छोड़ दिए गए हों ताकि यात्रा के दौरान अंदरूनी दबाव निकल सके"],"explanation":"लादने से पहले प्रत्येक पैकेज की जांच करें कि वह रिस या क्षतिग्रस्त न हो, और रिसाव या टूट दिखाने वाले किसी भी कंटेनर को अस्वीकार करें।"},"171":{"q":"मैं एक चालक हूं जो व्यस्त टर्मिनल यार्ड में अपने ट्रेलर पर ज्वलनशील तरल (क्लास 3) लोड कर रहा हूं। मेरे चारों ओर एक साथ कई चीजें हो रही हैं, और मैं सुरक्षित रूप से लोड करना चाहता हूं। इस हैज़मैट को लोड करते समय निम्नलिखित में से किसे मुझे कार्गो क्षेत्र से दूर रखना चाहिए?","options":["डॉक चालक दल द्वारा उपयोग किया जाने वाला पैलेट जैक","बगल के डॉक पर निष्क्रिय (आइडलिंग) खड़ा एक डिलीवरी ट्रक","खुली लौ या चिंगारी पैदा करने वाला स्रोत","खाली लकड़ी के पैलेटों का ढेर"],"explanation":"लादने के दौरान खुली लपटों और चिंगारी पैदा करने वाले स्रोतों को खतरनाक सामग्री से दूर रखें, क्योंकि ज्वलनशील सामग्री किसी भी प्रज्वलन स्रोत से आग पकड़ सकती है।"},"172":{"q":"मैं एक लंबी अंतर-राज्यीय यात्रा के लिए अपने बंद वैन में प्लेकार्ड वाले खतरनाक माल के कई ड्रम और बक्से लाद रहा हूँ। उन्हें अंदर चढ़ाने के बाद, दरवाजे बंद करके चलने से पहले मुझे इन कंटेनरों के साथ क्या करना चाहिए?","options":["उन्हें ट्रेलर की अगली दीवार से सटाकर रखें और भरोसा करें कि यात्रा के दौरान अगली दीवार उन्हें अपनी जगह पर बनाए रखेगी","वजन संतुलित करने के लिए उन्हें फर्श पर समान रूप से फैला दें, फिर भरोसा करें कि सामान्य फर्श घर्षण उन्हें टिकाए रखेगा","बाकी माल के लिए फर्श की जगह खाली करने हेतु उन्हें एक ही बगल की दीवार से सटाकर जितना ऊँचा हो सके ढेर कर दें","प्रत्येक कंटेनर को इस तरह से सहारा देकर सुरक्षित करें कि वाहन के चलते समय वह खिसक, फिसल या पलट न सके"],"explanation":"प्रत्येक खतरनाक सामग्री कंटेनर को इस तरह सहारा देकर सुरक्षित करें कि वाहन चलते समय वह खिसक, फिसल या पलट न सके।"},"173":{"q":"मैं खतरनाक अपशिष्ट का माल ढो रहा हूँ और टर्मिनल से निकलने से पहले शिपर मुझे बाकी कागज़ात के साथ एक खतरनाक अपशिष्ट मैनिफेस्ट सौंपता है। खतरनाक सामग्री नियमों का पालन करने के लिए मुझे उस मैनिफेस्ट के साथ क्या करना चाहिए?","options":["उस पर हस्ताक्षर करूँ और एक प्रति अपने शिपिंग कागज़ात के साथ पहुँच के भीतर रखूँ","हस्ताक्षरित अवस्था में उसे टर्मिनल पर छोड़ दूँ ताकि कैरियर मेरे लिए उसे दाखिल कर सके","उसे बिना हस्ताक्षर के तब तक ले जाऊँ जब तक डिलीवरी पर प्राप्तकर्ता सुविधा हस्ताक्षर न कर दे","यात्रा समाप्त होने के बाद हस्ताक्षरित प्रति राज्य एजेंसी को डाक से भेज दूँ"],"explanation":"खतरनाक अपशिष्ट मैनिफेस्ट पर चालक के हस्ताक्षर होने चाहिए और इसे ड्राइविंग के दौरान पहुंच के भीतर शिपिंग कागजात के साथ रखना चाहिए।"},"174":{"q":"मैं एक नया H-समर्थन वाला चालक हूँ, और एक शिपर मुझे एक ऐसे पदार्थ के कागज़ात देता है जिसे नियम विशेष रूप से ऐसे पदार्थ के रूप में सूचीबद्ध करते हैं जिसे किसी भी परिस्थिति में किसी भी वाणिज्यिक वाहन द्वारा बिल्कुल नहीं ले जाया जा सकता। कुछ भी और करने से पहले, इस भार के बारे में सोचने का सही तरीका क्या है?","options":["इसे किसी भी मात्रा में ढोया जा सकता है बशर्ते मैं ट्रेलर के चारों ओर प्लेकार्ड लगा दूँ","इसका परिवहन निषिद्ध है, इसलिए कोई भी चालक इसे कानूनी रूप से बिल्कुल नहीं ले जा सकता","इसे स्वतंत्र रूप से ढोया जा सकता है क्योंकि मेरा H समर्थन हर खतरा वर्ग को कवर करता है","इसे कभी प्लेकार्ड की ज़रूरत नहीं होती, इसलिए मैं इसे बिना किसी को सूचित किए ले जा सकता हूँ"],"explanation":"कुछ सामग्रियां इतनी खतरनाक होती हैं कि उनका परिवहन पूरी तरह प्रतिबंधित है और कोई भी उन्हें कानूनी रूप से नहीं ढो सकता।"},"175":{"q":"मैं वर्ग 1 विस्फोटक के रूप में चिह्नित एक खेप लोड कर रहा हूं, और शिपिंग पेपर पर सामग्री को वर्ग के तुरंत बाद एक डिवीजन संख्या के साथ सूचीबद्ध किया गया है। एक सहकर्मी मुझसे कहता है कि वर्ग 1 एक एकल अविभाजित श्रेणी है, इसलिए डिवीजन संख्या निश्चित रूप से एक टाइपिंग त्रुटि होगी। कौन सा कथन सही ढंग से बताता है कि वर्ग 1 कैसे संरचित है?","options":["वर्ग 1 एक एकल अविभाजित श्रेणी है, इसलिए इसके बाद कोई भी डिवीजन संख्या एक त्रुटि है","वर्ग 1 को पैकेजिंग रंग कोड के आधार पर ठीक दो समूहों में बांटा गया है","वर्ग 1 को कई डिवीजनों में बांटा गया है, जिन्हें 1.1 से 1.6 तक क्रमांकित किया गया है","वर्ग 1 का कोई उपसमूह नहीं है; डिवीजन केवल वर्ग 2 की गैसों के लिए मौजूद हैं"],"explanation":"खतरा वर्ग 1 (विस्फोटक) को 1.1 से 1.6 तक क्रमांकित कई डिवीजनों में बांटा गया है।"},"176":{"q":"एक माल टर्मिनल पर, एक डिस्पैचर मुझे \"डिवीजन 1.1\" लेबल वाले माल के शिपिंग कागजात देता है और पूछता है कि प्लेकार्ड लगाने और मार्ग तय करने से पहले मुझे विस्फोट की संभावना को कितनी गंभीरता से लेना चाहिए। खतरे का डिवीजन मुझे जो बताता है, उसके आधार पर कौन-सा कथन मेरे निर्णय को निर्देशित करना चाहिए?","options":["इसमें केवल प्रक्षेपण खतरा होता है, इसलिए मैं पूर्ण विस्फोट के बजाय मुख्य रूप से उड़ते टुकड़ों के लिए योजना बनाता हूँ","यह केवल मामूली आग का जोखिम पैदा करता है, इसलिए एक मानक अग्निशामक और सावधानीपूर्वक ईंधन भरना ही मुझे वास्तव में चाहिए","इसमें केवल पैकेज तक सीमित हल्का विस्फोट खतरा है, इसलिए इमारतों से दूरी कोई बड़ी चिंता नहीं है","यह एक सामूहिक विस्फोट खतरा प्रस्तुत करता है, जिसका अर्थ है कि पूरा माल एक साथ विस्फोट कर सकता है, इसलिए मुझे इसे सबसे खतरनाक विस्फोटक डिवीजन के रूप में मानना चाहिए"],"explanation":"डिवीजन 1.1 विस्फोटक मास विस्फोट का खतरा पेश करते हैं जहां पूरा भार एक साथ फट सकता है, जो उन्हें सबसे खतरनाक विस्फोटक डिवीजन बनाता है।"},"177":{"q":"मैं प्लेकार्ड लगा हुआ डिवीजन 1.2 विस्फोटक भार ढो रहा हूँ और एक छोटे कस्बे में भोजन के लिए रुकना है। चालक के रूप में, इस भार के नियमों के अनुसार कौन-सी क्रिया मुझे कानूनी रखती है?","options":["वाहन के साथ रहना, या किसी योग्य व्यक्ति से उसकी निगरानी कराना, ताकि भार कभी भी बिना निगरानी के न छूटे","केबिन को लॉक करना, ब्रेक लगाना और अंदर भोजन करते समय वाहन को रेस्तरां की पार्किंग में छोड़ देना","खिड़की से नज़र रखने के लिए वाहन को सड़क के यातायात वाले हिस्से के 5 फुट के भीतर खड़ा करना","जब तक वह किसी इमारत के बगल में खड़ा है, भार को 2 घंटे तक बिना निगरानी के छोड़ देना"],"explanation":"डिवीजन 1.1, 1.2 और 1.3 विस्फोटकों को कभी लावारिस नहीं छोड़ना चाहिए; चालक या कोई अन्य योग्य व्यक्ति हर समय भार के साथ रहकर उस पर नजर रखे।"},"178":{"q":"मैं डिवीजन 1.1 विस्फोटक सामग्री ढो रहा हूँ जब एक दो-लेन वाले सार्वजनिक राजमार्ग पर मेरे ट्रेलर में एक यांत्रिक खराबी आ जाती है। कंपनी का दूसरा ट्रक मौके पर आता है, और मेरा डिस्पैचर चाहता है कि मैं विस्फोटक माल को दूसरे वाहन में स्थानांतरित कर दूँ ताकि माल आगे बढ़ता रहे। खतरनाक सामग्री नियमों के अनुसार, मुझे वाहनों के बीच यह स्थानांतरण कहाँ करने की अनुमति है?","options":["यहीं राजमार्ग के किनारे पर, क्योंकि दूसरा ट्रक पहले से ही मौके पर है और माल लेने के लिए तैयार है","जब तक कोई वास्तविक आपातकाल न हो, सार्वजनिक सड़क पर बिल्कुल नहीं — स्थानांतरण टर्मिनल या डिपो जैसी सड़क से दूर सुरक्षित जगह पर किया जाना चाहिए","मार्ग पर कहीं भी, जब तक मैं स्थानांतरण के दौरान दोनों वाहनों के चारों ओर उचित प्लेकार्ड लगाता हूँ","यहाँ सड़क पर करना ठीक है, क्योंकि मेरे डिस्पैचर ने माल को चलता रखने का सीधा आदेश दिया है"],"explanation":"वर्ग 1 विस्फोटकों को वास्तविक आपात स्थिति को छोड़कर सार्वजनिक सड़क पर वाहनों के बीच स्थानांतरित नहीं किया जा सकता; स्थानांतरण टर्मिनल जैसी सुरक्षित, सड़क से हटकर जगह पर करना चाहिए।"},"179":{"q":"मैं डिवीजन 1.2 विस्फोटक ले जा रहा हूँ और मुझे आराम करने के लिए रुकना है। आगे मुझे एक विश्राम स्थल दिखता है जहाँ किसी ने सड़क किनारे अलाव जला रखा है। दूरी के नियम मेरे दिमाग में घूम रहे हैं। मुझे अपने पार्क किए गए विस्फोटक भार और उस खुली आग के बीच कम से कम कितनी दूरी रखनी चाहिए?","options":["5 फीट, वही न्यूनतम दूरी जो मुझे सड़क के यातायात वाले हिस्से से रखनी होती है","10 फीट, बस इतना दूर कि उड़ती चिंगारियों से बचा जा सके","300 फीट, विस्फोटक और खुली आग के बीच आवश्यक दूरी","1 फीट, क्योंकि आग अलाव के घेरे के अंदर सीमित है"],"explanation":"विस्फोटक ले जाने वाले वाहन को खुली आग से कम से कम 300 फीट दूर पार्क करना चाहिए।"},"180":{"q":"रवाना होने से पहले मैं एक क्लास 2 गैस लोड के शिपिंग कागजात की जांच कर रहा हूं, यह पुष्टि करने की कोशिश में कि मैं कौन सा डिवीजन ढो रहा हूं। मुझे पता है कि क्लास 2 में एक से अधिक प्रकार की गैस शामिल है, और कैरियर ने मुझे बताया कि क्लास 2 के तीन मान्यता प्राप्त डिवीजन हैं: ज्वलनशील गैस (2.1), गैर-ज्वलनशील गैस (2.2), और एक तीसरा डिवीजन जिसे मुझे प्लेकार्ड लगाने के लिए पहचानना है। निम्नलिखित में से कौन सा क्लास 2 गैसों का वह तीसरा मान्यता प्राप्त डिवीजन है?","options":["ज्वलनशील ठोस गैस, क्योंकि कुछ क्लास 2 गैसें एक दहनशील ठोस रूप में बस सकती हैं","संक्षारक (corrosive) गैस, क्योंकि टैंकों में दबाव वाली गैसें क्लास 8 संक्षारक सामग्री की तरह व्यवहार करती हैं","केवल-तरल गैस, क्योंकि दबाव में संग्रहीत गैसें हमेशा तरल अवस्था में ले जाई जाती हैं","जहरीली (विषैली) गैस, जो डिवीजन 2.3 है और किसी भी मात्रा में प्लेकार्ड की आवश्यकता हो सकती है"],"explanation":"वर्ग 2 गैसों में जहरीली (विषाक्त) गैस डिवीजन 2.3 के रूप में शामिल है, जो एक टेबल 1 सामग्री है जिसके लिए किसी भी मात्रा में प्लेकार्ड आवश्यक हैं।"},"181":{"q":"एक विश्राम पड़ाव के दौरान, मुझे पता चलता है कि मेरे प्लेकार्ड लगे माल पर रखे संपीड़ित गैस सिलेंडरों में से एक में धीमा रिसाव हो गया है और वाल्व के पास से सीटी जैसी आवाज आ रही है। पास के पार्किंग क्षेत्र में यात्री इधर-उधर घूम रहे हैं। निम्नलिखित में से कौन सी सबसे उपयुक्त तत्काल कार्रवाई है?","options":["लोगों को सिलेंडर से दूर ले जाएं, क्षेत्र को खाली रखें, और आपातकालीन सहायता के लिए कॉल करें","वाल्व को कस दें और रिसाव को स्वयं सील कर दें ताकि गैस निकलना बंद हो जाए","सिलेंडर को थोड़ा गर्म करें ताकि दबाव संतुलित हो जाए और सीटी की आवाज रुक जाए","वाल्व को फिर से बैठाने और दबाव कम करने के लिए सिलेंडर को लुढ़काएं और हिलाएं"],"explanation":"रिसाव वाले संपीड़ित-गैस सिलेंडर के लिए, लोगों को दूर हटाएं, क्षेत्र को साफ रखें, प्रज्वलन स्रोतों को रोकें, और इसे खुद ठीक करने के बजाय आपातकालीन सहायता बुलाएं।"},"182":{"q":"मैं एक क्लास 7 रेडियोधर्मी शिपमेंट लोड कर रहा हूँ, और शिपर मुझे रेडियोधर्मी लेबल वाले पैकेज सौंपता है। प्रत्येक लेबल पर एक नंबर दिखता है जो मुझे पैकेज के विकिरण स्तर के बारे में बताता है। इन क्लास 7 लेबलों पर मुझे कौन-सी क्रमांकन प्रणाली दिखाई देगी?","options":["लेबलों को A, B या C से क्रमांकित किया जाता है, जो पैकेज के परिवहन सूचकांक से मेल खाता है","लेबलों को I, II या III से क्रमांकित किया जाता है, जो पैकेज के विकिरण स्तर को दर्शाता है","लेबलों को 1 से 9 तक क्रमांकित किया जाता है, जो खतरा वर्ग प्रणाली से मेल खाता है","लेबलों को X, Y या Z से क्रमांकित किया जाता है, जो पैकिंग समूह अक्षर से मेल खाता है"],"explanation":"वर्ग 7 रेडियोधर्मी सामग्री पैकेज के विकिरण स्तर को इंगित करने के लिए रोमन अंक I, II, या III से चिह्नित तीन लेबल श्रेणियों का उपयोग करती है।"},"183":{"q":"मैं कई वर्ग 7 रेडियोधर्मी पैकेज लोड कर रहा हूँ, और शिपर मुझे हर लेबल पर छपे 'ट्रांसपोर्ट इंडेक्स' नंबर की ओर इशारा करता है। अपने ट्रेलर को सुरक्षित और कानूनी रूप से लोड करने के लिए, यह ट्रांसपोर्ट इंडेक्स मान वास्तव में मुझे क्या बताता है?","options":["बीमा उद्देश्यों के लिए रेडियोधर्मी सामग्री का कुल मौद्रिक मूल्य","गाड़ी में मौजूद सभी रेडियोधर्मी पैकेजों का संयुक्त सकल वजन","पैकेज को संभालते और परिवहन करते समय आवश्यक विकिरण नियंत्रण की मात्रा","उस रेडियोधर्मी सामग्री को सौंपा गया UN/NA पहचान संख्या"],"explanation":"क्लास 7 रेडियोधर्मी पैकेज पर ट्रांसपोर्ट इंडेक्स बताता है कि उसे संभालने और लादने के दौरान कितने रेडिएशन नियंत्रण की आवश्यकता है।"},"184":{"q":"मैं प्लेकार्ड लगे संक्षारक (corrosive) माल का एक भार शहर के पार ले जा रहा हूँ और मेरा जीपीएस एक ही गंतव्य तक तीन संभावित मार्ग दिखा रहा है, सभी लगभग एक समान दूरी के। टेक्सास के खतरनाक माल मार्ग दिशानिर्देशों के अनुसार, मुझे इनमें से कौन सा चुनने का सबसे अधिक प्रयास करना चाहिए?","options":["वह मार्ग जो एक लंबी भूमिगत सुरंग से होकर गुजरता है, क्योंकि इससे सतह की ट्रैफिक लाइटें टल जाती हैं और कुछ मिनट बच जाते हैं","वह मार्ग जो ठीक उसी समय भीड़ भरे डाउनटाउन स्टेडियम के पास से गुजरता है जब कोई आयोजन समाप्त हो रहा हो","वह मार्ग जो चौड़ी, अच्छी रोशनी वाली सड़कों पर बने रहने के लिए कई भीड़भाड़ वाले शॉपिंग प्लाज़ा के पास से घूमकर जाता है","वह मार्ग जो खुली आर-पार जाने वाली सड़कों पर बना रहता है और सुरंग तथा भीड़भाड़ वाले आयोजन क्षेत्रों दोनों को टाल देता है"],"explanation":"खतरनाक माल के चालकों को निर्धारित मार्गों का पालन करना चाहिए जो जहां भी संभव हो सुरंगों और घनी आबादी वाले या भीड़भाड़ वाले क्षेत्रों से बचें।"},"185":{"q":"मुझे प्रभाग 1.1 विस्फोटकों का एक भार पूरे राज्य में ले जाने के लिए भेजा गया है। मेरे प्रशिक्षक का कहना है कि इस यात्रा से पहले, संघीय नियमों के अनुसार मेरे वाहक को एक विशेष लिखित दस्तावेज़ तैयार करना आवश्यक है, जिसे मुझे साथ रखना और उसका पालन करना होगा। वह किस दस्तावेज़ की बात कर रहा है?","options":["एक लिखित मार्ग योजना जिसका यात्रा को पालन करना चाहिए","चालक का एक लिखित दैनिक ईंधन और मील-यात्रा लॉग","विस्फोटक माल के लिए एक लिखित बिक्री अनुबंध","सड़क के लिए एक लिखित 72-घंटे का मौसम पूर्वानुमान"],"explanation":"विस्फोटकों (डिवीजन 1.1, 1.2, 1.3) के माल को वाहक द्वारा तैयार और चालक द्वारा रखे गए लिखित मार्ग योजना के अनुसार ले जाना चाहिए।"},"186":{"q":"मैं प्लैकार्ड (placard) लगे संक्षारक (corrosive) माल के साथ एक लंबी यात्रा के तीन घंटे बीत चुका हूं और अभी शौचालय इस्तेमाल करने के लिए एक विश्राम क्षेत्र में रुका हूं। मेरी यात्रा-पूर्व जांच के बाद से ट्रक ठीक चल रहा है, और जब मैं निकला था तब टायर अच्छे दिख रहे थे। राजमार्ग पर वापस जाने से पहले मुझे अपने टायरों के बारे में क्या करना चाहिए?","options":["कुछ नहीं — एक गहन यात्रा-पूर्व टायर जांच पूरी यात्रा के लिए मुझे कवर कर देती है, जब तक कोई टायर वास्तव में पंक्चर न हो जाए","अभी टायरों का निरीक्षण करें, क्योंकि मुझे उन्हें यात्रा के आरंभ में और फिर हर 2 घंटे या हर 100 मील पर जांचना चाहिए","उन्हें केवल तभी जांचें जब टायर-दबाव चेतावनी लाइट जले या मुझे लगे कि ट्रक एक तरफ खिंच रहा है","प्रतीक्षा करें और टायरों का निरीक्षण दिन में एक बार करें, जो लंबी यात्रा पर प्लैकार्ड वाले माल के लिए पर्याप्त है"],"explanation":"प्लेकार्ड वाले खतरनाक माल को ले जाने वाले चालक को टायरों का निरीक्षण यात्रा की शुरुआत में और हर पड़ाव पर, यानी हर 2 घंटे या 100 मील पर करना चाहिए।"},"187":{"q":"मैं अपने प्लेकार्ड लगे टैंकर को अपने रूट के अगले चरण से पहले डीज़ल भरवाने के लिए फ्यूल आइलैंड पर ले जाता हूँ। जब मैं पंपिंग शुरू करने की तैयारी करता हूँ, तो निम्नलिखित में से कौन सा विकल्प बताता है कि नियमों का पालन करने के लिए मुझे इंजन और ईंधन भरने की प्रक्रिया को कैसे संभालना चाहिए?","options":["इंजन को धीमी गति पर चालू रखें ताकि एयर सिस्टम चार्ज रहे, और नोज़ल को खुद संभालें","इंजन बंद कर दें, नोज़ल को ऑटोमैटिक पर लॉक कर दें, और टैंक भरते समय अंदर जाकर भुगतान करें","इंजन बंद कर दें और पूरी प्रक्रिया के दौरान एक व्यक्ति को नोज़ल पर शारीरिक रूप से मौजूद रखें जो ईंधन के बहाव को नियंत्रित करे","ट्रांसफर पंप को बिजली देने के लिए इंजन को तेज़ गति पर चालू रखें, और नोज़ल पर किसी की ज़रूरत नहीं"],"explanation":"प्लेकार्ड वाले वाहन में ईंधन भरते समय इंजन बंद होना चाहिए और किसी को पूरे समय नोज़ल पर रहकर ईंधन के प्रवाह को नियंत्रित करना चाहिए।"},"188":{"q":"यदि आपको हैजमैट का रिसाव मिले, तो आपको नहीं करना चाहिए:","options":["दूसरों को चेतावनी देना","उसे छूना या साँस के साथ अंदर लेना","लोगों को दूर रखना","मदद के लिए बुलाना"],"explanation":"रिसने वाली सामग्री को कभी न छुएँ और न ही साँस के साथ अंदर लें।"},"189":{"q":"आप संक्षारक तरल (corrosive liquid) का प्लेकार्ड लगा हुआ भार ढो रहे हैं, तभी एक ड्रम से राजमार्ग के किनारे पर भारी रिसाव शुरू हो जाता है, जिससे एक गंभीर खतरनाक पदार्थ का रिसाव हो जाता है। दूसरों को सावधान करने, लोगों को दूर रखने और धूम्रपान रोकने के बाद, आपका वाहक आपको इस गंभीर घटना की अनिवार्य सूचना राष्ट्रीय प्रतिक्रिया केंद्र (National Response Center) को देने का निर्देश देता है। घटना की सूचना देने के लिए आप किस नंबर पर कॉल करते हैं?","options":["411, डायरेक्टरी सहायता लाइन, ताकि आपको निकटतम खतरनाक पदार्थ प्रतिक्रिया इकाई से जोड़ा जा सके","911, स्थानीय आपातकालीन लाइन, जो राष्ट्रीय प्रतिक्रिया केंद्र की सूचना देने की आवश्यकता को पूरी तरह पूरा करती है","1-800-555-1212, टोल-फ्री लाइन जो रिपोर्ट को उपयुक्त संघीय एजेंसी तक पहुंचाती है","1-800-424-8802, गंभीर खतरनाक पदार्थ घटनाओं की सूचना देने के लिए राष्ट्रीय प्रतिक्रिया केंद्र की लाइन"],"explanation":"गंभीर खतरनाक माल की घटनाओं की सूचना राष्ट्रीय प्रतिक्रिया केंद्र (National Response Center) को 1-800-424-8802 पर देनी चाहिए।"},"190":{"q":"किसी सुनसान सड़क किनारे मेरे प्लेकार्ड लगे ट्रेलर पर रखे एक ड्रम से संक्षारक (कॉरोसिव) तरल का रिसाव शुरू हो जाता है, और मुझे बिल्कुल पता नहीं कि इस रसायन का क्या करूँ या इसे कैसे निष्प्रभावी करूँ। दूसरों को सचेत करने और लोगों को दूर रखने के बाद, इस विशेष खतरनाक पदार्थ को संभालने पर 24 घंटे की आपातकालीन सलाह पाने के लिए मुझे किस नंबर पर कॉल करना चाहिए?","options":["1-800-424-9300, CHEMTREC आपातकालीन लाइन","1-800-275-8777, राष्ट्रीय शिपिंग और डाक हेल्पलाइन","1-888-275-8255, संघीय राजमार्ग सुरक्षा रिपोर्ट लाइन","1-800-829-1040, संघीय एजेंसी सूचना लाइन"],"explanation":"CHEMTREC 1-800-424-9300 पर 24 घंटे की आपातकालीन लाइन चलाता है जो किसी घटना में खतरनाक माल को संभालने के लिए चालकों को तुरंत तकनीकी मार्गदर्शन देता है।"},"191":{"q":"मैं टेक्सास में सीट बेल्ट बांधकर संक्षारक (कॉरोसिव) माल का प्लेकार्ड लोड चला रहा हूं। एक DPS अधिकारी मुझे रोककर मेरे हज़मैट शिपिंग कागज़ात के बारे में पूछता है। हैंडबुक के नियमों के अनुसार, गाड़ी चलाते समय वे कागज़ात कहां होने चाहिए थे?","options":["एक जलरोधी लिफाफे में सील करके ट्रेलर में माल के साथ रखे हुए","मेरी पहुंच के भीतर और साफ़ दिखाई देते हुए, मेरे बाकी कागज़ात के ऊपर रखे हुए","चालक सीट के पीछे बंक पर मेरी लॉगबुक बाइंडर के अंदर ज़िप किए हुए","कैबिन में सेंधमारी होने पर सुरक्षित रहने के लिए ग्लव बॉक्स में तालाबंद किए हुए"],"explanation":"वाहन चलाते समय खतरनाक माल के शिपिंग कागजात चालक की पहुंच के भीतर और बाकी कागजों के ऊपर साफ दिखाई देने वाली जगह पर रखे जाने चाहिए।"},"192":{"q":"मैं प्लेकार्ड लगा हुआ खतरनाक माल (HazMat) ले जा रहा हूँ और शौचालय उपयोग करने के लिए एक विश्राम क्षेत्र में रुकता हूँ। मैं इंजन बंद करके कुछ मिनटों के लिए केबिन से बाहर रहूँगा। टेक्सास DPS नियमों के अनुसार, जब मैं ट्रक से दूर रहूँ तो मेरे शिपिंग दस्तावेज़ कहाँ होने चाहिए?","options":["ग्लव बॉक्स में ताला लगाकर रखे जाएँ ताकि मेरी अनुपस्थिति में कोई छेड़छाड़ न कर सके","मेरी शर्ट की जेब में मोड़कर रखे जाएँ और विश्राम क्षेत्र में मेरे साथ ले जाए जाएँ","चालक की सीट पर या चालक के दरवाज़े की जेब में स्पष्ट रूप से दिखाई देते हुए छोड़े जाएँ","आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) के पास साइड कार्गो डिब्बे में रखे जाएँ"],"explanation":"जब चालक केबिन से बाहर जाता है, तो खतरनाक माल के शिपिंग कागजात चालक की सीट पर या चालक के दरवाजे की थैली में साफ दिखाई देने वाली जगह छोड़े जाने चाहिए।"},"193":{"q":"मैं एक विश्राम स्थल (rest area) पर खड़ा हूँ और मेरे ट्रेलर पर श्रेणी 3 की ज्वलनशील तरल वस्तुओं के लिए प्लेकार्ड (placard) लगे हैं। कुछ चालक मेरे ट्रक के पास खड़े बातें कर रहे हैं और एक चालक सिगरेट जला लेता है। अपने प्लेकार्ड वाले माल के लिए संघीय धूम्रपान नियम का पालन करने हेतु, सभी को जलती सिगरेट मेरे वाहन से कम से कम कितनी दूरी पर रखनी चाहिए?","options":["कम से कम 5 फुट, वही दूरी जो प्लेकार्ड वाले माल के साथ सड़क के चालू भाग से दूर पार्क करते समय आवश्यक होती है","कम से कम 2 फुट, क्योंकि ज्वलनशील तरल टैंक के भीतर सील बंद है और बहुत कम खतरा पैदा करता है","कम से कम 100 गज, वही दूरी जो रेलवे क्रॉसिंग पर बिना निगरानी छोड़े गए विस्फोटकों से रखी जाती है","वाहन से कम से कम 25 फुट, क्योंकि ज्वलनशील माल की इस सीमा के भीतर धूम्रपान की अनुमति नहीं है"],"explanation":"विस्फोटक, ऑक्सीकारक या ज्वलनशील माल ले जाने वाले प्लेकार्ड वाले वाहन के 25 फीट के भीतर धूम्रपान करना मना है।"},"194":{"q":"मैं एक नया ड्राइवर हूं जिसे टेक्सास भर में डिवीजन 1.1 विस्फोटकों का भार ढोने का काम सौंपा गया है। शिपर ने भार का वर्गीकरण और लेबलिंग पूरी कर ली है, और मेरे कैरियर ने यह यात्रा सौंपी है। यार्ड से निकलने से पहले, निम्नलिखित में से क्या मेरे पास केबिन में पहले से ही लिखित रूप में होना चाहिए?","options":["यात्रा के लिए एक लिखित मार्ग योजना और भार के शिपिंग पेपर्स","तौल कांटे से एक हस्ताक्षरित वजन पर्ची और मेरी ईंधन रसीद की एक प्रति","मार्ग के दौरान मैं जिन रेडियो चैनलों की निगरानी करूंगा उनकी लिखित सूची","मेरे रास्ते में पड़ने वाले हर काउंटी को कवर करने वाला नोटरीकृत मौसम पूर्वानुमान"],"explanation":"डिवीजन 1.1 विस्फोटक ले जाने से पहले, चालक को लदान कागजातों के साथ एक लिखित मार्ग योजना अपने पास रखनी चाहिए।"},"195":{"q":"मैं एक डॉक पर प्लेकार्ड लगे खतरनाक माल की खेप लोड कर रहा हूँ और अपने ट्रेलर पर चढ़ाने से पहले हर पैकेज का निरीक्षण कर रहा हूँ। शिपर मुझे चार कंटेनर देता है। मुझे किस एक को ले जाने से मना करना चाहिए?","options":["एक ड्रम जो कसकर सील किया गया है और जिसकी सीवन या ढक्कन पर कोई दिखाई देने वाली क्षति नहीं है","एक बाल्टी जिसके तल पर दरार से एक संक्षारक उत्पाद धीरे-धीरे रिस रहा है","एक कार्टन जिसकी बाहरी सतह पर सही खतरा वर्ग का लेबल लगा हुआ है","एक डिब्बा जो ठीक से बंद है और मेरे शिपिंग दस्तावेज़ों के विवरण से मेल खाता है"],"explanation":"चालक को किसी भी रिसते हुए खतरनाक माल की खेप लेने से इनकार करना चाहिए, जैसे दरार से उत्पाद रिसता हुआ कोई पैकेज।"},"196":{"q":"मेरे पास पहले से क्लास A CDL है और अब मैं संक्षारक पदार्थों के प्लेकार्ड लगे लदान ढोने के लिए H समर्थन (एंडोर्समेंट) जोड़ना चाहता हूं। टेक्सास DPS यह समर्थन जारी करने से पहले, कौन सी अतिरिक्त शर्त मुझे पूरी करनी होगी जो मेरी आधार CDL के लिए आवश्यक नहीं है?","options":["दूसरी DOT चिकित्सा जांच पास करना और एक अद्यतन चिकित्सा परीक्षक प्रमाणपत्र जमा करना","प्लेकार्ड लगे टैंक वाहन का उपयोग करके एक अलग वाहन-चालन कौशल परीक्षा पूरी करना","TSA सुरक्षा खतरा मूल्यांकन पास करना, जिसमें उंगलियों के निशान लेना और पृष्ठभूमि की जांच शामिल है","DPS में CDL दृष्टि जांच और सामान्य ज्ञान लिखित परीक्षा फिर से देना"],"explanation":"खतरनाक माल समर्थन के लिए विशेष रूप से TSA सुरक्षा खतरा मूल्यांकन पास करना आवश्यक है, जिसमें उंगलियों के निशान और पृष्ठभूमि जांच शामिल है।"},"197":{"q":"मेरे पास खतरनाक माल (HazMat, H) समर्थन के साथ टेक्सास CDL कई वर्षों से है और मैं हर चिकित्सा परीक्षा समय पर पास करता हूँ। एक नया चालक मुझसे कहता है कि एक बार जब मैंने TSA सुरक्षा खतरा मूल्यांकन पास करके H समर्थन प्राप्त कर लिया, तो मेरी क्रेडेंशियल का वह हिस्सा स्थायी है और जब तक मेरा मूल CDL वैध रहेगा, मुझे उससे फिर कभी निपटना नहीं पड़ेगा। मेरे खतरनाक माल समर्थन के बारे में कौन-सा कथन सही है?","options":["TSA खतरा मूल्यांकन पास होने के बाद यह जीवन भर के लिए तय हो जाता है, इसलिए उस हिस्से पर आगे कोई कार्रवाई कभी आवश्यक नहीं होती।","यह केवल तब तक वैध रहता है जब तक मैं अपनी DOT चिकित्सा परीक्षा पास करता रहूँ, जो इस समर्थन को नियंत्रित करती है।","जब तक मैं अपना मूल टेक्सास CDL सक्रिय रखता हूँ, यह स्वतः स्थानांतरित हो जाता है और कभी समाप्त नहीं होता।","इसे समय-समय पर नवीनीकृत करना आवश्यक है, जिसके लिए एक नए TSA सुरक्षा खतरा मूल्यांकन / पृष्ठभूमि जाँच से गुजरना पड़ता है।"],"explanation":"खतरनाक माल समर्थन की अवधि सीमित होती है और इसे नए TSA सुरक्षा खतरा मूल्यांकन को पास करके समय-समय पर नवीनीकृत करना पड़ता है।"},"198":{"q":"मैं प्लेकार्ड लगा हुआ संक्षारक (corrosive) माल ले जा रहा हूँ, तभी एक वाल्व खराब हो जाता है और उत्पाद सड़क के किनारे रिसने लगता है। मैं अपने केबिन से आपातकालीन प्रतिक्रिया गाइडबुक (ERG) निकालता हूँ। इस स्थिति में, ERG वास्तव में मुझे क्या करने में मदद करने के लिए बनाई गई है?","options":["सामग्री के खतरों और रिसाव के लिए सही प्रारंभिक कार्रवाई की पहचान करना ताकि मैं स्वयं और जनता की रक्षा कर सकूँ","खोए हुए उत्पाद के मौद्रिक मूल्य की गणना करना ताकि वाहक एक सटीक बीमा दावा दाखिल कर सके","डीजल बर्बाद न हो इसके लिए घटनास्थल के चारों ओर सबसे ईंधन-कुशल वैकल्पिक मार्ग निर्धारित करना","सफाई दल का इंतजार करते समय निकटतम स्वीकृत ठहरने और विश्राम क्षेत्र का पता लगाना"],"explanation":"आपातकालीन प्रतिक्रिया मार्गदर्शिका चालक को किसी पदार्थ के खतरों और रिसाव के लिए सही प्रारंभिक कार्रवाइयों की पहचान करने देती है ताकि वह स्वयं और जनता की रक्षा कर सके।"},"199":{"q":"एक दुर्घटना स्थल पर मेरे प्लेकार्ड लगे टैंक से रिसाव हो रहा है। एक अग्निशमन कर्मी दौड़कर आता है और मुझसे मेरे शिपिंग कागजात पर लिखा चार अंकों वाला पहचान संख्या (ID number) पढ़कर बताने को कहता है। एक को छोड़कर, नीचे दिए गए सभी विकल्प बताते हैं कि वह संख्या उसके लिए क्यों मायने रखती है। वह वास्तव में किस कारण से उसे चाहता है?","options":["यह उसे माल का डॉलर मूल्य बताता है ताकि वह वाहक का क्षति दावा दाखिल कर सके","यह उसे आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) में सामग्री को खोजकर सही प्रतिक्रिया प्रक्रियाएँ ज्ञात करने देता है","यह पुष्टि करता है कि मेरा H समर्थन और TSA पृष्ठभूमि जाँच इस भार के लिए वैध है","यह उचित शिपिंग नाम दिखाता है ताकि वह रेडियो पर डिस्पैचर को ज़ोर से पढ़कर बता सके"],"explanation":"चार अंकों का UN/NA पहचान संख्या प्रतिक्रियाकर्ता को आपातकालीन प्रतिक्रिया मार्गदर्शिका में पदार्थ खोजकर सही प्रतिक्रिया प्रक्रियाएं ज्ञात करने देती है।"},"200":{"q":"मैं प्लेकार्ड लगा हुआ माल ढो रहा हूँ, तभी मेरे ट्रेलर के नीचे से धुआँ निकलने लगता है और मैं देखता हूँ कि लपटें टायरों के साथ फैल रही हैं। मेरी कैब में एक छोटा अग्निशामक यंत्र है, लेकिन आग पहले ही इतनी बड़ी हो चुकी है कि मैं उसे सुरक्षित रूप से काबू नहीं कर सकता। नीचे दिए एक विकल्प को छोड़कर, सूचीबद्ध हर कार्रवाई इस स्थिति को और खतरनाक बना देगी। मुझे वास्तव में कौन-सी कार्रवाई करनी चाहिए?","options":["कार्गो के दरवाज़े खोलकर ठीक-ठीक देखना कि कौन-से ड्रम जल रहे हैं, ताकि मैं आपातकालीन कर्मियों को उनके बारे में बता सकूँ","अपना अग्निशामक यंत्र उठाकर खुद ही आग से लड़ता रहना जब तक वह पूरी तरह बुझ न जाए या मदद न पहुँच जाए","आसपास के लोगों को दूर रखना, हवा की दिशा के विपरीत (अपविंड) खड़ा रहना और तुरंत आपातकालीन कर्मियों को बुलाना","जलते हुए ट्रक को निकटतम शहर तक चलाकर ले जाना ताकि वहाँ के दमकलकर्मियों को मुझ तक पहुँचने में कम दूरी तय करनी पड़े"],"explanation":"जब चिह्नित खतरनाक माल में आग लगी हो और वह आपके नियंत्रण से बाहर हो, तो लोगों को दूर रखें, हवा की दिशा के विपरीत रहें और तुरंत आपातकालीन कर्मियों को बुलाएं।"},"201":{"q":"आप प्लेकार्ड (placard) लगे खतरनाक सामग्री (HazMat) का भार ढो रहे हैं और आपका GPS आपको सीधे एक लंबी हाईवे सुरंग से ले जा रहा है, जिससे लगभग एक घंटा बचेगा। आप निश्चित नहीं हैं कि आपकी सामग्री उस सुरंग में अनुमत है या नहीं। सुरंग के प्रवेश द्वार पर पहुँचने से पहले, आपको सबसे पहले क्या करना चाहिए?","options":["अपनी गति कम करें और दोनों लेन खाली रखें ताकि आप सुरंग से तेज़ी और सुरक्षित रूप से निकल सकें","प्रवेश करने से पहले प्लेकार्ड हटा दें ताकि सुरंग के कर्मचारी आपको अंदर न रोकें","सुरंग के प्रवेश द्वार के ठीक अंदर रुकें और अपने वाहक (carrier) को फोन करके पूछें कि क्या आप आगे बढ़ सकते हैं","निर्धारित मार्ग के नियमों की जाँच करें, क्योंकि कुछ खतरनाक सामग्री सुरंगों में प्रतिबंधित है और एक अलग मार्ग की आवश्यकता हो सकती है"],"explanation":"कुछ खतरनाक माल सुरंगों में प्रतिबंधित हैं, इसलिए चालक को पहले निर्धारित मार्ग नियमों की जांच करनी चाहिए क्योंकि अलग मार्ग की आवश्यकता हो सकती है।"},"202":{"q":"मेरे कैरियर ने प्लेकार्ड लगे खतरनाक माल (HazMat) के सफर से पहले मुझे एक लिखित सुरक्षा योजना दी और कहा कि मैं शिपिंग कागजात को सुरक्षित रखने, अपने मार्ग की पुष्टि करने और ट्रेलर तक अनधिकृत पहुँच को सीमित करने की उसकी प्रक्रियाओं का पालन करूँ। टेक्सास DPS के दृष्टिकोण से, इस सुरक्षा योजना का मुख्य (PRIMARY) उद्देश्य क्या है?","options":["इस संभावना को कम करना कि खतरनाक सामग्री अनधिकृत लोगों द्वारा चुराई जाए या उसका दुरुपयोग किया जाए","लोडिंग और अनलोडिंग को तेज़ करना ताकि डिलीवरी अपने निर्धारित समय से पहले पहुँच जाए","पड़ावों के बीच सबसे छोटा संभव मार्ग बनाकर ईंधन की खपत कम करना","कार्गो क्षेत्र को साफ़ रखना ताकि परिवहन के दौरान सामग्री दूषित न हो"],"explanation":"खतरनाक माल सुरक्षा योजना इसलिए होती है ताकि अनधिकृत लोगों द्वारा खतरनाक माल की चोरी या दुरुपयोग की संभावना कम की जा सके।"},"203":{"q":"मैं एक अनजान शहर से होकर प्लैकार्ड लगे संक्षारक (corrosive) माल की ढुलाई कर रहा हूँ और एक रात पहले रुककर अपना मार्ग तय कर रहा हूँ। टेक्सास CDL हैंडबुक के अनुसार, एक खतरनाक माल (HazMat) चालक के लिए अपना मार्ग पहले से योजना बनाना इतना महत्वपूर्ण क्यों है, इसका MUKHYA (मुख्य) कारण क्या है?","options":["इससे मैं रास्ते में टायर जाँच छोड़ सकता हूँ क्योंकि मुझे पहले से पता है कि यात्रा में कितना समय लगेगा","इससे मुझे उन प्रतिबंधित क्षेत्रों को पहचानने और उनसे दूर रहने में मदद मिलती है जहाँ मेरे प्लैकार्ड लगे माल की अनुमति नहीं है","इससे मैं ईंधन बचाने के लिए खुले राजमार्ग के हिस्सों पर अपने प्लैकार्ड हटा सकता हूँ","इससे यह गारंटी मिलती है कि मुझे रास्ते में सबसे सस्ते ईंधन स्टेशन और विश्राम स्थल मिलेंगे"],"explanation":"मार्ग की पहले से योजना बनाना चालक को उन प्रतिबंधित क्षेत्रों की पहचान करने और उनसे दूर रहने में मदद करता है जहां चिह्नित माल वर्जित है।"},"204":{"q":"मैं एक माल टर्मिनल पर ट्रेलर लोड कर रहा हूँ और मेरे मैनिफेस्ट में कक्षा 1 (डिवीजन 1.1) विस्फोटकों के कई पैलेट के साथ-साथ डॉक पर प्रतीक्षारत अन्य खतरनाक सामग्री भी शामिल है। डॉक चालक दल को सब कुछ एक साथ ढेर करने देने से पहले, यह तय करने में कि कौन से उत्पाद विस्फोटकों के साथ एक ही लोड में जा सकते हैं, मेरा मार्गदर्शन किसे करना चाहिए?","options":["विस्फोटक किसी भी खतरा वर्ग के साथ एक लोड साझा कर सकते हैं बशर्ते प्रत्येक पैलेट को अलग से रोका और बांधा गया हो ताकि वह परिवहन में न खिसके","विस्फोटकों को किसी भी चीज़ के साथ लोड किया जा सकता है बशर्ते संयुक्त माल ट्रेलर के लिए 1,001 पाउंड की प्लेकार्ड सीमा से कम रहे","पृथक्करण (लोड/अनलोड) तालिका विस्फोटकों को कुछ अन्य खतरनाक सामग्रियों के साथ लोड करने पर रोक लगाती है, इसलिए उन्हें मिलाने से पहले मुझे इसे जाँचना चाहिए","विस्फोटकों को पूरी तरह अकेले लोड किया जाना चाहिए और वे कभी भी किसी अन्य माल के साथ ट्रेलर साझा नहीं कर सकते"],"explanation":"विस्फोटकों को अन्य खतरनाक सामग्रियों के साथ मिलाने से पहले हमेशा पृथक्करण (लोड/अनलोड) तालिका देखें, क्योंकि कुछ उत्पादों को एक साथ लोड करना प्रतिबंधित है।"},"205":{"q":"मैं लोडिंग डॉक पर हूँ और अपने ट्रेलर में क्लास 8 संक्षारक तरल के कई ड्रम और बाल्टियाँ हाथ से लादने वाला हूँ। डॉक कर्मचारी पूछता है कि पट्टियों से बांधने से पहले मैं हर कंटेनर को कैसे रखवाना चाहता हूँ। भार को सुरक्षित रूप से पैक करने और तरल अंदर सील रहे, इसके लिए हर कंटेनर को कैसे रखा जाना चाहिए?","options":["बगल के बल लिटाकर ताकि ड्रम कसकर सटे रहें और रास्ते में कम खिसकें","मुँह नीचे की ओर करके ताकि कोई रिसाव ढक्कन से दूर बह जाए","खतरे के लेबल दीवार की ओर करके ताकि वे खरोंचें नहीं","सीधे खड़ा करके, मुँह ऊपर की ओर ताकि ढक्कन तरल के स्तर से ऊपर रहें"],"explanation":"तरल खतरनाक सामग्री को सीधा, बंद हिस्से ऊपर की ओर रखकर लोड करें ताकि खुले मुंह तरल के स्तर से ऊपर रहें और सील से रिसाव न हो।"},"206":{"q":"मैं एक ट्रेलर में संक्षारक (वर्ग 8) सामग्री के डिब्बे हाथ से लोड कर रहा हूँ, और एक डॉक कर्मचारी मुझे भारी डिब्बों को तेज़ी से जगह पर खींचने के लिए एक धातु का कार्गो हुक थमाता है। कुछ भी पकड़ने से पहले, कौन सा नियम मुझे इन पैकेजों पर उस हुक का उपयोग करने से रोकना चाहिए?","options":["मुझे ऐसा कोई हुक या औज़ार उपयोग नहीं करना चाहिए जो खतरनाक सामग्री के पैकेजों को छेद सकता, फाड़ सकता या किसी तरह क्षति पहुँचा सकता हो","जब तक मैं डिब्बों को सीधा रखूँ और लेबल बाहर की ओर रहें, मैं हुक का स्वतंत्र रूप से उपयोग कर सकता हूँ","हुक का उपयोग वर्ग 8 के लिए तभी अनुमत है जब मैं ट्रेलर के चारों ओर प्लेकार्ड लगा दूँ","हुक का उपयोग तभी अनुमत है जब मैं लोड करने के बाद पहले 100 मील के भीतर टायर जाँच लूँ"],"explanation":"ऐसे किसी हुक या औजार का प्रयोग कभी न करें जो खतरनाक सामग्री की पैकेजिंग को छेद, फाड़ या क्षतिग्रस्त कर सके, क्योंकि टूटने से सामग्री बाहर निकल सकती है।"},"207":{"q":"एक गर्म दोपहर में मैं अपने ट्रेलर में संपीड़ित गैस के सिलेंडर (श्रेणी 2) लाद रहा हूँ। नियमों के अनुसार इन्हें सही ढंग से संभालने के लिए, चलने से पहले मुझे इन सिलेंडरों के साथ क्या करना चाहिए?","options":["उन्हें ढीला लिटा दूँ ताकि वे अपने आप जम जाएँ और रास्ते में भार के बैठने पर खिसक सकें","उन्हें मजबूती से बाँध दूँ ताकि वे हिल न सकें और उन्हें गर्मी के स्रोतों से सुरक्षित रखूँ","उन्हें सीधा खड़ा करूँ और वाल्व थोड़ा खोल दूँ ताकि भीतरी दबाव धीरे-धीरे निकल जाए","उन्हें ट्रेलर की गर्म दीवार से सटाकर ऊँचा चढ़ा दूँ और केवल निचली पंक्ति को रोक लगाऊँ"],"explanation":"संपीड़ित गैस सिलेंडरों को मजबूती से बांधें ताकि वे हिल या गिर न सकें और उन्हें गर्मी से दूर रखें, क्योंकि गर्मी आंतरिक दबाव बढ़ाकर फटने का कारण बन सकती है।"},"208":{"q":"टेक्सास में एक ढुलाई से पहले मैं एक टैंकर पर खतरे के प्लेकार्ड लगा रहा हूँ और देखता हूँ कि उस पर दो प्लेकार्ड हैं: मुख्य खतरा वर्ग के लिए एक बड़ा प्राथमिक प्लेकार्ड और नीचे कोने में बिना वर्ग संख्या वाला एक छोटा दूसरा प्लेकार्ड। मेरा प्रशिक्षक दूसरे को 'सहायक' (subsidiary) प्लेकार्ड कहता है। यह इस माल के बारे में मुझे क्या बता रहा है?","options":["यह उस पुराने वर्गीकरण की पुष्टि करता है जिसे शिपर ने माल दोबारा लादने से पहले इस्तेमाल किया था","यह दर्शाता है कि टैंक खाली है और अंदर केवल अवशेष बचा है","यह चेतावनी देता है कि सामग्री अपने प्राथमिक खतरा वर्ग के अलावा एक अतिरिक्त खतरा भी रखती है","यह वर्तमान ईंधन स्तर को दर्शाता है ताकि बचावकर्मियों को पता चले कि कितना उत्पाद मौजूद है"],"explanation":"एक सहायक प्लेकार्ड उस अतिरिक्त खतरे की चेतावनी देता है जो सामग्री अपने प्राथमिक खतरा वर्ग के अलावा रखती है।"},"209":{"q":"मैं प्लेकार्ड (placard) लगे संक्षारक (corrosive) माल को ढोने की तैयारी कर रहा हूँ, और शिपर मुझे शिपिंग पेपर देता है जिसमें ऊपर की ओर एक आपातकालीन प्रतिक्रिया (emergency response) टेलीफोन नंबर दर्ज है। हस्ताक्षर करके रवाना होने से पहले, उस आपातकालीन प्रतिक्रिया नंबर को किस आवश्यकता को पूरा करना चाहिए?","options":["इसे केवल शिपर के सामान्य कार्यदिवस के व्यावसायिक घंटों के दौरान ही उपलब्ध होना चाहिए","यह एक रिकॉर्ड किए गए वॉइसमेल बॉक्स पर जा सकता है, बशर्ते कोई बाद में कॉल वापस कर दे","यह दस्तावेज़ों में दर्ज चालक का व्यक्तिगत मोबाइल नंबर होने की अनुमति है","यह एक ऐसा नंबर होना चाहिए जो खतरनाक माल के परिवहन के दौरान हर समय कर्मचारियों द्वारा संचालित और निगरानी में रखा जाए"],"explanation":"शिपिंग कागजात पर दिया आपातकालीन प्रतिक्रिया फोन नंबर उस पूरे समय निगरानी में और कोई व्यक्ति उत्तर देने को मौजूद रहना चाहिए जब तक खतरनाक सामग्री परिवहन में है।"},"210":{"q":"आप संक्षारक (corrosive) पदार्थों का प्लेकार्ड लगा हुआ भार ले जा रहे हैं, तभी एक जोड़ (fitting) टूट जाता है और आपके ट्रेलर के नीचे से एक तरल फैलकर दो-लेन वाले राजमार्ग के किनारे (शोल्डर) की ओर बढ़ने लगता है। अन्य वाहन अभी भी पास से गुज़र रहे हैं। सड़क से पूरी तरह हटकर रुकने के बाद, कुछ भी करने से पहले आपकी सबसे पहली प्राथमिकता क्या है?","options":["लोगों को रिसाव से दूर रखें और आ रहे यातायात को खतरे के बारे में सचेत करें","गिरे हुए पदार्थ को सड़क से पानी से धो दें ताकि वह ढलान पर आगे न फैले","प्लेकार्ड हटा दें या ढक दें ताकि जिज्ञासु दर्शक भार को लेकर घबराएँ नहीं","वापस केबिन में बैठकर अगले निकास (exit) तक गाड़ी चलाएँ ताकि घटनास्थल जल्दी खाली हो जाए"],"explanation":"खतरनाक सामग्री की घटना में चालक का पहला कर्तव्य है लोगों को रिसाव से दूर रखना और आ रहे यातायात को खतरे की चेतावनी देना।"},"211":{"q":"मैं अपने प्लेकार्ड (placard) वाले माल के साथ एक विश्राम स्थल पर रुका हूँ और धूम्रपान के लिए बाहर निकलना चाहता हूँ। इनमें से किसके पास मुझे बिल्कुल भी सिगरेट नहीं जलानी चाहिए?","options":["उस खाली, पूरी तरह से साफ़ की गई (purged) ट्रेलर के पास जिसे मैंने अभी छोड़ा है","ज्वलनशील तरल (flammable liquid) के प्लेकार्ड वाली ट्रेलर के पास","बगल वाले स्थान पर खड़ी एक यात्री कार के पास","मेरे ट्रैक्टर की साफ़, झाड़ू लगाई हुई कैब के पास"],"explanation":"ज्वलनशील पदार्थों के प्लेकार्ड वाले वाहन के 25 फीट के भीतर कभी धूम्रपान न करें, क्योंकि वाष्प खुली लौ या जलती सिगरेट से प्रज्वलित हो सकते हैं।"},"212":{"q":"ज्वलनशील तरल ले जा रहा आपका प्लेकार्ड लगा टैंकर एक ग्रामीण दो-लेन सड़क पर मुड़कर जैकनाइफ हो जाता है और आपको ट्रेलर के पास जमा हो रही तेज़ रासायनिक गंध महसूस होती है। दो वाहनचालक रुक गए हैं और दुर्घटनास्थल की ओर चल रहे हैं, एक सिगरेट जला रहा है। आपको सबसे पहले कौन-सा कदम उठाना चाहिए?","options":["वापस केबिन में चढ़कर रिसाव फैलने से पहले ट्रेलर को सड़क से हटाना","शिपिंग कागज़ात और आपातकालीन प्रतिक्रिया गाइडबुक (ERG) इकट्ठा करके रिसाव की सफाई शुरू करना","आसपास के लोगों को सुरक्षित दूरी पर रखना, धूम्रपान को रोकना और आपातकालीन प्रतिक्रिया दल तथा CHEMTREC को सूचित करना","आने वाले यातायात को खतरे की चेतावनी देने के लिए दुर्घटनास्थल के पीछे जलती हुई फ्लेयर रखना"],"explanation":"खतरनाक सामग्री दुर्घटना के बाद, दर्शकों को अच्छी तरह दूर रखें, किसी भी धूम्रपान को रोकें, और तुरंत आपातकालीन प्रतिक्रिया दल और CHEMTREC को सूचित करें।"},"213":{"q":"मैं लारेडो यार्ड में अपने प्लेकार्ड लगे ट्रेलर की यात्रा-पूर्व जाँच कर रहा हूँ और देखता हूँ कि पिछला प्लेकार्ड बुरी तरह फीका पड़ गया है और दाईं ओर का एक प्लेकार्ड मडफ्लैप ब्रैकेट के पीछे आंशिक रूप से छिपा है। मेरा साथी कहता है कि जब तक आगे और पीछे के प्लेकार्ड साफ हैं तब तक ठीक है, क्योंकि सामने से आता ट्रैफिक और मेरे पीछे का पुलिस वाला असल में वही देखते हैं। DPS के प्लेकार्ड नियमों के अनुसार कौन-सा कथन सही है?","options":["तुम्हारा साथी सही है कि केवल आगे और पीछे के प्लेकार्ड मायने रखते हैं, क्योंकि वे उन दिशाओं की ओर हैं जहाँ से अन्य चालक आते हैं, इसलिए फीका बगल वाला प्लेकार्ड चलाने से पहले नज़रअंदाज़ किया जा सकता है।","यह स्वीकार्य है जब तक वाहन पर कम से कम एक प्लेकार्ड केबिन के बाहर से पूरी तरह पढ़ने योग्य बना रहे, इसलिए एक साफ़ अगला प्लेकार्ड ही आज तुम्हें चलाने देता।","प्लेकार्ड केवल केबिन के भीतर से चालक को स्पष्ट दिखने चाहिए ताकि माल की चिह्निती की पुष्टि हो, इसलिए बाहरी फीकापन या रुकावट चलाने से पहले मायने नहीं रखती।","चारों प्लेकार्ड मौजूद होने चाहिए और हर एक उस दिशा से पढ़ने योग्य हो जिस ओर वह है, इसलिए फीका पिछला और आंशिक रूप से छिपा बगल वाला प्लेकार्ड चलाने से पहले ठीक करना ज़रूरी है।"],"explanation":"प्लेकार्ड चारों ओर आवश्यक हैं और प्रत्येक उस दिशा से पढ़ने योग्य होना चाहिए जिस ओर वह मुड़ा है, इसलिए कोई भी फीका या ढका प्लेकार्ड चलाने से पहले ठीक करना चाहिए।"},"214":{"q":"मैं प्लेकार्ड लगे हुए लोड पर अपनी प्री-ट्रिप जांच कर रहा हूं और पुष्टि करना चाहता हूं कि प्लेकार्ड नियमों के अनुसार लगाए गए हैं। अंदर छपे प्रतीक और श्रेणी संख्या को नजरअंदाज करते हुए, मेरे ट्रेलर के किनारे पर सही ढंग से लगाए गए प्रत्येक प्लेकार्ड को कौन सा समग्र आकार बनाना चाहिए?","options":["एक वर्ग जो अपने किसी एक कोने पर रखा गया हो, ताकि वह ऊपर की ओर नुकीले सिरे वाले हीरे (डायमंड) जैसा दिखे","एक वर्ग जो अपनी किसी सीधी भुजा पर सपाट रखा गया हो, जैसे सड़क के संकेत का पैनल","एक गोल वृत्ताकार डिस्क, ताकि चेतावनी हर कोण से दिखाई दे","ऊपर की ओर नुकीला एक त्रिकोण, जो मेरी किट के परावर्तक चेतावनी उपकरणों जैसा हो"],"explanation":"प्लेकार्ड एक वर्ग होता है जिसे 45 डिग्री घुमाकर एक कोने पर रखा जाता है, जिससे ऊपर की ओर नुकीला हीरे जैसा आकार बनता है।"},"215":{"q":"मैं प्लेकार्ड लगा हुआ खतरनाक माल (HazMat) का शिपमेंट लोड कर रहा हूँ और हस्ताक्षर करने से पहले दोबारा जाँच रहा हूँ कि हर पैकेज सही ढंग से चिह्नित है। पैकेज पर छपे उचित शिपिंग नाम के अलावा, पैकेज की मार्किंग पर और कौन सी जानकारी अवश्य होनी चाहिए?","options":["लोड स्वीकार करने वाले चालक के रूप में मेरा नाम","सामग्री की पहचान (UN/NA) संख्या","ट्रेलर पर लगे प्लेकार्ड से मेल खाता रंग कोड","वाहक के ट्रैक्टर में इस्तेमाल होने वाला ईंधन का प्रकार"],"explanation":"पैकेज के निशानों में सही शिपिंग नाम के साथ-साथ सामग्री का पहचान (UN/NA) नंबर भी होना चाहिए।"},"216":{"q":"टर्मिनल से निकलने से पहले मैं एक लदान के शिपिंग दस्तावेज़ों की जाँच कर रहा हूँ और मुझे सूचीबद्ध सामग्रियों में से एक के ठीक बगल में HM कॉलम में दर्ज \"RQ\" अक्षर दिखते हैं। दस्तावेज़ों पर हस्ताक्षर करके उन्हें अपनी पहुँच में रखने से पहले, वह \"RQ\" चिह्न उस प्रविष्टि के बारे में मुझे वास्तव में क्या बताता है?","options":["यह उस सुझाए गए कम-यातायात वाले मार्ग को दर्शाता है जिसका मुझे उस सामग्री को आबादी वाले क्षेत्रों से दूर रखने के लिए पालन करना चाहिए","यह पुष्टि करता है कि शिपर ने पैकेज की दोबारा जाँच की और उसे लदान के लिए रिसाव-रहित प्रमाणित किया","यह संकेत देता है कि सामग्री एक रिपोर्ट-योग्य मात्रा (reportable quantity) में मौजूद है, इसलिए उसके रिसाव की सूचना देना अनिवार्य है","इसका अर्थ है कि प्रविष्टि की समीक्षा करके मंज़ूरी दी गई है, इसलिए मैं उसे अपने कागज़ात में सबसे नीचे रख सकता हूँ"],"explanation":"\"RQ\" का अर्थ है रिपोर्ट योग्य मात्रा (Reportable Quantity), यानी सामग्री इतनी मात्रा में मौजूद है कि रिसाव होने पर उसकी सूचना देना ज़रूरी है।"},"217":{"q":"मैं एक मिश्रित खेप लोड कर रहा हूँ और डॉक पर्यवेक्षक मुझे कक्षा 6 (डिवीजन 6.1) ज़हर के रूप में चिह्नित कई पैकेज देता है। मेरे पास एक खाली ट्रेलर है और मुझे यह तय करना है कि इन्हें बाकी माल के सापेक्ष कहाँ रखूँ। इस ज़हर को सुरक्षित और कानूनी रूप से लोड करने के लिए, मुझे इसे किस चीज़ से बिल्कुल दूर रखना सुनिश्चित करना चाहिए?","options":["आपात स्थिति के लिए मेरे पास रखे परावर्तक चेतावनी त्रिकोण","कार्गो दरवाज़ों के पास लगा अग्निशामक यंत्र","ट्रेलर बॉडी के नीचे रखा अतिरिक्त टायर","माल में कोई भी भोजन, खाद्य पदार्थ या खाने योग्य उत्पाद"],"explanation":"ज़हरीली (डिवीज़न 6.1) सामग्री को संदूषण से बचाने के लिए किसी भी भोजन, खाद्य पदार्थ या खाने योग्य उत्पाद के साथ या पास कभी नहीं लादना चाहिए।"},"218":{"q":"मैं क्लास 5 ऑक्सीकारक (oxidizers) का प्लेकार्ड लगा हुआ माल ले जा रहा हूँ, तभी मेरे ट्रेलर के पास एक छोटी विद्युत आग लग जाती है। स्थिति का आकलन करते समय, इस सामग्री को किसी भी लौ से दूर रखना विशेष रूप से अत्यावश्यक क्यों है?","options":["ऑक्सीकारक ऑक्सीजन छोड़ते हैं, इसलिए वे आग को और अधिक गर्म और तीव्रता से जलाएँगे","ऑक्सीकारक लपटों को दबाकर बुझा देंगे, लेकिन इससे निकलने वाला धुआँ विषैला होता है","ऑक्सीकारक गर्मी के संपर्क में आते ही जम जाते हैं, जिससे ट्रेलर चटक सकता है और माल बिखर सकता है","ऑक्सीकारक आग के पास हानिरहित होते हैं, लेकिन प्लेकार्ड स्वयं ज्वलनशील होते हैं"],"explanation":"ऑक्सीकारक ऑक्सीजन छोड़ते हैं जो आग को भड़काती है, जिससे वह अधिक गर्म और तीव्रता से जलती है।"},"219":{"q":"मैं प्लेकार्ड लगे क्लास 3 ज्वलनशील तरल का माल ढो रहा हूँ, और शिपिंग पेपर पर इस पदार्थ का फ्लैश पॉइंट लिखा है। यात्रा-पूर्व सुरक्षा जाँच के दौरान मेरा प्रशिक्षक पूछता है कि यह फ्लैश पॉइंट संख्या इस माल के बारे में असल में क्या बताती है। कौन-सा कथन सही ढंग से बताता है कि फ्लैश पॉइंट क्या दर्शाता है?","options":["यह वह तापमान है जिस पर तरल जम जाता है और टैंक में हिलना-डुलना बंद कर देता है","यह वह न्यूनतम तापमान है जिस पर तरल इतना वाष्प छोड़ता है कि एक प्रज्वलनशील मिश्रण बन जाए","यह वह तापमान है जिस पर तरल बिना किसी चिंगारी या खुली लौ के अपने आप जल उठता है","यह वह तापमान है जिस पर तरल इतना फैल जाता है कि कंटेनर से रिसने लगता है"],"explanation":"फ्लैश पॉइंट वह न्यूनतम तापमान है जिस पर तरल पदार्थ इतना वाष्प छोड़ता है कि एक ज्वलनशील मिश्रण बन जाए।"},"220":{"q":"मैं सीमेंट पाउडर से भरा एक ड्राई बल्क टैंक चला रहा हूँ और एक संकेतित मोड़ वाले क्लोवरलीफ़ ऑफ-रैंप के पास पहुँच रहा हूँ। इस प्रकार का माल जिस तरह व्यवहार करता है, उसे देखते हुए, इस मोड़ को कैसे लेना है यह सबसे अधिक किस कारक से तय होना चाहिए?","options":["माल नीचे और जमा हुआ रहता है, इसलिए मैं बिना कोई समायोजन किए संकेतित हाईवे गति पर मोड़ ले सकता हूँ","टैंक में तरल टैंकर की तरह बैफ़ल होते हैं, इसलिए सर्ज पूरी तरह नियंत्रित है और केवल ब्रेकिंग दूरी मायने रखती है","माल ऊँचाई पर रहता है और वाहन के चलने पर खिसकता है, इसलिए मुझे मोड़ से काफ़ी पहले गति कम कर लेनी चाहिए और सहजता से स्टीयर करना चाहिए","चलते समय पाउडर ठोस रूप में जम जाता है, इसलिए मोड़ के भीतर अचानक स्टीयरिंग सुधार पूरी तरह सुरक्षित हैं"],"explanation":"ड्राई बल्क टैंक का गुरुत्व केंद्र ऊँचा होता है और भार खिसकता है, इसलिए मोड़ से काफ़ी पहले गति कम करें और सहजता से स्टीयर करें।"},"221":{"q":"यदि आप अनिश्चित हैं कि किसी लोड के लिए प्लेकार्ड की आवश्यकता है या नहीं, तो आपको चाहिए:","options":["अनुमान लगाकर चले जाएँ","तालिकाओं की जाँच करें","प्लेकार्ड छोड़ दें","किसी यात्री से पूछें"],"explanation":"नियमों की तालिकाओं की जाँच करें।"},"222":{"q":"मैंने अभी एक ऐसा लोड स्वीकार किया है जिस पर चारों तरफ प्लैकार्ड (खतरे की तख्तियाँ) लगाना अनिवार्य है, और वाहक का डिस्पैचर मुझे जल्दी निकलने के लिए दबाव डाल रहा है। यार्ड से निकलने से पहले, इस प्लैकार्ड वाले लोड को कानूनी रूप से चलाने के लिए मेरे पास व्यक्तिगत रूप से कौन-सा प्रमाणपत्र होना चाहिए?","options":["एक वैध DOT मेडिकल एक्ज़ामिनर प्रमाणपत्र, जो अकेले ही मुझे किसी भी प्लैकार्ड वाले लोड को ढोने का अधिकार देता है","एक टैंकर (N) एंडोर्समेंट, क्योंकि प्लैकार्ड वाले लोड हमेशा थोक टैंक ट्रेलरों में ढोए जाते हैं","मेरे लाइसेंस पर कुछ अतिरिक्त नहीं, क्योंकि शिपर ने पहले ही कागज़ात तैयार कर दिए और प्लैकार्ड लगा दिए हैं","एक वैध HazMat (H) एंडोर्समेंट, जो TSA पृष्ठभूमि जाँच और फिंगरप्रिंटिंग पास करने के बाद प्राप्त होता है"],"explanation":"प्लेकार्ड लगे HazMat भार को ढोने के लिए वैध HazMat (H) एंडोर्समेंट चाहिए, जो TSA पृष्ठभूमि जाँच और फ़िंगरप्रिंटिंग पास करने पर मिलता है।"},"223":{"q":"मैं संक्षारक पदार्थों का प्लेकार्ड लगा हुआ भार ढो रहा हूं और निकलने से पहले अपने शिपिंग दस्तावेज़ सही ढंग से तैयार करना चाहता हूं। मैं खतरनाक माल की प्रविष्टियों पर टैब लगाने और उन्हें स्पष्ट रूप से चिह्नित करने में कुछ मिनट लगाता हूं। जब कोई निरीक्षक या प्रथम प्रतिक्रियाकर्ता उन्हें मांगे, तो इन दस्तावेज़ों पर इस तरह टैब लगाने और चिह्नित करने का असली उद्देश्य क्या है?","options":["ताकि खतरनाक माल के दस्तावेज़ आपातकाल या निरीक्षण के समय जल्दी और आसानी से ढूंढे जा सकें","ताकि खतरनाक माल के दस्तावेज़ विशेष रूप से मांगे जाने तक मुड़े हुए और नज़र से दूर रखे जा सकें","ताकि खतरनाक माल की प्रविष्टियां भार के बाकी कागज़ात से अलग करके एक तरफ रखी जा सकें","ताकि डिलीवरी पूरी होने और हस्ताक्षर हो जाने के बाद खतरनाक माल के दस्तावेज़ फेंके जा सकें"],"explanation":"खतरनाक माल के शिपिंग कागज़ात पर टैब या निशान लगे होने चाहिए ताकि आपात या निरीक्षण के समय उन्हें जल्दी और आसानी से ढूँढा जा सके।"},"224":{"q":"आप प्लेकार्ड लगे संक्षारक (corrosive) पदार्थ का भार ढो रहे हैं, तभी एक जोड़ टूट जाता है और पदार्थ एक व्यस्त राजमार्ग के किनारे पर रिसने लगता है। आपके ट्रेलर के पास राहगीर इकट्ठा होने लगते हैं। नीचे दिए गए कार्यों में से किसी और चीज़ से पहले आपकी सबसे पहली प्राथमिकता क्या होनी चाहिए?","options":["शिपिंग कागजात निकालकर CHEMTREC को फोन करें और उत्पाद का सटीक नाम तथा मात्रा बताएं","रिसाव से खुद को दूर रखें और राहगीरों को हटाकर सभी को संपर्क में आने से बचाएं","आपातकालीन प्रतिक्रिया गाइडबुक (ERG) खोलकर उस पहचान संख्या के लिए रिसाव सफाई प्रक्रिया देखें","अपने वाहक (कैरियर) से संपर्क करें ताकि कंपनी अधिकारियों को आवश्यक घटना रिपोर्ट दाखिल कर सके"],"explanation":"किसी भी HazMat घटना में पहले जीवन की रक्षा करें: रिसाव से दूर रहें और आसपास के लोगों को संपर्क से दूर हटाएँ।"},"225":{"q":"आप ज्वलनशील तरल भरने के लिए अपने टैंक ट्रक को लोडिंग रैक तक ले जाते हैं। कार्गो टैंक में उत्पाद बहना शुरू होने से पहले, वाष्प को प्रज्वलित करने वाली स्थैतिक बिजली की चिंगारी को रोकने के लिए कौन सा कदम सबसे महत्वपूर्ण है?","options":["ट्रक के इंजन को चालू (आइडल पर) छोड़ देना ताकि भरने के दौरान अल्टरनेटर टैंक के स्तर सेंसर को बिजली देता रहे","अन्य वाहनों के आने की स्थिति में लोडिंग रैक के चारों ओर अपने परावर्तक चेतावनी त्रिकोण रख देना","भरने की लाइन खोलने से पहले टैंक को लोडिंग उपकरण से बॉन्ड (समान विभव) करना और दोनों को ग्राउंड (भू-संबद्ध) करना","गुंबद के ढक्कन को पहले से खोल देना ताकि जमा हुई वाष्प निकल जाए और अंदर का दबाव कम हो जाए"],"explanation":"भरने की लाइन खोलने से पहले बॉन्डिंग और ग्राउंडिंग करने से ज्वलनशील तरल के बहाव से बनी स्थैतिक बिजली निकल जाती है, जिससे वाष्प को प्रज्वलित करने वाली चिंगारी रुकती है।"},"226":{"q":"लोडिंग/अनलोडिंग के दौरान, अटेंडेंट को इतने भीतर रहना चाहिए:","options":["1 मील","25 फीट","2 मील","आधा मील"],"explanation":"स्पष्ट दृश्य के साथ 25 फीट के भीतर रहें।"},"227":{"q":"मैं प्लेकार्ड लगा हुआ (खतरनाक माल का) ऐसा भार ढो रहा हूँ जिसके लिए निगरानी आवश्यक है, और मैंने रात के लिए एक निर्धारित ठहराव स्थल पर वाहन खड़ा किया है। जब मैं पास के एक मोटल में आराम करता हूँ, तब मेरा सह-चालक परिचारक (अटेंडेंट) के रूप में वाहन के साथ रुकने को राज़ी हो जाता है। निम्नलिखित में से कौन सा सबसे अच्छी तरह बताता है कि इस निगरानी कर्तव्य को मान्य गिने जाने के लिए मेरे सह-चालक को इसे कैसे निभाना चाहिए?","options":["जब तक वह भार के 100 फीट के भीतर रहता है, तब तक वह स्लीपर बर्थ में झपकी ले सकता है","वह पार्किंग के दूसरी ओर एक बंद रेस्तराँ में बैठ सकता है, क्योंकि वह तब भी ट्रेलर को देख सकता है","यदि आसपास कोई नहीं है, तो वह अपनी निजी कार में ईंधन भरवाने के लिए थोड़ी देर के लिए जा सकता है","उसे जागते और सतर्क रहना चाहिए, वाहन के 100 फीट के भीतर रहना चाहिए और वाहन का बिना किसी रुकावट के स्पष्ट दृश्य होना चाहिए"],"explanation":"प्लेकार्ड वाले माल का परिचारक जागता और सतर्क रहना चाहिए, वाहन से 100 फीट के भीतर हो और उसका बिना रुकावट दृश्य बनाए रखे।"},"228":{"q":"मैं एक अंतरराज्यीय लंबी यात्रा पर प्लेकार्ड लगे (खतरनाक चिह्न वाले) ज्वलनशील तरल पदार्थ का भार ढो रहा हूँ और टर्मिनल से निकलने से ठीक पहले मैंने अपनी यात्रा-पूर्व टायर जाँच पूरी की है। मार्ग के दौरान निरीक्षण नियम का पालन करने के लिए, यात्रा के दौरान मुझे अपने टायरों को फिर से जाँचने के लिए कितनी बार रुकना चाहिए?","options":["कम से कम हर 2 घंटे में या हर 100 मील में, जो भी पहले हो","कम से कम हर 100 मील में, लेकिन एक बार हाईवे पर आने के बाद 2 घंटे वाला नियम लागू नहीं होता","कम से कम हर 3 घंटे में या हर 150 मील में, जो भी पहले हो","केवल तभी जब मैं ईंधन भरने या अनिवार्य 30 मिनट के विश्राम के लिए रुकता हूँ"],"explanation":"प्लेकार्ड वाला माल ढोते समय रास्ते में टायरों की जांच कम से कम हर 2 घंटे या हर 100 मील में, जो पहले हो, करनी चाहिए।"},"229":{"q":"मैं प्लेकार्ड लगे माल को ले जा रहे एक पलटे हुए वाहन की घटनास्थल पर सबसे पहले पहुँचा हूँ। डिस्पैचर धुएँ के कारण सही शिपिंग नाम नहीं पढ़ पा रहा, लेकिन वह मुझे रेडियो पर पैकेज पर स्टेंसिल किया हुआ 4-अंकों का UN पहचान संख्या बता देता है। केवल उसी संख्या का उपयोग करके आपातकालीन प्रतिक्रिया जानकारी को सबसे तेज़ी से ढूँढने के लिए मुझे ERG के किस अनुभाग में जाना चाहिए?","options":["नारंगी बॉर्डर वाले गाइड पृष्ठ, जो सामग्री को उनके निर्धारित खतरे के रंग के अनुसार समूहित करते हैं","पीले बॉर्डर वाले पृष्ठ, जो सामग्री को पहचान संख्या के अनुसार संख्यात्मक क्रम में सूचीबद्ध करते हैं","नीले बॉर्डर वाले पृष्ठ, जो सामग्री को शिपिंग नाम के अनुसार वर्णानुक्रम में सूचीबद्ध करते हैं","सफेद बॉर्डर वाले पृष्ठ, जो सामग्री को पैकेज के वजन और मात्रा के अनुसार सूचीबद्ध करते हैं"],"explanation":"ERG के पीले-किनारे वाले पृष्ठ सामग्री को ID नंबर के अनुसार संख्यात्मक क्रम में सूचीबद्ध करते हैं, इसलिए जब केवल 4-अंकीय ID नंबर पता हो तो ये सबसे तेज़ होते हैं।"},"230":{"q":"मैं अपने प्लेकार्ड लगे (placard) माल पर हुए रिसाव के स्थल पर हूं। शिपिंग कागजात नष्ट हो गए, इसलिए मेरे पास UN/NA पहचान संख्या नहीं है, लेकिन कंटेनर पर साफ तौर पर \"क्लोरीन\" (CHLORINE) उकेरा हुआ है। इस सामग्री को ERG के नीली बॉर्डर वाले पन्नों में तेजी से खोजने के लिए, प्रविष्टि ढूंढने हेतु मैं किस पर निर्भर हूं?","options":["कंटेनर पर उकेरी गई चार अंकों की UN/NA पहचान संख्या","टैंक पर प्रदर्शित प्लेकार्ड (placard) खतरा वर्ग संख्या","सामग्री का उचित शिपिंग नाम (proper shipping name), जो वर्णमाला क्रम में सूचीबद्ध है","पैकेज लेबल पर छपा DOT रंग कोड"],"explanation":"ERG के नीले-किनारे वाले पृष्ठ सामग्री को उचित शिपिंग नाम के अनुसार वर्णानुक्रम में सूचीबद्ध करते हैं, इसलिए जब नाम पता हो पर ID नंबर न हो तो ये उपयोगी होते हैं।"},"231":{"q":"मैं प्लेकार्ड (चेतावनी पट्टिका) लगे संक्षारक (corrosive) पदार्थ का भार ढो रहा हूँ, तभी एक कपलिंग विफल हो जाती है और उत्पाद किनारे की पट्टी पर रिसने लगता है। मैं अपनी आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) उठाता हूँ, पदार्थ का पहचान संख्या (ID) ढूँढता हूँ, और मुझे यह जानना है कि घटनास्थल पर लोगों की रक्षा कैसे करूँ और सुरक्षित प्रतिक्रिया कैसे दूँ। इस जानकारी के लिए मुझे ERG के किस भाग को देखना चाहिए?","options":["नीली किनारी वाले पृष्ठ, क्योंकि प्रत्येक पदार्थ के लिए प्रतिक्रिया कार्रवाई मार्गदर्शिकाएँ वहाँ उचित परिवहन नाम के अनुसार वर्णक्रम में व्यवस्थित होती हैं","हरी किनारी वाले पृष्ठ, क्योंकि वे सुरक्षात्मक कार्रवाई दूरियाँ सूचीबद्ध करते हैं और बताते हैं कि रिसाव को ठीक कैसे संभालना है","पीली किनारी वाले पृष्ठ, क्योंकि घटनास्थल पर क्या करना है यह बताने वाली क्रमांकित मार्गदर्शिकाएँ वहाँ UN/NA संख्या के अनुसार अनुक्रमित होती हैं","नारंगी किनारी वाले पृष्ठ, क्योंकि उनमें क्रमांकित प्रतिक्रिया कार्रवाई मार्गदर्शिकाएँ होती हैं जो बताती हैं कि लोगों की रक्षा कैसे करें और घटना को कैसे नियंत्रित करें"],"explanation":"ERG के नारंगी-किनारे वाले पृष्ठ क्रमांकित प्रतिक्रिया गाइड रखते हैं जो खतरों और लोगों की रक्षा तथा घटना को नियंत्रित करने के सार्वजनिक-सुरक्षा कदमों को बताते हैं।"},"232":{"q":"मेरे आगे चल रहा एक टैंकर पलट गया है और उसमें से ज़हरीली गैस रिस रही है। CHEMTREC को फ़ोन करते समय, मैं यह तय करने के लिए अपनी आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) को हरे किनारे वाले पन्नों पर खोलता हूँ कि मुझे लोगों को कहाँ ले जाना चाहिए। ये हरे पन्ने मुझे कौन-सी जानकारी देने के लिए बनाए गए हैं?","options":["प्रारंभिक पृथक्करण और सुरक्षात्मक कार्रवाई की दूरियाँ, जो बताती हैं कि लोगों को रिसाव से कितनी दूर तक निकालना और दूर रखना है","उचित शिपिंग नामों की सूची जो उनके चार अंकों वाले UN/NA पहचान संख्याओं से मिलान की गई हो","सामान्य प्रतिक्रिया मार्गदर्शिका जो उस पदार्थ के गाइड नंबर के लिए आग, रिसाव और प्राथमिक चिकित्सा की कार्रवाइयों का वर्णन करती है","घटना के दौरान तकनीकी सहायता के लिए कॉल करने हेतु CHEMTREC और आपातकालीन फ़ोन नंबर"],"explanation":"ERG के हरे-किनारे वाले पृष्ठ प्रारंभिक पृथक्करण और सुरक्षात्मक-कार्रवाई दूरियां देते हैं जो बताती हैं कि रिसाव से लोगों को कितनी दूर निकालना और दूर रखना है।"},"233":{"q":"मैं एक टर्मिनल पर अपना ट्रेलर लोड कर रहा हूँ और डॉक पर्यवेक्षक मुझे शिपिंग पेपर देता है जिसमें एक प्रविष्टि पर खतरे के डिवीजन के ठीक बाद एक अक्षर कोड (\"संगतता समूह\" अक्षर) छपा है। वह कहता है कि यह अक्षर बताता है कि उसी खतरा वर्ग की कौन-सी अन्य वस्तुएँ एक ही वाहन में एक साथ लोड की जा सकती हैं या नहीं की जा सकतीं। खतरनाक सामग्री के नियमों के अनुसार, यह संगतता-समूह अक्षर किस सामग्री वर्ग को संदर्भित करता है?","options":["वर्ग 8 संक्षारक, ताकि मैं ट्रेलर में अम्ल और क्षार को एक-दूसरे से प्रतिक्रिया करने से रोक सकूँ","वर्ग 1 विस्फोटक, ताकि मैं जान सकूँ कि कौन-से डिवीजन और प्रकार एक साथ लोड और परिवहन किए जा सकते हैं","वर्ग 2 गैसें, ताकि मैं लोडिंग के दौरान ज्वलनशील गैसों को विषैली गैसों से अलग कर सकूँ","वर्ग 7 रेडियोधर्मी, ताकि मैं परिवहन सूचकांक के कुल योग को एक वाहन की सीमा के भीतर रख सकूँ"],"explanation":"संगतता समूह अक्षर केवल वर्ग 1 विस्फोटकों के होते हैं, जो दर्शाते हैं कि कौन से विस्फोटक प्रभाग और प्रकार एक साथ सुरक्षित रूप से लादे और ढोए जा सकते हैं।"},"234":{"q":"मैं एक प्लेकार्ड वाले लोड के लिए शिपिंग पेपर तैयार कर रहा हूँ और मैं देखता हूँ कि एक एंट्री में पहचान संख्या 'UN' के ब␏␏बजाय 'NA' अक्षरों से शुरू होती है। एक नया ड्राइवर मुझसे पूछता है कि यह उपसर्ग (prefix) इस बारे में क्या संकेत देता है कि यह संख्या कहाँ मान्य है। निम्नलिखित में से उसे बताने के लिए सही बात कौन सी है?","options":["यह एक अंतर्राष्ट्रीय रूप से सुसंगत संख्या है जो यूरोप और एशिया में कहीं भी शिपमेंट के लिए मान्य है","यह संकेत देता है कि लोड केवल निर्धारित विदेशी निर्यात मार्गों पर ही ले जाया जा सकता है, घरेलू रूप से कभी नहीं","यह एक पहचान संख्या है जो संयुक्त राज्य अमेरिका और कनाडा सहित उत्तरी अमेरिका के भीतर उपयोग के लिए निर्धारित की गई है","इसका अर्थ है 'लागू नहीं' (Not Applicable), इसलिए उस लाइन के लिए किसी खतरा वर्ग या सही शिपिंग नाम की आवश्यकता नहीं है"],"explanation":"'NA' उपसर्ग एक ऐसा पहचान संख्या दर्शाता है जो केवल उत्तरी अमेरिका, यानी संयुक्त राज्य अमेरिका और कनाडा में उपयोग के लिए दी जाती है।"},"235":{"q":"मैं ह्यूस्टन से एक बंदरगाह की ओर, विदेश निर्यात के लिए, एक ज्वलनशील तरल का प्लेकार्ड लगा हुआ माल ले जा रहा हूँ, और मेरे शिपिंग कागजात में सामग्री को उचित शिपिंग नाम, खतरा वर्ग और एक 'UN' पहचान संख्या के साथ सूचीबद्ध किया गया है। मेरे साथ चल रहा एक नया ड्राइवर तर्क देता है कि यह 'UN' संख्या केवल यहाँ टेक्सास में मायने रखती है और जैसे ही माल राज्य से बाहर जाता है, इसे अनदेखा किया जा सकता है। इस 'UN' पहचान संख्या के बारे में कौन सा कथन सही है?","options":["'UN' संख्या केवल टेक्सास के भीतर लागू होती है, इसलिए नया ड्राइवर सही है: राज्य की सीमा पर यह मायने रखना बंद कर देती है","'UN' संख्या केवल समुद्र मार्ग से जाने वाले माल के लिए मान्य है, इसलिए जब माल बंदरगाह पहुँचता है तब यह लागू होती है","'UN' संख्या केवल हवाई मार्ग से जाने वाले माल के लिए मान्य है, इसलिए इस ट्रक के लिए एक अलग कोड की आवश्यकता है","'UN' संख्या अंतरराष्ट्रीय स्तर पर मान्यता प्राप्त है, इसलिए यह सामग्री की पहचान उसी तरह करती है चाहे माल कहीं भी जाए"],"explanation":"'UN' पहचान संख्या अंतरराष्ट्रीय स्तर पर मान्यता प्राप्त है, इसलिए माल कहीं भी जाए, यह सामग्री को एक ही तरह पहचानती है।"},"236":{"q":"मैं अपना प्री-ट्रिप निरीक्षण कर रहा हूं और देखता हूं कि मेरे एक पैकेज पर एक हीरे के आकार का लेबल है जिसे मैं नहीं पहचानता। लोड स्वीकार करने से पहले यह पुष्टि करने के लिए कि यह किसी जहरीले (विषैले) पदार्थ को चिह्नित कर रहा है, मुझे उस लेबल पर कौन सा प्रतीक खोजना चाहिए?","options":["हीरे के अंदर खोपड़ी और आड़ी-तिरछी हड्डियां","खतरा वर्ग संख्या के ऊपर एक ज्वाला प्रतीक","हीरे के अंदर किरणों के साथ जलती हुई एक काली गेंद","प्रोपेलर जैसा तीन-पंखों वाला त्रिपर्ण (trefoil) प्रतीक"],"explanation":"ज़हरीली या विषैली सामग्री (डिवीजन 6.1) को डायमंड लेबल के अंदर खोपड़ी और हड्डियों के निशान से पहचाना जाता है।"},"237":{"q":"मैं एक लोडिंग डॉक पर माल का निरीक्षण कर रहा हूँ और पीले-सफेद हीरे के आकार वाले श्रेणी 7 खतरा लेबल वाला एक पैकेज उठाता हूँ। लोड पर हस्ताक्षर करने से पहले सामग्री की पुष्टि करने के लिए, मैं हीरे के अंदर की छपाई जांचता हूँ। उस हीरे के आकार वाले लेबल पर छपा कौन सा एक शब्द पुष्टि करता है कि यह श्रेणी 7 का माल है?","options":["नाज़ुक (FRAGILE), क्योंकि पैकेज में नाज़ुक सीलबंद स्रोत कंटेनर होते हैं जो टूट सकते हैं","रेडियोधर्मी (RADIOACTIVE), क्योंकि श्रेणी 7 के हीरे के आकार वाले लेबल पर छपा शब्द सीधे खतरे को बताता है","संक्षारक (CORROSIVE), क्योंकि श्रेणी 7 के सीलबंद स्रोत अम्ल-प्रतिरोधी बाहरी आवरण में रखे जाते हैं","ऑक्सीकारक (OXIDIZER), क्योंकि रेडियोधर्मी पदार्थ ऐसी ऊर्जा छोड़ता है जो दहन को बनाए रख सकती है"],"explanation":"क्लास 7 के लेबल पर डायमंड के अंदर शब्द RADIOACTIVE छपा होता है, जो खतरे की श्रेणी सीधे बताता है।"},"238":{"q":"टेक्सास की एक गर्म दोपहर में मैं लोडिंग रैक पर अपने कार्गो टैंक में गैसोलीन भर रहा हूँ, और लोडर पूछता है कि पंप बंद करने से पहले मैं उत्पाद को कितना ऊपर तक भरवाना चाहता हूँ। इस ज्वलनशील तरल को सुरक्षित और कानूनी रूप से ढोने के लिए मुझे टैंक कैसे भरवाना चाहिए?","options":["ऊपर तक पूरा भरा हुआ ताकि ब्रेक लगाते समय तरल हिलकर बैफल्स से न टकराए","केवल आधा भरा हुआ, क्योंकि ज्वलनशील तरल के टैंक को कानूनन कभी भी 50 प्रतिशत से अधिक नहीं भरा जा सकता","पूरा भरने से पहले रुककर, ताकि यात्रा के दौरान गर्म होने पर उत्पाद के फैलने के लिए खाली जगह बची रहे","पूरी तरह ऊपर तक भरकर, फिर ढक्कन पर सही खतरे का लेबल लगाकर सील किया हुआ ताकि यह पूर्ण भार के रूप में गिना जाए"],"explanation":"ज्वलनशील तरल वाले कार्गो टैंक को पूरी तरह नहीं भरना चाहिए क्योंकि तरल गर्म होने पर फैलता है और उसे खाली जगह चाहिए।"},"239":{"q":"मैं एक ठंडी सुबह जल्दी एक कार्गो टैंक में ज्वलनशील तरल भर रहा हूँ, और जैसे-जैसे दिन गर्म होगा मैं दक्षिण की ओर बहुत अधिक गर्म मौसम में गाड़ी चलाने की योजना बना रहा हूँ। यह तय करने के लिए कि मैं टैंक को कितना सुरक्षित रूप से भर सकता हूँ, भार के बारे में कौन-सा तथ्य मेरे निर्णय को निर्देशित करना चाहिए?","options":["मैं टैंक को पूरी तरह ऊपर तक भर सकता हूँ, क्योंकि दिन के दौरान बाहरी तापमान बढ़ने पर तरल सिकुड़ता है और कम जगह लेता है","तरल पदार्थों के लिए भरने का स्तर मायने नहीं रखता, क्योंकि केवल संपीड़ित गैसें ही टैंक के आसपास तापमान बदलने पर आयतन बदलती हैं","मुझे इसे अभी ठंडा रहते हुए ऊपर तक भर देना चाहिए, क्योंकि ठंडा तरल फैलता है और अगर मैं दोपहर तक भरने का इंतज़ार करता तो वह बाहर बह जाता","मुझे टैंक में खाली जगह (आउटेज) छोड़नी चाहिए, क्योंकि तरल गर्म होने पर फैलेगा और उसे जगह चाहिए ताकि वह बाहर न बहे"],"explanation":"टैंक में खाली जगह (आउटेज) छोड़ें क्योंकि तरल गर्म होने पर फैलता है और ओवरफ्लो रोकने के लिए उसे जगह चाहिए।"},"240":{"q":"मैं एक डॉक पर प्लेकार्ड लगे दो बक्से खतरनाक माल (HazMat) लोड कर रहा हूँ, और शिपर के कागज़ात चेतावनी देते हैं कि ये दोनों पदार्थ अगर एक-दूसरे के संपर्क में आएँ तो खतरनाक रूप से प्रतिक्रिया कर सकते हैं। ट्रेलर आधा खाली है और मैं जल्दी काम खत्म करना चाहता हूँ। इस खेप को सुरक्षित रूप से लोड करने के लिए मुझे क्या करना चाहिए?","options":["दोनों पदार्थों को इस तरह लोड करूँ कि वे ट्रेलर में एक-दूसरे से अलग रखे जाएँ","दोनों पदार्थों को साथ-साथ लोड करूँ ताकि उन्हें मिलकर आसानी से उतारा जा सके","दोनों पैकेटों का खुला उत्पाद मिला दूँ ताकि वह परिवहन के दौरान एक समान बैठ जाए","दोनों पदार्थों को कसकर एक के ऊपर एक रखूँ ताकि रास्ते में कोई न खिसके"],"explanation":"ऐसे दो खतरनाक माल जो आपस में प्रतिक्रिया कर सकते हैं, उन्हें ट्रेलर में अलग-अलग रखकर लोड करना चाहिए।"},"241":{"q":"मैं डॉक पर हूं और एक ऐसी खतरनाक माल (HazMat) खेप लोड करने वाला हूं जिसके लिए प्लेकार्ड (placards) आवश्यक हैं, और कार्गो चढ़ने से पहले मैं अपना अंतिम निरीक्षण कर रहा हूं। यह आकलन करते समय कि मेरे ट्रेलर पर कोई भी खतरनाक माल लोड होने से पहले उपकरण किस स्थिति में होना चाहिए, निम्नलिखित में से कौन सा अवश्य सत्य होना चाहिए?","options":["मैं अभी लोड कर सकता हूं और रास्ते में पहली 2-घंटे की टायर जांच पर ब्रेक समायोजन और लाइट के काम करने की पुष्टि कर सकता हूं","कोई भी खतरनाक माल लोड होने से पहले ब्रेक और लाइटें पहले से ही निरीक्षित और सही ढंग से काम करने की पुष्टि की हुई होनी चाहिए","केवल ट्रेलर के सर्विस ब्रेक काम करने चाहिए; लाइटें बाद में जांची जा सकती हैं क्योंकि लोडिंग डॉक पर दिन में होती है","ब्रेक और लाइटें केवल प्लेकार्ड लगने के बाद ही मायने रखती हैं, इसलिए मैं पहले लोड कर सकता हूं और प्लेकार्डिंग के बाद जांच सकता हूं"],"explanation":"किसी भी खतरनाक माल को लोड करने से पहले ब्रेक और लाइट की जाँच कर उनके सही ढंग से काम करने की पुष्टि की जानी चाहिए।"},"242":{"q":"मैं एक शिपर के डॉक पर हाथ से संक्षारक (corrosive) पैकेजों का एक पैलेट लोड कर रहा हूँ, और कई डिब्बे भारी और पकड़ने में मुश्किल हैं। इन्हें सुरक्षित रूप से संभालने और कंटेनरों को नुकसान से बचाने के लिए, उठाने और हिलाने के लिए मुझे प्रत्येक पैकेज के किस हिस्से से पकड़ना चाहिए?","options":["इसे छपे हुए खतरे के लेबल से पकड़ूँ, क्योंकि वे पैनल संभालने का भार सहने के लिए मजबूत बनाए जाते हैं","इसे ढीली टेप वाली फ्लैप या बंधन (banding) से खींचूँ, क्योंकि वे डिब्बे की सबसे मजबूत पकड़ देती हैं","इसे पैकेज के ठोस, मजबूत हिस्से से उठाऊँ, कभी भी कमजोर हिस्सों या लेबल से नहीं","इसे डॉक पर सबसे नजदीकी किनारे से घसीटूँ, क्योंकि संक्षारक पदार्थ रगड़ सहन कर लेता है"],"explanation":"खतरनाक माल के पैकेज को किसी ठोस, मज़बूत हिस्से से उठाएँ, कभी कमज़ोर भागों या लेबल से नहीं, ताकि कंटेनर सुरक्षित रहे।"},"243":{"q":"मुझे अभी प्लेकार्ड लगे खतरनाक माल (हैज़मैट) की ढुलाई के लिए काम पर रखा गया है, और डिस्पैचर ने मुझे कंपनी के अपने लोडिंग और रूट के तरीकों वाली एक मोटी फाइल दी है। पढ़ते हुए मैं देखता हूँ कि कंपनी के नियम कभी-कभी उससे आगे जाते हैं जो मैंने अपने एंडोर्समेंट के लिए सीखा था। हर यात्रा में कानूनी रूप से सही बने रहने के लिए, अपने वाहक के कंपनी नियमों का पालन करने के अलावा, मुझे और किसका पालन हर समय करना अनिवार्य है?","options":["केवल मेरे वाहक के आंतरिक नियम, क्योंकि कंपनी की फाइल में पहले से ही वह सब शामिल है जो कानून मुझसे माँगता है","डिस्पैचर द्वारा रेडियो पर दिए गए मौखिक रूट निर्देश, जो किसी भी लिखित प्रक्रिया को रद्द कर देते हैं","जो स्थानीय सड़क संकेत और तय सीमाएँ कहती हैं, क्योंकि वे खतरनाक माल के लिए संघीय नियमों की जगह ले लेती हैं","संघीय और राज्य के खतरनाक माल नियम (HMR), जो वाहक के अपने नियमों के साथ-साथ अतिरिक्त रूप से लागू होते हैं"],"explanation":"ड्राइवर को संघीय और राज्य के खतरनाक माल नियमों (HMR) का पालन करना चाहिए, जो वाहक के अपने नियमों के अतिरिक्त लागू होते हैं।"},"244":{"q":"मैं एक प्लेकार्ड खतरनाक सामग्री का लोड ले रहा हूँ और शिपिंग पेपरों में एक हस्ताक्षरित प्रेषक (शिपर) प्रमाणन शामिल है। चालक के रूप में हस्ताक्षर करने से पहले, मैं निश्चित होना चाहता हूँ कि यह प्रमाणन वास्तव में मुझे क्या बता रहा है। शिपिंग पेपर पर प्रेषक का हस्ताक्षरित प्रमाणन कानूनी रूप से क्या दर्शाता है?","options":["कि खेप को नियमों के अनुसार सही ढंग से वर्गीकृत, वर्णित, पैक, चिह्नित और लेबल किया गया था","कि वाहक ने यह सत्यापित कर लिया है कि माल भाड़ा शुल्क सही है और ग्राहक ने खेप का भुगतान पहले ही कर दिया है","कि चालक ने व्यक्तिगत रूप से प्रत्येक पैकेज का निरीक्षण किया है और रास्ते में मिली किसी भी लीकेज की पूरी जिम्मेदारी स्वीकार की है","कि लोड को स्वतंत्र रूप से दो बार तोला गया था और कुल सकल वजन बिल ऑफ लेडिंग से बिल्कुल मेल खाता है"],"explanation":"शिपर का हस्ताक्षरित प्रमाणन कानूनी रूप से बताता है कि माल को नियमों के अनुसार सही ढंग से वर्गीकृत, वर्णित, पैक, चिह्नित और लेबल किया गया है।"},"245":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान मैं देखता हूँ कि ट्रेलर पर लगे चारों प्लेकार्ड चमकीले नारंगी रंग के हैं, जबकि अंदर अलग-अलग पैकेजों पर लगे छोटे हीरे (डायमंड) आकार के लेबल गहरे लाल रंग के हैं। एक साथी ड्राइवर मुझे बताता है कि ये रंग केवल इसलिए हैं ताकि शिपर्स माल की गिनती रख सकें। खतरा सूचना नियमों के अनुसार, हीरे के आकार के खतरा लेबल का रंग वास्तव में मुझे क्या बता रहा है?","options":["यह माल के लिए जिम्मेदार कैरियर और शिपर की पहचान बताता है","यह उस सामग्री से उत्पन्न खतरे का सामान्य प्रकार या वर्ग दर्शाता है","यह उस पैकेज में लदे उत्पाद का कुल वजन दर्शाता है","यह सामग्री को सौंपा गया UN/NA पहचान संख्या दर्शाता है"],"explanation":"डायमंड खतरे के लेबल का रंग खतरे के सामान्य प्रकार या श्रेणी को दर्शाता है, जैसे ज्वलनशील के लिए लाल और ऑक्सीकारक के लिए पीला।"},"246":{"q":"मैं डॉक पर अपना ट्रेलर लोड कर रहा हूँ और शिपिंग पेपर में डिवीज़न 2.3 के ज़हरीली गैस का एक छोटा पैकेज दिखाया गया है जिसका वज़न केवल लगभग 40 पाउंड है, साथ ही टेबल 2 के एक संक्षारक (corrosive) के कई ड्रम हैं जिनका कुल वज़न 600 पाउंड है। डॉक पर्यवेक्षक मुझसे कहता है कि मुझे किसी चीज़ के लिए प्लेकार्ड लगाने की ज़रूरत नहीं है क्योंकि मेरा पूरा भार 1,001 पाउंड की सीमा से काफ़ी कम है। निकलने से पहले मुझे प्लेकार्डिंग के बारे में क्या करना चाहिए?","options":["बिल्कुल प्लेकार्ड न लगाएं, क्योंकि दोनों सामग्रियों का संयुक्त वज़न 1,001 पाउंड से कम है।","केवल संक्षारक ड्रमों के लिए प्लेकार्ड लगाएं, क्योंकि वे कार्गो के वज़न का सबसे बड़ा हिस्सा हैं।","ज़हरीली गैस के लिए उसके वज़न की परवाह किए बिना प्लेकार्ड लगाएं, क्योंकि उस सामग्री के लिए किसी भी मात्रा में प्लेकार्ड आवश्यक है।","ट्रेलर पर कोई भी प्लेकार्ड जोड़ने से पहले भार के कुल 1,001 पाउंड तक पहुँचने का इंतज़ार करें।"],"explanation":"डिवीजन 2.3 जहरीली गैस जैसी टेबल 1 सामग्री को किसी भी मात्रा में प्लेकार्ड लगाना अनिवार्य है, चाहे पैकेज कितना भी हल्का हो।"},"247":{"q":"मैंने अभी-अभी ज्वलनशील तरल का एक भार पहुँचाया है और मेरे टैंक का गेज खाली दिखा रहा है, इसलिए मैं दोपहर के भोजन के लिए एक ट्रक स्टॉप पर रुकता हूँ। एक मित्र मुझसे कहता है कि चूँकि टैंक खाली हो चुका है, मैं चारों तरफ़ के सभी प्लेकार्ड हटा सकता हूँ और इस रिग को किसी भी गैर-खतरनाक माल वाले ट्रेलर की तरह इस्तेमाल कर सकता हूँ। कुछ भी छूने से पहले, अपने 'खाली' टैंक के बारे में मुझे सबसे सुरक्षित धारणा क्या बनानी चाहिए?","options":["चूँकि गेज खाली दिखा रहा है, टैंक में अब कोई खतरनाक सामग्री नहीं है और इसे संभालना पूरी तरह सुरक्षित है।","चूँकि उत्पाद निकल चुका है, मैं तुरंत कानूनी रूप से प्लेकार्ड हटा सकता हूँ, क्योंकि प्लेकार्ड केवल तभी लागू होते हैं जब तरल वास्तव में ढोया जा रहा हो।","चूँकि भार पहुँचा दिया गया है, अंदर का अवशेष पूरी तरह वाष्पित हो चुका है और कोई ज्वलनशील वाष्प या खतरा पैदा नहीं कर सकता।","चूँकि अंदर अवशेष और वाष्प रह सकते हैं, टैंक अब भी खतरनाक हो सकता है और इसे ऐसे ही समझा जाना चाहिए मानो उसमें अब भी खतरनाक सामग्री हो।"],"explanation":"खाली किए गए कार्गो टैंक में खतरनाक तरल अवशेष और वाष्प रह सकते हैं, इसलिए ठीक से साफ होने तक इसे भरे हुए की तरह माना और प्लेकार्ड लगाया जाना चाहिए।"},"248":{"q":"मैं अपना X एंडोर्समेंट ले रहा हूँ और परीक्षक मुझसे टर्मिनल पर 'कार्गो टैंक' (cargo tank) और पोर्टेबल टैंक के बीच का अंतर समझाने को कहता है। यार्ड में घूमते हुए, मुझे तरल खतरनाक माल वाले कई टैंक दिखते हैं। मुझे इनमें से किसे सही रूप से 'कार्गो टैंक' के रूप में पहचानना चाहिए?","options":["वह बल्क टैंक जो ट्रक या ट्रेलर से स्थायी रूप से जुड़ा है और उसी का अभिन्न हिस्सा है","एक स्वतंत्र स्टील टैंक जिसे फोर्कलिफ्ट से ट्रेलर पर लादा गया और जिसे वापस उठाकर उतारा जा सकता है","कोई भी टैंक जिसमें 1,001 पाउंड या उससे अधिक तरल हो, चाहे वह वाहन पर कैसे भी रखा हो","एक अलग 55-गैलन ड्रम जिसे ढुलाई के लिए ट्रेलर के बॉक्स के अंदर पट्टियों से बाँधा गया है"],"explanation":"कार्गो टैंक स्थायी रूप से ट्रक या ट्रेलर से जुड़ा होता है और उसका अभिन्न हिस्सा होता है, हटाने योग्य पोर्टेबल टैंक के विपरीत।"},"249":{"q":"मैं प्लेकार्ड (खतरे की सूचना पट्टिका) लगे HazMat लोड पर अपनी प्री-ट्रिप जाँच कर रहा हूँ और कैब में लगे अग्निशामक यंत्र की जाँच कर रहा हूँ। गेज पूरा भरा दिखा रहा है और यह मजबूती से लगा है, लेकिन चलने से पहले मैं पुष्टि करना चाहता हूँ कि यंत्र स्वयं आवश्यकता पूरी करता है। मेरे प्लेकार्ड वाले वाहन के लिए आवश्यकता पूरी करने वाली न्यूनतम (कम से कम) अग्निशामक रेटिंग कौन-सी है?","options":["1 A रेटिंग, क्योंकि अग्निशामक को लकड़ी और कागज जैसे सामान्य ज्वलनशील पदार्थों को संभालना चाहिए","कम से कम 10 B:C रेटिंग","कोई भी काम करने वाला अग्निशामक स्वीकार्य है, बशर्ते गेज पूरा भरा दिखाए और वह मजबूती से लगा हो","मेरे टैंक में समा सकने वाले गैलन ईंधन के लिए रेट किया गया पानी-प्रकार का अग्निशामक"],"explanation":"प्लेकार्ड लगे खतरनाक माल वाहन में कम से कम 10 B:C रेटिंग वाला अग्निशामक यंत्र होना चाहिए।"},"250":{"q":"मैं एक ग्रामीण दो-लेन सड़क पर ज्वलनशील तरल का प्लेकार्ड लगा हुआ (खतरनाक सामग्री का चिह्नित) भार ले जा रहा हूँ और बिना गेट, बत्ती या 'रुको' संकेत वाले एक अनियंत्रित रेलवे क्रॉसिंग के पास पहुँच रहा हूँ। निम्नलिखित में से कौन सा वर्णन करता है कि टेक्सास का कानून मुझसे क्या करने की अपेक्षा करता है?","options":["सड़क की गति पर चलते रहना, क्योंकि कोई संकेत या 'रुको' चिह्न नहीं है जो मुझे रुकने के लिए बाध्य करे","लगभग रुकने तक धीमा होना, पटरियों पर रहते हुए गियर बदलना, और गति बनाए रखने के लिए पार कर जाना","निकटतम पटरी से 15 से 50 फीट पहले रुकना, और केवल तभी पार करना जब बिना रुके पटरियों को पूरी तरह से साफ कर सकूँ","निकटतम पटरी से 5 फीट के भीतर रुकना, फिर रास्ता साफ होने की पुष्टि करके आगे बढ़ना"],"explanation":"प्लेकार्ड लगे वाहन को हमेशा निकटतम पटरी से 15 से 50 फीट पहले रुकना चाहिए और तभी पार करना चाहिए जब वह बिना रुके पटरियों को पूरी तरह पार कर सके।"},"251":{"q":"मैं प्लेकार्ड (चेतावनी पट्टिका) लगे ज्वलनशील तरल का भार ले जा रहा हूँ और मैंने रेलवे क्रॉसिंग से 15 से 50 फुट पहले अपना अनिवार्य पड़ाव कर लिया है। बत्तियाँ बंद हैं, कोई ट्रेन नहीं आ रही, और मुझे दिख रहा है कि दूसरी ओर रास्ता साफ है और मेरे पूरे वाहन के लिए पर्याप्त जगह है। पटरियों पर आगे बढ़ते समय इन्हें पार करने का सही तरीका क्या है?","options":["क्रॉसिंग के बीच में नीचे के गियर में डालना ताकि इंजन को पटरियों पर अधिक खींचने की शक्ति मिले","पार करते समय गियर ऊपर चढ़ाते जाना ताकि गति बढ़े और पटरियों पर कम समय लगे","आगे बढ़ने से पहले खुरदरापन महसूस करने के लिए पटरियों पर लगभग रेंगती गति तक धीमा होना","जब तक पूरी तरह क्रॉसिंग पार न कर लूँ, तब तक एक ही गियर में बिना गियर बदले पार करना"],"explanation":"रेल पटरियों को एक चुने हुए गियर में पार करें और पटरियों पर रहते हुए कभी गियर न बदलें ताकि पटरियों पर वाहन बंद न हो।"},"252":{"q":"मैं प्लेकार्ड लगा हुआ डिवीजन 1.1 विस्फोटकों का भार ढो रहा हूँ और मुझे रात भर के लिए रुकना है। पार्किंग में जगह चुनने के लिए घूमते समय, इनमें से कौन सी स्थिति मुझे किसी स्थान को अस्वीकार कर आगे बढ़ने पर मजबूर करनी चाहिए?","options":["कचरा जलाने वाले एक ड्रम के ठीक बगल वाली जगह, जहाँ मज़दूर सुलगता हुआ कचरा डालते हैं","सड़क के यातायात वाले हिस्से से 5 फीट से अधिक पीछे, एक समतल और अच्छी तरह से बनाई गई बजरी वाली जगह","पार्किंग का एक छायादार कोना जो ऊँचे पेड़ों की कतार से ठंडा बना रहता है","चिकनी, नई-नई बिछाई गई डामर और अच्छी जल निकासी वाली जगह"],"explanation":"विस्फोटकों को आग और चिंगारी फेंकने वाले कचरा जलाने वाले ड्रम जैसे सक्रिय प्रज्वलन स्रोतों से दूर रखना चाहिए।"},"253":{"q":"मैं भेजने वाले के डॉक पर अपने वैन ट्रेलर में क्लास 8 संक्षारक तरल के कई सीलबंद ड्रम लोड कर रहा हूँ। फोर्कलिफ्ट चालक पूछता है कि ढुलाई के लिए इन्हें कैसे रखूँ। इस माल को सुरक्षित और सही ढंग से ढोने के लिए, ड्रमों को कैसे ले जाना चाहिए?","options":["बगल में लिटाकर ताकि वे कसकर भरें और रास्ते में कम खिसकें","सीधा खड़ा करके, सही तरफ ऊपर रखकर, जैसे उन्हें भरा और सील किया गया था","उल्टा रखकर ढेर लगाकर ताकि रिसाव सीलबंद ऊपरी हिस्से में रुक जाए","बगल में लिटाकर पर कसकर गुटकों से रोककर ताकि वे लुढ़क न सकें"],"explanation":"खतरनाक सामग्री के ड्रम सीधे, सही तरफ ऊपर की ओर रखकर ले जाने चाहिए, क्योंकि उनके ढक्कन और सील ऊपर की ओर रहने के लिए बनाए गए हैं।"},"254":{"q":"मैं एक बल्क कार्गो टैंक तैयार कर रहा हूँ जो पिघला हुआ सल्फर ले जाता है, जिसे इतने ऊँचे तापमान पर भेजा जाता है कि वह उच्च-तापमान सामग्री (elevated-temperature material) माना जाता है। निकलने से पहले मैं यह पुष्टि करना चाहता हूँ कि टैंक पर वह अतिरिक्त चिह्न है जिसकी नियम इस तरह के माल के लिए माँग करते हैं। मैं कौन सा चिह्न जाँच रहा हूँ?","options":["\"COLD\" (ठंडा) चिह्न, क्योंकि यह चेतावनी आपातकर्मियों को बताती है कि सामग्री को परिवेश के तापमान से नीचे ठंडा रखा जाना चाहिए","उचित शिपिंग नाम के बगल में लिखा \"MOLTEN\" (पिघला हुआ) चिह्न, जो माल की द्रवित अवस्था को दर्शाता है","\"HOT\" (गरम) चिह्न, जो पास आने वाले हर व्यक्ति के लिए माल को उच्च-तापमान सामग्री के रूप में पहचान कराता है","\"WET\" (गीला) चिह्न, क्योंकि नियम किसी भी अत्यधिक गर्म तरल को पानी लगने पर खतरनाक पदार्थ की तरह मानते हैं"],"explanation":"उच्च तापमान वाली सामग्री पर HOT शब्द दर्शाना चाहिए ताकि पास आने वाले को जलने और ताप के खतरे की चेतावनी मिले।"},"255":{"q":"अपनी यात्रा-पूर्व जाँच के दौरान, मैं एक ड्रम के लदान दस्तावेज़ों की समीक्षा कर रहा हूँ जिसमें ऐसा पदार्थ है जिसके बारे में शिपर चेतावनी देता है कि नदी के पास गिरने पर यह मछलियों और जलमार्गों के लिए हानिकारक है। लदान स्वीकार करने से पहले मुझे यह पुष्टि करनी है कि पैकेज सही ढंग से चिह्नित है। जलीय पर्यावरण के लिए हानिकारक पदार्थ के रूप में इसकी पहचान कराने के लिए इस पैकेज पर कौन-सा चिह्न होना चाहिए?","options":["KEEP DRY (सूखा रखें), क्योंकि पानी के संपर्क से इस प्रकार का पदार्थ अधिक खतरनाक हो जाता है","DANGEROUS WHEN WET (गीला होने पर खतरनाक), क्योंकि खतरा पानी और जलमार्ग से जुड़ा है","THIS SIDE UP (यह ओर ऊपर), ताकि हानिकारक तरल पानी की ओर रिसकर बाहर न निकले","MARINE POLLUTANT (समुद्री प्रदूषक), जो जलीय पर्यावरण के लिए हानिकारक पदार्थ की पहचान कराता है"],"explanation":"जलमार्गों और जलीय जीवन के लिए हानिकारक पदार्थ की पहचान MARINE POLLUTANT चिह्न से होती है।"},"256":{"q":"मैं एक नया CDL ड्राइवर हूं जो HazMat एंडोर्समेंट के लिए पढ़ाई कर रहा हूं, और मेरा डिस्पैचर मुझे बताता है कि मुझे कानूनी रूप से उन नियमों को जानना आवश्यक है जो यह तय करते हैं कि खतरनाक सामग्रियों का वर्गीकरण, पैकेजिंग, चिह्नांकन और परिवहन कैसे किया जाता है। जब मैं पूछता हूं कि ये बाध्यकारी नियम वास्तव में कहां लिखे गए हैं, तो कौन सा स्रोत वह सही कानूनी प्राधिकरण है जिसका मुझे अध्ययन करना चाहिए?","options":["संघीय विनियम (49 CFR), जिनमें कानूनी रूप से बाध्यकारी खतरनाक सामग्री विनियम (HMR) शामिल हैं","आपातकालीन प्रतिक्रिया गाइडबुक (ERG), जिसमें कानूनी रूप से बाध्यकारी खतरा वर्गीकरण नियम शामिल हैं","टेक्सास CDL हैंडबुक (DL-7C), जो सभी HazMat परिवहन नियमों का आधिकारिक कानूनी स्रोत है","बिल ऑफ लैडिंग और शिपिंग पेपर, जहां वाहक लागू HazMat नियम लिखता है"],"explanation":"खतरनाक सामग्री विनियम कानूनी रूप से बाध्यकारी नियम हैं जो संघीय विनियम संहिता के शीर्षक 49 (49 CFR) में दर्ज हैं।"},"257":{"q":"मैंने अभी-अभी प्लेकार्ड लगा हुआ संक्षारक (corrosive) पदार्थों का माल उठाया है और एक लंबी अंतरराज्यीय यात्रा पर निकलने से पहले अपने कागजात व्यवस्थित करने के लिए एक ट्रक स्टॉप पर रुका हूँ। चलते समय नियमों का पालन करने के लिए मुझे अपनी आपातकालीन प्रतिक्रिया मार्गदर्शिका (ERG) कहाँ रखना आवश्यक है?","options":["वाहक के टर्मिनल कार्यालय में फाइल करके, ताकि किसी घटना के दौरान डिस्पैच इसे देख सके","वाहन के अंदर, जहाँ मैं प्लेकार्ड वाला माल चलाते समय इस तक पहुँच सकूँ","प्रेषक (shipper) के कागजात के साथ, क्योंकि प्रेषक ही खतरे की जानकारी तैयार करता है","ट्रेलर में संक्षारक पदार्थों के साथ ताला लगाकर, ताकि यह असली उत्पाद के साथ ही रहे"],"explanation":"आपातकालीन प्रतिक्रिया पुस्तिका को कैब के अंदर रखें जहाँ गाड़ी चलाते समय आप उस तक पहुँच सकें, क्योंकि यह तभी उपयोगी है जब आपके पास हो।"},"258":{"q":"आप प्लेकार्ड लगा हुआ माल ढो रहे हैं, तभी आप देखते हैं कि आपके सीलबंद ड्रमों में से एक से थोड़ी मात्रा में तरल पदार्थ ट्रेलर के फर्श पर टपक रहा है। रिसाव मामूली है और किसी की जान को तत्काल खतरा नहीं है। कौन सा कदम DPS खतरनाक माल प्रक्रिया का सबसे अच्छा पालन करता है?","options":["अपने रास्ते पर अगले ट्रक स्टॉप तक चलते रहें, जहाँ एक मैकेनिक ड्रम की जाँच करके उसे फिर से सील कर सके","रिसाव और अधिक फैलने से पहले उसे ठीक करवाने के लिए धीरे-धीरे निकटतम मरम्मत की दुकान तक चलाएँ","वाहन को जहाँ है वहीं छोड़ दें, उसे न हिलाएँ, और रिसाव से निपटने के लिए योग्य सहायता को बुलाएँ","टपकती बूँदों को सोखने वाले कपड़ों से ढक दें, चलते रहें, और यात्रा समाप्त होने पर रिसाव की सूचना दें"],"explanation":"यदि खतरनाक सामग्री का रिसाव मिले, तो वाहन को कभी न हिलाएँ और इसके बजाय योग्य सहायता बुलाएँ, क्योंकि हिलाने से संदूषण फैल सकता है।"},"259":{"q":"मैं प्लेकार्ड लगे ज्वलनशील तरल को लेकर एक लंबी यात्रा शुरू करने वाला हूँ, और मैं चाहता हूँ कि निकलने से पहले मेरी यात्रा-पूर्व जाँच खतरनाक माल (हैज़मैट) के मानक पर खरी उतरे। निम्नलिखित में से कौन-सा सबसे अच्छी तरह बताता है कि इस यात्रा के शुरू होने से पहले मुझे क्या जाँचना चाहिए?","options":["केवल शिपिंग कागज़ात और चारों प्लेकार्ड, क्योंकि वाहन की स्वयं की जाँच पिछली यात्रा में हो चुकी थी","केवल टायर, क्योंकि नियम मुझे हर 2 घंटे या 100 मील पर जिस एकमात्र चीज़ को दोबारा जाँचने को कहते हैं वह यही है","केवल ब्रेक प्रणाली, क्योंकि लदे हुए हैज़मैट वाहन में ब्रेक ही सबसे महत्वपूर्ण एकल घटक हैं","ब्रेक और पूरा वाहन, समूची इकाई की पूर्ण यात्रा-पूर्व जाँच करते हुए"],"explanation":"प्लेकार्ड लगी खतरनाक सामग्री ढोना आपके कर्तव्यों में जुड़ता है, इसलिए यात्रा से पहले ब्रेक और पूरे वाहन का संपूर्ण प्री-ट्रिप निरीक्षण करें।"},"260":{"q":"मैं टेक्सास के एक ग्रामीण राजमार्ग पर क्लोरीन (श्रेणी 2.3 ज़हरीली गैस) का प्लेकार्ड लगा हुआ माल ले जा रहा हूँ और एक बिना चिह्न वाले रेलवे क्रॉसिंग के पास पहुँचता हूँ जहाँ न कोई गेट है, न चमकती लाइटें हैं और न ही आसपास कोई अन्य यातायात है। यहाँ कानून मुझसे क्या करने की माँग करता है?","options":["निकटतम पटरी से 15 से 50 फीट पहले रुकूँ, और फिर तभी पार करूँ जब मैं पटरियों को पूरी तरह से खाली कर सकूँ","गति धीमी करूँ और इसे 'रास्ता दो' संकेत की तरह मानूँ, और चूँकि कोई संकेत या आती हुई ट्रेन नहीं है, धीरे-धीरे पार कर जाऊँ","केवल तभी रुकूँ जब मुझे लगा हुआ STOP या रेलवे क्रॉसिंग का चिह्न दिखे, अन्यथा राजमार्ग की निर्धारित गति से आगे बढ़ूँ","पटरियों से पहले निचले गियर में जाऊँ और पूरे क्रॉसिंग के दौरान इंजन को लगातार खींचता हुआ बनाए रखूँ"],"explanation":"प्लेकार्ड लगी जहरीली गैस वाली गाड़ी को हर क्रॉसिंग पर निकटतम पटरी से 15 से 50 फीट पहले रुकना चाहिए और तभी पार करना चाहिए जब वह पटरियों को पूरी तरह पार कर सके।"},"261":{"q":"मैंने अपना HazMat (H) इंडोर्समेंट प्राप्त किया और तब से प्लैकार्ड लोड ढो रहा हूँ। मेरा दोस्त कहता है कि एक बार सुरक्षा खतरा मूल्यांकन (TSA) और लिखित परीक्षा पास कर लेने पर, आप जीवनभर के लिए तैयार हो जाते हैं और फिर कभी HazMat सामग्री को छूने की जरूरत नहीं होती। अपडेट रहने के लिए Texas DPS वास्तव में मुझसे कितने अंतराल पर HazMat प्रशिक्षण दोहराने की अपेक्षा करता है?","options":["लगभग हर 1 वर्ष, प्रत्येक वार्षिक चिकित्सा प्रमाणपत्र नवीनीकरण से जुड़ा हुआ","लगभग हर 3 वर्ष","लगभग हर 10 वर्ष, मानक CDL नवीनीकरण चक्र के अनुरूप","फिर कभी नहीं — एक बार इंडोर्समेंट और TSA जाँच पास हो जाने पर, पुनः प्रशिक्षण की आवश्यकता नहीं होती"],"explanation":"खतरनाक सामग्री प्रशिक्षण लगभग हर 3 साल में दोहराया जाना चाहिए ताकि चालक सुरक्षित हैंडलिंग, प्लेकार्डिंग और आपातकालीन प्रक्रियाओं में अद्यतन रहे।"},"262":{"q":"मैं अपनी यात्रा-पूर्व जाँच कर रहा हूँ और शिपिंग कागज़ात में कक्षा 6.1 का माल दर्ज है; ट्रेलर पर पहले से ही 'POISON' (ज़हर/विषैला) लिखा हीरे के आकार का प्लेकार्ड लगा है। एक नया चालक मुझसे पूछता है कि यह प्लेकार्ड असल में हमें किस बारे में चेतावनी दे रहा है। मुझे उसे कौन-सा कथन देना चाहिए?","options":["यह चेतावनी देता है कि माल एक ज्वलनशील तरल है, इसलिए असली खतरा खुली लौ के पास आग पकड़ने का है","यह चेतावनी देता है कि माल संक्षारक है, इसलिए असली खतरा संपर्क में आने पर त्वचा और आँखों में रासायनिक जलन का है","यह चेतावनी देता है कि यह पदार्थ लोगों के लिए हानिकारक या घातक है, इसलिए इसके संपर्क में आने से ज़हर चढ़ सकता है या मौत हो सकती है","यह चेतावनी देता है कि माल एक ऑक्सीकारक है, इसलिए असली खतरा यह है कि यह अन्य पदार्थों को तेज़ी से जलाता है"],"explanation":"POISON या TOXIC प्लेकार्ड चेतावनी देता है कि सामग्री लोगों के लिए हानिकारक या घातक है और संपर्क में आने पर जहर दे सकती है या मार सकती है।"},"263":{"q":"मैं 'OXYGEN' (ऑक्सीजन, श्रेणी 2.2) प्लेकार्ड वाला माल ढो रहा हूँ और सड़क किनारे जाँच के दौरान मुझे अपने एक टायर से धुआँ निकलता दिखता है। स्थिति को परखते हुए, इस माल के पास की गर्मी और किसी भी लौ से कैसे निपटूँ — इसमें निम्नलिखित में से किसे सबसे अधिक महत्व देना चाहिए?","options":["ऑक्सीजन किसी भी छोटी आग को फैलने से पहले ही दबा कर बुझा देगी, इसलिए मेरे पास प्रतिक्रिया करने के लिए अतिरिक्त समय है।","ग़ैर-ज्वलनशील गैस होने के कारण ऑक्सीजन आग को किसी भी तरह प्रभावित नहीं कर सकती, इसलिए मेरी एकमात्र चिंता टायर है।","ऑक्सीजन आसपास के माल को ठंडा करके तापमान घटा देगी, जिससे गर्म टायर का ख़तरा कम हो जाएगा।","ऑक्सीजन आग को भड़का और तेज़ कर सकती है, इसलिए इस माल के पास की छोटी सी लौ को भी मुझे गंभीर ख़तरा मानना चाहिए।"],"explanation":"ऑक्सीजन आग को बढ़ावा देती और तेज़ करती है, इसलिए ऑक्सीजन भार के पास किसी भी लौ या अधिक गर्मी को गंभीर खतरे के रूप में लिया जाना चाहिए।"},"264":{"q":"आप डिवीजन 1.2 विस्फोटकों का प्लेकार्ड लगा हुआ लदान ले जा रहे हैं और आपको संघीय नियमों के तहत अनिवार्य विश्राम के लिए रुकना है। कानूनी पार्किंग स्थान ढूँढते समय, इंजन बंद करने से पहले आपको किस स्थान से कम से कम 300 फुट दूर रहना अनिवार्य है?","options":["सड़क किनारे एक गोदाम जहाँ कर्मचारी और ग्राहक नियमित रूप से एकत्र होते हैं","चलने योग्य सड़क के किनारे पर बनी रंगी हुई किनारा रेखा","आगे राजमार्ग को पार करती रेलवे पटरियों का एक समूह","विश्राम क्षेत्र में कानूनी रूप से खड़ा एक अन्य वाणिज्यिक वाहन"],"explanation":"डिवीजन 1.1, 1.2 और 1.3 विस्फोटकों को कभी भी ऐसी इमारत के 300 फीट के भीतर खड़ा नहीं किया जा सकता जहाँ लोग एकत्र होते हैं, जैसे सड़क किनारे का गोदाम।"},"265":{"q":"मैं प्लेकार्ड लगा हुआ माल ढो रहा हूँ और सड़क किनारे की एक समस्या जाँचने के लिए मुझे अपने ट्रक को कुछ मिनटों के लिए ग्रामीण राजमार्ग के किनारे खड़ा छोड़ना पड़ रहा है। नियमों के अनुसार वाहन की निगरानी होनी चाहिए। कानूनी रूप से निगरानीकर्ता गिने जाने के लिए, मुझे अपने खड़े प्लेकार्ड वाले वाहन से कितनी दूरी तक रहने की अनुमति है?","options":["वाहन से 5 फुट के भीतर, यानी वही दूरी जो मुझे सड़क के चलने वाले हिस्से से बनाए रखनी होती है","वाहन से 100 फुट के भीतर, उसे साफ़ नज़र में रखते हुए और ज़रूरत पड़ने पर हटा सकने की स्थिति में","वाहन से 300 फुट के भीतर, यानी वही दूरी जो पुलों और सुरंगों के आसपास आवश्यक होती है","एक-चौथाई मील के भीतर, बशर्ते मैं प्लेकार्ड अभी भी देख सकूँ"],"explanation":"प्लेकार्ड लगे खड़े वाहन के परिचारक को उससे 100 फीट के भीतर रहना चाहिए, उसे स्पष्ट दृष्टि में रखना चाहिए और आपात स्थिति में उसे हिला सकने में सक्षम होना चाहिए।"},"266":{"q":"अपनी प्री-ट्रिप जाँच के दौरान, मेरा डिस्पैचर मुझे बताता है कि मेरे रिग पर लगे कार्गो टैंकों में से एक कार्गो टैंक ट्रक नहीं, बल्कि एक \"पोर्टेबल टैंक\" (portable tank) है। इसकी पुष्टि के लिए जाँच करते समय, कौन सी विशेषता इसे सही रूप से पोर्टेबल टैंक के रूप में पहचानेगी?","options":["यह वाहन के चेसिस से स्थायी रूप से वेल्ड किया गया है और इसे हटाया नहीं जा सकता","यह ट्रेलर के फ्रेम का ही एक अभिन्न संरचनात्मक हिस्सा है","यह एक थोक कंटेनर है जो वाहन से स्थायी रूप से जुड़ा हुआ नहीं है","यह एक स्थिर टैंक है जो सीधे ट्रक की कैब और बॉडी में बना हुआ है"],"explanation":"पोर्टेबल टैंक एक थोक कंटेनर है जो वाहन से स्थायी रूप से जुड़ा नहीं होता, इसलिए इसे लादा और हटाया जा सकता है।"},"267":{"q":"मैं एक रासायनिक डिपो पर क्लास 2 संपीड़ित गैस का माल लाद रहा हूँ और डॉक पर्यवेक्षक पूछता है कि उस पर हस्ताक्षर करके ले जाने से पहले उत्पाद किस प्रकार के पात्र में पहले से पैक होना चाहिए। माल को कानूनी और सुरक्षित रूप से स्वीकार करने के लिए, संपीड़ित गैस किस प्रकार के पात्र में पैक होनी चाहिए?","options":["सिकुड़न-लिपटे पैलेट पर पट्टियों से बँधे मोटे फाइबरबोर्ड के डिब्बों में सील किया हुआ","फ्लैटबेड ट्रेलर की खुली बेड में ढीला लादकर कार्गो पट्टियों से कसा हुआ","सूखी थोक सामग्री की तरह अस्तर वाले हॉपर ट्रेलर में उँडेला हुआ","दबावयुक्त सिलेंडरों में रखा हुआ या उस गैस के लिए बने ट्यूब ट्रेलर में ढोया हुआ"],"explanation":"संपीड़ित गैस दबाव में रखी जाती है और इसे विशेष रूप से बने सिलेंडरों या गैस के लिए निर्मित ट्यूब ट्रेलर में ले जाना चाहिए।"},"268":{"q":"मैं टेक्सास की एक गर्म दोपहर में द्रवीकृत ज्वलनशील गैस का एक कार्गो टैंक ढो रहा हूँ, और जैसे-जैसे माल धूप में गर्म होता है मुझे एक छोटी सी फुफकार सुनाई देती है और टैंक के ऊपर लगे एक स्प्रिंग-चालित उपकरण से वाष्प का एक छोटा झोंका निकलता दिखता है, जो फिर अपने आप रुक जाता है। यह दाब निवारक वाल्व (प्रेशर रिलीफ वाल्व) क्या कर रहा है और मुझे इसके साथ कैसा बर्ताव करना चाहिए?","options":["यह टैंक को फटने से बचाने के लिए अंदर जमा हुए दाब को अपने आप छोड़ रहा है, इसलिए मैं इसे छेड़ता नहीं और इसे उसी तरह काम करने देता हूँ जैसा इसे डिज़ाइन किया गया है।","यह इस बात का संकेत है कि टैंक अपनी निर्धारित क्षमता से अधिक भरा हुआ है, इसलिए मुझे रुककर माल को तब तक निकालना चाहिए जब तक फुफकार बंद न हो जाए।","यह गैस को संपीड़ित रखने के लिए टैंक में दाब बढ़ा रहा है, इसलिए मुझे इसके बार-बार चलते रहने की उम्मीद करनी चाहिए और वाष्प को पूरी तरह नज़रअंदाज़ कर देना चाहिए।","यह खराब हो रहा है और कार्गो बाहर निकाल रहा है, इसलिए मुझे अगले पड़ाव पर वाल्व को कसकर या ढककर टैंक को पूरी तरह बंद कर देना चाहिए ताकि नुकसान रुक जाए।"],"explanation":"दबाव राहत वाल्व टैंक को फटने से बचाने के लिए जमा हुए आंतरिक दबाव को स्वचालित रूप से छोड़ता है, इसलिए इसे डिज़ाइन के अनुसार काम करने दें।"},"269":{"q":"यदि आपको कोई क्षतिग्रस्त हैजमैट पैकेज मिले, तो आपको चाहिए:","options":["इसे फिर भी स्वीकार कर लें","इसका परिवहन न करें","क्षति को छिपा दें","बस इसे अंदर डाल दें"],"explanation":"क्षतिग्रस्त पैकेज का परिवहन न करें।"},"270":{"q":"मैंने अभी-अभी एक प्लेकार्ड लगे खतरनाक माल (HazMat) की डिलीवरी उतारनी पूरी की है, और जब मैं वाहन के चारों ओर जाँच कर रहा हूँ, तो मुझे डॉक पर छोड़े गए एक पैकेज के नीचे एक गीला, रंग बदला हुआ दाग फैलता दिखता है और हल्की रासायनिक गंध आती है। पाने वाले (कंसाइनी) ने पहले ही माल के लिए हस्ताक्षर कर दिए हैं। DPS के HazMat नियमों के अनुसार, मुझे क्या करना सही है?","options":["मुझसे और कुछ करने की जरूरत नहीं — पाने वाले ने शिपमेंट के लिए हस्ताक्षर कर दिए हैं, इसलिए रिसने वाले पैकेज की जिम्मेदारी पूरी तरह उन पर आ गई है","रिसाव की तुरंत रिपोर्ट करनी चाहिए और यह सुनिश्चित करना चाहिए कि पैकेज को रोका जाए और सुरक्षित ढंग से संभाला जाए, चाहे डिलीवरी तकनीकी रूप से पूरी हो चुकी हो","पैकेज को चुपचाप नजर से हटाकर रख दूँ और कुछ न कहूँ, क्योंकि हस्ताक्षरित डिलीवरी के बाद रिसाव की रिपोर्ट करना केवल कागजी कार्रवाई बढ़ाएगा और मुझे देरी करवाएगा","पैकेज को टेप से दोबारा सील कर दूँ, उसकी कीमत नोट कर लूँ और नुकसान की भरपाई के लिए सामग्री को छूट पर निपटाने या पुनः बेचने की व्यवस्था करूँ"],"explanation":"पाई गई रिसाव की तुरंत सूचना दी जानी चाहिए और डिलीवरी पूरी होने के बाद भी पैकेज को नियंत्रित और सुरक्षित रूप से संभाला जाना चाहिए।"},"271":{"q":"डिलीवरी स्टॉप के दौरान मेरे ट्रेलर में संक्षारक (वर्ग 8) तरल का एक ड्रम फट जाता है और एक पोखर पार्किंग में फैल रहा है। मैंने पहले ही आसपास के लोगों को चेताया, लोगों को दूर रखा और CHEMTREC को सूचित किया। गिरे हुए पदार्थ की वास्तविक सफाई वास्तव में किसे करनी चाहिए?","options":["मुझे अपने दस्ताने और अवशोषक लेकर खुद ही इसे साफ करना चाहिए, क्योंकि मैं ही लोड का प्रभारी चालक हूँ","शिपर को आकर इसे साफ करना चाहिए, क्योंकि शिपर ने ही पदार्थ को वर्गीकृत और पैक किया था","प्रशिक्षित आपातकालीन कर्मियों या योग्य सफाई ठेकेदारों को सफाई संभालनी चाहिए","पदार्थ को जल्दी सीमित करने और हटाने में मदद के लिए आसपास मौजूद किसी भी व्यक्ति को निर्देशित किया जा सकता है"],"explanation":"रिसाव की सफाई एक विशेष कार्य है जिसे प्रशिक्षित आपातकालीन कर्मियों या योग्य सफाई ठेकेदारों द्वारा किया जाना चाहिए जो सामग्री को सुरक्षित रूप से संभाल सकें।"},"272":{"q":"मैंने अभी-अभी अपने हैज़मैट (खतरनाक माल) समर्थन के लिए आवश्यक सुरक्षा जागरूकता प्रशिक्षण (security awareness training) पूरा किया है, और एक सहकर्मी मुझसे पूछता है कि उस प्रशिक्षण का असली मकसद क्या था। यह प्रशिक्षण जिस उद्देश्य को पूरा करने के लिए बनाया गया है, उसके आधार पर निम्नलिखित में से कौन-सा विवरण मुझे क्या करना सिखाया गया, इसका सबसे अच्छा वर्णन है?","options":["उन चार खतरा वर्गों को याद करना जिन पर हमेशा प्लेकार्ड लगाना ज़रूरी होता है, ताकि मैं लोडिंग डॉक पर तेज़ी से प्लेकार्ड लगा सकूँ","अपनी अनुगमन दूरी और ब्रेक लगाने के बिंदुओं को समायोजित करना ताकि मैं प्लेकार्ड लगे माल को ट्रैफ़िक में तेज़ी से ले जा सकूँ","टर्मिनल पर मेरे दस्तावेज़ों की जाँच हो जाने के बाद रास्ते में बार-बार होने वाली जाँचों को छोड़ देना","अपने माल के आसपास संदिग्ध व्यवहार या संभावित सुरक्षा खतरों को पहचानना और उन खतरों की सूचना उचित अधिकारियों को देना"],"explanation":"सुरक्षा जागरूकता प्रशिक्षण चालकों को अपने माल के प्रति संदिग्ध व्यवहार या सुरक्षा खतरों को पहचानना और उन्हें उचित अधिकारियों को रिपोर्ट करना सिखाता है।"},"273":{"q":"मैं प्लेकार्ड लगे संक्षारक (corrosive) माल की खेप ले जा रहा हूँ, और एक तौल केंद्र पर एक राज्य पुलिस अधिकारी मुझसे मेरे शिपिंग पेपर्स पर माल का \"मूल विवरण\" (basic description) दिखाने को कहता है। मूल विवरण के रूप में मुझे अधिकारी को कौन-सा संयोजन दिखाना चाहिए?","options":["उचित शिपिंग नाम, खतरा वर्ग, पहचान संख्या और पैकिंग समूह","उचित शिपिंग नाम, कुल वजन, आपातकालीन फ़ोन नंबर और ERG गाइड पृष्ठ","खतरा वर्ग, प्लेकार्ड का रंग, प्रेषक के हस्ताक्षर और पैकेजों की संख्या","पहचान संख्या, वाहन पंजीकरण, वाहक का नाम और मार्ग योजना"],"explanation":"किसी खतरनाक सामग्री का मूल विवरण उचित शिपिंग नाम, खतरा वर्ग, पहचान संख्या और पैकिंग समूह होता है।"},"274":{"q":"मैं प्लेकार्ड लगे क्लास 3 ज्वलनशील तरल के माल को ले जा रहा हूँ, तभी कार्गो क्षेत्र में रिसते ड्रम के पास एक छोटी आग लग जाती है। मेरे पास बुझाने के कई विकल्प उपलब्ध हैं। इस आग को सबसे प्रभावी ढंग से बुझाने के लिए मुझे क्या उपयोग करना चाहिए?","options":["जलते तरल को ठंडा करने के लिए उस पर लगातार, भारी पानी की धारा डालें","ऑक्सीजन रोकने के लिए फोम से ढक दें या B:C रेटेड अग्निशामक का उपयोग करें","लपटों के दब जाने तक सड़क किनारे की ढीली रेत डालते रहें","पीछे हटकर और जवाबदाताओं की प्रतीक्षा करते हुए इसे अपने आप बुझने दें"],"explanation":"ज्वलनशील तरल (वर्ग 3) की आग को ऑक्सीजन रोकने के लिए फोम या B:C-रेटेड बुझाने वाले यंत्र से दबाना चाहिए, पानी से कभी नहीं।"},"275":{"q":"मैं श्रेणी 3 का ज्वलनशील तरल (पेट्रोल के ड्रम) ढो रहा हूँ, तभी रिसाव के बाद एक ड्रम कार्गो क्षेत्र में छोटी आग पकड़ लेता है। एक राहगीर पानी की बाल्टी लेकर दौड़ता हुआ आता है और आग बढ़ने से पहले लपटों को दबाने में मदद की पेशकश करता है। उसे पानी डालने देने से पहले, मुझे इस ज्वलनशील-तरल आग पर पानी से क्या अपेक्षा करनी चाहिए?","options":["लपटों को तेज़ी से बुझा देगा क्योंकि पानी आग की ऑक्सीजन आपूर्ति काट देता है","जलते पेट्रोल को उसके फ्लैश पॉइंट से नीचे ठंडा कर देगा और आग तुरंत बुझ जाएगी","आग को फैला देगा, क्योंकि जलता तरल पानी पर तैरता है और पानी के साथ बह जाता है","कुछ खास असर नहीं डालेगा, इसलिए मदद आने तक यही आज़माना सबसे सुरक्षित है"],"explanation":"पानी जलते हुए ज्वलनशील तरल जैसे पेट्रोल को फैला देता है, क्योंकि तरल पानी के ऊपर तैरता है और उसके साथ बह जाता है।"},"276":{"q":"मैं प्लेकार्ड लगे क्लास 5 ऑक्सीकारक (ऑक्सीडाइज़र) के माल को ले जा रहा हूँ, तभी माल में एक छोटी आग लग जाती है। एक राहगीर अग्निशामक यंत्र उठाकर कहता है, \"चिंता मत करो, हवा बंद करके इसे दबा देंगे तो यह जल्दी बुझ जाएगी।\" मैं जो ले जा रहा हूँ उसके रसायन विज्ञान के आधार पर, यह धारणा क्यों गलत है?","options":["क्योंकि ऑक्सीकारक संक्षारक होते हैं, इसलिए वे लपटों को दबाने से पहले ही अग्निशामक यंत्र को गला देते हैं","क्योंकि आग बहुत ठंडी है इसलिए प्रभावित नहीं होगी, क्योंकि ऑक्सीकारक केवल जमाव वाले तापमान पर ही जलते हैं","क्योंकि ऑक्सीकारक पानी सोख लेते हैं, इसलिए अग्निशामक से आने वाली कोई भी नमी आग को और तेज़ी से फैला देती है","क्योंकि ऑक्सीकारक अपनी स्वयं की ऑक्सीजन छोड़ता है, इसलिए आसपास बहुत कम हवा होने पर भी आग जलती रह सकती है"],"explanation":"ऑक्सीकारक (वर्ग 5) अपनी स्वयं की ऑक्सीजन छोड़ता है, इसलिए आसपास कम हवा होने पर भी आग जलती रहती है और इसे दबाकर नहीं बुझाया जा सकता।"},"277":{"q":"डॉक पर अपने यात्रा-पूर्व निरीक्षण के दौरान, मुझे एक छोटा गीला धब्बा और हल्की रासायनिक गंध दिखती है जो उस संक्षारक (क्लास 8) पैकेज से आ रही है जिसे एक शिपर ने अभी लोड किया है। बिल ऑफ लैडिंग पूरा दिखता है और डिलीवरी समय-संवेदनशील है। इस पैकेज को ढोने से इनकार करने का सबसे अच्छा कारण क्या है?","options":["रिसता हुआ पैकेज लोगों को नुकसान पहुंचा सकता है और आसपास के क्षेत्र को दूषित कर सकता है, इसलिए इसे नहीं ढोना चाहिए","छोटा रिसाव केवल समय पर डिलीवरी को प्रभावित करता है, इसलिए मैं इसे ढो सकता हूं बशर्ते मैं समय की भरपाई के लिए तेज़ चलाऊं","शिपर ने पहले ही बिल ऑफ लैडिंग पर हस्ताक्षर कर दिए हैं, इसलिए रिसाव वाहक की कागज़ी समस्या बन जाती है, मेरी नहीं","क्लास 8 माल के लिए हल्का धब्बा सामान्य है, इसलिए मैं पैकेज को पोंछकर बिना किसी और कार्रवाई के लोड कर सकता हूं"],"explanation":"रिसाव वाला खतरनाक सामग्री पैकेज लोगों को नुकसान पहुंचा सकता है और क्षेत्र को दूषित कर सकता है, इसलिए चालक को इसे लेने से मना करना चाहिए।"},"278":{"q":"सड़क किनारे विश्राम स्थल पर खड़े रहने के दौरान मेरे प्लेकार्ड लगे टैंकर में संक्षारक (कोरोसिव) रिसाव शुरू हो जाता है। सही प्रतिक्रिया यह है कि वाहन को वहीं छोड़ दिया जाए, लोगों को दूर रखा जाए और आपातकालीन कर्मियों को सूचित किया जाए। किस परिस्थिति में रिसाव वाले वाहन को वास्तव में हटाना मेरे लिए उचित होगा?","options":["टैंक खाली होने से पहले निकटतम ईंधन स्टेशन तक पहुँचने के लिए","फैलते खतरे से तत्काल जोखिम में पड़े लोगों को सुरक्षित दूर ले जाने के लिए","मरम्मत की दुकान तक जल्दी पहुँचने और लंबी देरी से बचने के लिए","सफाई में आसानी के लिए ट्रक को किसी इमारत के पास खड़ा करने हेतु"],"explanation":"रिसाव वाले खतरनाक माल वाहन को केवल तभी हटाना चाहिए जब लोगों को फैलते खतरे से तुरंत बचाना आवश्यक हो।"},"279":{"q":"मैं संक्षारक (corrosive) पदार्थों का प्लेकार्ड लगा हुआ लदान ले जा रहा हूँ, तभी कपलिंग खराब होने से सड़क के किनारे रिसाव हो जाता है। तत्काल खतरे को नियंत्रित करने, राहगीरों को दूर रखने, धूम्रपान रोकने तथा आपातकालीन सेवाओं और CHEMTREC को बुलाने के बाद भी, संघीय नियम यह आवश्यक करते हैं कि घटना की सूचना दी जाए। इस अनिवार्य घटना रिपोर्ट के लिए मैं किस पक्ष को सूचित करने का जिम्मेदार हूँ?","options":["प्रेषक (shipper) को, क्योंकि उसने ही संक्षारक पदार्थों का वर्गीकरण, पैकेजिंग और शिपिंग कागजात तैयार किए थे","स्थानीय अग्निशमन अधिकारी को, जिसे सड़क पर किसी भी रिसाव की आधिकारिक लिखित घटना रिपोर्ट दाखिल करनी होती है","मेरे नियोक्ता/वाहक (carrier) को, जो लदान के परिवहन और घटना की रिपोर्ट देने के लिए जिम्मेदार पक्ष है","रिसाव के सबसे नजदीकी DPS तौल-केंद्र निरीक्षक को, क्योंकि प्लेकार्ड लगे लदान तौल-केंद्रों पर ट्रैक किए जाते हैं"],"explanation":"वाहक वह पक्ष है जो माल के परिवहन और आवश्यक खतरनाक माल घटना रिपोर्ट दर्ज करने के लिए जिम्मेदार होता है।"},"280":{"q":"मैं अपने ट्रेलर के चारों ओर घूमकर ऐसे माल की प्री-ट्रिप जांच कर रहा हूं जिसके लिए क्लास 3 ज्वलनशील तरल का प्लेकार्ड चाहिए। यह पुष्टि करने के लिए कि प्लेकार्ड सही है, मैं खतरा वर्ग संख्या के लिए डायमंड (समचतुर्भुज) को देखता हूं। उस संख्या को पढ़ने के लिए मुझे प्लेकार्ड पर कहां देखना चाहिए?","options":["डायमंड के सबसे ऊपरी कोने पर, प्रतीक के ठीक ऊपर","डायमंड के बिल्कुल बीच में, प्रतीक के अंदर","डायमंड के सबसे दाएं कोने के साथ","डायमंड के निचले कोने पर, प्रतीक के नीचे"],"explanation":"DOT प्लेकार्ड पर खतरा वर्ग या डिवीजन संख्या हीरे के निचले कोने पर, प्रतीक के नीचे रखी जाती है।"},"281":{"q":"मैं अपनी यात्रा-पूर्व जांच कर रहा हूं और ट्रेलर पर लगे हीरे के आकार के प्लेकार्ड (खतरा-सूचक चिह्न) का निरीक्षण कर रहा हूं ताकि पुष्टि हो सके कि यह सही है। एक नजर में खतरे के प्रकार को तुरंत पहचानने के लिए, खतरा प्रतीक (जैसे लौ, खोपड़ी, या रेडियोधर्मी तिपतिया चिह्न) को देखने के लिए मुझे प्लेकार्ड के किस भाग को देखना चाहिए?","options":["प्लेकार्ड का ऊपरी कोना, लिखे हुए खतरा-वर्ग के नाम के ऊपर","प्लेकार्ड का निचला कोना, जहां खतरा-वर्ग संख्या छपी होती है","प्लेकार्ड का दायां किनारा, चार अंकों की पहचान संख्या के बगल में","प्लेकार्ड का केंद्र, तिरछे रंग-विभाजन के ठीक ऊपर"],"explanation":"DOT प्लेकार्ड पर खतरा प्रतीक हीरे के ऊपरी कोने पर, लिखित खतरा वर्ग के नाम के ऊपर रखा जाता है।"},"282":{"q":"लोडिंग डॉक पर, मेरा डिस्पैचर मुझे बताता है कि मेरा अगला माल \"बल्क पैकेजिंग\" (bulk packaging) में भेजा जाएगा और कागजात पर हस्ताक्षर करने से पहले मुझे इसकी जाँच करनी है। ट्रेलर का निरीक्षण करते समय, इनमें से कौन सा कंटेनर बल्क पैकेजिंग की परिभाषा से सही ढंग से मेल खाता है?","options":["सीलबंद फाइबरबोर्ड के डिब्बों से भरा एक पैलेट, जिनमें से हर एक में कुशनिंग के अंदर कई छोटी बोतलें रखी हैं","एक बड़ा पोर्टेबल टैंक जिसमें उत्पाद सीधे भरा गया है, और सामग्री को रखने वाली कोई आंतरिक पैकेजिंग नहीं है","ट्रेलर की दीवार के पास रखा एक अकेला 5-गैलन प्लास्टिक का ड्रम जिसमें पेंच वाला ढक्कन है","एक लेबल लगे गत्ते के डिब्बे के अंदर रखी हुई दानों से भरी एक छोटी ज़िप-सील बैग"],"explanation":"बल्क पैकेजिंग एक बड़ा कंटेनर है, जैसे पोर्टेबल टैंक, जिसमें उत्पाद सीधे भरा जाता है और कोई आंतरिक पैकेजिंग नहीं होती।"},"283":{"q":"मैं एक रासायनिक गोदाम में अपना ट्रेलर लोड कर रहा हूँ और शिपर मुझसे क्लास 8 संक्षारक पदार्थ के कई 'नॉन-बल्क' (non-bulk) पैकेजों के लिए हस्ताक्षर करने को कहता है। जब मैं अपने डॉक पर माल छाँट रहा हूँ, तो किस कंटेनर के उस 'नॉन-बल्क' विवरण से मेल खाने की उम्मीद मुझे करनी चाहिए?","options":["एक अलग ट्रेलर पर स्थायी रूप से लगा 6,000 गैलन का कार्गो टैंक","गोदाम की साइडिंग पर लाया जा रहा पोर्टेबल रेल टैंक कार","एक ही पैलेट पर एक साथ रखे गए सीलबंद 55 गैलन के स्टील ड्रम","उसी उत्पाद को प्राप्त करने की प्रतीक्षा कर रहा नदी बार्ज का कक्ष"],"explanation":"गैर-बल्क पैकेजिंग खतरनाक माल भेजने के लिए उपयोग किए जाने वाले छोटे कंटेनर हैं, जैसे ड्रम, बक्से, जरीकैन और बैग।"},"284":{"q":"ज्वलनशील तरल से भरे एक कार्गो टैंक की यात्रा-पूर्व जाँच के दौरान, मैं टैंक के ऊपर गुंबद (डोम) क्षेत्र का निरीक्षण करने के लिए ऊपर चढ़ता हूँ। राजमार्ग पर निकलने से पहले, माल को सुरक्षित और रिसाव-मुक्त रखने के लिए मैनहोल ढक्कनों की स्थिति कैसी होनी चाहिए?","options":["थोड़ा खुला रखा गया ताकि यात्रा के दौरान भीतरी वाष्प दबाव बाहर निकल सके","हटाकर केबिन में रख दिया गया ताकि सड़क पर वे ढीले होकर खड़खड़ाएँ नहीं","मार्ग पर अगले निरीक्षण पड़ाव तक पूरी तरह खुला छोड़ दिया गया","वाहन चलाने से पहले पूरी तरह बंद और ठीक से सील किया गया"],"explanation":"कार्गो टैंक के मैनहोल (डोम) कवर वाहन चलाने से पहले पूरी तरह बंद और ठीक से सील होने चाहिए ताकि माल अंदर रहे।"},"285":{"q":"मैं एक टैंकर चालक हूं और एक ट्रांसफर होज के माध्यम से क्लास 3 ज्वलनशील तरल लोड करने वाला हूं। लोडिंग से पहले की जांच के दौरान मैं देखता हूं कि एक होज की बाहरी परत घिसी हुई है और कपलिंग के पास एक छोटी सतही दरार है। इसे जोड़ने और उत्पाद प्रवाह शुरू करने से पहले, लोडिंग या अनलोडिंग में उपयोग होने वाले होज के बारे में हैंडबुक मुझसे क्या अपेक्षा करती है?","options":["केवल अच्छी स्थिति वाले होज का उपयोग करूं, इसलिए मुझे इस दरार वाले होज को अलग रखकर लोडिंग से पहले एक बिना क्षति वाला होज चुनना होगा","इस होज से लोडिंग जारी रखूं क्योंकि दरार केवल बाहरी परत पर है और दबाव स्थिर रखने के लिए इंजन चालू रहेगा","दरार वाले होज का उपयोग करूं पर प्रवाह दर कम कर दूं, क्योंकि धीमा ट्रांसफर सीमांत स्थिति वाले होज को फेल होने से रोकता है","होज को जैसा है वैसा जोड़ दूं और ट्रांसफर के दौरान रिसाव देखने के लिए 25 फीट दूर एक दूसरा व्यक्ति खड़ा कर दूं"],"explanation":"खतरनाक माल लोड या अनलोड करने वाली नली अच्छी स्थिति में होनी चाहिए, इसलिए दरार वाली नली हटाकर बिना क्षति वाली नली उपयोग करें।"},"286":{"q":"मैं एक टर्मिनल पर अपने प्लेकार्ड लगे ट्रेलर को तैयार कर रहा हूँ, और कई काम एक साथ आ गए हैं: मुझे ट्रैक्टर में ईंधन भरना है, एक जली हुई क्लीयरेंस लाइट बदलनी है, शिपिंग कागजात पर हस्ताक्षर करने हैं, और क्लास 3 ज्वलनशील तरल के ड्रमों को ट्रेलर में स्थानांतरित करने वाले दल की निगरानी करनी है। इनमें से किस काम के दौरान मुझे सभी प्रज्वलन स्रोतों — जलती सिगरेट, खुली लपटें, चिंगारी छोड़ने वाले औज़ार — को कार्य से पूरी तरह दूर रखने में सबसे अधिक सख्त होना चाहिए?","options":["ट्रैक्टर में ईंधन भरते समय, क्योंकि टैंक भरते समय ईंधन गेज पर नज़र रखने के लिए इंजन चालू रहता है","जब दल क्लास 3 ज्वलनशील तरल के ड्रम ट्रेलर में लोड कर रहा हो, क्योंकि स्थानांतरण के दौरान वाष्प प्रज्वलित हो सकते हैं","जली हुई क्लीयरेंस लाइट बदलते समय, क्योंकि मैं लोड के पास बिजली की वायरिंग के साथ काम कर रहा होऊँगा","शिपिंग कागजात की जाँच और हस्ताक्षर करते समय, क्योंकि गाड़ी चलाने से पहले मुझे उन्हें ऊपर और पहुँच के भीतर रखना होता है"],"explanation":"क्लास 3 ज्वलनशील तरल लोड करते समय सभी प्रज्वलन स्रोतों को दूर रखें, क्योंकि स्थानांतरण के दौरान निकलने वाले वाष्प प्रज्वलित हो सकते हैं।"},"287":{"q":"एक निर्धारित खतरनाक माल (HazMat) मार्ग पर निकलने से पहले, मैं डिवीजन 1.1 विस्फोटकों से लदे ट्रक की यात्रा-पूर्व जाँच कर रहा हूँ। वाहन के चारों ओर घूमते समय कई चीज़ें मेरा ध्यान खींचती हैं। निम्नलिखित में से कौन-सी खोज अपने आप में इस वाहन को चलाने के लिए असुरक्षित बना देगी और इस माल को ढोने से पहले इसे ठीक करना आवश्यक कर देगी?","options":["पिछले मडफ्लैप में से एक चटका हुआ है और निचले किनारे से थोड़ा मुड़ा हुआ है","मेरी आपातकालीन किट में एक परावर्तक त्रिकोण की सतह फीकी और धुंधली पड़ गई है","टैंक के पास एक फिटिंग से लगातार ईंधन टपक रहा है — ईंधन का रिसाव है","यात्री-साइड का दर्पण ढीला लगा है और इंजन के सुस्त चलने पर कंपन करता है"],"explanation":"विस्फोटक ले जाने वाले वाहन में ईंधन या तेल का कोई रिसाव नहीं होना चाहिए, क्योंकि कोई भी रिसाव माल के पास आग और प्रज्वलन का अस्वीकार्य खतरा है।"},"288":{"q":"सड़क पर एक अधिकारी मुझे रोकता है और इस बात का प्रमाण मांगता है कि मैं प्लेकार्ड लगे संक्षारक (corrosive) पदार्थों के टैंक को ढोने के लिए अधिकृत हूं। मैंने अपना TSA सुरक्षा खतरा मूल्यांकन और फिंगरप्रिंटिंग कई महीने पहले पूरा कर लिया था और सब कुछ पास कर लिया था। मैं कौन सा एक दस्तावेज़ सौंपूं जो वास्तव में यह दिखाता है कि मेरा HazMat (H/X) एंडोर्समेंट वर्तमान में वैध है?","options":["TSA सुरक्षा खतरा मूल्यांकन का स्वीकृति पत्र जो मुझे पृष्ठभूमि जांच पास होने के बाद डाक से मिला था","मेरा वर्तमान DOT मेडिकल परीक्षक प्रमाणपत्र, क्योंकि यही साबित करता है कि मैं शारीरिक रूप से गाड़ी चलाने के लिए फिट हूं","फिंगरप्रिंट रसीद और आवेदन पैकेट जो मैंने एंडोर्समेंट के लिए लाइसेंस कार्यालय में जमा किया था","मेरा वाणिज्यिक चालक लाइसेंस (CDL), क्योंकि H या X एंडोर्समेंट सीधे लाइसेंस पर ही छपा होता है"],"explanation":"खतरनाक सामग्री समर्थन एक कोड है (H, या टैंक और खतरनाक सामग्री के लिए X) जो आपके वाणिज्यिक ड्राइवर लाइसेंस के सामने सीधे छपा होता है।"},"289":{"q":"मैं संक्षारक (corrosives) का प्लेकार्ड लगा हुआ माल ढो रहा हूँ और अपने कागजात जाँचने के लिए थोड़ी देर रुकना है। मुझे जो भी जगहें मिल रही हैं, वे सब दो-लेन वाले राजमार्ग के पास हैं। प्लेकार्ड लगे वाहन को पार्क करने के नियमों के अनुसार, इनमें से कौन सी जगह मुझे उल्लंघन में डाल देगी?","options":["एक किनारे की जगह जहाँ मेरा ट्रक सड़क के चलने वाले हिस्से से केवल 3 फीट दूर खड़ा होगा","एक बजरी वाला मैदान जो सड़क के चलने वाले हिस्से के किनारे से लगभग 20 फीट पीछे है","विश्राम-क्षेत्र की एक जगह जो सड़क के चलने वाले हिस्से से 10 फीट पीछे मापी गई है","एक चौड़ा मोड़-स्थल जो मेरे ट्रक को सड़क के चलने वाले हिस्से से पूरे 8 फीट दूर रखता है"],"explanation":"प्लेकार्ड लगे वाहन को सड़क के यातायात वाले हिस्से से 5 फीट के भीतर पार्क नहीं करना चाहिए।"},"290":{"q":"मैं प्लेकार्ड लगा हुआ माल उठा रहा हूँ और शिपर मुझे ऐसे दस्तावेज़ देता है जिनमें सही शिपिंग नाम, खतरा वर्ग और पहचान संख्या दर्ज है। कैरियर ने यात्रा भेज दी है और किसी भी घटना की रिपोर्ट करेगा। यह सोचते हुए कि इस खतरनाक माल के सुरक्षित परिवहन के लिए कानूनी रूप से और कौन ज़िम्मेदार है, शिपर और कैरियर के साथ साझा-ज़िम्मेदारी की कड़ी को कौन सा पक्ष पूरा करता है?","options":["माल प्राप्त करने वाला ग्राहक, क्योंकि वह डॉक पर माल स्वीकार करता है","चालक, जो माल की जाँच करता है, रिसाव वाले माल को मना करता है, प्लेकार्ड लगाता है और सुरक्षित ढंग से चलाता है","वह TSA अधिकारी जिसने मेरी पृष्ठभूमि-जाँच मंज़ूरी जारी की","डिस्पैचर, जो केवल मार्ग सौंपता है और कभी माल को नहीं छूता"],"explanation":"चालक माल का निरीक्षण करके, रिसाव वाले या गलत चिह्नित शिपमेंट को अस्वीकार करके, सभी ओर प्लेकार्ड लगाकर और सुरक्षित रूप से चलाकर खतरनाक सामग्री सुरक्षा श्रृंखला को पूरा करता है।"},"291":{"q":"मैं एक क्लास 7 रेडियोधर्मी शिपमेंट लोड कर रहा हूं, और शिपर मुझसे कहता है कि दस्तावेज़ पर हस्ताक्षर करने से पहले मैं सत्यापित करूं कि लेबल परिवहन सूचकांक से मेल खाते हैं। पैकेज को देखते हुए, मुझे दो लेबल दिखाई देते हैं जिन पर रोमन अंकों में एक श्रेणी छपी है जो विकिरण स्तर बताती है। इन रेडियोधर्मी लेबलों पर मुझे श्रेणी पदनामों का कौन सा समूह मिलने की उम्मीद करनी चाहिए?","options":["श्रेणियां A, B, या C, पैकेज समूह से मेल खाने के लिए अक्षरों में","श्रेणियां 1, 2, या 9, खतरा वर्ग संख्याओं से मेल खाती हुई","श्रेणियां I, II, या III, विकिरण स्तर को दर्शाती हुई","श्रेणियां X, Y, या Z, परिवहन सूचकांक सीमा को चिह्नित करती हुई"],"explanation":"रेडियोधर्मी (वर्ग 7) लेबल पर रोमन अंकों में एक श्रेणी होती है — I, II या III — जो विकिरण स्तर और परिवहन सूचकांक को दर्शाती है।"},"292":{"q":"मैं एक ट्रेलर में दो अलग-अलग खतरनाक सामग्री (HazMat) के पैकेज लोड कर रहा हूँ, और शिपिंग पेपर दिखाते हैं कि ये एक-दूसरे के साथ प्रतिक्रियाशील (reactive) हैं। शिपर ने मुझे इन्हें अलग रखने को नहीं कहा, और इन्हें साथ-साथ रखने की जगह है। इन्हें एक-दूसरे के पास सुरक्षित करने से पहले, मुझे किस वास्तविक सुरक्षा चिंता पर विचार करना चाहिए?","options":["इन्हें साथ रखना ठीक है क्योंकि पैकेजिंग अकेले ही ऐसी बनी होती है कि कोई भी दो सामग्री कभी आपस में क्रिया न कर सकें","एकमात्र चिंता यह है कि संयुक्त वजन मुझे 1,001 पाउंड की उस सीमा से ऊपर ले जा सकता है जिस पर प्लेकार्ड लगाना अनिवार्य होता है","कुछ खास नहीं होता; प्रतिक्रियाशील सामग्री एक ही जगह रखे जाने पर बस एक-दूसरे को निष्क्रिय कर देती हैं","दो प्रतिक्रियाशील रसायनों को साथ लोड करने से आग या रासायनिक प्रतिक्रिया शुरू हो सकती है, इसलिए इन्हें अलग रखना ज़रूरी है"],"explanation":"असंगत प्रतिक्रियाशील सामग्री को लोडिंग के दौरान अलग रखा जाना चाहिए क्योंकि संपर्क से आग या खतरनाक रासायनिक प्रतिक्रिया हो सकती है।"},"293":{"q":"मेरे प्लेकार्ड लगे ट्रेलर पर एक ड्रम से कोई अज्ञात तरल पदार्थ सड़क के किनारे पर रिस रहा है, और शिपिंग पेपर्स में स्पष्ट नहीं है कि वह वास्तव में क्या है। यह पता लगाने के लिए कि वह पदार्थ क्या है ताकि मैं प्रतिक्रिया देने वालों को सटीक जानकारी दे सकूँ, इनमें से मुझे कभी भी क्या नहीं करना चाहिए?","options":["यह पहचानने में मदद के लिए पदार्थ को चखना या छूना कि वह क्या है","शिपिंग पेपर्स पर सही शिपिंग नाम और पहचान संख्या (ID नंबर) जाँचना","चार अंकों की पहचान संख्या को आपातकालीन प्रतिक्रिया गाइडबुक (ERG) में देखना","प्लेकार्ड और लेबल पर दर्शाए गए खतरे के वर्ग (hazard class) को नोट करना"],"explanation":"किसी सामग्री की पहचान के लिए उसे कभी न चखें और न छुएं, क्योंकि थोड़ी मात्रा भी गंभीर चोट, विषाक्तता या रासायनिक जलन का कारण बन सकती है।"},"294":{"q":"आप ज्वलनशील तरल का प्लेकार्ड (पहचान-पट्टी) लगा हुआ माल ले जा रहे हैं और सड़क किनारे एक विश्राम स्थल पर रुकते हैं। केबिन से बाहर रहते हुए, आप ट्रेलर के पिछले हिस्से में माल के पास से आती लपटें देखते हैं। आग पहले से ही इतनी बड़ी है कि आपके छोटे अग्निशामक यंत्र से उसे बुझाया नहीं जा सकता। आपको सबसे पहले क्या करना चाहिए?","options":["केबिन में चढ़कर जलते ट्रेलर को विश्राम स्थल से दूर किसी खुले मैदान में ले जाने की कोशिश करना","लोगों को वाहन से दूर रखना और मदद के लिए आपातकालीन सेवाओं को सूचित करना","धुआं निकालने और अंदर जल रहे माल तक पहुंचने के लिए ट्रेलर के दरवाजे खोलना","शिपिंग कागजात को केबिन में अलग रख देना ताकि आग उन्हें नष्ट न कर सके"],"explanation":"हाथ के अग्निशामक से नियंत्रण से बाहर खतरनाक सामग्री की आग में, पहले लोगों को दूर रखकर और आपातकालीन कर्मियों को सूचित करके जीवन की रक्षा करें।"},"295":{"q":"मैं एक प्लेकार्ड लगे ट्रेलर पर अपनी यात्रा-पूर्व जाँच कर रहा हूँ जिसे डॉक चालक दल ने रात भर में लोड किया, और चालक की सीट पर रखे कागजात में कक्षा 8 के संक्षारक भार का उल्लेख है। चलने से पहले, चारों ओर पहले से लटके प्लेकार्ड के बारे में मुझे जो एक बात अवश्य पक्की करनी है, वह क्या है?","options":["कि प्लेकार्ड का रंग मेरे ट्रैक्टर के किनारे की पेंट योजना और अक्षरों से मेल खाता है","कि चारों में से हर तरफ एक प्लेकार्ड लगा हो ताकि वह हर दिशा से पढ़ा जा सके","कि प्लेकार्ड शिपिंग कागजात में दर्शाए अनुसार मेरे द्वारा वास्तव में ढोई जा रही सामग्री की सही पहचान करते हैं","कि प्लेकार्ड भार खींचने वाले ट्रैक्टर द्वारा जलाए जाने वाले ईंधन के प्रकार से मेल खाते हैं"],"explanation":"चालक को यह सत्यापित करना चाहिए कि प्लेकार्ड वास्तव में ले जाई जा रही सामग्री की सही पहचान करते हैं, शिपिंग कागजात से मिलान करके।"},"296":{"q":"मैं संक्षारक पदार्थों (श्रेणी 8) का एक ऐसा माल लाद रहा हूँ जिस पर प्लेकार्ड (चेतावनी पट्ट) लगाना अनिवार्य है, लेकिन मेरे सप्लाई बॉक्स में श्रेणी 8 के प्लेकार्ड खत्म हो गए हैं। मेरे पास पिछली यात्रा से बचे श्रेणी 3 (ज्वलनशील) के प्लेकार्ड हैं, और ट्रक पहले ही कई घंटे देरी से चल रहा है। निकलने से पहले इस माल पर प्लेकार्ड लगाने के बारे में सोचने का सही तरीका कौन-सा है?","options":["छोटी यात्रा के लिए श्रेणी 3 के प्लेकार्ड इस्तेमाल करना ठीक है, क्योंकि कोई भी प्लेकार्ड दिखाना अन्य चालकों को यह चेतावनी तो देता ही है कि मैं खतरनाक माल ले जा रहा हूँ","जब तक मैं श्रेणी 8 दर्शाने वाले शिपिंग कागजात सीट पर पहुँच के भीतर रखता हूँ, तब तक मैं बिना किसी प्लेकार्ड के चल सकता हूँ","श्रेणी 3 के प्लेकार्ड दो ओर लगाना और बाकी दो ओर खाली छोड़ देना ठीक है, क्योंकि माल पर केवल आंशिक रूप से प्लेकार्ड लगा है","गलत (श्रेणी 3) प्लेकार्ड दिखाना अवैध और असुरक्षित है, इसलिए जब तक मुझे सही श्रेणी 8 के प्लेकार्ड न मिल जाएँ, तब तक मुझे माल को हिलाना नहीं चाहिए"],"explanation":"प्लेकार्ड चारों ओर सही होने चाहिए, इसलिए गलत प्लेकार्ड के साथ माल नहीं ले जाया जा सकता; वर्ग 8 संक्षारक के लिए वर्ग 8 प्लेकार्ड चाहिए।"},"297":{"q":"आप टेक्सास भर में फ्लेमेबल लिक्विड का प्लेकार्ड लगा हुआ (placarded) भार ले जा रहे हैं और आपकी ड्यूटी-घंटों की घड़ी आपको अगले 20 मिनट में विश्राम लेने के लिए मजबूर कर रही है। आगे आपको एक खचाखच भरा शॉपिंग-सेंटर पार्किंग स्थल, परिवारों से भरा एक भीड़भाड़ वाला सड़क-किनारे का विश्राम क्षेत्र, और किसी भी भीड़ से अच्छी तरह दूर एक शांत बजरी वाला रुकने का स्थान दिखाई दे रहा है। आपको अपनी रुकने की जगह कहाँ योजना बनानी चाहिए?","options":["शांत बजरी वाले रुकने के स्थान पर, प्लेकार्ड लगे भार के साथ जब भी रुकें तो लोगों से दूर एक सुरक्षित स्थान चुनते हुए","भीड़भाड़ वाले सड़क-किनारे विश्राम क्षेत्र में, क्योंकि प्लेकार्ड लगे वाहनों के लिए विश्राम क्षेत्र ही एकमात्र कानूनी रूप से स्वीकृत रुकने के बिंदु हैं","खचाखच भरे शॉपिंग-सेंटर पार्किंग में, क्योंकि गवाहों वाले व्यस्त, अच्छी रोशनी वाले क्षेत्र में रहने से भार चोरी से अधिक सुरक्षित रहता है","जहाँ भी आप समय समाप्त होने पर हों वहीं, ड्राइव समय न खोने के लिए सड़क के चलने वाले हिस्से के किनारे पर ही पार्क करते हुए"],"explanation":"प्लेकार्ड लगे माल को ले जाते समय, हमेशा लोगों से दूर सुरक्षित जगह पर रुकने की योजना बनाएं ताकि कुछ गलत होने पर जोखिम कम से कम हो।"},"298":{"q":"मैंने अभी-अभी अपना H समर्थन (endorsement) प्राप्त किया है और अपनी पहली प्लेकार्ड-युक्त यात्रा से पहले मैं यह दोहरा रहा हूँ कि सभी खतरनाक माल (hazmat) नियम क्यों मौजूद हैं। एक अनुभवी ड्राइवर मुझे बताता है कि नियम तीन मुख्य लक्ष्यों पर आधारित हैं: उत्पाद को रोके रखना, खतरे की सूचना देना, और एक और लक्ष्य। नीचे दिए गए लक्ष्यों में से एक को छोड़कर, बाकी सभी खतरनाक माल नियमों के वास्तविक उद्देश्य को दर्शाते हैं। कौन-सा विकल्प इनमें शामिल नहीं है क्योंकि वह तीसरे लक्ष्य को गलत बताता है?","options":["सामग्री को रोके रखना ताकि रिसाव को रोका या सीमित किया जा सके","माल को तेज़ी से पहुँचाना और वाहक की डिलीवरी लागत को कम करना","प्लेकार्ड, लेबल और शिपिंग दस्तावेज़ों के माध्यम से खतरे की सूचना देना","यह सुनिश्चित करना कि उत्पाद सुरक्षित रूप से और बिना नुकसान के अपने गंतव्य तक पहुँचे"],"explanation":"खतरनाक माल नियमों के लक्ष्य उत्पाद को रोकना, जोखिम की सूचना देना और सुरक्षित परिवहन सुनिश्चित करना है, न कि डिलीवरी तेज करना या लागत घटाना।"},"299":{"q":"मैं एक नया खतरनाक माल (HazMat) चालक हूं जो संक्षारक (corrosive) पदार्थ का लदान उठा रहा है। ड्रम सीलबंद दिखते हैं, लेकिन मैं देखता हूं कि शिपिंग कागजात मेरे पहुंचने से पहले ही भर दिए गए थे और उत्पाद को कैसे वर्गीकृत और पैक किया गया, इसमें मेरी कोई भूमिका नहीं थी। यह तय करते समय कि किसका कौन-सा कर्तव्य है, निम्नलिखित में से कौन-सा कर्तव्य चालक के रूप में मेरा नहीं बल्कि प्रेषक (शिपर) का है?","options":["किसी भी रेलवे क्रॉसिंग से 15 से 50 फुट पहले रुकना और पार करते समय गियर न बदलना","ट्रेलर के चारों ओर प्लेकार्ड लगाना और गाड़ी चलाते समय कागजात अपनी पहुंच के भीतर रखना","पदार्थ का सही शिपिंग नाम निर्धारित करना और उसके लिए उपयुक्त पैकेजिंग चुनना","यदि कोई ड्रम रिस रहा हो तो लदान को अस्वीकार करना और ढोने से पहले माल का निरीक्षण करना"],"explanation":"शिपर सामग्री का वर्गीकरण करता है, सही शिपिंग नाम तय करता है और चालक तक माल पहुंचने से पहले उचित पैकेजिंग चुनता है।"}}};
  Object.keys(REPL).forEach(function(i){ cat.questions[+i]=REPL[i]; });
  APPEND.forEach(function(a){ cat.questions[a.idx]=a.obj; });
  ["ru","tr","es","hi"].forEach(function(L){ var m=TR[L]||{}; Object.keys(m).forEach(function(i){ I.q[L][SUBJ][+i]=m[i]; }); });
})();
